export const recipes=[{"id":1,"servings":4,"tipType":"pasta","pairingsType":"pasta","nutrition":{"cal":784,"prot":33,"carb":76,"fat":38,"fib":3},"origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"スパゲッティ・カルボナーラ","en":"Spaghetti Carbonara","ro":"Spaghete Carbonara"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["スパゲッティ400g","グアンチャーレ（またはパンチェッタ）200g、1cm角に切る","卵黄4個 + 全卵1個","ペコリーノ・ロマーノ80g、細かくすりおろす","パルミジャーノ・レッジャーノ40g、細かくすりおろす","粗挽き黒コショウ小さじ1","パスタ用の細かい塩"],"en":["400g spaghetti","200g guanciale (or pancetta), cut into 1cm cubes","4 large egg yolks + 1 whole egg","80g Pecorino Romano, finely grated","40g Parmigiano Reggiano, finely grated","1 tsp freshly cracked black pepper","Fine sea salt for pasta water"],"ro":["400g spaghete","200g guanciale (sau pancetta), tăiat cuburi de 1 cm","4 gălbenușuri de ou mari + 1 ou întreg","80g Pecorino Romano, ras fin","40g Parmigiano Reggiano, ras fin","1 linguriță piper negru proaspăt măcinat","Sare de mare fină pentru apa de fiert"]},"howIsMade":{"ja":"4リットルの水を沸騰させ、海水を薄めたようなほどよい塩気になるまで塩をたっぷり加え、袋のアルデンテ時間より2分早く茹で上げる——残りはソースの中で仕上げる。同時に、グアンチャーレを冷たいフライパンに入れて中弱火にかけ、8〜10分間ゆっくりと脂を溶かして黄金色になり縁がカリカリになるまで炒める——冷たいフライパンから始めることで焦げを防ぎ、旨味を最大限に引き出せる。グアンチャーレを炒めている間に、卵黄と全卵を両方のチーズと粗挽きコショウをたっぷり加えて混ぜ、濃厚でクリーミーな淡黄色のペースト状にする——これがソースだ。茹で汁を捨てる直前に、少なくとも250mlの白濁した茹で汁を取り分けておく——溶け込んだデンプンが滑らかな乳化を可能にする。グアンチャーレのフライパンを完全に火から下ろし——この工程は絶対に省けない——湯切りしてまだ湯気が立つスパゲッティをフライパンに直接入れ、30秒間しっかり和えて脂を吸わせる。卵クリームをパスタにかけ、茹で汁を少量ずつ加えながら常にトスし続ける——余熱が卵を滑らかで光沢のあるソースに仕上げる——ソースがパスタを綺麗にコーティングして底に溜まらなくなったら水の追加をやめる。塩加減を確認し——グアンチャーレとペコリーノはすでに塩気が強い——盛り付ける間にソースが締まるようなら少し茹で汁を足す。温めたボウルにすぐに盛り、余分なペコリーノをかけ、ペッパーミルで自信を持って何回転かしてから供する。","en":"Bring 4 litres of water to a rolling boil, salt it generously until it tastes pleasantly of the sea, then cook the spaghetti for 2 minutes less than the packet's al dente time — it will finish in the sauce. Meanwhile, place the guanciale in a cold, wide pan over medium-low heat and let the fat render slowly for 8–10 minutes until it turns golden and the edges crisp; starting from cold prevents burning and draws out maximum flavour. While the guanciale renders, beat the egg yolks and whole egg with both cheeses and a generous amount of coarsely cracked pepper until you have a thick, pale, creamy paste — this is the sauce. Just before draining, scoop out at least 250 ml of the cloudy pasta water and keep it within reach; the dissolved starch is what makes a smooth emulsion possible. Take the guanciale pan completely off the heat — this step is non-negotiable — then add the drained, steaming spaghetti directly into it and toss for 30 seconds so every strand absorbs the rendered fat. Pour the egg cream over the pasta, then add pasta water a small splash at a time, tossing and folding constantly; the residual heat sets the egg into a smooth, glossy sauce — stop adding water when the sauce coats the pasta without pooling. Taste and adjust salt — the guanciale and Pecorino are already salty — then add a little more pasta water if the sauce tightens as you plate. Serve immediately in warm bowls, finish with an extra shaving of Pecorino and several confident turns of the pepper mill."}},{"id":2,"origin":{"ja":"ルーマニア","en":"Romania","ro":"România"},"name":{"ja":"トライプスープ","en":"Tripe Soup","ro":"Ciorbă de burtă"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":27,"carb":8,"fat":20,"fib":1},"ingredients":{"ja":["下処理済み牛のホルモン（もつ）800g、5×1cmの短冊切り","中くらいのにんじん2本（約200g）","パセリの根1本","セロリアック1切れ（約150g）","大きな玉ねぎ1個","にんにく4片、すりつぶす","大きな卵3個の卵黄のみ","全脂サワークリーム300ml（脂肪分20%以上）","白ワインビネガー大さじ3","塩と白コショウ適量","フレッシュラビッジの葉（任意）"],"en":["800g pre-cleaned beef tripe, cut into 5×1 cm strips","2 medium carrots (about 200g)","1 parsley root","1 piece celeriac (about 150g)","1 large onion","4 garlic cloves, crushed","3 large eggs, yolks only","300ml full-fat sour cream (min. 20%)","3 tbsp white wine vinegar","salt and white pepper to taste","fresh lovage leaves (optional)"],"ro":["800g burtă de vită (precurățată și fiartă), tăiată fâșii de 5×1 cm","2 morcovi medii (aprox. 200g)","1 rădăcină de pătrunjel","1 bucată țelină rădăcină (aprox. 150g)","1 ceapă mare","4 căței de usturoi, pisați","3 ouă mari, gălbenușurile separate","300ml smântână grasă (min. 20%)","3 linguri oțet de vin alb","sare și piper alb după gust","frunze de leuștean proaspăt (opțional)"]},"howIsMade":{"ja":"もつが前処理されていない場合は、粗塩をこすりつけながら冷水でよく洗い、3〜4回すすぐ。塩水で弱火2〜3時間（圧力鍋なら40〜50分）、フォークで刺さるくらいになるまで煮る。水を切り、5×1cmの細切りにする。にんじん・パセリの根・セロリアック・玉ねぎを塩水2Lで40分煮て野菜を引き上げる。もつの細切りをスープに加えて15分煮る。卵黄とサワークリームを均一になるまで混ぜる。温度調節：熱いスープを何杯かずつクリーム混合物に加えながら泡立て器でよく混ぜてから鍋に戻す——分離を防ぐ。すりおろしにんにく・酢・塩・白コショウを加える。加えた後は再沸騰させない。熱々のまま盛り付ける。","en":"If tripe is not pre-cleaned, rub thoroughly with coarse salt under cold running water and rinse 3–4 times. Boil tripe in salted water for 2–3 hours on low heat until easily pierced with a fork — or 40–50 minutes in a pressure cooker. Drain and cut into 5×1 cm strips. Simmer carrots, parsley root, celeriac, and onion in 2L salted water for 40 minutes, then discard the vegetables (or blend and return for a thicker soup). Add the tripe strips to the broth and simmer 15 minutes. Whisk egg yolks with sour cream until smooth. Temper the mixture: ladle several spoonfuls of hot broth into the cream gradually, whisking constantly before pouring it back into the pot — this prevents curdling. Stir in crushed garlic, vinegar, salt, and white pepper. Do not boil again after adding the liaison — it will curdle. Serve piping hot with chilli and garlic sauce on the side."}},{"id":3,"servings":6,"tipType":"def","pairingsType":"def","nutrition":{"cal":770,"prot":21,"carb":27,"fat":62,"fib":1},"origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"キッシュ・ロレーヌ","en":"Quiche Lorraine","ro":"Quiche Lorraine"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ja":["ショートクラスト生地200g（1枚）空焼き済み","スモークラードン200gまたはスモークベーコンのさいの目切り","大きな卵3個","ダブルクリーム300ml（脂肪分35%以上）","グリュイエールチーズ60g（細かくすり下ろす）","フレッシュナツメグ小さじ1/4（すり下ろし）","塩と白こしょう適量","型に塗るバター"],"en":["200g shortcrust pastry (1 sheet), blind-baked","200g smoked lardons or diced smoked bacon","3 large eggs","300ml double cream (min. 35% fat)","60g Gruyère cheese, finely grated","1/4 tsp freshly grated nutmeg","salt and white pepper to taste","butter for greasing"],"ro":["200g aluat scurt (1 foaie), copt în alb","200g lardon afumat sau bacon afumat, tocat cuburi","3 ouă mari","300ml smântână grasă (min. 35%)","60g Gruyère, ras fin","1/4 linguriță nucșoară rasă proaspăt","sare și piper alb după gust","unt pentru uns forma"]},"howIsMade":{"ja":"生地を伸ばして23cmのタルト型に敷き、縁にしっかり押し当てる。20分冷蔵。180°Cで空焼き: クッキングシートを敷き、重石を入れて15分焼く; 重石とシートを取り除きさらに5分焼いて薄く金色にする。その間、ラードンを乾いたフライパンで脂が溶けて金色になるまで5分炒め、取り出す。卵、クリーム、ナツメグ、塩、白こしょうを泡立てる。ラードンをタルト底に均等に散らし、卵液を注ぎ、グリュイエールをかける。180°Cで25〜30分、ちょうど固まるまで焼く — 型を揺らすと中心がまだ軽く揺れるくらい。10分冷ましてから切り分ける。","en":"Roll out the pastry and line a 23cm tart tin, pressing firmly into the edges. Chill 20 minutes. Blind-bake at 180°C: line with baking paper, fill with baking beans, bake 15 minutes; remove beans and paper and bake a further 5 minutes until pale golden. Meanwhile, cook the lardons in a dry pan until golden and the fat is rendered, about 5 minutes; drain on paper. Whisk together eggs, cream, nutmeg, salt and white pepper. Scatter the lardons evenly over the base, pour the egg mixture over, and sprinkle with Gruyère. Bake 25–30 minutes at 180°C until just set — the centre should tremble slightly when you shake the tin. Cool 10 minutes before slicing. A true Quiche Lorraine contains no onion or vegetables, only lardons and the classic custard."}},{"id":4,"origin":{"ja":"スペイン","en":"Spain","ro":"Spania"},"name":{"ja":"ガスパチョ","en":"Gazpacho","ro":"Gazpacho"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":260,"prot":4,"carb":24,"fat":16,"fib":3},"ingredients":{"ja":["完熟トマト（サンマルツァーノまたはプラムトマト）800g、粗みじん切り","赤パプリカ1個（約200g）、種を取り粗みじん切り","きゅうり1本（約200g）、皮をむいて粗みじん切り","ニンニク2片","前日の白パン（耳なし）100g","エクストラバージンオリーブオイル60ml","赤ワインビネガー大さじ2","塩小さじ1","冷水200ml"],"en":["800g ripe tomatoes (San Marzano or plum), roughly chopped","1 red bell pepper (about 200g), deseeded and chopped","1 medium cucumber (about 200g), peeled and chopped","2 garlic cloves","100g day-old white bread, crusts removed","60ml extra-virgin olive oil","2 tbsp red wine vinegar","1 tsp fine salt","200ml cold water"],"ro":["800g roșii coapte (San Marzano sau roșii de câmp), tăiate cuburi","1 ardei gras roșu (aprox. 200g), curățat de semințe și tocat","1 castravete mediu (aprox. 200g), curățat și tocat","2 căței de usturoi","100g pâine albă veche de o zi, fără coajă","60ml ulei de măsline extravirgin","2 linguri oțet de vin roșu","1 linguriță sare fină","200ml apă rece"]},"howIsMade":{"ja":"パンを小さくちぎり、冷水200mlに10分浸す。トマト、パプリカ、きゅうり、にんにくをブレンダーに入れ、最高速で1分間攪拌する。浸したパンとその水、ビネガー、塩を加えて再び攪拌。モーターを回したままオリーブオイルを細く流し入れる——乳化がなめらかな舌触りを生む。塩とビネガーを味見して調整。なめらかに仕上げたければ細かいストレーナーで漉す。最低2時間冷蔵する——6〜8°Cのガスパチョは室温よりはるかに風味豊か。冷やしたボウルに注ぎ、オリーブオイルをひとたらしして出す。","en":"Tear the bread into pieces and soak in 200ml cold water for 10 minutes. Put tomatoes, pepper, cucumber, and garlic into a blender and blitz for 1 minute on high. Add the soaked bread along with its soaking water, vinegar, and salt; blitz again. With the motor running, pour olive oil in a thin stream — this emulsification gives the soup its silky texture. Taste and adjust salt and vinegar. Pass through a fine-mesh sieve for a smoother result, or leave it rustic. Chill at least 2 hours — gazpacho at 6–8°C is vastly more flavourful than at room temperature. Serve in chilled bowls with a drizzle of olive oil on top."}},{"id":5,"origin":{"ja":"日本","en":"Japan","ro":"Japonia"},"name":{"ja":"寿司","en":"Sushi","ro":"Sushi"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":430,"prot":15,"carb":51,"fat":14,"fib":3},"ingredients":{"ja":["寿司用短粒米2カップ","水2½カップ","米酢60ml","砂糖大さじ1","塩小さじ1","焼き海苔4枚（20×18cm）","刺身用サーモン200g、薄切り","熟したアボカド1個、スライス","小ぶりきゅうり½本、せん切り","醤油（つけ用）","わさびとガリ（酢漬けしょうが）添え"],"en":["2 cups Japanese short-grain sushi rice","2½ cups water","60ml rice vinegar","1 tbsp sugar","1 tsp salt","4 nori sheets (20×18 cm)","200g sashimi-grade salmon fillet, thinly sliced","1 ripe avocado, sliced","½ small cucumber, julienned","soy sauce to serve","wasabi and pickled ginger (gari) to serve"],"ro":["2 căni orez japonez pentru sushi (bob scurt)","2½ căni apă","60ml oțet de orez","1 lingură zahăr","1 linguriță sare","4 foi nori (20×18 cm)","200g file de somon sashimi-grade, feliat subțire","1 avocado copt, feliat","½ castravete mic, julienizat","sos de soia pentru servire","wasabi și ghimbir murat (gari) pentru servire"]},"howIsMade":{"ja":"米を炊く：冷水で水が澄むまで4〜5回研ぐ。米と水2½カップを強火で沸騰させ、蓋をして最弱火で12分、火を止めて10分蒸らす。ボウルで米酢・砂糖・塩を溶かす。ご飯を大きなバットに広げ、木のしゃもじで切るように合わせ酢を混ぜ込む——円を描くように混ぜると米が潰れる。濡れ布巾をかけて室温まで冷ます（冷蔵庫NG）。海苔を光沢面を下にして巻きすに置く。酢飯を海苔の¾に広げ（遠い端は3cm空ける）。手前の端にサーモン・アボカド・きゅうりを並べる。巻きすの手前を持ち上げ力強く巻き、ご飯粒で閉じる。濡らした包丁で8切れに切る。醤油・わさび・ガリを添えてすぐに出す。","en":"Cook the rice: rinse under cold water until the water runs clear (4–5 washes). Bring rice and 2½ cups water to a boil, cover, reduce to lowest heat for 12 minutes, then rest off heat 10 minutes. Dissolve vinegar, sugar, and salt in a small bowl. Spread cooked rice onto a large tray and fold the dressing in using a wooden paddle with cutting motions — do not stir in circles or the rice turns mushy. Cover with a damp cloth and cool to room temperature (not fridge). Lay a nori sheet shiny-side down on the bamboo mat. Spread seasoned rice over ¾ of the nori (leaving a 3 cm gap at the far edge). Arrange salmon, avocado, and cucumber along the near edge in a single row. Roll firmly from the near edge, pressing as you go; seal the bare nori with a few rice grains. Slice with a sharp, lightly wet knife into 8 rounds. Serve at once with soy sauce, wasabi, and pickled ginger."}},{"id":7,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":775,"prot":40,"carb":39,"fat":49,"fib":1},"origin":{"ja":"アメリカ","en":"USA","ro":"SUA"},"name":{"ja":"チーズバーガー","en":"Cheeseburger","ro":"Cheeseburger"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛ひき肉500g（脂肪20%）","ブリオッシュバンズ4個（半分に切ってトースト）","アメリカン・チェダーチーズ4枚","完熟トマト2個（厚めにスライス）","アイスバーグレタス大4枚","中玉ねぎ1個（薄い輪切り）","バーガーソース大さじ2（マヨネーズ、ケチャップ、マスタード、みじん切りピクルス）","塩と挽きたて黒こしょう"],"en":["500g ground beef (80% lean, 20% fat)","4 brioche buns, halved and toasted","4 slices American cheddar","2 ripe tomatoes, thickly sliced","4 large iceberg lettuce leaves","1 medium onion, thinly sliced into rings","2 tbsp burger sauce (mayo, ketchup, mustard, diced pickles)","salt and freshly ground black pepper"],"ro":["500g carne de vită tocată (80% carne / 20% grăsime)","4 chifle brioche, tăiate și prăjite","4 felii cheddar american","2 roșii coapte, tăiate felii groase","4 frunze de salată iceberg","1 ceapă medie, tăiată rondele subțiri","2 linguri sos de burger (maioneză, ketchup, muștar, castraveți murați tocați)","sare și piper negru proaspăt măcinat"]},"howIsMade":{"ja":"牛ひき肉に塩こしょうをして125gの玉を4つ作る。鋳鉄製スキレットを強火でよく煙が出るまで熱する。各玉を硬いスパチュラで鍋に直接押しつける — スマッシュ技法で90秒でカリカリの焼き目がつく。裏返し、チーズをのせて蓋を30秒して溶かす。バンズを切り面を下にして1分焼く。組み立て: 下のバンズ、バーガーソース、レタス、トマト、溶けたチーズ付きパティ、オニオンリング、上のバンズ。すぐに提供する。","en":"Season the ground beef with salt and pepper and divide into four 125g balls. Heat a cast-iron skillet over high heat until smoking. Press each ball flat on the pan with a firm spatula — the smash technique creates a crisp, lacy crust in about 90 seconds. Flip, add a slice of cheddar, and cover for 30 seconds to melt. Toast the buns cut-side down for 1 minute. Assemble: bottom bun, burger sauce, lettuce, tomato, patty with melted cheese, onion rings, top bun. Serve immediately — the crust fades fast."}},{"id":8,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":390,"prot":26,"carb":32,"fat":18,"fib":4},"origin":{"ja":"メキシコ","en":"Mexico","ro":"Mexic"},"name":{"ja":"タコス","en":"Tacos","ro":"Tacos"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛ひき肉500g（脂肪20%）","小さいコーントルティーヤ8枚（15cm）","クミンパウダー小さじ1","スモークパプリカ小さじ1","完熟トマト2個（ピコ・デ・ガヨ用に細かく刻む）","小さい白玉ねぎ1個（細かく刻む）","新鮮コリアンダー、ライムくし切り、サルサ、サワークリームを付け合わせに","塩と黒こしょう"],"en":["500g ground beef (80% lean)","8 small corn tortillas (15cm)","1 tsp ground cumin","1 tsp smoked paprika","2 ripe tomatoes, finely diced (for pico de gallo)","1 small white onion, finely diced","fresh cilantro, lime wedges, salsa, and sour cream for serving","salt and black pepper"],"ro":["500g carne de vită tocată (80% carne)","8 tortilla mici din porumb (15cm)","1 linguriță chimion măcinat","1 linguriță boia afumată","2 roșii coapte, tocate mărunt (pico de gallo)","1 ceapă albă mică, tocată mărunt","coriandru proaspăt, felii de lime, sos salsa și smântână pentru servit","sare și piper negru"]},"howIsMade":{"ja":"乾いたスキレットで強火に牛ひき肉を炒め、細かくほぐす — 最初はあまりかき混ぜず焼き色をつける。余分な脂を流す。クミン、パプリカ、塩こしょうを加えてさらに2分炒める。コーントルティーヤを温める: ガス火に直接かざして各面15秒焼き色がついて膨らむまで、または熱したフライパンで乾煎り。ピコ・デ・ガヨ: ダイス状のトマトと玉ねぎに塩ひとつまみとライム汁を混ぜる。タコ1個につき2枚のトルティーヤを重ねる。肉、ピコ・デ・ガヨ、コリアンダー、ライム汁、サルサまたはサワークリームをのせる。","en":"Brown the ground beef in a dry skillet over high heat, breaking it into fine crumbles — do not stir too much at first so the meat develops colour. Drain excess fat. Add cumin, paprika, salt and pepper; cook 2 more minutes. Warm the corn tortillas: hold them directly over a gas flame for 15 seconds per side until they blister and char lightly, or dry-toast in a hot pan. For quick pico de gallo: toss diced tomato with diced onion, a pinch of salt, and a squeeze of lime. Double-stack two tortillas per taco to prevent splitting. Spoon on the seasoned beef, then top with pico de gallo, cilantro leaves, a squeeze of lime, and salsa or sour cream to taste."}},{"id":9,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":375,"prot":23,"carb":11,"fat":19,"fib":3},"origin":{"ja":"インド","en":"India","ro":"India"},"name":{"ja":"チキンカレー","en":"Chicken Curry","ro":"Curry de pui"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["骨付き鶏もも肉・鶏脚800g、皮を取り除く","大玉ねぎ2個（約350g）、細かく刻む","缶詰のクラッシュトトマト400g","ショウガペースト大さじ1（3cmの塊から）","ニンニクペースト大さじ1（5片分）","ひまわり油大さじ3","クミンシード小さじ1","コリアンダーパウダー小さじ2","ガラムマサラ小さじ1","ターメリック小さじ½","カシミールチリパウダー小さじ1（またはマイルドパプリカ）","全脂ヨーグルト200ml、泡立てておく","塩 適量","仕上げ用の新鮮なコリアンダー"],"en":["800g bone-in chicken thighs and drumsticks, skin removed","2 large onions (about 350g), finely diced","400g canned crushed tomatoes","1 tbsp ginger paste (from a 3cm piece)","1 tbsp garlic paste (from 5 cloves)","3 tbsp sunflower oil","1 tsp cumin seeds","2 tsp ground coriander","1 tsp garam masala","½ tsp turmeric","1 tsp Kashmiri chili powder (or mild paprika)","200ml full-fat yogurt, whisked","Salt to taste","Fresh coriander leaves to finish"],"ro":["800g pulpe de pui cu os, fără piele","2 cepe mari (aprox. 350g), tăiate mărunt","400g roșii tocate din conservă","1 lingură pastă de ghimbir (bucată de 3 cm)","1 lingură pastă de usturoi (5 căței)","3 linguri ulei de floarea-soarelui","1 linguriță semințe de chimen","2 lingurițe coriandru măcinat","1 linguriță garam masala","½ linguriță turmeric","1 linguriță praf de ardei Kashmiri (sau boia dulce)","200ml iaurt gras, bătut","Sare după gust","Frunze de coriandru proaspăt pentru finisare"]},"howIsMade":{"ja":"厚底の鍋で中強火に油を熱する。クミンシードを加え30秒ぱちぱちと炒る。玉ねぎを加え、よくかき混ぜながら15〜18分、深いきつね色になるまで炒める——この焦がし炒めが風味の土台。ショウガとニンニクペーストを加え、生臭さが消えるまで2分炒める。コリアンダー、ターメリック、カシミールチリを加えて1分炒る。クラッシュトトマトを加え、中火で時々混ぜながら10分煮て、油がマサラの縁に分離するまで煮詰める。鶏肉を加えてマサラを絡め5分焼き付ける。火から下ろし、泡立てたヨーグルトを大さじ一杯ずつ加えて分離を防ぐ。中弱火に戻し蓋をして25〜30分煮込み、鶏肉が骨から外れやすくなるまで煮る。ガラムマサラを加え塩を調整し、新鮮なコリアンダーで仕上げる。バスマティライスかナンと共に供する。","en":"Heat oil in a heavy-bottomed pot over medium-high heat. Add cumin seeds and let sizzle 30 seconds. Add diced onions and fry, stirring often, for 15–18 minutes until deep golden — this caramelisation builds the flavour base. Stir in ginger and garlic paste; cook 2 minutes until the raw smell disappears. Add ground coriander, turmeric, and Kashmiri chili; stir 1 minute. Pour in crushed tomatoes and cook over medium heat, stirring often, for 10 minutes until the oil separates to the sides. Add chicken pieces, coat in masala, and sear 5 minutes. Remove from heat; stir in whisked yogurt one tablespoon at a time to prevent curdling. Return to medium-low heat, cover, and simmer 25–30 minutes until the chicken falls easily from the bone. Stir in garam masala, adjust salt, finish with fresh coriander. Serve with basmati rice or naan."}},{"id":10,"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":215,"prot":4,"carb":19,"fat":13,"fib":4},"origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"ラタトゥイユ","en":"Ratatouille","ro":"Ratatouille"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["ナス中1本（約300g）2cm角切り","ズッキーニ中2本（約400g）2cm輪切り","赤パプリカ1個、種を除いてざく切り","黄パプリカ1個、種を除いてざく切り","完熟プラムトマト4個（約400g）大まかに刻む","大玉ねぎ1個、ざく切り","ニンニク4片、薄切り","エクストラバージンオリーブオイル大さじ4","乾燥プロヴァンスハーブ小さじ1","塩と黒こしょう適量"],"en":["1 medium aubergine (about 300g), cut into 2cm cubes","2 medium courgettes (about 400g), cut into 2cm rounds","1 red bell pepper, deseeded and diced","1 yellow bell pepper, deseeded and diced","4 ripe plum tomatoes (about 400g), roughly chopped","1 large onion, diced","4 garlic cloves, thinly sliced","4 tbsp extra-virgin olive oil","1 tsp dried herbes de Provence","salt and black pepper to taste"],"ro":["1 vânătă medie (aprox. 300g), cuburi de 2cm","2 dovlecei medii (aprox. 400g), rondele de 2cm","1 ardei gras roșu, curățat și tocat","1 ardei gras galben, curățat și tocat","4 roșii prune coapte (aprox. 400g), tocate grosier","1 ceapă mare, tocată","4 căței de usturoi, feliați subțire","4 linguri ulei de măsline extravirgin","1 linguriță herbes de Provence uscate","sare și piper negru după gust"]},"howIsMade":{"ja":"ナスに軽く塩をふって15分置き、アクを抜いてからキッチンペーパーで水気を拭く。広めのフライパンでオリーブオイル大さじ1を中強火で熱する。ナスを薄く焼き色がつくまで約5分炒め、取り出す。ズッキーニ3分、パプリカ4分と順に炒めて取り出す。同じフライパンに残りのオイルを足し、玉ねぎを透明になるまで5分炒める。ニンニクを加えて1分。トマトとハーブを加え、トマトが崩れるまで10分煮る。全ての野菜を戻してやさしく混ぜ、塩こしょうで調味し、蓋なしで15〜20分弱火で煮込む。温かくても室温でも美味しく、翌日はさらに味が深まる。","en":"Lightly salt the aubergine cubes and set aside for 15 minutes to draw out bitterness, then pat dry. Heat 1 tbsp oil in a wide pan over medium-high heat. Saute the aubergine until lightly golden, about 5 minutes; remove and set aside. Saute the courgettes 3 minutes, then the peppers 4 minutes; remove each in turn. In the same pan, heat the remaining oil and sweat the onion until soft and translucent, 5 minutes. Add garlic and cook 1 minute. Add the tomatoes and herbes de Provence; cook 10 minutes until the tomatoes collapse into a sauce. Return all vegetables, stir gently, season with salt and pepper, and simmer uncovered 15–20 minutes until everything is tender and fragrant. Serve warm or at room temperature — ratatouille tastes even better the next day."}},{"id":11,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"スブラキ","en":"Souvlaki","ro":"Souvlaki"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["豚肩肉700g（3cm角に切る）","エクストラバージンオリーブオイル大さじ3","レモン1個分の果汁","にんにく3片（潰す）","乾燥ギリシャオレガノ小さじ2","乾燥タイム小さじ1","塩と挽きたて黒コショウ","木製または金属の串"],"en":["700g pork shoulder, cut into 3cm cubes","3 tbsp extra-virgin olive oil","juice of 1 lemon","3 garlic cloves, crushed","2 tsp dried Greek oregano","1 tsp dried thyme","salt and freshly ground black pepper","wooden or metal skewers"],"ro":["700g ceafă de porc, tăiată cuburi de 3 cm","3 linguri ulei de măsline extravirgin","sucul de la 1 lămâie","3 căței de usturoi, zdrobiți","2 linguriță oregano grecesc uscat","1 linguriță cimbru uscat","sare și piper negru proaspăt măcinat","frigărui de lemn sau metal"]},"howIsMade":{"ja":"ボウルにオリーブオイル、レモン汁、潰したにんにく、オレガノ、タイムを合わせる。豚肉の角切りを加えてよく絡め、蓋をして冷蔵庫で最低1時間（一晩が理想）マリネする。木の串は使う前に30分水に浸ける。串1本に5〜6個の肉を少し間隔を空けて刺す。強火（炭火が最適）で8〜10分、2分ごとに裏返しながら焼く。外側がこんがりと焦げ目がつき、肉汁が透明になったら完成。温かいピタパンにタジキソース、トマト、赤玉ねぎと添えてすぐに出す。","en":"Combine olive oil, lemon juice, crushed garlic, oregano and thyme in a bowl. Add the pork cubes, toss to coat thoroughly, cover and refrigerate for at least 1 hour — overnight is better. If using wooden skewers, soak them in water for 30 minutes. Thread 5-6 cubes per skewer, leaving small gaps between pieces. Grill over high heat (charcoal is ideal) for 8-10 minutes total, turning every 2 minutes, until the outside is charred and the juices run clear. The meat should be firm but not dry — pull it at 70°C internal. Serve immediately in warm pita with tzatziki, sliced tomatoes and red onion."},"nutrition":{"cal":420,"prot":35,"carb":3,"fat":29,"fib":0}},{"id":12,"origin":{"ja":"インド","en":"India","ro":"India"},"name":{"ja":"ダール","en":"Dhal","ro":"Dhal"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"veg","ingredients":{"ja":["赤レンズ豆（マスールダール）300g","ギー（またはサラダ油）大さじ2","大玉ねぎ1個、みじん切り","ニンニク4片、みじん切り","生姜2cm、すりおろし","カットトマト缶400g（または新鮮な大きなトマト3個）","ターメリック（粉）小さじ1","クミン（粉）小さじ1","コリアンダー（粉）小さじ1","ガラムマサラ小さじ½","赤唐辛子（粉）小さじ½","ココナッツミルク400ml（または水）","塩適量","生コリアンダーとレモンのくし切り添え"],"en":["300g dried red lentils (masoor dal)","2 tbsp ghee (or vegetable oil)","1 large onion, finely chopped","4 garlic cloves, minced","2 cm fresh ginger, grated","400g canned chopped tomatoes (or 3 large fresh tomatoes)","1 tsp ground turmeric","1 tsp ground cumin","1 tsp ground coriander","½ tsp garam masala","½ tsp ground red chilli","400ml coconut milk (or water)","salt to taste","fresh coriander and lemon wedges to serve"],"ro":["300g linte roșie uscată (masoor dal)","2 linguri ghee (sau ulei vegetal)","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","2 cm ghimbir proaspăt, ras","400g roșii din conservă, tăiate cuburi (sau 3 roșii mari proaspete)","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","1 linguriță coriandru măcinat","½ linguriță garam masala","½ linguriță ardei iute roșu măcinat","400ml lapte de nucă de cocos (sau apă)","sare după gust","coriandru proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"ja":"赤レンズ豆を冷水で3〜4回洗い、水が澄むまで繰り返す。大きな鍋でギーを中火で溶かす。玉ねぎを加え頻繁にかき混ぜながら10〜12分、きつね色になるまで炒める——このステップを省かないこと、炒めた玉ねぎが味の土台になる。にんにくと生姜を加えて1分炒める。ターメリック・クミン・コリアンダー・チリパウダーを入れ30秒、香りが立つまで炒める。トマトを加えて3〜4分煮詰める。洗ったレンズ豆とココナッツミルク（または水）を加え、弱火で蓋をせずに20〜25分、時々かき混ぜながら、レンズ豆が溶けてとろりとするまで煮る。ガラムマサラを加えて塩で味を調える。ライスかナンに添え、コリアンダーとレモンを搾って出す。","en":"Rinse the red lentils under cold water 3–4 times until the water runs clear. In a large pan melt ghee over medium heat. Add the onion and cook, stirring often, for 10–12 minutes until golden and soft — do not skip this step, the caramelised base is the backbone of flavour. Add garlic and ginger, fry 1 minute. Add turmeric, cumin, coriander, and red chilli, stir 30 seconds until fragrant. Add tomatoes, simmer 3–4 minutes until slightly thickened. Add the rinsed lentils and coconut milk (or water), reduce to a gentle simmer and cook uncovered for 20–25 minutes, stirring occasionally, until lentils collapse and the dhal is thick and creamy. Stir in garam masala and adjust salt. Thin with a little hot water if needed. Serve with rice or naan, topped with fresh coriander and a squeeze of lemon."},"nutrition":{"cal":490,"prot":21,"carb":56,"fat":19,"fib":13}},{"id":13,"timeMins":{"total":20,"active":20},"servings":4,"tipType":"def","pairingsType":"veg","origin":{"ja":"メキシコ","en":"Mexico","ro":"Mexic"},"name":{"ja":"ワカモレ","en":"Guacamole","ro":"Guacamole"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["完熟ハスアボカド3個","ライム2個の絞り汁（大さじ3程度）","小さい赤玉ねぎ1個、細かく刻む","完熟ローマトマト2個、種を除いてダイス状に切る","小さいハラペーニョ1個、細かく刻む（辛みを抑えるなら種を除く）","新鮮なコリアンダー15g、粗くきざむ","細かい天然塩小さじ1/2、好みで追加"],"en":["3 ripe Hass avocados","juice of 2 limes (about 3 tbsp)","1 small red onion, finely diced","2 ripe Roma tomatoes, deseeded and diced","1 small jalapeño, finely chopped (seeds removed for mild heat)","15g fresh cilantro, roughly chopped","1/2 tsp fine sea salt, plus more to taste"],"ro":["3 avocado Hass coapte","sucul a 2 lime (aprox. 3 linguri)","1 ceapă roșie mică, tocată mărunt","2 roșii Roma coapte, curățate de semințe și tocate","1 ardei jalapeno mic, tocat fin (fără semințe pentru mai puțin iute)","15g coriandru proaspăt, tocat grosier","1/2 linguriță sare fină de mare"]},"howIsMade":{"ja":"アボカドを縦半分に切り、種を取り除いてスプーンで果肉をボウルに入れる。すぐにライム汁を加える — 酸が変色を遅らせる。好みの食感になるようにフォークで潰す: 粗めか滑らかに。玉ねぎ、トマト、ハラペーニョ、コリアンダーを折り込む。塩で味を調える。ライムと塩を好みに調整。保存する場合は、ラップをグアカモレの表面に直接押しつけて空気を遮断する — ライム汁が種よりはるかに変色を防ぐ。色と風味が最良の2時間以内に食べる。","en":"Halve and stone the avocados. Scoop the flesh into a bowl and add the lime juice immediately — the acid slows browning. Mash with a fork to your preferred texture: very chunky or almost smooth. Fold in the diced onion, tomato, jalapeño, and cilantro. Season with salt. Taste and adjust lime and salt. To store, press cling film directly onto the surface of the guacamole to exclude air — the lime juice prevents browning far better than the avocado stone. Serve within 2 hours for best colour and flavour."},"nutrition":{"cal":200,"prot":3,"carb":13,"fat":17,"fib":9}},{"id":14,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ja":"ロシア","en":"Russia","ro":"Rusia"},"name":{"ja":"ボルシチ","en":"Borscht","ro":"Bors"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["生ビートルート500g、皮をむいて粗くすりおろす","白キャベツ300g、細切り","蝋質じゃがいも300g、2cm角に切る","中くらいのにんじん2本、せん切り","大きな玉ねぎ1個、みじん切り","ニンニク3片、みじん切り","トマトペースト大さじ2","牛または野菜ブロス1.5リットル","ひまわり油大さじ2","リンゴ酢大さじ1（深紅色を定着させるため）","塩と黒コショウ適量","サワークリームと新鮮なディル（盛り付け用）"],"en":["500g raw beetroot, peeled and coarsely grated","300g white cabbage, thinly shredded","300g waxy potatoes, cut into 2cm cubes","2 medium carrots, julienned","1 large onion, diced","3 garlic cloves, minced","2 tbsp tomato paste","1.5 litres beef or vegetable broth","2 tbsp sunflower oil","1 tbsp apple cider vinegar (to fix the deep red colour)","Salt and black pepper to taste","Sour cream and fresh dill to serve"],"ro":["500g sfeclă roșie crudă, curățată și rasă grosier","300g varză albă, feliată subțire","300g cartofi waxy, cuburi de 2 cm","2 morcovi medii, julien","1 ceapă mare, tocată","3 căței de usturoi, tocați","2 linguri pastă de roșii","1,5 litri supă de vită sau legume","2 linguri ulei de floarea-soarelui","1 lingură oțet de mere (pentru culoare vie)","Sare și piper după gust","Smântână și mărar proaspăt pentru servire"]},"howIsMade":{"ja":"中火で油を熱し、玉ねぎとにんじんを加えて7〜8分炒めてやわらかくする。トマトペーストとニンニクを加えて2分炒める。すりおろしたビートルートとリンゴ酢を加えて5分煮る——酢が深紅色を定着させる。熱いブロスを注いでじゃがいもを加える。沸騰したら弱火にして15分煮込む。キャベツを加えてさらに10分、ちょうど柔らかくなるまで煮る。塩、コショウ、必要であればさらに酢で味を調える。深い器に盛り、サワークリームと刻んだ新鮮なディルをのせて提供する。","en":"Heat oil over medium heat, add onion and carrots, and sauté 7–8 minutes until softened. Stir in tomato paste and garlic; cook 2 minutes. Add the grated beetroot and apple cider vinegar; cook 5 minutes — the vinegar fixes the deep red colour. Pour in the hot broth and add potatoes. Bring to a boil, reduce heat and simmer 15 minutes. Add shredded cabbage and simmer another 10 minutes until the cabbage is just tender and the potatoes are soft but not falling apart. Taste for salt, add pepper and extra vinegar if the soup needs brightness. Ladle into deep bowls and top with a generous spoonful of sour cream and fresh chopped dill."},"nutrition":{"cal":260,"prot":5,"carb":28,"fat":9,"fib":7}},{"id":15,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"ja":"アメリカ","en":"USA","ro":"SUA"},"name":{"ja":"アメリカンパンケーキ","en":"Pancakes","ro":"Clătite americane"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ja":["薄力粉200g","ベーキングパウダー小さじ2","砂糖大さじ1","塩小さじ1/2","全乳240ml","大きめの卵2個","溶かしバター30g（フライパン用も別途用意）","バニラエッセンス小さじ1"],"en":["200g plain flour","2 tsp baking powder","1 tbsp sugar","1/2 tsp salt","240ml whole milk","2 large eggs","30g melted butter, plus extra for the pan","1 tsp vanilla extract"],"ro":["200g făină albă","2 linguriță praf de copt","1 lingură zahăr","1/2 linguriță sare","240ml lapte integral","2 ouă mari","30g unt topit, plus extra pentru tigaie","1 linguriță extract de vanilie"]},"howIsMade":{"ja":"大きなボウルに薄力粉、ベーキングパウダー、砂糖、塩を合わせる。別のボウルで牛乳、卵、溶かしバター、バニラエッセンスを混ぜる。液体を粉類に加え、ゴムベラで軽く混ぜる — 少しダマが残るくらいがちょうどいい。混ぜすぎるとグルテンが出てパサパサになる。生地を5分休ませる。フライパンを中火で熱してバターを薄く塗り、キッチンペーパーで拭う。生地を1杯分（約80ml）流し入れ、表面に泡が立ち縁が乾いてきたら（2〜3分）裏返す。さらに1〜2分焼いて底面がきつね色になったら完成。本物のメープルシロップ、バター、季節のフルーツを添えてすぐ出す。","en":"In a large bowl, whisk together flour, baking powder, sugar and salt. In a second bowl, whisk milk, eggs, melted butter and vanilla. Pour the wet ingredients into the dry and fold gently with a spatula — a few lumps are fine and even desirable; over-mixing develops gluten and makes the pancakes tough. Rest the batter 5 minutes: the baking powder bubbles will rise to the surface. Heat a non-stick pan over medium heat, add a small knob of butter and wipe away the excess. Pour one ladle (about 80ml) of batter per pancake. Cook 2-3 minutes until bubbles break on the surface and the edges look set and dry. Flip and cook 1-2 minutes more until golden on the underside. Serve immediately — pancakes deflate as they cool. Top with real maple syrup, fresh butter and seasonal fruit."},"nutrition":{"cal":340,"prot":10,"carb":45,"fat":13,"fib":1}},{"id":16,"servings":4,"tipType":"def","pairingsType":"fish","origin":{"ja":"タイ","en":"Thailand","ro":"Thailanda"},"name":{"ja":"パッタイ","en":"Pad Thai","ro":"Pad Thai"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["乾燥フラットライスヌードル200g（30分水に浸す）","生エビ200g（殻と背ワタを取る）","卵2個","タマリンドペースト大さじ2","ナンプラー大さじ2","オイスターソース大さじ1","パームシュガーまたは砂糖小さじ1","中性油大さじ2","にんにく2かけ（みじん切り）","エシャロット1個（薄切り）","もやし100g","ねぎ3本（3cm切り）","ローストピーナッツ大さじ3（粗めに砕く）","ライム1個（くし切り）","乾燥チリ（好みで）"],"en":["200g dried flat rice noodles (soaked 30 min)","200g raw medium prawns, peeled and deveined","2 eggs","2 tbsp tamarind paste","2 tbsp fish sauce","1 tbsp oyster sauce","1 tsp palm sugar or brown sugar","2 tbsp neutral oil","2 cloves garlic, minced","1 shallot, thinly sliced","100g bean sprouts","3 spring onions, cut into 3cm pieces","3 tbsp roasted peanuts, roughly crushed","1 lime, cut into wedges","Dried chili flakes to serve"],"ro":["200g tăiței lat de orez (înmuiați 30 min)","200g creveți cruzi, curățați","2 ouă","2 linguri pastă de tamarind","2 linguri sos de pește","1 lingură sos de stridii","1 linguriță zahăr de palmier","2 linguri ulei neutru","2 căței de usturoi, tocați","1 șalotă, feliată","100g germeni de fasole","3 cepe verzi, tăiate 3cm","3 linguri alune prăjite, zdrobite","1 lime, pentru servire","Fulgi de ardei iute, după gust"]},"howIsMade":{"ja":"ライスヌードルを冷水に30分浸けてから水気を切る。タマリンドペースト・ナンプラー・オイスターソース・砂糖を小さなボウルで混ぜてソースを作る。中華鍋に油を引き、煙が出るくらいの強火に熱する。にんにくとエシャロットを30秒炒め、エビを加えて2分、ピンク色になるまで炒める。端に寄せ、卵を割り入れて30秒軽く炒り、エビと合わせる。水気を切った麺を加えてソースを回しかけ、2〜3分絶えずかき混ぜながら麺がソースを吸い、端が少し焦げ始めるまで炒める。火を止め、もやしと葱を加えて和える。潰したピーナッツ・ライムのくし切り・チリフレークを添えてすぐに盛り付ける。","en":"Soak rice noodles in cold water for 30 minutes, then drain. Mix tamarind paste, fish sauce, oyster sauce and sugar in a small bowl to make the sauce. Heat oil in a wok over very high heat until just smoking; fry garlic and shallot for 30 seconds, add prawns and cook 2 minutes until just pink. Push everything to the side, crack in eggs and scramble lightly for 30 seconds, then toss everything together. Add drained noodles and pour the sauce over; toss constantly for 2–3 minutes until the noodles absorb the sauce and begin to caramelise at the edges. Remove from heat, fold in bean sprouts and spring onions; serve immediately topped with crushed peanuts, a lime wedge and chili flakes to taste."},"nutrition":{"cal":380,"prot":18,"carb":40,"fat":13,"fib":2}},{"id":17,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ドイツ","en":"Germany","ro":"Germania"},"name":{"ja":"シュニッツェル","en":"Schnitzel","ro":"Schnitzel"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["骨なし豚ロースカツレツ4枚（各150g程度）、余分な脂肪を除く","塩こしょうで調味した薄力粉80g","大きな卵2個、溶きほぐす","細かい乾燥パン粉（ゼンメルブレーゼル）150g","揚げ用中性油（ひまわりまたは菜種）200ml","サーブ用くし切りレモン1個","塩と白こしょう"],"en":["4 boneless pork loin chops (about 150g each), trimmed","80g plain flour, seasoned with salt and pepper","2 large eggs, beaten","150g fine dry breadcrumbs (Semmelbrösel)","200ml neutral oil (sunflower or rapeseed) for frying","1 lemon, cut into wedges for serving","salt and white pepper"],"ro":["4 cotlete de porc din spată (aprox. 150g fiecare), dezosate și degresate","80g făină simplă, condimentată cu sare și piper","2 ouă mari, bătute","150g pesmet fin uscat (Semmelbrösel)","200ml ulei neutru (floarea-soarelui sau rapiță) pentru prăjit","1 lămâie, tăiată fâșii pentru servit","sare și piper alb"]},"howIsMade":{"ja":"各カツレツを2枚のラップの間に挟み、肉叩きまたは麺棒で均一に4〜5mmの厚さに叩く — 薄く均一な切り身が本格シュニッツェルの定義的特徴。水気を拭き取り、塩と白こしょうで調味する。浅い皿を3つ準備する: 調味した小麦粉、溶き卵、パン粉。各シュニッツェルを小麦粉に通して（余分を振り落とす）、卵に浸け、パン粉にしっかり押しつける — あまり強く押さないこと。衣が軽くなっていると熱油の中で膨れ上がりバリっとした食感になる。広いフライパンに1cmの深さの油を注いで170〜180°Cに熱する。各面を2〜3分、濃い黄金色でカリッとするまで揚げ焼きにする。ワイヤーラックで水を切る — 絶対にキッチンペーパーの上に置かない（蒸気が衣をふやかす）。すぐにレモンのくし形と一緒に提供する。","en":"Place each pork chop between two sheets of cling film and beat with a meat mallet or rolling pin until evenly 4–5mm thick — the thin, even cut is the defining feature of a proper schnitzel. Pat dry and season with salt and white pepper. Set up three shallow dishes: seasoned flour, beaten eggs, breadcrumbs. Coat each schnitzel in flour (shake off the excess), dip in egg, then press firmly into breadcrumbs to coat evenly — do not press the crumb down too hard; it should stay airy so it puffs and blisters in hot oil. Pour oil into a wide pan to a depth of 1cm and heat to 170–180°C. Fry 2–3 minutes per side until deep golden and crisp. Drain on a wire rack — never on paper towel, which traps steam and kills the crust. Serve immediately with lemon wedges."},"nutrition":{"cal":570,"prot":45,"carb":15,"fat":35,"fib":1}},{"id":18,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ブラジル","en":"Brazil","ro":"Brazilia"},"name":{"ja":"フェイジョアーダ","en":"Feijoada","ro":"Feijoada"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["黒豆400g（前夜から水に浸す）","スモーク豚スペアリブ400g","チョリソーまたはスモークソーセージ200g（輪切り）","スモークベーコン200g（さいの目切り）","玉ねぎ大1個（みじん切り）","にんにく4片（みじん切り）","ローリエ2枚","オリーブオイル大さじ3","塩・コショウ・唐辛子フレーク適量"],"en":["400g dried black beans, soaked overnight","400g smoked pork ribs","200g chourico or smoked sausage, sliced","200g smoked bacon, diced","1 large onion, chopped","4 garlic cloves, minced","2 bay leaves","3 tbsp olive oil","salt, pepper and chilli flakes to taste"],"ro":["400g fasole neagră uscată, înmuiată 12 ore","400g coaste de porc afumate","200g chouriço sau cârnați afumați, feliați","200g bacon afumat, tăiat cuburi","1 ceapă mare, tocată","4 căței de usturoi, tocați","2 foi de dafin","3 linguri ulei de măsline","sare, piper și fulgi de ardei iute după gust"]},"howIsMade":{"ja":"浸けておいた黒豆を水洗いし、大きな鍋に入れて5cmほど上まで水を加える。スモークリブとローリエを加え、沸騰後は中火で1時間、アクを取りながら煮る。別のフライパンにオリーブオイルを熱し、玉ねぎを8分炒めてから、にんにくを加えてさらに2分炒める。チョリソーとベーコンを加えて5分焼き色をつける。これをすべて豆の鍋に移してよく混ぜ、弱火で45〜60分、黒豆が完全に柔らかくなりスープが濃くなるまで煮込む。木べらで鍋の縁に豆を押しつけて潰すと、自然にとろみがつく。塩・コショウで味を調える。白ご飯、新鮮なオレンジスライス、ファロファ（バターで炒めたキャッサバ粉）と一緒に深皿で提供する。","en":"Drain the soaked beans and place in a large pot with fresh cold water to cover by 5cm. Add the smoked ribs and bay leaves. Bring to a boil, then simmer over medium heat for 1 hour, skimming any foam. Meanwhile, heat olive oil in a skillet, saute onion 8 minutes until soft and golden, add garlic and cook 2 minutes more. Add chourico and bacon, brown for 5 minutes. Transfer everything to the bean pot, stir well and simmer on low heat for 45-60 minutes until the beans are completely tender and the broth has thickened. Crush a handful of beans against the pot side with a wooden spoon — this thickens the stew naturally. Adjust salt and pepper. Serve in deep bowls with white rice, fresh orange slices and farofa (toasted manioc flour)."},"nutrition":{"cal":620,"prot":38,"carb":45,"fat":32,"fib":14}},{"id":19,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"中国","en":"China","ro":"China"},"name":{"ja":"宮保鶏丁","en":"Kung Pao Chicken","ro":"Pui Gong Bao"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["鶏胸肉500g、2cm角に切る","無塩ローストピーナッツ100g","干し中国唐辛子8〜10本","ネギ4本、3cm長に切る","ニンニク3片、薄切り","ショウガ2cm、薄切り","四川唐辛子油またはひまわり油大さじ2","漬け込みタレ：醤油大さじ1・片栗粉小さじ1・ごま油小さじ1","ソース：醤油大さじ2・鎮江黒米酢大さじ1・砂糖大さじ1・片栗粉小さじ1・水大さじ2"],"en":["500g chicken breast, cut into 2cm cubes","100g unsalted roasted peanuts","8–10 dried Chinese chili peppers (Sichuan or similar)","4 spring onions, cut into 3cm pieces","3 garlic cloves, thinly sliced","2cm piece of ginger, thinly sliced","2 tbsp Sichuan chili oil or sunflower oil","Marinade: 1 tbsp soy sauce, 1 tsp cornstarch, 1 tsp sesame oil","Sauce: 2 tbsp soy sauce, 1 tbsp black rice vinegar (Chinkiang), 1 tbsp sugar, 1 tsp cornstarch, 2 tbsp water"],"ro":["500g piept de pui, tăiat cuburi de 2 cm","100g arahide prăjite nesărate","8–10 ardei iuți uscați chinezești (chili Sichuan)","4 cepe verzi, tăiate bucăți de 3 cm","3 căței de usturoi, feliați subțire","1 bucată ghimbir de 2 cm, feliată subțire","2 linguri ulei cu ardei Sichuan sau ulei de floarea-soarelui","Marinată: 1 lingură sos de soia, 1 linguriță amidon de porumb, 1 linguriță ulei de susan","Sos: 2 linguri sos de soia, 1 lingură oțet de orez negru (Chinkiang), 1 lingură zahăr, 1 linguriță amidon de porumb, 2 linguri apă"]},"howIsMade":{"ja":"鶏肉をマリネ材料と和えて15分置く。ソースの材料を小さなボウルで混ぜておく。中華鍋を最強火で煙が出るまで熱し、油を加えて干し唐辛子を30秒炒めて色が変わるまで（焦がさない）炒める。鶏肉を加えて3〜4分かき混ぜず焼き、片面がきつね色になったらひっくり返してさらに2分。ニンニク、ショウガ、ネギの白い部分を加えて1分炒める。ソースを流し込み1分激しく炒めて絡める。ピーナッツとネギの緑の部分を加えて30秒炒める。ジャスミンライスと一緒にすぐ提供する。","en":"Toss chicken with marinade ingredients and leave for 15 minutes. Combine sauce ingredients in a small bowl. Heat wok over highest heat until smoking; add oil and fry dried chilis and Sichuan peppercorns 30 seconds until darkened but not black — they should smell toasted, not burnt. Add chicken pieces and sear 3–4 minutes without stirring, until golden on one side; toss and cook 2 more minutes. Add garlic, ginger, and the white parts of the spring onion; stir-fry 1 minute. Pour in the sauce, toss vigorously for 1 minute until thickened and clinging to the chicken. Throw in peanuts and green spring onion tops; toss 30 seconds. Serve immediately with jasmine rice."},"nutrition":{"cal":400,"prot":32,"carb":11,"fat":22,"fib":2}},{"id":20,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ja":"イギリス","en":"United Kingdom","ro":"Marea Britanie"},"name":{"ja":"フィッシュ・アンド・チップス","en":"Fish and Chips","ro":"Fish and Chips"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["タラまたはハドック（白身魚）の切り身4枚（各約180g）、皮なし","粉質のじゃがいも1kg（キタアカリなど）、厚めに切る","揚げ油（植物油 約2リットル）","衣：薄力粉180g（まぶし用に追加）","ベーキングパウダー小さじ1","塩小さじ1","キンキンに冷えたラガービールまたはペールエール 300ml","塩とモルトビネガー（盛り付け用）"],"en":["4 cod or haddock fillets (about 180g each), skin removed","1kg floury potatoes (Maris Piper or King Edward), cut into thick chips","Vegetable oil for deep-frying (about 2 litres)","Batter: 180g plain flour, plus extra for dusting","1 tsp baking powder","1 tsp fine salt","300ml ice-cold lager or pale ale","Salt and malt vinegar to serve"],"ro":["4 fileuri de cod sau haddock (aprox. 180g fiecare), fără piele","1 kg cartofi floury (Maris Piper sau King Edward), tăiați bețe groase","Ulei vegetal pentru prăjit (aprox. 2 litri)","Pentru aluat: 180g făină tip 550 + extra pentru tăvălit","1 linguriță praf de copt","1 linguriță sare fină","300ml bere blondă rece (lager sau ale)","Sare și oțet de malt pentru servire"]},"howIsMade":{"ja":"チップスを2段階で揚げる：140°Cで8分間、色づかず柔らかくなるまで揚げ、取り出してラックで冷ます。衣を作る：薄力粉、ベーキングパウダー、塩を混ぜ、氷冷ビールを少しずつ加えてダブルクリームの固さになるまで泡立てる——混ぜすぎない。魚の切り身をキッチンペーパーで完全に乾かす。油を185°Cに熱する。各切り身に薄力粉をまぶして余分を払い、衣に浸けて数秒たれさせる。6〜8分揚げる——途中で熱い油を上から回しかけてむらなくカリカリに——衣が深い黄金色で香ばしくなるまで。紙の上で油切り。油を200°Cに上げてチップスを3〜4分二度揚げして全体を金色カリカリに。すぐに塩とモルトビネガーと一緒に提供する。","en":"Cook chips in two stages: fry at 140°C for 8 minutes until soft but not coloured; drain and cool on a rack. Make the batter by whisking flour, baking powder, and salt together, then gradually whisk in ice-cold beer until the consistency of double cream — do not overmix. Pat fish fillets completely dry with paper towels. Heat oil to 185°C. Dust each fillet in the extra flour, shake off excess, dip into batter and let it drip for a few seconds. Fry 6–8 minutes — halfway through, spoon hot oil over the top for even crisping — until the batter is deep golden and crunchy. Drain on paper. Raise oil to 200°C and fry chips a second time for 3–4 minutes until golden and crisp all over. Serve immediately with salt and malt vinegar."},"nutrition":{"cal":850,"prot":35,"carb":85,"fat":42,"fib":5}},{"id":21,"origin":{"ja":"ベトナム","en":"Vietnam","ro":"Vietnam"},"name":{"ja":"フォー","en":"Pho","ro":"Pho"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":225,"active":75},"pairingsType":"def","ingredients":{"ja":["乾燥ライスヌードル（バインフォー、幅5mm）400g","牛バラ肉または牛フランク500g（だし用）","牛骨（骨髄または関節骨）1kg","玉ねぎ2個、半分に切る","生姜5cm、縦半分に切る","スターアニス3個","シナモンスティック5cm","クローブ3個","ナンプラー（ニョクマム）大さじ2","砂糖小さじ1","塩適量","フレッシュもやし200g","香菜（パクチー）とタイバジル","赤唐辛子2本、薄切り（テーブル用）","ライム2個、くし形切り（テーブル用）","ホイシンソースとスリラチャソース（テーブル用）"],"en":["400g dried rice noodles (banh pho, 5mm width)","500g beef brisket or flank (for the broth)","1kg beef bones (marrow or knuckle)","2 medium onions, halved","5 cm fresh ginger, halved lengthways","3 star anise","1 cinnamon stick (5 cm)","3 cloves","2 tbsp fish sauce (nuoc mam)","1 tsp sugar","salt to taste","200g fresh bean sprouts","fresh coriander and Thai basil","2 red chillies, sliced (at the table)","2 limes, quartered (at the table)","hoisin sauce and sriracha (at the table)"],"ro":["400g tăiței de orez (banh pho, lățime 5mm), uscați","500g piept de vită sau flacără (pentru supă)","1kg oase de vită (măduvă sau coadă)","2 cepe medii, înjumătățite","5 cm ghimbir proaspăt, înjumătățit","3 anasoane stelate","1 baton de scorțișoară (5 cm)","3 cuișoare","2 linguri sos de pește (nuoc mam)","1 linguriță zahăr","sare după gust","200g muguri de soia proaspeți","coriandru proaspăt și busuioc thai","2 ardei iuți roșii, feliați (la masă)","2 lămâi verzi, tăiate în sferturi (la masă)","sos hoisin și sos sriracha (la masă)"]},"howIsMade":{"ja":"牛骨を沸騰した湯で5分間下茹でし、お湯を捨てて洗い流す——アクと不純物を除いてスープを澄ませる。玉ねぎとしょうがの切り口をガスコンロの直火またはグリルで縁が軽く焦げるまで炙る（各面2〜3分）——この工程がスープに琥珀色の深みをもたらす。大きな鍋に冷水3Lを入れ、骨・バラ肉・炙った玉ねぎとしょうが・スターアニス・シナモン・クローブを加える。強火で沸騰させてから最弱火に落とし、蓋をせずに3時間煮る。時々アクと脂をすくう。1時間半経ったらバラ肉を取り出して冷まし、薄切りにする。だしを細かいストレーナーで漉し、ナンプラー・砂糖・塩で味を調える。ヌードルを冷水に20分浸し、沸騰した湯で30秒茹でて水を切る。器に分けて熱々のスープを注ぎ、肉を盛る。もやし・コリアンダー・タイバジル・唐辛子・ライム・ソースをテーブルに添えて出す。","en":"Blanch beef bones in boiling water for 5 minutes, discard water, rinse well — this removes impurities and keeps the broth clear. Char the onion halves and ginger directly over a gas flame or under the grill until lightly blackened on the edges (2–3 minutes per side) — this gives the broth its golden colour and depth. Fill a large pot with 3L cold water, add bones, brisket, charred onion, ginger, star anise, cinnamon, and cloves. Bring to a boil, reduce to a bare simmer, cook uncovered for 3 hours, skimming fat periodically. Remove the brisket after 1½ hours, let cool, slice thinly. Strain broth through a fine sieve, season with fish sauce, sugar, and salt. Soak noodles in cold water 20 minutes, boil 30 seconds, drain. Divide noodles into bowls, ladle boiling broth over, add meat slices. Serve with bean sprouts, coriander, basil, chilli, lime, and sauces at the table."},"nutrition":{"cal":380,"prot":28,"carb":42,"fat":10,"fib":2}},{"id":22,"origin":{"ja":"スペイン","en":"Spain","ro":"Spania"},"name":{"ja":"パエリア","en":"Paella","ro":"Paella"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"fish","ingredients":{"ja":["ボンバ米（または短粒米）300g","骨なし鶏もも肉400g、一口大に切る","生海老（殻付きまたは殻なし）300g","ムール貝400g、洗ってひげを取る","大玉ねぎ1個、みじん切り","ニンニク4片、みじん切り","赤パプリカ1個、さいの目切り","カットトマト缶400g","サフランスレッド小さじ½（温水大さじ2に浸す）","スモークパプリカ（ピメントン・デ・ラ・ベラ）小さじ1","温めた鶏だし800ml","オリーブオイル大さじ3","塩と黒コショウ適量","パセリとレモンのくし切り添え"],"en":["300g bomba rice (or short-grain rice)","400g boneless chicken thighs, cut into pieces","300g raw prawns (shell-on or peeled)","400g mussels, scrubbed and debearded","1 large onion, finely chopped","4 garlic cloves, minced","1 red bell pepper, diced","400g canned crushed tomatoes","½ tsp saffron threads (soaked in 2 tbsp warm water)","1 tsp smoked paprika (pimentón de la Vera)","800ml warm chicken stock","3 tbsp olive oil","salt and black pepper to taste","fresh parsley and lemon wedges to serve"],"ro":["300g orez bomba (sau orez cu bob scurt)","400g pulpe de pui dezosate, tăiate în bucăți","300g creveți crudi (cu coajă sau fără)","400g midii, spălate și curățate","1 ceapă mare, tocată","4 căței de usturoi, tocați","1 ardei gras roșu, tăiat cuburi","400g roșii din conservă, concasate","½ linguriță șofran (înmuiat în 2 linguri apă caldă)","1 linguriță boia de ardei afumată (pimentón de la Vera)","800ml fond de pui cald","3 linguri ulei de măsline","sare și piper negru după gust","pătrunjel proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"ja":"サフランを温水大さじ2に浸す、パエリアパン（または幅広の浅い鍋）にオリーブオイルを入れて中強火に熱する。鶏肉を塩こしょうし、各面4〜5分ずつ焼いてしっかりきつね色に仕上げたら取り出す、同じ鍋で玉ねぎを5分炒め、にんにくと赤パプリカを加えてさらに3分炒める。カットトマトとスモークパプリカを加えて3〜4分、とろりと濃くなるまで煮詰める——これがソフリト、パエリアの魂、米を加えて1分炒める。サフランと浸け水ごと温かいだしを注ぎ均一に広げる、鶏肉を戻す。中火に調整し、以後かき混ぜない——だしを加えたらパエリアは絶対にかき混ぜない、蓋をせず10分加熱。海老とムール貝を上に並べて軽く押さえる、8〜10分加熱し海老がピンク色、貝が開いたら完成（開かない貝は除く）。ソカラットが欲しければ最後の2分だけ強火に——ぱちぱちという音を聞く、5分休ませる、パセリを散らしてレモンを添えて出す。","en":"Soak saffron in 2 tbsp warm water; heat olive oil in a paella pan (or wide shallow pan) over medium-high heat. Season chicken, sear 4–5 minutes per side until deeply golden; remove and set aside; in the same pan fry onion 5 minutes, add garlic and red pepper, cook 3 more minutes. Add crushed tomatoes and smoked paprika, cook 3–4 minutes until thickened — this is the sofrito, the soul of the paella; add the rice, stir 1 minute to toast lightly. Pour in the warm stock with the saffron and its soaking water, spread evenly; return the chicken. Adjust to medium heat and do not stir again — never stir paella once the stock is added; cook uncovered for 10 minutes. Place prawns and mussels on top, pressing gently into the rice; cook 8–10 minutes more until prawns are pink and mussels open (discard any that stay shut). For socarrat (the coveted crispy bottom crust), raise to high heat the last 2 minutes — listen for a light crackling; rest 5 minutes; garnish with parsley and serve with lemon wedges."},"nutrition":{"cal":520,"prot":32,"carb":58,"fat":16,"fib":3}},{"id":23,"servings":4,"tipType":"def","pairingsType":"korean","origin":{"ja":"韓国","en":"South Korea","ro":"Coreea de Sud"},"name":{"ja":"ビビンバ","en":"Bibimbap","ro":"Bibimbap"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["短粒白米2カップ","牛サーロイン200g（薄切り）","ズッキーニ1本（せん切り）","にんじん1本（せん切り）","ほうれん草200g","もやし100g","しいたけ4枚（軸を取る）","卵4個","コチュジャン大さじ4","ごま油大さじ3","醤油大さじ2","砂糖小さじ1","にんにく3かけ（みじん切り）","炒りごま（飾り用）"],"en":["2 cups short-grain white rice","200g beef sirloin, thinly sliced against the grain","1 medium courgette, julienned","1 medium carrot, julienned","200g baby spinach","100g bean sprouts","4 shiitake mushrooms, stems removed","4 eggs","4 tbsp gochujang (Korean chili paste)","3 tbsp sesame oil","2 tbsp soy sauce","1 tsp sugar","3 cloves garlic, minced","Sesame seeds to garnish"],"ro":["2 căni orez cu bob scurt","200g vită (antricot), felii subțiri","1 dovlecel mediu, julien","1 morcov mediu, julien","200g spanac baby","100g germeni de fasole","4 ciuperci shiitake, fără codiță","4 ouă","4 linguri gochujang (pastă de ardei coreean)","3 linguri ulei de susan","2 linguri sos de soia","1 linguriță zahăr","3 căței de usturoi, tocați","Semințe de susan, pentru decor"]},"howIsMade":{"ja":"米を2.5カップの水で炊く：沸騰したら蓋をして最弱火で12分、火を止めて10分蒸らす。牛肉を醤油大さじ1・ごま油大さじ1・砂糖小さじ1・にんにく半量で15分漬け込む。ほうれん草を塩ゆでで30秒茹で、水気をよく絞りごま油小さじ1と塩で和える；もやしをにんにくと塩で2分炒める；にんじんとズッキーニを各2分ごま油で別々に炒める。漬け込んだ牛肉を強火で3〜4分焦げ目がつくまで焼く；しいたけを醤油少量で2分炒める；ごま油で目玉焼きを作る。ご飯を4つの器に分け、野菜と肉を扇形に盛り付け、中央に卵を置き、コチュジャン大さじ1をのせてごま油とごまを散らす——食べる前によく混ぜる。","en":"Cook rice in 2.5 cups water: bring to a boil, cover and simmer on the lowest heat for 12 minutes, then rest off the heat for 10 minutes. Marinate beef with 1 tbsp soy sauce, 1 tbsp sesame oil, 1 tsp sugar and half the garlic for 15 minutes. Blanch spinach 30 seconds in boiling salted water, squeeze dry, season with 1 tsp sesame oil and salt; sauté bean sprouts 2 minutes with garlic and salt; stir-fry carrot and courgette separately for 2 minutes each with a drizzle of sesame oil. Sear marinated beef over high heat 3–4 minutes until caramelised; slice shiitake and sauté 2 minutes with a splash of soy sauce; fry eggs sunny-side up in sesame oil. Divide rice among 4 bowls, arrange vegetables and beef in sections, place an egg in the centre, add 1 tbsp gochujang per bowl, drizzle with sesame oil and scatter sesame seeds — mix everything together before eating."},"nutrition":{"cal":450,"prot":22,"carb":65,"fat":12,"fib":5}},{"id":24,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"ja":"シリア","en":"Syria","ro":"Siria"},"name":{"ja":"フムス","en":"Hummus","ro":"Hummus"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["茹でたひよこ豆400g（缶詰1缶）、皮を取り除いたもの","タヒニ80g（良質なもの、よく混ぜる）","レモン2個の絞り汁（大さじ4程度）","ニンニク2片（おろし）","細かい塩小さじ1/2","氷水3–5大さじ","仕上げ用エクストラバージンオリーブオイル大さじ2"],"en":["400g (1 can) cooked chickpeas, skins removed","80g tahini (good quality, stirred well)","juice of 2 lemons (about 4 tbsp)","2 garlic cloves, grated","1/2 tsp fine salt","3–5 tbsp ice-cold water","2 tbsp extra-virgin olive oil for finishing"],"ro":["400g năut gătit (1 conservă), coaja îndepărtată","80g pastă de susan (tahini de calitate, bine amestecată)","sucul a 2 lămâi (aprox. 4 linguri)","2 căței de usturoi, rași","1/2 linguriță sare fină","3–5 linguri apă rece cu gheață","2 linguri ulei de măsline extravirgin pentru finalizare"]},"howIsMade":{"ja":"最も滑らかなフムスのために、ひよこ豆を一粒ずつやさしく押して皮を取り除く — 小さな手間が大きな差を生む。フードプロセッサーでタヒニとレモン汁だけを1分間処理して色が薄くなりクリーミーになるまで混ぜる。ニンニクと塩を加えて30秒処理。ひよこ豆を加えて1分処理。機械を動かしながら氷水を大さじ1ずつ垂らす — 冷たい水がフムスを軽くふんわりとさせる。側面をこそげながら計3–5分処理し完全に滑らかにする。味を確認しレモンと塩を調整。ボウルに広げてオリーブオイルをたらし、スモークパプリカまたはスマックをかけて仕上げる。冷蔵で5日保存可能。","en":"For the smoothest hummus, pop the skins off the chickpeas by gently squeezing each one — a small step that makes a big difference. In a food processor, blitz tahini and lemon juice alone for 1 minute until pale and creamy. Add garlic and salt; blitz 30 seconds. Add the chickpeas and process 1 minute. With the machine running, drizzle in ice-cold water tablespoon by tablespoon — the cold water aerates and lightens the hummus. Process 3–5 minutes total, scraping down the sides, until completely smooth. Taste and adjust lemon and salt. Spread in a bowl, drizzle with olive oil, and finish with smoked paprika or sumac. Keeps refrigerated up to 5 days."},"nutrition":{"cal":220,"prot":8,"carb":22,"fat":12,"fib":6}},{"id":25,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"ja":"レバノン","en":"Lebanon","ro":"Liban"},"name":{"ja":"タブーレ","en":"Tabbouleh","ro":"Tabbouleh"},"category":{"ja":"サラダ","en":"Salad","ro":"Salate"},"ingredients":{"ja":["イタリアンパセリ200g（葉のみ、細かく刻む）","細挽きブルグル50g（冷水に20分浸けてよく絞る）","完熟トマト3個（約300g、小さく角切り）","細ねぎ4本（細かく切る）","フレッシュミントの葉20g（細かく刻む）","レモン2個分の果汁（約80ml）","エクストラバージンオリーブオイル大さじ4、塩と黒コショウ適量"],"en":["200g flat-leaf parsley, leaves only, finely chopped","50g fine bulgur wheat, soaked in cold water 20 min then squeezed dry","3 ripe tomatoes (about 300g), finely diced","4 spring onions, finely sliced","20g fresh mint leaves, finely chopped","juice of 2 lemons (about 80ml)","4 tbsp extra-virgin olive oil, salt and black pepper to taste"],"ro":["200g pătrunjel plat, frunze tocate mărunt","50g bulgur fin, înmuiat 20 min în apă rece, stors bine","3 roșii coapte (cca 300g), tăiate cuburi mici","4 cepe verzi, tocate fin","20g frunze de mentă proaspătă, tocate mărunt","sucul de la 2 lămâi (cca 80ml)","4 linguri ulei de măsline extravirgin, sare și piper negru după gust"]},"howIsMade":{"ja":"ブルグルを冷水に20分浸け、ざるに上げた後、手でしっかり水気を絞る — 湿っていなく乾燥した状態が理想。パセリをできるだけ細かく刻む。本物のタブーレはハーブが主役の料理で、穀物が主役ではない。パセリ、ミント、細ねぎ、トマト、絞ったブルグルを大きなボウルに合わせる。レモン汁とオリーブオイルを加えてよく混ぜ、10分置く — レモン汁がブルグルをなじませ、ハーブの香りを引き出す。塩・コショウで味を調えて室温で提供する。","en":"Soak the bulgur in cold water for 20 minutes, then drain and squeeze out as much water as possible with your hands — it should be dry, not wet. Chop the parsley as finely as you can; authentic tabbouleh is herb-forward, not grain-forward. Combine parsley, mint, spring onions, tomatoes and squeezed bulgur in a large bowl. Add lemon juice and olive oil, toss well and let rest 10 minutes — the lemon juice continues to soften the bulgur and blooms the herbs. Adjust salt and pepper. Serve at room temperature. True tabbouleh is a parsley salad with bulgur, not a bulgur salad with a little parsley."},"nutrition":{"cal":180,"prot":4,"carb":20,"fat":10,"fib":4}},{"id":26,"servings":4,"tipType":"pasta","pairingsType":"pasta","origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"リゾット","en":"Risotto","ro":"Risotto"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["アルボリオまたはカルナローリ米320g","大きめシャロット1個または小玉ねぎ1個（みじん切り）","無塩バター50g（分割使用）","辛口白ワイン100ml","温めた鶏または野菜の出汁1.2L","パルミジャーノ・レッジャーノ40g（すり下ろしたて）","エクストラバージンオリーブオイル大さじ1","塩と白こしょう適量"],"en":["320g Arborio or Carnaroli rice","1 large shallot or small onion, finely diced","50g unsalted butter, divided","100ml dry white wine","1.2L warm chicken or vegetable stock","40g Parmigiano-Reggiano, freshly grated","1 tbsp extra-virgin olive oil","salt and white pepper to taste"],"ro":["320g orez Arborio sau Carnaroli","1 șalotă sau ceapă mică, tocată fin","50g unt nesărat, împărțit","100ml vin alb sec","1,2L supă caldă de pui sau legume","40g Parmigiano-Reggiano, ras proaspăt","1 lingură ulei de măsline extravirgin","sare și piper alb după gust"]},"howIsMade":{"ja":"調理中は出汁を常に弱火で温めておく — 冷たい出汁を加えると調理が止まり、クリーミーさが台無しになる。厚底の広いフライパンにオリーブオイルとバターの半量を中火で熱する。シャロットを3分、柔らかくなるまで炒める。米を加えて混ぜながら2分炒り、粒の縁がほんのり半透明になるまで。ワインを注いで完全に吸収されるまで混ぜる。温かい出汁を一杓ずつ加え、常にかき混ぜながら前の分が完全に吸収されるのを待って次を加える — この核心ステップは16〜18分かかる。米はアルデンテであるべき。火から下ろし、残りの冷たいバターとパルミジャーノを力強くかき混ぜる（これをマンテカトゥーラという）。1分休ませて温かいボウルに盛ってすぐ提供する。","en":"Keep the stock warm over low heat throughout cooking — adding cold stock stops the cooking and ruins the creaminess. Heat oil and half the butter in a wide, heavy pan over medium heat. Sweat the shallot until soft, 3 minutes. Add the rice and toast, stirring, for 2 minutes until grains are slightly translucent at the edges. Pour in the wine and stir until completely absorbed. Add warm stock one ladleful at a time, stirring constantly and waiting for each ladleful to be absorbed before adding the next — this is the essential step and takes 16–18 minutes. The rice should be al dente with a creamy coating. Off the heat, beat in the remaining cold butter and the Parmigiano vigorously — the fat emulsifies into the starches creating a glossy sauce (this is called mantecatura). Rest 1 minute, then serve immediately in warm bowls."}},{"id":27,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"スウェーデン","en":"Sweden","ro":"Suedia"},"name":{"ja":"スウェーデン風ミートボール","en":"Swedish Meatballs","ro":"Chifteluțe suedeze"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["豚と牛の合い挽き肉500g（半々）","中玉ねぎ1個（すり下ろし）","白い食パン1枚（耳なし）、大さじ3の牛乳に浸したもの","大きな卵1個","オールスパイスパウダー小さじ1/4","ナツメグ（すり下ろし）小さじ1/4","炒め用バター大さじ2","牛肉のブイヨン250ml","ダブルクリーム150ml"],"en":["500g mixed ground pork and beef (50/50)","1 medium onion, grated","1 slice white bread, crusts removed, soaked in 3 tbsp milk","1 large egg","1/4 tsp ground allspice","1/4 tsp freshly grated nutmeg","2 tbsp butter for frying","250ml beef stock","150ml double cream"],"ro":["500g carne tocată amestecată porc și vită (50/50)","1 ceapă medie, rasă","1 felie de pâine albă fără coajă, înmuiată în 3 linguri lapte","1 ou mare","1/4 linguriță ienibahar măcinat","1/4 linguriță nucșoară rasă","2 linguri unt pentru prăjit","250ml supă de vită","150ml smântână pentru frișcă"]},"howIsMade":{"ja":"浸したパンを絞って余分な牛乳を取り除き、合い挽き肉、すり下ろした玉ねぎ（絞る）、卵、オールスパイス、ナツメグ、塩こしょうとよく混ぜる。しっかり混ぜるが捏ねすぎない — 捏ねすぎるとミートボールが固くなる。濡れた手で直径約3cmの丸に成形し20〜24個作る。フライパンにバターを溶かし中火で熱する。ミートボールをバッチに分けて全面を均一に焼き色がつくよう転がしながら6〜8分焼く。取り出して置く。同じフライパンに牛肉のブイヨンを加え焦げをこそげ、沸騰させる。クリームを加えて5分間煮詰める。ミートボールをソースに戻して弱火でさらに5分煮る。リンゴンベリーのジャム、ゆで芋またはマッシュポテト、ピクルスと一緒に提供する。","en":"Squeeze the soaked bread to remove excess milk, then mix with the ground meat, grated onion (squeeze out excess liquid), egg, allspice, nutmeg, salt and pepper. Mix well but do not overwork — overworking makes the meatballs tough. With wet hands, roll into balls about 3cm in diameter, yielding about 20–24 meatballs. Melt butter in a wide skillet over medium heat. Fry the meatballs in batches, rolling gently to brown all sides evenly, 6–8 minutes per batch. Remove and set aside. In the same pan, stir in the beef stock, scraping up the fond, and bring to a simmer. Add the cream and simmer 5 minutes until slightly thickened. Return the meatballs to the sauce and cook on low heat 5 more minutes. Serve with lingonberry jam, boiled or mashed potatoes, and pickled cucumber."}},{"id":28,"servings":4,"tipType":"meat","timeMins":{"total":720,"active":75},"pairingsType":"japanese","origin":{"ja":"日本","en":"Japan","ro":"Japonia"},"name":{"ja":"定番日本のラーメン","en":"Classic Japanese Ramen","ro":"Ramen clasic japonez"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["新鮮または乾燥ラーメン麺4食分（合計約400g）","鶏がらまたは豚骨スープ1L","醤油100ml（味に合わせて）","みりん大さじ2","豚バラまたは肩ロース200g（薄切り、チャーシュー用）","半熟卵4個（醤油とみりんで一晩漬けた味玉）","焼き海苔2枚（半分に切る）","メンマ大さじ4","長ねぎ2本（薄切り）","ごま油大さじ1"],"en":["4 portions fresh or dried ramen noodles (about 400g total)","1L chicken or pork bone broth","100ml soy sauce (or to taste)","2 tbsp mirin","200g pork belly or shoulder, thinly sliced (chashu)","4 soft-boiled eggs (marinated overnight in soy sauce and mirin)","2 sheets nori (dried seaweed), halved","4 tbsp bamboo shoots (menma)","2 spring onions, thinly sliced","1 tbsp sesame oil"],"ro":["4 porții tăiței ramen proaspeți sau uscați (aprox. 400g total)","1L supă de pui sau os de porc","100ml sos de soia (sau după gust)","2 linguri mirin","200g burtă de porc sau pulpă, feliată subțire (chashu)","4 ouă fierte moi (marinate în soia și mirin peste noapte)","2 foi nori (alge uscate), tăiate în jumătate","4 linguri mlădițe de bambus (menma)","2 cepe verzi, feliați subțire","1 lingură ulei de susan"]},"howIsMade":{"ja":"スープに醤油とみりんを合わせ、10分間弱火で煮てから味見 — 汁は深い旨み、ほんのり塩辛く、微かな甘みがあるべき。味玉（前日がベスト）：卵をきっかり6分30秒茹で、すぐ氷水にとり、殻をむいて醤油大さじ3、みりん大さじ2、水50mlに一晩漬ける。チャーシュー：豚バラをきつく巻いてタコ糸で縛り、醤油・みりん・酒・砂糖でとろ火2時間ブレイズ。冷めたらスライス。麺をパッケージの指示通り茹で（通常2〜3分）、湯切りして温めた丼に盛る。熱々のスープをたっぷりかける。チャーシュー2〜3枚、味玉の半割り、縦に立てた海苔1枚、メンマ、ねぎをのせ、ごま油をたらす。すぐに提供する。","en":"Combine the broth with soy sauce and mirin; simmer 10 minutes and taste — the broth should be deeply savoury, slightly salty, with a hint of sweetness. Ramen eggs (best made the night before): boil eggs for exactly 6 minutes 30 seconds, shock in ice water, peel, and marinate overnight in 3 tbsp soy sauce, 2 tbsp mirin, and 50ml water. Chashu pork: roll pork belly tightly, tie with kitchen string, and braise in soy sauce, mirin, sake, and sugar over a gentle simmer for 2 hours until tender. Slice when cool. Cook noodles per package directions (usually 2–3 minutes), drain, and portion into warmed bowls. Ladle hot broth over. Top with 2–3 slices of chashu pork, a halved ramen egg, a piece of nori standing upright, bamboo shoots, spring onions, and a drop of sesame oil. Serve immediately."}},{"id":29,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"ja":"アルゼンチン","en":"Argentina","ro":"Argentina"},"name":{"ja":"エンパナーダ","en":"Empanadas","ro":"Empanadas"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["薄力粉400g","ラードまたは冷たいバター100g（さいの目）","ぬるま湯150ml","塩小さじ1","牛ひき肉300g","中玉ねぎ1個（みじん切り）","固ゆで卵2個（刻む）","グリーンオリーブ12個（種を取って薄切り）","クミンパウダー小さじ1","スイートパプリカ小さじ1"],"en":["400g plain flour","100g lard or cold butter, diced","150ml warm water","1 tsp salt","300g ground beef","1 medium onion, finely chopped","2 hard-boiled eggs, chopped","12 green olives, pitted and sliced","1 tsp ground cumin","1 tsp sweet paprika"],"ro":["400g făină albă","100g untură sau unt rece, cuburi","150ml apă caldă","1 linguriță sare","300g carne de vită tocată","1 ceapă medie, tocată fin","2 ouă fierte tari, tăiate","12 măsline verzi, fără sâmburi și tăiate","1 linguriță chimen măcinat","1 linguriță boia dulce"]},"howIsMade":{"ja":"生地を作る：薄力粉と塩を合わせ、ラードまたは冷たいバターを指先でパン粉状になるまでこすり合わせる。ぬるま湯を少しずつ加えて5分こねると、なめらかで弾力のある生地になる。ラップで包み30分休ませる。フィリングを作る：玉ねぎを少量の油で8分炒め、牛ひき肉を加えて中火で10分、よく崩しながら炒める。クミン、パプリカ、塩・コショウで調味し、完全に冷ましてから刻んだ固ゆで卵とオリーブを混ぜる。生地を3mm厚に伸ばし、12cmの円を切り抜く。中心にフィリングを大さじ1杯のせ、縁を水で湿らせて半月形に折り、ねじり縁で閉じる。200度のオーブンで20〜25分焼いてきつね色にするか、180度の油で両面3〜4分揚げる。","en":"Make the dough: combine flour and salt, rub in the lard or cold butter with your fingertips until the mixture resembles breadcrumbs, then add warm water gradually and knead 5 minutes to a smooth, elastic dough. Wrap and rest 30 minutes. For the filling, saute onion in a little oil for 8 minutes, add ground beef and cook 10 minutes over medium heat, breaking it up well. Season with cumin, paprika, salt and pepper. Cool completely, then fold in the chopped boiled eggs and olives. Roll dough to 3mm thick and cut 12cm circles. Place a tablespoon of filling in the centre, moisten the edges, fold into a half-moon and seal with a twisted rope border (repulge). Bake at 200 degrees C for 20-25 minutes until golden, or deep-fry at 180 degrees C for 3-4 minutes per side."}},{"id":30,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"ザジキ","en":"Tzatziki","ro":"Tzatziki"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["全脂肪ギリシャヨーグルト500g（可能なら一晩水切りしておく）","大きいキュウリ1本（約300g）、すりおろしてよく水気を絞る","にんにく2片（細かくすりおろす）","エクストラバージンオリーブオイル大さじ2（サーブ用にも少量）","フレッシュディル大さじ1（細かく刻む）","レモン半個分の果汁","細かい海塩（適量）"],"en":["500g full-fat Greek yogurt (strained overnight if possible)","1 large cucumber (about 300g), grated and well squeezed","2 garlic cloves, finely grated","2 tbsp extra-virgin olive oil, plus a drizzle to serve","1 tbsp fresh dill, finely chopped","juice of half a lemon","fine sea salt to taste"],"ro":["500g iaurt grecesc integral (scurs peste noapte dacă e posibil)","1 castravete mare (cca 300g), ras și bine stors","2 căței de usturoi, rași fin","2 linguri ulei de măsline extravirgin, plus un pic pentru servit","1 lingură mărar proaspăt, tocat mărunt","sucul de la jumătate de lămâie","sare fină după gust"]},"howIsMade":{"ja":"最重要のステップ：キュウリを粗めにすりおろし、清潔なふきんまたはざるに入れる。少量の塩をふって10分おき、その後しっかり絞る — キュウリは重量の約半分を水として失う。余分な水分がザジキを水っぽくする原因。ヨーグルトに絞ったキュウリ、すりおろしにんにく、オリーブオイル、レモン汁、ディルを合わせて混ぜる。塩で味を調えて蓋をし、最低30分冷蔵する — 休ませることで風味が深まる。オリーブオイルをひと回しかけ、フレッシュディルを飾って温かいピタパンと一緒に提供する。","en":"The most important step: grate the cucumber on the coarse side of a box grater and place in a clean tea towel or colander. Sprinkle with a little salt, leave 10 minutes, then squeeze out hard — the cucumber will shed almost half its weight in water. Excess moisture is what makes tzatziki watery and weak. Combine the yogurt with the well-squeezed cucumber, grated garlic, olive oil, lemon juice and dill. Taste and adjust salt. Cover and refrigerate at least 30 minutes before serving — the flavours deepen as it rests. Serve drizzled with olive oil and a few fresh dill sprigs, alongside warm pita bread or souvlaki."}},{"id":31,"servings":4,"tipType":"soup","pairingsType":"french","origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"フレンチオニオンスープ","en":"French Onion Soup","ro":"Supă de ceapă franțuzească"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["黄玉ねぎ1kg（薄切り）","無塩バター60g","薄力粉大さじ1","辛口白ワイン200ml","良質のビーフストック1.2L","バゲット厚切り4枚（トーストする）","グリュイエールチーズ150g（すりおろし）","塩・黒コショウ・フレッシュタイム"],"en":["1kg yellow onions, thinly sliced","60g unsalted butter","1 tbsp plain flour","200ml dry white wine","1.2 litres good beef stock","4 thick slices baguette, toasted","150g Gruyere, grated","salt, black pepper and fresh thyme sprigs"],"ro":["1kg ceapă galbenă, tăiată julienne","60g unt nesărat","1 lingură făină","200ml vin alb sec","1,2 litri supă bună de vită","4 felii groase de baghetă, prăjite","150g Gruyère, ras","sare, piper negru și crenguțe de cimbru proaspăt"]},"howIsMade":{"ja":"厚底の鍋でバターを中弱火で溶かす。玉ねぎと塩ひとつまみを加え、5分ごとにかき混ぜながら45〜60分炒める — 焦がさないよう辛抱強く続けることが肝心。玉ねぎはカラメル色になるまで炒める。タイムと薄力粉を加えて1分炒める。白ワインを注いで3分沸騰させる。ビーフストックを加えて沸騰させ、弱火で20分煮込む。塩・コショウで味を整える。耐熱の器に注ぎ、トーストしたバゲットを1枚ずつ浮かべ、グリュイエールを山盛りのせてグリル（上火）で3〜4分、チーズがぷつぷつと泡立ち金色になるまで焼く。すぐに提供する。","en":"Melt the butter in a heavy-bottomed pot over medium-low heat. Add the onions with a pinch of salt and cook for 45-60 minutes, stirring every 5 minutes — patience is everything here. The onions must turn the colour of caramel, not burnt. Add a splash of water whenever they stick. Add the thyme and flour, stir for 1 minute. Pour in the wine and let it bubble for 3 minutes. Add the beef stock, bring to a simmer and cook 20 minutes. Taste and adjust salt and pepper. Ladle into oven-safe bowls, float a slice of toasted baguette in each, pile on the Gruyere and grill (broil) for 3-4 minutes until the cheese is bubbling and golden brown. Serve immediately — the cheese will set as it cools."}},{"id":32,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ハンガリー","en":"Hungary","ro":"Ungaria"},"name":{"ja":"グヤーシュ","en":"Goulash","ro":"Gulaș"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛肩肉またはすね肉700g（3cm角）","ワクシー種のジャガイモ400g（皮をむいてさいの目切り）","大玉ねぎ2個（みじん切り）","赤パプリカ2個（さいの目切り）","ハンガリー産甘口パプリカパウダー大さじ3","カットトマト缶400g","ビーフストック1L","ラードまたは植物油大さじ3","キャラウェイシード小さじ2、塩・黒コショウ適量"],"en":["700g beef chuck or shin, cut into 3cm cubes","400g waxy potatoes, peeled and diced","2 large onions, finely chopped","2 red bell peppers, diced","3 tbsp sweet Hungarian paprika","400g canned chopped tomatoes","1 litre beef stock","3 tbsp lard or vegetable oil","2 tsp caraway seeds, salt and black pepper to taste"],"ro":["700g carne de vită (spată sau greabăn), cuburi de 3 cm","400g cartofi cerosi, curățați și tăiați cuburi","2 cepe mari, tocate mărunt","2 ardei grași roșii, tăiați cuburi","3 linguri boia ungurească dulce","400g roșii tocate la conservă","1 litru supă de vită","3 linguri untură sau ulei vegetal","2 linguriță semințe de chimen, sare și piper negru după gust"]},"howIsMade":{"ja":"牛肉の角切りをペーパータオルで水気を取り、塩・コショウで下味をつける。厚手の鍋でラードを強火で熱し、肉を少量ずつ表面に焼き色がつくまで焼く — あまり動かさないこと、蒸し焼きではなく焦げ目をつけることが重要。取り出しておく。中火に落として玉ねぎを10分炒める。パプリカを加えて1分炒める — 焦がすと苦くなる。赤パプリカ、カットトマト、キャラウェイシード、ビーフストックを加える。牛肉を戻して沸騰させ、蓋をして弱火で60〜75分煮込む。ジャガイモを加えてさらに25分、やわらかくなるまで煮る。塩で味を調えて深皿によそい、カリカリのパンを添えて出す。","en":"Pat the beef cubes dry and season with salt and pepper. Heat the lard or oil in a heavy pot over high heat and brown the meat in batches — do not stir too much; you want a crust, not steamed meat. Remove and set aside. Reduce heat to medium, add the onions and cook 10 minutes. Add the paprika and stir for 1 minute — do not let it burn or it turns bitter. Add the peppers, tomatoes, caraway seeds and beef stock. Return the beef, bring to a boil, cover and simmer on low heat for 60-75 minutes. Add the potatoes and simmer 25 more minutes until tender and the beef flakes easily under pressure. Taste and adjust salt. Serve in deep bowls with crusty bread to mop up the rich broth."}},{"id":33,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ja":"エジプト","en":"Egypt","ro":"Egipt"},"name":{"ja":"コシャリ","en":"Koshari","ro":"Koshari"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["長粒白米200g","グリーンレンズ豆200g","小さめのマカロニまたはディタリーニ150g","缶詰ひよこ豆400g（水気を切る）","缶詰クラッシュトマト800g","玉ねぎ大3個（2個はソース用、1個はカリカリトッピング用）","植物油大さじ4","にんにく3片みじん切り、塩・クミン・酢（適量）"],"en":["200g long-grain white rice","200g green lentils","150g small macaroni or ditalini","400g canned chickpeas, drained","800g canned crushed tomatoes","3 large onions (2 for sauce, 1 for crispy topping)","4 tbsp vegetable oil","3 garlic cloves, minced, salt, cumin and vinegar to taste"],"ro":["200g orez cu bob lung","200g linte verde","150g macaroane mici sau ditalini","400g năut la conservă, scurs","800g roșii tocate la conservă","3 cepe mari (2 pentru sos, 1 pentru topping crocant)","4 linguri ulei vegetal","3 căței de usturoi, tocați, sare, chimen și oțet după gust"]},"howIsMade":{"ja":"レンズ豆を無塩の水で20分、アルデンテに茹でて水を切る。白米を塩水で15分炊く。小さめのパスタをアルデンテに茹でて水を切る。3個目の玉ねぎを薄い輪切りにして油で中強火で15〜20分、頻繁にかき混ぜながら濃いきつね色でカリカリになるまで揚げ炒める。キッチンペーパーに置く。同じ油でみじん切りの玉ねぎを残り2個分10分炒め、にんにく・クミン・缶詰トマト・少量の酢と塩を加える。ソースを20〜25分、とろみがつくまで煮る。ひよこ豆を加えてさらに5分。レンズ豆を白米に混ぜる。盛り付け方は：米+レンズ豆、パスタ、トマト+ひよこ豆ソース、そしてカリカリ玉ねぎを一番上に。室温で食べる。","en":"Cook the lentils in unsalted water for 20 minutes until al dente, then drain. Cook the rice in salted water for 15 minutes. Cook the pasta al dente and drain. Slice the third onion into thin rings and fry in oil over medium-high heat for 15-20 minutes, stirring often, until deep golden brown and crispy — this is the prized topping. Drain on paper towels. In the same oil, saute the remaining chopped onions 10 minutes, add garlic, cumin, canned tomatoes, a splash of vinegar and salt. Simmer the sauce 20-25 minutes until thick. Add the chickpeas and simmer 5 more minutes. Mix lentils into the rice. To serve, layer rice-lentil mixture, pasta, tomato-chickpea sauce, and top with the crispy onion rings. Koshari is eaten at room temperature."}},{"id":35,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"ja":"トルコ","en":"Turkey","ro":"Turcia"},"name":{"ja":"バクラヴァ","en":"Baklava","ro":"Baklava"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"ingredients":{"ja":["フィロ生地500g（解凍済み）","無塩バター200g（溶かす）","クルミ200g（細かく刻む）","ピスタチオ100g（細かく刻む）","シナモンパウダー小さじ1","砂糖300g","水200ml","はちみつ大さじ2＋レモン汁大さじ1"],"en":["500g phyllo pastry sheets, thawed","200g unsalted butter, melted","200g walnuts, finely chopped","100g pistachios, finely chopped","1 tsp ground cinnamon","300g sugar","200ml water","2 tbsp honey plus 1 tbsp lemon juice"],"ro":["500g foi de plăcintă (phyllo), dezghețate","200g unt nesărat, topit","200g nuci, tocate mărunt","100g fistic, tocat mărunt","1 linguriță scorțișoară măcinată","300g zahăr","200ml apă","2 linguri miere plus 1 lingură suc de lămâie"]},"howIsMade":{"ja":"まずシロップを作る：砂糖を水で溶かして5分煮る、はちみつとレモン汁を加えてさらに5分煮る。完全に冷ます — シロップは熱いバクラヴァにかける時に冷たくなければならない、クルミ・ピスタチオ・シナモンを混ぜる。33x23cmのバットに溶かしバターを塗る、フィロ生地を8枚重ね、各シートにバターを塗る。ナッツ類をたっぷり広げる、バターを塗った4枚の生地で覆い、またナッツを重ねる。ナッツを使い切るまで繰り返し、バターを塗った8枚の生地で締めくくる、焼く前にひし形または正方形に切る。160度で45〜50分、薄い金色になるまで焼く、オーブンから出した瞬間に冷たいシロップを全体にかける、2〜3時間置いてから提供する。","en":"Make the syrup first: dissolve sugar in water, boil 5 minutes, add honey and lemon juice, boil 5 more minutes; leave to cool completely — the syrup must be cold when poured over hot baklava. Mix the walnuts with pistachios and cinnamon; grease a 33x23cm baking tray with melted butter. Layer 8 phyllo sheets, brushing each with butter; scatter a generous layer of nut mixture. Cover with 4 buttered phyllo sheets, then another nut layer; repeat until the nuts are used up, finishing with 8 buttered phyllo sheets. Cut into diamonds or squares before baking; bake at 160 degrees C for 45-50 minutes until pale golden. The moment it comes out of the oven, pour the cold syrup all over — the temperature contrast helps the baklava absorb every drop; leave to rest 2-3 hours before serving."}},{"id":36,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"ja":"メキシコ","en":"Mexico","ro":"Mexic"},"name":{"ja":"チリコンカーン","en":"Chili con carne","ro":"Chili con carne"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛ひき肉500g（脂肪分最低20%）","赤インゲン豆の水煮缶400g（水気を切る）","カットトマト缶400g","大玉ねぎ2個（みじん切り）","にんにく3片（みじん切り）","チポトレペースト大さじ2または乾燥チポトレチリ2本","クミンパウダー大さじ1とスモークパプリカ大さじ1","植物油大さじ2","塩と黒コショウ"],"en":["500g beef mince (min. 20% fat)","400g canned red kidney beans, drained","400g canned chopped tomatoes","2 large onions, chopped","3 garlic cloves, minced","2 tbsp chipotle paste or 2 dried chipotle chillies, rehydrated","1 tbsp ground cumin and 1 tbsp smoked paprika","2 tbsp vegetable oil","salt and black pepper"],"ro":["500g carne de vită tocată (min. 20% grăsime)","400g fasole roșie kidney la conservă, scursă","400g roșii tocate la conservă","2 cepe mari, tocate","3 căței de usturoi, tocați","2 linguri pastă de chipotle sau 2 ardei iuți uscați","1 lingură chimen măcinat și 1 lingură boia afumată","2 linguri ulei vegetal","sare și piper negru"]},"howIsMade":{"ja":"大きな鍋で強火に油を熱する。牛ひき肉を2回に分けて焼き、よくほぐす — 灰色の蒸し塊ではなく、小さなカラメル化した粒にしたい。肉を取り出し、同じ油でたまねぎを8分炒める。にんにく・クミン・スモークパプリカを加えて1分炒める。チポトレペースト・トマト缶・豆・肉と水200mlを加える。沸騰後弱火にして半蓋をして45〜60分煮込む。水っぽければ最後の15分蓋を取る。塩で味を調え、サワークリーム・チェダーチーズ・ハラペーニョ・コリアンダーを添えて提供する。","en":"Heat the oil in a large pot over high heat. Brown the mince in two batches, breaking it up well — you want small caramelised pieces, not a grey steamed mass. Remove the meat and in the same oil, saute the onion for 8 minutes. Add garlic, cumin and smoked paprika, stir for 1 minute. Add chipotle paste, canned tomatoes, drained beans, the browned meat and 200ml water. Bring to a boil, reduce to low, partially cover and simmer 45-60 minutes, stirring occasionally. Chili should be thick, not watery — uncover for the last 15 minutes if too thin. Taste and adjust salt. Serve in bowls with sour cream, grated cheddar, sliced jalapeños, fresh coriander and tortilla chips."}},{"id":37,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"中国","en":"China","ro":"China"},"name":{"ja":"甘酢鶏肉","en":"Sweet and Sour Chicken","ro":"Pui dulce-acrișor"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["鶏胸肉500g（3cm角に切る）","コーンスターチ大さじ1（まぶし用）","パイナップル水煮缶200g（汁を取っておく）","赤パプリカ1個と緑ピーマン1個（さいの目切り）","小玉ねぎ1個（さいの目切り）","米酢大さじ3","砂糖大さじ2・醤油大さじ2・ケチャップ大さじ1","植物油大さじ2＋ごま油小さじ1"],"en":["500g chicken breast, cut into 3cm pieces","1 tbsp cornstarch (for coating)","200g canned pineapple chunks, juice reserved","1 red and 1 green bell pepper, diced","1 small onion, diced","3 tbsp rice vinegar","2 tbsp sugar, 2 tbsp soy sauce, 1 tbsp ketchup","2 tbsp vegetable oil plus 1 tsp sesame oil"],"ro":["500g piept de pui, tăiat cuburi de 3 cm","1 lingură amidon de porumb (pentru acoperire)","200g bucăți de ananas la conservă, sucul rezervat","1 ardei roșu și 1 ardei verde, tăiați cuburi","1 ceapă mică, tăiată cuburi","3 linguri oțet de orez","2 linguri zahăr, 2 linguri sos de soia, 1 lingură ketchup","2 linguri ulei vegetal plus 1 linguriță ulei de susan"]},"howIsMade":{"ja":"まずソースを作る：米酢・砂糖・醤油・ケチャップ・パイナップルの缶汁大さじ3を混ぜ合わせる。鶏肉にコーンスターチをまぶして余分を払う。中華鍋または大きなフライパンで植物油を強火で熱する。鶏肉を2〜3回に分けて4〜5分、こんがりカリッとするまで炒め焼きする。取り出しておく。同じ鍋に少量の油を足し、玉ねぎを2分炒め、パプリカ・ピーマンを加えてさらに2分強火で炒める — シャキシャキを保つこと。パイナップルを加え、ソースを注いで1〜2分グツグツさせてとろみと艶を出す。鶏肉を戻してよく絡める。ごま油をひとかけして完成。すぐに蒸しご飯と一緒に提供する。","en":"Make the sauce first: mix rice vinegar, sugar, soy sauce, ketchup and 3 tbsp of the pineapple juice. Toss the chicken pieces in cornstarch and shake off excess. Heat vegetable oil in a wok or large skillet over high heat. Fry the chicken in batches for 4-5 minutes until crisp and golden — do not crowd the pan. Set aside. In the same wok, add a little more oil and stir-fry the onion 2 minutes, add the peppers and cook 2 more minutes on high — they should stay crisp. Add the pineapple, pour in the sauce and bubble for 1-2 minutes until thick and glossy. Return the chicken and toss everything together. Finish with sesame oil. Serve immediately over steamed rice."}},{"id":38,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"ja":"オーストラリア","en":"Australia","ro":"Australia"},"name":{"ja":"パブロバ","en":"Pavlova","ro":"Pavlova"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"ingredients":{"ja":["大きな卵白4個、室温","220gキャスターシュガー（細目砂糖）","コーンスターチ 小さじ2","白ワインビネガー 小さじ1","バニラエッセンス 小さじ1","生クリーム300ml（脂肪分35%以上）、泡立て用","いちご200g、薄切り","パッションフルーツ2個、果肉をくりぬく"],"en":["4 large egg whites, room temperature","220g caster sugar","2 tsp cornstarch","1 tsp white wine vinegar","1 tsp vanilla extract","300ml double cream, for whipping","200g fresh strawberries, sliced","2 passion fruits, pulp scooped"],"ro":["4 albușuri mari, la temperatura camerei","220g zahăr fin (caster sugar)","2 lingurițe amidon de porumb","1 linguriță oțet de vin alb","1 linguriță extract de vanilie","300ml smântână pentru frișcă (min. 35% grăsime)","200g căpșuni proaspete, feliate","2 fructe ale pasiunii, pulpă"]},"howIsMade":{"ja":"オーブンを120°Cに予熱し、クッキングシートに直径22cmの円を描く。卵白にひとつまみの塩を加えて泡立て、角がやわらかく立つまで泡立てる。キャスターシュガーを1さじずつ加えながらその都度よく混ぜる——光沢があり、しっかりとしたメレンゲになるまで8〜10分。コーンスターチ、酢、バニラを泡立て器でやさしく折り込む。メレンゲを円の上に盛り、縁を少し高くする。90分焼く——外側が乾いてうっすらクリーム色になればOK。オーブンを切り、扉を少し開けたまま2時間以上かけて完全に冷ます。提供直前に生クリームをやわらかく泡立ててメレンゲに広げ、いちごとパッションフルーツを飾る。","en":"Preheat oven to 120°C and trace a 22cm circle on baking paper. Whisk egg whites with a pinch of salt to soft peaks. Add caster sugar one tablespoon at a time, whisking well after each addition — takes 8-10 minutes until the meringue is glossy, stiff, and has no sugar grains when rubbed between fingers. Fold in cornstarch, vinegar, and vanilla with a spatula. Mound the meringue onto the paper circle, building the sides slightly higher than the centre. Bake 90 minutes — the shell should be dry and faintly cream-coloured. Turn off oven and leave the pavlova to cool completely inside with the door ajar, at least 2 hours. Just before serving, whip cream to soft peaks and spread over the meringue. Top with strawberries and passion fruit pulp."}},{"id":39,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ja":"カナダ","en":"Canada","ro":"Canada"},"name":{"ja":"プーティン","en":"Poutine","ro":"Poutine"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["800gのラセット又はメイクイーンのじゃがいも、皮むき","150gのフレッシュチーズカード、室温","無塩バター 大さじ2","薄力粉 大さじ2","牛肉スープ 500ml、熱いもの","ウスターソース 小さじ1","揚げ油 適量（植物油）","塩と黒胡椒"],"en":["800g Russet or Maris Piper potatoes, peeled","150g fresh cheese curds, room temperature","2 tbsp unsalted butter","2 tbsp plain flour","500ml beef stock, hot","1 tsp Worcestershire sauce","vegetable oil for frying","salt and black pepper"],"ro":["800g cartofi Russet sau Desiree, curatati","150g cas proaspat (cheese curds), la temperatura camerei","2 linguri unt nesarat","2 linguri făină alba","500ml supa de vita, fierbinte","1 lingurita sos Worcestershire","ulei vegetal pentru prajit","sare si piper negru"]},"howIsMade":{"ja":"じゃがいもを1cm厚の拍子木切りにし、冷水に30分浸けてでんぷんを除く——これがカリカリに仕上がる秘訣。しっかり水気を拭く。1回目の揚げ: 150°Cの油で5〜6分、火が通るが色が付かない程度に揚げる。油切りして10分休ませる。2回目の揚げ: 190°Cで3〜4分、きつね色でカリカリになるまで揚げる。すぐに塩を振る。グレイビーソース: バターを中火で溶かし、薄力粉を加えて2分炒めてルーを作る。熱いスープを少しずつ加えてホイッパーで混ぜ、3〜4分でとろみをつける。ウスターソースを加えて味を調える。熱々のポテトを深皿に盛り、室温のチーズカードを散らし、すぐに熱いグレイビーをかける。","en":"Cut potatoes into 1cm batons and soak in cold water for 30 minutes to remove starch — this is what makes them crispy. Dry thoroughly. First fry: heat oil to 150°C and fry potatoes 5-6 minutes until cooked through but without colour. Drain and rest 10 minutes. Second fry: heat oil to 190°C and fry 3-4 minutes until golden and very crispy. Season immediately with salt. For the gravy: melt butter over medium heat, add flour and cook 2 minutes stirring — it should turn pale golden. Add hot stock gradually, whisking constantly until thickened, 3-4 minutes. Add Worcestershire, season. Pile hot fries into a deep bowl, scatter room-temperature cheese curds over, and immediately pour the hot gravy on top — the heat partially melts the curds while keeping their signature squeak."}},{"id":40,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ja":"ポーランド","en":"Poland","ro":"Polonia"},"name":{"ja":"ピエロギ","en":"Pierogi","ro":"Pierogi"},"category":{"ja":"夕食","en":"Dinner","ro":"Cina"},"ingredients":{"ja":["薄力粉300g（打ち粉用追加）","大きな卵1個＋ぬるま湯150ml（生地用）","粉質じゃがいも500g、茹でてつぶしたもの","フレッシュチーズ（トゥワルク）または乾燥カッテージチーズ200g","中玉ねぎ2個、みじん切り","無塩バター40g","スモークベーコンのカット100g","塩・白こしょう・フレッシュチャイブ（提供時）"],"en":["300g plain flour, plus extra for dusting","1 large egg plus 150ml warm water (for dough)","500g floury potatoes, boiled and mashed","200g farmer's cheese (twarog) or dry cottage cheese","2 medium onions, finely diced","40g unsalted butter","100g smoked bacon lardons","salt, white pepper and fresh chives to serve"],"ro":["300g făină alba, plus extra pentru intins","1 ou mare plus 150ml apa calda (pentru aluat)","500g cartofi fainosi, fierti si zdrobiti","200g branza de vaci (twarog) sau branza proaspata","2 cepe medii, taiate marunt","40g unt nesarat","100g bacon afumat, taiat cubulete","sare, piper alb si ceapa verde proaspata pentru servit"]},"howIsMade":{"ja":"小麦粉に卵と温水を加え、5分こねてなめらかで弾力のある生地を作り、30分休ませる。じゃがいもを柔らかく茹で、フレッシュチーズ・塩・白こしょうと一緒につぶす。フライパンで半量の玉ねぎをバターで黄金色に炒め（10分）、具材に混ぜ込む。生地を3mmに伸ばし、直径8cmで抜く。各ディスクに具を小さじ1盛り、半分に折って縁をしっかり押さえて封をする。塩水で3〜4分茹でる——浮き上がったら完成。同時にベーコンをカリカリに炒め、残りの玉ねぎを加えて炒める。茹でたピエロギをバターで両面2〜3分ずつ焼いて焼き色をつける。ベーコン・炒め玉ねぎ・サワークリームと共に提供。","en":"Mix flour with egg and warm water, knead 5 minutes to a smooth, elastic dough, cover and rest 30 minutes. Boil potatoes until tender, mash with farmer's cheese, salt and white pepper. In a pan, fry half the onion in butter until golden (10 min), stir into filling. Roll dough to 3mm, cut 8cm circles. Place a teaspoon of filling on each disc, fold in half and seal the edges firmly by pressing with fingers or a fork. Boil in salted water 3-4 minutes — they float when done. Meanwhile, fry bacon until crisp, add remaining onion and brown. Pan-fry the boiled pierogi in butter 2-3 minutes per side until golden patches appear. Serve with bacon, fried onion and sour cream."}},{"id":41,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"インドネシア","en":"Indonesia","ro":"Indonezia"},"name":{"ja":"ナシゴレン","en":"Nasi Goreng","ro":"Nasi Goreng"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["前日炊いたジャスミンライス4カップ","骨なし鶏もも肉300g、1cm角に切る","卵4個","エシャロット4個、薄切り","ニンニク4片、みじん切り","赤い鷹の爪2本、薄切り","ケチャップ・マニス（甘口醤油）大さじ2","醤油大さじ1","えびみそ（テラシ）小さじ1、炒って使用","サラダ油大さじ3","塩と白こしょう 適量","きゅうりのスライスと揚げエシャロット 盛り付け用"],"en":["4 cups day-old cooked jasmine rice","300 g boneless chicken thigh, cut into 1 cm cubes","4 eggs","4 shallots, thinly sliced","4 garlic cloves, minced","2 red bird's eye chillies, thinly sliced","2 tbsp kecap manis (sweet soy sauce)","1 tbsp soy sauce","1 tsp shrimp paste (terasi), toasted","3 tbsp vegetable oil","salt and white pepper to taste","cucumber slices and fried shallots to serve"],"ro":["4 căni orez jasmin fiert în ziua precedentă","300 g pulpă de pui dezosată, tăiată cubulețe de 1 cm","4 ouă","4 eșalote, feliate subțire","4 căței de usturoi, tocați","2 ardei iuți roșii, feliați subțire","2 linguri kecap manis (sos de soia dulce)","1 lingură sos de soia","1 linguriță pastă de creveți (terasi), prăjită","3 linguri ulei vegetal","sare și piper alb după gust","felii de castravete și eșalote prăjite pentru servire"]},"howIsMade":{"ja":"冷ご飯を手でほぐして塊を取り除く。中華鍋に大さじ1の油を強火で煙が出るまで熱する。鶏肉を加えて3〜4分炒め、火が通って薄く色づいたら取り出して脇に置く。残りのサラダ油大さじ2を中華鍋に加える。エシャロットを加えて2分炒め、しんなりするまで炒める。ニンニク、唐辛子、えびみそを加えて1分炒め、香りが立つまで炒める。ご飯を加えて平らに広げ、1分間触れずにおいて薄い焦げを作り、その後2〜3分強く混ぜ合わせる。鶏肉を中華鍋に戻し、ケチャップ・マニスと醤油を加えて全体にからめる。塩と白こしょうで味を調える。ご飯を端に寄せ、卵を割り入れて軽くかき混ぜてから、ご飯と混ぜ合わせて1分炒める。器に盛り、きゅうりのスライスと揚げエシャロットをのせてすぐに提供する。","en":"Break up the cold rice with your hands to separate any clumps. Heat 1 tbsp of oil in a wok over high heat until smoking. Add the chicken cubes and stir-fry for 3–4 minutes until cooked through and lightly golden; remove and set aside. Add the remaining 2 tbsp of oil to the wok. Add the shallots and stir-fry for 2 minutes until softened. Add the garlic, chilli, and shrimp paste and stir-fry for 1 minute until fragrant. Add the rice, spread into an even layer, and leave untouched for 1 minute to form a slight crust, then toss vigorously for 2–3 minutes. Return the chicken, add the kecap manis and soy sauce, and toss to coat evenly. Season with salt and white pepper. Push the rice to the side, crack in the eggs, scramble briefly, then fold into the rice and cook for 1 minute until just set. Serve in bowls topped with cucumber slices and fried shallots."}},{"id":42,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ja":"スイス","en":"Switzerland","ro":"Elveția"},"name":{"ja":"フォンデュ","en":"Fondue","ro":"Fondue"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["グリュイエールチーズ400g、粗くすりおろす","エメンタールチーズ200g、粗くすりおろす","ニンニク1片、半分に切る","辛口白ワイン（フォンダンまたはシャスラ）300ml","コーンスターチ大さじ1","キルシュ（チェリーブランデー）大さじ2","フレッシュナツメグ ひとつまみ","黒こしょう（挽きたて）適量","大きなバゲット1本（約500g）、2cm角に切る","コルニッションと茹でた新じゃがいも 盛り付け用"],"en":["400 g Gruyère, coarsely grated","200 g Emmental, coarsely grated","1 garlic clove, halved","300 ml dry white wine (Fendant or Chasselas)","1 tbsp cornstarch","2 tbsp kirsch (cherry brandy)","a pinch of freshly grated nutmeg","freshly ground black pepper to taste","1 large crusty baguette (about 500 g), cut into 2 cm cubes","cornichons and boiled new potatoes to serve"],"ro":["400 g Gruyère, ras grosier","200 g Emmental, ras grosier","1 cățel de usturoi, tăiat pe jumătate","300 ml vin alb sec (Fendant sau Chasselas)","1 lingură amidon de porumb","2 linguri kirsch (rachiu de cireșe)","un praf de nucșoară rasă proaspăt","piper negru proaspăt măcinat după gust","1 baghetă mare crocantă (cca. 500 g), tăiată cubulețe de 2 cm","cornișoni și cartofi noi fierți pentru servire"]},"howIsMade":{"ja":"フォンデュ鍋の内側をニンニクの切り口で擦る；ニンニクは捨てる。鍋にワインを注いで中火で沸騰直前まで温める。おろしたグリュイエールとエメンタールをコーンスターチと混ぜ合わせる。チーズを温めたワインに3回に分けて加え、毎回8の字を描くように混ぜながら完全に溶けてなめらかになるまで合計約8〜10分間溶かす。キルシュ、ナツメグ、黒こしょうを加える。フォンデュはスプーンをコーティングできるほどの濃度になっていること。鍋をフォンデュバーナーの最低火力に置いて穏やかに泡立つ状態を保つ。パンをフォンデュフォークに刺してチーズの中で底まで届くよう回し入れ、焦げつきを防ぐ。コルニッションと茹でた新じゃがいもを添えて提供する。","en":"Rub the inside of a fondue pot with the cut sides of the garlic clove; discard the garlic. Pour the wine into the pot and heat over medium heat until just below simmering. Toss the grated Gruyère and Emmental with the cornstarch until evenly coated. Add the cheese to the warm wine in three batches, stirring in a figure-eight motion after each addition until fully melted and smooth, about 8–10 minutes total. Stir in the kirsch, nutmeg, and a grind of black pepper; the fondue should be thick enough to coat a spoon. Place the pot over a fondue burner set to low to keep it gently bubbling. Spear bread cubes on fondue forks and swirl into the cheese, reaching the bottom of the pot to prevent a crust from forming. Serve with cornichons and boiled new potatoes."}},{"id":43,"servings":4,"tipType":"fish","pairingsType":"middle-eastern","origin":{"ja":"イラク","en":"Iraq","ro":"Irak"},"name":{"ja":"マスグーフ","en":"Masgouf","ro":"Masgouf"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["カープまたはスズキ1尾（約1.5kg）、内臓を取り除き洗う","オリーブオイル大さじ4","塩小さじ1","ターメリックパウダー小さじ1","クミンパウダー小さじ1","トマト2個、粗みじん切り","レモン1個、スライス","ニンニク4片、みじん切り","小玉ねぎ1個、粗みじん切り","トマトペースト大さじ2","黒こしょう（挽きたて）適量","薄焼きパン4枚 添え物として","スライスした玉ねぎ・トマト・ピクルス 添え物として"],"en":["1 whole carp or sea bass (about 1.5 kg), gutted and cleaned","4 tbsp olive oil","1 tsp salt","1 tsp ground turmeric","1 tsp ground cumin","2 tomatoes, roughly chopped","1 lemon, sliced","4 garlic cloves, minced","1 small onion, roughly chopped","2 tbsp tomato paste","freshly ground black pepper to taste","4 flatbreads to serve","sliced onion, tomato, and pickles to serve"],"ro":["1 crap sau biban întreg (cca. 1,5 kg), curățat și eviscerat","4 linguri ulei de măsline","1 linguriță sare","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","2 roșii, tăiate grosier","1 lămâie, feliată","4 căței de usturoi, tocați","1 ceapă mică, tocată grosier","2 linguri pastă de roșii","piper negru proaspăt măcinat după gust","4 pâini plate pentru servire","ceapă feliată, roșii și murături pentru servire"]},"howIsMade":{"ja":"鋭い包丁で背骨に沿って深く切り込み、魚を開いて平らにする。身に4cm間隔で斜めに切り込みを入れる。オリーブオイル、ターメリック、クミン、塩、こしょうを混ぜ合わせ、身の全体と腹腔内部に塗り込む。常温で20分マリネする。その間に、トマト、玉ねぎ、ニンニク、レモンスライス、トマトペーストを混ぜてぬり用ソースを作る。魚を2本の長い串に刺して平らに固定する。熾き火（直火は避ける）の上で30〜40分焼く：最初の20分は身を下にして、身が白くなって骨から離れてきたら、続けて皮を下にして10〜15分、皮がパリッとするまで焼く。5分ごとにソースをぬる。薄焼きパン、玉ねぎ、トマト、ピクルスとともにすぐに提供する。","en":"Using a sharp knife, make a deep cut along the backbone to butterfly the fish open flat. Score the flesh diagonally every 4 cm. Mix the olive oil, turmeric, cumin, salt, and pepper; rub all over the flesh and inside the cavity. Leave to marinate for 20 minutes at room temperature. Meanwhile, combine the tomatoes, onion, garlic, lemon slices, and tomato paste to make the basting sauce. Thread the fish onto two long skewers (or use a fish grill basket) to hold it flat. Grill over glowing wood embers or charcoal (not open flames) for 30–40 minutes: flesh side down for the first 20 minutes until the flesh is opaque and pulls away from the bone, then skin side down for 10–15 minutes until the skin is crisp. Baste with the sauce every 5 minutes. Serve immediately with flatbread, sliced onion, tomato, and pickles."}},{"id":44,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ja":"イスラエル","en":"Israel","ro":"Israel"},"name":{"ja":"シャクシュカ","en":"Shakshuka","ro":"Shakshuka"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ja":["オリーブオイル大さじ2","大きな玉ねぎ1個、細かく刻む","赤いパプリカ1個、細かく刻む","ニンニク4片、みじん切り","クミンパウダー小さじ1","スイートパプリカ小さじ1","スモークパプリカ小さじ½","チリフレーク小さじ¼","ホールトマト缶（400g）2缶、つぶしたもの","砂糖小さじ1","塩と黒こしょう（挽きたて）適量","卵6個","新鮮なパセリまたはパクチー ひとつかみ、粗みじん切り","クラスティパンまたはピタパン 盛り付け用"],"en":["2 tbsp olive oil","1 large onion, finely diced","1 red bell pepper, finely diced","4 garlic cloves, minced","1 tsp ground cumin","1 tsp sweet paprika","½ tsp smoked paprika","¼ tsp chilli flakes","2 x 400 g cans crushed tomatoes","1 tsp sugar","salt and freshly ground black pepper to taste","6 eggs","a small handful of fresh flat-leaf parsley or coriander, roughly chopped","crusty bread or pita to serve"],"ro":["2 linguri ulei de măsline","1 ceapă mare, tăiată mărunt","1 ardei kapia roșu, tăiat mărunt","4 căței de usturoi, tocați","1 linguriță chimen măcinat","1 linguriță boia dulce","½ linguriță boia afumată","¼ linguriță fulgi de ardei iute","2 x 400 g roșii zdrobite la conservă","1 linguriță zahăr","sare și piper negru proaspăt măcinat după gust","6 ouă","o mână de frunze de pătrunjel sau coriandru, tocate grosier","pâine crocantă sau pita pentru servire"]},"howIsMade":{"ja":"深さのある幅広のフライパンにオリーブオイルを中火で熱する。玉ねぎと赤いパプリカを加えて時々かき混ぜながら8分炒め、しんなりして色づいたら、ニンニク、クミン、甘口と燻製パプリカ、チリフレークを加えて1分、香りが立つまで炒める。トマトを加え、砂糖を入れ、塩とこしょうをたっぷり加える。時々混ぜながら10分煮てソースを濃くする。スプーンでソースに6つのくぼみを作る。各くぼみに卵を1個ずつ割り入れ、フタをして8〜10分、白身が固まり黄身がとろりとした状態になるまで加熱する。パセリまたはパクチーを散らし、すぐにパンまたはピタとともに提供する。","en":"Heat the olive oil in a wide, deep frying pan over medium heat. Add the onion and red pepper and cook, stirring occasionally, for 8 minutes until softened and beginning to colour. Add the garlic, cumin, sweet paprika, smoked paprika, and chilli flakes and stir for 1 minute until fragrant. Pour in the crushed tomatoes, add the sugar, and season generously with salt and pepper. Simmer for 10 minutes, stirring occasionally, until the sauce thickens and deepens in colour. Make 6 wells in the sauce with a spoon. Crack one egg into each well, then cover the pan with a lid and cook for 8–10 minutes until the whites are just set but the yolks are still runny. Scatter the parsley or coriander over the top and serve immediately from the pan with crusty bread or pita."}},{"id":45,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ja":"フィンランド","en":"Finland","ro":"Finlanda"},"name":{"ja":"サーモンスープ","en":"Salmon Soup","ro":"Lohikeitto"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["新鮮なサーモンフィレ600g、皮なし、3cmの角切り","煮崩れしにくいじゃがいも500g（シャーロットなど）、皮むき2cm角","長ねぎ1本（白い部分と薄い緑の部分）、薄い輪切り","中サイズのにんじん2本、皮をむき5mm厚の輪切り","良質の魚のだし汁1リットル","生クリーム200ml","ローリエ1枚","ホールのオールスパイス5粒","塩小さじ1、好みで追加","白こしょう粉¼小さじ","新鮮なディル大きな束（約30g）、ざく切り"],"en":["600 g fresh salmon fillet, skin removed, cut into 3 cm chunks","500 g waxy potatoes (Charlotte or similar), peeled and cut into 2 cm cubes","1 large leek, white and pale-green parts, thinly sliced into rings","2 medium carrots, peeled and sliced 5 mm thick","1 litre good-quality fish stock","200 ml double cream","1 bay leaf","5 whole allspice berries","1 tsp fine sea salt, plus more to taste","¼ tsp ground white pepper","1 large bunch fresh dill (about 30 g), roughly chopped"],"ro":["600 g file de somon proaspăt, fără piele, tăiat cuburi de 3 cm","500 g cartofi cu pulpă fermă (Charlotte sau similari), curățați, cuburi de 2 cm","1 praz mare, partea albă și verde deschis, tăiat rondele subțiri","2 morcovi medii, curățați, rondele de 5 mm","1 litru supă de pește bine aromatizată","200 ml smântână dulce pentru gătit","1 frunză de dafin","5 boabe de ienibahar","1 linguriță sare fină, plus după gust","¼ linguriță piper alb măcinat","1 mănunchi mare de mărar proaspăt (cca 30 g), tocat grosier"]},"howIsMade":{"ja":"魚のだし汁を大きな鍋に入れ、中火で静かに沸騰させる。じゃがいも、にんじん、長ねぎ、ローリエ、オールスパイスを加える。弱火で12〜15分、じゃがいもにナイフを刺したとき抵抗なく入るまで煮る。火を最低限に下げる——だし汁がかすかにゆれる程度で、沸かさない。サーモンを加え、4〜5分、魚がちょうど不透明になり押すと簡単にほぐれるまで煮る。クリームを加え、沸かさずに2分加熱する。塩と白こしょうで味をととのえる。ローリエとオールスパイスを除く。温めたボウルに盛り、新鮮なディルをたっぷりのせる。黒いライ麦パンと一緒に提供する。","en":"Pour the fish stock into a large pot and bring to a gentle simmer over medium heat. Add the potatoes, carrots, leek, bay leaf, and allspice berries. Cook at a gentle simmer for 12–15 minutes until the potatoes are just tender when pierced with a knife. Lower the heat so the stock barely trembles — do not boil. Add the salmon chunks and cook for 4–5 minutes until the fish is just opaque and flakes easily when nudged. Stir in the cream and heat for 2 minutes without letting it boil. Season with salt and white pepper. Remove the bay leaf and allspice berries. Ladle into warmed bowls and heap each portion with a generous amount of fresh dill. Serve with dark rye bread alongside."}},{"id":46,"servings":4,"tipType":"meat","timeMins":{"total":300,"active":60},"pairingsType":"middle-eastern","origin":{"ja":"イラン","en":"Iran","ro":"Iran"},"name":{"ja":"ゴルメサブジ","en":"Ghormeh Sabzi","ro":"Ghormeh Sabzi"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["骨なし子羊の肩肉（または牛の煮込み用肉）700g、4cmの角切り","乾燥赤インゲン豆200g、一晩水に浸けて水切り（または400g缶詰、水切り）","大きな玉ねぎ1個、細かく刻む","フレッシュフェヌグリークの葉80g（または乾燥フェヌグリーク3大さじ / カスーリメーティ）","フレッシュのイタリアンパセリ100g、細かく刻む","フレッシュのコリアンダー（パクチー）80g、細かく刻む","フレッシュの法蓮草50g、細かく刻む","乾燥ペルシャライム（リムー・アマーニー）4個、串で穴を開けたもの","ターメリックパウダー小さじ1","挽きたて黒こしょう小さじ½","塩小さじ1、好みで追加","植物油大さじ3、分けて使用"],"en":["700 g boneless lamb shoulder (or beef chuck), cut into 4 cm cubes","200 g dried red kidney beans, soaked overnight and drained (or 400 g canned, drained)","1 large onion, finely diced","80 g fresh fenugreek leaves (or 3 tbsp dried fenugreek / kasuri methi)","100 g fresh flat-leaf parsley, finely chopped","80 g fresh coriander (cilantro), finely chopped","50 g fresh spinach, finely chopped","4 dried Persian limes (limoo amani), pierced with a skewer","1 tsp ground turmeric","½ tsp ground black pepper","1 tsp fine sea salt, plus more to taste","3 tbsp vegetable oil, divided"],"ro":["700 g carne de miel fără os (spată) sau vită pentru tocăniță, tăiată cuburi de 4 cm","200 g fasole boabe roșie uscată, hidratată peste noapte și scursă (sau 400 g la conservă, scursă)","1 ceapă mare, tăiată mărunt","80 g frunze proaspete de schinduf (sau 3 linguri schinduf uscat / kasoori methi)","100 g pătrunjel frunze plate proaspăt, tocat mărunt","80 g coriandru proaspăt, tocat mărunt","50 g spanac proaspăt, tocat mărunt","4 lămâi persane uscate (limoo amani), înțepate cu un frigărui","1 linguriță turmeric măcinat","½ linguriță piper negru măcinat","1 linguriță sare fină, plus după gust","3 linguri ulei vegetal, separat"]},"howIsMade":{"ja":"大きな重い鍋に油大さじ1を中強火で熱する、肉を2回に分けて3〜4分ずつ、全面が深い茶色になるまで焼く。取り出す、同じ鍋で玉ねぎを中火で8分、黄金色になるまで炒める。ターメリックと黒こしょうを加えて1分炒める、肉を戻し、水切りした豆と穴を開けたライムを加える。ぎりぎり浸かる程度の水を注ぐ、沸騰させてアクを取り、最小火に下げる。その間、残りの油で大きなフライパンを強火で熱し、全てのハーブ（フェヌグリーク、パセリ、コリアンダー、ほうれん草）を15〜20分、常に混ぜながら、非常に濃いダークグリーンになり水分が完全に飛ぶまで炒める——このステップが料理特有の深い風味を作る、炒めたハーブをシチューに混ぜる。塩で味付けする、蓋をして最小火で2〜2.5時間（乾燥豆）または1.5時間（缶詰）、時々混ぜながら肉が非常に柔らかくなるまで煮る、バスマティライスに盛り付けて提供する。","en":"Heat 1 tbsp oil in a large heavy pot over medium-high heat; brown the meat in two batches, 3–4 minutes per batch, until deep brown on all sides. Remove and set aside; in the same pot, cook the onion over medium heat for 8 minutes until golden. Add the turmeric and black pepper; stir for 1 minute; return the meat to the pot. Add the drained kidney beans and pierced dried limes; pour over just enough water to barely cover. Bring to the boil, skim the foam, then reduce to the lowest possible simmer; meanwhile, heat the remaining 2 tbsp oil in a large frying pan over medium-high heat. Add all the herbs (fenugreek, parsley, coriander, spinach) and stir-fry for 15–20 minutes, until the herbs turn very dark green and all moisture has fully evaporated — this step is critical and builds the stew's characteristic deep flavour; stir the fried herbs into the stew. Season with salt; cover and simmer on the lowest heat for 2–2.5 hours (if using dried beans) or 1.5 hours (canned beans), stirring occasionally, until the meat is very tender and pulls apart easily. The stew should be thick and deeply coloured; serve over steamed basmati rice."}},{"id":47,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ja":"ポルトガル","en":"Portugal","ro":"Portugalia"},"name":{"ja":"バカリャウ・ア・ブラス","en":"Bacalhau à Brás","ro":"Bacalhau à Brás"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["塩ダラ（バカリャウ）500g、冷水に24–48時間浸けてほぐす","じゃがいも600g、皮をむき極細のマッチ棒状に切る","卵6個（大）、軽く溶きほぐす","中玉ねぎ2個、薄切り","特級エキストラバージンオリーブオイル 大さじ4","にんにく3片、薄切り","イタリアンパセリ小束、粗みじん切り","種抜き黒オリーブ80g","塩と白こしょう各適量"],"en":["500g salted cod (bacalhau), soaked 24–48h in cold water and shredded into flakes","600g waxy potatoes, peeled and cut into very thin matchstick strips","6 large eggs, lightly beaten","2 medium white onions, thinly sliced","4 tbsp extra-virgin olive oil","3 garlic cloves, thinly sliced","Small bunch of fresh flat-leaf parsley, roughly chopped","80g black olives, pitted, to serve","Salt and white pepper to taste"],"ro":["500g cod sărat (bacalhau), înmuiat 24–48h și desfăcut în fâșii","600g cartofi cerați, curățați și tăiați în bețișoare foarte subțiri","6 ouă mari, ușor bătute","2 cepe medii albe, tăiate felii subțiri","4 linguri ulei de măsline extravirgin","3 căței de usturoi, tăiați felii subțiri","Legătură mică de pătrunjel proaspăt, tocat grosier","80g măsline negre, fără sâmburi","Sare și piper alb"]},"howIsMade":{"ja":"ほぐした塩ダラを冷水に漬け、24–48時間かけて4回水を換え、小さな一切れが心地よい塩味になるまで続けます、水を切り水気を拭き取ります。じゃがいもを非常に細いマッチ棒状に切ります、深いフライパンに中性油2cmを入れ170°Cに熱し、2回に分けて3–4分ずつ薄く金色になるまで揚げます。キッチンペーパーに取り油を捨て、フライパンを拭きます、オリーブオイルを中弱火で熱し、玉ねぎとにんにくをよく混ぜながら12–15分炒めます。塩ダラを加えて2分混ぜます、じゃがいもを加えて優しく和えます。白こしょうで味付けした溶き卵を流し入れ、弱火でゆっくりと大きく折りたたむように絶えず2–3分混ぜます、卵がまだ少し生っぽく見えるうちに火から下ろし余熱で仕上げます、塩を確認し、パセリを散らし黒オリーブを添えて供します。","en":"Soak the shredded cod in cold water, changing the water four times over 24–48 hours until a small piece tastes pleasantly savoury rather than sharp; drain and pat dry. Cut potatoes into very thin matchstick strips; heat 2cm of neutral oil in a deep frying pan to 170°C and fry the potato strips in batches for 3–4 minutes until pale golden; drain on paper. Discard the frying oil and wipe the pan; heat olive oil over medium-low heat and cook the onion and garlic, stirring often, for 12–15 minutes until very soft and lightly golden. Add the cod flakes and stir for 2 minutes until warmed through; tip in the potato strips and toss once. Pour in the beaten eggs seasoned with white pepper; stir continuously over low heat with slow, wide folds for 2–3 minutes — the eggs should set in soft, creamy layers, never dry or granular. Remove from heat while the eggs still look slightly underdone; residual heat finishes the dish; taste for salt before adding any — the cod may already hold enough; scatter with parsley and serve straight from the pan with black olives alongside."}},{"id":48,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"フィリピン","en":"Philippines","ro":"Filipine"},"name":{"ja":"アドボ","en":"Adobo","ro":"Adobo"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["骨付き皮付きの鶏もも肉とドラムスティック1.2kg（または豚バラ肉1kg、4cmの角切り）","ニンニク6片、つぶしたもの","サトウキビ酢または白ワインビネガー125ml","醤油80ml","ローリエ3枚","ホールの黒こしょう小さじ1","水80ml","植物油大さじ2"],"en":["1.2 kg chicken thighs and drumsticks, bone-in skin-on (or 1 kg pork belly cut into 4 cm cubes)","6 garlic cloves, crushed","125 ml cane vinegar or white wine vinegar","80 ml soy sauce","3 bay leaves","1 tsp whole black peppercorns","80 ml water","2 tbsp vegetable oil"],"ro":["1,2 kg pulpe și tobe de pui (cu os, cu piele) sau 1 kg burtă de porc tăiată cuburi de 4 cm","6 căței de usturoi, zdrobiți","125 ml oțet de trestie sau oțet alb de vin","80 ml sos de soia","3 frunze de dafin","1 linguriță boabe de piper negru","80 ml apă","2 linguri ulei vegetal"]},"howIsMade":{"ja":"大きな鍋に鶏肉（または豚肉）、ニンニク、酢、醤油、ローリエ、黒こしょう、水を合わせる。室温で30分マリネする。かき混ぜずに中強火で沸騰させる。沸騰したら弱火にし、蓋をして30分（鶏肉）または45分（豚肉）、肉が柔らかくなるまで煮る。蓋を取り、中火に上げる。肉を時々ひっくり返しながら15〜20分煮詰め、ソースがスプーンの裏にとろりとかかる光沢ある濃いグレーズになるまで煮詰める。別の鍋に油を強火で熱し、肉を皮面を下にして入れ、3〜4分、皮がきつね色でパリパリになるまで焼く。ソースに戻して絡める。ローリエを除く。白ご飯の上に盛り付けて提供する。","en":"Combine the chicken (or pork), garlic, vinegar, soy sauce, bay leaves, peppercorns, and water in a large pot. Marinate for 30 minutes at room temperature. Bring to the boil over medium-high heat without stirring. Once boiling, reduce heat to low, cover, and simmer for 30 minutes (chicken) or 45 minutes (pork) until the meat is tender. Uncover and increase heat to medium. Continue simmering, turning the meat occasionally, for 15–20 minutes until the sauce reduces to a glossy, thick glaze that coats the back of a spoon. In a separate pan, heat the oil over high heat. Add the cooked pieces skin-side down and fry for 3–4 minutes until the skin is golden brown and crisp. Return to the sauce and toss to coat. Discard bay leaves. Serve over steamed white rice."}},{"id":49,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ジャマイカ","en":"Jamaica","ro":"Jamaica"},"name":{"ja":"ジャークチキン","en":"Jerk Chicken","ro":"Jerk Chicken"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["鶏もも肉と手羽元合わせて1.5kg、皮付き、骨まで深く切り込みを入れる","青ねぎ6本、大きく刻む","スコッチボネットまたはハバネロ3個、種を除く","にんにく5片","生姜2cm、皮をむく","濃口醤油 大さじ2","黒砂糖 大さじ2","オールスパイス（粉末）大さじ1","乾燥タイム 小さじ1","シナモン（粉末）小さじ½","黒こしょう 小さじ½","植物油 大さじ2","ライム2個分の果汁、ライムくし形切りも添える"],"en":["1.5kg chicken thighs and drumsticks, skin-on, scored deeply with a knife","6 spring onions, roughly chopped","3 Scotch bonnet chilies or habaneros, seeds removed for moderate heat","5 garlic cloves","2cm piece fresh ginger, peeled","2 tbsp dark soy sauce","2 tbsp brown sugar","1 tbsp ground allspice","1 tsp dried thyme","½ tsp ground cinnamon","½ tsp black pepper","2 tbsp vegetable oil","Juice of 2 limes, plus wedges to serve"],"ro":["1,5 kg pulpe și copane de pui, cu piele, crestați adânc","6 fire ceapă verde, tăiate grosier","3 ardei Scotch bonnet (sau habanero), semințele îndepărtate","5 căței de usturoi","Bucată de 2cm ghimbir proaspăt, curățat","2 linguri sos de soia închis la culoare","2 linguri zahăr brun","1 lingură ienibahar măcinat","1 linguriță cimbru uscat","½ linguriță scorțișoară măcinată","½ linguriță piper negru","2 linguri ulei vegetal","Suc de la 2 lămi verzi, plus felii pentru servire"]},"howIsMade":{"ja":"フードプロセッサーで青ねぎ、スコッチボネット、にんにく、生姜、醤油、黒砂糖、オールスパイス、タイム、シナモン、黒こしょう、油、ライム果汁を粗いペースト状になるまで混ぜます。鶏肉の各ピースを骨まで深く切り込みます——マリネが肉の内側まで浸透して初めてジャークが完成します。ペーストを全体に塗り込み、各切り込みに押し込みます。冷蔵庫で最低4時間、できれば一晩マリネします。調理30分前に冷蔵庫から出します。炭火グリルの場合：中高熱で35–45分、10分ごとに裏返しながら、汁が透明になり外側が一部焦げるまで焼きます。オーブンの場合：200°Cで網の上で40分、続けてグリルで5分。5分休ませてから提供します。ライスアンドピーズ、揚げプランテーン、ライムくし形と一緒に供します。","en":"Blend spring onions, Scotch bonnets, garlic, ginger, soy sauce, brown sugar, allspice, thyme, cinnamon, black pepper, oil, and lime juice in a food processor until a rough paste forms. Score the chicken pieces deeply down to the bone — jerk only works if the marinade penetrates inside the meat. Rub the paste all over and into every cut. Cover and marinate in the refrigerator for at least 4 hours, ideally overnight. Remove from the fridge 30 minutes before cooking. To grill over charcoal: cook over medium-hot coals for 35–45 minutes, turning every 10 minutes, until the juices run clear and the exterior is deeply charred in places. To oven-roast: place on a rack over a baking tray at 200°C for 40 minutes, then finish under a hot grill for 5 minutes to char the skin. Allspice is the defining spice — do not substitute with mixed spice. Rest 5 minutes before serving. Serve with rice and peas, fried plantain, and lime wedges."}},{"id":50,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"エチオピア","en":"Ethiopia","ro":"Etiopia"},"name":{"ja":"ドロワット","en":"Doro Wat","ro":"Doro Wat"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["鶏肉（もも肉とドラムスティック、骨付き）1.2kg","レモン汁大さじ3","大きな玉ねぎ4個（約800g）、非常に細かく刻む","ニテル・キベ（エチオピアのスパイスバター）または澄ましバター80g","ニンニク6片、みじん切り","生姜大さじ2、すりおろし（約3cmの塊）","ベルベル（berbere）スパイスミックス大さじ4","カルダモンパウダー小さじ1","フェヌグリークパウダー小さじ½","水またはチキンストック250ml","固ゆで卵4個、殻をむいてフォークで全面に穴を開けたもの","塩適量"],"en":["1.2 kg chicken pieces (thighs and drumsticks, bone-in)","3 tbsp lemon juice","4 large onions (about 800 g), very finely diced","80 g niter kibbeh (Ethiopian spiced butter) or clarified butter","6 garlic cloves, minced","2 tbsp fresh ginger, finely grated (about 3 cm piece)","4 tbsp berbere spice blend","1 tsp ground cardamom","½ tsp ground fenugreek","250 ml water or chicken stock","4 hard-boiled eggs, shelled and scored all over with a fork","salt to taste"],"ro":["1,2 kg piese de pui (pulpe și tobe cu os)","3 linguri suc de lămâie","4 cepe mari (cca 800 g), tăiate mărunt fin","80 g unt etiopian niter kibbeh (sau unt clarificat)","6 căței de usturoi, tocați mărunt","2 linguri ghimbir proaspăt ras (cca 3 cm bucată)","4 linguri amestec de condimente berbere","1 linguriță cardamom măcinat","½ linguriță schinduf măcinat","250 ml apă sau supă de pui","4 ouă fierte tari, curățate, înțepate cu furculița","sare după gust"]},"howIsMade":{"ja":"鶏肉にフォークで全体に穴を開け、レモン汁をすり込む、細かく刻んだ玉ねぎを大きな重い鍋に入れ、油も脂も使わずに弱火で加熱する。頻繁にかき混ぜながら25〜30分、玉ねぎがとても柔らかくなり、深いキャラメル色になって甘い香りが立つまで炒める——この長い乾燥炒めがシチューの風味の基盤を作る、ニテル・キベを加えてかき混ぜる。ニンニク、生姜、ベルベル、カルダモン、フェヌグリークを加える、絶えず混ぜながら5分炒め、スパイスが開きバターが深い赤オレンジ色になるまで。鶏肉を加えて全体をコーティングする、5分炒め、全面を焼き固める。水またはチキンストックを加える、沸騰させてから最小火に下げ、蓋をして40〜45分、途中で鶏肉をひっくり返しながら、肉が非常に柔らかくなるまで煮る。卵にフォークで全面に穴を開けソースの中に埋める、蓋をせずに10分煮る。塩で調味する、インジェラ（エチオピアのフラットブレッド）または蒸しご飯と一緒に提供する。","en":"Prick the chicken all over with a fork and rub with lemon juice; put the finely diced onions into a large heavy pot over low heat with no oil or fat. Cook, stirring often, for 25–30 minutes until the onions are very soft, deep golden-brown, and smell caramel-like — this long dry fry builds the stew's flavour base; add the niter kibbeh and stir to coat. Add the garlic, ginger, berbere, cardamom, and fenugreek; cook for 5 minutes, stirring constantly, until the spices bloom and the butter turns deep red-orange. Add the chicken pieces and turn to coat completely; cook 5 minutes, turning, until sealed on all sides. Pour in the water or stock; bring to the boil, then reduce to the lowest simmer. Cover and cook for 40–45 minutes, turning the chicken halfway through, until the meat is very tender and nearly falling off the bone; score the eggs all over with a fork and nestle them into the sauce. Simmer uncovered for 10 more minutes until the eggs are stained red from the sauce and the sauce has thickened; season with salt; serve on injera flatbread or steamed rice."}},{"id":51,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"ja":"シリア","en":"Syria","ro":"Siria"},"name":{"ja":"キッベ","en":"Kibbeh","ro":"Kibbeh"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["生地：細かいブルグル小麦（#1グレード）300g、洗って水切り","非常に脂肪の少ないラム（または牛）ミンチ400g、冷やしておく","中玉ねぎ1個、細かくすりおろし","オールスパイスパウダー小さじ1","シナモンパウダー小さじ1","塩小さじ1","黒こしょう粉小さじ½","詰め物：ラム（または牛）ミンチ300g","中玉ねぎ1個、細かく刻む","松の実（またはカシューナッツ）80g","オールスパイスパウダー小さじ1","シナモンパウダー小さじ½","植物油大さじ1","揚げ油（植物油 約1リットル）"],"en":["Shell: 300 g fine bulgur wheat (#1 grade), rinsed and drained","400 g very lean lamb (or beef) mince, chilled","1 medium onion, finely grated","1 tsp ground allspice","1 tsp ground cinnamon","1 tsp fine salt","½ tsp ground black pepper","Filling: 300 g lamb (or beef) mince","1 medium onion, finely diced","80 g pine nuts (or cashews)","1 tsp ground allspice","½ tsp ground cinnamon","1 tbsp vegetable oil","Vegetable oil for deep-frying (about 1 litre)"],"ro":["Coajă: 300 g bulgur fin (#1), clătit și scurs bine","400 g carne de miel sau vită slabă, tocată fin și răcită","1 ceapă medie, rasă sau blenderizată","1 linguriță condiment allspice (ienibahar măcinat)","1 linguriță scorțișoară măcinată","1 linguriță sare fină","½ linguriță piper negru măcinat","Umplutură: 300 g carne de miel sau vită tocată","1 ceapă medie, tăiată mărunt","80 g nuci de pin (sau nuci caju)","1 linguriță allspice","½ linguriță scorțișoară","1 lingură ulei vegetal","Ulei vegetal pentru prăjit adânc (cca 1 litru)"]},"howIsMade":{"ja":"ブルグルを冷水に15分浸し、水を切ってから手でしっかりと水分を絞る、フードプロセッサーで冷やしたミンチ、すりおろした玉ねぎ、オールスパイス、シナモン、塩、こしょうと合わせる。3〜4分処理し、必要に応じて氷水を大さじ1ずつ加え、固くなめらかな生地にする、30分冷蔵する。詰め物作り：中火で油を熱する、玉ねぎを5分炒めて柔らかくする。ミンチを加えて6〜8分、崩しながら炒める、オールスパイス、シナモン、こしょう、松の実を加えて2分炒める。完全に冷ます、成形：冷水で手を濡らす。60gの生地を取り、人差し指の周りで壁5mmの中空魚雷形にする、大さじ1の詰め物を入れる。開いた端を固く閉じてとがった先端にする、繰り返す。30分以上冷蔵する、揚げる：油を175°Cに熱する。4〜5個ずつ、そっと返しながら4〜5分、全面がきつね色になるまで揚げる、ペーパーで油を切る、温かいうちにヨーグルトやニンニクソースとピタパンと一緒に提供する。","en":"Soak the bulgur in cold water for 15 minutes, then drain and squeeze out all moisture firmly with your hands; combine with the chilled lean mince, grated onion, allspice, cinnamon, salt, and pepper in a food processor. Process for 3–4 minutes, adding ice water a tablespoon at a time if needed, until you have a smooth, stiff dough; refrigerate for 30 minutes. Make the filling: heat the oil over medium heat; cook the onion for 5 minutes until soft. Add the mince and brown, breaking it up, for 6–8 minutes; stir in allspice, cinnamon, pepper, and pine nuts; cook 2 minutes. Cool completely; shape: wet your hands with cold water. Take a 60 g piece of dough and mould it around your index finger into a hollow torpedo shape with 5 mm thick walls; fill the hollow with about 1 tablespoon of filling. Pinch the open end firmly to seal it into a pointed torpedo; repeat with the remaining dough and filling. Refrigerate for at least 30 minutes; fry: heat oil to 175°C. Fry in batches of 4–5 for 4–5 minutes, turning gently, until deep golden brown all over; drain on paper; serve warm with yoghurt or garlic sauce and pita bread."}},{"id":52,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"ja":"オランダ","en":"Netherlands","ro":"Olanda"},"name":{"ja":"スタンポット","en":"Stamppot","ro":"Stamppot"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["粉質のじゃがいも（メイクイーンや男爵など）1kg、皮をむいて4等分","カーリーケール（ブールエンコール）400g、硬い茎を取り除き葉をざく切り","スモーク豚ソーセージ（ルークウォルスト）またはブラートヴルスト400g","無塩バター80g、角切り","全乳100ml、温めておく","ナツメグ（すりおろし）小さじ1/4","塩（天然塩）小さじ1と1/2、使い分け","黒こしょう（挽きたて）小さじ1/2"],"en":["1 kg floury potatoes (such as Maris Piper or Russet), peeled and quartered","400 g curly kale (boerenkool), tough stems removed, leaves roughly chopped","400 g smoked pork sausage (rookworst) or bratwurst","80 g unsalted butter, cut into cubes","100 ml whole milk, warmed","1/4 tsp freshly grated nutmeg","1 1/2 tsp fine sea salt, divided","1/2 tsp freshly ground black pepper"],"ro":["1 kg cartofi făinoși (tip Maris Piper sau Russet), curățați și tăiați în sferturi","400 g varză creață (boerenkool), tulpini dure îndepărtate, frunze tocate grosier","400 g cârnați afumați din porc (rookworst) sau bratwurst","80 g unt nesărat, tăiat cubulețe","100 ml lapte integral, încălzit","1/4 linguriță nucșoară proaspăt rasă","1 1/2 linguriță sare fină de mare, împărțită","1/2 linguriță piper negru proaspăt măcinat"]},"howIsMade":{"ja":"大きな鍋に塩小さじ1を入れた水を沸騰させ、じゃがいもを加えて18-20分間、ナイフを刺してすっと通るまで茹でる。じゃがいもを茹でている間に、別の鍋に塩水を沸騰させてケールを入れ、5-6分間しんなりして柔らかくなるまで湯通しし、しっかり水気を切って余分な水を絞ってから粗く刻む。スモークソーセージをフライパンに入れてかぶるくらいの水を加え、中火で20分間中まで温まるまで煮る — または油少々で中火で8-10分間、途中で裏返しながら全面がきつね色になるまで焼く。じゃがいもを湯切りして熱いまま鍋に戻し、弱火で1-2分間鍋を揺すりながら蒸し乾かして水っぽいマッシュを防ぐ。バターと温めた牛乳を加え、ポテトマッシャーで力強く押しつぶしてなめらかでクリーミーなマッシュにする。水気を切ったケールを混ぜ込み、残りの塩、黒こしょう、ナツメグで味を調えて全体がよく混ざるまで混ぜる。すぐに深めの皿に盛り、スライスしたソーセージをのせて提供する。","en":"Bring a large pot of water with 1 tsp salt to the boil, add the potatoes, and cook for 18-20 minutes until completely tender when pierced with a knife. While the potatoes cook, bring a separate pot of salted water to the boil, add the kale, and blanch for 5-6 minutes until wilted and tender; drain well, squeeze out excess water, and chop roughly. Place the smoked sausage in a pan, add enough water to just cover, and simmer over medium heat for 20 minutes until heated through — or pan-fry in a little oil over medium heat for 8-10 minutes, turning halfway, until browned on all sides. Drain the potatoes and return them to the hot pot over low heat for 1-2 minutes, shaking the pot to steam-dry them and prevent a watery mash. Add the butter and warm milk and mash vigorously with a potato masher until smooth and creamy. Fold in the drained kale, season with the remaining salt, black pepper, and nutmeg, and stir until evenly combined. Serve immediately in deep bowls with the sliced sausage on top."}},{"id":53,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ニュージーランド","en":"New Zealand","ro":"Noua Zeelandă"},"name":{"ja":"ハンギ","en":"Hangi","ro":"Hangi"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["骨付き羊肩肉またはリブ600g、4cm角に切る","鶏ドラムスティック4本（約600g）、皮付き","煮崩れしにくいじゃがいも500g、皮をむいて半分に切る","クマラ（オレンジ色のさつまいも）300g、皮をむいて4cm角に切る","バターナットかぼちゃ300g、皮をむいて4cm角に切る","サボイキャベツ1/4個（約300g）、4つに切る","植物油大さじ3","塩小さじ1と1/2","黒こしょう（粗挽き）小さじ1/2"],"en":["600 g bone-in lamb shoulder or ribs, cut into 4 cm pieces","4 chicken drumsticks (about 600 g total), skin-on","500 g waxy potatoes, peeled and halved","300 g kumara (orange sweet potato), peeled and cut into 4 cm cubes","300 g butternut pumpkin, peeled and cut into 4 cm cubes","1/4 head savoy cabbage (about 300 g), cut into 4 wedges","3 tbsp vegetable oil","1 1/2 tsp fine salt","1/2 tsp ground black pepper"],"ro":["600 g carne de miel cu os (spată sau coaste), tăiată în bucăți de 4 cm","4 pulpe inferioare de pui (cca 600 g total), cu os și piele","500 g cartofi waxy, curățați și tăiați în jumătăți","300 g kumara (batată portocalie), curățată și tăiată cubulețe de 4 cm","300 g dovleac butternut, curățat și tăiat cubulețe de 4 cm","1/4 dintr-un cap de varză Savoy (cca 300 g), tăiată în 4 sferturi","3 linguri ulei vegetal","1 1/2 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ja":"オーブンを180°C（ファン160°C）に予熱する。羊肉と鶏肉全体に塩と黒こしょうをふる。大きな耐熱鍋に油を入れ強火で熱し、羊肉を1面3-4分ずつ全面がしっかり色づくまで焼いて取り出す。同じ鍋でドラムスティックを皮目を下にして4-5分、皮が黄金色でカリッとするまで焼いて取り出す。焼いた肉をすべて鍋に並べ、じゃがいも、クマラ、かぼちゃ、キャベツの切れ端を肉の間にしっかり詰める。水200mlを注いで、アルミホイルを二重にして鍋のふちに押し当てて密封し、蓋をする。オーブンで2時間焼き、羊肉が完全に柔らかくなって骨から簡単に外れ、すべての野菜にフォークがすっと刺さるまで加熱する — まだ固い場合は再度蓋をして30分追加で焼く。蓋とホイルを外し、オーブンを220°Cに上げて蓋なしで15分、皮がカリッとするまでロースト。10分休ませてから大皿に盛り、溜まった肉汁を上からかけて提供する。","en":"Heat the oven to 180°C (160°C fan). Season the lamb and chicken all over with salt and pepper. Heat the oil in a large flameproof casserole over high heat and brown the lamb pieces for 3-4 minutes per side until deeply coloured, then transfer to a plate. In the same pot, brown the chicken drumsticks skin-side down for 4-5 minutes until the skin is golden and crisp, then set aside. Arrange all the browned meat in the casserole and tuck the potatoes, kumara, pumpkin, and cabbage wedges snugly around and between the pieces. Pour in 200 ml of water, then seal the casserole very tightly with a double layer of foil pressed against the rim and put the lid on. Cook in the oven for 2 hours until the lamb is completely tender and pulls away from the bone easily, and all the vegetables are soft when pierced with a fork — if not quite done, cover again and cook for 30 minutes more. Remove the lid and foil, raise the oven to 220°C, and roast uncovered for 15 minutes until the skin crisps. Rest for 10 minutes before transferring everything to a large platter and spooning the collected juices over the top."}},{"id":54,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ja":"ベルギー","en":"Belgium","ro":"Belgia"},"name":{"ja":"ムール貝とフライドポテト","en":"Moules-frites","ro":"Moules-frites"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["生きた新鮮なムール貝2kg、たわしで洗い足糸を除去","粉質じゃがいも800g、皮をむいて太めのスティック状に切る","無塩バター50g","エシャロット4個、みじん切り","にんにく4片、薄切り","辛口白ワイン200ml","セロリ2本、薄切り","新鮮なパセリの小束、細かく刻む","植物油または牛脂（揚げ油用）","塩と黒こしょう"],"en":["2kg fresh live mussels, scrubbed and beards removed","800g floury potatoes, peeled and cut into thick batons","50g unsalted butter","4 shallots, finely diced","4 garlic cloves, thinly sliced","200ml dry white wine","2 celery stalks, finely sliced","Small bunch of fresh parsley, finely chopped","Vegetable oil or beef dripping, for deep-frying","Salt and black pepper"],"ro":["2 kg midii proaspete vii, curățate și cu beard-ul îndepărtat","800g cartofi făinoși, curățați și tăiați bețe groase","50g unt nesărat","4 șalote, tocate mărunt","4 căței de usturoi, felii subțiri","200ml vin alb sec","2 tulpini de țelină, feliate subțire","Legătură mică de pătrunjel proaspăt, tocat mărunt","Ulei vegetal sau grăsime de vită, pentru prăjit","Sare și piper negru"]},"howIsMade":{"ja":"フリット用：ジャガイモを太めのスティック状に切り、冷水に30分浸して表面のでんぷんを抜き、しっかり水気を拭き取ります、140°Cで6–8分、火が通るが色づかない状態まで揚げ、完全に冷まします。開いているムール貝を台に打ちつけて閉じなければ捨てます、大きな鍋でバターを中強火で溶かします。エシャロットとセロリを加えて3分炒めます、にんにくを加えて1分炒めます。白ワインを注いで沸騰させ、ムール貝を加えてしっかり蓋をします、4–5分蒸し煮し、鍋を1〜2回振り、全ての貝が開いたら完成。開かないものは捨てます、パセリの大部分を加え、ブロスの味を調えます。揚げ油を190°Cに上げ、下揚げしたスティックをバッチで2–3分、こんがりとしてとてもカリカリになるまで揚げます、すぐ塩をふります、ムール貝をブロスごと深皿に盛り、フリットを添えます。","en":"For the frites: cut potatoes into thick batons and soak in cold water for 30 minutes to remove surface starch, then drain and dry thoroughly; first fry at 140°C for 6–8 minutes until cooked through but uncoloured; drain and cool completely. Tap each open mussel on the counter — discard any that do not close; melt butter in a large heavy pot over medium-high heat. Add shallots and celery and cook for 3 minutes until softened; add garlic and cook for 1 minute. Pour in the white wine, bring to a boil, then add the mussels and cover tightly; steam for 4–5 minutes, shaking the pot once or twice, until the shells have opened wide. Discard any that remain shut; stir in most of the parsley and season the broth. Raise the frying oil to 190°C and fry the blanched batons in batches for 2–3 minutes until golden and very crisp; drain and season immediately with salt; serve the mussels in wide bowls in their broth, the frites alongside, with the remaining parsley and mayonnaise on the side."}},{"id":55,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"ムサカ","en":"Moussaka","ro":"Moussaka"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["大きめのナス2本（合計約1kg）、1cm厚の輪切り","ラム挽き肉500g（または牛挽き肉）","玉ねぎ大1個、みじん切り","にんにく3片、みじん切り","カットトマト缶400g（1缶）","トマトペースト大さじ2","赤ワイン100ml","ドライオレガノ小さじ1","シナモンパウダー小さじ1/2","バター60g（ベシャメル用）","薄力粉60g（ベシャメル用）","温めた牛乳700ml","卵黄2個","ケファロティリチーズ80g、すりおろし（またはパルメザン）","オリーブオイル大さじ3","塩と挽きたての黒コショウ"],"en":["2 large eggplants (about 1 kg total), sliced 1 cm thick","500 g lamb mince (or beef mince)","1 large onion, finely diced","3 garlic cloves, minced","400 g chopped tomatoes (1 can)","2 tbsp tomato paste","100 ml red wine","1 tsp dried oregano","1/2 tsp ground cinnamon","60 g butter (for the bechamel)","60 g plain flour (for the bechamel)","700 ml warm milk","2 egg yolks","80 g grated kefalotyri (or parmesan)","3 tbsp olive oil","Salt and freshly ground black pepper"],"ro":["2 vinete mari (aproximativ 1 kg in total), feliate de 1 cm grosime","500 g carne tocata de miel (sau de vita)","1 ceapa mare, tocata marunt","3 căței de usturoi, zdrobiti","400 g rosii tocate in conserva (1 conserva)","2 linguri pasta de rosii","100 ml vin rosu","1 lingurita oregano uscat","1/2 lingurita scortisoara macinata","60 g unt (pentru bechamel)","60 g făină alba (pentru bechamel)","700 ml lapte cald","2 galbenusuri de ou","80 g kefalotyri ras (sau parmezan)","3 linguri ulei de masline","Sare si piper negru proaspat macinat"]},"howIsMade":{"ja":"大きめのナス2本を1cm厚の輪切りにし、たっぷり塩をふってザルに30分置き、苦味の出る水分を抜き、キッチンペーパーで水気を拭く。 輪切りにオリーブオイルを塗り、200度のオーブンで途中一度返しながら20-25分、黄金色で柔らかくなるまで焼く。 広めのフライパンにオリーブオイル大さじ2を中強火で熱し、ラム挽き肉500gと刻んだ玉ねぎ1個、にんにく3片を8-10分炒め、赤ワイン100mlで鍋肌をこそげて煮詰める。 刻みトマト400g、トマトペースト大さじ2、シナモン小さじ1/2、オレガノ小さじ1を加え、20分弱火で煮込み、汁気が縁にたまらない程度まで濃くする。 ベシャメルは鍋でバター60gを溶かし、薄力粉60gを加えて2分炒めて薄い金色のルーにし、温めた牛乳700mlを少しずつ加えながら絶えず泡立てて濃度をつけ、火から下ろして30秒落ち着かせ、卵黄2個とすりおろしたケファロティリまたはパルメザン80gを混ぜ込む。 30x20cmの耐熱皿にナス、ラムソースの半量、残りのナス、残りのソースの順に重ね、上からベシャメルを流してヘラで平らにならす。 180度のオーブンで40-45分、表面がしっかり黄金色になり、縁でソースがふつふつと沸くまで焼く。 ムサカは切り分ける前に必ず15-20分休ませる；この工程は省略不可で、層が落ち着いて切り口がきれいに保たれる。","en":"Slice 2 large eggplants into 1 cm rounds, salt them generously and let them sit in a colander for 30 minutes to draw out the bitter water; pat dry with paper towels. Brush the slices with olive oil and roast at 200 C for 20-25 minutes, turning once, until golden and tender. In a wide pan heat 2 tbsp oil over medium-high and brown 500 g minced lamb with one chopped onion and 3 garlic cloves for 8-10 minutes, then deglaze with 100 ml red wine and let it reduce. Add 400 g chopped tomatoes, 2 tbsp tomato paste, half a tsp cinnamon and 1 tsp oregano; simmer 20 minutes until thick and no excess liquid pools at the edge. For the bechamel melt 60 g butter in a saucepan, whisk in 60 g flour and cook 2 minutes until blond, then gradually add 700 ml warm milk whisking constantly until thick; off the heat, let it cool 30 seconds and beat in 2 egg yolks with 80 g grated kefalotyri or parmesan. In a 30x20 cm baking dish layer half the eggplant, all the lamb sauce, the remaining eggplant, then pour the bechamel on top and level it with a spatula. Bake at 180 C for 40-45 minutes until the top is deeply golden and the sauce bubbles at the edges. Rest the moussaka for 15-20 minutes before cutting; this step is non-negotiable so the layers set and the slices hold their shape."},"timeMins":{"total":105,"active":35}},{"id":56,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"チェコ","en":"Czech Republic","ro":"Republica Cehă"},"name":{"ja":"スヴィチュコヴァー","en":"Svíčková","ro":"Svíčková"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛ヒレ肉 1.2 kg（トップラウンドまたはトップサイド）","スモークベーコン 100 g、ラード用に細切り（任意）","バター 30 g","クセのない油 大さじ 1","大きい玉ねぎ 1 個、角切り","大きいニンジン 2 本、角切り","パースニップ 1 本、角切り","セロリアック 150 g、角切り","ローリエ 2 枚","オールスパイス 6 粒","黒こしょう（粒）10 粒","レモンの皮 1/2 個分","ディジョンマスタード 大さじ 1","トマトペースト 大さじ 2","辛口白ワイン 200 ml","ビーフストック 500 ml","生クリーム 200 ml（乳脂肪 33%）","薄力粉 大さじ 1（任意、とろみ付け用）","砂糖 小さじ 1","レモン汁 1/2 個分","塩、お好みで","盛り付け用：ホイップクリーム、クランベリーソース、レモン薄切り、クネドリーキ"],"en":["1.2 kg beef sirloin (top round or topside)","100 g smoked bacon, cut in thin strips for larding (optional)","30 g butter","1 tbsp neutral oil","1 large onion, diced","2 large carrots, diced","1 parsnip, diced","150 g celeriac, diced","2 bay leaves","6 allspice berries","10 black peppercorns","Zest of 1/2 lemon","1 tbsp Dijon mustard","2 tbsp tomato paste","200 ml dry white wine","500 ml beef stock","200 ml heavy cream (33% fat)","1 tbsp plain flour (optional, for thickening)","1 tsp sugar","Juice of 1/2 lemon","Salt, to taste","To serve: whipped cream, cranberry compote, lemon slice, knedliky"],"ro":["1,2 kg mușchi de vită (vrabia sau pulpă top)","100 g bacon afumat, tăiat fâșii subțiri pentru lardonare (opțional)","30 g unt","1 lingură ulei neutru","1 ceapă mare, tăiată cuburi","2 morcovi mari, tăiați cuburi","1 rădăcină de păstârnac, tăiată cuburi","150 g țelină rădăcină, tăiată cuburi","2 foi de dafin","6 boabe de ienibahar","10 boabe de piper negru","Coaja de la 1/2 lămâie","1 lingură de muștar Dijon","2 linguri de pastă de roșii","200 ml vin alb sec","500 ml supă de vită","200 ml smântână grasă (33% grăsime)","1 lingură de făină albă (opțional, pentru îngroșare)","1 linguriță de zahăr","Zeama de la 1/2 lămâie","Sare, după gust","Pentru servire: frișcă bătută, dulceață de merișoare, felie de lămâie, knedlíky"]},"howIsMade":{"ja":"牛ヒレ肉1.2kgに薄切りスモークベーコンを差し込んでラルドネするか、料理用たこ糸できつく縛り、塩と挽きたて黒こしょうで全面にしっかり下味をつける。重いダッチオーブンにバター30gと油大さじ1を中強火で熱し、牛肉を全面8〜10分焼いて深い茶色の焼き色がついたら皿に取り出す。同じ鍋に角切りミルポワ（大きいニンジン1本、パースニップ1本、セロリアック150g、大きい玉ねぎ1個）を入れ10〜12分炒めて縁がキャラメル色になったら、月桂樹の葉2枚、オールスパイス6粒、黒こしょう10粒、レモン皮1/2個分、マスタード大さじ1を加える。トマトペースト大さじ2を加えて2分炒めて色が濃くなったら、辛口白ワイン200mlとビーフストック500mlで鍋底をこすりながらデグラセし、牛肉を野菜の上に戻す。ふたをして160度のオーブンで1.5〜2時間、30分ごとに肉を返しながら、フォークが抵抗なく刺さるまで蒸し焼きにする。牛肉を取り出してまな板にのせ、ホイルをかぶせて休ませる間に、煮汁と野菜をハンドブレンダーで滑らかになるまで撹拌し、細かいざるで濾して鍋に戻す。生クリーム200mlを加え、必要なら冷水で溶いた小麦粉大さじ1を加えて5分煮詰め、スプーンの背に艶やかにとろみが残るまで仕上げ、塩、砂糖小さじ1、レモン汁少々で甘酸のバランスを整える。肉を繊維に逆らって1cm厚にスライスし、温かいソースをたっぷりかけ、ホイップクリーム一さじ、クランベリーソース、レモン1切れを添え、クネドリーキ（パンの団子）と一緒に提供する。","en":"Lard the beef sirloin (1.2 kg) with thin strips of smoked bacon, or truss it tightly with kitchen twine; season generously with salt and freshly ground pepper on all sides. Heat 30 g butter and 1 tbsp oil in a heavy Dutch oven over medium-high and sear the beef on every side for 8-10 minutes until a deep brown crust forms, then transfer to a plate. In the same pot brown the mirepoix (1 large carrot, 1 parsnip, 150 g celeriac, 1 large onion, all diced) for 10-12 minutes until caramelised at the edges; add 2 bay leaves, 6 allspice berries, 10 whole black peppercorns, the zest of half a lemon and 1 tbsp mustard. Stir in 2 tbsp tomato paste and cook 2 minutes until it darkens, then deglaze with 200 ml dry white wine and 500 ml beef stock, scraping the bottom, and nestle the beef back in on top of the vegetables. Cover and braise at 160°C for 1.5 to 2 hours, turning the beef every 30 minutes, until a fork slides in with no resistance. Lift the beef onto a board and tent with foil to rest; blend the cooking liquid and vegetables with a stick blender until smooth and pass the sauce through a fine sieve back into the pot. Stir in 200 ml heavy cream and, if needed, 1 tbsp flour slaked in a little cold water; simmer 5 minutes until the sauce coats the back of a spoon glossily, then adjust with salt, 1 tsp sugar and a squeeze of lemon to balance the sweet-sour. Slice the beef against the grain into 1 cm slices, ladle the warm sauce over the top and garnish with a spoon of whipped cream, cranberry compote and a lemon slice; serve with houskove knedliky (bread dumplings)."}},{"id":57,"servings":4,"tipType":"meat","timeMins":{"total":195,"active":45},"pairingsType":"meat","origin":{"ja":"ノルウェー","en":"Norway","ro":"Norvegia"},"name":{"ja":"フォリコール","en":"Fårikål","ro":"Fårikål"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["骨付き羊肩肉または首肉1.2kg、5cm角に切る","白キャベツ1.2kg（大1個分）、芯を除いて8つの厚い切れ目に切る","黒こしょう（ホール）大さじ1","冷水600ml","塩小さじ1と1/2"],"en":["1.2 kg bone-in lamb shoulder or neck, cut into 5 cm pieces","1.2 kg white cabbage (about 1 large head), cored and cut into 8 thick wedges","1 tbsp whole black peppercorns","600 ml cold water","1 1/2 tsp fine salt"],"ro":["1,2 kg carne de miel cu os (spata sau gat), taiata in bucati de 5 cm","1,2 kg varza alba (1 cap mare), miezul indepartat, taiata in 8 sferturi groase","1 lingura boabe intregi de piper negru","600 ml apa rece","1 1/2 lingurita sare fina"]},"howIsMade":{"ja":"羊肉を塩小さじ1で全面に下味をつける。キャベツの1/2量を大きくて重い鍋の底に均一に敷き詰める。その上に羊肉を置き、黒こしょうと残りの塩(小さじ1/2)を散らし、残りのキャベツをその上に重ねる。冷水を鍋の内側の壁づたいに静かに注ぐ — かき混ぜない。ふたをしっかりして中火で軽く沸騰させ、約8-10分。できるだけ弱火にして混ぜずに2〜2.5時間煮込み、羊肉が完全に柔らかくなって骨から落ち、キャベツが崩れて肉汁を完全に吸収するまで待つ。2時間後に羊肉が抵抗なく骨から外れ、スープが旨味豊かで香り高いか確認し — まだなら、ふたをして30分延長する。塩加減を調整。深皿にスープとともに盛り、各人分に羊肉とキャベツの両方が入るよう注意する。","en":"Season the lamb pieces all over with 1 tsp of the salt. Arrange half the cabbage wedges in an even layer at the bottom of a large, heavy pot. Lay the lamb pieces on top, scatter over the peppercorns and the remaining 1/2 tsp salt, then arrange the remaining cabbage on top. Pour the cold water carefully down the inside wall of the pot — do not stir. Cover tightly and bring to a gentle boil over medium heat, about 8-10 minutes. Reduce the heat to the lowest possible simmer and cook undisturbed for 2 to 2.5 hours until the lamb is completely tender and falls off the bone, and the cabbage has collapsed and fully absorbed the meat juices. After 2 hours check that the lamb pulls away from the bone with no resistance and the broth is rich and fragrant — if not quite done, cover and simmer for 30 minutes more. Taste and adjust salt. Ladle into deep bowls with the broth, ensuring each serving has both lamb and cabbage."}},{"id":58,"servings":4,"tipType":"veg","pairingsType":"middle-eastern","origin":{"ja":"スーダン","en":"Sudan","ro":"Sudan"},"name":{"ja":"フール・メダメス","en":"Ful Medames","ro":"Ful Medames"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ja":["乾燥小そら豆400g（一晩冷水に浸したもの）または缶詰のそら豆800g（洗って水切り）","にんにく4かけ、みじん切り","生レモン汁60ml（大きめのレモン1個分）、お好みで追加","エクストラバージンオリーブオイル大さじ4、使い分け","クミンパウダー小さじ1","コリアンダーパウダー小さじ1/2","天然塩小さじ1/2、お好みで追加","カイエンペッパーまたは辛口パプリカ小さじ1/4","中程度の完熟トマト2個（約250g）、細かく刻む","小さめの赤玉ねぎ1個（約100g）、細かく刻む","イタリアンパセリ20g、葉をざく切り"],"en":["400 g dried small fava beans, soaked overnight in cold water (or 800 g canned fava beans, rinsed and drained)","4 garlic cloves, finely minced","60 ml fresh lemon juice (about 1 large lemon), plus more to taste","4 tbsp extra-virgin olive oil, divided","1 tsp ground cumin","1/2 tsp ground coriander","1/2 tsp fine sea salt, plus more to taste","1/4 tsp cayenne pepper or hot paprika","2 medium ripe tomatoes (about 250 g), finely diced","1 small red onion (about 100 g), finely diced","20 g flat-leaf parsley, leaves roughly chopped"],"ro":["400 g fasole fava uscata, inmuiata peste noapte in apa rece (sau 800 g fasole fava la conserva, clatita si scursa)","4 căței de usturoi, tocati marunt","60 ml suc proaspat de lamaie (cca 1 lamaie mare), plus dupa gust","4 linguri ulei de masline extravirgin, impartit","1 lingurita chimen macinat","1/2 lingurita coriandru macinat","1/2 lingurita sare fina de mare, plus dupa gust","1/4 lingurita ardei iute macinat sau boia picanta","2 rosii mijlocii coapte (cca 250 g), taiate marunt","1 ceapa rosie mica (cca 100 g), taiata marunt","20 g patrunjel plat, frunzele tocate grosier"]},"howIsMade":{"ja":"乾燥豆を使う場合、水を切って新しい冷水を4-5cmかぶるくらい注ぎ、沸騰させてから弱火で1.5〜2時間、指で押してつぶれるほど完全に柔らかくなるまで煮る。水を切り、100mlの茹で汁を取り置く。缶詰の場合は洗って水を切り、100mlの水を代用する。弱火の鍋に豆を戻し、にんにく、レモン汁、オリーブオイル大さじ3、クミン、コリアンダー、塩、カイエンを加える。3-4分加熱しながら豆の約半量をフォークで潰し、クリーミーで一部粒の残るテクスチャーにし、必要なら取り置いた液体を少しずつ加える。レモン汁、塩、スパイスの量を調整し、酸味とスパイスのバランスを整える。浅めの皿に盛り、ダイスしたトマト、赤玉ねぎ、パセリを散らす。残りのオリーブオイル大さじ1をかけ、温かいピタパンと一緒にすぐに提供する。","en":"If using dried beans, drain the soaked beans and cover with fresh cold water by 4-5 cm; bring to the boil and simmer for 1.5 to 2 hours until the beans are completely soft when pressed between fingers, then drain, reserving 100 ml of cooking liquid. If using canned beans, rinse, drain, and use 100 ml of water as the liquid. Return the beans to the pot over low heat and add the garlic, lemon juice, 3 tbsp of the olive oil, cumin, coriander, salt, and cayenne. Cook for 3-4 minutes, mashing about half the beans with a fork to create a creamy, partly chunky texture, adding reserved cooking liquid a splash at a time if too thick. Taste and adjust lemon, salt, and spice — the ful should be tangy and warmly spiced. Divide into shallow bowls and scatter the diced tomatoes, red onion, and parsley over the top. Drizzle the remaining 1 tbsp olive oil over each serving and serve immediately with warm pita bread."}},{"id":59,"servings":4,"tipType":"fish","timeMins":{"total":50,"active":40},"pairingsType":"mediterranean","origin":{"ja":"クロアチア","en":"Croatia","ro":"Croația"},"name":{"ja":"クルニ・リゾット","en":"Crni Rizot","ro":"Crni Rižot"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["新鮮または解凍したイカ500g、内臓を取り、墨袋2〜3個を残す","アルボリオ米またはカルナローリ米300g","中玉ねぎ1個（約150g）、みじん切り","にんにく3かけ、みじん切り","辛口ダルマチア産白ワイン（またはPošip）100ml","温かい魚のだし1リットル（または水と魚だしキューブ1個）","エキストラバージンオリーブオイル60ml","冷たいバター30g、角切り","新鮮なパセリ大さじ2、みじん切り","レモン1/2個、果汁のみ","塩小さじ1","黒こしょう小さじ1/2"],"en":["500 g fresh or thawed squid, cleaned, with 2-3 ink sacs reserved","300 g arborio or carnaroli rice","1 medium onion (about 150 g), finely chopped","3 garlic cloves, finely minced","100 ml dry Dalmatian white wine (or Pošip)","1 litre warm fish stock (or water with 1 fish stock cube)","60 ml extra-virgin olive oil","30 g cold butter, cubed","2 tbsp fresh parsley, chopped","1/2 lemon, juice only","1 tsp fine sea salt","1/2 tsp ground black pepper"],"ro":["500 g calmari proaspeti sau decongelati, curatati, cu 2-3 saculeti de cerneala separati","300 g orez arborio sau carnaroli","1 ceapa medie (cca 150 g), tocata marunt","3 căței de usturoi, tocati marunt","100 ml vin alb sec dalmatian (sau Pošip)","1 litru fond de peste cald (sau apa cu 1 cub de fond de peste)","60 ml ulei de masline extravirgin","30 g unt rece, taiat cubulete","2 linguri patrunjel proaspat, tocat","1/2 lamaie, doar zeama","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat"]},"howIsMade":{"ja":"イカを丁寧に下処理する：墨袋を壊さないよう少量の水と共に小さなボウルに分け、胴を1cmの輪切りに、足を半分に切る。大きめの厚手のフライパンにオリーブオイル大さじ4を中火で熱し、玉ねぎを4-5分炒めて柔らかくし、にんにくをさらに1分炒める。イカの輪と足を加え2-3分炒めて表面が白くなる程度に火を通し、ワインを注いで完全に蒸発させる（約2分）。米を加え1分かき混ぜて油をなじませ、温かい魚のだしを1杯ずつ加えながら絶えずかき混ぜる — 合計16-18分。途中で残りのだしに墨袋を破って混ぜ鍋に注ぐと、リゾットが瞬時に深い漆黒に変わり、海の風味が深まる。米がアル・デンテでクリーミー、まだ少しだしが残った状態で火を止め、冷たいバター、残りのオリーブオイル大さじ2、レモン汁、パセリを加える。30秒間しっかりかき混ぜてマンテカトゥーラを行い、蓋をして2分休ませる。すぐに深皿に盛り、上からパセリを散らし、レモン一切れを添えて提供する。","en":"Clean the squid carefully: lift out the ink sacs intact into a small bowl with a splash of water, then cut the bodies into 1 cm rings and halve the tentacles. In a wide heavy pan, heat 4 tbsp olive oil over medium heat and sauté the onion for 4-5 minutes until soft, then add the garlic for 1 minute more. Add the squid rings and tentacles, sauté for 2-3 minutes until just opaque, then pour in the wine and let it evaporate completely (about 2 minutes). Add the rice and stir for 1 minute to coat with fat, then begin adding the hot fish stock one ladle at a time, stirring constantly for 16-18 minutes total. Halfway through, break the ink sacs into the remaining stock and pour it in — the risotto turns deep jet black instantly and gains a profound oceanic depth. When the rice is al dente and creamy with a little stock still pooling, kill the heat and add the cold butter, the remaining 2 tbsp olive oil, the lemon juice, and the parsley. Stir vigorously for 30 seconds for the mantecatura, then cover and rest for 2 minutes. Serve immediately in shallow bowls with extra parsley on top and a wedge of lemon alongside."}},{"id":60,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"モンゴル","en":"Mongolia","ro":"Mongolia"},"name":{"ja":"ボーズ","en":"Buuz","ro":"Buuz"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["生地：薄力粉300g（打ち粉用に追加）","ぬるま湯150ml（約50°C）","塩小さじ1/2","具材：羊のひき肉400g（または羊と牛の合いびき）","中玉ねぎ1個（約150g）、みじん切り","にんにく3かけ、みじん切り","ひまわり油大さじ2","クミンパウダー小さじ1","塩小さじ1","黒こしょう（粗挽き）小さじ1/2","冷水50ml"],"en":["Dough: 300 g all-purpose flour, plus extra for dusting","150 ml warm water (about 50 C)","1/2 tsp fine salt","Filling: 400 g ground lamb (or half lamb, half beef)","1 medium onion (about 150 g), finely diced","3 garlic cloves, finely minced","2 tbsp sunflower oil","1 tsp ground cumin","1 tsp fine sea salt","1/2 tsp ground black pepper","50 ml cold water"],"ro":["Aluat: 300 g făină alba, plus extra pentru intins","150 ml apa calda (cca 50 C)","1/2 lingurita sare fina","Umplutura: 400 g carne de miel tocata (sau amestec miel-vita)","1 ceapa medie (cca 150 g), taiata marunt","3 căței de usturoi, tocati marunt","2 linguri ulei de floarea-soarelui","1 lingurita chimen macinat","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat","50 ml apa rece"]},"howIsMade":{"ja":"生地を作る：小麦粉と塩を合わせ、ぬるま湯を注いで5-6分こね、なめらかで弾力のある生地にする。湿ったタオルで覆い、30分休ませる。具を作る：羊のひき肉、玉ねぎ、にんにく、油、クミン、塩、黒こしょう、冷水をボウルに合わせ、手でよく混ぜて均一でやや粘りのある状態にする。生地を20〜24等分（各約20g）し、それぞれを直径約10cmの薄い円形に延ばし、中心を端より少し厚めにする。各円の中央に具を大さじ1杯分（約25g）のせる。具を囲むように端を持ち上げてひだを寄せ、中央に小さな蒸気穴を残す——モンゴル伝統の形。蒸し器にクッキングシートを敷き、ボーズを2cm間隔で並べる。中華鍋や浅い鍋に水を入れて強火で沸騰させ、蒸し器をのせて20〜22分、生地が完全に火が通り中の肉がピンク色でなくなるまで蒸す。すぐに提供する。","en":"Make the dough: mix flour and salt, pour in the warm water, and knead for 5-6 minutes until smooth and elastic. Cover with a damp cloth and rest for 30 minutes. Make the filling: combine the lamb, onion, garlic, oil, cumin, salt, pepper, and cold water in a bowl and mix well with your hands until evenly combined and slightly sticky. Divide the dough into 20-24 equal pieces (about 20 g each) and roll each into a thin round about 10 cm across, keeping the centre slightly thicker than the edges. Place 1 heaped tablespoon (about 25 g) of filling in the centre of each round. Lift the edges up around the filling and pleat them together at the top, leaving a small steam hole in the centre — the classic Mongolian shape. Line a bamboo steamer with parchment paper or cabbage leaves and arrange the buuz in a single layer with 2 cm between each. Fill a wok or wide pot with water and bring to a rolling boil; set the steamer basket over the boiling water and steam for 20-22 minutes until the dough is cooked through and the filling is no longer pink inside. Serve immediately."}},{"id":61,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"パキスタン","en":"Pakistan","ro":"Pakistan"},"name":{"ja":"ビリヤニ","en":"Biryani","ro":"Biryani"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["骨なし鶏もも肉（または仔羊の肩肉）800g、大きめに切り分け、可能なら骨付き","全脂無糖ヨーグルト200g、泡立てておく","ジンジャーガーリックペースト 大さじ2","ガラムマサラ 小さじ1","チリパウダー 小さじ1","ターメリック 小さじ1/2","塩 小さじ1","温めた牛乳 大さじ3 + サフランの糸 ひとつまみ","バスマティライス 400g","水 2.5リットル（米の下茹で用）","ギー 大さじ4","グリーンカルダモン 4粒","ブラックカルダモン 2粒","シナモンスティック 1本","クローブ 6粒","ローリエ 2枚","大きな玉ねぎ 2個、薄切り","中サイズのトマト 2個、すりおろす","生ミントのみじん切り 大さじ2","生コリアンダー（パクチー）のみじん切り 大さじ2","追加のギー 大さじ1、溶かしておく（回しかけ用）","添えに：冷たいヨーグルトのライタ、レモンのくし切り"],"en":["800g boneless chicken thighs (or lamb shoulder), cut into large pieces, bone-in if possible","200g plain whole-milk yoghurt, whisked","2 tbsp ginger-garlic paste","1 tsp garam masala","1 tsp chilli powder","1/2 tsp turmeric","1 tsp salt","3 tbsp warm milk + a pinch of saffron threads","400g basmati rice","2.5 litres water (for par-boiling the rice)","4 tbsp ghee","4 green cardamom pods","2 black cardamom pods","1 cinnamon stick","6 cloves","2 bay leaves","2 large onions, thinly sliced","2 medium tomatoes, grated","2 tbsp chopped fresh mint","2 tbsp chopped fresh coriander","1 tbsp extra ghee, melted (to drizzle)","To serve: cold yoghurt raita, lemon wedges"],"ro":["800 g pulpe de pui dezosate (sau spata de miel), taiate cuburi mari, cu os daca este posibil","200 g iaurt gras de vaca, batut","2 linguri pasta de ghimbir-usturoi","1 lingurita garam masala","1 lingurita pudra de chili","1/2 lingurita turmeric","1 lingurita sare","3 linguri lapte cald + un varf de fire de sofran","400 g orez basmati","2,5 l apa (pentru fierberea partiala a orezului)","4 linguri ghee","4 capsule cardamom verde","2 capsule cardamom negru","1 bat de scortisoara","6 cuișoare","2 foi de dafin","2 cepe mari, taiate solzi subtiri","2 rosii medii, rase","2 linguri menta proaspata, tocata","2 linguri coriandru proaspat, tocat","1 lingura ghee suplimentar, topit (pentru stropit)","Pentru servit: raita de iaurt rece, felii de lamaie"]},"howIsMade":{"ja":"鶏肉（またはラム肉）800gに、泡立てたヨーグルト200g、ジンジャーガーリックペースト大さじ2、ガラムマサラ小さじ1、チリパウダー小さじ1、ターメリック小さじ1/2、塩小さじ1、温めた牛乳大さじ3に浸したサフラン少々を混ぜ合わせ、ラップをして最低1時間、理想的には冷蔵庫で4時間マリネする。 厚手の鍋にギーまたは油大さじ4を中火で溶かし、油が光ってきたらグリーンカルダモン4粒、ブラックカルダモン2粒、シナモンスティック1本、クローブ4粒、ローリエ1枚を加え、軽くパチパチと音がするまで30秒香りを立てる。 薄切りにした大きな玉ねぎ2個を加え、頻繁にかき混ぜながら12〜15分炒め、濃い茶色でカリッとさせる。半量はキッチンペーパーに取り出して飾り用にし、残りは香り立つ油とともに鍋に残す。 マリネした肉とすりおろしたトマト2個を鍋に入れ、中火で8〜10分炒め、ヨーグルトが分離し油が縁に浮いてくるまで混ぜる。火を弱めて蓋をし、さらに15分煮込んで肉がほぼ柔らかくソースが濃いままになるようにする。 同時にバスマティライス400gを水が澄むまで洗って30分浸水させ、別鍋に水2.5リットルを沸かして塩小さじ2、カルダモン3粒、シナモン1本、ローリエ2枚を加え、油を数滴落として米を投入し、ちょうど5〜6分茹でて粒が70%、芯がまだ固い状態にしてすぐ湯切りする。 肉のマサラの上に湯切りした米の半量を広げ、揚げ玉ねぎの半量、刻んだミント大さじ2、コリアンダー大さじ2を散らし、残りの米を重ねる。サフラン入り温牛乳大さじ4と溶かしギー大さじ2を回しかけ、残りの玉ねぎ、ミント、コリアンダーで仕上げる。 鍋を密閉できる蓋で閉じる（またはアルミ箔で覆って蓋を押し付ける）、最弱火に置き、可能なら火力分散プレートまたは鉄板の上で蓋を開けずにダム調理を25分行う、こもった蒸気が米と肉を同時に仕上げる。 火を止めて密閉した鍋を10分休ませる、蓋を開けて側面から中央に向かってフォークで優しくほぐし肉と米の層をなじませ、冷たいヨーグルトのライタとレモンのくし切りを添えてすぐに供する。","en":"Mix 800 g chicken (or lamb) with 200 g whisked yoghurt, 2 tbsp ginger-garlic paste, 1 tsp garam masala, 1 tsp chilli powder, 1/2 tsp turmeric, 1 tsp salt and a pinch of saffron threads soaked in 3 tbsp warm milk; cover and marinate at least 1 hour, ideally 4 hours in the fridge. Melt 4 tbsp ghee or oil in a heavy-bottomed pot over medium heat; when it shimmers, add 4 green cardamom pods, 2 black cardamom pods, 1 cinnamon stick, 4 cloves and 1 bay leaf and let them bloom for 30 seconds until they crackle lightly. Add 2 large onions sliced thin and fry for 12-15 minutes, stirring often, until deep brown and crisp; lift out half onto kitchen paper for garnish and leave the rest in the pot with the aromatic oil. Slide the marinated meat into the pot with 2 grated tomatoes and cook 8-10 minutes over medium heat, stirring until the yoghurt breaks and the oil rises to the edges; lower the heat and simmer covered another 15 minutes until the meat is almost tender but the sauce stays thick. Meanwhile rinse 400 g basmati rice until the water runs clear and soak for 30 minutes; bring 2.5 litres of water to the boil with 2 tsp salt, 3 cardamom pods, 1 cinnamon stick and 2 bay leaves, slip in the rice with a few drops of oil and cook for exactly 5-6 minutes until the grains are 70% done — still firm in the centre; drain at once. Spread half of the drained rice over the meat masala, scatter half of the fried onions, 2 tbsp chopped mint and 2 tbsp coriander, then layer the remaining rice on top; drizzle with 4 tbsp warm saffron milk and 2 tbsp melted ghee, and finish with the remaining onions, mint and coriander. Seal the pot with a tight lid (or cover with foil and press the lid down), set it on the lowest possible flame, ideally over a heat diffuser or a cast-iron tava, and dum cook for 25 minutes without lifting the lid — the trapped steam finishes the rice and meat together. Turn off the heat and let the sealed pot rest for 10 minutes; open, gently fluff from the side inwards to fold the meat and rice layers, and serve straight away with cold yoghurt raita and lemon wedges."},"timeMins":{"total":105,"active":50}},{"id":62,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ja":"チュニジア","en":"Tunisia","ro":"Tunisia"},"name":{"ja":"ブリック","en":"Brik","ro":"Brik"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["ブリック生地（マルスーカ/ウアルカ）4枚、直径約30cm（春巻きの皮で代用可）","大きな卵4個（1枚につき1個）","オリーブオイル漬けのツナ缶160g、しっかり水切り","小さな玉ねぎ1個（約80g）、みじん切り","小さなケーパー大さじ3、洗って粗く刻む","イタリアンパセリ20g、みじん切り","クミンパウダー小さじ1/2","塩小さじ1/2","カイエンペッパーまたはハリッサペースト小さじ1/4","揚げ油（植物油）500ml","レモン1個（4等分）、添え用"],"en":["4 sheets of brik pastry (or malsouka/ouarka), about 30 cm in diameter (or spring roll wrappers as substitute)","4 large eggs (1 per brik)","160 g canned tuna in olive oil, well drained","1 small onion (about 80 g), finely diced","3 tbsp small capers, rinsed and roughly chopped","20 g flat-leaf parsley, finely chopped","1/2 tsp ground cumin","1/2 tsp fine sea salt","1/4 tsp cayenne pepper or harissa paste","500 ml vegetable oil for deep-frying","1 lemon, cut into 4 wedges, to serve"],"ro":["4 foi de brik (sau malsouka/ouarka), cca 30 cm diametru (sau foi de spring roll ca substitut)","4 oua mari (1 pe brik)","160 g ton la conserva in ulei de masline, bine scurs","1 ceapa mica (cca 80 g), taiata marunt","3 linguri capere mici, clatite si tocate grosier","20 g patrunjel plat, tocat marunt","1/2 lingurita chimen macinat","1/2 lingurita sare fina de mare","1/4 lingurita ardei iute macinat sau harissa","500 ml ulei vegetal pentru prajit adanc","1 lamaie, taiata in 4, pentru servire"]},"howIsMade":{"ja":"水気を切ったツナ、玉ねぎ、ケーパー、パセリ、クミン、塩、カイエンをボウルに合わせてよく混ぜ、具を作る。植物油を深くて広いフライパンに3-4cmの深さまで注ぎ、175°Cに熱する。ブリック生地を清潔な台に広げ、ツナ具の1/4量を生地の下半分に置き、中央に軽くくぼみを作る。くぼみに卵を1個割り入れる。素早く生地を半分に折り半月形にし、縁をしっかり押さえて卵が漏れないよう閉じる。ブリックを熱した油に丁寧に滑り込ませ、片面1.5〜2分、一度ひっくり返しながら全面が深い金色でカリッとするまで揚げる。穴あきレードルで取り出し、30秒キッチンペーパーで油切りする。すぐに提供する — 黄身はとろとろからわずかに固まった状態、生地はパリパリに仕上がるはず。上からレモンを絞る。","en":"Combine the drained tuna, onion, capers, parsley, cumin, salt, and cayenne in a bowl and mix well to make the filling. Pour the vegetable oil into a deep, wide pan to a depth of 3-4 cm and heat to 175°C. Lay a brik pastry sheet flat on a clean surface and spoon a quarter of the tuna filling onto the lower half, creating a slight hollow in the centre. Crack 1 egg into the hollow. Working quickly, fold the pastry in half to form a half-moon, pressing the edges firmly together to seal and prevent the egg from escaping. Carefully slide the brik into the hot oil and fry for 1.5-2 minutes per side until deep golden and crisp all over, flipping once with a wide spatula. Lift out with a slotted spoon and drain on paper towels for 30 seconds. Serve immediately — the yolk should be runny to lightly set and the pastry crackling crisp. Squeeze a lemon wedge over the top."}},{"id":63,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ja":"ジョージア","en":"Georgia","ro":"Georgia"},"name":{"ja":"ハチャプリ","en":"Khachapuri","ro":"Khachapuri"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ja":["薄力粉（中力粉可）500g、打ち粉用に少量","インスタントドライイースト 7g（1袋）","砂糖 小さじ1","細挽きの海塩 小さじ1","ぬるま湯 250ml（約40°C）","オリーブオイル 大さじ2","スルグニチーズまたはモッツァレラ 400g、粗くすりおろす","フェタチーズ 200g、ほぐす","大きな卵 4個（ハチャプリ1つにつき1個）","無塩バター 40g、4等分に切る"],"en":["500 g plain flour (all-purpose), plus extra for dusting","7 g instant yeast (1 sachet)","1 tsp caster sugar","1 tsp fine sea salt","250 ml warm water (about 40°C / 105°F)","2 tbsp olive oil","400 g sulguni or mozzarella, coarsely grated","200 g feta cheese, crumbled","4 large eggs (1 per khachapuri)","40 g unsalted butter, cut into 4 equal pieces"],"ro":["500 g făină albă, plus extra pentru pudrare","7 g drojdie instant (1 plic)","1 linguriță zahăr","1 linguriță sare fină de mare","250 ml apă caldă (aproximativ 40°C)","2 linguri ulei de măsline","400 g suluguni sau mozzarella, ras grosier","200 g brânză feta, sfărâmată","4 ouă mari (câte 1 pentru fiecare khachapuri)","40 g unt nesărat, tăiat în 4 bucăți egale"]},"howIsMade":{"ja":"大きなボウルに薄力粉、イースト、砂糖、塩を入れて混ぜ、ぬるま湯とオリーブオイルを加えてひとまとめにしてから、打ち粉をした台の上で8〜10分こねて滑らかでやや弾力のある生地に仕上げる。丸めてオイルを薄く塗ったボウルに入れ、湿らせた布で覆い、温かい場所で1時間休ませて2倍の大きさに発酵させる。発酵中にすりおろしたスルグニ（またはモッツァレラ）とほぐしたフェタを混ぜてフィリングを作り、250°Cに予熱したオーブンに重いベーキングトレイまたはピザストーンを入れておく。発酵した生地を4等分し、打ち粉をした台の上でそれぞれを25x15cmほどの楕円形に伸ばす。長辺を3cmずつ内側に折り込んでクルッと巻き上げて縁を作り、両端をしっかり合わせてつまんでボート型に整える。クッキングシートの上にボート型を並べ、各キャビティにチーズのフィリングを四等分して詰め、熱したトレイに滑らせて12〜14分焼き、生地が黄金色になりチーズが泡立ってうっすら焼き色がついたら取り出す。チーズの中央を軽く押して窪みを作り、卵を1個ずつ割り入れてオーブンに戻し、白身が固まり黄身がとろとろの状態になるまで3〜4分焼く。卵の上にバターをひとかけらのせてすぐに供し、パンの縁を引きちぎってとろけたチーズと黄身に浸して食べる。","en":"Mix the flour, yeast, sugar, and salt in a large bowl, add the warm water and olive oil and stir to a rough dough, then knead on a lightly floured surface for 8-10 minutes until smooth and slightly tacky. Shape into a ball, place in an oiled bowl, cover with a damp cloth, and leave in a warm place for 1 hour until doubled in size. While the dough rises, mix the grated sulguni (or mozzarella) and crumbled feta together in a bowl; heat the oven to 250°C (230°C fan) with a heavy baking tray or pizza stone inside. Divide the risen dough into 4 equal pieces and roll each on a lightly floured surface into an oval about 25 x 15 cm. Fold the long edges inward by 3 cm and roll them up into a thick raised border, then pinch both short ends firmly together to form a boat shape. Arrange the boats on baking parchment, fill each cavity completely with a quarter of the cheese mixture, then slide onto the hot tray and bake for 12-14 minutes until the crust is golden and the cheese is bubbling and lightly browned. Remove from the oven, press a small hollow in the centre of each cheese filling, crack 1 egg into each hollow, and return to the oven for 3-4 minutes until the white is just set but the yolk remains runny. Place a piece of butter on top of each egg and serve immediately — tear strips of the border and dip into the melted cheese and yolk."}},{"id":64,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"南アフリカ","en":"South Africa","ro":"Africa de Sud"},"name":{"ja":"ボボティ","en":"Bobotie","ro":"Bobotie"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛または羊の赤身ひき肉 750g","中玉ねぎ2個（計約300g）、みじん切り","白パン2枚（約60g）、耳を除く","全乳 125ml、使用量を分けておく","大きな卵 2個","サルタナレーズン 50g","ドライアプリコット（約6個）30g、みじん切り","アプリコットジャムまたはスイートチャツネ 大さじ2","マイルドカレーパウダー 大さじ2","ターメリックパウダー 小さじ1","植物油 大さじ2","細挽きの海塩 小さじ1","黒こしょう 小さじ1/2","ローリエ（生または乾燥）4枚"],"en":["750 g lean beef or lamb mince","2 medium onions (about 300 g total), finely diced","2 slices white bread (about 60 g), crusts removed","125 ml whole milk, divided","2 large eggs","50 g sultanas (golden raisins)","30 g dried apricots (about 6), finely chopped","2 tbsp apricot jam or sweet chutney","2 tbsp mild curry powder","1 tsp ground turmeric","2 tbsp vegetable oil","1 tsp fine sea salt","1/2 tsp ground black pepper","4 fresh or dried bay leaves"],"ro":["750 g carne tocată de vită sau miel, slabă","2 cepe medii (aproximativ 300 g), fin tocate","2 felii pâine albă (aproximativ 60 g), fără coajă","125 ml lapte integral, împărțit","2 ouă mari","50 g stafide galbene (sultane)","30 g caise uscate (aproximativ 6 bucăți), fin tocate","2 linguri gem de caise sau chutney dulce-picant","2 linguri pudră de curry blând","1 linguriță turmeric măcinat","2 linguri ulei vegetal","1 linguriță sare fină de mare","1/2 linguriță piper negru măcinat","4 foi de dafin proaspete sau uscate"]},"howIsMade":{"ja":"パンを牛乳60mlに5分浸し、余分な液を絞って小さなボウルでほぐす。大きなフライパンに油を熱し、玉ねぎを加えて中高火で8〜10分炒め、しんなりして黄金色になるまで炒める。カレーパウダーとターメリックを加えて1分香りが立つまで炒め、ひき肉を加えて8〜10分、塊を崩しながら炒め、全体に火が通り水分が飛んだら火を止める。浸したパン、レーズン、ドライアプリコット、ジャム、塩、胡椒を加えてよく混ぜる。オーブンを180°C（160°Cコンベクション）に予熱し、中サイズの耐熱皿（約25×20cm）に軽くバターを塗る。肉の混合物を皿に移して平らに押しつけ、ローリエを表面に差し込む。卵と残りの牛乳65mlに塩少々を加えて滑らかに混ぜ、肉の上に均一に流す。カスタードが固まり黄金色になるまで35〜40分焼く。5分休ませてからイエローライスとチャツネを添えて供する。","en":"Soak the bread in 60 ml of the milk for 5 minutes, then squeeze out the excess liquid and crumble into a small bowl. Heat the oil in a large frying pan over medium-high heat, add the onions and cook, stirring, for 8-10 minutes until soft and golden. Add the curry powder and turmeric and stir for 1 minute until fragrant, then add the mince and cook for 8-10 minutes, breaking up any lumps, until browned and all liquid has evaporated. Remove from the heat and mix in the soaked bread, sultanas, dried apricots, apricot jam, salt, and pepper until evenly combined. Heat the oven to 180°C (160°C fan) and lightly grease a medium baking dish (about 25 x 20 cm). Transfer the meat mixture into the dish, press it into an even layer, and tuck the bay leaves into the surface. Beat the eggs with the remaining 65 ml milk and a pinch of salt until smooth, then pour evenly over the meat. Bake for 35-40 minutes until the custard topping is set and golden brown with no wobble in the centre. Rest for 5 minutes before serving with yellow rice, chutney, and sambals."}},{"id":65,"servings":4,"tipType":"fish","pairingsType":"latin","origin":{"ja":"ペルー","en":"Peru","ro":"Peru"},"name":{"ja":"セビーチェ","en":"Ceviche","ro":"Ceviche"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["非常に新鮮な白身魚の切り身（スズキ、カレイ、またはヒラメ）700g、皮と骨を除く","ライム果汁 180ml（ライム約8〜10個分）、味を見て追加","小さな赤玉ねぎ（約150g）1個、半月形の薄切り","アヒ・アマリリョ1〜2本またはハラペーニョ1本、種を除いてみじん切り","にんにく 1かけ、すりおろし","新鮮なしょうが（約1cm）小さじ1、すりおろし","新鮮なコリアンダー（パクチー）30g、葉と細い茎をざく切り","細挽きの海塩 小さじ1","白こしょうパウダー 小さじ1/4","トウモロコシ 2本、茹でて5cmの輪切りにする","小さなさつまいも（約400g）2個、柔らかくなるまで茹でて皮をむき、薄切り"],"en":["700 g very fresh white fish fillets (sea bass, sole, or halibut), skin and bones removed","180 ml fresh lime juice (about 8-10 limes), plus more to taste","1 small red onion (about 150 g), halved and thinly sliced into half-moons","1-2 ají amarillo chillies or 1 jalapeño, deseeded and finely diced","1 garlic clove, finely grated","1 tsp fresh ginger (about 1 cm piece), finely grated","30 g fresh coriander (cilantro), leaves and fine stems, roughly chopped","1 tsp fine sea salt","1/4 tsp ground white pepper","2 ears of corn, boiled and cut into 5 cm rounds","2 small sweet potatoes (about 400 g), boiled until tender, peeled and sliced"],"ro":["700 g file de pește alb foarte proaspăt (biban de mare, limbă sau halibut), fără piele și oase","180 ml suc proaspăt de lime (aproximativ 8-10 lime-uri), plus extra după gust","1 ceapă roșie mică (aproximativ 150 g), tăiată felii subțiri în jumătate de lună","1-2 ardei ají amarillo sau 1 jalapeño, fără semințe, fin tocați","1 căței de usturoi, fin ras","1 linguriță ghimbir proaspăt (aproximativ 1 cm), fin ras","30 g coriandru proaspăt, frunze și tulpini subțiri, grosier tocat","1 linguriță sare fină de mare","1/4 linguriță piper alb măcinat","2 știuleți de porumb, fierți și tăiați în rondele de 5 cm","2 cartofi dulci mici (aproximativ 400 g), fierți, curățați și feliați"]},"howIsMade":{"ja":"キッチンペーパーで魚の水分を拭き取り、2cmの角切りにして残った骨を取り除き、非反応性のボウル（ガラスや陶器）に入れる。塩と白こしょうを振りかけて混ぜ、赤玉ねぎ・チリ・にんにく・しょうがを加えてやさしく和える。ライム果汁を注ぐ——魚がほぼ浸かる量——ゆっくりと混ぜ、魚を押し沈める。ラップをして10〜15分冷蔵し、途中一度混ぜる。各ブロックの外側が不透明でほんのり弾力が出てきたが、中心がまだわずかに半透明な状態が古典的なペルースタイル。塩とライム果汁を調整し、コリアンダーの大半を加えて混ぜ、少量をトッピング用に取り置く。冷やしたボウルにトウモロコシの輪切りとさつまいものスライスを添えてすぐに供し、残りのコリアンダーをのせる。","en":"Pat the fish dry with paper towels and cut into 2 cm cubes, removing any remaining pin bones, then place in a non-reactive bowl (glass or ceramic). Season with the salt and white pepper and toss to coat. Add the red onion, chilli, garlic, and ginger and mix gently. Pour over the lime juice — it should nearly cover the fish — then stir gently and press the fish down to submerge it as much as possible. Cover and refrigerate for 10-15 minutes, stirring once halfway through, until the outside of each cube is opaque and just firm to the touch while the very centre remains slightly translucent — the classic Peruvian style, not fully cooked through. Taste and adjust salt and lime juice. Stir in most of the coriander, reserving a little for garnish. Serve immediately in chilled bowls alongside the corn rounds and sweet potato slices, with the remaining coriander scattered over the top."}},{"id":66,"servings":8,"tipType":"korean","pairingsType":"korean","origin":{"ja":"韓国","en":"South Korea","ro":"Coreea de Sud"},"name":{"ja":"キムチ","en":"Kimchi","ro":"Kimchi"},"category":{"ja":"副菜","en":"Side dish","ro":"Garnitură"},"ingredients":{"ja":["白菜1株（約2kg）","非ヨード化海塩大さじ3","コチュガル（韓国産唐辛子フレーク）大さじ4","にんにく5かけ（みじん切り）","おろし生姜小さじ1","ナンプラー大さじ1（ヴィーガンは醤油）","砂糖小さじ1","ねぎ6本（3cm切り）","にんじん1本（せん切り）"],"en":["1 large napa cabbage (about 2 kg)","3 tbsp sea salt (non-iodised)","4 tbsp gochugaru (Korean red pepper flakes)","5 cloves garlic, finely minced","1 tsp fresh ginger, grated","1 tbsp fish sauce (or soy sauce for vegan)","1 tsp sugar","6 spring onions, cut into 3cm pieces","1 medium carrot, julienned"],"ro":["1 varză napa mare (aprox. 2 kg)","3 linguri sare de mare (fără iod)","4 linguri gochugaru (fulgi de ardei coreean)","5 căței de usturoi, tocați mărunt","1 linguriță ghimbir proaspăt, ras","1 lingură sos de pește (sau sos de soia pentru variantă vegană)","1 linguriță zahăr","6 cepe verzi, tăiate în bucăți de 3 cm","1 morcov mediu, julien"]},"howIsMade":{"ja":"白菜を縦に4等分し、5cmの幅に切る。塩をまぶし、手で2〜3分もみ込み、1〜2時間置く（ときどき返す）。しんなりして水分が出たら冷水で2〜3回しっかりすすいで水気を絞る；適度な塩辛さになればOK。コチュガル・にんにく・生姜・ナンプラー・砂糖をボウルで混ぜ、ねぎとにんじんを加える。絞った白菜を合わせ、手袋をしてすべてに赤いペーストが均一に絡まるようによく和える。清潔な1Lの瓶に空気を抜きながら隙間なく詰め、3〜4cmの余白を残す。室温で1〜2日置いてから冷蔵庫へ移す——3〜5日で食べ頃、1週間後がより美味。","en":"Quarter the napa cabbage lengthwise, then cut crosswise into 5cm pieces. Toss with sea salt and massage 2–3 minutes, let sit 1–2 hours turning occasionally until the cabbage has wilted and released water. Rinse the cabbage thoroughly in cold water 2–3 times, drain and squeeze firmly to remove excess moisture; it should taste pleasantly salty — rinse once more if too salty. Mix gochugaru, garlic, ginger, fish sauce and sugar in a bowl; add spring onions and carrot. Add drained cabbage to the paste and mix thoroughly with your hands (wear gloves) — every piece should be evenly coated in red paste. Pack tightly into clean 1-litre jars, press down firmly to eliminate air pockets, leaving 3–4 cm of headspace; leave at room temperature for 1–2 days, then refrigerate — kimchi is ready in 3–5 days and best after 1 week."}},{"id":67,"servings":4,"tipType":"meat","timeMins":{"total":285,"active":60},"pairingsType":"vietnamese","origin":{"ja":"ベトナム","en":"Vietnam","ro":"Vietnam"},"name":{"ja":"バインミー","en":"Banh Mi","ro":"Banh Mi"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["小さめのバゲット4本（各約20cm）、縦半分に切る","豚ヒレ肉 400g、薄切り（約5mm）","醤油 大さじ2","ナンプラー 大さじ1","ごま油 小さじ1 + 砂糖 小さじ1 + 黒こしょう 小さじ1/4（マリネ用）","中玉にんじん 2本（約200g）、皮をむいて千切り","大根 100g、皮をむいて千切り（またはにんじんで代用）","米酢 大さじ3","砂糖 大さじ1 + 塩 小さじ1/2（なます用）","鶏レバーパテ 60g","マヨネーズ 大さじ4","大きなきゅうり 1本、細い棒状に切る","ハラペーニョまたは赤唐辛子 2本、薄い輪切り","新鮮なコリアンダー（パクチー）20g、枝ごと"],"en":["4 small baguettes or demi-baguettes (about 20 cm each), halved lengthwise","400 g pork tenderloin, thinly sliced (about 5 mm)","2 tbsp soy sauce","1 tbsp fish sauce","1 tsp sesame oil + 1 tsp sugar + 1/4 tsp black pepper (marinade)","2 medium carrots (about 200 g), peeled and julienned","100 g daikon, peeled and julienned (or extra carrot)","3 tbsp rice vinegar","1 tbsp sugar + 1/2 tsp fine salt (for pickling)","60 g chicken liver pâté","4 tbsp mayonnaise","1 large cucumber, cut into thin batons","2 jalapeños or red chillies, thinly sliced","20 g fresh coriander, sprigs"],"ro":["4 baghetele mici (de circa 20 cm), tăiate pe lungime","400 g mușchi de porc, tăiat felii subțiri (circa 5 mm)","2 linguri sos de soia","1 lingură sos de pește","1 linguriță ulei de susan + 1 linguriță zahăr + 1/4 linguriță piper negru (pentru marinadă)","2 morcovi medii (aproximativ 200 g), curățați și tăiați julienne","100 g daikon (ridiche asiatică), curățat și juliennat (sau morcov în plus)","3 linguri oțet de orez","1 lingură zahăr + 1/2 linguriță sare (pentru murat)","60 g pate de ficat de pui","4 linguri maioneză","1 castravete mare, tăiat bețe subțiri","2 jalapeño sau ardei roșii, tăiați rondele","20 g coriandru proaspăt, crenguțe"]},"howIsMade":{"ja":"にんじんと大根を米酢・砂糖・塩と合わせてよく混ぜ、少なくとも20分（冷蔵庫では最大4時間）漬けて、やや柔らかくなりつつもシャキシャキした食感が残る状態にする。醤油・ナンプラー・ごま油・砂糖・黒こしょうを合わせ、豚肉を加えてよく絡め、常温で15〜20分マリネする。重いフライパンまたはグリルパンを強火で煙が出るほど熱し、豚肉を2〜3回に分けて一層に並べ、片面1〜2分ずつ、端がキャラメル色で全体が金色になるまで焼く。バゲットを200°Cのオーブンで4〜5分焼いて皮をパリッとさせる。切り口にパテとマヨネーズをたっぷり塗る。温かい豚肉、水気を切ったなます、きゅうりの棒切り、ハラペーニョ、コリアンダーの枝を重ねる。軽く押さえてすぐに供する。","en":"Combine the carrots and daikon with the rice vinegar, sugar, and salt, toss well, and leave to pickle for at least 20 minutes (or up to 4 hours in the fridge) until slightly softened but still crunchy. Mix the soy sauce, fish sauce, sesame oil, sugar, and black pepper in a bowl, add the sliced pork, and toss to coat; marinate for 15-20 minutes at room temperature. Heat a heavy frying pan or griddle over high heat until smoking, add the pork in a single layer in 2-3 batches, and cook for 1-2 minutes per side until caramelised and golden brown at the edges. Toast the baguettes in a 200°C oven for 4-5 minutes until the crust is crisp. Spread the cut sides generously with pâté and mayonnaise. Layer in the warm pork slices, the drained pickled carrots and daikon, cucumber batons, jalapeño slices, and generous sprigs of coriander. Press gently and serve immediately."}},{"id":68,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"インドネシア","en":"Indonesia","ro":"Indonezia"},"name":{"ja":"サテ","en":"Satay","ro":"Satay"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["骨なし皮なし鶏もも肉 700g、2cmの角切り","醤油 大さじ3","ココナッツミルク 大さじ2","薄力粉ブラウンシュガー 大さじ1","コリアンダーパウダー 小さじ2","クミンパウダー 小さじ1","ターメリックパウダー 小さじ1","にんにく 2かけ、すりおろし","レモングラス 1本、白い部分のみみじん切り","クリームピーナッツバター 200g","ココナッツミルク 200ml（ソース用）","ケチャップマニス（甘口醤油） 大さじ2","ライム果汁 大さじ1","サンバルオエレクまたはスリラチャ 小さじ1","竹串 20本、冷水に30分浸す"],"en":["700 g boneless skinless chicken thighs, cut into 2 cm cubes","3 tbsp soy sauce","2 tbsp coconut milk","1 tbsp light brown sugar","2 tsp ground coriander","1 tsp ground cumin","1 tsp ground turmeric","2 garlic cloves, finely grated","1 lemongrass stalk, pale part only, finely minced","200 g smooth peanut butter","200 ml coconut milk (for sauce)","2 tbsp kecap manis (sweet soy sauce)","1 tbsp lime juice","1 tsp sambal oelek or sriracha","20 bamboo skewers, soaked in cold water for 30 minutes"],"ro":["700 g pulpe de pui dezosate și fără piele, tăiate cubulețe de 2 cm","3 linguri sos de soia","2 linguri lapte de cocos","1 lingură zahăr brun pal","2 lingurițe coriandru măcinat","1 linguriță chimen măcinat","1 linguriță turmeric măcinat","2 căței de usturoi, fin rași","1 tulpină lemongrass, partea palidă, fin tocată","200 g unt de arahide cremos","200 ml lapte de cocos (pentru sos)","2 linguri kecap manis (sos de soia dulce)","1 lingură suc de lime","1 linguriță sambal oelek sau sriracha","20 bețișoare de bambus, înmuiate în apă rece 30 de minute"]},"howIsMade":{"ja":"醤油、ココナッツミルク、ブラウンシュガー、コリアンダーパウダー、クミン、ターメリック、にんにく、レモングラスをボウルに混ぜてマリネを作る。鶏肉を加えてよく絡め、常温で少なくとも30分、または冷蔵庫で最大4時間マリネする。ピーナッツソースを作る：小鍋にピーナッツバター、ココナッツミルク、ケチャップマニス、ライム果汁、サンバルを合わせ、弱火で3〜4分混ぜて滑らかでシルキーな状態にする（濃すぎれば水で伸ばす）。鶏肉4〜5個ずつ水に浸した竹串に押し付けながら刺す。炭火グリルまたは鋳鉄のグリルパンを強火で熱し、軽く油を塗る。串焼きを片面3〜4分、一度返して焼き、表面にこんがりとした焼き色がついて串からスムーズに外れるまで焼く（内部温度75°C）。温かいピーナッツソースときゅうりのスライスを添えてすぐに供する。","en":"Mix the soy sauce, coconut milk, brown sugar, ground coriander, cumin, turmeric, garlic, and lemongrass in a bowl to make the marinade. Add the chicken cubes, toss to coat, and marinate for at least 30 minutes at room temperature or up to 4 hours in the refrigerator. Make the peanut sauce: combine the peanut butter, coconut milk, kecap manis, lime juice, and sambal in a small saucepan over low heat and stir for 3-4 minutes until smooth and silky; thin with a splash of water if too thick. Thread 4-5 chicken pieces onto each soaked skewer, pressing them close together. Heat a charcoal grill, cast-iron griddle, or grill pan over high heat and brush lightly with oil. Grill the skewers for 3-4 minutes per side, turning once, until deeply charred in spots and the chicken pulls away from the skewer easily — internal temperature should reach 75°C. Serve immediately with the warm peanut sauce for dipping and sliced cucumber alongside."}},{"id":69,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"ja":"マレーシア","en":"Malaysia","ro":"Malaysia"},"name":{"ja":"ラクサ","en":"Laksa","ro":"Laksa"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["ラクサペースト 大さじ3（または赤カレーペーストにエビペースト小さじ1を加えたもの）","植物油 大さじ2","ココナッツミルク 800ml（400ml缶 × 2）","鶏ガラスープまたは水 600ml","ナンプラー 大さじ2","砂糖 小さじ1","生の中サイズのエビ 400g、殻と背わたを除く","木綿豆腐 200g、水切りして2cm角に切る","新鮮な豆もやし 200g","ライスバーミセリ 200g、沸騰した湯に3分浸してザルに上げる","大きな卵 4個、固ゆで（7分）してむき、半分に切る","さやいんげん 100g、端を切り落として半分に切る","ライム 2個、くし形に切る","新鮮なコリアンダー 20g、葉のみ","青ねぎ 2本、薄切り"],"en":["3 tbsp laksa paste (or red curry paste with 1 tsp shrimp paste added)","2 tbsp vegetable oil","800 ml coconut milk (2 x 400 ml cans)","600 ml chicken stock or water","2 tbsp fish sauce","1 tsp sugar","400 g raw medium prawns, peeled and deveined","200 g firm tofu, drained and cut into 2 cm cubes","200 g fresh bean sprouts","200 g rice vermicelli noodles, soaked in boiling water 3 minutes and drained","4 large eggs, hard-boiled (7 minutes), peeled and halved","100 g green beans, trimmed and halved","2 limes, cut into wedges","20 g fresh coriander, leaves only","2 spring onions, thinly sliced"],"ro":["3 linguri pastă laksa (sau pastă de curry roșu cu 1 linguriță pastă de creveți)","2 linguri ulei vegetal","800 ml lapte de cocos (2 conserve de 400 ml)","600 ml supă de pui sau apă","2 linguri sos de pește","1 linguriță zahăr","400 g creveți cruzi medii, curățați și devenați","200 g tofu ferm, scurs și tăiat cuburi de 2 cm","200 g muguri de soia proaspeți","200 g vermicelli de orez, înmuiați în apă clocotită 3 minute și scurși","4 ouă mari, fierte tari (7 minute), decojite și tăiate jumătate","100 g fasole verde, curățată și tăiată în jumătăți","2 lime, tăiate felii","20 g coriandru proaspăt, frunze","2 cepe verzi, feliate subțire"]},"howIsMade":{"ja":"ライスバーミセリを沸騰したお湯に3分浸し、ザルにあけて冷水で洗って水気を切り、置いておく。卵を7分固ゆでにして氷水で冷やし、むいて半分に切る。大きなフライパンまたはウォックに油を熱し、ラクサペーストを加えて常に混ぜながら2〜3分炒め、香りが立ちオイルが分離してきたら次の工程へ。コナッツミルクと鶏ガラスープを注いで穏やかな沸騰を保つ。ナンプラーと砂糖を加えて味見し、スープは濃厚でやや塩味があるべき。さやいんげんを加えて3分煮たら、エビと豆腐を加えてさらに2〜3分、エビがピンクになって火が通るまで煮る。麺を4つの深めのボウルに分け、エビ・豆腐・いんげん入りの熱いスープを注ぐ。豆もやし・ゆで卵の半分・青ねぎ・コリアンダーを各ボウルにのせる。ライムのくし形切りを添えてすぐに供する。","en":"Soak the rice vermicelli in boiling water for 3 minutes, drain, rinse under cold water, and set aside. Hard-boil the eggs for 7 minutes, cool in iced water, peel, and halve. Heat the oil in a large wok or saucepan over medium heat, add the laksa paste, and fry, stirring constantly, for 2-3 minutes until fragrant and the oil begins to separate. Pour in the coconut milk and chicken stock and bring to a steady simmer. Add the fish sauce and sugar, taste, and adjust — the broth should be rich and slightly salty. Add the green beans and cook for 3 minutes, then add the prawns and tofu and cook for 2-3 minutes until the prawns are pink and just cooked through. Divide the noodles between 4 deep bowls and ladle the hot broth with prawns, tofu, and beans on top. Finish each bowl with bean sprouts, 2 halved eggs, spring onions, and coriander. Serve immediately with lime wedges on the side."}},{"id":70,"servings":4,"tipType":"def","pairingsType":"mexican","origin":{"ja":"エルサルバドル","en":"El Salvador","ro":"El Salvador"},"name":{"ja":"ププサ","en":"Pupusa","ro":"Pupusa"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["マサハリーナ（例：Maseca、ニキスタマル処理済みコーン粉）400g、追加分も用意","ぬるま湯 350ml（約40°C）、必要に応じて追加","細挽きの海塩 小さじ1","缶詰の炒り黒豆またはピント豆 200g、温めておく","ケソ・ケシージョまたはモッツァレラ 200g、粗くすりおろす","植物油 大さじ2（焼き用）","白キャベツ 300g（約1/4玉）、ごく細く千切り","小さなにんじん（約80g）1本、皮をむいて粗くすりおろす","小さな白玉ねぎ（約60g）半個、薄切り","りんご酢または白ワインビネガー 100ml","水 100ml（カルティード用）","塩 小さじ1 + 砂糖 小さじ1（カルティード用）","乾燥オレガノ 小さじ1/2","トマトサルサ 200ml、添え用"],"en":["400 g masa harina (nixtamalized corn flour, such as Maseca), plus extra","350 ml warm water (about 40°C), plus more if needed","1 tsp fine sea salt","200 g canned refried black or pinto beans, warmed","200 g queso quesillo or mozzarella, coarsely grated","2 tbsp vegetable oil (for cooking)","300 g white cabbage (about 1/4 head), very finely shredded","1 small carrot (about 80 g), peeled and coarsely grated","1/2 small white onion (about 60 g), thinly sliced","100 ml apple cider vinegar or white vinegar","100 ml water (for curtido)","1 tsp fine salt + 1 tsp sugar (for curtido)","1/2 tsp dried oregano","200 ml tomato salsa, to serve"],"ro":["400 g masa harina (făină de porumb nixtamalizată, ex. Maseca), plus extra","350 ml apă caldă (circa 40°C), plus dacă e nevoie","1 linguriță sare fină de mare","200 g fasole neagră sau pinto refulată (din conservă, încălzită)","200 g queso quesillo sau mozzarella, ras grosier","2 linguri ulei vegetal (pentru prăjit)","300 g varză albă (aprox. 1/4 căpățână), fin feliată","1 morcov mic (aprox. 80 g), curățat și ras","1/2 ceapă albă mică (aprox. 60 g), felii subțiri","100 ml oțet de mere sau oțet alb","100 ml apă (pentru curtido)","1 linguriță sare fină + 1 linguriță zahăr (pentru curtido)","1/2 linguriță oregano uscat","200 ml salsa de roșii pentru servit"]},"howIsMade":{"ja":"まずカルティードを作る：キャベツ・にんじん・玉ねぎをボウルに合わせ、酢・水・塩・砂糖・オレガノを混ぜて注ぎ、よく和えて少なくとも30分（または冷蔵庫で一晩）漬けておく。生地を作る：マサハリーナと塩を大きなボウルで合わせ、ぬるま湯を少しずつ加えながら手でこねて滑らかで弾力のある生地にする——割れずにまとまるべき；必要なら水を大さじ1ずつ足す。リフライドビーンズとすりおろしたチーズを混ぜてフィリングを作る。生地を8等分（各約90g）にする。濡らした手のひらで一つを直径約12cmの丸く平らにし、フィリングを山盛り大さじ2杯中央に置き、縁を引き上げてしっかりつまんで閉じる；厚さ約1cm、直径12cmの円盤に整え、割れ目を補修する。重い鉄板または鋳鉄のフライパンを中高火で熱して油を薄く引く。3〜4分ずつ、暗い焦げ目がつき表面が乾いてベタつきがなくなるまで焼く。カルティードを上にたっぷりのせてサルサを添え、熱いうちに供する。","en":"Make the curtido first: combine the cabbage, carrot, and onion in a bowl, mix the vinegar, water, salt, sugar, and oregano, pour over the vegetables, toss well, and set aside to pickle for at least 30 minutes (or overnight in the fridge). Make the dough: combine the masa harina and salt in a large bowl, pour in the warm water gradually, and mix with your hands until a smooth, pliable dough forms — it should hold together without cracking; add a tablespoon of water at a time if needed. Mix the refried beans and grated cheese together to make the filling. Divide the dough into 8 equal balls (about 90 g each). Press a ball flat in your damp palm into a disc about 12 cm across, place 2 heaped tablespoons of filling in the centre, then fold the edges up over the filling and pinch firmly to seal; gently re-flatten into a disc about 1 cm thick and 12 cm wide, patching any cracks. Heat a heavy griddle or cast-iron skillet over medium-high heat and brush with oil. Cook the pupusas in batches for 3-4 minutes per side until dark golden-brown patches appear and the dough feels dry rather than tacky. Serve hot with the curtido piled on top and salsa alongside."}},{"id":72,"servings":4,"tipType":"fish","pairingsType":"vietnamese","origin":{"ja":"カンボジア","en":"Cambodia","ro":"Cambodgia"},"name":{"ja":"アモック","en":"Amok","ro":"Amok"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["白身魚の切り身（ティラピア、鯛、またはナマズ）600g、皮なし、3cmのひと口大に切る","ココナッツミルク 400ml（400ml缶 × 1）","大きな卵 2個、軽く溶く","ナンプラー 大さじ3","グラニュー糖 小さじ1","レモングラス 2本、白い部分のみ、非常に細かく刻む","にんにく 3かけ、細かく刻む","シャロット 3個（約100g）、細かく刻む","ガランガルペースト 小さじ1（または新鮮なガランガル1cm、すりおろし）","ターメリックパウダー 小さじ1/2","乾燥チリフレーク 小さじ1/2、または生の赤唐辛子 1本、細切り","カフィルライムの葉 4枚、茎を取り除いて非常に細かく切る","大きなバナナの葉のシート 4枚（30 x 30cm）、炎の上で柔らかくしたもの、またはラメキン型 4個","新鮮なバジルまたはタイバジルの葉 20g、飾り用"],"en":["600 g white fish fillets (tilapia, snapper, or catfish), skin removed, cut into 3 cm pieces","400 ml coconut milk (1 x 400 ml can)","2 large eggs, lightly beaten","3 tbsp fish sauce","1 tsp caster sugar","2 lemongrass stalks, pale parts only, very finely minced","3 garlic cloves, finely minced","3 shallots (about 100 g), finely minced","1 tsp galangal paste (or 1 cm fresh galangal, grated)","1/2 tsp ground turmeric","1/2 tsp dried chilli flakes or 1 fresh red chilli, finely sliced","4 kaffir lime leaves, stems removed, very finely shredded","4 large banana leaf squares (30 x 30 cm), softened over a flame, or 4 ramekins","20 g fresh basil or Thai basil leaves, to garnish"],"ro":["600 g file de pește alb (tilapia, biban sau somn), fără piele, tăiat bucăți de 3 cm","400 ml lapte de cocos (1 conservă de 400 ml)","2 ouă mari, ușor bătute","3 linguri sos de pește","1 linguriță zahăr","2 tulpini lemongrass, doar partea palidă, fin tocate","3 căței de usturoi, fin tocați","3 șalote (aproximativ 100 g), fin tocate","1 linguriță pastă de galangal (sau 1 cm galangal proaspăt, ras)","1/2 linguriță turmeric măcinat","1/2 linguriță fulgi de ardei iute uscat sau 1 ardei roșu, fin tocat","4 frunze de kaffir lime, cotoare îndepărtate, fin feliate","4 pătrate mari de frunze de bananier (30 x 30 cm), înmuiate, sau ramekine","20 g frunze de busuioc proaspăt sau busuioc thai, pentru garnitură"]},"howIsMade":{"ja":"レモングラス、にんにく、シャロット、ガランガル、ターメリック、チリを滑らかなペーストになるまで乳鉢でつぶすかブレンドする。大きなボウルにコナッツミルク、溶き卵、ナンプラー、砂糖を合わせてよく混ぜ、スパイスペーストと刻んだカフィルライムの葉の半量を加える。魚を加えてやさしく和え、15分マリネする。バナナの葉をガスコンロの炎の上か熱湯に30秒当てて柔らかくする。各シートを幅12cm・深さ4cmほどのカップ型に折り畳み、爪楊枝で固定する。魚の混合物を4つのカップに均等に分け、それぞれ3分の2ほどまで入れ、残りのカフィルライムの葉を散らす。カップを沸騰した湯の上に置いた竹製蒸し器にセットし、しっかりふたをして18〜20分蒸す。カップを静かに傾けても液状でなく、表面がほんのり固まっていたらできあがり。バジルの葉を飾り、ジャスミンライスを添えてすぐに供する。","en":"Pound or blend the lemongrass, garlic, shallots, galangal, turmeric, and chilli into a smooth paste. In a large bowl, whisk together the coconut milk, beaten eggs, fish sauce, and sugar until combined. Stir in the spice paste and half the shredded kaffir lime leaves. Add the fish pieces and fold gently to coat; marinate for 15 minutes. Soften the banana leaf squares over a gas flame or in hot water for 30 seconds until pliable. Fold each into a cup shape about 12 cm across and 4 cm deep, securing with a toothpick. Divide the fish mixture evenly among the 4 banana leaf cups, filling each about two-thirds full, then scatter the remaining kaffir lime leaves on top. Set the cups in a bamboo steamer over boiling water, cover tightly, and steam for 18-20 minutes until the amok is just set — no longer liquid when the cup is gently tilted — and the top is slightly firm to the touch. Garnish with fresh basil leaves and serve immediately with steamed jasmine rice."}},{"id":73,"servings":4,"tipType":"meat","pairingsType":"indian","origin":{"ja":"ネパール","en":"Nepal","ro":"Nepal"},"name":{"ja":"モモ","en":"Momo","ro":"Momo"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["薄力粉 300g（打ち粉用に少量追加）","ぬるま湯 150ml","鶏または豚のひき肉 500g","中玉ねぎ 1個（約120g）、ごく細かいみじん切り","にんにく 3片、細かいみじん切り","生姜 大さじ1（約2cm分）、細かくすりおろす","パクチー（コリアンダー） 30g、細かく刻む","クミンパウダー 小さじ1","コリアンダーパウダー 小さじ1/2","ターメリック 小さじ1/4","塩 小さじ1（2カ所に分けて使用）","中サイズのトマト 4個（約400g）、半分に切る","乾燥赤唐辛子 2本 または 唐辛子フレーク 小さじ1/2","植物油 大さじ1"],"en":["300 g plain flour (all-purpose), plus extra for dusting","150 ml warm water","500 g ground chicken or pork","1 medium onion (about 120 g), very finely diced","3 garlic cloves, finely minced","1 tbsp fresh ginger (about 2 cm piece), finely grated","30 g fresh coriander (cilantro), finely chopped","1 tsp ground cumin","1/2 tsp ground coriander","1/4 tsp ground turmeric","1 tsp fine sea salt, divided","4 medium tomatoes (about 400 g), halved","2 dried red chillies or 1/2 tsp chilli flakes","1 tbsp vegetable oil"],"ro":["300 g făină albă (tip 550), plus extra pentru pudrat","150 ml apă caldă","500 g carne tocată de pui sau porc","1 ceapă medie (circa 120 g), tocată mărunt","3 căței de usturoi, tocați mărunt","1 lingură ghimbir proaspăt (circa 2 cm), ras fin","30 g coriandru proaspăt, tocat mărunt","1 linguriță chimen măcinat","1/2 linguriță coriandru măcinat","1/4 linguriță turmeric","1 linguriță sare fină, împărțită","4 roșii medii (circa 400 g), tăiate în jumătăți","2 ardei iuți uscați sau 1/2 linguriță fulgi de ardei iute","1 lingură ulei vegetal"]},"howIsMade":{"ja":"ボウルに薄力粉と塩小さじ1/2を合わせ、ぬるま湯を少しずつ加えながら5〜6分こねて、なめらかで弾力があり、べたつかない生地を作る。湿らせた布をかけて30分休ませる。別のボウルにひき肉、玉ねぎ、にんにく、生姜、パクチー、クミン、コリアンダーパウダー、ターメリック、残りの塩小さじ1/2、油を加えてよく混ぜ、冷蔵庫で15分なじませる。タレを作る：トマトと乾燥唐辛子を乾いたフライパンで強火にかけ4〜5分、柔らかく焦げ目がついたら、にんにくと塩ともにミキサーでなめらかになるまで撹拌する。生地を24等分（各約15g）に切り分け、それぞれを直径8cmの薄い円形に伸ばす。中央に山盛り小さじ1の具をのせ、縁を小さい重ね折りでひだをつけながら包み、上部をしっかりつまんで封じる。軽く油を塗ったクッキングシートを敷いた蒸し器にモモを1cm間隔で並べる。沸騰した湯の上で12〜15分蒸し、皮が透き通り、軽く押すと弾力がある状態にする。トマトチリソースを添えてすぐに供する。","en":"Combine flour and 1/2 tsp of the salt in a bowl, then add warm water a little at a time, mixing until a rough dough forms; knead for 5-6 minutes until smooth, firm, and no longer sticky, then cover with a damp cloth and rest for 30 minutes. In a separate bowl, mix the ground meat, onion, garlic, ginger, coriander leaves, cumin, ground coriander, turmeric, the remaining 1/2 tsp salt, and oil until well combined; refrigerate for 15 minutes to let the flavours meld. Meanwhile, make the dipping sauce: char the tomato halves and dried chillies in a dry heavy skillet over high heat for 4-5 minutes until softened and blackened in spots, then blend with the garlic and remaining salt until smooth. Divide the rested dough into 24 equal pieces (about 15 g each) and roll each into a thin round about 8 cm across. Place a heaped teaspoon of filling in the centre of each round, then gather the edges and pleat them together with small overlapping folds, pinching firmly at the top to seal. Line a bamboo or metal steamer with lightly oiled parchment paper and arrange the momo at least 1 cm apart. Set over a pot of vigorously boiling water, cover tightly, and steam for 12-15 minutes until the wrappers turn translucent and a gently pressed momo springs back without feeling doughy inside. Serve immediately with the tomato-chilli sauce."}},{"id":74,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ja":"エクアドル","en":"Ecuador","ro":"Ecuador"},"name":{"ja":"エンセボジャード","en":"Encebollado","ro":"Encebollado"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["新鮮なマグロ 700g、またはツナ缶2缶（水煮、計400g）、汁を切ったもの","キャッサバ（ユカ）600g、皮をむいて4cm角に切ったもの","大きな赤玉ねぎ 1個（約200g）、薄い半月切り","中サイズのトマト 4個（約400g）、ざく切り","にんにく 4片、粗みじん切り","クミンパウダー 小さじ1","アチョーテペースト 小さじ1、または甘口パプリカ 小さじ1/2","フィッシュストック、または水 1.5リットル","ライムジュース 大さじ3（ライム約2個分）","植物油 大さじ2","塩 小さじ1","パクチー（コリアンダー）30g、2つに分ける（半分は調理用、半分はトッピング用）","ハラペーニョまたはアヒペッパー 1本、種を除いて薄切り","小ねぎ 2本、薄切り（飾り用）"],"en":["700 g fresh tuna or 2 cans tuna in water (400 g total), drained","600 g cassava (yuca), peeled and cut into 4 cm chunks","1 large red onion (about 200 g), thinly sliced into half-moons","4 medium tomatoes (about 400 g), roughly chopped","4 garlic cloves, roughly chopped","1 tsp ground cumin","1 tsp achiote paste or 1/2 tsp sweet paprika","1.5 litres fish stock or water","3 tbsp fresh lime juice (about 2 limes)","2 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), divided — half to cook, half to garnish","1 jalapeño or aji pepper, deseeded and finely sliced","2 spring onions, thinly sliced (to garnish)"],"ro":["700 g ton proaspăt sau 2 conserve ton în apă (400 g total), scurse","600 g yuca (manioc), curățată și tăiată bucăți de 4 cm","1 ceapă roșie mare (circa 200 g), tăiată în felii subțiri","4 roșii medii (circa 400 g), tăiate grosier","4 căței de usturoi, tăiați grosier","1 linguriță chimen măcinat","1 linguriță pastă de achiote sau 1/2 linguriță paprika dulce","1,5 litri supă de pește sau apă","3 linguri zeamă de lămâie verde (circa 2 lămâi)","2 linguri ulei vegetal","1 linguriță sare fină","30 g coriandru proaspăt, împărțit — jumătate pentru gătit, jumătate pentru servit","1 jalapeno sau ardei iute, fără semințe, feliat subțire","2 fire ceapă verde, tăiate subțire (pentru decor)"]},"howIsMade":{"ja":"大きな鍋に油を中火で熱し、玉ねぎ、にんにく、トマト、ハラペーニョ、クミンを加え、時々かき混ぜながら8〜10分炒めて玉ねぎを完全に柔らかくしトマトをとろりとした状態にする。アチョーテペーストを加えて1分炒め、油が深いオレンジ色になったらストックを注ぐ。煮立ったらキャッサバを加え、20〜25分煮て完全に柔らかくし端がほぐれ始めるまで火を通す。生マグロを使う場合は、塩を少し加えた沸騰寸前の湯に入れて5〜6分ポーチし、少し冷ましてから大きめにほぐす。ほぐしたマグロ（またはツナ缶）、パクチーの半量、ライムジュースを鍋に加え、弱火で3〜4分煮て味をなじませる。塩で味を調え、深皿に盛り付ける。残りのパクチーと小ねぎをトッピングし、トスタダスまたはバナナチップスを添えて提供する。","en":"Heat the oil in a large pot over medium heat, add the onion, garlic, tomatoes, jalapeño, and cumin, and cook for 8-10 minutes, stirring occasionally, until the onion is very soft and the tomatoes have broken down into a thick paste. Stir in the achiote paste and cook for 1 minute until the oil turns a deep orange. Pour in the stock, bring to a boil, then add the cassava and cook for 20-25 minutes until completely tender and just beginning to break apart at the edges. If using fresh tuna, poach the steaks in lightly salted simmering water for 5-6 minutes until just cooked through, cool slightly, and flake into large chunks. Add the flaked tuna (or drained canned tuna), half the coriander, and the lime juice to the pot; simmer for 3-4 minutes to marry the flavours. Season with salt to taste, then ladle the soup into deep bowls. Top with the remaining coriander and spring onions, and serve with tostadas or plantain chips on the side."}},{"id":75,"servings":4,"tipType":"soup","pairingsType":"middle-eastern","origin":{"ja":"モロッコ","en":"Morocco","ro":"Maroc"},"name":{"ja":"ハリラ","en":"Harira","ro":"Harira"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["ラム肩肉 400g、3cm角に切ったもの","ひよこ豆（缶詰）400g（1缶400g）、水を切って洗ったもの","緑色または茶色のレンズ豆 150g、洗ったもの","中サイズのトマト 4個（約400g）、ざく切り","大きな玉ねぎ 1個（約200g）、ごく細かいみじん切り","葉つきセロリ 3本（約150g）、薄切り","にんにく 3片、細かいみじん切り","クミンパウダー 小さじ1","シナモン 小さじ1 + 生姜パウダー 小さじ1","ターメリック 小さじ1/2 + 塩 小さじ1","オリーブオイル 大さじ2","水またはラムストック 1.5リットル","細いバーミセリ 60g、2cm長さに折ったもの","新鮮なパクチーとイタリアンパセリ 30g、粗みじん切り"],"en":["400 g lamb shoulder, cut into 3 cm chunks","400 g canned chickpeas (1 x 400 g can), rinsed and drained","150 g green or brown lentils, rinsed","4 medium tomatoes (about 400 g), roughly chopped","1 large onion (about 200 g), finely diced","3 celery stalks with leaves (about 150 g), finely sliced","3 garlic cloves, finely minced","1 tsp ground cumin","1 tsp ground cinnamon + 1 tsp ground ginger","1/2 tsp ground turmeric + 1 tsp fine sea salt","2 tbsp olive oil","1.5 litres water or lamb stock","60 g thin vermicelli, broken into 2 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped"],"ro":["400 g spata de miel, taiata bucati de 3 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","150 g linte verde sau bruna, clatita","4 rosii medii (circa 400 g), taiate grosier","1 ceapa mare (circa 200 g), tocata marunt","3 tulpini de telina cu frunze (circa 150 g), feliate subtire","3 căței de usturoi, tocati marunt","1 lingurita chimen macinat","1 lingurita scortisoara + 1 lingurita ghimbir macinat","1/2 lingurita turmeric + 1 lingurita sare fina","2 linguri ulei de masline","1,5 litri apa sau supa de miel","60 g vermicelli subtire, rupt in bucati de 2 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier"]},"howIsMade":{"ja":"大きな鍋に油を中強火で熱し、ラム肉を加えて4〜5分、時々返しながら全面を焼き付ける。玉ねぎ、セロリ、にんにくを加えて5分炒め、しんなりさせる。クミン、シナモン、生姜、ターメリック、塩を加えて1分炒め、スパイスの香りを引き出す。トマト、ひよこ豆、レンズ豆を加えて水またはストックを注ぎ、沸騰したらアクを取る。火を弱めて蓋を少しずらし、45〜50分煮込み、ラムが柔らかくなりレンズ豆がスープに溶け込んで少しとろみが出るまで待つ。バーミセリを加え5〜6分煮る。火を止めてコリアンダーとパセリを混ぜ込み、レモン汁をお好みで加える。ボウルに盛り、パンとナツメヤシを添えてすぐに提供する。","en":"Heat the oil in a large pot over medium-high heat, add the lamb chunks and sear for 4-5 minutes, turning occasionally, until browned on all sides. Add the onion, celery, and garlic and cook for 5 minutes until softened. Stir in the cumin, cinnamon, ginger, turmeric, and salt and cook for 1 minute until fragrant. Add the tomatoes, chickpeas, and lentils, pour in the water or stock, and bring to a boil; skim any foam from the surface. Reduce the heat to low, cover partially, and simmer for 45-50 minutes until the lamb is tender and the lentils have dissolved into the broth, thickening it slightly. Stir in the vermicelli and cook for 5-6 minutes until tender. Remove from the heat, stir in the coriander and parsley, and squeeze in lemon juice to taste. Ladle into bowls and serve immediately with crusty bread and dates."}},{"id":76,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"ja":"ジョージア","en":"Georgia","ro":"Georgia"},"name":{"ja":"ロビオ","en":"Lobio","ro":"Lobio"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["乾燥赤インゲン豆 500g（または400g缶詰 2缶、洗ったもの）","大きな玉ねぎ 1個（約200g）、ごく細かいみじん切り","にんにく 4片、細かいみじん切り","クルミ 100g（ハーフ）、細かく砕くか細かく刻む","コリアンダーパウダー 小さじ1","フェネグリーク 小さじ1/2（ウツォ・スネリ）","シナモン 小さじ1/2","唐辛子フレーク 小さじ1/2 または小さな赤唐辛子 1本種を除いて刻む","白ワインビネガーまたは赤ワインビネガー 大さじ2","植物油 大さじ3","塩 小さじ1","新鮮なパクチー 30g、細かく刻む","ザクロの実 大さじ4（約1/2個分）","小ねぎ 4本、薄切り"],"en":["500 g dried red kidney beans (or 2 x 400 g cans, rinsed)","1 large onion (about 200 g), finely diced","4 garlic cloves, finely minced","100 g walnut halves, finely ground or very finely chopped","1 tsp ground coriander","1/2 tsp ground fenugreek (utsho suneli)","1/2 tsp ground cinnamon","1/2 tsp dried chilli flakes or 1 small red chilli, deseeded and minced","2 tbsp white wine vinegar or red wine vinegar","3 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), finely chopped","4 tbsp pomegranate seeds (about 1/2 pomegranate)","4 spring onions, thinly sliced"],"ro":["500 g fasole rosie uscata (sau 2 x 400 g conserve, clatite)","1 ceapa mare (circa 200 g), tocata marunt","4 căței de usturoi, tocati marunt","100 g miez de nuca, macinat fin sau tocat marunt","1 lingurita coriandru macinat","1/2 lingurita schinduf macinat (utsho suneli)","1/2 lingurita scortisoara","1/2 lingurita fulgi de ardei iute sau 1 ardei iute mic, fara seminte, tocat","2 linguri otet alb sau de vin rosu","3 linguri ulei vegetal","1 lingurita sare fina","30 g coriandru proaspat, tocat marunt","4 linguri boabe de rodie (circa 1/2 rodie)","4 fire ceapa verde, taiate subtire"]},"howIsMade":{"ja":"乾燥豆を使う場合は一晩冷水に浸し、水を切り、大きな鍋に新しい冷水を張って中火にかけ、アクを取りながら弱火で45〜60分、豆が完全に柔らかくほぐれ始め、煮汁が濃い赤でとろりとした状態になるまで煮る。フライパンに油を中火で熱し、玉ねぎを加えて時々かき混ぜながら10〜12分、濃いきつね色でとても柔らかくなるまで炒める。にんにく、コリアンダーパウダー、フェネグリーク、シナモン、チリを加えて2分炒め、香りを出す。玉ねぎの炒め物、砕いたクルミ、酢を豆に加え弱火で10分、時々かき混ぜながら煮込み、風味がなじみ豆が非常に柔らかくとろりとしたソース状になるまで — 鍋の縁に豆を数粒押しつけてつぶしてとろみを出す。塩と酢を調整する。火を止め、パクチーの半量を混ぜ込む。浅皿に盛り、小ねぎ、ザクロの実、残りのパクチーをのせ、温かいままパンを添えて供する。","en":"If using dried beans, soak them overnight in cold water, then drain, cover with fresh cold water in a large pot, bring to a boil, skim any foam, and simmer for 45-60 minutes until completely tender and starting to break apart, with a thick dark-red cooking liquid. Heat the oil in a frying pan over medium heat, add the onion and cook for 10-12 minutes, stirring occasionally, until deep golden and very soft. Add the garlic, ground coriander, fenugreek, cinnamon, and chilli and cook for 2 minutes until fragrant. Stir the onion mixture, ground walnuts, and vinegar into the cooked beans and simmer over low heat for 10 minutes, stirring occasionally, until the flavours meld and the beans are very soft with a thick sauce — mash a few beans against the side of the pot to help thicken. Season with salt and more vinegar to taste. Remove from the heat and stir in half the fresh coriander. Transfer to a shallow dish and top with the spring onions, pomegranate seeds, and remaining coriander. Serve warm with flatbread."}},{"id":77,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"ja":"アルジェリア","en":"Algeria","ro":"Algeria"},"name":{"ja":"シャクシュカ","en":"Chakhchoukha","ro":"Chakhchoukha"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["骨つきラム肩肉または首肉 600g、4cm角に切ったもの","ひよこ豆（缶詰）400g（1缶400g）、水を切って洗ったもの","中サイズのトマト 4個（約400g）、ざく切り","中玉ねぎ 2個（約300g）、ごく細かいみじん切り","にんにく 4片、細かいみじん切り","植物油 大さじ2","クミンパウダー 小さじ1","コリアンダーパウダー 小さじ1","スイートパプリカ 小さじ1","シナモン 小さじ1/2 + 黒コショウ 小さじ1/2","塩 小さじ1","水またはラムストック 600ml","ルガグ（アルジェリアのフラットブレッド）または大きなトルティーヤ 4枚、5cm大にちぎったもの","新鮮なパクチーとイタリアンパセリ 30g、粗みじん切り（トッピング用）"],"en":["600 g bone-in lamb shoulder or neck, cut into 4 cm pieces","400 g canned chickpeas (1 x 400 g can), rinsed and drained","4 medium tomatoes (about 400 g), roughly chopped","2 medium onions (about 300 g), finely diced","4 garlic cloves, finely minced","2 tbsp vegetable oil","1 tsp ground cumin","1 tsp ground coriander","1 tsp sweet paprika","1/2 tsp ground cinnamon + 1/2 tsp ground black pepper","1 tsp fine sea salt","600 ml water or lamb stock","4 large sheets of rougag (Algerian flatbread) or large tortillas, torn into 5 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped (to garnish)"],"ro":["600 g spata de miel cu os sau gat, taiata bucati de 4 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","4 rosii medii (circa 400 g), taiate grosier","2 cepe medii (circa 300 g), tocate marunt","4 căței de usturoi, tocati marunt","2 linguri ulei vegetal","1 lingurita chimen macinat","1 lingurita coriandru macinat","1 lingurita boia dulce","1/2 lingurita scortisoara + 1/2 lingurita piper negru","1 lingurita sare fina","600 ml apa sau supa de miel","4 foi mari de rougag (lipie algeriana) sau 4 tortilla mari, rupte bucati de 5 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier (pentru decor)"]},"howIsMade":{"ja":"大きな重い鍋に油を強火で熱し、ラム肉を数回に分けて4〜5分、全面に焼き色がつくまでこんがり焼く。玉ねぎとにんにくを加えて5分炒め、柔らかく金色になるまで炒める。クミン、コリアンダー、パプリカ、シナモン、塩、コショウを加えてスパイスの香りが出るまで1分炒める。トマトを加えて8〜10分、時々かき混ぜながら煮てとろりとした濃いソース状にする。水またはストックを注ぎ、ひよこ豆を加えて沸騰させる。弱火に落として蓋をし、50〜60分煮込み、ラムが完全に柔らかくなり骨から外れるようになるまで待つ。大きな盛り皿の底に千切ったフラットブレッドを並べ、熱い肉とソースをたっぷりかけ、パンを優しく押さえて液体をしっかり吸わせる。新鮮なコリアンダーとパセリを散らしてすぐに供する。","en":"Heat the oil in a large heavy pot over medium-high heat, add the lamb in batches and sear for 4-5 minutes until browned on all sides. Add the onion and garlic and cook for 5 minutes until softened and golden. Stir in the cumin, coriander, paprika, cinnamon, salt, and pepper and cook for 1 minute until the spices smell toasted. Add the tomatoes and cook for 8-10 minutes, stirring occasionally, until they break down into a thick sauce. Pour in the water or stock, add the chickpeas, and bring to a boil; reduce the heat to low, cover, and simmer for 50-60 minutes until the lamb is completely tender and falling off the bone. Scatter the torn flatbread pieces over the bottom of a large serving dish and ladle the hot meat and sauce generously on top, pressing the bread down gently so it absorbs the liquid and softens — it should be soaked through but not dissolving. Garnish with the fresh coriander and parsley and serve immediately."}},{"id":78,"servings":4,"tipType":"meat","timeMins":{"total":330,"active":60},"pairingsType":"meat","origin":{"ja":"インドネシア","en":"Indonesia","ro":"Indonezia"},"name":{"ja":"ルンダン","en":"Rendang","ro":"Rendang"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛肩肉または胸肉 1kg、5cm角に切ったもの","ココナッツミルク 800ml（400ml缶 2缶）","シャロット 5個（約150g）、ざく切り","にんにく 4片、ざく切り","生姜 大さじ2（約3cm分）、ざく切り","ガランガル 大さじ1（約2cm分）またはガランガルペースト 小さじ1","レモングラス 3本、白い部分のみ、大きめに切る","乾燥赤唐辛子 4〜6本、温水に15分浸し、水を切ったもの","カフィルライムの葉 4枚、茎を取って細かく刻む","ターメリックパウダー 小さじ1","コリアンダーパウダー 小さじ1","クミンパウダー 小さじ1","塩 小さじ1","植物油 大さじ1"],"en":["1 kg beef chuck or brisket, cut into 5 cm cubes","800 ml full-fat coconut milk (2 x 400 ml cans)","5 shallots (about 150 g), roughly chopped","4 garlic cloves, roughly chopped","2 tbsp fresh ginger (about 3 cm piece), roughly chopped","1 tbsp fresh galangal (about 2 cm) or 1 tsp galangal paste","3 lemongrass stalks, pale parts only, roughly sliced","4-6 dried red chillies, soaked in warm water 15 minutes and drained","4 kaffir lime leaves, stems removed, very finely shredded","1 tsp ground turmeric","1 tsp ground coriander","1 tsp ground cumin","1 tsp fine sea salt","1 tbsp vegetable oil"],"ro":["1 kg muschi de vita sau piept, taiat cuburi de 5 cm","800 ml lapte de cocos integral (2 x 400 ml)","5 esalote (circa 150 g), taiate grosier","4 căței de usturoi, tăiați grosier","2 linguri ghimbir proaspat (circa 3 cm), taiat grosier","1 lingura galangal proaspat (circa 2 cm) sau 1 lingurita pasta galangal","3 tulpini de lemongrass, partile palide, feliate grosier","4-6 ardei iuti rosii uscati, înmuiați in apa calda 15 minute, scursi","4 frunze de kafir lime, coada indepartata, maruntite fin","1 lingurita turmeric macinat","1 lingurita coriandru macinat","1 lingurita chimen macinat","1 lingurita sare fina","1 lingura ulei vegetal"]},"howIsMade":{"ja":"シャロット、にんにく、生姜、ガランガル、レモングラス、浸した唐辛子をココナッツミルク大さじ2と一緒にフードプロセッサーで完全に滑らかなペースト状になるまで混ぜる — 約2分。大きな重い鍋に油を中火で熱し、スパイスペーストを加えて5〜6分間、常にかき混ぜながら炒め、深い黄金色になり生の香りが消えるまで続ける。牛肉の角切りを加えてペーストで全体を覆い、3〜4分炒めて軽く色がつくまで加熱する。残りのココナッツミルクを加え、カフィルライムの葉、ターメリック、コリアンダー、クミン、塩を入れて混ぜ合わせる。沸騰したら弱めの中火に落とし、蓋をせずに1時間半煮込み、15〜20分ごとにかき混ぜながらココナッツミルクが大幅に濃くなって薄茶色になるまで待つ。さらに30〜45分、より頻繁にかき混ぜながら煮続け、ソースがほぼ完全に蒸発して油が分離し、肉が自らの脂で揚げられ深いマホガニーブラウン色になったら完成。白飯と一緒に提供する。","en":"Blend the shallots, garlic, ginger, galangal, lemongrass, and soaked chillies with 2 tbsp of the coconut milk until completely smooth — about 2 minutes in a food processor. Heat the oil in a large heavy pot over medium heat, add the spice paste and cook for 5-6 minutes, stirring constantly, until deep golden and the raw smell has gone. Add the beef cubes and stir to coat with the paste; cook for 3-4 minutes until lightly coloured. Pour in the remaining coconut milk, add the kaffir lime leaves, turmeric, coriander, cumin, and salt, and stir to combine. Bring to a boil, then reduce to medium-low and simmer uncovered for 1.5 hours, stirring every 15-20 minutes, until the coconut milk thickens significantly and turns light brown. Continue cooking, stirring more frequently (every 5-10 minutes), for another 30-45 minutes as the sauce reduces to almost nothing and the oil splits from the coconut; the beef will begin to fry in its own fat and turn deep mahogany brown — this is when rendang is ready. Serve with steamed white rice."}},{"id":79,"servings":4,"tipType":"fish","timeMins":{"total":4380,"active":45},"pairingsType":"fish","origin":{"ja":"スウェーデン","en":"Sweden","ro":"Suedia"},"name":{"ja":"グラブラックス","en":"Gravlax","ro":"Gravlax"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["600gサーモンフィレ、皮付き、骨を取り除く","大さじ3の粗塩","大さじ2のグラニュー糖","小さじ1の白胡椒、粗くつぶす","60gの新鮮なディル（大束1束）、粗みじん切り","大さじ2のアクアビットまたはウォッカ（任意）"],"en":["600 g salmon fillet, skin-on and pin-boned","3 tbsp coarse sea salt","2 tbsp caster sugar","1 tsp white peppercorns, coarsely crushed","60 g fresh dill (1 large bunch), roughly chopped","2 tbsp aquavit or vodka (optional)"],"ro":["600 g file de somon cu piele, cu oasele îndepărtate","3 linguri sare grunjoasă de mare","2 linguri zahăr tos","1 linguriță boabe de piper alb, zdrobite grosier","60 g mărar proaspăt (1 legătură mare), tocat grosier","2 linguri aquavit sau vodcă (opțional)"]},"howIsMade":{"ja":"小さなボウルに粗塩、砂糖、砕いた白胡椒を混ぜ合わせます。大きなラップの上にサーモンを皮目を下にして置き、ディルの半量を肉面に均等に押しつけ、塩の硬化剤を均等に広げ、アクアビットを使う場合はふりかけ、残りのディルで覆います。ラップできつく包み、深い容器に入れ、上から重いお皿を乗せて魚を押さえます。48〜72時間冷蔵し、12時間ごとに包みをひっくり返します — 塩水が容器に溜まります。ラップを外し、冷水で洗い流し、キッチンペーパーで水気を拭き取ります。薄くて柔軟な刃のナイフで斜めに非常に薄くスライスし、黒パンまたはライ麦パンにマスタード・ディルソースを添えて提供します。","en":"Mix the coarse salt, sugar, and crushed peppercorns in a small bowl. Lay the salmon skin-side down on a large piece of cling film; press half the dill evenly over the flesh, spread the cure uniformly over the top, drizzle with aquavit if using, then cover with the remaining dill. Wrap tightly in the cling film and place in a deep dish, setting a heavy plate on top to press the fish. Refrigerate for 48-72 hours, turning the parcel every 12 hours as it cures — brine will pool in the dish. Unwrap, rinse under cold water, and pat dry with paper towels. Slice very thinly on the diagonal with a sharp flexible knife and serve on dark rye bread with a mustard-dill sauce."}},{"id":80,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ベルギー","en":"Belgium","ro":"Belgia"},"name":{"ja":"ストーフフレス","en":"Stoofvlees","ro":"Stoofvlees"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["1kgの煮込み用牛肉（肩またはバラ）、4cm角に切る","330mlのベルギー産ダークエール（Leffe Bruneなど）","500gの玉ねぎ（中3個ほど）、薄切り","大さじ2のディジョンマスタード","厚めのブラウンパン2枚（約80g）、耳なし","大さじ2のサラダ油","ローリエ2枚","新鮮なタイム3枝","大さじ1のブラウンシュガー","大さじ1の赤ワインビネガー","小さじ1の塩","小さじ1/2の黒こしょう"],"en":["1 kg beef stew meat (chuck or brisket), cut into 4 cm cubes","330 ml dark Belgian ale (Leffe Brune or similar)","500 g onions (about 3 medium), thinly sliced","2 tbsp Dijon mustard","2 thick slices (about 80 g) stale brown bread, crusts removed","2 tbsp neutral oil","2 bay leaves","3 fresh thyme sprigs","1 tbsp brown sugar","1 tbsp red wine vinegar","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["1 kg carne de vită pentru tocăniță (capac sau piept), tăiată cuburi de 4 cm","330 ml bere belgiană brună (Leffe Brune sau similară)","500 g ceapă (circa 3 medii), feliată subțire","2 linguri muștar Dijon","2 felii groase (circa 80 g) pâine brună veche, fără coajă","2 linguri ulei neutru","2 foi de dafin","3 crenguțe de cimbru proaspăt","1 lingură zahăr brun","1 lingură oțet de vin roșu","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ja":"牛肉に塩こしょうをふります。大きな鍋に油を熱し、中強火で牛肉を数回に分けて3〜4分ずつ表面をしっかり焼きつけ（両面とも深いきつね色になるまで）、取り出しておきます。火を中火に落とし、同じ鍋に玉ねぎを入れて12〜15分炒め、しんなりとした黄金色になるまで炒めます。牛肉を鍋に戻し、ローリエとタイムを加え、ビールを注ぎます — 肉がほぼ浸かる量が目安です。パンの片面にマスタードをたっぷり塗り、マスタード面を下にして煮込みの上に置きます；パンが溶けてソースにとろみをつけます。ブラウンシュガーとビネガーを加えてよく混ぜ、沸騰したら弱火にし、ふたを少しずらして2時間煮込み、30分ごとにかき混ぜながら肉がとても柔らかくなるまで煮ます。最後の20〜30分はふたを外し、ソースがスプーンの裏に張りつくほど艶やかで濃いグレービーになるまで煮詰めます；ローリエとタイムを取り除き、フリットまたはマッシュポテトとともにどうぞ。","en":"Season the beef with salt and pepper. Heat the oil in a large heavy casserole over medium-high and brown the beef in batches for 3-4 minutes per side until deeply golden; transfer to a plate. Reduce heat to medium, add the onions to the same pot and cook for 12-15 minutes, stirring occasionally, until soft and golden. Return the beef to the pot, tuck in the bay leaves and thyme, and pour in the beer — it should nearly cover the meat. Spread one side of each bread slice thickly with mustard and lay them mustard-side down on top of the stew; the bread will dissolve and thicken the sauce. Stir in the brown sugar and vinegar, bring to a gentle simmer, cover with the lid slightly ajar, and cook over low heat for 2 hours, stirring every 30 minutes, until the beef is very tender. Remove the lid for the final 20-30 minutes to reduce the sauce to a glossy dark gravy that coats the back of a spoon; discard the bay leaves and thyme and serve with frites or mashed potato."}},{"id":81,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"ja":"モルドバ","en":"Moldova","ro":"Moldova"},"name":{"ja":"ゼアマ","en":"Zeama","ro":"Zeamă"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["1kgの骨付き鶏肉（モモとムネ）","中くらいのニンジン2本（約200g）、皮をむいて半分に切る","中くらいの玉ねぎ1個、半分に切る","葉付きセロリの茎2本","150gの細い卵麺","200mlのボルシ（発酵小麦ふすまの液）または大さじ4の新鮮なレモン汁","新鮮なラヴェージ少量（約15g）、粗みじん切り、またはパセリ","小さじ1の塩","小さじ1/2の白こしょう"],"en":["1 kg bone-in chicken pieces (legs and thighs)","2 medium carrots (about 200 g), peeled and halved","1 medium onion, halved","2 celery stalks with leaves","150 g thin egg noodles","200 ml borș (fermented wheat bran liquid) or 4 tbsp fresh lemon juice","1 small bunch fresh lovage (about 15 g), roughly chopped, or flat-leaf parsley","1 tsp fine salt","1/2 tsp white pepper"],"ro":["1 kg bucăți de pui cu os (pulpe și coapse)","2 morcovi medii (circa 200 g), curățați și tăiați în jumătate","1 ceapă medie, tăiată în jumătate","2 tulpini de țelină cu frunze","150 g tăiței subțiri de ou","200 ml borș sau 4 linguri suc proaspăt de lămâie","1 legătură mică leuștean proaspăt (circa 15 g), tocat grosier, sau pătrunjel","1 linguriță sare fină","1/2 linguriță piper alb"]},"howIsMade":{"ja":"鶏肉を大きな鍋に入れ、2リットルの冷水をかぶるくらい注ぎ、中強火で沸騰させます；最初の5〜10分間、表面に浮かぶアクをすくい取り、スープが澄んでくるまで続けます。ニンジン、タマネギ、セロリを加え、火を弱め、蓋を少しずらして45〜50分煮込み、鶏肉が完全に火が通り骨から外れるくらい柔らかくなるまで煮ます。鶏肉と野菜を取り出し、タマネギは捨て、ニンジンを輪切りにして鶏肉を小さく手でほぐし、皮と骨を取り除きます。ほぐした鶏肉とニンジンの輪切りを鍋に戻し、中火で再び沸騰させます。麺を加えて5〜7分（または袋の表示通り）、アルデンテになるまで煮ます。ボルシュまたはレモン汁を加えてよく混ぜ、味を見ます — スープは心地よい酸味がするはずです；足りなければさらに加えます。塩と白こしょうで味を調え、ラヴェージまたはパセリを加えてすぐにどうぞ。","en":"Place the chicken in a large pot, cover with 2 litres of cold water, and bring to a boil over medium-high heat; skim the foam that rises for the first 5-10 minutes until the broth runs clear. Add the carrots, onion, and celery, reduce heat to medium-low, partially cover, and simmer for 45-50 minutes until the chicken is cooked through and falling from the bone. Lift out the chicken and vegetables; discard the onion, slice the carrots into rounds, and shred the chicken into bite-sized pieces, discarding skin and bones. Return the shredded chicken and carrot rounds to the pot and bring back to a simmer over medium heat. Add the noodles and cook for 5-7 minutes (or per packet) until just tender. Pour in the borș or lemon juice, stir, and taste — the soup should have a pleasant sour edge; add more as needed. Season with salt and white pepper, stir in the lovage or parsley, and serve immediately."}},{"id":82,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"オーストラリア","en":"Australia","ro":"Australia"},"name":{"ja":"ミートパイ","en":"Meat Pie","ro":"Meat Pie"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["375gの市販ショートクラスト生地","250gの市販パイ生地（パフペイストリー）","500gの赤身牛ひき肉","中くらいの玉ねぎ1個（約150g）、細かく刻む","にんにく2片、みじん切り","250mlの牛肉スープ","大さじ2のトマトペースト","大さじ1のウスターソース","大さじ2の薄力粉","卵1個、溶き卵（仕上げ用）","小さじ1の塩","小さじ1/2の黒こしょう"],"en":["375 g ready-made shortcrust pastry","250 g ready-made puff pastry","500 g lean beef mince","1 medium onion (about 150 g), finely diced","2 garlic cloves, minced","250 ml beef stock","2 tbsp tomato paste","1 tbsp Worcestershire sauce","2 tbsp plain flour","1 egg, lightly beaten, for brushing","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["375 g aluat fraged gata preparat","250 g aluat foietaj gata preparat","500 g carne de vită tocată (slabă)","1 ceapă medie (circa 150 g), tăiată mărunt","2 căței de usturoi, pisați","250 ml supă de vită","2 linguri pastă de roșii","1 lingură sos Worcestershire","2 linguri făină albă","1 ou, bătut ușor, pentru uns","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ja":"オーブンを200°C（ファン180°C）に予熱します。大きなフライパンに少量の油を熱し、中強火で玉ねぎとにんにくを3〜4分炒め、しんなりさせます。牛肉のひき肉を加えてスプーンでほぐしながら6〜8分炒め、全体に焼き色をつけます。薄力粉を加えて1分炒め、牛肉スープ、トマトペースト、ウスターソース、塩、こしょうを加えてよく混ぜます。中火で12〜15分、時々かき混ぜながら煮込み、ソースがスプーンの裏に張りつくほど濃くなるまで煮ます；火から下ろして15分冷まします。ショートクラスト生地を伸ばし、4枚の円形を切り抜いて直径約12cmの個別のパイ型4個に敷き込み、底をフォークで刺します。具材を均等に型に分け、パイ生地の蓋を乗せて端をしっかり押さえて閉じ、溶き卵を塗ります。25〜30分焼き、表面が深い黄金色になり蓋がふくらんでサクサクになったら完成です；5分休ませてからトマトソースとともに提供します。","en":"Preheat the oven to 200°C (180°C fan). Heat a drizzle of oil in a large frying pan over medium-high heat, add the onion and garlic and cook for 3-4 minutes until softened. Add the beef mince and cook, breaking it up with a spoon, for 6-8 minutes until browned all over. Stir in the flour, cook for 1 minute, then add the stock, tomato paste, Worcestershire sauce, salt, and pepper; stir to combine. Simmer over medium heat for 12-15 minutes, stirring occasionally, until the gravy thickens to coat the back of a spoon — the filling should be moist but not runny; remove from heat and cool for 15 minutes. Roll out the shortcrust pastry and cut 4 circles to line 4 individual pie tins (about 12 cm diameter); press into the tins and prick the bases with a fork. Divide the filling evenly between the tins, top with puff pastry lids, press the edges to seal, and brush with beaten egg. Bake for 25-30 minutes until deep golden and the lids are puffed and crisp; rest for 5 minutes then serve with tomato sauce."}},{"id":83,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"ja":"シリア","en":"Syria","ro":"Siria"},"name":{"ja":"ファッテ","en":"Fatteh","ro":"Fatteh"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ja":["大きなピタパン2枚（約200g）、一口大にちぎる","400gのひよこ豆缶詰（400g缶1缶）、水切りして洗う","500gの全脂肪プレーンヨーグルト","にんにく3片、みじん切り","大さじ2のタヒニ","大さじ2の新鮮なレモン汁","大さじ3の無塩バター","50gの松の実","小さじ1のクミンパウダー","小さじ1の甘いパプリカ","小さじ1/2の塩","大さじ2の新鮮なパセリ、細かく刻む"],"en":["2 large pita breads (about 200 g), torn into bite-sized pieces","400 g canned chickpeas (1 x 400 g can), drained and rinsed","500 g full-fat plain yogurt","3 garlic cloves, minced","2 tbsp tahini","2 tbsp fresh lemon juice","3 tbsp unsalted butter","50 g pine nuts","1 tsp ground cumin","1 tsp sweet paprika","1/2 tsp fine salt","2 tbsp fresh parsley, finely chopped"],"ro":["2 pâini pita mari (circa 200 g), rupte în bucăți","400 g năut din conservă (1 x 400 g), scurs și clătit","500 g iaurt integral simplu","3 căței de usturoi, pisați","2 linguri tahini","2 linguri suc proaspăt de lămâie","3 linguri unt nesărat","50 g semințe de pin","1 linguriță chimion măcinat","1 linguriță boia dulce","1/2 linguriță sare fină","2 linguri pătrunjel proaspăt, tocat fin"]},"howIsMade":{"ja":"オーブンを200°Cに予熱します。ピタパンをちぎり、少量の油と混ぜてオーブントレイに広げ、8〜10分焼いて黄金色でカリカリになるまで焼きます。ひよこ豆を水切りし、小鍋に塩ひとつまみとクミンとともに中火で3〜4分温めます。ヨーグルト、にんにく、タヒニ、レモン汁、塩をなめらかになるまでよく混ぜ、味を調えます。焼いたピタパンを大皿に均等に一層に並べます。温めたひよこ豆をピタパンの上に均等にのせます。ヨーグルトソースをひよこ豆の上に惜しみなくかけます。小さなフライパンにバターを溶かし、松の実を加えて2〜3分炒め、きつね色になったらパプリカを加えてすぐにヨーグルトの上にかけます。刻んだパセリを散らし、ピタパンがやわらかくなる前にすぐに提供します。","en":"Preheat the oven to 200°C. Toss the pita pieces with a drizzle of oil, spread on a baking tray and bake for 8-10 minutes until golden and crisp. Drain the chickpeas; heat in a small saucepan with a pinch of salt and cumin over medium heat for 3-4 minutes until warmed through. Whisk the yogurt, garlic, tahini, lemon juice, and salt until smooth; taste and adjust seasoning. Spread the toasted pita pieces in an even layer on a large serving platter. Spoon the warm chickpeas evenly over the pita. Pour the yogurt sauce over the chickpeas, covering everything generously. Melt the butter in a small pan over medium heat; add the pine nuts and cook for 2-3 minutes, stirring, until golden; stir in the paprika and immediately drizzle the hot butter and pine nuts over the yogurt. Scatter the chopped parsley on top and serve immediately before the pita softens."}},{"id":84,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ja":"デンマーク","en":"Denmark","ro":"Danemarca"},"name":{"ja":"スモーブロー","en":"Smørrebrød","ro":"Smørrebrød"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ja":["デンマーク産ダークライ麦パン（ルブロー）8枚、約400g","無塩バター100g、室温に戻す","マリネしたニシンのフィレ400g（8枚）、水切り","固茹で卵4個（10分茹でる）、殻をむいて輪切り","小さな赤玉ねぎ1個（約80g）、極薄のリング切り","ラディッシュ4個、薄い輪切り","大さじ2のケイパー、水切り","大さじ4のサワークリームまたはクレームフレーシュ","小さじ1のディジョンマスタード","新鮮なディル少量（約15g）","小さじ1/2の塩"],"en":["8 slices dark rye bread (rugbrød), about 400 g","100 g unsalted butter, softened","400 g pickled herring fillets (8 fillets), drained","4 eggs, hard-boiled (10 minutes), peeled and sliced into rounds","1 small red onion (about 80 g), very finely sliced into rings","4 radishes, thinly sliced into rounds","2 tbsp capers, drained","4 tbsp soured cream or crème fraîche","1 tsp Dijon mustard","1 small bunch fresh dill (about 15 g)","1/2 tsp fine salt"],"ro":["8 felii de pâine daneză de secară (rugbrød), circa 400 g","100 g unt nesărat, înmuiat","400 g hering murat (8 fileuri), scurs","4 ouă fierte tari (10 minute), decojite și feliate în rondele","1 ceapă roșie mică (circa 80 g), feliată subțire în inele","4 ridichi, feliate subțire în rondele","2 linguri capere, scurse","4 linguri smântână sau crème fraîche","1 linguriță muștar Dijon","1 legătură mică de mărar proaspăt (circa 15 g)","1/2 linguriță sare fină"]},"howIsMade":{"ja":"卵を固茹でにします：沸騰したお湯に入れて10分ゆで、冷水に5分つけてから殻をむき、輪切りにします。小さなボウルにサワークリームとディジョンマスタード、塩ひとつまみを混ぜ合わせます。各ライ麦パンのスライスに柔らかいバターを端まで惜しみなく塗ります — 1枚あたり大さじ1程度が目安です。バターを塗った各スライスにマリネしたニシンのフィレを1〜2枚のせ、自然に沿わせます。ニシンの上にマスタードクリームを少量のせ、ゆで卵の輪切りを2〜3枚並べます。赤玉ねぎのリング、ラディッシュのスライス、ケイパーを散らします。新鮮なディルの枝を飾り、冷えたビールまたはアクアビットとともに即座に提供します。","en":"Hard-boil the eggs: lower into boiling water and cook for 10 minutes, then transfer to cold water for 5 minutes before peeling and slicing into rounds. Mix the soured cream with the Dijon mustard and a pinch of salt in a small bowl. Spread each slice of rye bread generously with softened butter right to the edges — about 1 tablespoon per slice. Lay 1-2 pickled herring fillets on each buttered slice, letting them curve naturally over the surface. Spoon a small dollop of mustard cream onto the herring, then arrange 2-3 egg rounds alongside. Scatter red onion rings, radish slices, and capers over the top. Finish with fresh dill sprigs and serve immediately with a cold beer or aquavit."}},{"id":85,"origin":{"ja":"北朝鮮","en":"North Korea","ro":"Coreea de Nord"},"name":{"ja":"ネンミョン","en":"Naengmyeon","ro":"Naengmyeon"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","timeMins":{"total":600,"active":60},"pairingsType":"korean","ingredients":{"ja":["乾燥そば粉麺（メミルグクス）400g","牛バラ肉300g、やわらかくなるまで煮て冷蔵し薄切り","牛バラ肉のだし1.5L、完全に冷やして脂を除く","韓国梨（ナシ）1個、皮をむいて薄切り","きゅうり1本（せん切り）","固ゆで卵4個、半切り","米酢大さじ2","韓国からし（キョジャ）小さじ1またはイングリッシュマスタード","コチュガル大さじ1（テーブル用、任意）","塩と砂糖で味を調える","氷は適量"],"en":["400g dried buckwheat noodles (memil-guksu)","300g beef brisket, simmered until tender, chilled, thinly sliced","1.5L beef brisket broth, fully chilled and defatted","1 Korean pear (nashi), peeled, thinly sliced","1 medium cucumber, julienned","4 hard-boiled eggs, halved","2 tbsp rice vinegar","1 tsp Korean mustard (gyeoja) or English mustard","1 tbsp gochugaru (optional, as table condiment)","salt and sugar to taste for the broth","ice cubes as needed"],"ro":["400g tăiței de hrișcă uscați (memil-guksu)","300g piept de vită, fiert și refrigerat, feliat subțire","1.5L supă de piept de vită (răcită complet la frigider, degresată)","1 pară coreeană (nashi), curățată, feliată subțire","1 castravete mediu, feliat julien","4 ouă fierte tari, înjumătățite","2 linguri oțet de orez","1 linguriță muștar coreean (gyeoja) sau muștar englez","1 lingură gochugaru (opțional, pentru condiment la masă)","sare și zahăr după gust pentru supa de bază","cuburi de gheață — câte este necesar"]},"howIsMade":{"ja":"前日：牛バラ肉を水2Lに塩小さじ1・生姜2cm・長ねぎ3本と一緒に弱火で1.5〜2時間煮る。肉をだしの中で冷まし、一晩冷蔵。翌日、固まった脂を取り除く。冷たいだしを米酢・砂糖・塩で味付け——ほんのり酸っぱくわずかに甘い味に仕上げる。必要に応じて氷をさらに加える。麺をパッケージ通り茹で（3〜4分）、すぐに冷水で30秒手でもみ洗いして澱粉を落としながら完全に冷やす。深めの器に麺を入れ、冷たいだしを注いで浸す。牛バラ肉・梨・きゅうり・卵の順に盛り付ける。酢とからしを添えてすぐに出す。","en":"Day before: simmer beef brisket in 2L water with 1 tsp salt, a 2 cm piece of ginger, and 3 spring onions over low heat for 1.5–2 hours. Let meat cool in the broth, then refrigerate overnight. Next day, lift off the solidified fat layer. Season the cold broth with rice vinegar, sugar, and salt — it should be lightly tart and subtly sweet. Chill further with ice if needed. Cook noodles per packet (usually 3–4 minutes), drain and immediately rinse under cold running water for 30 seconds, rubbing with hands to remove starch and chill completely. Nest noodles in deep bowls. Ladle cold broth to cover. Top with sliced brisket, pear, julienned cucumber, and halved egg. Serve at once with vinegar and mustard on the side."}},{"id":86,"origin":{"ja":"パキスタン","en":"Pakistan","ro":"Pakistan"},"name":{"ja":"ニハリ","en":"Nihari","ro":"Nihari"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"ja":["牛すね肉（骨付き）1kg、5cm幅に切る","マロウボーン（骨髄骨）2本、各約5cm","ギーまたは澄ましバター 大さじ4","大玉ねぎ2個（約300g）、薄切り","ショウガとニンニクのペースト 大さじ2","赤唐辛子パウダー 小さじ1.5","コリアンダーパウダー 小さじ1","ターメリックパウダー 小さじ1/2","塩 小さじ1.5","ニハリマサラまたはガラムマサラ 小さじ1","薄力粉 大さじ3と冷水100mlを混ぜた水溶き粉","新鮮なショウガ5cm（皮をむいて千切り）、仕上げ用","レモン1個（くし形切り）と新鮮なコリアンダーの葉ひとつかみ、仕上げ用"],"en":["1 kg bone-in beef shanks, cut into 5 cm pieces","2 marrow bones, each about 5 cm long","4 tbsp ghee or clarified butter","2 large onions (~300 g), thinly sliced","2 tbsp ginger-garlic paste","1.5 tsp red chilli powder","1 tsp ground coriander","1/2 tsp ground turmeric","1.5 tsp salt","1 tsp nihari masala or garam masala","3 tbsp plain flour mixed with 100 ml cold water","5 cm piece of fresh ginger, peeled and julienned, to serve","1 lemon cut into wedges and a handful of fresh coriander leaves, to serve"],"ro":["1 kg rasol de vită cu os, tăiat în bucăți de 5 cm","2 oase cu măduvă, fiecare de aproximativ 5 cm","4 linguri unt clarificat (ghee) sau ulei","2 cepe mari (~300 g), feliate subțire","2 linguri pastă de ghimbir și usturoi","1,5 linguriță praf de ardei iute roșu","1 linguriță coriandru măcinat","1/2 linguriță turmeric măcinat","1,5 linguriță sare","1 linguriță masala nihari sau garam masala","3 linguri făină albă amestecate cu 100 ml apă rece","5 cm ghimbir proaspăt, curățat și juliennat, pentru servire","1 lămâie tăiată în felii și un mănunchi de frunze de coriandru, pentru servire"]},"howIsMade":{"ja":"大きな厚手鍋にギー大さじ3を中強火で熱し、玉ねぎを12–15分間かき混ぜながら炒めて深いきつね色にし、穴あきスプーンで取り出す。残りのギーを加えて強火にし、牛すね肉とマロウボーンを数回に分けて各面3–4分ずつ焼き色をつけ、取り出す。中火に落とし、ショウガとニンニクのペーストを加えて1–2分炒め、香りが立ったら赤唐辛子、コリアンダー、ターメリックを加えて30秒混ぜる。肉と炒め玉ねぎを鍋に戻し、塩と水（約1.2リットル）を加えて肉の5cm上まで浸し、沸騰させてアクをすくう。最弱火にして蓋をしっかり閉め、3–4時間煮込んで骨から肉がほぐれやすくなるまで火を通す。ニハリマサラを混ぜ入れ、水溶き粉を細い流れで注ぎながら混ぜ、蓋を取って10–15分煮てスープにとろみをつけ、スプーンの裏を覆う程度になったら完成。器に盛り、千切りショウガ、コリアンダー、レモン汁をかけてナンや焼きたてのパンと合わせて供する。","en":"Heat 3 tbsp ghee in a large heavy pot over medium-high heat and fry the onions for 12–15 minutes, stirring often, until deep golden brown, then remove with a slotted spoon and set aside. Add the remaining ghee, raise the heat to high, and sear the beef shanks and marrow bones in batches for 3–4 minutes per side until browned, then set aside. Reduce heat to medium, add the ginger-garlic paste and fry for 1–2 minutes until fragrant, then add the chilli powder, coriander, and turmeric and stir for 30 seconds. Return the meat and fried onions to the pot, add the salt and enough water to cover by 5 cm (about 1.2 litres), bring to a boil and skim any foam. Reduce heat to the lowest setting, cover tightly, and simmer for 3–4 hours until the beef is completely tender and falling from the bone. Stir in the nihari masala, pour in the flour slurry in a thin stream while stirring, and simmer uncovered for 10–15 minutes until the broth thickens to a glossy consistency that coats the back of a spoon. Ladle into bowls, top with julienned ginger, coriander leaves, and a squeeze of lemon, and serve with naan or crusty bread."}},{"id":87,"origin":{"ja":"ベトナム","en":"Vietnam","ro":"Vietnam"},"name":{"ja":"ブンボーフエ","en":"Bún bò Huế","ro":"Bún bò Huế"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":195,"active":75},"pairingsType":"vietnamese","ingredients":{"ja":["骨付き豚すね肉600g、4cm幅に切る","牛骨500g、下茹で済み","牛すね肉400g、薄切り","乾燥丸型ライスヴェルミチェッリ（ブン）400g","レモングラス3本、叩いて5cm幅に切る","シャロット3個、半分に切って炙り焼き","ニンニク4片、叩いて潰す","発酵エビペースト（マム・ルオック）大さじ2","ナンプラー 大さじ3","チリオイル 大さじ2、または乾燥チリフレーク 小さじ1","砂糖 小さじ1","塩 小さじ1","添え物：豆もやし200g、新鮮なハーブ（ミントまたはベトナムコリアンダー）、ライム2個のくし形切り、赤唐辛子2本の薄切り"],"en":["600 g bone-in pork hock, cut into 4 cm pieces","500 g beef bones, blanched","400 g beef shank, thinly sliced","400 g dried round rice vermicelli (bún)","3 lemongrass stalks, bruised and cut into 5 cm pieces","3 shallots, halved and charred","4 garlic cloves, bruised","2 tbsp fermented shrimp paste (mắm ruốc)","3 tbsp fish sauce","2 tbsp chilli oil or 1 tsp dried chilli flakes","1 tsp sugar","1 tsp salt","to serve: 200 g bean sprouts, fresh herbs (mint, perilla or Vietnamese coriander), 2 limes cut into wedges, and 2 red chillies sliced"],"ro":["600 g picior de porc cu os, tăiat în bucăți de 4 cm","500 g oase de vită, opărite","400 g rasol de vită, feliat subțire","400 g tăiței rotunzi de orez uscați (bún)","3 tulpini de lemongrass, zdrobite și tăiate în bucăți de 5 cm","3 șalote, tăiate pe jumătate și pârlite","4 căței de usturoi, zdrobiți","2 linguri pastă de creveți fermentați (mắm ruốc)","3 linguri sos de pește","2 linguri ulei de ardei iute sau 1 linguriță fulgi de ardei iute","1 linguriță zahăr","1 linguriță sare","pentru servit: 200 g muguri de fasole, ierburi proaspete (mentă sau coriandru vietnamez), 2 lămâi verzi în sferturi și 2 ardei iuți roșii felieți"]},"howIsMade":{"ja":"豚すね肉と牛骨を沸騰したお湯で5分茹でこぼし、ザルに上げて冷水で洗い流す。シャロットとニンニクを切り口を下にして乾いたフライパンで強火で3–4分炙り、軽く焦げ目をつける。豚すね肉、牛骨、レモングラス、炙りシャロット、ニンニクを大鍋に入れ、冷水2.5リットルを注いで沸騰させ、アクをすくってから弱火で1時間煮込む。エビペーストを熱いスープ100mlで溶かして鍋に加え、ナンプラー、砂糖、塩、チリオイルも加えて旨みがあり軽く辛く香り豊かになるよう味を調える。薄切り牛すね肉を加えて弱火で15–20分ポーチし、火が通って柔らかくなったら取り出して薄切りにする。ライスヴェルミチェッリをパッケージの指示通りに茹で（通常3–5分）、水を切り、4つの深皿に分ける。熱いスープをかけ、豚肉と牛肉を盛り付け、豆もやし、ハーブ、ライムのくし形切り、唐辛子とともに即座に供する。","en":"Blanch the pork hock and beef bones in boiling water for 5 minutes, drain and rinse under cold water. Char the shallots and garlic cut-side down in a dry pan over high heat for 3–4 minutes until lightly blackened. Place the pork hock, bones, lemongrass, charred shallots, and garlic in a large pot, add 2.5 litres of cold water, bring to a boil, skim well, then simmer over low heat for 1 hour. Dissolve the shrimp paste in 100 ml of hot broth, stir into the pot, then add fish sauce, sugar, salt, and chilli oil, adjusting until the broth is savoury, lightly spicy, and fragrant. Add the beef shank slices and poach over gentle heat for 15–20 minutes until just cooked through and tender, then remove and slice thinly. Cook the rice vermicelli according to packet instructions (usually 3–5 minutes), drain, and divide among 4 deep bowls. Ladle the hot broth over the noodles, top with slices of pork hock and beef shank, and serve immediately with bean sprouts, fresh herbs, lime wedges, and sliced chilli on the side."}},{"id":88,"origin":{"ja":"ブラジル","en":"Brazil","ro":"Brazilia"},"name":{"ja":"ムケッカ","en":"Moqueca","ro":"Moqueca"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"ja":["白身魚の切り身（スズキ、タラ、またはアンコウ）800g、5cm幅に切る","ライム2個、果汁のみ","塩 小さじ1","大玉ねぎ1個（約180g）、薄切り","ニンニク4片、みじん切り","赤パプリカ1個（約150g）、種を除いてスライス","緑パプリカ1個（約150g）、種を除いてスライス","大きな完熟トマト2個（約300g）、角切り","全脂肪ココナッツミルク 400ml","赤パームオイル（デンデ）大さじ2","新鮮なコリアンダー20g、粗みじん切り、仕上げ用追加分も用意","黒コショウ 小さじ1/2"],"en":["800 g firm white fish fillets (sea bass, cod, or monkfish), cut into 5 cm chunks","2 limes, juice only","1 tsp salt","1 large onion (~180 g), thinly sliced","4 garlic cloves, finely minced","1 red bell pepper (~150 g), deseeded and sliced","1 green bell pepper (~150 g), deseeded and sliced","2 large ripe tomatoes (~300 g), diced","400 ml full-fat coconut milk","2 tbsp dendê (red palm oil)","20 g fresh coriander, roughly chopped, plus extra to serve","1/2 tsp ground black pepper"],"ro":["800 g fileuri de pește alb ferm (biban de mare, cod sau merluciu), tăiate în bucăți de 5 cm","2 lămâi verzi (lime), sucul","1 linguriță sare","1 ceapă mare (~180 g), feliată subțire","4 căței de usturoi, tocați mărunt","1 ardei gras roșu (~150 g), curat și feliat","1 ardei gras verde (~150 g), curat și feliat","2 roșii coapte mari (~300 g), tocate cuburi","400 ml lapte de cocos integral","2 linguri ulei de palmier roșu (dendê)","20 g coriandru proaspăt, tocat grosier, plus extra pentru garnit","1/2 linguriță piper negru măcinat"]},"howIsMade":{"ja":"魚の切り身をライム果汁、塩小さじ1/2、黒コショウと和え、野菜を準備する間15–20分マリネする。大きな広口のフライパンにデンデオイル大さじ1を中火で熱し、玉ねぎを加えて6–8分、しんなりして軽く色づくまで炒める。ニンニク、赤と緑のパプリカ、トマトを加えてよく混ぜ、トマトが崩れ始めるまで5分煮る。マリネした魚を野菜の上に一重に並べ、ココナッツミルクを上から注いで魚を優しく液体に沈め、混ぜない。弱火でふつふつするまで持ち込み、蓋をして12–15分、魚が不透明になり押すと崩れるまで火を通す。残りのデンデオイル大さじ1を表面に回しかけ、コリアンダーを散らして塩を調える。白いご飯や厚切りのパンと一緒にライムのくし形切りを添えて、フライパンのまま食卓へ。","en":"Toss the fish chunks with the lime juice, 1/2 tsp salt, and the black pepper and leave to marinate for 15–20 minutes while you prepare the vegetables. Heat 1 tbsp dendê oil in a large wide pan over medium heat, add the onion slices, and cook for 6–8 minutes until softened and lightly golden. Add the garlic, bell peppers, and tomatoes, stir well, and cook for 5 minutes until the tomatoes begin to break down. Lay the marinated fish over the vegetables in a single layer, pour the coconut milk over the top, and gently push the fish down into the liquid without stirring. Bring to a gentle simmer, cover, and cook for 12–15 minutes until the fish is opaque and flakes easily when pressed. Drizzle the remaining 1 tbsp dendê oil over the surface, scatter the coriander on top, and taste for salt. Serve directly from the pan with white rice or crusty bread, with lime wedges on the side."}},{"id":89,"origin":{"ja":"イスラエル","en":"Israel","ro":"Israel"},"name":{"ja":"サビッチ","en":"Sabich","ro":"Sabich"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"def","pairingsType":"middle-eastern","ingredients":{"ja":["大きなピタパン4枚","大きなナス1本（約400g）、1cm幅の輪切り","揚げ油 大さじ4","卵4個","ワックス系じゃがいも300g、柔らかくなるまで茹でて1cm幅に切る","タヒニペースト 大さじ4","レモン1個、果汁のみ","ニンニク1片、潰したもの","アンバソース（マンゴーピクルスソース）大さじ4","トマト2個（約200g）、みじん切り","キュウリ1本（約150g）、みじん切り","塩 小さじ1","ピクルスのキュウリ4切れと新鮮なパセリ、仕上げ用"],"en":["4 large pita breads","1 large aubergine (~400 g), cut into 1 cm rounds","4 tbsp oil for frying","4 eggs","300 g waxy potatoes, boiled until tender and sliced 1 cm thick","4 tbsp tahini paste","1 lemon, juice only","1 garlic clove, crushed","4 tbsp amba sauce (fermented mango pickle sauce)","2 tomatoes (~200 g), finely diced","1 cucumber (~150 g), finely diced","1 tsp salt","4 slices pickled cucumber and fresh parsley, to serve"],"ro":["4 lipii pita mari","1 vânătă mare (~400 g), tăiată în felii de 1 cm","4 linguri ulei pentru prăjit","4 ouă","300 g cartofi galbeni, fierți până sunt moi și feliați la 1 cm grosime","4 linguri pastă de tahini","1 lămâie, sucul","1 cățel de usturoi, zdrobit","4 linguri sos amba (sos din mango murat)","2 roșii (~200 g), tăiate mărunt","1 castravete (~150 g), tăiat mărunt","1 linguriță sare","4 felii castraveți murați și pătrunjel proaspăt, pentru servire"]},"howIsMade":{"ja":"卵を固茹でにする：沸騰した湯に入れ10分茹で、冷水に5分浸してから殻を剥き輪切りにする。ナスの輪切り両面に塩小さじ1/2を振り10分おいてから、キッチンペーパーで水気を拭き取る。フライパンに油を中強火で熱し、ナスを数回に分けて各面3–4分、深いきつね色になり全体が柔らかくなるまで焼いてキッチンペーパーに取る。タヒニをレモン果汁、ニンニク、冷水大さじ3–4と混ぜてなめらかで注ぎやすいソースにする。トマトとキュウリのみじん切りを塩小さじ1/2とオリーブオイル少量で和えてシンプルなサラダを作る。ピタパンを乾いたフライパンで1枚ずつ各面1分温め、破らないように慎重にポケットを開く。各ピタの中に揚げナス、ジャガイモと卵の輪切り、野菜サラダ、タヒニソース多めをはさみ、アンバソースをスプーン一杯加え、ピクルス、パセリをのせて即座に供する。","en":"Hard-boil the eggs: lower into boiling water, cook for 10 minutes, then transfer to cold water for 5 minutes, peel, and slice into rounds. Sprinkle the aubergine slices on both sides with 1/2 tsp salt and leave for 10 minutes, then pat dry with kitchen paper. Heat the oil in a large non-stick pan over medium-high heat and fry the aubergine in batches for 3–4 minutes per side until deep golden and tender throughout, then drain on kitchen paper. Whisk the tahini with the lemon juice, crushed garlic, and 3–4 tbsp cold water until creamy and pourable. Combine the diced tomatoes and cucumber with the remaining 1/2 tsp salt and a drizzle of olive oil. Warm each pita for 1 minute per side in a dry pan, then carefully open the pocket without tearing. Layer each pita with fried aubergine, sliced potato and egg, the tomato-cucumber salad, a generous drizzle of tahini sauce, a spoonful of amba sauce, pickled cucumber, and fresh parsley, and serve immediately."}},{"id":90,"origin":{"ja":"キューバ","en":"Cuba","ro":"Cuba"},"name":{"ja":"ロパ・ビエハ","en":"Ropa Vieja","ro":"Ropa Vieja"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"ja":["牛フランク（フランクステーキ）または胸肉700g","オリーブオイル 大さじ2","大玉ねぎ1個（約200g）、薄切り","赤パプリカと緑パプリカ各1個（各約150g）、種を除いて細切り","ニンニク4片、みじん切り","缶詰のクラッシュトマト400g","トマトペースト 大さじ2","辛口白ワイン 100ml","クミン 小さじ1","乾燥オレガノ 小さじ1","ローリエ2枚","塩 小さじ1、黒コショウ 小さじ1/2"],"en":["700 g beef flank steak or brisket","2 tbsp olive oil","1 large onion (~200 g), thinly sliced","1 red bell pepper and 1 green bell pepper (~150 g each), deseeded and sliced","4 garlic cloves, finely minced","400 g canned crushed tomatoes","2 tbsp tomato paste","100 ml dry white wine","1 tsp ground cumin","1 tsp dried oregano","2 bay leaves","1 tsp salt and 1/2 tsp ground black pepper"],"ro":["700 g antricot sau piept de vită","2 linguri ulei de măsline","1 ceapă mare (~200 g), feliată subțire","1 ardei gras roșu și 1 ardei gras verde (~150 g fiecare), curățați și feliați","4 căței de usturoi, tocați mărunt","400 g roșii zdrobite la conservă","2 linguri pastă de roșii","100 ml vin alb sec","1 linguriță chimion măcinat","1 linguriță oregano uscat","2 foi de dafin","1 linguriță sare și 1/2 linguriță piper negru măcinat"]},"howIsMade":{"ja":"牛肉を鍋に入れ、冷たい塩水で浸し、沸騰させてアクをすくい、弱火で蓋をして1時間半〜2時間、繊維がほぐれやすくなるまで煮る。肉を取り出し、煮汁200mlを取り置き、肉を繊維に沿って長くほぐす。広口鍋にオリーブオイルを中火で熱し、玉ねぎと両パプリカを加えて8–10分、しんなりして軽く色づくまで炒める。ニンニク、クミン、オレガノを加えて1分炒め、白ワインを注いで2分間半量になるまで煮詰める。クラッシュトマト、トマトペースト、取り置いた煮汁、ローリエを加え、塩こしょうで味を調えて10分煮てソースを軽く煮詰める。ほぐした牛肉を加えてよく混ぜ、さらに10–15分煮込んで肉にソースをしっかり吸わせ、全体がジューシーになったら完成。ローリエを除き、白いご飯と揚げプランテンとともに供する。","en":"Place the beef in a pot, cover with cold salted water, bring to a boil, skim, reduce heat, and simmer covered for 1.5–2 hours until the meat pulls apart easily. Remove the beef, reserve 200 ml of the cooking liquid, and shred the meat into long strips. Heat the oil in a wide heavy pan over medium heat, add the onion and both bell peppers, and cook for 8–10 minutes until softened and beginning to colour. Add the garlic, cumin, and oregano and stir for 1 minute, then pour in the white wine and cook for 2 minutes until reduced by half. Stir in the crushed tomatoes, tomato paste, reserved cooking liquid, and bay leaves, season with salt and pepper, and simmer for 10 minutes until the sauce thickens slightly. Add the shredded beef, stir to combine, and simmer for 10–15 minutes more until the beef absorbs the sauce and the mixture is juicy but not soupy. Remove the bay leaves and serve with white rice and fried plantains."}},{"id":91,"origin":{"ja":"スコットランド","en":"Scotland","ro":"Scoția"},"name":{"ja":"カレンスキンク","en":"Cullen Skink","ro":"Cullen Skink"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ja":["スモークハドック（燻製のハドックフィレ）600g、着色料なしが望ましい","全乳 700ml","粉ふきいも向けジャガイモ500g、皮をむいて2cm角に切る","大玉ねぎ1個（約200g）、みじん切り","無塩バター 大さじ2","ローリエ2枚","生クリーム（脂肪分35%以上）100ml","新鮮なパセリ10g、みじん切り","白コショウ 小さじ1/2","塩 小さじ1/2"],"en":["600 g undyed smoked haddock fillets","700 ml whole milk","500 g floury potatoes (such as Maris Piper), peeled and cut into 2 cm cubes","1 large onion (~200 g), finely diced","2 tbsp unsalted butter","2 bay leaves","100 ml double cream","10 g fresh parsley, finely chopped","1/2 tsp white pepper","1/2 tsp salt"],"ro":["600 g fileuri de eglefin afumat (de preferință necolorat)","700 ml lapte integral","500 g cartofi făinoși, curățați și tăiați cuburi de 2 cm","1 ceapă mare (~200 g), tăiată mărunt","2 linguri unt fără sare","2 foi de dafin","100 ml frișcă grasă","10 g pătrunjel proaspăt, tocat mărunt","1/2 linguriță piper alb","1/2 linguriță sare"]},"howIsMade":{"ja":"スモークハドックを皮目を下にして広口鍋に入れ、牛乳を注ぎ、ローリエを加えて中火でそっと沸騰させ、8–10分ポーチして最も厚い部分が不透明になりほぐれるようになるまで加熱する。穴あきスプーンで魚を取り出し、皮と骨を取り除き、身を大きめにほぐし、ポーチ液をザルで濾す。同じ鍋でバターを中火で溶かし、玉ねぎを加えて8–10分、色がつかずに完全に柔らかくなるまで時々かき混ぜながら炒める。ジャガイモと濾した牛乳を加えて弱火で沸騰させ、蓋を少しずらして15–18分、ナイフで刺すと完全に柔らかくなるまで煮る。ジャガイモの約3分の1を木べらで鍋の側面に押しつぶしてスープにとろみをつけ、残りはそのまま。生クリームを加え、ほぐしたハドックを戻して弱火で2–3分温め、白コショウと塩で味を調える（魚自体が塩辛いので慎重に）。温めたボウルに盛り、パセリを散らし、パンとともに供する。","en":"Place the smoked haddock skin-side down in a wide pan, pour over the milk, add the bay leaves, and bring to a gentle simmer over medium heat; poach for 8–10 minutes until the fish is just opaque and flakes at the thickest part. Lift the fish out with a slotted spoon, remove the skin and any bones, break the flesh into large flakes, and strain the poaching milk through a sieve into a jug. Melt the butter in the same pan over medium heat, add the diced onion, and cook for 8–10 minutes, stirring occasionally, until completely soft but not coloured. Add the potato cubes and the strained milk, bring to a simmer, cover loosely, and cook for 15–18 minutes until the potatoes are completely tender when pierced with a knife. Lightly mash about one-third of the potatoes against the side of the pan with the back of a spoon to thicken the soup, leaving the rest in chunks. Stir in the double cream, return the flaked haddock to the pan, and simmer gently for 2–3 minutes until just heated through; season with white pepper and salt, tasting carefully as the haddock is already salty. Ladle into warmed bowls, scatter with chopped parsley, and serve with crusty bread."}},{"id":92,"origin":{"ja":"インドネシア","en":"Indonesia","ro":"Indonezia"},"name":{"ja":"ガドガド","en":"Gado-Gado","ro":"Gado-Gado"},"category":{"ja":"サラダ","en":"Salad","ro":"Salată"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ja":["かたい豆腐400g、水気を絞り2cm角に切る","テンペ150g、2cm角に切る","大きめの卵4個","ねっとりした食感のじゃがいも300g、皮をむいて4等分","さやいんげん200g、端を切り落とす","白キャベツ200g、細切り","もやし150g","きゅうり1本（約200g）、半月切り","植物油大さじ3","なめらかなピーナッツバター200g","ココナッツミルク200ml","ケチャップマニス（甘口醤油）大さじ2","タマリンドペースト大さじ2、ぬるま湯大さじ4で溶く","ヤシ砂糖または薄茶色の砂糖小さじ1","にんにく2片、すりおろす","チリフレーク小さじ1/2","塩小さじ1/2","えびせん（クルプック）とライムのくし形切り（付け合わせ）"],"en":["400 g firm tofu, pressed and cut into 2 cm cubes","150 g tempeh, cut into 2 cm cubes","4 large eggs","300 g waxy potatoes, peeled and quartered","200 g green beans, trimmed","200 g white cabbage, thinly shredded","150 g bean sprouts","1 cucumber (~200 g), sliced into half-moons","3 tbsp vegetable oil","200 g smooth peanut butter","200 ml coconut milk","2 tbsp kecap manis (sweet soy sauce)","2 tbsp tamarind paste dissolved in 4 tbsp warm water","1 tsp palm sugar or soft brown sugar","2 garlic cloves, finely grated","1/2 tsp chilli flakes","1/2 tsp salt","prawn crackers (krupuk) and lime wedges to serve"],"ro":["400 g tofu ferm, presat și tăiat în cuburi de 2 cm","150 g tempeh, tăiat în cuburi de 2 cm","4 ouă mari","300 g cartofi cu coajă crocantă, curățați și tăiați în sferturi","200 g fasole verde, curățată de capete","200 g varză albă, feliată subțire","150 g germeni de soia","1 castravete (~200 g), tăiat în felii semilună","3 linguri ulei vegetal","200 g unt de arahide cremos","200 ml lapte de cocos","2 linguri kecap manis (sos de soia dulce)","2 linguri pastă de tamarind dizolvată în 4 linguri apă caldă","1 linguriță zahăr de palmier sau zahăr brun","2 căței de usturoi, rași fin","1/2 linguriță fulgi de ardei iute","1/2 linguriță sare","chipsuri de creveți (krupuk) și felii de lămâie verde pentru servit"]},"howIsMade":{"ja":"卵を静かに沸騰したお湯に9分間入れて固ゆでにし、氷水に移して冷めたらむいて半分に切る。よく塩を効かせた沸騰したお湯でじゃがいもを12〜15分、刺してやわらかくなるまでゆでる；穴あきスプーンですくって取り出し、同じ湯でさやいんげんを3分、鮮やかな緑色でまだ歯ごたえが残る程度にゆでて水気を切る。せん切りキャベツをコランダーに入れて熱湯を回しかけ、30秒数えて余分な水を絞る。フライパンにオイルを中強火で熱し、豆腐を1面3〜4分ずつこんがりとするまで揚げ焼きにして取り出す；同じフライパンでテンペを1面2〜3分ずつ深い金色になるまで焼く。ピーナッツバター、ココナッツミルク、ケチャップマニス、タマリンド液、ヤシ砂糖、すりおろしにんにく、チリフレークを小鍋で合わせ、弱火で絶えず混ぜながら5〜7分、スプーンの背に絡む程度のなめらかなソースになるまで煮る。キャベツ、じゃがいも、いんげん、もやし、きゅうりを大皿に盛り、豆腐、テンペ、ゆで卵の切り口を上にのせる。温かいピーナッツソースを全体にかけ、えびせんとライムのくし形を添えて供する。","en":"Hard-boil the eggs in simmering water for 9 minutes, transfer to a bowl of ice water, then peel and halve when cool. Cook the potatoes in well-salted boiling water for 12–15 minutes until just tender when pierced; lift out with a slotted spoon and drain, then blanch the green beans in the same water for 3 minutes until bright green and still with some bite, and drain. Blanch the shredded cabbage by pouring boiling water over it in a colander, count 30 seconds, then press out excess water. Heat the oil in a non-stick frying pan over medium-high heat and fry the tofu cubes for 3–4 minutes per side until golden and crisp; remove, then fry the tempeh in the same pan for 2–3 minutes per side until deep golden. Combine the peanut butter, coconut milk, kecap manis, tamarind water, palm sugar, grated garlic, and chilli flakes in a small saucepan; cook over low heat, stirring constantly, for 5–7 minutes until smooth and thick enough to coat the back of a spoon — thin with a splash of water if needed. Arrange the cabbage, potatoes, green beans, bean sprouts, and cucumber slices on a large platter or individual plates; place the tofu, tempeh, and egg halves on top. Pour the warm peanut sauce over everything, and serve with prawn crackers and lime wedges on the side."}},{"id":93,"origin":{"ja":"スウェーデン","en":"Sweden","ro":"Suedia"},"name":{"ja":"シナモンロール","en":"Cinnamon Bun","ro":"Kanelbulle"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"servings":12,"tipType":"dessert","pairingsType":"dessert","ingredients":{"ja":["薄力粉500g（打ち粉用別途）","全脂牛乳250ml","ドライイースト7g（1袋）","グラニュー糖10g（生地用）","大きめの卵1個","食塩不使用バター100g、室温に戻したもの","カルダモンパウダー小さじ1","塩小さじ1/2","食塩不使用バター75g、室温に戻したもの（フィリング）","グラニュー糖75g（フィリング）","シナモンパウダー大さじ1","カルダモンパウダー小さじ1（フィリング）","卵1個、溶いたもの（卵液用）","パールシュガー大さじ2"],"en":["500 g plain flour, plus extra for dusting","250 ml whole milk","7 g fast-action dried yeast (1 sachet)","10 g caster sugar (for dough)","1 large egg","100 g unsalted butter, softened","1 tsp ground cardamom","1/2 tsp salt","75 g unsalted butter, softened (filling)","75 g caster sugar (filling)","1 tbsp ground cinnamon","1 tsp ground cardamom (filling)","1 egg, beaten (for egg wash)","2 tbsp pearl sugar"],"ro":["500 g făină albă, plus extra pentru presărat","250 ml lapte integral","7 g drojdie uscată instant (1 plic)","10 g zahăr tos (pentru aluat)","1 ou mare","100 g unt nesărat, la temperatura camerei","1 linguriță cardamom măcinat","1/2 linguriță sare","75 g unt nesărat, la temperatura camerei (umplutură)","75 g zahăr tos (umplutură)","1 lingură scorțișoară măcinată","1 linguriță cardamom măcinat (umplutură)","1 ou bătut (pentru uns)","2 linguri zahăr perle"]},"howIsMade":{"ja":"牛乳を37°Cに温め、イーストと10gのグラニュー糖を加えて5〜10分置き、泡立つまで待つ。大きなボウルに薄力粉、カルダモン、塩を合わせ、中央に窪みを作ってイースト液と卵を加え、粗い生地にまとめる。100gの室温のバターを少しずつ加えながら、軽く打ち粉をした台の上で8〜10分こねる。生地がなめらかで弾力があり手に付かなくなるまでこねたら、丸めてボウルに戻し、覆って温かい場所で60〜90分、2倍に膨らむまで発酵させる。75gのバター、75gのグラニュー糖、シナモン、2本目のカルダモン小さじ1をよく混ぜてフィリングを作る。発酵した生地を軽く打ち粉した台に取り出し、40×50cmの長方形に伸ばす。フィリングを均等に塗り、生地を縦に三つ折りにして再度伸ばし、12本に切る。各ストリップをねじって結び目状に巻き端を下に折り込んでからオーブンシートを敷いた天板に並べ、ふんわり覆って30〜45分ふっくりするまで二次発酵させる（オーブンを200°C、ファン180°Cに予熱）。溶き卵を塗り、パールシュガーを散らして12〜15分、深い黄金色になるまで焼く。冷却ラックに移してキッチンタオルをかぶせ柔らかさを保つ。","en":"Warm the milk to 37°C, stir in the yeast and the 10 g of caster sugar, and leave for 5–10 minutes until frothy. Combine the flour, cardamom, and salt in a large bowl; make a well, pour in the yeast mixture and beaten egg, then bring together into a rough dough. Add the 100 g of softened butter a piece at a time and knead on a lightly floured surface for 8–10 minutes until the dough is smooth, elastic, and no longer sticks to your hands; cover and leave in a warm place for 60–90 minutes until doubled in size. Beat together the 75 g of butter, 75 g of caster sugar, cinnamon, and the second teaspoon of cardamom until smooth for the filling. Turn the risen dough onto a lightly floured surface and roll into a 40×50 cm rectangle; spread the filling evenly, fold the dough lengthways into thirds, roll again, and cut into 12 strips. Twist each strip and coil into a knot, tucking the end underneath, then space on lined baking trays; cover loosely and prove 30–45 minutes until noticeably puffed, while preheating the oven to 200°C (fan 180°C). Brush with beaten egg, scatter with pearl sugar, and bake for 12–15 minutes until deep golden brown; transfer to a wire rack and cover with a tea towel to keep them soft."}},{"id":94,"origin":{"ja":"メキシコ","en":"Mexico","ro":"Mexic"},"name":{"ja":"チレス・エン・ノガダ","en":"Chiles en nogada","ro":"Chiles en nogada"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"ja":["大きめのポブラノチリ4本（合計約700g）","豚ひき肉400g","オリーブオイルまたはラード大さじ2","中玉ねぎ1個（約150g）、みじん切り","にんにく3片、みじん切り","完熟トマト2個（約300g）、皮をむいてみじん切り","レーズン50g","皮をむいたアーモンド50g、粗みじん切り","完熟の桃または洋梨1個（約150g）、皮をむいて細かく刻む","シナモンパウダー小さじ1、クローブパウダー小さじ1/2、塩小さじ1、黒こしょう小さじ1/2","くるみ150g、温かいミルクに30分漬けて水気を切る","クリームチーズ150g、室温に戻す","サワークリーム100ml","ざくろ1個分の種（約100g）","フラットリーフパセリの葉ひとつかみ"],"en":["4 large poblano chiles (~700 g total)","400 g ground pork","2 tbsp olive oil or lard","1 medium onion (~150 g), finely diced","3 garlic cloves, minced","2 ripe tomatoes (~300 g), peeled and diced","50 g raisins","50 g blanched almonds, roughly chopped","1 ripe peach or pear (~150 g), peeled and diced","1 tsp ground cinnamon, 1/2 tsp ground cloves, 1 tsp salt, 1/2 tsp black pepper","150 g walnut halves, soaked in warm milk 30 minutes then drained","150 g cream cheese, softened","100 ml soured cream","seeds of 1 pomegranate (~100 g)","small handful of fresh flat-leaf parsley leaves"],"ro":["4 ardei poblano mari (~700 g total)","400 g carne de porc tocată","2 linguri ulei de măsline sau untură","1 ceapă medie (~150 g), tăiată mărunt","3 căței de usturoi, tocați","2 roșii coapte (~300 g), curățate de coajă și tocate","50 g stafide","50 g migdale decojite, tocate grosier","1 piersică sau pară coaptă (~150 g), curățată și tăiată cubulețe","1 linguriță scorțișoară, 1/2 linguriță cuișoare, 1 linguriță sare, 1/2 linguriță piper negru","150 g miez de nucă, înmuiat 30 minute în lapte cald și scurs","150 g cremă de brânză, la temperatura camerei","100 ml smântână fermentată","semințele unui rodiu (~100 g)","o mână de frunze de pătrunjel plat proaspăt"]},"howIsMade":{"ja":"ポブラノチリをガスコンロの直火やグリルで8〜10分、トングで回しながら全体が真っ黒になるまで焦がす；蓋をしたボウルに10分入れ、皮をこすり落としたあと、縦に1本切り込みを入れ、形を崩さないよう小さなスプーンで種と筋を取り除く。広めのフライパンにオイルを中火で熱し、玉ねぎを加えて5〜6分完全に柔らかくなるまで炒める；にんにくを加えてさらに1分炒める。豚ひき肉を加え、木べらでほぐしながら8分間ピンク色が残らなくなるまで炒める；トマトを加えて5分、水分が飛ぶまで煮る。レーズン、アーモンド、桃、シナモン、クローブ、塩、こしょうを加えて5分炒め、果肉が柔らかくほぼ水分がなくなったら火から下ろして室温まで冷ます。浸したくるみを水気を切ってからクリームチーズとサワークリームと共にブレンダーで完全になめらかになるまで攪拌する；塩で味を調える。冷ました肉だねを各チリにしっかり詰め、切り込みを軽く押さえて閉じ、皿に並べる。くるみソースを各チリにたっぷりかけ、ざくろの種とパセリの葉を散らし、室温で供する。","en":"Char the poblano chiles over an open gas flame or under a hot grill for 8–10 minutes, turning with tongs until the skin is completely blackened on all sides; place in a covered bowl for 10 minutes, then rub off the skin, make a single lengthways slit, and remove the seeds and veins with a small spoon while keeping each chile intact. Heat the oil in a wide frying pan over medium heat, add the onion, and cook for 5–6 minutes until completely soft; add the garlic and cook 1 minute more until fragrant. Add the ground pork and cook, breaking it up with a wooden spoon, for 8 minutes until no pink remains; add the diced tomatoes and cook for 5 minutes until they collapse and the liquid reduces. Stir in the raisins, almonds, peach, cinnamon, cloves, salt, and pepper; cook for 5 minutes until the fruit softens and the mixture is fairly dry, then remove from heat and cool to room temperature. Drain the soaked walnuts and blend with the cream cheese and soured cream until completely smooth; season with a pinch of salt — the nogada should be thick enough to coat a spoon. Stuff each poblano firmly with the cooled meat filling, pressing gently to close the slit; arrange on individual plates or a large serving dish. Spoon the walnut sauce generously over each chile, scatter pomegranate seeds and parsley leaves on top, and serve at room temperature."}},{"id":95,"origin":{"ja":"レバノン","en":"Lebanon","ro":"Liban"},"name":{"ja":"レンズ豆のスープ","en":"Lentil Soup","ro":"Supă de linte"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"ja":["赤レンズ豆300g、水が澄むまで洗う","オリーブオイル大さじ2","大きめの玉ねぎ1個（約200g）、みじん切り","中サイズのにんじん2本（約200g）、皮をむいてサイコロ切り","にんにく3片、みじん切り","クミンパウダー小さじ2","コリアンダーパウダー小さじ1","ターメリック小さじ1/2","カイエンペッパー小さじ1/4","野菜または鶏のブロス1.2リットル","レモン1個分の果汁","無塩バター大さじ2（仕上げ用）","スイートパプリカパウダー小さじ1（仕上げ用）","塩と黒こしょう適量","新鮮なコリアンダーまたはパセリとレモンのくし形切り（付け合わせ）"],"en":["300 g red lentils, rinsed until water runs clear","2 tbsp olive oil","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), peeled and diced","3 garlic cloves, minced","2 tsp ground cumin","1 tsp ground coriander","1/2 tsp ground turmeric","1/4 tsp cayenne pepper","1.2 litres vegetable or chicken stock","juice of 1 lemon","2 tbsp unsalted butter (for topping)","1 tsp sweet paprika (for topping)","salt and black pepper to taste","fresh coriander or parsley and lemon wedges to serve"],"ro":["300 g linte roșie, clătită până apa devine limpede","2 linguri ulei de măsline","1 ceapă mare (~200 g), tăiată mărunt","2 morcovi medii (~200 g), curățați și tăiați cubulețe","3 căței de usturoi, tocați","2 lingurițe chimen măcinat","1 linguriță coriandru măcinat","1/2 linguriță turmeric","1/4 linguriță ardei cayenne","1,2 litri supă de legume sau pui","sucul de la 1 lămâie","2 linguri unt nesărat (pentru topping)","1 linguriță paprika dulce (pentru topping)","sare și piper negru după gust","coriandru proaspăt sau pătrunjel, felii de lămâie pentru servit"]},"howIsMade":{"ja":"大きな鍋にオリーブオイルを中火で熱し、玉ねぎとにんじんを加え、時々かき混ぜながら8〜10分、柔らかく玉ねぎが透き通るまで炒める。にんにく、クミン、コリアンダー、ターメリック、カイエンを加え、スパイスが香るまで1〜2分混ぜる。洗ったレンズ豆とブロスを加え、沸騰させてから弱火に落とし、蓋を少しずらして20〜25分、レンズ豆が完全に柔らかくなり溶け始めるまで煮る。スープの約半量をハンドブレンダーでクリーミーでありながら食感が残るように粗く混ぜる（または全部を完全に滑らかにする）；必要ならブロスを加えてのばす。レモン果汁を混ぜ入れ、塩と黒こしょうで充分に調味する。小さなパンにバターを溶かし、パプリカを加えて香りが立つまで30秒炒める。温かいスープを温めたボウルに注ぎ、パプリカバターをかけ、新鮮なコリアンダーを散らし、レモンのくし形切りとパンを添えて供する。","en":"Heat the olive oil in a large saucepan over medium heat, add the onion and carrots, and cook for 8–10 minutes, stirring occasionally, until softened and the onion is translucent. Add the garlic, cumin, coriander, turmeric, and cayenne; stir for 1–2 minutes until the spices are fragrant and toasted. Add the rinsed lentils and stock, bring to a boil, then reduce the heat, partially cover, and simmer for 20–25 minutes until the lentils are completely tender and beginning to dissolve into the liquid. Use an immersion blender to puree about half the soup directly in the pot for a creamy yet textured finish — or blend it all smooth if you prefer; thin with a splash of extra stock or water if needed. Stir in the lemon juice and season generously with salt and black pepper. Melt the butter in a small pan over medium heat, add the sweet paprika, and let it sizzle for 30 seconds until fragrant and deep red. Ladle the hot soup into warmed bowls, drizzle the paprika butter over each portion, scatter fresh coriander on top, and serve with lemon wedges and crusty bread."}},{"id":96,"origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"スパナコピタ","en":"Spanakopita","ro":"Spanakopita"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"servings":6,"tipType":"veg","pairingsType":"veg","ingredients":{"ja":["フィロ生地500g（冷凍の場合は解凍）","新鮮なほうれん草1kg、洗ったもの（または冷凍600g、解凍してしっかり絞ったもの）","フェタチーズ300g、砕いたもの","中サイズ玉ねぎ2個、みじん切り","青ねぎ4本、小口切り","大きな卵3個、溶きほぐしたもの","新鮮なディル30g、刻んだもの","新鮮なパセリ20g、刻んだもの","エクストラバージンオリーブオイル150ml","ケファロティリまたはペコリーノ100g、すりおろし（オプション）","ナツメグ小さじ1/2、すりおろしたて","塩と挽きたての黒胡椒適量"],"en":["500g phyllo pastry, thawed if frozen","1kg fresh spinach, washed (or 600g frozen spinach, thawed and squeezed dry)","300g feta cheese, crumbled","2 medium onions, finely chopped","4 spring onions, finely sliced","3 large eggs, beaten","30g fresh dill, chopped","20g fresh parsley, chopped","150ml extra virgin olive oil","100g grated kefalotyri or pecorino (optional)","1/2 tsp freshly grated nutmeg","salt and freshly ground black pepper to taste"],"ro":["500g foi de plăcintă (phyllo), decongelate dacă sunt din congelator","1kg spanac proaspăt, spălat (sau 600g spanac congelat, decongelat și stors bine)","300g brânză feta, sfărâmată","2 cepe medii, tocate fin","4 cepe verzi, tăiate fin","3 ouă mari, bătute","30g mărar proaspăt, tocat","20g pătrunjel proaspăt, tocat","150ml ulei de măsline extravirgin","100g kefalotyri sau pecorino, ras (opțional)","1/2 linguriță nucșoară proaspăt rasă","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"ja":"オーブンを180°C（ファン160°C）に予熱する、ほうれん草1kgを洗い、大鍋に入れて中火で4–5分加熱し、しんなりさせる、ざるにあけてスプーンの背で水気をしっかり押し出し、さらに少量ずつキッチンペーパーで包んで絞る。フライパンにオリーブオイル大さじ3を熱し、みじん切りの玉ねぎを中火で8分炒め、柔らかく透き通るまで加熱する、青ねぎを加えてさらに2分炒める。大きなボウルに、絞ったほうれん草、玉ねぎ、フェタ300g、ケファロティリ（使う場合）、溶き卵3個、ディル、パセリ、ナツメグ、塩、こしょうを入れる、混ぜすぎるとほうれん草がさらに水を出すので、優しく合わせる。25×35cmの耐熱皿にオリーブオイルを塗る、フィロ生地を1枚敷き、油を塗り、その上にもう1枚を重ねる、これを繰り返して底に8層作る、使わないフィロは少し湿らせた布で覆っておく。フィロの底に詰め物を均一に広げる、さらに8枚のフィロで覆い、各層にたっぷりのオリーブオイルを塗る。端を内側に折り込む、鋭いナイフで表面に6–8等分の切れ目を入れるが、切るのは上の層だけ — そうすることで取り分ける時にフィロが砕け散らない、表面に水を数滴ふりかけ、生地が反らないようにする。40–45分焼き、表面が濃いきつね色になり、軽く叩くとサクッとした音がするまで焼く、15分休ませてから、切れ目に沿ってカットする。","en":"Preheat the oven to 180°C (fan 160°C); wash 1kg of spinach and wilt it in a large pot over medium heat for 4–5 minutes, until just collapsed; tip into a colander and press out as much water as possible, then squeeze handfuls dry between paper towels. Warm 3 tablespoons of olive oil in a pan and cook the chopped onions over medium heat for 8 minutes, until soft and translucent; add the spring onions and cook 2 more minutes. In a large bowl, combine the squeezed spinach, the onion mixture, 300g crumbled feta, the kefalotyri if using, 3 beaten eggs, dill, parsley, nutmeg, salt and pepper; mix gently — do not overwork or the spinach will release more water. Brush a 25×35 cm baking dish with olive oil; lay one sheet of phyllo, brush with olive oil, and top with another sheet; continue until you have 8 layers as the base; keep unused phyllo covered with a slightly damp cloth. Spread the filling evenly over the phyllo base; top with 8 more sheets of phyllo, brushing each layer generously with olive oil. Tuck the edges in; with a sharp knife, score the top into 6–8 portions, cutting only through the top layers — this prevents shattering when serving; sprinkle a few drops of water on top to stop the pastry curling. Bake for 40–45 minutes, until the top is deep golden brown and the pastry sounds crisp when tapped; rest 15 minutes before cutting along the scored lines."},"timeMins":{"total":90,"active":40}},{"id":97,"origin":{"ja":"ナイジェリア","en":"Nigeria","ro":"Nigeria"},"name":{"ja":"ジョロフライス","en":"Jollof Rice","ro":"Jollof Rice"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"def","ingredients":{"ja":["長粒パーボイルド米（またはバスマティ米）400g、水が澄むまで洗ったもの","完熟ローマトマト6個、ざく切り（または缶詰のカットトマト400g）","大きな赤パプリカ2個、種を除いてざく切り","スコッチボネット唐辛子または赤唐辛子1本、種を除く","大きな玉ねぎ2個（1個はブレンダー用、1個は薄切り）","にんにく4片、皮を剥いたもの","新鮮な生姜30g、皮を剥いたもの","トマトペースト大さじ3","植物油120ml（伝統的にはピーナッツオイル）","熱い鶏ガラまたは野菜ストック750ml","ローリエ2枚","カレーパウダー小さじ1","ドライタイム小さじ1","スモークパプリカ小さじ1","塩と挽きたての黒胡椒適量"],"en":["400g long-grain parboiled rice (or basmati), rinsed until water runs clear","6 ripe Roma tomatoes, roughly chopped (or 400g canned chopped tomatoes)","2 large red bell peppers, deseeded and roughly chopped","1 scotch bonnet or red chilli, deseeded","2 large onions (1 blended, 1 sliced)","4 garlic cloves, peeled","30g fresh ginger, peeled","3 tbsp tomato paste","120ml vegetable oil (groundnut oil is traditional)","750ml hot chicken or vegetable stock","2 bay leaves","1 tsp curry powder","1 tsp dried thyme","1 tsp smoked paprika","salt and freshly ground black pepper to taste"],"ro":["400g orez cu bob lung parboiled (sau basmati), spălat până apa rămâne limpede","6 roșii Roma coapte, tăiate grosier (sau 400g roșii din conservă)","2 ardei kapia roșii mari, fără semințe și tăiați grosier","1 ardei scotch bonnet sau ardei iute roșu, fără semințe","2 cepe mari (una mixată, una feliată)","4 căței de usturoi, curățați","30g ghimbir proaspăt, curățat","3 linguri pastă de roșii","120ml ulei vegetal (tradițional, ulei de arahide)","750ml supă fierbinte de pui sau legume","2 foi de dafin","1 linguriță pudră de curry","1 linguriță cimbru uscat","1 linguriță boia afumată","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"ja":"米400gを水が澄むまで冷水で洗い、水を切る — この工程で余分なデンプンが落ち、米粒が一粒一粒立つ仕上がりになる。ブレンダーにトマト、赤パプリカ、唐辛子、玉ねぎ1個、にんにく、生姜を入れ、なめらかなペースト状にする。厚手の鍋に油120mlを中火で熱する、薄切りの玉ねぎを加え、軽くきつね色になるまで5–6分炒める。トマトペースト大さじ3を加え、色が濃くなり生の香りが消えるまで3分炒める。ブレンドしたパプリカ・トマトペーストを注ぎ、ローリエ、カレーパウダー、タイム、スモークパプリカを加える、中火で蓋をせず18–20分、頻繁に混ぜながら、ソースが煮詰まり深い赤色になって油が表面に浮いてくるまで煮る — これが最も重要な工程。洗った米を加え、すべての粒がソースに絡むよう混ぜる、熱いストック750mlを注ぎ、塩こしょうで調味して再び沸騰させる。火を最弱まで下げ、鍋にしっかり蓋をする（本格的な仕上がりにするには、蓋をする前に縁をアルミ箔で密封すると良い）、触らずに25–30分炊き、米が柔らかくなり水分が吸収されるまで火を通す。火を止め、さらに10分蓋をしたまま蒸らす、フォークでやさしくほぐす — 底にはわずかにスモーキーなおこげができているはず、揚げプランテン、グリルチキン、またはシンプルなサラダと共に提供する。","en":"Rinse 400g of rice in cold water until the water runs clear, then drain — this removes excess starch and keeps the grains separate. Blend the tomatoes, red bell peppers, chilli, one onion, garlic and ginger to a smooth paste in a blender. Heat 120ml oil in a heavy-bottomed pot over medium heat; add the sliced onion and fry for 5–6 minutes, until lightly golden. Stir in 3 tablespoons of tomato paste and cook for 3 minutes, until darkened and the raw aroma is gone. Pour in the blended pepper mixture, add the bay leaves, curry powder, thyme and smoked paprika; cook uncovered over medium heat for 18–20 minutes, stirring often, until the sauce reduces, deepens to a dark red and the oil rises to the surface — this is the critical step. Add the rinsed rice and stir until every grain is coated in sauce; pour in 750ml hot stock, season with salt and pepper, and bring back to a boil. Reduce the heat to the lowest setting, cover the pot tightly (seal the rim with foil before placing the lid for an authentic finish), and cook undisturbed for 25–30 minutes, until the rice is tender and the liquid is absorbed. Turn off the heat and leave covered for 10 more minutes; fluff gently with a fork — the bottom layer should have a slight smoky crust; serve with fried plantain, grilled chicken, or a simple salad."}},{"id":98,"origin":{"ja":"サモア","en":"Samoa","ro":"Samoa"},"name":{"ja":"オカ・イア","en":"Oka i'a","ro":"Oka i'a"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ja":["刺身用マグロまたはマヒマヒ500g、皮と骨を取り除き、1.5cm角に切ったもの","新鮮なライム果汁120ml（ライム約6個分）","全脂ココナッツミルク200ml（開けたて、または缶詰）","中サイズのきゅうり1本、皮と種を除いて小さな角切り","小さな赤玉ねぎ1個、細かい角切り","完熟トマト2個、種を除いて角切り","小さな赤唐辛子1本、細かく刻んだもの（オプション）","青ねぎ1本、小口切り","細かい海塩小さじ1","挽きたての黒胡椒","飾り用の新鮮なコリアンダーの葉"],"en":["500g sashimi-grade tuna or mahi-mahi, skinned and boned, cut into 1.5 cm cubes","120ml fresh lime juice (about 6 limes)","200ml full-fat coconut milk (freshly opened or canned)","1 medium cucumber, peeled, deseeded, and finely diced","1 small red onion, finely diced","2 ripe tomatoes, deseeded and diced","1 small red chilli, finely chopped (optional)","1 spring onion, finely sliced","1 tsp fine sea salt","freshly ground black pepper","fresh coriander leaves, to garnish"],"ro":["500g ton sau mahi-mahi de calitate sashimi, fără piele și oase, tăiat cuburi de 1,5 cm","120ml suc proaspăt de lime (aproximativ 6 lime)","200ml lapte de cocos integral (proaspăt deschis sau din conservă)","1 castravete mediu, curățat, fără semințe, tăiat cuburi mici","1 ceapă roșie mică, tăiată cuburi mici","2 roșii coapte, fără semințe, tăiate cuburi","1 ardei iute roșu mic, tocat fin (opțional)","1 ceapă verde, tăiată fin","1 linguriță sare fină de mare","piper negru proaspăt măcinat","frunze de coriandru proaspăt, pentru ornat"]},"howIsMade":{"ja":"角切りの魚を反応しないボウル（ガラスまたはセラミック）に入れる、新鮮なライム果汁120mlを注ぎ、すべての切り身が均一に絡むよう和える、冷蔵庫で15–20分マリネする — 表面は不透明になり、中心は半透明のままが理想。魚をマリネしている間に、さいの目に切った赤玉ねぎを冷水に10分浸してから水を切る、この工程で辛味が和らぎ、シャキッとした食感は残る。細かい網ザルで魚をしっかり水切りする、大部分のライム果汁は捨て、大さじ2杯分は残しておく。魚を清潔なボウルに戻す、きゅうり、水切りした赤玉ねぎ、トマト、唐辛子、青ねぎを加える、魚が崩れないよう優しく和える。ココナッツミルク200mlと残しておいたライム果汁大さじ2を加える、塩と挽きたての黒胡椒数振りを加える、ココナッツミルクが魚を包み込み、崩さないように優しく折り混ぜる。味を見て塩やライムを調整する、すぐに、よく冷やしたまま、浅めの器に盛る、新鮮なコリアンダーの葉をふりかける。","en":"Place the cubed fish in a non-reactive (glass or ceramic) bowl; pour over 120ml fresh lime juice and toss until every piece is coated; refrigerate for 15–20 minutes — the surface should turn opaque while the centre stays translucent. While the fish marinates, soak the diced red onion in cold water for 10 minutes, then drain; this softens its raw bite without losing the crunch. Drain the fish thoroughly through a fine sieve; discard most of the lime juice but reserve 2 tablespoons. Return the fish to a clean bowl; add the cucumber, drained red onion, tomatoes, chilli and spring onion; toss gently so the fish stays intact. Pour in 200ml coconut milk and the reserved 2 tbsp lime juice; add the salt and a few grinds of pepper; fold everything together gently — the coconut milk should coat without breaking the fish. Taste and adjust salt or lime; serve immediately, very cold, in shallow bowls; scatter fresh coriander leaves on top."}},{"id":99,"origin":{"ja":"アルメニア","en":"Armenia","ro":"Armenia"},"name":{"ja":"ホロヴァッツ","en":"Khorovats","ro":"Khorovats"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["豚肩肉または牛フィレ800g、4cm角に切ったもの","大きな赤玉ねぎ2個（1個はマリネ用にスライス、1個は串用にくし形切り）","赤パプリカ1個、4cm大に切ったもの","緑パプリカ1個、4cm大に切ったもの","中サイズのナス1本、3cmの輪切り","完熟トマト4個（丸ごとグリル用）","ひまわり油大さじ3","挽きたての黒胡椒小さじ1","粗塩小さじ2","新鮮なバジルとパセリ少々、付け合わせ用","ラヴァシュなどのフラットブレッド、添え用"],"en":["800g pork shoulder or beef tenderloin, cut into 4 cm cubes","2 large red onions (1 sliced for the marinade, 1 cut into wedges for skewering)","1 red bell pepper, cut into 4 cm pieces","1 green bell pepper, cut into 4 cm pieces","1 medium aubergine, cut into 3 cm rounds","4 ripe tomatoes (to be grilled whole alongside)","3 tbsp sunflower oil","1 tsp freshly ground black pepper","2 tsp coarse salt","a small handful of fresh basil and parsley, to serve","lavash or another flatbread, to serve"],"ro":["800g pulpă de porc sau mușchi de vită, tăiat cuburi de 4 cm","2 cepe roșii mari (una feliată pentru marinadă, una tăiată felii pentru frigărui)","1 ardei gras roșu, tăiat bucăți de 4 cm","1 ardei gras verde, tăiat bucăți de 4 cm","1 vânătă medie, tăiată rondele de 3 cm","4 roșii coapte (pentru grătar întregi)","3 linguri ulei de floarea-soarelui","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare grunjoasă","un mănunchi de busuioc și pătrunjel proaspăt, pentru servit","lavaș sau alt tip de pâine plată"]},"howIsMade":{"ja":"玉ねぎ1個を薄切りにする、大きなボウルに800gの角切り肉、スライス玉ねぎ、塩小さじ2、黒こしょう小さじ1、ひまわり油大さじ3を入れる、手でしっかり揉み込み、冷蔵庫で4–8時間、または一晩マリネする。炭に火を起こし、白い縁を持つ赤く輝く熾火になるまで燃え下がらせる——約30–40分、グリル網を炭の上15cmにセットする。マリネした肉を金属串に刺し、玉ねぎのくし切りを交互に挟む、熱気が回るよう肉と肉の間に少し隙間を空ける。パプリカ丸ごと、ナスの輪切り、トマトを肉とは別の場所のグリルに直接置く、頻繁に回転させながら、皮が全面真っ黒になるまで——合計12–15分。肉の串を熾火の最も熱い部分の上に置く、2分ごとに返しながら10–14分焼き、表面は深く焦げ色がつき、中心はまだピンク色（豚肉の場合は内部温度60°C）になるまで。グリルした野菜を皿に移し、5分間アルミホイルで覆い、その後焦げた皮を取り除く、ざっくり刻んで、出てきた汁、塩、刻みパセリと混ぜて素朴なレリッシュにする。串を熱いうちに野菜のレリッシュ、新鮮なバジル、レモンのくし切り、温めたラヴァシュと共に出し、巻いて食べる。","en":"Thinly slice one onion; in a large bowl, combine 800g cubed meat, the sliced onion, 2 tsp salt, 1 tsp black pepper, and 3 tbsp sunflower oil; massage well by hand and refrigerate 4–8 hours, or overnight. Light a charcoal fire and let it burn down to glowing red embers with white edges — about 30–40 minutes; position the grill 15 cm above the coals. Thread the marinated meat onto metal skewers, alternating with wedges of onion and leaving small gaps between pieces so the hot air can circulate. Lay the whole peppers, aubergine slices and tomatoes directly on the grill, away from the meat; char them rotating frequently, until the skins blacken on every side — about 12–15 minutes total. Place the meat skewers over the hottest part of the embers; grill 10–14 minutes, turning every 2 minutes, until the meat is deeply caramelised outside but still pink in the centre — internal temperature 60°C for pork. Transfer the grilled vegetables to a plate, cover with foil for 5 minutes, then strip off the blackened skins; roughly chop and mix with the resting juices, salt, and chopped parsley to make a rustic relish. Serve the skewers hot with the vegetable relish, fresh basil, lemon wedges, and warm lavash for wrapping."}},{"id":100,"origin":{"ja":"エストニア","en":"Estonia","ro":"Estonia"},"name":{"ja":"ヴェリヴォルスト","en":"Verivorst","ro":"Verivorst"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["豚の血500g（生または解凍）","豚脂または脂身の多い豚バラ200g、細かい角切り","押し麦200g、茹でて冷ましたもの","大きな玉ねぎ2個、みじん切り","ドライマジョラム小さじ1","オールスパイス小さじ1","黒こしょう小さじ1","粗塩小さじ2","洗浄済みの天然腸詰めケーシング1.5m","豚脂大さじ2、調理用","リンゴンベリージャムとピクルスのきゅうり、添え用"],"en":["500g pig's blood (fresh or thawed)","200g pork fat or fatty pork belly, finely diced","200g pearl barley, cooked and cooled","2 large onions, finely chopped","1 tsp dried marjoram","1 tsp ground allspice","1 tsp ground black pepper","2 tsp coarse salt","1.5m cleaned natural sausage casing","2 tbsp pork lard, for cooking","lingonberry jam and pickled cucumbers, to serve"],"ro":["500g sânge de porc (proaspăt sau decongelat)","200g slănină sau piept de porc gras, tăiat cuburi mici","200g orz perlat, fiert și răcit","2 cepe mari, tocate fin","1 linguriță maghiran uscat","1 linguriță ienibahar măcinat","1 linguriță piper negru măcinat","2 lingurițe sare grunjoasă","1,5m maț natural curățat","2 linguri untură de porc, pentru gătit","gem de lingonberry și castraveți murați, pentru servit"]},"howIsMade":{"ja":"大きなフライパンに角切りの豚脂を入れ、弱火で8–10分、脂が大部分溶け出してキューブが黄金色になるまで揚げる、みじん切りの玉ねぎを加え、さらに6–8分炒め、柔らかく透き通るまで加熱する、完全に冷ます。大きなボウルに、茹でた押し麦、炒めた玉ねぎと豚脂（油ごと）、マジョラム、オールスパイス、塩、こしょうを入れて混ぜる、よく混ぜ合わせる。豚の血を泡立て器で軽くかき混ぜて固まりをほぐし、大麦の混合物に少しずつ加える、詰め物は艶があり流れるが、流動的過ぎないテクスチャーが理想。腸詰めケーシングを冷たい流水で5分洗う、片端を調理用のひもで結ぶ。ケーシングの開いている端を広い漏斗かソーセージスタッファーに通す、混合物を少しずつ詰めていき、加熱中の膨張を見越してケーシングを3分の2までしか満たさないようにする、12–15cmごとに結び、それぞれに針で数か所穴を開ける。大鍋の水を80°Cまで加熱する — 沸騰させない、ソーセージをそっと入れ、30–40分かけて静かに茹でる、触ると弾力があり、刺すと透明な肉汁が出れば完成。ソーセージを取り出し、10分休ませる、オーブンを200°Cに予熱する。ソーセージに溶かしたラードを塗り、天板にのせて12–15分焼く、途中で一度返し、皮がパリッと美しい焼き色になるまで焼く、熱々のままリンゴンベリージャムとピクルスのきゅうりを添えて供する。","en":"In a large pan, fry the diced pork fat over low heat for 8–10 minutes, until most of its fat has rendered and the cubes are golden; add the chopped onions and cook 6–8 minutes more, until soft and translucent; set aside to cool completely. In a large bowl, combine the cooked pearl barley, the fried onions and pork fat (with all their fat), the marjoram, allspice, salt and pepper; mix well. Whisk the blood briefly to break up any clots, then stir it gradually into the barley mixture; the filling should look glossy and pourable, but not too liquid. Rinse the sausage casing under cold running water for 5 minutes; tie off one end with kitchen twine. Slide the open end of the casing onto a wide funnel or sausage stuffer; pipe the mixture in gradually, leaving the casing two-thirds full to allow expansion during cooking; tie off into 12–15 cm sausages and prick each with a needle in several places. Bring a large pot of water to 80°C — not boiling; slip the sausages in and poach gently for 30–40 minutes, until they feel firm to the touch and the juices run clear when pricked. Lift the sausages out and let them rest 10 minutes; preheat the oven to 200°C. Brush the sausages with melted lard and roast on a tray for 12–15 minutes, turning once, until the skins are crisp and burnished; serve hot with lingonberry jam and pickled cucumbers."}},{"id":102,"origin":{"ja":"韓国","en":"South Korea","ro":"Coreea de Sud"},"name":{"ja":"トッポッキ","en":"Tteokbokki","ro":"Tteokbokki"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"ja":["円柱形の餅（ガレトック）500g、新鮮または解凍","おでん（エオムク）150g、三角形に切る","コチュジャン（発酵唐辛子ペースト）大さじ3","コチュガル（韓国唐辛子フレーク）大さじ1","砂糖大さじ1","醤油小さじ1","煮干しだし500ml（またはだしパック入りの水）","長ねぎ2本（5cm幅に切る）","固ゆで卵2個（皮をむく）","ごま油小さじ1","炒りごま小さじ1"],"en":["500g cylindrical rice cakes (garae-tteok), fresh or thawed","150g eomuk (Korean fish cake), cut into triangles","3 tbsp gochujang (fermented red chili paste)","1 tbsp gochugaru (Korean red pepper flakes)","1 tbsp sugar","1 tsp soy sauce","500ml anchovy stock (or water with a dashi packet)","2 spring onions, cut into 5 cm pieces","2 hard-boiled eggs, peeled","1 tsp sesame oil","1 tsp toasted sesame seeds"],"ro":["500g tteok cilindric (garae-tteok) proaspăt sau dezghețat","150g eomuk (prăjitură de pește coreeană), tăiat în triunghiuri","3 linguri gochujang (pastă de ardei iute fermentat)","1 lingură gochugaru (fulgi de ardei iute coreean)","1 lingură zahăr","1 linguriță sos de soia","500ml supă de hamsii (sau apă cu dashi)","2 cepe verzi, tăiate în bucăți de 5 cm","2 ouă fierte tari, decojite","1 linguriță ulei de susan","1 linguriță semințe de susan prăjite"]},"howIsMade":{"ja":"餅が硬かったり冷蔵されていたら、ぬるま湯に20〜30分浸して柔らかくし、水を切る。広めの浅鍋に煮干しだし500mlを入れ、中強火で沸騰させる。コチュジャン大さじ3、コチュガル大さじ1、砂糖大さじ1、醤油小さじ1を加える、泡立て器でしっかり混ぜ、ペーストを完全に溶かして艶のある赤いソースにする。水を切った餅を加える、優しく混ぜて全ての餅にソースを絡め、中火で8〜10分、頻繁にかき混ぜながら煮る、餅が柔らかくなり、ソースがスプーンの背にとろりとからむ濃さになるまで。エオムクを加え、さらに3〜4分煮て、ソースを吸い込んで鮮やかな赤色になるまで火を通す。ゆで卵2個を入れて温める、味を見て、必要なら砂糖をひとつまみか醤油を数滴加えて調える。ごま油をたらし、長ねぎと炒りごまを散らす、フライパンからそのまま、熱々をすぐに供する。","en":"If the rice cakes are hard or refrigerated, soak them in warm water for 20–30 minutes until pliable; drain. In a wide shallow pan, bring 500ml of anchovy stock to a boil over medium-high heat. Stir in 3 tbsp gochujang, 1 tbsp gochugaru, 1 tbsp sugar and 1 tsp soy sauce; whisk until the paste fully dissolves and the sauce turns glossy red. Add the drained rice cakes; stir gently to coat every piece, then simmer over medium heat for 8–10 minutes, stirring often, until the rice cakes are tender and the sauce has thickened to a syrupy consistency that coats the back of a spoon. Add the eomuk pieces and cook for another 3–4 minutes, until they have absorbed the sauce and turned bright red. Slip in the 2 hard-boiled eggs to warm through; taste and adjust with a pinch of sugar or a splash of soy if needed. Drizzle with sesame oil, sprinkle with the spring onions and sesame seeds; serve immediately, very hot, straight from the pan."}},{"id":103,"origin":{"ja":"エクアドル","en":"Ecuador","ro":"Ecuador"},"name":{"ja":"エビのセビーチェ","en":"Shrimp Ceviche","ro":"Ceviche de camarón"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ja":["中サイズのエビ600g、殻と背わたを取り除いたもの","新鮮なライム果汁180ml（ライム約8個分）","新鮮なオレンジ果汁120ml","大きな赤玉ねぎ1個、細かい角切り","完熟トマト3個、種を取り角切り","赤唐辛子（アヒ）1本、細かく刻んだもの（オプション）","新鮮なコリアンダーの葉30g、刻んだもの","オリーブオイル大さじ3","細かい海塩小さじ1","挽きたての黒胡椒","チフレス（プランテンチップス）または炒ったコーン、添え用"],"en":["600g medium shrimp, peeled and deveined","180ml fresh lime juice (about 8 limes)","120ml fresh orange juice","1 large red onion, finely diced","3 ripe tomatoes, deseeded and diced","1 red chili (ají), finely chopped (optional)","30g fresh coriander leaves, chopped","3 tbsp olive oil","1 tsp fine sea salt","freshly ground black pepper","chifles (plantain chips) or toasted corn, to serve"],"ro":["600g creveți medii, decojiți și fără vene","180ml suc proaspăt de lime (aproximativ 8 lime)","120ml suc proaspăt de portocale","1 ceapă roșie mare, tăiată cuburi mici","3 roșii coapte, fără semințe și tăiate cuburi","1 ardei iute roșu (ají), tocat fin (opțional)","30g frunze de coriandru proaspăt, tocate","3 linguri ulei de măsline","1 linguriță sare fină de mare","piper negru proaspăt măcinat","chifles (chipsuri de plantain) sau porumb prăjit, pentru servit"]},"howIsMade":{"ja":"大鍋に塩水を沸かす、エビを入れ、60〜90秒、ピンク色で不透明になるまで茹でる、すぐに引き上げて氷水のボウルに移して冷やす。エビの水気を切り、好みで半分に切るかそのままにし、反応しないボウル（ガラスかセラミック）に入れる。ライム果汁180mlとオレンジ果汁120mlをエビにかける、和えて蓋をし、冷蔵庫で15〜20分マリネする。エビをマリネしている間、さいの目に切った赤玉ねぎを塩を入れた氷水に10分浸して水を切る — 辛味が和らぎ、シャキッとした食感は残る。水切りした玉ねぎ、トマト、唐辛子、コリアンダー、オリーブオイル大さじ3、塩小さじ1をエビのボウルに加える、優しく和える。味を見て、塩・ライム・唐辛子で調整する、5分置いて味をなじませる。浅めの器によく冷やして盛り、チフレスや炒りコーンを添えて歯応えのコントラストを楽しむ。","en":"Bring a large pot of salted water to a boil; add the shrimp and boil for 60–90 seconds, until pink and opaque; drain immediately and shock in a bowl of ice water. Drain the shrimp, halve them or leave them whole as you prefer, and place in a non-reactive (glass or ceramic) bowl. Pour 180ml lime juice and 120ml orange juice over the shrimp; toss, cover, and refrigerate for 15–20 minutes. While the shrimp marinates, soak the diced red onion in salted ice water for 10 minutes, then drain — this softens the harsh bite without losing crunch. Add the drained onion, tomatoes, chili, coriander, 3 tbsp olive oil and 1 tsp salt to the shrimp bowl; toss gently. Taste and adjust salt, lime, or chili; let rest for 5 minutes so the flavours settle. Serve very cold in shallow bowls, with chifles or toasted corn alongside for crisp contrast."}},{"id":104,"origin":{"ja":"ドミニカ共和国","en":"Dominican Republic","ro":"Republica Dominicană"},"name":{"ja":"ラ・バンデラ","en":"La Bandera","ro":"La Bandera"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"ja":["長粒白米400g","乾燥赤キドニービーンズ250g（または茹で/缶詰800g、水気を切る）","骨付き鶏もも肉または牛肩肉600g、4cm角に切ったもの","大きな緑色プランテン2本、皮を剥いて1cm厚の輪切り","中サイズの緑ピーマン1個、細かい角切り","小さな赤ピーマン1個、細かい角切り","大きな玉ねぎ1個、みじん切り","にんにく4片、みじん切り","新鮮なコリアンダー30g、刻んだもの（あればクラントロ）","完熟トマト2個、角切り（または缶詰のカットトマト200g）","トマトペースト大さじ2","植物油60ml（プランテン揚げ用に追加）","ドライオレガノ小さじ1","ライム1個分の絞り汁","塩と挽きたての黒胡椒"],"en":["400g long-grain white rice","250g dried red kidney beans (or 800g cooked/canned, drained)","600g bone-in chicken thighs or beef chuck, cut into 4 cm cubes","2 large green plantains, peeled and sliced 1 cm thick","1 medium green bell pepper, finely diced","1 small red bell pepper, finely diced","1 large onion, finely chopped","4 garlic cloves, minced","30g fresh coriander, chopped (or culantro if available)","2 ripe tomatoes, diced (or 200g canned chopped tomatoes)","2 tbsp tomato paste","60ml vegetable oil (plus more for frying plantains)","1 tsp dried oregano","juice of 1 lime","salt and freshly ground black pepper"],"ro":["400g orez cu bob lung alb","250g fasole roșie uscată (sau 800g fasole gătită)","600g pulpe de pui cu os sau pulpă de vită, tăiată cuburi de 4 cm","2 banane plantain verzi mari, decojite, tăiate rondele de 1 cm","1 ardei gras verde mediu, tăiat cuburi mici","1 ardei gras roșu mic, tăiat cuburi mici","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","30g coriandru proaspăt, tocat (sau culantro)","2 roșii coapte, tăiate cuburi (sau 200g roșii din conservă)","2 linguri pastă de roșii","60ml ulei vegetal (plus mai mult pentru prăjit)","1 linguriță oregano uscat","zeamă de la 1 lime","sare și piper negru proaspăt măcinat"]},"howIsMade":{"ja":"乾燥豆を使う場合は一晩浸ける、水を切り、新鮮な水1Lと塩ひとつまみで覆い、60〜75分やわらかくなるまで煮る、煮汁を250ml取り置く。肉に塩、こしょう、オレガノ、ライム果汁で下味をつける、ソフリートを準備する間15分置く。厚手鍋に油大さじ2を熱する、ソフリートを作る：玉ねぎを5分炒め、にんにく、両方のピーマン、コリアンダーの半量を加える、やわらかくなるまで4分炒める。ソフリートを片側に寄せる、空いた場所に肉を入れ、各面3〜4分焼く、トマトペースト大さじ2と角切りトマトを加え、3分炒める、水500mlを加え、蓋をして35〜40分、肉がフォークでほぐれてソースがとろみがつくまで煮込む。その間に米を炊く：米400gを水が澄むまで洗う、広い鍋に油大さじ1と塩小さじ1を熱し、米を加え、水700mlで覆い、沸騰させてから最弱火にし、蓋をして18〜20分蒸し炊きする、火から外して10分蒸らす。豆を仕上げる：小鍋に油大さじ1と手順3で取り置いたソフリート大さじ1を熱する、水切りした豆と取り置きの煮汁250ml、塩小さじ1を加える、12〜15分、ひと握りの豆を鍋肌で潰してとろみをつけながら煮る。フライパンに5cmの油を175°Cに熱する、プランテンを3〜4分黄金色まで揚げる、紙の上で油を切り、プレスかコップの底で平らに押しつぶし、さらに1〜2分カリッとなるまで再揚げする、熱いうちに塩を振る。盛り付け：ベースに米、横に豆をひしゃくでたっぷり、ブレイズした肉とソースをたっぷり、揚げプランテンを4〜5枚添える、残りのコリアンダー、ライムのくし切り、シンプルな緑のサラダで仕上げる。","en":"Soak the dried beans overnight if using; drain, cover with 1L fresh water and a pinch of salt, and simmer for 60–75 minutes, until fully tender; reserve 250ml of the cooking liquid. Season the meat with salt, pepper, oregano, and lime juice; rest for 15 minutes while you prepare the sofrito. Heat 2 tbsp oil in a heavy pot; make a sofrito: sauté the onion for 5 minutes, then add the garlic, both peppers, and half the coriander; cook 4 minutes until soft. Push the sofrito to one side; add the meat to the empty space and brown for 3–4 minutes per side; stir in 2 tbsp tomato paste and the diced tomatoes, cook for 3 minutes; pour in 500ml water, cover, and simmer for 35–40 minutes, until the meat is fork-tender and the sauce has thickened. Meanwhile cook the rice: rinse 400g of rice until the water runs clear; in a wide pot, heat 1 tbsp oil and 1 tsp salt, add the rice, cover with 700ml water, bring to a boil, then reduce to the lowest heat and steam, covered, for 18–20 minutes; rest 10 minutes off heat. Finish the beans: in a small pot, heat 1 tbsp oil and a spoonful of the sofrito set aside in step 3; add the drained beans plus 250ml reserved cooking liquid and 1 tsp salt; simmer for 12–15 minutes, mashing a handful against the side of the pot to thicken to a saucy consistency. Heat 5 cm of oil in a frying pan to 175°C; fry the plantain slices for 3–4 minutes until golden; drain on paper, flatten with a press or the back of a cup, and refry for 1–2 minutes until crisp; salt while hot. Plate each portion with rice as the base, a ladle of beans alongside, a generous portion of braised meat with its sauce, and 4–5 plantain rounds; finish with the remaining coriander, lime wedges, and a simple green salad."}},{"id":105,"origin":{"ja":"イラン","en":"Iran","ro":"Iran"},"name":{"ja":"フェセンジャン","en":"Fesenjan","ro":"Fesenjan"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"ja":["骨なし鶏もも肉800g、または小さな鴨1羽（1.5kg）を切り分けたもの","むきクルミ300g、ローストして細かく挽いたもの","ザクロシロップ120ml","大きな玉ねぎ2個、みじん切り","植物油大さじ3","ターメリック小さじ1","シナモン小さじ1","ナツメグ小さじ1/2、すりおろしたて","ブラウンシュガー大さじ1（または好みで）","熱い鶏ガラスープまたは水1L","新鮮なザクロの実、飾り用","塩と挽きたての黒胡椒","バスマティライス、添え用"],"en":["800g boneless chicken thighs, or 1 small duck (1.5kg) jointed","300g shelled walnuts, toasted and finely ground","120ml pomegranate molasses","2 large onions, finely chopped","3 tbsp vegetable oil","1 tsp ground turmeric","1 tsp ground cinnamon","1/2 tsp freshly grated nutmeg","1 tbsp brown sugar (or to taste)","1 litre hot chicken stock or water","fresh pomegranate seeds, to garnish","salt and freshly ground black pepper","basmati rice, to serve"],"ro":["800g pulpe de pui dezosate, sau 1 rață mică (1,5kg) tăiată","300g miez de nucă, prăjit și măcinat fin","120ml melasă de rodie","2 cepe mari, tocate fin","3 linguri ulei vegetal","1 linguriță turmeric măcinat","1 linguriță scorțișoară măcinată","1/2 linguriță nucșoară proaspăt rasă","1 lingură zahăr brun (sau după gust)","1 litru supă de pui sau apă fierbinte","semințe de rodie proaspete, pentru ornat","sare și piper negru proaspăt măcinat","orez basmati pentru servit"]},"howIsMade":{"ja":"クルミ300gを乾いたフライパンに入れ、中火で4〜5分、絶えず揺すりながらローストする、香りが立って色が少し濃くなるまで、冷ましてからフードプロセッサーでできるだけ細かいペーストにする。厚手鍋に油大さじ3を中火で熱する、みじん切りの玉ねぎを加え、12〜15分、深いきつね色で甘くなるまで炒める、ターメリック、シナモン、ナツメグを加え1分炒める。肉に塩こしょうで下味をつける、鍋に入れて各面4〜5分、色づくまで焼く、皿に取り出す。クルミペーストを鍋に加え、木ベラで3分混ぜる、油が出始め、香ばしい香りがするまで——この工程がソースに深みを与える。熱いスープ1Lを注ぎ、肉を肉汁ごと戻し入れ、弱火で蓋をせず30〜40分、ナッツペーストが焦げないよう頻繁にかき混ぜながら煮る。ザクロシロップとブラウンシュガーを加える、味見：ソースは甘酸っぱく、深く旨い味であるべき、さらに弱火で30〜40分、肉が完全に柔らかくなり、ソースがほぼ黒に近くなり、クルミの油が表面に浮くまで煮込む。塩、酸味のためにシロップ追加、まろやかさのために砂糖追加で調整する、温かいバスマティライスにかけ、新鮮なザクロの実を散らす。","en":"Toast 300g of walnuts in a dry pan over medium heat for 4–5 minutes, tossing constantly, until fragrant and slightly darker; cool, then grind to as fine a paste as possible in a food processor. In a heavy pot, heat 3 tbsp oil over medium heat; add the chopped onions and cook for 12–15 minutes, until deeply golden and sweet; stir in the turmeric, cinnamon, and nutmeg and cook for 1 minute. Season the meat with salt and pepper; add to the pot and brown for 4–5 minutes per side, just for colour; lift onto a plate. Add the walnut paste to the pot and stir with a wooden spoon for 3 minutes, until it starts releasing oil and smells toasted — this is the step that builds the sauce's depth. Pour in 1 litre of hot stock, return the meat with its juices, and simmer uncovered over low heat for 30–40 minutes, stirring often so the nut paste does not scorch. Add the pomegranate molasses and brown sugar; taste: the sauce should be tart-sweet and deeply savoury; continue to simmer over low heat for another 30–40 minutes, until the meat is fully tender, the sauce has darkened to almost black, and walnut oil rises to the surface. Adjust with salt, more molasses (for tartness) or sugar (to round it); serve over warm basmati rice, scattered with fresh pomegranate seeds."}},{"id":106,"origin":{"ja":"フィリピン","en":"Philippines","ro":"Filipine"},"name":{"ja":"カレカレ","en":"Kare-Kare","ro":"Kare-Kare"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["牛テール1.2kg、関節で切り分けたもの（または骨付き牛スネ）","無糖ピーナッツバター200g（または煎ったピーナッツ250gを挽いたもの）","アナトーシード（アチュエテ）大さじ2 — またはアナトーパウダー大さじ1","生米大さじ4、フライパンで乾煎りして挽いたもの","大きな玉ねぎ1個、みじん切り","にんにく6片、みじん切り","大きなナス1本、4等分に切ったもの","長いインゲン（シタオ）200g、7cm長さに切ったもの","大きなチンゲンサイ1株または200gのペチャイ、縦半分にしたもの","水（または牛骨スープ）1.5L","植物油60ml","塩 適量","バゴオン（フィリピンの発酵エビペースト）、添え用","蒸したご飯、添え用"],"en":["1.2kg oxtail, cut at the joints (or bone-in beef shank)","200g unsweetened peanut butter (or 250g roasted peanuts, ground)","2 tbsp annatto (achuete) seeds — or 1 tbsp annatto powder","4 tbsp raw rice, toasted in a dry pan and ground","1 large onion, finely chopped","6 garlic cloves, minced","1 large eggplant, cut into quarters","200g long green beans (sitaw), cut into 7 cm lengths","1 large bok choy or 200g pechay, halved lengthwise","1.5L water (or beef stock)","60ml vegetable oil","salt to taste","bagoong (Filipino shrimp paste), to serve","steamed rice, to serve"],"ro":["1,2kg coadă de vită, tăiată în bucăți la articulație (sau pulpă de vită cu os)","200g pastă de arahide neîndulcită (sau 250g arahide prăjite, măcinate)","2 linguri semințe de annatto (achiote) — sau 1 lingură pudră de annatto","4 linguri orez crud, prăjit într-o tigaie uscată și măcinat","1 ceapă mare, tocată fin","6 căței de usturoi, tocați","1 vânătă mare, tăiată sferturi","200g fasole verde lungă, tăiată în bucăți de 7 cm","1 bok choy mare sau 200g pak choi, tăiat pe lungime","1,5L apă (sau supă de vită)","60ml ulei vegetal","sare după gust","bagoong (pastă de creveți filipineză) pentru servit","orez fiert, pentru servit"]},"howIsMade":{"ja":"牛テールを大鍋に入れ、水1.5Lを加える、沸騰させたらアクを取り、5分茹でる、湯を切ってテールを洗い、澄んだスープにする。テールを鍋に戻し、新鮮な水（または牛骨スープ）1.5Lを加え、弱火で2.5〜3時間、肉が骨からほぐれ落ちる手前まで煮込む、肉を取り出し、スープ1Lを取り置く。アナトーシードを熱湯大さじ3に10分浸して、深い赤橙色の液体になるまで漉す（またはアナトーパウダーを直接溶く）。清潔な鍋に油60mlを熱する、玉ねぎを5分炒め、にんにくを加えてさらに1分炒める。ピーナッツバター、アナトー液、取り置きスープ1Lを加える、泡立て器でなめらかに混ぜる、5分煮込んでから、煎り米粉を加えると——ソースが目に見えてとろみがついてくる。肉をソースに戻し、弱火で10〜15分煮込む、とろみが強すぎたらスープで伸ばす、塩は控えめに——卓上のバゴオンが非常に塩辛いため。ナス、長インゲンを加えて5分煮る、上にチンゲンサイを乗せ、蓋をしてさらに3分、野菜が柔らかいが鮮やかな色を保つまで火を通す。深い器に入れ、蒸したご飯にかけて、小皿のバゴオンを添えて出す——各人が好みの量を混ぜ込む。","en":"Put the oxtail in a large pot with 1.5L water; bring to a boil, skim the foam, and boil for 5 minutes; drain and rinse the meat for a clear broth. Return the meat to the pot with 1.5L fresh water (or beef stock) and simmer gently for 2.5–3 hours, until the meat falls almost off the bone; lift out the meat and reserve 1L of the broth. Steep the annatto seeds in 3 tbsp hot water for 10 minutes, then strain to a deep red-orange liquid (or dissolve the annatto powder directly). In a clean pot, heat 60ml oil; sauté the onion for 5 minutes, add the garlic and cook 1 minute more. Stir in the peanut butter, annatto liquid, and 1L of the reserved broth; whisk to keep it smooth; simmer 5 minutes, then add the toasted ground rice — the sauce will begin to thicken visibly. Return the meat to the sauce and simmer over low heat for 10–15 minutes, loosening with more broth if it becomes too thick; season with salt (sparingly — the bagoong at the table is very salty). Add the eggplant quarters and long beans, simmer 5 minutes; lay the bok choy on top, cover, and cook for another 3 minutes, until the vegetables are tender but still vibrant. Serve in deep bowls over steamed rice, with bagoong in a small bowl alongside — each diner stirs in as much as they like."}},{"id":107,"origin":{"ja":"ポルトガル","en":"Portugal","ro":"Portugalia"},"name":{"ja":"フランセジーニャ","en":"Francesinha","ro":"Francesinha"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["白い食パン（厚切り）8枚","リブアイまたはサーロインステーキ400g、4枚に薄切りしたもの","リングイサ（または燻製ソーセージ）4本、縦半分","ハム8枚","辛味サラミまたはチョリソー8枚","チェダーまたはゴーダ（溶けるタイプ）12枚","卵4個、トッピング用","バター30g","卵焼き用の油","ソース用：","ラガービール400ml","ビーフストック200ml","トマトペースト200g","ウイスキーまたはブランデー60ml","小さな玉ねぎ1個、みじん切り","にんにく2片、みじん切り","ローリエ1枚","唐辛子フレーク小さじ1/2（またはピリピリ）","小麦粉大さじ1","塩・こしょう・砂糖 適量","フライドポテト、添え用"],"en":["8 thick slices white bread (sandwich loaf)","400g rib-eye or sirloin steak, cut into 4 thin slices","4 linguiça or smoked sausage links, halved lengthwise","8 slices cooked ham","8 slices spicy salami or chouriço","12 slices Cheddar or Gouda, melting type","4 eggs, for topping","30g butter","oil for frying eggs","For the sauce:","400ml lager beer","200ml beef stock","200g tomato paste","60ml whisky or brandy","1 small onion, finely chopped","2 garlic cloves, minced","1 bay leaf","1/2 tsp chili flakes (or piri-piri)","1 tbsp flour","salt, pepper, sugar to taste","fries, to serve"],"ro":["8 felii groase de pâine albă (tip toast)","400g antricot sau mușchi de vită, în 4 felii subțiri","4 cârnați linguiça (sau cabanos afumat), tăiați pe lungime","8 felii de șuncă (presunto) fiartă","8 felii salami picant (chouriço)","12 felii brânză cheddar sau Gouda topit","4 ouă (pentru deasupra)","30g unt","ulei pentru prăjit ouăle","Pentru sos:","400ml bere blondă","200ml bulion de vită","200g pastă de roșii","60ml whisky sau brandy","1 ceapă mică, tocată","2 căței de usturoi, tocați","1 frunză de dafin","1/2 linguriță fulgi de chili (sau piri-piri)","1 lingură făină","sare, piper, zahăr după gust","cartofi prăjiți, pentru servit"]},"howIsMade":{"ja":"ソースから作る：鍋でバター大さじ1を熱し、玉ねぎを5分炒め、にんにくと小麦粉大さじ1を加えて1分炒める、トマトペーストを加え2分炒める。ビールとウイスキーを注ぎ、アルコールを飛ばすため2分煮立てる、ビーフストック、ローリエ、唐辛子フレーク、塩と砂糖をひとつまみ加える、弱火で25〜30分、ソースがとろみがついてつやが出るまで煮込む、なめらかな仕上がりにするため漉す。ステーキを塩こしょうで下味付け、残りのバターをフライパンで溶かし、片面1.5分ずつ焼いて表面に色をつける、取り出す。同じフライパンでリングイサを片面2〜3分焼き色をつける。サンドイッチ1個につき、食パン2枚をバターまたは油で両面1分ずつ焼く、重ねる：パン1枚、ハム2枚、ステーキ1枚、サラミ2枚、リングイサ半分2つ、もう1枚のパン、軽く押さえる。サンドイッチを油を塗った耐熱皿に並べる、各サンドイッチにチーズを3枚乗せ、220°Cのグリルで3〜4分、チーズが溶けて泡立ち、所々色づくまで焼く。サンドイッチ1個につき卵1個を油で目玉焼きにし、黄身は半熟に。深皿にサンドイッチを置き、チーズの上に目玉焼きを乗せ、熱いソースをサンドイッチの周囲にたっぷり注ぐ——皿の底に溜まる量、フライドポテトを添えてすぐに出す。","en":"Make the sauce first: heat 1 tbsp of the butter in a saucepan, sauté the onion for 5 minutes, add the garlic and 1 tbsp flour, cook for 1 minute; stir in the tomato paste and cook for 2 minutes. Pour in the beer and whisky, simmer 2 minutes to burn off the alcohol; add the beef stock, bay leaf, chili flakes, a pinch each of salt and sugar; simmer over low heat for 25–30 minutes, until the sauce is thick and glossy; strain for a smooth finish. Season the steak slices with salt and pepper; melt the remaining butter in a frying pan and sear the steak for 1.5 minutes per side, until browned; lift out. In the same pan, fry the linguiça halves for 2–3 minutes per side, until coloured. For each sandwich, toast 2 slices of bread in butter or oil on both sides (1 minute per side); layer: 1 slice bread, 2 slices ham, 1 slice steak, 2 slices salami, 2 linguiça halves, top with second slice of bread; press gently. Place the sandwiches in a greased baking dish; cover each with 3 slices of cheese and slide under a grill at 220°C for 3–4 minutes, until the cheese melts, bubbles and browns in spots. Fry 1 egg per sandwich in oil, leaving the yolk runny. Set each sandwich in a deep plate, place a fried egg on top of the cheese, and pour the hot sauce generously around the sandwich — it should pool at the base of the plate; serve immediately with fries on the side."}},{"id":109,"origin":{"ja":"ペルー","en":"Peru","ro":"Peru"},"name":{"ja":"チャウファご飯","en":"Arroz Chaufa","ro":"Arroz Chaufa"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"ja":["長粒米500g、炊いて冷ましたもの（できれば前日のもの）","鶏むね肉または豚ロース300g、1.5cm角に切ったもの","大きな卵3個、溶きほぐしたもの","赤パプリカ1個、細かい角切り","青ねぎ6本、白い部分はみじん切り、緑の部分は取り置き","にんにく3片、みじん切り","新鮮な生姜20g、みじん切り","醤油60ml","オイスターソース大さじ1","焙煎ごま油大さじ1","クセのない植物油60ml","アヒアマリージョペースト小さじ1（または唐辛子粉小さじ1/2）","塩・白こしょう 適量"],"en":["500g long-grain rice, cooked and cooled (preferably day-old)","300g chicken breast or pork loin, cut into 1.5 cm cubes","3 large eggs, beaten","1 red bell pepper, finely diced","6 spring onions, white parts finely sliced, green parts reserved","3 garlic cloves, minced","20g fresh ginger, finely minced","60ml soy sauce","1 tbsp oyster sauce","1 tbsp toasted sesame oil","60ml neutral vegetable oil","1 tsp ají amarillo paste (or 1/2 tsp chili powder)","salt and white pepper to taste"],"ro":["500g orez cu bob lung fiert și răcit (preferabil de o zi)","300g piept de pui sau pulpă de porc, tăiat cuburi de 1,5 cm","3 ouă mari, bătute","1 ardei kapia roșu, tăiat cuburi mici","6 cepe verzi, partea albă tăiată fin, verdele păstrat","3 căței de usturoi, tocați","20g ghimbir proaspăt, tocat fin","60ml sos de soia","1 lingură sos de stridii","1 lingură ulei de susan","60ml ulei vegetal neutru","1 linguriță aji amarillo pastă (sau 1/2 linguriță pudră de chili)","sare și piper alb după gust"]},"howIsMade":{"ja":"卵に塩ひとつまみを加えて溶く、中火で中華鍋に油大さじ1を熱し、卵を流し入れ、混ぜながら素早く薄焼き卵にする、皿に取り出して角切りにし、取り置く。鍋をしっかり熱したまま、油大さじ1を追加、塩ひとつまみを振った肉を3〜4分炒め、縁が色づき中まで火が通るまで、卵の皿に取り出す。残りの植物油を鍋に注ぎ、軽く煙が立つまで熱する、にんにく、生姜、パプリカを加え、香りが立つまで30秒炒める。青ねぎの白い部分とアヒアマリージョペーストを加える、30秒炒めて油に香りを移す。冷たいご飯を加える、へらで小さく切り分け、3〜4分の間に何度か鍋底に押しつけてはひっくり返す、米粒が一粒一粒分かれ、わずかなジューッという音が聞こえるまで。醤油とオイスターソースをご飯にかけ、1分炒めて全体に色をなじませる、肉と卵を鍋に戻す。火を止める、ごま油を回しかけ、青ねぎの緑の部分を加える、白こしょうで味を調える、中華鍋から直接、熱々のうちにすぐに供する。","en":"Beat the eggs with a pinch of salt; heat 1 tbsp of vegetable oil in a wok over medium heat, pour in the eggs, and quickly make a thin omelette by stirring; tip onto a plate and cut into small cubes; set aside. With the wok very hot, add another 1 tbsp oil; stir-fry the meat with a pinch of salt for 3–4 minutes, until browned at the edges and cooked through; move to the plate with the eggs. Pour the remaining vegetable oil into the wok and heat until it just begins to smoke; add the garlic, ginger, and bell pepper, and stir-fry for 30 seconds, until fragrant. Add the white parts of the spring onions and the ají amarillo paste; stir-fry for 30 seconds, letting the flavours infuse the oil. Add the cold rice; use a spatula to break it into small pieces, pressing it against the bottom of the wok between tosses for 3–4 minutes, until every grain is separate and you hear a slight sizzle. Pour the soy sauce and oyster sauce over the rice, tossing for 1 minute to distribute evenly and pick up colour; return the meat and egg to the wok. Turn off the heat; drizzle with the sesame oil and add the green parts of the spring onions; season with white pepper; serve immediately, hot, straight from the wok."}},{"id":110,"origin":{"ja":"シンガポール","en":"Singapore","ro":"Singapore"},"name":{"ja":"チリクラブ","en":"Chili Crab","ro":"Chili Crab"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ja":["生きたマッドクラブ2匹（合計1.5kg）、掃除して関節で半分に切ったもの","トマトペースト大さじ4","サンバル・オラック大さじ3（またはチリペースト）","スイートチリソース大さじ2","ケチャップ60ml","新鮮な生姜30g、すりおろしたもの","にんにく6片、みじん切り","大きな卵2個、溶きほぐしたもの","青ねぎ3本、刻んだもの","米酢大さじ1","砂糖小さじ2","塩小さじ1","鶏ガラスープ500ml（または水）","植物油60ml","コーンスターチ大さじ1を水大さじ2で溶いたもの","揚げ饅頭（中華風蒸しパン）、添え用"],"en":["2 live mud crabs (1.5kg total), cleaned and halved at the joints","4 tbsp tomato paste","3 tbsp sambal oelek (or chili paste)","2 tbsp sweet chili sauce","60ml ketchup","30g fresh ginger, grated","6 garlic cloves, minced","2 large eggs, beaten","3 spring onions, chopped","1 tbsp rice vinegar","2 tsp sugar","1 tsp salt","500ml chicken stock (or water)","60ml vegetable oil","1 tbsp cornstarch mixed with 2 tbsp water","fried mantou (Chinese buns), to serve"],"ro":["2 crabi de noroi vii (1,5kg în total), curățați și tăiați în jumătăți la articulații","4 linguri pastă de roșii","3 linguri sos sambal oelek (sau pastă de chili)","2 linguri sos dulce de chili","60ml ketchup","30g ghimbir proaspăt, ras","6 căței de usturoi, tocați","2 ouă mari, bătute","3 cepe verzi, tocate","1 lingură oțet de orez","2 lingurițe zahăr","1 linguriță sare","500ml supă de pui (sau apă)","60ml ulei vegetal","1 lingură amidon de porumb amestecat cu 2 linguri apă","mantou prăjit (chifle chinezești), pentru servit"]},"howIsMade":{"ja":"カニを冷凍庫に30分入れて優しく麻痺させる、掃除して、上の甲羅を外し、内側のやわらかい内臓を取り除き、関節でカニを半分に切る、包丁の背でハサミを叩いて割り、味が染み込むようにする。小さなボウルで卵を溶く、別のボウルでトマトペースト、サンバル、スイートチリソース、ケチャップ、米酢、砂糖、塩を混ぜる——これがソースのベース。大きな中華鍋または深鍋に油60mlを強火で熱する、カニの切り身を入れて3〜4分炒め、甲羅が赤くなるまで返す、皿に取り出す。同じ油でおろし生姜とにんにくを30秒、強い香りが立つまで炒める。トマトのソースベースと鶏ガラスープ500mlを注ぐ、沸騰させ、辛さの好みでサンバルを追加。カニを鍋に戻し、蓋をして8〜10分煮込む、途中で一度返し、身が完全に火が通り柔らかくなるまで。水溶きコーンスターチを細い線で加え、混ぜながらソースをとろみと艶のある仕上がりにする、溶き卵を鍋の周囲に螺旋状に流し入れ、混ぜずに30秒置くと絹のようなリボン状になる、1度だけ折りたたむ。刻んだ青ねぎを散らす、すぐに大皿に盛り付け、揚げ饅頭を添えてソースを浸して食べる。","en":"Place the crabs in the freezer for 30 minutes to humanely stun them; clean them, lift off the top shell, remove the soft inner organs, and chop the crab in half at the joints; crack the claws with the back of a knife so the flavour penetrates. Beat the eggs in a small bowl; in another bowl, stir together the tomato paste, sambal, sweet chili sauce, ketchup, vinegar, sugar and salt — this is the sauce base. Heat 60ml of oil in a large wok or deep pot over high heat; add the crab pieces and stir-fry for 3–4 minutes, turning, until the shells turn red; lift onto a plate. In the same oil, sauté the grated ginger and garlic for 30 seconds, until very fragrant. Pour in the tomato-paste mixture and 500ml chicken stock; bring to a boil, adjust with more sambal for more heat. Return the crab pieces, cover the wok and simmer for 8–10 minutes, turning once halfway, until the meat is fully cooked and tender. Stir the cornstarch slurry into the sauce in a thin stream so the sauce thickens to a glossy coat; pour the beaten eggs around the wok in a spiral without stirring — they will set as silky ribbons; wait 30 seconds, then fold once. Scatter with the chopped spring onions; serve immediately on a large platter with fried mantou alongside to soak up the sauce."}},{"id":111,"origin":{"ja":"メキシコ","en":"Mexico","ro":"Mexic"},"name":{"ja":"タマーレ","en":"Tamale","ro":"Tamale"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"mexican","ingredients":{"ja":["乾燥トウモロコシの皮20〜24枚","マサ・ハリナ（ニクスタマル化したトウモロコシ粉）500g","豚ラード250g、室温に戻したもの","温かい鶏ガラスープ500ml","ベーキングパウダー大さじ1","塩小さじ2","具用：","骨なし豚肩肉500g、煮込んでほぐしたもの","乾燥グアヒージョ唐辛子4本、ヘタと種を除く","乾燥アンチョ唐辛子2本、ヘタと種を除く","小さな玉ねぎ1個、4等分","にんにく3片","クミンパウダー小さじ1","メキシカンオレガノ小さじ1","植物油大さじ2","塩 適量","赤または緑のサルサ、添え用"],"en":["20–24 dried corn husks","500g masa harina (nixtamalized corn flour)","250g pork lard, at room temperature","500ml warm chicken stock","1 tbsp baking powder","2 tsp salt","For the filling:","500g boneless pork shoulder, simmered and shredded","4 dried guajillo chilies, stems and seeds removed","2 dried ancho chilies, stems and seeds removed","1 small onion, quartered","3 garlic cloves","1 tsp ground cumin","1 tsp Mexican oregano","2 tbsp vegetable oil","salt to taste","red or green salsa, to serve"],"ro":["20–24 foi de porumb uscate (chiote)","500g masa harina (făină de porumb nixtamalizată)","250g untură de porc, la temperatura camerei","500ml supă de pui caldă","1 lingură praf de copt","2 lingurițe sare","Pentru umplutură:","500g pulpă de porc dezosată, fiartă și mărunțită","4 ardei iuți guajillo uscați, fără semințe","2 ardei iuți ancho uscați, fără semințe","1 ceapă mică, tăiată sferturi","3 căței de usturoi","1 linguriță chimion măcinat","1 linguriță oregano mexican","2 linguri ulei vegetal","sare după gust","salsă roșie sau verde, pentru servit"]},"howIsMade":{"ja":"トウモロコシの皮をぬるま湯に30分浸し、しなやかにする、浮かないよう皿で押さえる。ソースを作る：グアヒージョとアンチョ唐辛子を乾いたフライパンで片面1分ずつ、香りが立つまで焼く、熱湯に15分浸す、戻した唐辛子と玉ねぎ、にんにく、クミン、オレガノ、戻し汁250mlをミキサーにかける、ソースを濾す。フライパンに油大さじ2を熱し、唐辛子ソースを入れて8〜10分、とろみがつくまで煮る、ほぐした豚肉を加え、塩で味を調え、さらに5分煮る、冷ます。ハンドミキサーでラードを3分泡立て、ふわふわで色が薄くなるまで、ベーキングパウダーと塩を加え、30秒さらに混ぜる。マサ・ハリナと温かいスープを交互に加え、絶えず泡立てる、生地は軽くふんわりとし、スパチュラに絡む状態に、小さく丸めて冷水に落とすと浮くのが目安。皮の水を切る、各タマーレに、皮の上に生地を大さじ3薄く広げ、両側2cm・上5cmを残す、中央に具を大さじ2乗せる。皮の両側を具の上に折り、細い側を上に折り上げる、上は開けたまま、開口を上にして蒸し器に立てる。60〜75分蒸し、開けた時に生地が皮から綺麗に剥がれれば出来上がり、10分休ませてから供する、赤または緑のサルサを添えて温かいうちに供する。","en":"Soak the corn husks in warm water for 30 minutes, until pliable; weight them down with a plate so they stay submerged. Make the sauce: toast the guajillo and ancho chilies in a dry pan for 1 minute per side, until fragrant; cover with hot water for 15 minutes; blend the rehydrated chilies with the onion, garlic, cumin, oregano and 250ml of the soaking liquid; strain the sauce. Heat 2 tbsp oil in a pan, pour in the chili sauce and simmer for 8–10 minutes, until thickened; add the shredded pork, season with salt and cook another 5 minutes; let it cool. Beat the lard with a mixer for 3 minutes, until fluffy and pale; add the baking powder and salt, mix 30 seconds more. Add the masa harina alternately with warm chicken stock, beating continuously; the dough should be light, fluffy, and cling to the spatula; test by dropping a small ball into cold water — it should float. Drain the corn husks; for each tamale, spread 3 tbsp of dough in a thin layer on a husk, leaving a 2 cm border on the sides and 5 cm at the top; place 2 tbsp filling down the centre. Fold the sides of the husk over the filling, then fold the narrow end up, leaving the top open; stand the tamales vertically in a steamer basket, open ends up. Steam for 60–75 minutes, until the dough peels cleanly away from the husk when you open one; let them rest 10 minutes before serving; serve warm with red or green salsa alongside."}},{"id":112,"origin":{"ja":"タイ","en":"Thailand","ro":"Thailanda"},"name":{"ja":"トムヤム","en":"Tom Yum","ro":"Tom Yum"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"thai","ingredients":{"ja":["鶏がらまたは海鮮スープ1L","生エビ300g（殻と背ワタを取る）","レモングラス2本（3cmに切って潰す）","ガランガル（またはしょうが）30g（薄切り）","コブミカンの葉6枚","タイの赤唐辛子3〜4本（半分に切る）","エリンギまたはマッシュルーム200g（スライス）","ナンプラー大さじ3","新鮮なライム果汁大さじ2","パームシュガー大さじ1","トムヤムペースト大さじ2（任意）","ねぎ1本（飾り用）","パクチー（盛り付け用）"],"en":["1L chicken or seafood stock","300g raw prawns, peeled and deveined","2 stalks lemongrass, cut into 3cm pieces and bruised","30g galangal (or ginger), thinly sliced","6 kaffir lime leaves","3–4 Thai red chillies, halved","200g oyster or button mushrooms, sliced","3 tbsp fish sauce","2 tbsp fresh lime juice","1 tbsp palm sugar","2 tbsp tom yum paste (optional)","1 spring onion stalk, to garnish","Fresh coriander to serve"],"ro":["1 L supă de pui sau stoc de fructe de mare","300g creveți cruzi, curățați","2 tulpini lemongrass, secționate în bucăți de 3 cm și zdrobite","30g galangal (sau ghimbir), felii subțiri","6 frunze de kaffir lime","3–4 ardei iuți roșii thailandezi, tăiați pe jumătate","200g ciuperci pleurotus sau champignon, feliate","3 linguri sos de pește","2 linguri suc proaspăt de lime","1 lingură zahăr de palmier","2 linguri pastă tom yum (opțional)","1 tulpină ceapă verde, pentru servire","Coriandru proaspăt, pentru servire"]},"howIsMade":{"ja":"大鍋に1Lのストックを入れて静かに煮立てる。潰したレモングラスの茎、ガランガルの薄切り、コブミカンの葉を加える、10分弱火で煮込み、香り高く仕上げる。トムヤムペースト（使う場合）、半分に切った唐辛子、スライスしたきのこを加える、きのこが少し柔らかくなるまで3〜4分煮る。エビを加え、ちょうど2〜3分煮る — ピンク色になりカールするまで、煮すぎると硬くなる。鍋を火から外す、ナンプラー大さじ3、新鮮なライム果汁大さじ2、パームシュガー大さじ1を加える。味見してバランスを整える：酸味・塩気・辛味・ほのかな甘みが同時に感じられる状態に、酸味が足りなければライム、塩気が足りなければナンプラーを足す。すぐに深い器に盛り、ねぎとパクチーを散らす、レモングラス・ガランガル・ライムの葉は香り出しで、食べない。","en":"Bring 1L of stock to a gentle simmer in a large pot. Add the bruised lemongrass stalks, sliced galangal, and kaffir lime leaves; simmer for 10 minutes to infuse the aromatics and turn the broth deeply fragrant. Stir in the tom yum paste (if using), halved chillies, and sliced mushrooms; cook for 3–4 minutes, until the mushrooms soften slightly. Add the prawns and cook for exactly 2–3 minutes — they should turn pink and curl; do not overcook or they will become rubbery. Take the pot off the heat; stir in 3 tbsp fish sauce, 2 tbsp fresh lime juice, and 1 tbsp palm sugar. Taste and adjust the balance: the soup should be sour, salty, spicy, and lightly sweet all at once; add more lime for sharpness or more fish sauce for salt. Serve immediately in deep bowls, scattered with spring onion and fresh coriander; the lemongrass, galangal, and lime leaves are aromatics and are not meant to be eaten."}},{"id":113,"origin":{"ja":"アルゼンチン","en":"Argentina","ro":"Argentina"},"name":{"ja":"ミラネサ","en":"Milanesa","ro":"Milanesa"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"ja":["薄切り牛肉4枚（うちもも肉またはサーロイン）、各約150g","大きな卵2個","にんにく2片、みじん切り","新鮮なパセリ20g、みじん切り","乾燥パン粉150g（軽い衣にしたいならパンコ）","薄力粉100g","塩小さじ1","挽きたての黒胡椒小さじ1/2","揚げ油用の植物油500ml","レモン1個、くし形切り、添え用"],"en":["4 thin beef steaks (top round or sirloin), about 150g each","2 large eggs","2 garlic cloves, finely minced","20g fresh parsley, finely chopped","150g dried breadcrumbs (panko works for a lighter crust)","100g plain flour","1 tsp salt","1/2 tsp freshly ground black pepper","500ml vegetable oil, for frying","1 lemon, cut into wedges, to serve"],"ro":["4 felii subțiri de vită (vrăbioară sau pulpă), aproximativ 150g fiecare","2 ouă mari","2 căței de usturoi, tocați fin","20g pătrunjel proaspăt, tocat","150g pesmet uscat (eventual panko pentru o crustă mai aerată)","100g făină simplă","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","500ml ulei vegetal, pentru prăjit","1 lămâie, tăiată felii, pentru servit"]},"howIsMade":{"ja":"牛肉のスライスをラップ2枚の間に挟み、肉叩きで5mmの厚さに叩く、塩こしょうの半量を両面に振る。浅いボウルに卵を割り入れ、にんにくのみじん切り、パセリ、残りの塩こしょうを加えて混ぜる。浅い皿を2つ用意：1つに小麦粉、もう1つにパン粉、衣の順番：小麦粉 → 溶き卵 → パン粉。各スライスを小麦粉にまぶし余分を払い、卵液にくぐらせ（2秒水を切る）、パン粉に両面を押し付ける、パン粉が肉を完全に覆うように。衣をつけた肉を網の上で10分休ませる——衣の付きが良くなる。大きなフライパンに1cmの油を入れて175°Cに熱する（温度計、またはパン1かけで30秒で色がつくか確認）。1〜2枚ずつ片面2分ずつ揚げ、衣が深いきつね色になり中が柔らかくなるまで、ペーパーではなくバットに乗せた網で油を切る（紙だと衣が湿る）。すぐにレモンのくし切りを添えて提供——食べる直前に衣の上に絞る。","en":"Place the beef slices between two sheets of cling film; pound with a meat mallet until 5 mm thick; season with half the salt and pepper on both sides. Beat the eggs in a wide shallow bowl with the minced garlic, parsley, and the remaining salt and pepper. Set up two shallow plates: one with the flour, one with the breadcrumbs; breading line: flour → beaten egg → breadcrumbs. Dip each slice in flour, shaking off the excess, then in the egg mixture (let it drip for 2 seconds), then press into the breadcrumbs on both sides; the crumbs should fully coat the meat. Let the breaded slices rest on a wire rack for 10 minutes — the breading adheres better this way. Heat 1 cm of oil in a large frying pan to 175°C (use a thermometer or test with a bread cube — it should brown in 30 seconds). Fry the slices one or two at a time for 2 minutes per side, until the crust is deep golden and the meat is tender; drain on a rack over a tray (not on paper — it steams the crust). Serve immediately with lemon wedges to squeeze over the crust just before eating."}},{"id":114,"origin":{"ja":"カンボジア","en":"Cambodia","ro":"Cambodgia"},"name":{"ja":"ロックラック","en":"Lok Lak","ro":"Lok Lak"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"vietnamese","ingredients":{"ja":["牛フィレまたはサーロイン600g、2.5cm角に切ったもの","オイスターソース大さじ3","醤油大さじ2","パームシュガー大さじ1（または黒糖）","トマトペースト大さじ1","にんにく6片、みじん切り","挽きたての黒胡椒小さじ2（たっぷり）","植物油大さじ3","大きな玉ねぎ1個、薄切り","卵4個（目玉焼き用）","小ぶりのレタス1個（アイスバーグまたはロメイン）、葉をはがす","トマト2個、薄切り","きゅうり1本、薄切り","ディップソース用：","ライム2個の絞り汁","粗塩小さじ1","挽きたての黒胡椒小さじ1/2","蒸したご飯、添え用"],"en":["600g beef tenderloin or sirloin, cut into 2.5 cm cubes","3 tbsp oyster sauce","2 tbsp soy sauce","1 tbsp palm sugar (or brown sugar)","1 tbsp tomato paste","6 garlic cloves, minced","2 tsp freshly ground black pepper (generous)","3 tbsp vegetable oil","1 large onion, thinly sliced","4 eggs (for frying)","1 small head of lettuce (iceberg or romaine), leaves separated","2 tomatoes, sliced","1 cucumber, sliced","For the dipping sauce:","juice of 2 limes","1 tsp coarse salt","1/2 tsp freshly ground black pepper","steamed rice, to serve"],"ro":["600g vrăbioară sau mușchi de vită, tăiată cuburi de 2,5 cm","3 linguri sos de stridii","2 linguri sos de soia","1 lingură zahăr de palmier (sau zahăr brun)","1 lingură pastă de roșii","6 căței de usturoi, tocați","2 lingurițe piper negru proaspăt măcinat (din belșug)","3 linguri ulei vegetal","1 ceapă mare, tăiată felii subțiri","4 ouă (pentru ochiuri)","1 cap mic de salată verde (iceberg sau romană), frunzele separate","2 roșii, feliate","1 castravete, feliat","Pentru sos:","zeama de la 2 lime","1 linguriță sare grunjoasă","1/2 linguriță piper negru proaspăt măcinat","orez fiert, pentru servit"]},"howIsMade":{"ja":"ボウルに牛肉、オイスターソース、醤油、パームシュガー、トマトペースト、にんにくの半量、黒コショウ小さじ1を入れて和える、常温で30分マリネする。ディップソースを作る：小皿にライム果汁、粗塩、残りの黒コショウを入れて混ぜる。大皿にレタスの葉、トマトのスライス、きゅうりのスライスを盛り付ける。フライパンに少量の油を熱し、卵4個を半熟の目玉焼きにする、温かい皿に取り置く。大きな中華鍋に油大さじ3を強火で熱し、軽く煙が立つまで加熱。玉ねぎと残りのにんにくを加え、香りが立つまで30秒炒める。マリネした牛肉を一段に並べて入れる、1分間触らず焼き目をつけ、その後2分間勢いよく炒める、牛肉は外側はこんがり、中はピンク色を保つように——焼きすぎない。熱々の牛肉をサラダの上に乗せ、各ポーションに目玉焼き1個を添える、ライムのディップソースと、各客にご飯をすぐに添えて出す。","en":"In a bowl, combine the beef with oyster sauce, soy sauce, palm sugar, tomato paste, half the garlic, and 1 tsp black pepper; let it marinate at room temperature for 30 minutes. Make the dipping sauce: stir lime juice, coarse salt, and the remaining pepper in a small bowl; set aside. Arrange the serving platter: lettuce leaves, tomato slices, and cucumber slices laid out on a large platter. Fry 4 eggs in a pan with a little oil, leaving the yolks runny; set them aside on a warm plate. Heat 3 tbsp oil in a large wok over very high heat until it just begins to smoke. Add the sliced onion and remaining garlic, stir-fry for 30 seconds, until fragrant. Add the marinated beef in a single layer; leave it untouched for 1 minute to sear, then stir-fry vigorously for 2 more minutes; the beef should be charred outside and pink inside — do not overcook. Spoon the hot beef over the salad platter, place a fried egg on each portion; serve immediately with the lime dipping sauce alongside and steamed rice for each diner."}},{"id":115,"origin":{"ja":"ウズベキスタン","en":"Uzbekistan","ro":"Uzbekistan"},"name":{"ja":"マンティ","en":"Manti","ro":"Manti"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["生地用：","中力粉500g","ぬるま湯250ml","卵1個","塩小さじ1","具用：","包丁で粗く刻んだ牛肉または羊肉600g（ひき肉ではなく）","大きな玉ねぎ3個、みじん切り（玉ねぎと肉の体積比1:1が必須）","クミンパウダー小さじ1","挽きたての黒胡椒小さじ1","塩小さじ2","羊の尾脂またはラルドの極小角切り100g（任意・伝統的）","盛り付け用：","バター100g","全脂肪ヨーグルト200g（またはサワークリーム）","甘いパプリカパウダー大さじ1","新鮮なコリアンダーまたはパセリ、刻んだもの"],"en":["For the dough:","500g all-purpose flour","250ml warm water","1 egg","1 tsp salt","For the filling:","600g coarsely chopped beef or lamb (knife-cut, not ground)","3 large onions, finely chopped (use a 1:1 onion-to-meat ratio by volume — essential)","1 tsp ground cumin","1 tsp freshly ground black pepper","2 tsp salt","100g lamb-tail fat or pork lardons in tiny cubes (optional, traditional)","To serve:","100g butter","200g full-fat yogurt (or sour cream)","1 tbsp sweet paprika","fresh coriander or parsley leaves, chopped"],"ro":["Pentru aluat:","500g făină","250ml apă caldă","1 ou","1 linguriță sare","Pentru umplutură:","600g carne tocată grosier de vită sau miel","3 cepe mari, tăiate fin (foarte importantă proporția 1:1 cu carnea după volum)","1 linguriță chimion măcinat","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare","100g grăsime de coadă de oaie sau slănină tăiată cuburi mici (opțional, dar tradițional)","Pentru servit:","100g unt","200g iaurt gras (sau smântână)","1 lingură boia dulce","frunze de coriandru sau pătrunjel proaspăt, tocate"]},"howIsMade":{"ja":"生地を作る：大きなボウルに小麦粉と塩を入れて混ぜる、卵をぬるま湯と一緒に溶き、小麦粉に加える、10分こねて滑らかで弾力のある生地にする、ラップで覆い30分休ませる。具を作る：包丁切りの肉、玉ねぎ、クミン、塩、こしょう、羊の尾脂（使う場合）を混ぜる、手で均一になるまで混ぜる、玉ねぎから水分が出る — 混ぜ込んだままにする。生地を4等分、それぞれをできるだけ薄く（1〜2mm）伸ばす、10x10cmの正方形に切る。各正方形の中心に大さじ1杯強の具を置く、生地の四隅を具の上に持ち上げ、上部でつまんで閉じ、その後四辺をつまんで密封したパッケージにする。蒸し器のバスケットに油を塗る、マンティを互いに触れないよう一段に並べる（蒸すと膨らむ）。中火で35〜40分、水が常に沸騰している状態で蒸す、生地が半透明でわずかに艶が出てくれば完成。小さな鍋でバターを溶かし、甘いパプリカパウダーを混ぜる、火から外して1分置く。大皿にマンティを並べ、刻んだパセリを散らし、パプリカバターを上からかける、小皿のヨーグルトを添えて出す。","en":"Make the dough: in a large bowl, combine the flour with salt; beat the egg with warm water and pour over the flour; knead for 10 minutes until smooth and elastic; cover with cling film and rest for 30 minutes. Make the filling: combine the knife-cut meat, onions, cumin, salt, pepper, and lamb-tail fat (if using); mix by hand until uniform; the onions will release liquid — keep it in. Divide the dough into 4 pieces; roll each as thin as possible (1–2 mm); cut into 10x10 cm squares. Place a generous tablespoon of filling in the centre of each square; lift the four corners of the dough up over the filling and pinch them together at the top, then pinch the four side edges closed to form a sealed parcel. Brush a steamer basket with oil; arrange the manti in a single layer, not touching (they will swell as they cook). Steam for 35–40 minutes over medium heat with the water at a steady boil; the dough should become translucent and slightly glossy when done. Melt the butter in a small saucepan, stir in the sweet paprika; let it rest 1 minute off the heat. Arrange the manti on a large platter, scatter with chopped parsley, and spoon the paprika butter over the top; serve with yogurt in a small bowl alongside."}},{"id":116,"origin":{"ja":"ジョージア","en":"Georgia","ro":"Georgia"},"name":{"ja":"チャホフビリ","en":"Chakhokhbili","ro":"Chakhokhbili"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["骨付き鶏もも肉とドラムスティック1.2kg","大きな玉ねぎ4個（約600g）、薄切り — 玉ねぎと鶏肉の重量比1:1が伝統的","完熟トマト6個（約700g）、皮を剥いてざく切り","赤パプリカ1個、種を除いて角切り","にんにく6片、みじん切り","トマトペースト大さじ2","クメリ・スネリ小さじ1（ジョージアのスパイスミックス）","粉末ブルーフェヌグリーク小さじ1/2（ウツホ・スネリ）","ドライセイボリーまたはマジョラム小さじ1","新鮮なコリアンダー30g、葉と茎を分けて、両方刻む","新鮮なパセリ20g、刻んだもの","塩小さじ1","挽きたての黒胡椒","白ワインビネガー大さじ1（任意、爽やかさのため）","ジョージアのフラットブレッドや素朴なパン、添え用"],"en":["1.2kg bone-in chicken thighs and drumsticks","4 large onions (about 600g), thinly sliced — a 1:1 onion-to-chicken ratio by weight is traditional","6 ripe tomatoes (about 700g), peeled and roughly chopped","1 red bell pepper, deseeded and diced","6 garlic cloves, minced","2 tbsp tomato paste","1 tsp khmeli-suneli (Georgian spice blend)","1/2 tsp ground blue fenugreek (utskho suneli)","1 tsp dried savory or marjoram","30g fresh coriander, leaves and stems separated, both chopped","20g fresh parsley, chopped","1 tsp salt","freshly ground black pepper","1 tbsp white wine vinegar (optional, for brightness)","Georgian flatbread or any sturdy bread, to serve"],"ro":["1,2kg pulpe de pui cu os (pulpe superioare și ciocănele)","4 cepe mari (aproximativ 600g), feliate subțire — raportul 1:1 ceapă:pui după greutate este tradițional","6 roșii coapte (aproximativ 700g), decojite și tăiate grosier","1 ardei kapia roșu, fără semințe, tăiat cuburi","6 căței de usturoi, tocați","2 linguri pastă de roșii","1 linguriță khmeli-suneli (amestec de condimente georgian)","1/2 linguriță schinduf albastru măcinat (utskho suneli)","1 linguriță cimbru de iarnă uscat (sau maghiran)","30g coriandru proaspăt, frunze și tulpini separate, ambele tocate","20g pătrunjel proaspăt, tocat","1 linguriță sare","piper negru proaspăt măcinat","1 lingură oțet de vin alb (opțional, pentru prospețime)","pâine georgiană sau alt tip de pâine rustică, pentru servit"]},"howIsMade":{"ja":"厚手の鍋を中強火で乾燥状態に温める——油は入れない、鶏肉を皮目を下にして並べ、片面6〜8分ずつ、深いきつね色になるまで焼く、鶏自身の脂が出る——これがチャホフビリを定義する乾煎り工程。鶏肉を皿に取り出す、鍋には大さじ3〜4の脂が残るはず——そのまま使う。スライス玉ねぎを鍋に入れる、中火で12〜15分、頻繁に混ぜながら、深いきつね色で柔らかくなるまで炒める。パプリカ、にんにくの半量、刻んだコリアンダーの茎、クメリ・スネリ、ブルーフェヌグリーク、セイボリーを加える、香りが立つまで2分炒める。トマトペーストを加えて2分炒め、色が濃くなるまで、刻んだトマトを加え、鶏肉を肉汁ごと鍋に戻す。火を弱め、蓋をして35〜45分煮込み、途中で1度鶏肉を返す、鶏肉が骨から離れそうになり、トマトが濃厚で艶のあるソースになる。蓋を取り、ソースをさらに濃縮させたければ5分蓋を開けて煮る、残りのにんにく、酢（使う場合）、刻んだコリアンダーとパセリの大部分を加える。味見をして塩こしょうで調える、熱いうちに浅い器に盛り、ジョージアのフラットブレッド（または素朴なパン）をソースに浸して食べる、残りのハーブを散らす。","en":"Heat a heavy dry pot over medium-high heat — no oil; lay the chicken pieces skin-side down and cook for 6–8 minutes per side, until deeply golden; the chicken renders its own fat — this is the dry-brown step that defines chakhokhbili. Lift the chicken onto a plate; the pot should hold 3–4 tbsp of rendered fat — keep it. Add the sliced onions to the rendered fat; cook over medium heat for 12–15 minutes, stirring often, until deeply golden and soft. Stir in the bell pepper, half the garlic, the chopped coriander stems, khmeli-suneli, blue fenugreek, and savory; cook 2 minutes, until fragrant. Add the tomato paste and cook 2 more minutes, until it darkens; add the chopped tomatoes and return the chicken with its juices to the pot. Reduce the heat to low, cover, and braise for 35–45 minutes, turning the chicken once halfway; the chicken should be falling off the bone and the tomatoes broken down into a thick, glossy sauce. Lift the lid and simmer uncovered 5 more minutes to thicken the sauce if needed; stir in the remaining garlic, the vinegar (if using), and most of the chopped coriander leaves and parsley. Taste, adjust salt and pepper; serve hot in shallow bowls with Georgian flatbread (or any sturdy bread) to mop up the sauce; scatter the remaining herbs on top."}},{"id":117,"origin":{"ja":"ペルー","en":"Peru","ro":"Peru"},"name":{"ja":"ロモ・サルタード","en":"Lomo Saltado","ro":"Lomo Saltado"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"ja":["牛サーロインまたはフィレ600g、1cm幅の細切り","大きなジャガイモ3個（約700g）、太めのフライドポテト用に切ったもの","大きな赤玉ねぎ1個、1cm幅のくし切り","中サイズのローマトマト2個、くし切り（または厚めの輪切り）","黄色のアヒアマリージョ唐辛子1本（または赤パプリカ1個 + アヒアマリージョペースト小さじ1）","にんにく4片、みじん切り","新鮮な生姜大さじ2、すりおろし","醤油大さじ3","赤ワインビネガー大さじ2","新鮮なコリアンダー30g、粗く刻んだもの","植物油大さじ3（フライドポテト用に500ml追加）","塩小さじ1","挽きたての黒胡椒小さじ1/2","炊いた白いバスマティ米400g","ライム1個、くし切り（オプション）"],"en":["600g beef sirloin or tenderloin, cut into 1 cm strips","3 large potatoes (about 700g), cut into thick fries","1 large red onion, cut into 1 cm-thick wedges","2 medium Roma tomatoes, cut into wedges (or thick slices)","1 yellow ají amarillo pepper (or 1 red bell pepper + 1 tsp ají amarillo paste)","4 garlic cloves, minced","2 tbsp fresh ginger, grated","3 tbsp soy sauce","2 tbsp red wine vinegar","30g fresh coriander, roughly chopped","3 tbsp vegetable oil (plus 500ml for frying potatoes)","1 tsp salt","1/2 tsp freshly ground black pepper","400g white basmati rice, cooked","1 lime, cut into wedges (optional)"],"ro":["600g vrăbioară sau mușchi de vită, tăiată fâșii de 1 cm grosime","3 cartofi mari (aproximativ 700g), tăiați cartofi prăjiți groși","1 ceapă roșie mare, feliată în pene groase de 1 cm","2 roșii Roma medii, tăiate sferturi (sau felii groase)","1 ardei aji amarillo galben (sau 1 ardei kapia + 1 linguriță pastă aji amarillo)","4 căței de usturoi, tocați","2 linguri ghimbir proaspăt, ras","3 linguri sos de soia","2 linguri oțet de vin roșu","30g coriandru proaspăt, tocat grosier","3 linguri ulei vegetal (plus 500ml pentru cartofi)","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","400g orez basmati alb, gătit","1 lime, tăiat felii (opțional)"]},"howIsMade":{"ja":"牛肉に塩・こしょうで下味をつけ、常温で10分休ませる——強火でよく焼き目がつく。深い鍋に500mlの油を175°Cに熱する、ジャガイモを6〜7分、黄金色でカリッとなるまで揚げる、網に取り出して油を切り、熱いうちに軽く塩を振る。大きな中華鍋または鋳鉄パンを強火で熱し、油大さじ2を入れる——軽く煙が立つまで、これが重要な工程：ペルー風「ウォク・ヘイ」効果を出すために鍋は非常に熱くなければならない。牛肉を一段に並べて入れる、30秒触らずに焼き色をつけ、その後勢いよく90秒炒める——牛肉は表面はこんがり、中心はピンク色を残す、皿に取り出す。同じ鍋に油大さじ1を追加、玉ねぎのくし切りとアヒアマリージョを90秒炒める——玉ねぎはシャキッとした食感を保つこと。にんにくと生姜を加え、香りが立つまで30秒炒める、トマトを加え、1分炒める——少し柔らかくなるが崩れない程度。醤油と赤ワインビネガーを鍋肌に回し入れる（蒸発して芳ばしい煙が立つ）、牛肉を肉汁ごと戻し、フライドポテトを加える、30秒勢いよく炒めて全体に絡める。火を止め、刻んだコリアンダーを散らして一度混ぜる、すぐに温かいバスマティ米にかけ、ライムのくし切りを添えて供する。","en":"Season the beef strips with salt and pepper; let them rest for 10 minutes at room temperature — they will sear better at high heat. Heat 500ml of oil in a deep pan to 175°C; fry the potatoes for 6–7 minutes until golden and crisp; drain on a rack and salt lightly while hot. Heat a large wok or cast-iron pan over very high heat with 2 tbsp of vegetable oil — the oil should just begin to smoke; this is the critical step: the pan must be very hot for the Peruvian \"wok hei\" effect. Add the beef in a single layer; leave untouched for 30 seconds to sear, then stir-fry vigorously for 90 seconds — the beef should be browned outside but still pink in the centre; lift onto a plate. In the same wok, add 1 tbsp more oil; stir-fry the onion wedges and ají amarillo for 90 seconds — the onion should stay crisp, not soft. Add the garlic and ginger, stir-fry for 30 seconds until fragrant; add the tomatoes and cook for 1 minute — they should soften slightly but not break down. Pour the soy sauce and red wine vinegar around the edge of the pan (they will steam and create aromatic smoke); return the beef with its juices and add the fries; toss vigorously for 30 seconds, until everything is coated. Turn off the heat, scatter the chopped coriander, and toss once; serve immediately over warm basmati rice with lime wedges on the side."}},{"id":118,"origin":{"ja":"モロッコ","en":"Morocco","ro":"Maroc"},"name":{"ja":"チキン・タジン","en":"Chicken Tagine","ro":"Chicken Tagine"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"ja":["骨付き皮付き鶏もも肉 1.2 kg（約 8 切れ）、余分な皮を取り除く","大きな黄玉ねぎ 2 個（~400 g）、1 個はマリネ用にすりおろし、1 個は煮込みの土台用に薄切り","にんにく 6 片、みじん切り","新生姜 4 cm、細かくすりおろす","クミンパウダー小さじ 1 + 生姜パウダー小さじ 1 + コリアンダーパウダー小さじ 1 + ターメリック小さじ 1/2 + 甘いパプリカパウダー小さじ 1/2 + ホワイトペッパー小さじ 1/2 + サフラン糸ひとつまみ（8-10 本、湯大さじ 2 に浸す）","新鮮なコリアンダー（パクチー）の小束 ~25 g、細かく刻む（半量はマリネに、半量は仕上げに）","新鮮なイタリアンパセリの小束 ~25 g、細かく刻む（半量はマリネに、半量は仕上げに）","塩小さじ 1.5 + 黒胡椒小さじ 1/2","オリーブオイル大さじ 3 + 無塩バター大さじ 1（または最も伝統的なスメンを使用）","塩漬けレモン 2 個、洗って果肉を除き、皮を細切りに（皮の合計約 80 g）","緑のモロッコオリーブ 150 g（または Castelvetrano）、洗って大きければ種を抜く","熱湯または低塩のチキンスープ 400 ml","生レモン半個分の絞り汁（最後に加える、爽やかさのため）","提供時：温かいモロッコの薄焼きパン khobz でソースをすくう、または蒸したクスクス"],"en":["1.2 kg bone-in skin-on chicken thighs (about 8 pieces), trimmed of excess skin","2 large yellow onions (~400 g), one finely grated for the marinade, one thinly sliced for the stew base","6 garlic cloves, minced","4 cm fresh ginger, finely grated","1 tsp ground cumin + 1 tsp ground ginger + 1 tsp ground coriander + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground white pepper + a generous pinch of saffron threads (8-10 strands, bloomed in 2 tbsp hot water)","1 small bunch fresh coriander (cilantro), about 25 g, finely chopped (half for the marinade, half for garnish)","1 small bunch flat-leaf parsley, about 25 g, finely chopped (half for the marinade, half for garnish)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","3 tbsp olive oil + 1 tbsp unsalted butter (or smen for the most traditional flavour)","2 preserved lemons, rinsed, flesh discarded, peel cut into thin strips (about 80 g of peel total)","150 g green Moroccan olives (or Castelvetrano), rinsed, pitted if large","400 ml hot water or low-salt chicken stock","Juice of half a fresh lemon (added at the end, to brighten)","To serve: warm khobz flatbread to mop up the sauce, or steamed couscous"],"ro":["1.2 kg pulpe de pui cu os și piele (aproximativ 8 bucăți), curățate de pielea în exces","2 cepe galbene mari (~400 g), una rasă fin pentru marinadă, una tăiată felii subțiri pentru baza tocăniței","6 căței de usturoi, tocați","4 cm ghimbir proaspăt, ras fin","1 linguriță chimion măcinat + 1 linguriță ghimbir măcinat + 1 linguriță coriandru măcinat + 0.5 linguriță turmeric + 0.5 linguriță boia dulce + 0.5 linguriță piper alb măcinat + un vârf generos de șofran (8-10 fire, înflorite în 2 linguri apă fierbinte)","1 legătură mică de coriandru proaspăt (cilantro), ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1 legătură mică de pătrunjel cu frunza lată, ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1.5 linguriță sare + 0.5 linguriță piper negru proaspăt măcinat","3 linguri ulei de măsline + 1 lingură unt nesărat (sau smen pentru aroma cea mai tradițională)","2 lămâi conservate, clătite, pulpa îndepărtată, coaja tăiată fâșii subțiri (aproximativ 80 g de coajă)","150 g măsline verzi marocane (sau Castelvetrano), clătite, fără sâmburi dacă sunt mari","400 ml apă fierbinte sau supă de pui cu puțină sare","Zeama de la jumătate de lămâie proaspătă (adăugată la final, pentru prospețime)","Pentru servit: pâine plată khobz caldă pentru a culege sosul, sau couscous aburit"]},"howIsMade":{"ja":"鶏肉をマリネする：大きなボウルにすりおろした玉ねぎ、にんにく、生姜、すべてのドライスパイス、サフランの戻し水、刻んだコリアンダーの半量、パセリの半量、塩小さじ1.5、黒胡椒小さじ1/2、オリーブオイル大さじ1.5を入れて混ぜる。鶏もも肉を加え、皮の表裏にマリネをよく揉み込む。蓋をして冷蔵庫で最低1時間、4時間あれば明らかに良く、一晩寝かせれば最高。\n\n焼き付けて土台を作る：タジン鍋または厚手鍋で残りのオリーブオイル大さじ1.5とバターを中火で熱する。薄切り玉ねぎを加え、混ぜながら8分炒めて柔らかく軽い狐色にする。玉ねぎを片側に寄せ、鶏もも肉を皮目を下にして並べ、3-4分焼いて皮が深い狐色になったらひっくり返す。\n\n煮込む：ボウルに残ったマリネを一滴残らず鍋にこそげ入れる。熱湯または鶏ガラスープ400 mlを注ぐ。ゆっくり沸かしたら蓋をして弱火の最弱に落とす。30分煮る — 円錐形の蓋が、タジンの本質である蒸気を閉じ込める。\n\n塩漬けレモンとオリーブを加える：蓋を開け、塩漬けレモンの皮の千切りと緑のオリーブを鶏肉の周り（上ではなく）に差し込む — 両方とも塩水を放つので、強く混ぜない。再び蓋をして10-15分煮る。鶏肉の最も厚い部分が75 °Cになり、ソースが光沢のある軽くスプーンの背を覆う濃度になるまで。\n\n仕上げて提供する：蓋を取り、生レモン半個分の汁を全体に絞り、取り置いたコリアンダーとパセリを散らす。塩を加える前に味見を — 塩漬けレモンとオリーブはどちらも塩分を加える。タジンからそのまま、温かいモロッコの薄焼きパン khobz をソースに添えて、または蒸したクスクスと一緒に提供する。","en":"MARINATE THE CHICKEN: in a large bowl combine the grated onion, garlic, ginger, all the dry spices, the bloomed saffron with its water, half the chopped coriander, half the parsley, 1.5 tsp salt, 0.5 tsp black pepper and 1.5 tbsp olive oil. Add the chicken thighs and massage the marinade thoroughly into and under the skin. Cover and refrigerate at least 1 hour; 4 hours is markedly better, overnight is best.\n\nSEAR AND BUILD THE BASE: heat the remaining 1.5 tbsp olive oil and the butter in a tagine vessel or wide heavy-bottomed pot over medium heat. Add the sliced onion and cook 8 minutes, stirring, until soft and lightly golden. Push the onions to one side, lay the marinated chicken skin-side down and sear 3-4 minutes until the skin is deep golden, then flip.\n\nSIMMER: scrape every drop of marinade from the bowl into the pot. Pour in the 400 ml hot water or stock. Bring to a gentle simmer, then cover and reduce the heat to its lowest setting. Cook 30 minutes — the conical lid traps the steam that defines a tagine.\n\nADD PRESERVED LEMON AND OLIVES: lift the lid, tuck the preserved-lemon strips and green olives around (not on top of) the chicken — both release brine, so resist the urge to stir vigorously. Re-cover and cook 10-15 minutes more, until the chicken reads 75 °C / 170 °F at the thickest part and the sauce has reduced to a glossy, brothy consistency that coats the back of a spoon.\n\nFINISH AND SERVE: uncover, squeeze the half-lemon juice over the dish, and scatter the reserved coriander and parsley on top. Taste before salting — preserved lemons and olives both contribute salt, so the dish often needs nothing more. Serve straight from the tagine with warm khobz flatbread to mop up the sauce, or alongside steamed couscous."}},{"id":120,"origin":{"ja":"ベネズエラ","en":"Venezuela","ro":"Venezuela"},"name":{"ja":"アレパ","en":"Arepa","ro":"Arepa"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"latin","ingredients":{"ja":["生地用：","ハリナP.A.N.（事前加熱した白トウモロコシ粉）400g","ぬるま湯500ml","塩小さじ1","植物油大さじ2","レイナ・ペピアダ（チキンとアボカドの定番具）用：","鶏胸肉2枚（約500g）、茹でてほぐしたもの","完熟アボカド1個、角切り","マヨネーズ大さじ3","ライム果汁大さじ1","青ねぎ1本、小口切り","新鮮なコリアンダー10g、刻んだもの","塩こしょう","他の人気の具：","新鮮な白チーズ（ケソ・フレスコ）200g、スライス","ほぐした牛肉（カルネ・メチャダ）100g","焼き面用の植物油"],"en":["For the dough:","400g harina P.A.N. (pre-cooked white corn flour)","500ml warm water","1 tsp salt","2 tbsp vegetable oil","For reina pepiada (classic chicken-avocado filling):","2 chicken breasts (about 500g), poached and shredded","1 ripe avocado, diced","3 tbsp mayonnaise","1 tbsp lime juice","1 spring onion, finely sliced","10g fresh coriander, chopped","salt and pepper","Other popular fillings:","200g fresh white cheese (queso fresco), sliced","100g shredded beef (carne mechada)","vegetable oil for griddle"],"ro":["Pentru aluat:","400g harina P.A.N. (făină de porumb pre-fiartă)","500ml apă caldă","1 linguriță sare","2 linguri ulei vegetal","Pentru reina pepiada (umplutura clasică):","2 piepți de pui (aproximativ 500g), fierți și mărunțiți","1 avocado copt, tăiat cuburi","3 linguri maioneză","1 lingură zeamă de lime","1 ceapă verde, tăiată fin","10g coriandru proaspăt, tocat","sare și piper","Alte umpluturi populare:","200g brânză albă proaspătă (queso fresco), feliată","100g carne de vită mărunțită (carne mechada)","ulei vegetal pentru prăjit pe plită"]},"howIsMade":{"ja":"大きなボウルにぬるま湯500ml、塩、油を入れて混ぜる、ハリナP.A.N.400gを少しずつ加え、手かヘラで混ぜる。3〜4分こねて、なめらかで柔らかい生地にする、布をかけて5分休ませる——粉が水を吸って、生地が成形しやすくなる。生地をテスト：少しベタつくが生っぽくない状態が理想、成形時にひび割れたら、水を大さじ1足す。8つの均等な球（各約100g）に分ける、手のひらで挟んで直径8cm、厚さ1.5cmの円盤に成形し、湿らせた指で縁を整える。厚手のフライパンまたは鉄板を中火で熱し、少量の油をひく、アレパを並べ、片面4〜5分ずつ、金色で濃い斑点ができるまで焼く。天板に移し、180°Cに予熱したオーブンで10〜15分仕上げる、軽く叩いて中が空洞のような音がすれば焼き上がり。アレパが休んでいる間にレイナ・ペピアダを作る：ほぐした鶏肉にアボカド、マヨネーズ、ライム果汁、青ねぎ、コリアンダー、塩、こしょうを混ぜる。各アレパを鋭利なナイフで水平に切り込み（ピタブレッドのポケットのように）、完全には分けない、レイナ・ペピアダ（または好みの具）を詰める、外側がカリッと、内側が温かいうちにすぐに供する。","en":"In a large bowl, combine 500ml warm water with salt and oil; gradually add 400g harina P.A.N., mixing with your hand or a spatula. Knead for 3–4 minutes until the dough is smooth and pliable; cover with a cloth and let it rest for 5 minutes — the flour absorbs the water and the dough becomes easier to shape. Test the dough: it should be slightly sticky but not raw; if it cracks while shaping, add a tablespoon more water. Divide into 8 equal balls (about 100g each); flatten each between your palms into a 8 cm wide, 1.5 cm thick disc, smoothing the edges with damp fingers. Heat a heavy pan or griddle over medium heat with a little oil; add the arepas and cook for 4–5 minutes per side, until a golden crust with darker spots forms. Transfer to a baking tray and finish in a preheated 180°C oven for 10–15 minutes, until they sound hollow when tapped lightly; this is the doneness test. While the arepas rest, make the reina pepiada: mix the shredded chicken with avocado, mayonnaise, lime juice, spring onion, coriander, salt, and pepper. Slice each arepa horizontally with a sharp knife (like a pita pocket), without cutting all the way through; stuff with reina pepiada (or your chosen filling); serve immediately while the arepa is warm and crisp on the outside."}},{"id":121,"origin":{"ja":"フィンランド","en":"Finland","ro":"Finlanda"},"name":{"ja":"カレリアンピーラッカ","en":"Karelian Pie","ro":"Karjalanpiirakka"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ja":["生地用：","ライ麦粉150g","薄力粉100g","冷水150ml","塩小さじ1/2","植物油大さじ1","米のお粥詰め物用：","短粒米（プディングライス）200g","全乳1リットル","塩小さじ1/2","バター20g","ムナヴォイ（卵バター、定番の添え物）用：","無塩バター（柔らかくしたもの）100g","固ゆで卵2個、皮をむいて細かく刻んだもの","塩小さじ1/4","白胡椒小さじ1/4"],"en":["For the dough:","150g rye flour","100g plain white flour","150ml cold water","1/2 tsp salt","1 tbsp vegetable oil","For the rice porridge filling:","200g short-grain rice (pudding rice)","1 litre whole milk","1/2 tsp salt","20g butter","For muna voi (egg butter, classic topping):","100g soft unsalted butter","2 hard-boiled eggs, peeled and finely chopped","1/4 tsp salt","1/4 tsp white pepper"],"ro":["Pentru aluat:","150g făină de secară","100g făină albă","150ml apă rece","1/2 linguriță sare","1 lingură ulei vegetal","Pentru umplutura de orez:","200g orez cu bob rotund (orez pudding)","1 litru lapte integral","1/2 linguriță sare","20g unt","Pentru muna voi (untul de ouă pentru servire):","100g unt moale","2 ouă fierte tari, decojite și tocate fin","1/4 linguriță sare","1/4 linguriță piper alb"]},"howIsMade":{"ja":"米のお粥を作る（前日に作っても良い）：鍋に米200gと熱湯250mlを入れる、中火で8分、水分が吸収されるまで炊く。牛乳1Lと塩小さじ1/2を加える、弱火で頻繁にかき混ぜながら35〜45分、お粥が非常にクリーミーで濃厚になるまで煮る、バター20gを混ぜ入れ、完全に冷ます。生地用：ボウルにライ麦粉、薄力粉、塩を混ぜる、冷水と油を加え、5分こねてしっかりしているが弾力のある生地にする。生地を16等分に分けて丸める、ライ麦粉を打った台で、各球をとても薄い楕円（厚さ1mm、長さ12cm）に伸ばす。各楕円の中央に冷たいお粥大さじ1〜2を乗せ、縁を2cm空ける。生地を両側の長辺から具の上に持ち上げ、中央は開けたまま、指でつまんで特徴的なジグザグ模様のひだを作る — これがカレリアの伝統的な閉じ方。ベーキングシートを敷いた天板にパイを並べる、250°Cに予熱したオーブンで15〜20分、縁が黄金色になるまで焼く。焼いている間にムナヴォイを作る：柔らかいバターを刻んだ卵、塩、白胡椒と混ぜる、パイを温かいうちに、ご飯の露出した面にムナヴォイをたっぷり塗って供する。","en":"Make the rice porridge (can be made a day ahead): combine 200g rice with 250ml hot water in a pot; cook 8 minutes over medium heat, until the water is absorbed. Add 1 litre milk and 1/2 tsp salt; simmer over low heat, stirring often, for 35–45 minutes, until the porridge is very creamy and thick; stir in 20g butter and cool completely. For the dough: combine rye flour, white flour, and salt in a bowl; add cold water and oil, knead for 5 minutes until firm but elastic. Divide the dough into 16 equal pieces and roll into balls; on a rye-floured surface, roll each ball into a very thin oval (1 mm thick, 12 cm long). Spoon 1–2 tbsp cold rice porridge into the centre of each oval, leaving a 2 cm border. Lift the dough over the filling on both long sides, leaving the centre exposed; pinch the dough with your fingers to create the characteristic zigzag pleats — this is the traditional Karelian seal. Arrange the pies on a lined baking tray; bake in a preheated 250°C oven for 15–20 minutes, until the edges are golden brown. While the pies bake, make muna voi: mash the soft butter with the chopped eggs, salt, and white pepper; serve the pies warm, generously spread with muna voi over the exposed rice surface."}},{"id":123,"origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"パスタ・エ・ファジョーリ","en":"Pasta e fagioli","ro":"Pasta e fagioli"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"ja":["ショートパスタ200g（ディタリーニ、トゥベッティ、またはオレキエッテ）","缶詰のボルロッティまたはカネリーニ豆400g、水気を切る（または乾燥200gを一晩浸して茹でる）","大きな玉ねぎ1個、みじん切り","にんじん2本、細かい角切り","セロリ2本、細かい角切り","にんにく3片、みじん切り","パンチェッタまたはベーコン100g、角切り（オプション）","缶詰のカットトマト400g","トマトペースト大さじ2","ローリエ1枚","新鮮なローズマリー1枝","新鮮なタイム1枝","熱い鶏ガラまたは野菜ストック1.2L","エクストラバージンオリーブオイル大さじ4","パルミジャーノの皮1切れ（オプション、旨味のため）","塩と挽きたての黒胡椒","すりおろしパルミジャーノとエクストラバージンオリーブオイル、添え用"],"en":["200g short pasta (ditalini, tubetti, or orecchiette)","400g canned borlotti or cannellini beans, drained (or 200g dried, soaked overnight and cooked)","1 large onion, finely chopped","2 carrots, finely diced","2 celery stalks, finely diced","3 garlic cloves, minced","100g pancetta or bacon, diced (optional)","400g canned chopped tomatoes","2 tbsp tomato paste","1 bay leaf","1 sprig fresh rosemary","1 sprig fresh thyme","1.2L hot chicken or vegetable stock","4 tbsp extra-virgin olive oil","1 piece Parmigiano rind (optional, for flavour)","salt and freshly ground black pepper","grated Parmigiano and extra-virgin olive oil, to serve"],"ro":["200g paste scurte (ditalini, tubetti sau orecchiette)","400g fasole borlotti sau cannellini din conservă, scurse (sau 200g fasole uscată înmuiată peste noapte și fiartă)","1 ceapă mare, tocată fin","2 morcovi, tăiați cuburi mici","2 tulpini de țelină, tăiate cuburi mici","3 căței de usturoi, tocați","100g pancetta sau bacon, tăiat cuburi (opțional)","400g roșii sfărâmate din conservă","2 linguri pastă de roșii","1 frunză de dafin","1 crenguță de rozmarin proaspăt","1 crenguță de cimbru proaspăt","1,2 litri supă de pui sau legume fierbinte","4 linguri ulei de măsline extravirgin","1 bucată coajă de Parmigiano (opțional, pentru aromă)","sare și piper negru proaspăt măcinat","Parmigiano ras și ulei de măsline extravirgin, pentru servit"]},"howIsMade":{"ja":"厚手の大鍋にオリーブオイル大さじ3を中火で熱する、パンチェッタの角切り（使う場合）を加え、5分焼いて色付けて脂を出す。玉ねぎ、にんじん、セロリ、塩ひとつまみを加える、10〜12分炒めて柔らかく軽くキャラメル色になるまで — これがソッフリット、香味のベース。にんにく、トマトペースト、ローズマリー、タイムを加える、2分炒めてペーストの色が濃くなるまで。カットトマト、ローリエ、パルミジャーノの皮（使う場合）を加える、中火で5分煮る。豆の半量はそのまま、もう半量はフォークかハンドホイッパーで潰して加える（伝統的な食感は両方を要する）、熱いストック1.2Lを注ぐ、沸騰させる。パスタを加え、中火で8〜10分、頻繁にかき混ぜながらアルデンテに茹でる、パスタからデンプンが出てスープがとろみがつく。味見をして塩を調整、パルミジャーノの皮、ローズマリー、タイムを取り除く、スープを5分休ませる — さらにとろみがついて濃厚なクリーミーシチューになる。深い器に熱々を盛る、挽きたての黒胡椒をたっぷり、すりおろしパルミジャーノを山盛り、最後にエクストラバージンオリーブオイルを回しかけて仕上げる。","en":"In a large heavy-bottomed pot, heat 3 tbsp olive oil over medium heat; add the diced pancetta (if using) and cook for 5 minutes, until browned and the fat has rendered. Add the onion, carrots, celery and a pinch of salt; sauté for 10–12 minutes, until soft and lightly caramelised — this is the soffritto, the aromatic foundation. Stir in the garlic, tomato paste, rosemary, and thyme; cook for 2 minutes, until the paste darkens. Add the chopped tomatoes, bay leaf, and Parmigiano rind (if using); simmer for 5 minutes over medium heat. Add half the beans whole and the other half mashed with a fork or hand whisk (the traditional texture calls for both); pour in 1.2L hot stock; bring to a boil. Add the pasta and cook for 8–10 minutes over medium heat, stirring often, until al dente; the liquid will thicken as the pasta releases starch. Taste and adjust salt; remove the Parmigiano rind, rosemary, and thyme stems; let the soup rest 5 minutes — it will thicken further into a dense, creamy stew. Serve hot in deep bowls; crown with generous fresh black pepper, a heavy drift of grated Parmigiano, and a final drizzle of extra-virgin olive oil."}},{"id":124,"origin":{"ja":"スリランカ","en":"Sri Lanka","ro":"Sri Lanka"},"name":{"ja":"コットゥ","en":"Kottu","ro":"Kottu"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"ja":["ゴダンバ・ロティまたはパラータ8枚（合計約640g）、1cm幅の細切り","骨と皮を除いた鶏もも肉600g、1.5cm角に切る","Lサイズの卵5個、塩ひとつまみを加えて軽く溶く","中サイズの赤玉ねぎ2個（約240g）、薄切り","大きなリーキ1本（約200g）、整えて薄切りにして洗う","小さなにんじん2本（約140g）、千切り","新鮮な青唐辛子3本、薄切り（種を除けば辛さ控えめ）","新鮮な生姜のすりおろし大さじ2","にんにく5片、みじん切り","スリランカ風カレーパウダー小さじ2","ターメリックパウダー小さじ1","カシミールチリパウダーまたは甘いパプリカパウダー小さじ2","新鮮なカレーリーフ15枚","温かいチキンまたはココナッツカレーソース400ml","醤油大さじ3","ココナッツオイルまたは植物油大さじ4","塩小さじ1.5、好みで追加","ライム果汁大さじ2、仕上げ用"],"en":["8 godhamba roti or paratha (about 640 g total), thinly sliced into 1 cm-wide strips","600 g boneless, skinless chicken thigh, cut into 1.5 cm pieces","5 large eggs, lightly beaten with a pinch of salt","2 medium red onions (about 240 g), thinly sliced","1 large leek (about 200 g), trimmed, thinly sliced, and washed","2 small carrots (about 140 g), julienned","3 fresh green chillies, finely sliced (seeded for a milder finish)","2 tbsp finely grated fresh ginger","5 garlic cloves, finely chopped","2 tsp Sri Lankan curry powder","1 tsp ground turmeric","2 tsp Kashmiri chilli powder or sweet paprika","15 fresh curry leaves","400 ml warm chicken or coconut curry sauce","3 tbsp soy sauce","4 tbsp coconut or vegetable oil","1.5 tsp salt, plus more to taste","2 tbsp lime juice, to finish"],"ro":["8 lipii godhamba sau paratha (aproximativ 640 g în total), tăiate în fâșii subțiri de 1 cm lățime","600 g pulpă de pui dezosată, fără piele, tăiată în bucăți de 1,5 cm","5 ouă mari, bătute ușor cu un praf de sare","2 cepe roșii medii (aproximativ 240 g), feliate subțire","1 praz mare (aproximativ 200 g), curățat, feliat subțire și spălat","2 morcovi mici (aproximativ 140 g), tăiați julienne","3 ardei iuți verzi proaspeți, feliați subțire (fără semințe pentru un gust mai blând)","2 linguri ghimbir proaspăt, ras fin","5 căței de usturoi, tocați fin","2 lingurițe pudră de curry srilankez","1 linguriță turmeric măcinat","2 lingurițe pudră de ardei iute Kashmiri sau boia dulce","15 frunze de curry proaspete","400 ml sos de curry de pui sau de cocos, cald","3 linguri sos de soia","4 linguri ulei de cocos sau vegetal","1,5 lingurițe sare, plus după gust","2 linguri suc de lime, pentru finisare"]},"howIsMade":{"ja":"大きなフライパンか中華鍋に油大さじ1を中強火で熱する、鶏肉に塩小さじ0.5とカレーパウダーひとつまみで下味をつけ、ときどき混ぜながら7–8分炒め、軽く色づき中まで火が通る（中心にピンク色が残らない）まで加熱する、皿に取り出す。同じフライパンに残りの油大さじ3を加える、油がきらめき始めたらカレーリーフを入れる——5–10秒間パチパチと音がする、スライスした赤玉ねぎを加え、3–4分炒める、柔らかくなり縁が半透明になりつつも形が崩れない程度に。リーキ、にんじん、青唐辛子を加えて2–3分炒める——野菜は歯ごたえを残し、柔らかくしすぎない。野菜をフライパンの片側に寄せる、空いたところに生姜とにんにくを入れ、香りが立つまで30秒、焦がさずに加熱する、残りのカレーパウダー、ターメリック、カシミールチリパウダーを加え、20–30秒香ばしくなるまで炒める。溶き卵をフライパンの中央に流し入れ、60–90秒やさしくかき混ぜる、固まりつつもつやが残る状態で——ヘラで卵を小さく崩す。鶏肉と細切りのロティをフライパンに戻す、全体を1–2分混ぜ合わせ、ロティにスパイスと鶏汁の色を移す。しょうゆと温かいカレーソースを鍋肌から回しかける、金属ヘラ2本（または重い木べらの背）で、3–4分間カチカチと刻むように勢いよく混ぜる——山に切り込みを入れ続けて、ロティの細切りが小さく不揃いな破片に砕け、ソースを吸い込むようにする、仕上がりは艶やかでひとまとまり、汁気は残らない状態にする。味見をして塩を必要に応じて足す、ライム果汁を絞り、もう一度全体を和え、湯気の立つうちに直ちに供する、横にカレーソースをひとさじ添えて。","en":"Heat 1 tbsp of the oil in a large skillet or wok over medium-high heat; season the chicken with 0.5 tsp of the salt and a pinch of the curry powder; cook for 7–8 minutes, stirring occasionally, until lightly golden and just cooked through (no pink in the centre); transfer to a plate. Add the remaining 3 tbsp of oil to the same pan; when shimmering, add the curry leaves — they will crackle for 5–10 seconds; add the sliced red onions and cook for 3–4 minutes until softened and translucent at the edges but still firm. Add the leek, carrots, and green chillies and stir-fry for 2–3 minutes — the vegetables should remain crisp-tender, not soft. Push the vegetables to one side of the pan; add the ginger and garlic to the open space and cook for 30 seconds, until fragrant but not browned; stir in the remaining curry powder, the turmeric, and the Kashmiri chilli powder; toast for 20–30 seconds until aromatic. Pour the beaten eggs into the centre of the pan and gently scramble for 60–90 seconds until set but still glossy — break the curd into small pieces with the spatula. Return the chicken to the pan along with the sliced roti; toss everything together for 1–2 minutes so the roti picks up colour from the spices and chicken juices. Pour the soy sauce and warm curry sauce around the edge of the pan; use two metal spatulas (or the back of a heavy wooden spoon) and chop-and-toss the mixture vigorously for 3–4 minutes — keep cutting through the pile so the roti strips break down into small irregular pieces and soak up the sauce; the mixture should look glossy and unified, not soupy. Taste and add more salt if needed; squeeze over the lime juice, toss once more, and serve immediately while the kottu still steams, with an extra ladle of curry sauce on the side."}},{"id":125,"origin":{"ja":"ラトビア","en":"Latvia","ro":"Letonia"},"name":{"ja":"ピラギ","en":"Piragi","ro":"Piragi"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"servings":8,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["強力粉500g、打ち粉用に少量追加","全乳250ml、38°Cにやさしく温めたもの","インスタントドライイースト7g（小さじ2）の1袋","グラニュー糖50g","細かい海塩小さじ1","無塩バター70g、溶かして少し冷ましたもの","Lサイズの卵1個、軽く溶いたもの","燻製ベーコンの脂入り部分350g（または燻製シュペック）、5mm角に細かく切る","大きな玉ねぎ1個（約180g）、非常に細かく刻む","中性油大さじ1（ベーコンが脂が少ない場合のみ）","挽きたての黒胡椒小さじ0.5","キャラウェイシード一つまみ、軽く潰す（オプション）","Lサイズの卵黄1個と牛乳大さじ1を合わせたもの、艶出し用","フレーク状の海塩、振りかけ用（オプション）"],"en":["500 g strong white bread flour, plus extra for dusting","250 ml whole milk, gently warmed to 38°C","7 g sachet (2 tsp) instant dry yeast","50 g caster sugar","1 tsp fine sea salt","70 g unsalted butter, melted and slightly cooled","1 large egg, lightly beaten","350 g smoked streaky bacon (or smoked speck), in small 5 mm dice","1 large onion (about 180 g), very finely diced","1 tbsp neutral oil (only if the bacon is very lean)","0.5 tsp freshly ground black pepper","Pinch of caraway seeds, lightly crushed (optional)","1 large egg yolk beaten with 1 tbsp milk, for glazing","Flaky sea salt, for sprinkling (optional)"],"ro":["500 g făină albă de pâine, plus pentru tăvălit","250 ml lapte integral, încălzit ușor la 38°C","1 plic de 7 g (2 lingurițe) drojdie instant uscată","50 g zahăr tos","1 linguriță sare fină de mare","70 g unt nesărat, topit și ușor răcit","1 ou mare, bătut ușor","350 g bacon afumat (sau speck afumat), tăiat cuburi mici de 5 mm","1 ceapă mare (aproximativ 180 g), tocată foarte fin","1 lingură ulei neutru (doar dacă baconul este foarte slab)","0,5 linguriță piper negru proaspăt măcinat","Un vârf de semințe de chimen, ușor zdrobite (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru glazură","Fulgi de sare de mare, pentru presărat (opțional)"]},"howIsMade":{"ja":"温めた牛乳を大きなボウルに注ぎ、その上にイーストと砂糖を振り入れ、軽くかき混ぜる、5–10分置き、表面に泡が立つまで——イーストが生きている合図。牛乳に溶かしバター、溶き卵、塩を加える、小麦粉を入れ、木べらでぼそぼそした生地になるまで混ぜる、打ち粉をした台に取り出し、8–10分こねる、なめらかで弾力があり、わずかに粘着する程度まで。生地をボール状に丸め、薄く油を塗ったボウルに入れ、湿らせた布をかけて温かい場所で1時間から1時間15分発酵させる、倍の大きさになるまで。並行して具材を準備、角切りのベーコンを乾いたフライパンに入れ、中火で5–6分、頻繁にかき混ぜながら脂が溶け出して縁がほんのり色づき始めるが、ベーコンがカリッとならない程度まで炒める、玉ねぎ（必要なら油も）を加えてさらに4–5分、玉ねぎが透き通るが色がつかないまで炒める、コショウとキャラウェイで味付けし、完全に冷ます。発酵した生地のガスを抜き、24等分（1個約35g）にする、各片を滑らかな球に丸め、めん棒で8cmの楕円形、厚さ約4mmに伸ばす。各楕円の半分の上に冷ました具材を小さじ1ずつのせ、生地を折りたたんで閉じ、縁をしっかりつまんで密閉する、封じた両端を優しく中央へ寄せて、伝統の三日月形に整え、合わせ目を下にして天板に並べる。ピラギをクッキングシートを敷いた天板2枚に3cm間隔で並べる、軽くカバーをして20–25分追加発酵させ、明らかにふっくらするまで、並行してオーブンを220°C（425°F / ファン200°C）に予熱する。上面に卵黄の艶出しを塗り、好みで塩フレークを振り、12–15分焼く——上面が深い黄金色になり、合わせ目がしっかり閉じ、底を叩くと空洞音がしたら焼き上がり、ラックで5分冷まし、温かいうちに供する。","en":"Pour the warm milk into a large bowl, scatter the yeast and sugar over it, and stir lightly; let stand 5–10 minutes until foamy on the surface — this confirms the yeast is alive. Add the melted butter, beaten egg, and salt to the milk; pour in the flour and stir with a wooden spoon until a shaggy dough forms; tip onto a lightly floured surface and knead for 8–10 minutes, until smooth, elastic, and only slightly tacky to the touch. Shape the dough into a ball, place it in a lightly oiled bowl, cover with a damp cloth, and leave to rise in a warm spot for 1 hour to 1 hour 15 minutes, until doubled. Meanwhile, prepare the filling; cook the diced bacon in a dry frying pan over medium heat for 5–6 minutes, stirring often, until the fat has rendered and the edges just begin to colour but the bacon is not crisp; add the onion (and the oil if needed) and cook for another 4–5 minutes, until the onion is translucent but not browned; season with the pepper and caraway; cool completely. Knock back the risen dough and divide it into 24 equal pieces (about 35 g each); roll each piece into a smooth ball, then flatten with a rolling pin into an 8 cm oval, about 4 mm thick. Spoon 1 tsp of cold filling onto one half of each oval, fold the dough over to enclose, and pinch the edges firmly to seal; pull the sealed ends gently toward each other to form the classic crescent shape, with the seam facing down on the tray. Arrange the piragi on two parchment-lined trays, leaving 3 cm between them; cover lightly and let rise for another 20–25 minutes, until visibly puffy; meanwhile heat the oven to 220°C (425°F / fan 200°C). Brush the tops with the egg-yolk glaze, sprinkle with flaky salt if using, and bake for 12–15 minutes — they are ready when the tops are deep golden brown, the seams hold tight, and the bottoms sound hollow when tapped; cool on a rack for 5 minutes and serve warm."}},{"id":126,"origin":{"ja":"ベトナム","en":"Vietnam","ro":"Vietnam"},"name":{"ja":"バインセオ","en":"Banh Xeo","ro":"Bánh xèo"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"vietnamese","ingredients":{"ja":["米粉250g","コーンスターチ30g","ターメリックパウダー小さじ1","細かい海塩小さじ0.5、豚肉用に追加分","グラニュー糖小さじ1","全脂ココナッツミルク400ml","冷たい炭酸水350ml（または冷たい水）","青ねぎ4本、青い部分を薄切り（約30g）","豚バラまたは肩肉300g、厚さ5mmの細切り","生むき海老300g（中サイズ約24尾）、背わたを取る","新鮮な緑豆もやし200g","中サイズの玉ねぎ1個（約120g）、薄切り","中性油60ml（落花生油または植物油）、揚げ用","魚醤大さじ1、ヌクチャム用にさらに大さじ3","新鮮なライム果汁大さじ3","グラニュー糖大さじ2（ヌクチャム用）","にんにく1片みじん切りと赤唐辛子小1本薄切り（ヌクチャム用）","サニーレタスまたはロメインレタス1個、葉を分けたもの、新鮮なハーブ大束（ミント、シソ、コリアンダー、タイバジル）、千切りきゅうり1本（添え物）"],"en":["250 g rice flour","30 g cornflour (cornstarch)","1 tsp ground turmeric","0.5 tsp fine sea salt, plus more for the pork","1 tsp caster sugar","400 ml full-fat coconut milk","350 ml cold sparkling water (or cold still water)","4 spring onions, green tops finely sliced (about 30 g)","300 g pork belly or shoulder, cut into 5 mm-thick strips","300 g raw peeled prawns (about 24 medium), deveined","200 g fresh mung bean sprouts","1 medium onion (about 120 g), thinly sliced","60 ml neutral oil (peanut or vegetable), for frying","1 tbsp fish sauce, plus 3 tbsp for the nuoc cham","3 tbsp fresh lime juice","2 tbsp caster sugar (for the nuoc cham)","1 garlic clove, finely minced, and 1 small red chilli, finely sliced (for the nuoc cham)","1 head butter lettuce or romaine, leaves separated, plus a large bunch of fresh herbs (mint, perilla, coriander, Thai basil) and 1 cucumber, julienned, to serve"],"ro":["250 g făină de orez","30 g amidon de porumb","1 linguriță turmeric măcinat","0,5 linguriță sare fină de mare, plus în plus pentru carnea de porc","1 linguriță zahăr tos","400 ml lapte de cocos integral","350 ml apă minerală rece (sau apă plată rece)","4 cepe verzi, părțile verzi feliate subțire (aproximativ 30 g)","300 g piept sau pulpă de porc, tăiat fâșii de 5 mm grosime","300 g creveți cruzi decojiți (aproximativ 24 medii), curățați de venă","200 g germeni proaspeți de fasole mung","1 ceapă medie (aproximativ 120 g), feliată subțire","60 ml ulei neutru (de arahide sau vegetal), pentru prăjit","1 lingură sos de pește, plus 3 linguri pentru nuoc cham","3 linguri suc de lime proaspăt","2 linguri zahăr tos (pentru nuoc cham)","1 cățel de usturoi tocat fin și 1 ardei iute roșu mic feliat subțire (pentru nuoc cham)","1 căpățână de salată verde de unt sau romană, frunze separate, plus o legătură mare de ierburi proaspete (mentă, perilla, coriandru, busuioc thailandez) și 1 castravete tăiat julienne, pentru servit"]},"howIsMade":{"ja":"生地は最低30分前に準備する、大きなボウルに米粉、コーンスターチ、ターメリック、塩小さじ0.5、砂糖小さじ1を入れ、泡立て器で混ぜる、ココナッツミルクと炭酸水を加え、滑らかになるまで混ぜる、青ねぎの青い部分を加える、蓋をして冷蔵庫で最低30分（最大4時間）休ませる——休ませることで粉が水分を吸い、より香ばしく仕上がる。生地を休ませる間にヌクチャムを作る、ボウルに魚醤大さじ3、ライム果汁大さじ3、砂糖大さじ2、温水大さじ4を入れ、砂糖が溶けるまで混ぜる、にんにくのみじん切りと唐辛子の薄切りを加える、脇に置いておく。豚肉の細切りに魚醤大さじ1とコショウ小さじ0.5をまぶす、海老は洗って水気を拭く、もやしを洗って水を切る、レタス・ハーブ・きゅうりを皿に並べる。直径24cmのフッ素樹脂加工フライパンを中強火で熱する、油小さじ1を加えて回し、海老2〜3尾と豚肉の細切りひとつかみを入れる、60〜90秒炒め、海老がピンク色に丸まり、豚肉の縁が金色になるが完全には火が通らない程度にする。生地を混ぜ直してから、お玉で約100mlをフライパンに流し入れる、すぐに回して薄く底全体を覆い、側面の半分まで上らせる、生地の半分の上に薄切り玉ねぎをひとつまみ散らす。蓋を60秒する——蒸気が上面に火を通す、蓋を外し、油小さじ1を縁に回しかけ、さらに2〜3分焼く、縁が濃い金色になり、薄いヘラできれいにフライパンから持ち上がるまで。豚肉と海老をのせた半分にもやしをひと盛り重ねる、空いた半分をかぶせて半月形にし、温めた皿に滑らせる、残りの生地・海老・豚肉・もやしで繰り返す、4〜5枚作れるはず。パリパリと音がしているうちに直ちに供する、食べ方：一片を破いて、ハーブときゅうりとともにレタスで包み、ヌクチャムに浸す、曲げたときにパリッと音がするのが理想——柔らかくなる場合は、次の一枚はもっと熱したフライパンと少し薄めの生地で。","en":"Make the batter at least 30 minutes ahead; whisk together the rice flour, cornflour, turmeric, 0.5 tsp salt, and 1 tsp sugar in a large bowl; pour in the coconut milk and sparkling water and whisk until smooth; stir in the sliced spring-onion greens; cover and rest in the fridge for at least 30 minutes (up to 4 hours) — the resting hydrates the flour for a crisper crepe. While the batter rests, mix the nuoc cham; stir 3 tbsp fish sauce, 3 tbsp lime juice, 2 tbsp sugar, and 4 tbsp warm water in a bowl until the sugar dissolves; add the minced garlic and sliced chilli; set aside. Toss the pork strips with 1 tbsp fish sauce and 0.5 tsp pepper; rinse and pat dry the prawns; wash the bean sprouts and shake dry; arrange the lettuce, herbs, and cucumber on a serving platter. Heat a 24 cm non-stick pan over medium-high heat; add 1 tsp oil, swirl to coat, then add 2–3 prawns and a handful of pork strips; stir-fry for 60–90 seconds until the prawns curl pink and the pork edges are golden but not fully cooked through. Stir the batter, then ladle about 100 ml into the pan, immediately swirling so the batter coats the base in a thin layer and reaches halfway up the sides; drop a small handful of sliced onion over one half of the crepe. Cover with a lid for 60 seconds — the steam helps cook the top; then uncover, drizzle 1 tsp oil around the edge, and cook for a further 2–3 minutes, until the edges turn deep golden and lift cleanly from the pan with a thin spatula. Pile a handful of bean sprouts onto the half topped with pork and prawns; fold the empty half over to form a half-moon, then slide onto a warmed plate; repeat with the remaining batter, prawns, pork, and bean sprouts; you should get 4–5 crepes. Serve immediately, while the crepes are still loud-crispy; to eat: tear a piece, wrap it in lettuce with herbs and cucumber, and dip into the nuoc cham; the crepe should crackle audibly as it bends — if it goes soft, the next one needs a hotter pan and a slightly thinner pour."}},{"id":127,"origin":{"ja":"ペルー","en":"Peru","ro":"Peru"},"name":{"ja":"カウサ・リメーニャ","en":"Causa Limeña","ro":"Causa Limeña"},"category":{"ja":"前菜","en":"Appetizer","ro":"Aperitiv"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"ja":["黄色のペルー産ジャガイモ1kg（またはユーコンゴールドなどの蝋質の黄色ジャガイモ）、皮をむいて大きめに切る","新鮮なライム果汁60ml（約2個分）","中性油60ml（ひまわり油またはオリーブ油）","アヒ・アマリージョペースト大さじ2（または代替としてアヒ・アマリージョ大さじ1＋韓国コチュジャン小さじ1）","細かい海塩小さじ1.5、好みで追加","挽きたての白胡椒小さじ0.5","良質なオリーブオイル漬けツナ160g缶 2個分、汁気を切る（または茹でてほぐした鶏むね肉320g）","良質マヨネーズ120g","青ねぎ2本、非常に細く小口切り（約20g）","セロリの茎小1本、みじん切り（約30g、オプション）","細かい海塩小さじ0.5","大きな熟したアボカド1個（約200g）、5mm厚にスライスしてライム果汁小さじ1と和える","黒オリーブ12個（ボティハまたはカラマタ）、半分に切り種を取り除く","固ゆで卵2個、半分または四つ切り","新鮮なコリアンダーまたはパセリの小枝"],"en":["1 kg yellow Peruvian potatoes (or Yukon Gold or other waxy yellow potatoes), peeled and cut into chunks","60 ml fresh lime juice (about 2 limes)","60 ml neutral oil (sunflower or olive)","2 tbsp ají amarillo paste (or 1 tbsp ají amarillo + 1 tsp Korean gochujang as substitute)","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground white pepper","2 × 160 g tins of high-quality tuna in olive oil, drained (or 320 g cooked shredded chicken breast)","120 g good mayonnaise","2 spring onions, very finely sliced (about 20 g)","1 small celery stalk, finely diced (about 30 g, optional)","0.5 tsp fine sea salt","1 large ripe avocado (about 200 g), sliced 5 mm thick and tossed with 1 tsp lime juice","12 black olives (botija or kalamata), halved and pitted","2 hard-boiled eggs, halved or quartered","Sprigs of fresh coriander or parsley"],"ro":["1 kg cartofi galbeni peruvieni (sau Yukon Gold ori alți cartofi galbeni cu pastă fermă), curățați și tăiați în bucăți","60 ml suc proaspăt de lime (aproximativ 2 lime)","60 ml ulei neutru (de floarea-soarelui sau de măsline)","2 linguri pastă de ají amarillo (sau 1 lingură ají amarillo + 1 linguriță gochujang ca substitut)","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper alb proaspăt măcinat","2 conserve de 160 g de ton de calitate în ulei de măsline, scurse (sau 320 g piept de pui fiert și mărunțit)","120 g maioneză bună","2 cepe verzi, feliate foarte fin (aproximativ 20 g)","1 tulpină mică de țelină, tocată fin (aproximativ 30 g, opțional)","0,5 linguriță sare fină de mare","1 avocado mare copt (aproximativ 200 g), feliat la 5 mm și amestecat cu 1 linguriță suc de lime","12 măsline negre (botija sau Kalamata), tăiate în două și fără sâmburi","2 ouă fierte tare, tăiate în jumătăți sau sferturi","Crenguțe de coriandru sau pătrunjel proaspăt"]},"howIsMade":{"ja":"塩をきかせた湯（1リットルあたり塩大さじ1程度）でジャガイモを18〜20分茹で、ナイフが抵抗なく入るが崩れない状態にする、湯切りし、網の上で5分間蒸らす。まだ温かいうちに、ジャガイモをライサーまたは目の細かいざるで広めのボウルに通す、アヒ・アマリージョペースト、ライム果汁、油、塩小さじ1.5、白胡椒を加える、手で2〜3分やさしくこね、なめらかで絹のような少し弾力のあるマッシュにする、つまむと形を保つくらい。味見して塩やライムで調整する、蓋をして室温まで冷まし、20分冷蔵してわずかに引き締める。詰め物を作る、汁気を切ったツナ（または鶏肉）をボウルにほぐす、マヨネーズ、青ねぎ、（使うなら）セロリ、塩小さじ0.5を加える、やさしく和える——魚の繊維が見えるように、なめらかにしすぎない、使うまで冷蔵する。22 × 12cmのパウンド型（または直径18cmのケーキリング）にラップを敷き、外にゆとりを残す、マッシュの3分の1を底に押し付け、1.5cmの均一な層を作る、湿らせたスプーンの背で表面をならす。ツナまたは鶏肉の詰め物の半分をジャガイモ層の上に1cmの厚さで広げる、縁を5mm残す、アボカドのスライスを重なるように一層に並べる、マッシュのもう3分の1をアボカドの上に押し付け、残りの詰め物を重ね、最後にマッシュの最後の層を敷く。ラップを上から折り返し、手のひらや小さな板で押して具材をしっかり締める、冷蔵庫で最低1時間（最大6時間）冷やし、層を固める。ラップを利用してテリーヌを取り出し、剥がして、熱い湿った包丁で8つの十分な分量に切り分ける（切るたびに刃を洗う）、各スライスにオリーブ半分、固ゆで卵のくし切り、コリアンダーの小枝をのせる、切ってから2時間以内に冷たいうちに供する。","en":"Boil the potatoes in well-salted water (about 1 tbsp salt per litre) for 18–20 minutes, until a knife slides in with no resistance but the potatoes are not falling apart; drain and leave to steam-dry on a rack for 5 minutes. While still warm, pass the potatoes through a ricer or fine sieve into a wide bowl; add the ají amarillo paste, lime juice, oil, 1.5 tsp salt, and white pepper; knead gently with your hands for 2–3 minutes — the mash should be smooth, silky, and slightly elastic, holding its shape when pinched. Taste and adjust with more salt or lime; cover and let cool to room temperature, then chill for 20 minutes to firm slightly. Make the filling; flake the drained tuna (or shred the chicken) into a bowl; add the mayonnaise, spring onions, celery (if using), and 0.5 tsp salt; fold gently — keep visible flakes of fish rather than a smooth purée; chill until needed. Line a 22 × 12 cm loaf tin (or a round 18 cm cake ring) with cling film, leaving a generous overhang; press one-third of the potato mash into the base in an even 1.5 cm layer, using the back of a damp spoon to smooth. Spread half the tuna or chicken filling over the potato in a 1 cm layer, leaving a 5 mm border; arrange the avocado slices on top in a tight overlapping single layer; press a second third of potato over the avocado, then top with the remaining filling and a final layer of potato. Fold the cling film over the top and press firmly with the flat of your hand or a small board to compact the terrine; refrigerate for at least 1 hour (or up to 6 hours) to set the layers. Lift the terrine out using the cling film, peel back, and slice into 8 generous portions with a hot wet knife (rinse the blade between cuts); top each slice with an olive half, a wedge of hard-boiled egg, and a sprig of coriander; serve cold, within 2 hours of slicing."}},{"id":129,"origin":{"ja":"キルギス","en":"Kyrgyzstan","ro":"Kârgâzstan"},"name":{"ja":"ベシュバルマク","en":"Beshbarmak","ro":"Beshbarmak"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["骨付きラム肩肉または牛ブリスケット（あるいはミックス）1.2kg、大きく4切れに分ける","冷水3リットル","細かい海塩大さじ1、好みで追加","玉ねぎ1個、半割（出汁用）","にんじん1本、半割（出汁用）","ローリエ2枚","黒胡椒10粒","中力粉400g、打ち粉用に少量追加","Lサイズの卵2個","ぬるま湯150ml","細かい海塩小さじ1","大きな玉ねぎ2個（約350g）、半割して薄い半月切り","挽きたての黒胡椒小さじ0.5","砂糖ひとつまみ","新鮮なディルまたはパセリ、粗く刻む"],"en":["1.2 kg bone-in lamb shoulder or beef brisket (or a mix), cut into 4 large pieces","3 litres cold water","1 tbsp fine sea salt, plus more to taste","1 onion, halved (for the broth)","1 carrot, halved (for the broth)","2 bay leaves","10 whole black peppercorns","400 g plain (all-purpose) flour, plus extra for dusting","2 large eggs","150 ml warm water","1 tsp fine sea salt","2 large onions (about 350 g), halved and thinly sliced into half-moons","0.5 tsp freshly ground black pepper","Pinch of sugar","Fresh dill or parsley, roughly chopped"],"ro":["1,2 kg umăr de miel sau piept de vită cu os (sau un amestec), tăiat în 4 bucăți mari","3 litri apă rece","1 lingură sare fină de mare, plus după gust","1 ceapă, tăiată în două (pentru bulion)","1 morcov, tăiat în două (pentru bulion)","2 frunze de dafin","10 boabe de piper negru întregi","400 g făină albă obișnuită, plus pentru tăvălit","2 ouă mari","150 ml apă caldă","1 linguriță sare fină de mare","2 cepe mari (aproximativ 350 g), tăiate în două și feliate subțire în semilune","0,5 linguriță piper negru proaspăt măcinat","Un vârf de zahăr","Mărar sau pătrunjel proaspăt, tocat grosier"]},"howIsMade":{"ja":"大きな鍋に肉を入れ、冷水で覆い、中火でゆっくりと沸騰させる——ゆっくり加熱することでスープに最大限の旨みが移る、最初の10分間は灰色のあくを丁寧に取り、表面が澄むまで続ける。塩大さじ1、半割の玉ねぎ、にんじん、ローリエ、黒胡椒の実を加える、火を弱火（表面がほとんど動かない程度）に落とし、蓋をせずに2〜2.5時間、肉が骨から外れるくらいまで煮込む。肉が煮込まれている間に生地を作る、広めのボウルに小麦粉と塩小さじ1を入れて泡立て器で混ぜ、中央にくぼみを作って卵とぬるま湯を加える、フォークで混ぜ、打ち粉をした台で8〜10分こねる、引き締まり、なめらかで弾力のある生地に、ラップをして室温で30分休ませる。休ませた生地を4等分する、1つずつ作業し、残りはラップをかけたまま、打ち粉をした台でできるだけ薄く——約1mm厚に伸ばす、約8 × 8cmの正方形（または10 × 5cmのひし形）に切る、たっぷり打ち粉を振ってトレイに平らに並べ、くっつかないようにする。肉をスープから取り出してまな板に置き、アルミホイルをふんわりかけて休ませる、スープを目の細かい網でこして清潔な鍋に移し、煮込んだ野菜は捨てる、スープは弱火で保温する。別の小鍋に熱いスープ500mlを取り分ける、薄切りの玉ねぎと砂糖ひとつまみを加え、5〜6分弱火で煮る——玉ねぎは透明感が残り、ちょうど柔らかいくらい、崩れないように、黒胡椒小さじ0.5を加える。こしたスープを再び強火で沸かす、生地の正方形を数回に分けて投入し、くっつかないように静かに混ぜ、1回あたり3〜4分、浮いてアルデンテになるまで茹でる、穴あきお玉で温めた皿に取り出す。肉を繊維に逆らって厚切りにし、麺の上に並べる、玉ねぎとそのスープをたっぷり肉にかける、刻んだディルを散らし、各人に温かい澄んだスープを一杯ずつ添えて、合間にすすってもらう、湯気が立つうちに直ちに供する。","en":"Place the meat in a large stockpot, cover with the cold water, and bring slowly to the boil over medium heat — slow heating draws maximum flavour into the broth; skim the grey foam carefully for the first 10 minutes until the surface runs clear. Add the 1 tbsp salt, halved onion, carrot, bay leaves, and peppercorns; reduce the heat to a bare simmer (the surface should barely move) and cook uncovered for 2–2.5 hours, until the meat is fork-tender and falling from the bone. While the meat simmers, make the dough; whisk the flour and 1 tsp salt in a wide bowl, make a well, and add the eggs and warm water; stir with a fork, then knead on a floured surface for 8–10 minutes until firm, smooth, and elastic; cover with cling film and rest at room temperature for 30 minutes. Divide the rested dough into 4 pieces; working with one piece at a time and keeping the rest covered, roll out as thinly as possible on a floured surface — about 1 mm thick; cut into rough 8 × 8 cm squares (or 10 × 5 cm diamonds); dust generously with flour and lay flat on a tray so they do not stick. Lift the meat out of the broth onto a board, cover loosely with foil, and rest; strain the broth into a clean pot through a fine sieve and discard the boiling vegetables; keep the broth at a gentle simmer. Ladle 500 ml of the hot broth into a separate small pot; add the thinly sliced onions and a pinch of sugar and simmer for 5–6 minutes — the onions should stay translucent and just tender, not collapsed; stir in 0.5 tsp black pepper. Bring the strained broth back to a vigorous boil; drop the dough squares in batches, stir gently to prevent sticking, and cook 3–4 minutes per batch until they float and are al dente; lift out with a slotted spoon onto a warmed serving platter. Slice the meat thickly against the grain and arrange over the noodles; spoon the onions and their broth liberally over the meat; scatter with chopped dill, then ladle a cup of the hot clear broth on the side for each diner to sip between bites; serve immediately while everything is steaming hot."}},{"id":130,"origin":{"ja":"タイ","en":"Thailand","ro":"Thailanda"},"name":{"ja":"ココナッツライス","en":"Coconut Rice","ro":"Orez cu lapte de cocos"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ja":["長粒米400g（タイのジャスミン米またはバスマティ米）","全脂ココナッツミルク400ml（標準缶1個分）","冷水250ml","細かい海塩小さじ1","グラニュー糖小さじ1","新鮮なパンダンリーフ2枚、結んで束ねる（または、パンダンエキス小さじ1——任意だが伝統的）","小さなエシャロット1個（約30g）、薄切り","レモングラスの茎1本、軽くつぶす（任意、東南アジア風の香り付け）","ライムの皮、3cmの細長い1片（任意、爽やかさを添える）","ココナッツオイルまたは中性油大さじ1","無糖ココナッツファイン30g、軽くトーストする（飾り用）","新鮮なコリアンダーの葉ひとつかみ（飾り用）"],"en":["400 g long-grain rice (Thai jasmine or basmati)","400 ml full-fat coconut milk (1 standard tin)","250 ml cold water","1 tsp fine sea salt","1 tsp caster sugar","2 fresh pandan leaves, tied into a knot (or 1 tsp pandan extract — optional but traditional)","1 small shallot (about 30 g), finely sliced","1 stalk lemongrass, lightly bruised (optional, for Southeast Asian aroma)","3 cm strip lime zest (optional, for brightness)","1 tbsp coconut oil or neutral oil","30 g unsweetened desiccated coconut, lightly toasted (for garnish)","Small handful fresh coriander leaves (for garnish)"],"ro":["400 g orez cu bob lung (jasmine thailandez sau basmati)","400 ml lapte de cocos integral (1 conservă standard)","250 ml apă rece","1 linguriță sare fină de mare","1 linguriță zahăr tos","2 frunze de pandan proaspete, legate în nod (sau 1 linguriță extract de pandan — opțional, dar tradițional)","1 eșalotă mică (aproximativ 30 g), feliată fin","1 tulpină de lemongrass, ușor zdrobită (opțional, pentru aroma sud-est asiatică)","Coajă de lime de 3 cm, fâșie subțire (opțional, pentru prospețime)","1 lingură ulei de cocos sau ulei neutru","30 g cocos rasă neîndulcită, ușor prăjită (pentru garnitură)","Un pumn mic de frunze de coriandru proaspete (pentru garnitură)"]},"howIsMade":{"ja":"ザルに入れた米を冷水でかき混ぜながら約1分間、水がほぼ澄むまで洗う、よく水を切る、これにより表面のでんぷんが取れ、炊き上がりが粒立つ。厚手の2リットル鍋にココナッツオイルを入れ、中火で熱する、エシャロットのスライスを加え、90秒〜2分、柔らかく縁がほんのり色づくまで、焦がさずに炒める。水気を切った米を加え、30秒かき混ぜて全粒に油をまとわせる、ココナッツミルクと水を注ぎ、塩、砂糖、結んだパンダンリーフ、つぶしたレモングラス、ライムの皮を加える。一度だけかき混ぜて塩を溶かし、中強火で穏やかに沸騰させる——ココナッツミルクが底にくっつかないよう、約2分間やさしくかき混ぜ続ける。火を最弱にし、ぴったり合う蓋をして12分間動かさずに炊く、蓋は絶対に開けない——閉じ込められた蒸気が米を均一に炊き上げる。火を止め（蓋はそのまま）、10分蒸らす——この最後の蒸気が米粒を乾かしてくっつくのを防ぐ。蓋を開け、パンダン、レモングラス、ライムの皮を取り出して捨てる、フォークでやさしくほぐし、トーストしたココナッツファインとコリアンダーの葉を散らして、カレーやサンボル、焼き魚と一緒にすぐ供する。","en":"Rinse the rice thoroughly in a sieve under cold running water for about 1 minute, swirling with your hand, until the water runs almost clear; drain well; this removes surface starch and keeps the grains separate at the end. Heat the coconut oil in a heavy-based 2-litre pan over medium heat; add the sliced shallot and stir-fry for 90 seconds–2 minutes, until softened and lightly golden at the edges but not browned. Add the drained rice to the pan and stir for 30 seconds to coat each grain in oil; pour in the coconut milk and water, then add the salt, sugar, knotted pandan leaves, bruised lemongrass, and lime zest. Stir once to dissolve the salt and bring to a gentle boil over medium-high heat — keep stirring gently for about 2 minutes so the coconut milk does not catch on the base. Lower the heat to the lowest possible setting, cover with a tight-fitting lid, and cook undisturbed for 12 minutes; do not lift the lid — the trapped steam is what cooks the rice evenly. Turn off the heat (leave the pan covered) and rest the rice for 10 minutes — this finishing steam dries the grains and stops them clumping. Lift the lid, remove and discard the pandan, lemongrass, and lime zest; fluff the rice gently with a fork, scatter the toasted desiccated coconut and coriander leaves over the top, and serve immediately alongside curry, sambols, or grilled fish."}},{"id":131,"origin":{"ja":"マレーシア","en":"Malaysia","ro":"Malaezia"},"name":{"ja":"ナシレマッ","en":"Nasi lemak","ro":"Nasi lemak"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"ja":["長粒のジャスミン米400g","全脂ココナッツミルク400ml","冷水200ml","細かい海塩小さじ1","新鮮なパンダンリーフ2枚を結び、つぶしたレモングラス1本と新鮮な生姜の薄切り3枚（ご飯用）","皮なし生ピーナッツ60g","イカンビリス60g（マレーシア産乾燥小魚）","Lサイズの卵4個","中サイズのきゅうり1本（約200g）、5mm厚の輪切り","乾燥赤唐辛子10本、お湯に15分浸して水気を切る","新鮮な赤唐辛子4本（マイルド）","大きなエシャロット2個（約120g）、皮をむき、にんにく3片と親指大の新鮮な生姜（15g）","ベラチャン大さじ1（焙煎エビペースト）または代用にナンプラー小さじ1.5","タマリンドペースト大さじ2をぬるま湯大さじ4で溶いたもの（または、ライム果汁大さじ3）","パームシュガーまたは黒砂糖大さじ2","中サイズの赤玉ねぎ1個（約120g）、薄い輪切り","中性油60mlと250ml（60mlはサンバル用、残りはイカンビリスとピーナッツの揚げ用）","サンバル用に細かい海塩小さじ0.5"],"en":["400 g long-grain jasmine rice","400 ml full-fat coconut milk","200 ml cold water","1 tsp fine sea salt","2 fresh pandan leaves tied into a knot, plus 1 bruised stalk of lemongrass and 3 thin slices of fresh ginger (for the rice)","60 g raw skinless peanuts","60 g ikan bilis (dried Malaysian anchovies)","4 large eggs","1 medium cucumber (about 200 g), sliced into 5 mm rounds","10 dried red chillies, soaked in hot water for 15 minutes and drained","4 fresh red chillies (mild)","2 large shallots (about 120 g), peeled, plus 3 garlic cloves and 1 thumb-sized piece of fresh ginger (15 g)","1 tbsp belacan (toasted shrimp paste), or 1.5 tsp fish sauce as a substitute","2 tbsp tamarind paste mixed with 4 tbsp warm water (or 3 tbsp lime juice)","2 tbsp palm sugar or dark brown sugar","1 medium red onion (about 120 g), sliced into thin rings","60 ml plus 250 ml neutral oil (split: 60 ml for the sambal, the rest for frying anchovies and peanuts)","0.5 tsp fine sea salt for the sambal"],"ro":["400 g orez jasmine cu bob lung","400 ml lapte de cocos integral","200 ml apă rece","1 linguriță sare fină de mare","2 frunze de pandan proaspete, legate în nod, plus 1 tulpină de lemongrass zdrobită și 3 felii subțiri de ghimbir proaspăt (pentru orez)","60 g arahide crude fără pieliță","60 g ikan bilis (anșoa malaezieni uscați)","4 ouă mari","1 castravete mediu (aproximativ 200 g), tăiat rondele de 5 mm","10 ardei iuți roșii uscați, înmuiați în apă fierbinte 15 minute și scurși","4 ardei iuți roșii proaspeți (blânzi)","2 eșalote mari (aproximativ 120 g), decojite, plus 3 căței de usturoi și o bucată de ghimbir cât degetul mare (15 g)","1 lingură belacan (pastă de creveți prăjită) sau 1,5 linguriță sos de pește ca substitut","2 linguri pastă de tamarin amestecată cu 4 linguri apă caldă (sau 3 linguri suc de lime)","2 linguri zahăr de palmier sau zahăr brun închis","1 ceapă roșie medie (aproximativ 120 g), feliată inele subțiri","60 ml plus 250 ml ulei neutru (împărțit: 60 ml pentru sambal, restul pentru prăjit anșoa și arahide)","0,5 linguriță sare fină de mare pentru sambal"]},"howIsMade":{"ja":"米はザルに入れて冷水でかき混ぜながら1分間、水がほぼ澄むまで洗い、よく水気を切る、2リットルの厚手鍋に米、ココナッツミルク、水、塩小さじ1、パンダンリーフ、レモングラス、生姜を入れる、中強火で穏やかに沸騰させ、一度だけかき混ぜる、火を最弱にしてぴったり蓋をし、12分間動かさず炊く、火を止め、蓋をしたまま10分蒸らす——閉じ込められた蒸気で炊き上げと粒の乾きが完成する、盛り付け前にパンダン・レモングラス・生姜を取り除く。米を炊いている間にピーナッツを揚げる、小さなフライパンに250mlの油を入れ160°Cに熱する、ピーナッツを3〜4分、淡い金色になるまで揚げる（冷めると色が濃くなる）、穴あきお玉でキッチンペーパーに上げ、軽く塩を振る。イカンビリスはペーパーで水気を拭く、同じ油で2回に分けて1回60〜90秒、一度だけかき混ぜながら、カリッと濃い金色になるまで揚げる、別のペーパーに取り出し、油は取っておく。ゆで卵：静かに沸騰する湯に入れ、しっかりした黄身ならちょうど8分、半熟気味なら7分茹でる、すぐに氷水で3分冷やし、殻をむいて半分に切る。サンバル用ペーストを作る、水気を切った乾燥唐辛子、生唐辛子、エシャロット、にんにく、生姜15gの塊、ベラチャンをブレンダーまたは乳鉢に入れ、取り置いた油大さじ2と一緒に粗いペースト状にする。ウォックか広いフライパンに新しい油60mlを入れ中火で熱する、サンバルペーストを加え、絶えずかき混ぜながら12〜15分炒める、油が縁から分離し、ペーストが深い煉瓦色になるまで、この長時間炒めが香味野菜の生臭さを消す。赤玉ねぎの輪切り、タマリンド水、パームシュガー、塩小さじ0.5を加え、さらに6〜8分弱火で煮込む、玉ねぎが柔らかくなり、スプーンで鍋肌をなぞるとくっきり線が残るほどの艶やかでジャム状の質感になるまで、味見をして調整——辛さ・甘み・酸味・塩味がほぼ均等になるように。盛り付け：皿の中央にご飯を山状に盛る、周りにゆで卵半分、サンバルをたっぷりひと匙、ピーナッツの小山、イカンビリスの小山、きゅうりの扇形を並べる、一口ごとに各山から少量ずつ混ぜながら食べる。","en":"Rinse the rice in a sieve under cold running water for 1 minute, until the water runs almost clear, then drain well; put it in a heavy 2-litre pan with the coconut milk, water, 1 tsp salt, pandan, lemongrass, and ginger; bring to a gentle boil over medium-high heat, stirring once; lower the heat to the lowest setting, cover with a tight lid, and cook undisturbed for 12 minutes; turn off the heat and rest, covered, for another 10 minutes — the trapped steam finishes cooking and dries the grains; discard the aromatics before serving. While the rice cooks, fry the peanuts; heat the 250 ml oil in a small pan to 160°C; fry the peanuts for 3–4 minutes until pale gold (they will darken as they cool), then lift onto paper towels with a slotted spoon; salt lightly. Pat the ikan bilis dry; in the same oil, fry them in two batches for 60–90 seconds per batch, stirring once, until crisp and deep gold; lift onto a separate sheet of paper; reserve the oil. Hard-boil the eggs: lower them into gently simmering water and cook for exactly 8 minutes for set yolks (or 7 minutes for slightly jammy); transfer immediately to iced water for 3 minutes, then peel and halve. Make the sambal paste; combine the drained dried chillies, fresh chillies, shallots, garlic, the 15 g ginger piece, and belacan in a blender or mortar with 2 tbsp of the reserved oil and process to a coarse paste. Heat 60 ml fresh oil in a wok or wide pan over medium heat; add the sambal paste and fry, stirring continuously, for 12–15 minutes, until the oil splits out around the edges and the paste turns deep brick-red; this long fry is what kills the raw bite of the aromatics. Stir in the red onion rings, tamarind water, palm sugar, and 0.5 tsp salt; simmer for 6–8 minutes more, until the onions are softened and the sambal has a glossy, jammy texture that holds a clean line when you drag a spoon across the pan; taste and balance — it should be hot, sweet, sour, and savoury in roughly equal measure. To serve: mound a portion of rice on each plate; surround with a hard-boiled egg half, a generous spoonful of sambal, a small heap of peanuts, a small heap of crispy anchovies, and a fan of cucumber slices; eat by mixing small amounts from each pile into each bite."}},{"id":132,"origin":{"ja":"スイス","en":"Switzerland","ro":"Elveția"},"name":{"ja":"ロスティ","en":"Rösti","ro":"Rösti"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ja":["蝋質ジャガイモ1kg（Yukon Gold、Charlotteまたは類似品種）、皮ごと","無塩バター60g、30gずつ2回分に分ける","中性油大さじ2（ひまわり油またはぶどう種油）、大さじ1ずつ2回分に分ける","細かい海塩小さじ1、好みで追加","挽きたての黒胡椒小さじ0.5","ナツメグ少々（任意、ベルン式の伝統）","小さい玉ねぎ1個（約80g）、ごく細かいみじん切り（任意、定番アレンジ）","熟成グリュイエール60g、粗くおろす（任意、より濃厚な仕上がり用）","細かく刻んだ新鮮なチャイブ大さじ1、飾り用"],"en":["1 kg waxy potatoes (Yukon Gold, Charlotte, or similar), unpeeled","60 g unsalted butter, in two 30 g portions","2 tbsp neutral oil (sunflower or grapeseed), in two 1 tbsp portions","1 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","Pinch of grated nutmeg (optional, traditional in Bernese versions)","1 small onion (about 80 g), very finely diced (optional, common variation)","60 g aged gruyère, coarsely grated (optional, for a richer finish)","1 tbsp finely chopped fresh chives, to garnish"],"ro":["1 kg cartofi cu pastă fermă (Yukon Gold, Charlotte sau similari), necurățați","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru (de floarea-soarelui sau de struguri), împărțit în două porții de 1 lingură","1 linguriță sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","Un vârf de nucșoară rasă (opțional, tradițional în versiunea berneză)","1 ceapă mică (aproximativ 80 g), tăiată foarte fin (opțional, variantă obișnuită)","60 g gruyère maturat, ras grosier (opțional, pentru finisare mai bogată)","1 lingură arpagic proaspăt tocat fin, pentru garnitură"]},"howIsMade":{"ja":"前日に、皮付きのままのジャガイモを塩を効かせた湯（1リットルあたり塩大さじ1）で8〜10分茹でる——ナイフを刺すと多少抵抗があり、中心は生のままがよい、湯切りして完全に冷ます、一晩、蓋をせずに冷蔵庫に入れ、表面を乾かしてでんぷんを固める。翌日、冷えたジャガイモの皮をむく——皮はするりとはがれるはずだ、ボックスチーズおろし器の粗い目で、長く均一な千切りに、温まらないよう手早く擦る。ボウルで擦ったジャガイモに塩、コショウ、ナツメグを振り、指先で軽く混ぜる——強く押さえず、千切りを長いまま保つ。24cmのフッ素加工またはよく育てた鋳鉄パンに、油大さじ1とバター30gを入れ中火で熱する、バターが泡立ち、ナッツ色になるまで、みじん切り玉ねぎを使うなら入れて、90秒〜2分、柔らかくほんのり色づくまで炒める。味付けしたジャガイモを均一に広げ、ヘラの背で軽く押さえて、厚さ1.5cm、直径約22cmのケーキ状にする——強く押さない、空気の隙間が中心の食感を生む、8〜10分動かさず焼き、底が濃い黄金色になり、ヘラを差し込むときれいにはがれるまで。平らな皿をパンに被せ、rösti を皿に返し、焼き面を上にしてスライドさせてパンに戻す、残りのバター30gと油大さじ1を縁に加え、生地の下に回るようにする、さらに7〜9分焼き、二面目も同じく濃い黄金色になり、中心が熱く柔らかい（小ぶりの包丁を中心に刺して抵抗がない）状態まで仕上げる。rösti をまな板に滑らせ、グリュイエール（使う場合）を散らして余熱で軽く溶かし、チャイブをのせて4等分に切る、目玉焼きを上に、燻製ハムやブラートヴルストを添えてすぐに供する。","en":"The day before, parboil the potatoes whole and unpeeled in well-salted water (1 tbsp salt per litre) for 8–10 minutes — a knife should meet some resistance, the centre should still be raw; drain and cool completely; refrigerate uncovered overnight so the surface dries and the starches firm up. The next day, peel the cold potatoes — the skins should slip off easily; grate them on the large holes of a box grater into long, even shreds, working briskly so they do not warm. In a bowl, season the grated potatoes with the salt, pepper, and nutmeg, and toss gently to distribute — use your fingertips, not a heavy hand, so the strands stay long. Heat 1 tbsp oil and 30 g of the butter in a 24 cm non-stick or well-seasoned cast-iron pan over medium heat until the butter foams and just turns nut-brown; add the diced onion (if using) and cook for 90 seconds–2 minutes, until soft and lightly golden. Add the seasoned potato to the pan in one even layer, lightly pressing with the back of a spatula to form a 1.5 cm cake about 22 cm across — do not pack it down hard, the air gaps are what crisp the inside; cook undisturbed for 8–10 minutes, until the underside is deep golden brown and pulls cleanly from the pan when you slide a spatula under it. Hold a flat plate over the pan, invert the rösti onto it, then slide it back into the pan with the cooked side up; add the remaining 30 g butter and 1 tbsp oil around the edges so they run under the cake; cook for a further 7–9 minutes, until the second side is equally deep golden and the centre is hot and tender (a paring knife pushed into the middle should meet no resistance). Slide the rösti onto a board, scatter with the grated gruyère if using (the residual heat will melt it lightly), top with chopped chives, and cut into 4 wedges; serve immediately with a fried egg on top, smoked ham, or Bratwurst."}},{"id":133,"origin":{"ja":"ルーマニア","en":"Romania","ro":"România"},"name":{"ja":"ソーセージと豆の煮込み","en":"Beans with Sausages","ro":"Fasole cu cârnați"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["乾燥白いんげん豆500g（カネリーニ、ナビー、ギリシャ巨大豆など）、冷水で一晩浸す","燻製豚肉ソーセージ4本（合計約500g；例：cârnați Pleșcoi、スモークポーランドソーセージなど）","燻製ベーコン150g（カイザー）または燻製スペアリブ、2cm角に切る（任意、深みを加える用）","大玉ねぎ2個（約350g）、みじん切り","中サイズのにんじん2本（約200g）、みじん切り","中サイズの赤パプリカ1個、みじん切り","にんにく4片、みじん切り","トマトペースト大さじ3","缶詰のクラッシュトマト200g（または新鮮なトマト2個、すりおろし）","ローリエ3枚","甘いパプリカパウダー小さじ1","ドライタイム小さじ0.5（または、新鮮なタイムの枝1本）","挽きたての黒胡椒小さじ0.5","細かい海塩小さじ1.5、好みで追加","ひまわり油60ml（または、ラード30g）","水1.5〜2リットル（または無塩のチキンストックでより濃厚に）","新鮮なディルかパセリのみじん切り大さじ2、仕上げ用","白ワインビネガー大さじ1（任意、最後に味を整える用）"],"en":["500 g dried white beans (cannellini, navy, or Greek elephant), soaked overnight in cold water","4 smoked pork sausages (about 500 g; e.g. cârnați Pleșcoi or smoked Polish sausage)","150 g smoked bacon (kaiser) or smoked pork ribs, cut into 2 cm pieces (optional, for extra depth)","2 large onions (about 350 g), finely diced","2 medium carrots (about 200 g), finely diced","1 medium red bell pepper, finely diced","4 garlic cloves, finely chopped","3 tbsp tomato paste","200 g canned crushed tomatoes (or 2 fresh tomatoes, grated)","3 bay leaves","1 tsp sweet paprika","0.5 tsp dried thyme (or 1 sprig fresh)","0.5 tsp freshly ground black pepper","1.5 tsp fine sea salt, plus more to taste","60 ml sunflower oil (or 30 g lard)","1.5–2 litres water (or unsalted chicken stock for richer flavour)","2 tbsp finely chopped fresh dill or parsley, to finish","1 tbsp white wine vinegar (optional, to balance at the end)"],"ro":["500 g fasole albă uscată (cannellini, navy sau fasole gigant grecească), înmuiată peste noapte în apă rece","4 cârnați afumați de porc (aproximativ 500 g, ex. cârnați Pleșcoi sau cârnați polonezi afumați)","150 g kaiser afumat sau coaste de porc afumate, tăiate bucăți de 2 cm (opțional, pentru profunzime)","2 cepe mari (aproximativ 350 g), tocate fin","2 morcovi medii (aproximativ 200 g), tocați mărunt","1 ardei kapia roșu mediu, tocat fin","4 căței de usturoi, tocați fin","3 linguri bulion (pastă de roșii)","200 g roșii sfărâmate din conservă (sau 2 roșii proaspete, date pe răzătoare)","3 foi de dafin","1 linguriță boia dulce","0,5 linguriță cimbru uscat (sau 1 crenguță proaspătă)","0,5 linguriță piper negru proaspăt măcinat","1,5 lingurițe sare fină de mare, plus după gust","60 ml ulei de floarea-soarelui (sau 30 g untură)","1,5–2 litri apă (sau supă neagră de pui pentru o aromă mai bogată)","2 linguri mărar sau pătrunjel proaspăt tocat fin, pentru finisare","1 lingură oțet de vin alb (opțional, pentru echilibru la final)"]},"howIsMade":{"ja":"前夜、乾燥豆を大きなボウルに入れ、少なくとも2リットルの冷水を注ぎ、8〜12時間浸す、豆はほぼ倍に膨らみ、ガスを生む糖分を多く失う。翌日、豆を水切りしてすすぐ、厚手の鍋に新鮮な水を5cmかぶる程度に入れ、煮立たせて蓋なしで10分煮る、再び水切りする——この最初の素早い茹でで豆の癖が和らぎ、最終的な煮込み時間が短くなる。豆を鍋に戻し、新鮮な水（または出汁）1.5リットル、燻製ベーコン（使う場合）、ローリエ2枚を加える、穏やかな沸騰にして半蓋で50〜60分煮込む——豆はちょうど柔らかくなり、崩れない程度、塩はまだ入れない（この段階の塩は皮を硬くする）。豆を煮ている間に、深めの広いフライパンに油を入れ中火で熱する、みじん切り玉ねぎとひとつまみの塩を加え、頻繁にかき混ぜながら8〜10分、柔らかく縁が黄金色になるまで炒める、にんじんと赤パプリカを加え、さらに5〜6分炒めて柔らかくする。野菜をフライパンの片側に寄せ、空いたところににんにくを入れて30秒炒め、続けてパプリカパウダーとタイムを加え、20〜30秒香りが立つまで焙る、トマトペーストとクラッシュトマトを加え、3〜4分混ぜながら煮て、トマトが濃い赤になり油が縁に分離するまで。ソーセージのうち2本を2cm厚の輪切りにする、残り2本は仕上げにのせるため丸ごと残す、輪切りソーセージをトマトベースに加え、2〜3分焼いて脂を出す。豆鍋を煮汁ごとトマトベースに注ぎ、残りのローリエ、塩小さじ1.5、黒胡椒を加える、丸ごとのソーセージを鍋に埋め込む、蓋なしで35〜45分、ときどきかき混ぜながら煮込む、豆が柔らかくなり、煮汁がスプーンの背を覆う薄いとろみのソースになるまで、詰まりすぎたら水を少量加える。味見し、塩で整え、必要なら白ワインビネガーを加える（少量の酸が燻製の風味を引き立てる）、丸ごとのソーセージを取り出し、斜めにスライスする、深皿に豆をよそい、それぞれにソーセージのスライスを扇状に重ね、刻んだディルを散らし、ピクルスとカントリーブレッドまたはポレンタとともに供する。","en":"The night before, place the dried beans in a large bowl, cover with at least 2 litres of cold water, and leave to soak for 8–12 hours; they will roughly double in size and lose much of the gas-producing sugars. The next day, drain and rinse the beans; put them in a heavy pot with fresh water to cover by 5 cm, bring to a boil, and cook uncovered for 10 minutes; drain again — this first quick boil mellows the beans and shortens the final cooking time. Return the beans to the pot with 1.5 litres of fresh water (or stock), the smoked bacon (if using), and 2 of the bay leaves; bring to a gentle simmer and cook partially covered for 50–60 minutes — the beans should be just tender but not falling apart; do not salt yet (salt at this stage toughens the skins). While the beans simmer, heat the oil in a wide deep pan over medium heat; add the diced onions and a generous pinch of salt and cook for 8–10 minutes, stirring often, until soft and golden brown at the edges; add the carrots and red bell pepper and cook for another 5–6 minutes, until softened. Push the vegetables to one side, add the garlic to the empty space and cook for 30 seconds, then stir in the paprika and thyme — toast for 20–30 seconds until fragrant; add the tomato paste and crushed tomatoes and cook, stirring, for 3–4 minutes, until the tomato is deeper red and the oil splits out around the edges. Slice 2 of the smoked sausages into 2 cm rounds; keep the other 2 whole for the top; add the sliced sausage to the tomato base and cook for 2–3 minutes to render some fat. Tip the bean pot and its liquid into the tomato base, add the remaining bay leaf, the 1.5 tsp salt, and the black pepper; bury the whole sausages in the stew; simmer uncovered for 35–45 minutes, stirring occasionally, until the beans are soft and the liquid has thickened to a thin gravy that coats the back of a spoon; add a splash of water if it tightens too much. Taste, adjust with salt, and add the white wine vinegar if using (a touch of acid brightens the smoke); lift out the whole sausages and slice on the diagonal; ladle the beans into deep bowls, top each with a fan of sausage slices, scatter with chopped dill, and serve with pickles and crusty bread or polenta."}},{"id":134,"origin":{"ja":"ハンガリー","en":"Hungary","ro":"Ungaria"},"name":{"ja":"チキン・パプリカシュ","en":"Chicken Paprikash","ro":"Chicken Paprikash"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["骨付き皮付きの鶏もも肉とドラムスティック1.5kg（約8切れ）","大玉ねぎ2個（約400g）、みじん切り","ハンガリーの甘いパプリカパウダー大さじ3（Édesnemes、できればカロチャまたはセゲド産）、必要に応じてハンガリーの辛いパプリカパウダー小さじ0.5（任意）","にんにく3片、みじん切り","中サイズの赤パプリカ1個、みじん切り","中サイズのトマト1個（約100g）、皮をむいてみじん切り（または、トマトペースト大さじ2）","ラード60g（または、中性油大さじ4）","塩を加えていない温かい鶏ストック500ml、または水","全脂サワークリーム200g（脂肪分20%以上——軽いサワークリームは分離するので使わない）","中力粉大さじ1","細かい海塩小さじ1.5、好みで追加","挽きたての黒胡椒小さじ0.5","キャラウェイシード小さじ1（任意、一部地域で伝統的）","新鮮なディルまたはパセリ、刻む、飾り用"],"en":["1.5 kg bone-in, skin-on chicken thighs and drumsticks (about 8 pieces)","2 large onions (about 400 g), finely diced","3 tbsp sweet Hungarian paprika (Édesnemes, preferably from Kalocsa or Szeged), plus 0.5 tsp hot Hungarian paprika (optional)","3 garlic cloves, finely chopped","1 medium red bell pepper, finely diced","1 medium tomato (about 100 g), peeled and finely diced (or 2 tbsp tomato paste)","60 g lard (or 4 tbsp neutral oil)","500 ml hot unsalted chicken stock or water","200 g full-fat sour cream (at least 20% fat — do NOT use light sour cream, it will split)","1 tbsp plain (all-purpose) flour","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","1 tsp caraway seeds (optional, traditional in some regions)","Fresh dill or parsley, chopped, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","2 cepe mari (aproximativ 400 g), tocate fin","3 linguri paprika dulce maghiară (Édesnemes, de preferință din Kalocsa sau Szeged), plus 0,5 linguriță paprika iute maghiară (opțional)","3 căței de usturoi, tocați fin","1 ardei gras roșu mediu, tăiat cuburi mici","1 roșie medie (aproximativ 100 g), curățată și tăiată cuburi mici (sau 2 linguri pastă de roșii)","60 g untură (sau 4 linguri ulei neutru)","500 ml supă de pui fierbinte nesărată sau apă","200 g smântână grasă (cel puțin 20% grăsime — NU smântână ușoară, se taie)","1 lingură făină albă","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","1 linguriță semințe de chimen (opțional, tradițional în unele regiuni)","Mărar sau pătrunjel proaspăt tocat, pentru garnitură"]},"howIsMade":{"ja":"鶏肉をキッチンペーパーで拭き、両面に塩小さじ1と黒胡椒で味付け、常温で15分休ませる。28cmの厚手のダッチオーブンか広めの深いフライパンにラードを入れ、中強火で溶かす、2回に分けて、皮を下にして4〜5分、もう一方を3分、皮がしっかり黄金色になるまで焼く——詰め込みすぎない、皿に取り出す。火を中火に落とし、出た脂を大さじ3ほど残してすべて捨てる、玉ねぎとひとつまみの塩を加え、頻繁にかき混ぜながら12〜15分炒める、柔らかく、艶やかで、しっかり黄金色になるまで——このじっくり炒める工程がパプリカシュの味の土台だ。にんにく、赤パプリカ、（使うなら）キャラウェイシードを加え、さらに2〜3分、パプリカが軽く柔らかくなるまで炒める。フライパンを完全に火から下ろす、甘いパプリカパウダー（と必要なら辛いパプリカ）を入れる——パプリカは直火で焦げて苦くなるため、入れるときは必ず火から下ろす、30秒混ぜて玉ねぎが深い煉瓦色に染まり、温かく甘い香りが立つまで。フライパンを中火に戻す、みじん切りのトマト（またはトマトペースト）を加え、1分混ぜる、温かいストックと残りの塩小さじ0.5を注ぎ、鶏肉を皮を上にしてソースに戻す、穏やかに煮立たせる。蓋をして弱火で35〜45分煮込む、鶏肉が骨から簡単に外れ、中心温度が75°Cに達するまで、鶏肉を温めた皿に移し、アルミホイルで軽く覆い、ソースを仕上げる。サワークリームに小麦粉を泡立て器で滑らかに混ぜ、ソースを一杯加えて温度をなじませる、火を止めた状態でなじませたクリームをフライパンに戻し、絹のように滑らかになるまで混ぜる、鶏肉を温める程度だけソースに戻し、塩で味を整え、ノケドリや生パスタ、バターヌードルにかけて、刻んだディルを散らして供する。","en":"Pat the chicken dry with paper towels and season both sides with 1 tsp of the salt and the black pepper; rest at room temperature for 15 minutes. Melt the lard in a heavy 28 cm Dutch oven or wide deep pan over medium-high heat; working in two batches, sear the chicken skin-side down for 4–5 minutes, then 3 minutes on the other side, until the skin is deep golden — do not crowd the pan; lift onto a plate. Reduce the heat to medium and pour off all but about 3 tbsp of the rendered fat; add the onions and a pinch of salt and cook for 12–15 minutes, stirring often, until soft, glossy, and fully golden — this slow sweat is the foundation of paprikash flavour. Add the garlic, red bell pepper, and caraway seeds (if using) and cook for another 2–3 minutes, until the pepper is just softened. Take the pan off the heat completely; stir in the sweet paprika (and hot paprika if using) — paprika scorches and turns bitter on direct heat, so the pan must be off when it goes in; stir for 30 seconds until the onions are stained a deep brick red and the spice smells warm and sweet. Return the pan to medium heat; add the diced tomato (or tomato paste) and stir for 1 minute; pour in the hot stock and the remaining 0.5 tsp salt, then nestle the chicken back into the sauce, skin-side up; bring to a gentle simmer. Cover and braise on the lowest heat for 35–45 minutes, until the chicken pulls easily from the bone and the internal temperature reads 75°C; lift the chicken onto a warm plate and tent with foil while you finish the sauce. Whisk the flour into the sour cream until smooth, then whisk in a ladle of the hot pan sauce to temper; off the heat, pour the tempered cream back into the pan and stir until silky; return the chicken to the sauce just to warm through, taste and adjust salt, then serve over nokedli, fresh pasta, or buttered noodles with chopped dill on top."}},{"id":135,"origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"パスタ・アッラ・ノルマ","en":"Pasta alla Norma","ro":"Pasta alla Norma"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"ja":["中サイズのなす2本（合計約700g）、皮ごと、2cm角に切る","なすの塩漬け用に細かい海塩小さじ1.5、パスタを茹でる水用に追加","なすを揚げ焼きするためのエクストラバージンオリーブオイル300ml","リガトーニ、ペンネリガーテ、またはマッケローニ400g","ソース用のエクストラバージンオリーブオイル大さじ3","にんにく3片、薄切り","乾燥唐辛子のフレーク小さじ0.5（任意）","ホールトマト缶800g（できればサンマルツァーノ）、手でつぶす、またはパッサータ700g","グラニュー糖小さじ1（トマトが酸っぱい場合のみ）","挽きたての黒胡椒小さじ0.5","新鮮なバジル大1束（約30g）、葉を摘んで手でちぎる","リコッタサラータ120g、細かくおろす、仕上げ用に追加","パスタを茹でる水に入れる粗い海塩大さじ1"],"en":["2 medium aubergines (about 700 g total), unpeeled, cut into 2 cm cubes","1.5 tsp fine sea salt for salting the aubergine, plus more for the pasta water","300 ml extra-virgin olive oil for shallow-frying the aubergine","400 g rigatoni, penne rigate, or maccheroni","3 tbsp extra-virgin olive oil for the sauce","3 garlic cloves, sliced thin","0.5 tsp dried chilli flakes (optional)","800 g whole peeled tomatoes (San Marzano if available), crushed by hand, or 700 g passata","1 tsp caster sugar (only if the tomatoes are sharp)","0.5 tsp freshly ground black pepper","1 large bunch fresh basil (about 30 g), leaves picked and torn","120 g ricotta salata, finely grated, plus more to serve","1 tbsp coarse sea salt for the pasta water"],"ro":["2 vinete medii (aproximativ 700 g în total), necurățate, tăiate cuburi de 2 cm","1,5 lingurițe sare fină de mare pentru asezonarea vinetelor, plus mai multă pentru apa pastelor","300 ml ulei de măsline extravirgin pentru prăjit vinetele","400 g rigatoni, penne rigate sau maccheroni","3 linguri ulei de măsline extravirgin pentru sos","3 căței de usturoi, feliați subțire","0,5 linguriță fulgi de ardei iute uscat (opțional)","800 g roșii întregi, decojite (San Marzano dacă e posibil), zdrobite cu mâna, sau 700 g pasată","1 linguriță zahăr tos (doar dacă roșiile sunt acrișoare)","0,5 linguriță piper negru proaspăt măcinat","1 legătură mare de busuioc proaspăt (aproximativ 30 g), frunzele rupte","120 g ricotta salata, rasă fin, plus în plus pentru servit","1 lingură sare grunjoasă de mare pentru apa pastelor"]},"howIsMade":{"ja":"なすの角切りに細かい塩小さじ1.5を加え、ザルに入れてボウルの上で30分置き、苦みのある水分を引き出す、これでなすが揚げる時に吸う油の量も減る、キッチンペーパーで軽く押さえ、水気を拭く。広めの深いフライパンにオリーブオイル300mlを入れて170°Cに熱する、なすひとつでテスト——勢いよく弾ければOK、なすを3回に分け、1回3〜4分、頻繁にひっくり返しながら、全面が濃いきつね色になり中まで柔らかくなる（ナイフがすっと通る）まで揚げる、穴あきお玉でキッチンペーパーに取って油を切る、脇に置く。なすを揚げている間に、大鍋に水4リットルと粗塩大さじ1を入れて沸騰させる。広いソテーパンにオリーブオイル大さじ3を入れ中火で熱する、スライスしたにんにくと唐辛子フレーク（使う場合）を入れ、60〜90秒、にんにくの縁が淡い黄金色になるが焦げない程度に炒める。つぶしたトマト、（必要なら）砂糖、塩小さじ0.5、黒胡椒を加える、混ぜて軽い沸騰にする、12〜15分、ときどきかき混ぜながら煮込み、ソースが少しとろみ、油が表面に上がるまで、最後の1分でちぎったバジルの半量を加える。沸騰した湯にパスタを入れ、袋の表示より1分短く茹でアルデンテにする、でんぷん質のゆで汁を250ml取り置き、湯切りする。揚げたなすをトマトソースに混ぜ、ゆでパスタを加える、中火で1〜2分、必要に応じてゆで汁を加えながら勢いよく和え、ソースがすべての具材につやよく絡むようにする——フライパンを傾けて流れる程度、でも水っぽくない状態に。火を止め、おろしリコッタサラータの半量と残ったバジルのほとんどを加えて一度だけ和える、温めた4つの皿に分け、それぞれにさらにリコッタサラータと残りのバジルの葉、そして生のオリーブオイルを回しかけて、すぐに供する。","en":"Toss the aubergine cubes with the 1.5 tsp fine salt in a colander and leave to drain over a bowl for 30 minutes — this draws out bitter water and stops the aubergine from drinking too much oil during frying; press lightly with a paper towel and pat dry. Heat the 300 ml olive oil in a wide deep frying pan to 170°C; test with a single aubergine cube — it should sizzle briskly; fry the aubergine in three batches for 3–4 minutes per batch, turning often, until deeply golden on all sides and tender inside (a knife should pass through easily); lift onto paper towels with a slotted spoon to drain; reserve. While the aubergine fries, bring a large pot with 4 litres of water and 1 tbsp coarse salt to a rolling boil. In a wide sauté pan, heat the 3 tbsp olive oil over medium heat; add the sliced garlic and chilli flakes (if using) and cook for 60–90 seconds — the garlic should just turn pale gold around the edges, never brown. Add the crushed tomatoes, the sugar (if using), 0.5 tsp salt, and the black pepper; stir and bring to a simmer; cook for 12–15 minutes, stirring occasionally, until the sauce has thickened slightly and the oil rises to the surface; tear in half of the basil for the last minute. Drop the pasta into the boiling water and cook 1 minute less than the package says for al dente; reserve 250 ml of starchy pasta water, then drain. Fold the fried aubergine into the tomato sauce, then add the drained pasta; toss vigorously over medium heat for 1–2 minutes, adding splashes of pasta water as needed, until the sauce clings glossy to every piece — it should be loose enough to flow when you tilt the pan but not watery. Off the heat, scatter half the grated ricotta salata and most of the remaining basil and toss once; divide between four warmed bowls, finish each with more ricotta salata, the last basil leaves, and a drizzle of raw olive oil; serve immediately."}},{"id":137,"origin":{"ja":"トルクメニスタン","en":"Turkmenistan","ro":"Turkmenistan"},"name":{"ja":"イチレクリ","en":"Ichlekli","ro":"Ichlekli"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["中力粉500g、打ち粉用に少量追加","細かい海塩小さじ1","ぬるま湯240ml","中性油大さじ1（ひまわり油またはぶどう種油）","ラム肩肉または牛肩ロース500g、細かいみじん切り（または大きめに切ってフードプロセッサーで断続的に砕く）","ラムテールファットまたは牛脂100g、細かい角切り（または、無塩バター30gで代用）","大玉ねぎ2個（約350g）、みじん切り","蝋質ジャガイモ200g、皮をむいて5mm角切り（任意だが伝統的）","細かい海塩小さじ1.5","挽きたての黒胡椒小さじ1","クミンパウダー小さじ1","コリアンダーパウダー小さじ0.5","乾燥赤唐辛子フレーク小さじ0.5（任意）","Lサイズの卵黄1個と牛乳大さじ1を合わせたもの、艶出し用"],"en":["500 g plain (all-purpose) flour, plus extra for rolling","1 tsp fine sea salt","240 ml warm water","1 tbsp neutral oil (sunflower or grapeseed)","500 g lamb shoulder or beef chuck, finely minced (or coarsely diced and pulsed in a processor)","100 g lamb-tail fat or beef suet, finely diced (or 30 g unsalted butter as substitute)","2 large onions (about 350 g), finely diced","200 g waxy potatoes, peeled and diced into 5 mm cubes (optional but traditional)","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground coriander","0.5 tsp dried red pepper flakes (optional)","1 large egg yolk, beaten with 1 tbsp milk, for brushing"],"ro":["500 g făină albă obișnuită, plus pentru întins","1 linguriță sare fină de mare","240 ml apă caldă","1 lingură ulei neutru (de floarea-soarelui sau de struguri)","500 g umăr de miel sau pulpă de vită, tocate fin (sau cuburi mărunte pulsate într-un robot)","100 g grăsime de coadă de miel sau seu de vită, tăiate fin (sau 30 g unt nesărat ca substitut)","2 cepe mari (aproximativ 350 g), tocate fin","200 g cartofi cu pastă fermă, curățați și tăiați cuburi de 5 mm (opțional, dar tradițional)","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță coriandru măcinat","0,5 linguriță fulgi de ardei iute uscat (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru uns"]},"howIsMade":{"ja":"生地を作る、広めのボウルで小麦粉と塩を泡立て器で混ぜる、中央にくぼみを作り、温水と油を注ぎ、木べらでひと固まりになるまで混ぜる、打ち粉をした台で6〜8分こねる、滑らかで、しっかりとして、弾力がある——パン生地よりやや固めに仕上げる、ラップに包み、30分常温で休ませる、その間に詰め物を準備する。大きなボウルに、ひき肉、脂、玉ねぎ、（使うなら）ジャガイモの角切り、塩、コショウ、クミン、コリアンダー、唐辛子フレークを入れ、手で1分混ぜる、粘り気が出てしっかりまとまるまで、あらかじめ加熱しない——詰め物は生地の中で火を通す。オーブンを220°C（425°F／ファン200°C）に予熱し、中段に厚手の天板を逆さに、またはピザストーンを置いて、少なくとも20分しっかり加熱する、この熱い表面が底をパリッとさせる。休ませた生地を2等分する、打ち粉をした台で、片方を直径32cm、厚さ約2mmに伸ばす——縁を中央より薄くして、合わせ目が厚くならないようにする。円盤をクッキングシートにスライドさせる、詰め物を生地全体に2cmの縁を残して広げ、1.5cmの厚さに軽く押さえる。もう片方の生地も32cmに伸ばして上に乗せる、縁をしっかり押さえて2枚の生地を合わせ、縁を内側にロールして指でつまみ、ロープ状にきつく閉じて肉汁が漏れないようにする。卵黄の艶出しを表面に塗り、フォークで中央に6〜8カ所穴を開けて蒸気の逃げ道を作る、クッキングシートごとパイを熱い天板にスライドさせる、30〜35分焼く——表面が濃いきつね色になり、底を叩くと空洞音がするまで。パイを5分まな板の上で休ませる（蒸気が落ち着き詰め物が固まる）、鋭いナイフで8等分に切り、緑茶、プレーンヨーグルト、または発酵乳と一緒にすぐに供する。","en":"Make the dough; whisk the flour and salt in a wide bowl; make a well, pour in the warm water and oil, and stir with a wooden spoon until a shaggy dough forms; knead on a lightly floured surface for 6–8 minutes until smooth, firm, and elastic — slightly stiffer than bread dough; wrap in cling film and rest at room temperature for 30 minutes while you prepare the filling. In a large bowl, combine the minced lamb, fat, onions, potato cubes (if using), salt, pepper, cumin, coriander, and pepper flakes; mix with your hands for 1 minute until the mixture is sticky and well bound; do not pre-cook — the filling cooks inside the dough. Heat the oven to 220°C (425°F / fan 200°C) and place an upturned heavy baking tray or pizza stone on the middle rack to heat through for at least 20 minutes; the hot surface is what crisps the bottom. Divide the rested dough into two equal pieces; on a lightly floured surface, roll one piece into a 32 cm round, about 2 mm thick — work the edges thinner than the centre so the seal will not be too thick. Slide the round onto a sheet of baking parchment; spread the filling evenly over the disc, leaving a 2 cm border, and press it down lightly into a 1.5 cm layer. Roll out the second piece of dough to the same 32 cm round and lay it on top; press the two layers together firmly around the edge, then roll and pinch the rim inward into a tight rope-like border so no juice can escape. Brush the top with the egg-yolk glaze and prick the centre in 6–8 places with a fork to let steam vent; slide the pie, on its parchment, onto the hot tray in the oven; bake for 30–35 minutes, until the top is deep golden brown and the bottom sounds hollow when you tap it. Rest the pie on a board for 5 minutes (the steam settles and the filling firms up), then cut into 8 wedges with a sharp knife; serve hot with green tea, plain yoghurt, or soured milk."}},{"id":138,"origin":{"ja":"ウクライナ","en":"Ukraine","ro":"Ucraina"},"name":{"ja":"キエフ風チキン","en":"Chicken Kiev","ro":"Pui Kiev"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["無塩バター100g、室温で柔らかくする","にんにく3片、ごく細かいみじん切り（または、にんにくペースト大さじ1）","イタリアンパセリ30g、ごく細かいみじん切り","レモン汁大さじ1","細かい海塩小さじ0.5","挽きたての黒胡椒小さじ0.25","皮なし骨なしの鶏むね肉大4枚（1枚約200g）","むね肉の下味用に細かい海塩小さじ1","むね肉の下味用に挽きたての黒胡椒小さじ0.5","中力粉80g","Lサイズの卵2個、冷水大さじ1と合わせて溶く","パン粉（パン粉または細かい乾燥パン粉）150g","中性油750ml（ひまわり油または菜種油）、揚げ用","無塩バター大さじ1、油の仕上げ用（任意、香ばしい衣に）","レモンのくし切りとパセリ少々、添え用"],"en":["100 g unsalted butter, softened to room temperature","3 garlic cloves, very finely minced (or 1 tbsp garlic paste)","30 g flat-leaf parsley, very finely chopped","1 tbsp lemon juice","0.5 tsp fine sea salt","0.25 tsp freshly ground black pepper","4 large skinless chicken breasts (about 200 g each)","1 tsp fine sea salt for the breasts","0.5 tsp freshly ground black pepper for the breasts","80 g plain (all-purpose) flour","2 large eggs, beaten with 1 tbsp cold water","150 g panko or fine dry breadcrumbs","750 ml neutral oil (sunflower or rapeseed), for deep-frying","1 tbsp unsalted butter, for finishing the oil (optional, for a nuttier crust)","Lemon wedges and a small bunch of parsley, to serve"],"ro":["100 g unt nesărat, înmuiat la temperatura camerei","3 căței de usturoi, tocați foarte fin (sau 1 lingură pastă de usturoi)","30 g pătrunjel cu frunze plate, tocat foarte fin","1 lingură suc de lămâie","0,5 linguriță sare fină de mare","0,25 linguriță piper negru proaspăt măcinat","4 piepți mari de pui dezosați și fără piele (aproximativ 200 g fiecare)","1 linguriță sare fină de mare pentru piepți","0,5 linguriță piper negru proaspăt măcinat pentru piepți","80 g făină albă obișnuită","2 ouă mari, bătute cu 1 lingură apă rece","150 g panko sau pesmet fin uscat","750 ml ulei neutru (de floarea-soarelui sau de rapiță), pentru prăjire adâncă","1 lingură unt nesărat, pentru aromatizarea uleiului (opțional, pentru o crustă cu unt prăjit)","Felii de lămâie și o legătură mică de pătrunjel, pentru servit"]},"howIsMade":{"ja":"ハーブバターを作る、柔らかくしたバターをボウルに入れ、にんにくのみじん切り、刻んだパセリ、レモン汁、塩小さじ0.5、コショウ小さじ0.25を加え、均一になるまで混ぜる、ラップに移し、長さ12cm、太さ2cmの棒状に成形して、しっかり包み、最低1時間冷凍する、切れる固さになるまで。冷えたバターの棒を4等分の円柱に切る、鶏肉の準備をする間、冷凍庫に戻しておく——バターが冷たくないと揚げ中に漏れ出す。よく切れる包丁で各鶏むね肉の厚い側に深い水平のポケットを作る、反対側の端から約1cm手前で止め、貫通させない、本のように開き、ラップ2枚の間に挟み、肉たたきで中心から外へ均一に5mmの厚さまで叩く、内側に塩小さじ1とコショウ小さじ0.5で下味をつける。叩いた各むね肉の中央に冷たいバターの円柱を1本ずつ置く、長い2辺をバターにかぶせ、空気を抜きながらきつく巻いて密閉した円柱状にし、余分なフラップは下に押し込む、それぞれをラップで包み、30分冷蔵する。浅い容器を3つ用意する：1つは小麦粉、1つは溶き卵と水、1つはパン粉、包みを取り、小麦粉をまぶし余分を払い、卵にくぐらせ水気を切り、パン粉をしっかり全面に押しつける、卵とパン粉を二度づけする——この二重衣がバターの噴出を防ぐ、残り3つも同じく行う。深鍋で油を170°Cに熱する、パン粉ひとつで温度をテスト——20秒で淡い黄金色になり音を立てるべきだ、キーウを2つ慎重に入れ、6〜7分、一度返しながら、全面が深い黄金色になるまで揚げる、トレイの上に置いた網に取って油を切る、残り2つも同様に。必要に応じてオーブンで仕上げる、揚げたキーウを天板にのせた網に置き、180°C（350°F）で8〜10分焼く、温度プローブを肉（バターではなく）に差し込み70°Cになるまで、こうすれば衣を焦がさず肉までしっかり火が入る。網の上で2分休ませてから皿に盛る、テーブルで各キーウの上部を突き刺すと——溶けたハーブバターが金色の流れとして噴き出す、レモンのくし切りとパセリを添え、マッシュポテトかバターライスとともにすぐに供する。","en":"Make the herb butter; beat the softened butter in a bowl with the minced garlic, chopped parsley, lemon juice, 0.5 tsp salt, and 0.25 tsp pepper until evenly combined; scrape onto cling film, shape into a 12 cm long, 2 cm thick log, wrap tightly, and freeze for at least 1 hour, until firm enough to slice. Slice the chilled butter log into 4 equal cylinders; return them to the freezer while you prepare the chicken — the butter must be very cold or it will leak out during frying. With a sharp knife, cut a deep horizontal pocket into the thick side of each chicken breast, stopping about 1 cm before the opposite edge — do not cut through; open the breast like a book, lay it between two sheets of cling film, and pound gently with a meat mallet to an even 5 mm thickness, working from the centre outwards; season the inside with 1 tsp salt and 0.5 tsp pepper. Place one cold butter cylinder along the centre of each pounded breast; fold the two long sides over the butter, then roll the breast tightly into a sealed cylinder, pressing to expel air; tuck any loose flaps underneath; wrap each parcel in cling film and refrigerate for 30 minutes. Set up three shallow bowls: one with the flour, one with the beaten eggs and water, one with the breadcrumbs; take a parcel, dip in flour and pat off excess, then egg, draining well, then breadcrumbs — press firmly on all sides; dip the egg and breadcrumbs again for a second coat: this double coat is what stops the butter from blowing out during frying; repeat with the other three. Heat the oil in a deep pan to 170°C; test with a breadcrumb — it should sizzle and turn pale gold in 20 seconds; lower two Kievs in carefully and fry for 6–7 minutes, turning once, until the crust is deeply golden brown all over; lift onto a wire rack set over a tray; repeat with the other two. Finish in the oven if needed; place the fried Kievs on a rack over a baking tray and bake at 180°C (350°F) for 8–10 minutes, until a temperature probe pushed into the chicken (not the butter) reads 70°C; this ensures the chicken is cooked through without overcooking the crust. Rest for 2 minutes on the rack, then plate; pierce the top of each Kiev at the table — the molten herb butter will spill out in a golden stream; serve immediately with lemon wedges and parsley, alongside mashed potatoes or buttered rice."}},{"id":139,"origin":{"ja":"リトアニア","en":"Lithuania","ro":"Lituania"},"name":{"ja":"ツェペリナイ","en":"Cepelinai","ro":"Cepelinai"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["生の蝋質ジャガイモ1.5kg（Yukon Goldや類似品種）、皮をむいて計量","粉質ジャガイモ500g（Russet または King Edward）、皮をむいて計量","レモン汁大さじ1またはクエン酸小さじ1（生のすりおろしジャガイモが灰色になるのを防ぐ）","生地用に細かい海塩小さじ1","コーンスターチ大さじ2 — 生のジャガイモが非常に水っぽい場合のみ","粗くひいた豚肩肉500g（または、豚50% + 牛50%）","中サイズの玉ねぎ1個（約150g）、ごく細かいみじん切り","詰め物用に細かい海塩小さじ1","挽きたての黒胡椒小さじ0.5","ドライマジョラムまたはドライセイボリー小さじ1","詰め物用に冷水60ml","燻製ベーコン200g、角切り","大玉ねぎ1個（約200g）、薄切り","全脂サワークリーム200g","ディルまたはパセリ、細かく刻む、飾り用","茹で湯用に粗い海塩大さじ1"],"en":["1.5 kg raw waxy potatoes (Yukon Gold or similar), peeled and weighed","500 g floury potatoes (Russet or King Edward), peeled and weighed","1 tbsp lemon juice or 1 tsp citric acid (to prevent the raw grated potato from greying)","1 tsp fine sea salt for the dough","2 tbsp cornflour (cornstarch) — only if the raw potato is very wet","500 g coarsely minced pork shoulder (or 50% pork + 50% beef)","1 medium onion (about 150 g), very finely diced","1 tsp fine sea salt for the filling","0.5 tsp freshly ground black pepper","1 tsp dried marjoram or dried savory","60 ml cold water for the filling","200 g smoked streaky bacon, cubed","1 large onion (about 200 g), finely sliced","200 g full-fat sour cream","Dill or parsley, finely chopped, to garnish","1 tbsp coarse sea salt for the cooking water"],"ro":["1,5 kg cartofi cu pastă fermă (Yukon Gold sau similari), curățați și cântăriți după curățare","500 g cartofi făinoși (Russet sau King Edward), curățați și cântăriți după curățare","1 lingură suc de lămâie sau 1 linguriță acid citric (pentru a împiedica înnegrirea cartofului ras crud)","1 linguriță sare fină de mare pentru aluat","2 linguri amidon de porumb — doar dacă aluatul rămâne prea umed","500 g carne de porc tocată grosier (sau 50% porc + 50% vită)","1 ceapă medie (aproximativ 150 g), tocată foarte fin","1 linguriță sare fină de mare pentru umplutură","0,5 linguriță piper negru proaspăt măcinat","1 linguriță maghiran uscat sau cimbru de munte uscat","60 ml apă rece pentru umplutură","200 g bacon afumat striat, tăiat cuburi","1 ceapă mare (aproximativ 200 g), feliată fin","200 g smântână grasă","Mărar sau pătrunjel, tocat fin, pentru garnitură","1 lingură sare grunjoasă de mare pentru apa de fierbere"]},"howIsMade":{"ja":"まず詰め物を作り、風味をなじませる、豚ひき肉、ごく細かいみじん切り玉ねぎ、塩小さじ1、コショウ、マジョラム、冷水60mlをボウルに入れ、手で1〜2分こねて粘りが出てよくまとまるまで混ぜる、ラップをかけて冷蔵庫に入れ、ジャガイモ生地を準備する間冷やす。粉質ジャガイモ500gを丸ごと皮ごと塩水で25〜30分、しっかり柔らかくなるまで茹でる、湯切りして熱いうちに皮をむき、ライサーか細かくマッシュする、トレイに広げて室温まで冷ます——温かいマッシュは次の段階で生のジャガイモを煮てしまう。ボックスチーズおろし器の細かい面で1.5kgの生ジャガイモを、きれいなふきんを敷いた大きなボウルにすりおろす、ふきんをまとめ、もう一つのボウルの上で強く絞り、できるだけ多くの汁を絞り出す、約250mlの汁が得られるはず；5分置く。絞り汁の透明な水を慎重に注ぎ捨て、底に沈んだ白いでんぷんを残す、このでんぷんを擂りおろした絞りジャガイモに戻して混ぜる——これがcepelinaiをまとめる天然の結着剤、冷ましたマッシュ、レモン汁、塩小さじ1を加える、手で2〜3分こねて、粘りと弾力のある生地にする、生地がまだ湿っていればコーンスターチを足す。濡らした手で生地を8等分（1個約220g）に分ける、濡らした手のひらで1つを12 × 8cmの楕円形に伸ばし、中央に約60gの冷えた詰め物を置き、生地を持ち上げて詰め物を包み、縁をつまんで完全に密封する、長さ12cmの飛行船形に整える、蒸気や水が入る亀裂は作らない。広めの深鍋に4リットルの水と粗塩大さじ1を入れ、静かに沸騰させる（強い沸騰ではcepelinaiが壊れる）、2回に分けて鍋に入れ、底につかないように一度だけそっとかき混ぜ、最も穏やかな沸騰で25〜30分茹でる、表面がマットから半透明になり、上に浮き上がるまで。茹でている間にソースを作る、角切りベーコンを乾いたフライパンに入れ、中火で6〜8分、脂が出てカリッとするまで焼く、スライス玉ねぎを加え、さらに5〜6分、柔らかくほんのり色づくまで炒める、火を止めて混ぜ、温かくしておく。茹で上がったcepelinaiを穴あきお玉で温めた皿に取る——1人2個、ベーコンと玉ねぎの混ぜ物を脂ごとたっぷりかけ、冷たいサワークリームをひと盛り、刻んだディルを散らす、すべてが熱く、中心がジューシーなうちに直ちに供する。","en":"Make the filling first so the flavours marry; mix the minced pork, finely diced onion, 1 tsp salt, pepper, marjoram, and 60 ml cold water in a bowl with your hand for 1–2 minutes, until the mixture is sticky and well bound; cover and chill while you prepare the potato dough. Boil the 500 g floury potatoes whole and unpeeled in salted water for 25–30 minutes, until very tender; drain, peel while hot, and pass through a ricer or mash smoothly; spread out on a tray to cool to room temperature — hot mash would cook the raw potato in the next step. Grate the 1.5 kg waxy potatoes on the fine side of a box grater into a large bowl lined with a clean kitchen towel; gather the towel and squeeze hard over a second bowl to extract as much liquid as possible; you should end up with about 250 ml of liquid; leave it to settle for 5 minutes. Carefully pour off the clear water from the bowl of squeezed liquid, leaving the white starch settled at the bottom; scrape this starch back into the squeezed grated potato — it is the natural binder that holds the dumplings together; add the cooled mashed potato, the lemon juice, and 1 tsp salt; mix vigorously by hand for 2–3 minutes, until you have a sticky, elastic dough; add the cornflour only if the dough still feels wet. With wet hands, divide the dough into 8 equal pieces (about 220 g each); flatten one piece on a wet palm into a 12 × 8 cm oval, place about 60 g of the chilled filling in the centre, then wrap the dough up and around the filling, pinching to seal completely; smooth into a 12 cm zeppelin shape, with no cracks where steam or water could enter. Bring a wide deep pan with 4 litres of water and 1 tbsp coarse salt to a gentle simmer (not a rolling boil — vigorous water can break the dumplings); lower the cepelinai in 2 batches, stir gently once to keep them off the base, and cook for 25–30 minutes at the gentlest simmer, until the surface goes from matte to translucent and the dumplings float high. While they cook, make the sauce; cook the cubed bacon in a dry frying pan over medium heat for 6–8 minutes until the fat renders and the cubes are crisp; add the sliced onion and cook for another 5–6 minutes until soft and lightly golden; stir off the heat and keep warm. Lift the cooked cepelinai out with a slotted spoon onto warmed plates — 2 per person; scatter generously with the bacon-onion mixture and its fat, top with a heap of cold sour cream, and finish with chopped dill; serve immediately while everything is hot and the centres are juicy."}},{"id":140,"origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"鶏のフリカッセ","en":"Chicken Fricassée","ro":"Fricassée de Poulet"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"french","ingredients":{"ja":["骨付き皮付きの鶏もも肉とドラムスティック1.5kg（約8切れ）、または1.5kgの丸鶏を8つに切り分けたもの","細かい海塩小さじ1＋挽きたての白胡椒小さじ0.5（黒胡椒でも可だがソースに点が残る）","無塩バター60g、30g＋30gに分ける","中性油大さじ2","パールオニオンか小エシャロット250g、皮をむく（または中サイズの玉ねぎ1個みじん切り）","ブラウンマッシュルームかホワイトマッシュルーム200g、大きければ半分か4等分","中サイズのにんじん2本（約200g）、皮をむいて5cmのスティック状","にんにく2片、みじん切り","中力粉30g","辛口白ワイン150ml（リースリングまたはソーヴィニヨン・ブラン）","塩を加えていない温かい鶏ストック500ml","小さなブーケガルニ1束（ローリエ1枚＋タイム4枝＋パセリの軸4本を紐で束ねる）","ダブルクリーム200ml（脂肪分35%以上）、好みで卵黄2個でリエゾンを濃厚に","新鮮なレモン汁大さじ1","細かく刻んだ新鮮なイタリアンパセリ大さじ2、飾り用"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces), or a 1.5 kg whole chicken jointed into 8","1 tsp fine sea salt + 0.5 tsp freshly ground white pepper (black pepper works but speckles the sauce)","60 g unsalted butter, divided into 30 g + 30 g","2 tbsp neutral oil","250 g pearl onions or small shallots, peeled (or 1 medium onion finely diced)","200 g chestnut or button mushrooms, halved or quartered if large","2 medium carrots (about 200 g), peeled and cut into 5 cm batons","2 garlic cloves, finely minced","30 g plain (all-purpose) flour","150 ml dry white wine (Riesling or Sauvignon Blanc)","500 ml hot unsalted chicken stock","1 small bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks tied with string)","200 ml double cream (heavy cream, 35% fat or higher), plus 2 optional egg yolks for a richer liaison","1 tbsp fresh lemon juice","2 tbsp finely chopped fresh flat-leaf parsley, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți) sau 1,5 kg pui întreg dezasamblat în 8 bucăți","1 linguriță sare fină de mare + 0,5 linguriță piper alb proaspăt măcinat (piperul negru funcționează dar pătează sosul)","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru","250 g cepe de primăvară sau eșalote mici, decojite (sau 1 ceapă medie tocată fin)","200 g ciuperci champignon (albe sau brune), tăiate în jumătăți sau sferturi dacă sunt mari","2 morcovi medii (aproximativ 200 g), curățați și tăiați bastonașe de 5 cm","2 căței de usturoi, tocați fin","30 g făină albă obișnuită","150 ml vin alb sec (Riesling sau Sauvignon Blanc)","500 ml supă de pui fierbinte nesărată","1 bouquet garni mic (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel legate cu sfoară)","200 ml smântână grasă (cel puțin 35% grăsime), plus 2 gălbenușuri opționale pentru o legătură mai bogată","1 lingură suc de lămâie proaspăt","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură"]},"howIsMade":{"ja":"キッチンペーパーで鶏肉の水気を拭き、両面に塩小さじ1と白胡椒で味付け、常温で15分休ませる。28cmの厚手のソテーパンかダッチオーブンにバター30gと油大さじ2を中火で熱する、バターが泡立ったら、鶏肉を皮を下にして1段に並べ（必要なら数回に分ける）、片面ずつ5〜6分焼く、表面は淡い黄金色になる程度で、絶対に焦がさない、茶色いクラストはソースを濁す、皿に取り出す。火を中弱火に落とす、同じ鍋にパールオニオンを入れ、5〜6分、軽く色づきつつもまだ淡い状態まで炒める、鶏肉と同じ皿に取る。にんじんときのこを鍋に入れて4〜5分炒める、きのこは一度水を出してから再び吸う、にんにくを加えて30秒炒める。野菜の上に小麦粉を振り、絶えずかき混ぜながら2分炒めて粉の生臭さを飛ばす、野菜の周りに淡色のルーが形成される、白ワインを注いで強めの沸騰にし、底のうま味をこすり落としながら、半量に煮詰める（1〜2分）。鶏肉とパールオニオンを鍋に戻し1段に並べる、熱いストックをほぼひたるまで注ぎ、ブーケガルニを入れ、最も穏やかな沸騰にする、蓋をして30〜35分（ももの場合）または25分（先に取り出すむね）煮込み、肉が骨から離れ内部温度が75°Cになるまで。鶏肉と野菜を温めた皿に移し、ホイルをかぶせる、ブーケガルニを取り除く、ソースを中火で強く沸かして3〜5分煮詰め、スプーンの背を覆う濃度（約350ml）にする。リエゾンを作る、小ボウルで生クリームと卵黄をホイップする、熱いソースを玉杓子1杯入れて温度を合わせ、火を止めたパンに温められた混合物を戻して入れる、優しく混ぜる——絶対に沸騰させない、沸騰すると卵黄が固まる、レモン汁を加え、味見をして塩で整える、鶏肉にかけ、刻んだパセリを散らし、ご飯、バターを絡めた麺、または蒸したジャガイモとともにすぐに供する。","en":"Pat the chicken pieces dry with paper towels and season both sides with 1 tsp salt and the white pepper; rest at room temperature for 15 minutes. Heat 30 g of the butter and 2 tbsp oil in a wide 28 cm heavy-based sauté pan or Dutch oven over medium heat; when the butter foams, add the chicken skin-side down in one layer (work in batches if needed) and cook 5–6 minutes per side — the surface should turn pale gold and gilded, NOT brown; a brown crust would muddy the sauce; lift onto a plate. Reduce the heat to medium-low; add the pearl onions to the same pan and cook for 5–6 minutes, stirring, until lightly gilded but still pale; lift onto the plate with the chicken. Add the carrots and mushrooms to the pan and cook for 4–5 minutes — the mushrooms will release their water and reabsorb it; add the garlic and stir for 30 seconds. Sprinkle the flour over the vegetables and stir constantly for 2 minutes to cook out the raw taste — a pale roux will form around the vegetables; pour in the wine and bring to a brisk simmer, scraping up any sediment from the pan base, until reduced by half (1–2 minutes). Return the chicken and pearl onions to the pan in a single layer; pour in the hot stock to nearly cover, tuck in the bouquet garni, and bring to the gentlest simmer; cover and cook for 30–35 minutes for thighs (or 25 minutes for breasts removed earlier), until the meat pulls easily from the bone and the internal temperature reads 75°C. Lift the chicken and vegetables to a warmed dish and cover with foil; discard the bouquet garni; bring the sauce to a brisk simmer over medium heat and reduce for 3–5 minutes, until it coats the back of a spoon (about 350 ml). Make the liaison; whisk the cream and egg yolks together in a small bowl; whisk in a ladle of hot sauce to temper, then pour the tempered mixture back into the pan off the heat; stir gently — DO NOT BOIL, or the yolks will scramble; add the lemon juice, taste and adjust the salt; pour over the chicken, scatter with chopped parsley, and serve immediately with rice, buttered noodles, or steamed potatoes."}},{"id":141,"origin":{"ja":"クウェート","en":"Kuwait","ro":"Kuweit"},"name":{"ja":"マチブース","en":"Machboos","ro":"Machboos"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"ja":["骨付き皮付きの鶏もも肉とドラムスティック1.5kg（または骨付きラム肩肉1.2kgを6cm角に切る）","バスマティ米400g、洗って冷水に30分浸し、水気を切る","中性油60ml（または、ギー30g＋油大さじ2でより濃厚な味に）","大玉ねぎ3個（約600g）、薄切り——少量を生のまま盛り付け用に取り置く","にんにく6片、みじん切り","親指大の新鮮な生姜1片（約30g）、すりおろし","中サイズのトマト3個（約300g）、すりおろす（または、ホールトマト缶200g）","トマトペースト大さじ2","ドライライム（ルーミ）2個、ナイフで3か所穴を開ける（または代用として新鮮なライム果汁大さじ2、伝統色は薄れる）","バハラット大さじ1（または、シナモンパウダー小さじ1＋クミンパウダー小さじ1＋コリアンダーパウダー小さじ1＋カルダモンパウダー小さじ0.5＋黒胡椒パウダー小さじ0.5）","ターメリックパウダー小さじ0.5","グリーンカルダモンの莢4個、軽く割る＋シナモンスティック（5cm）1本＋クローブ4個＋ローリエ2枚","新鮮なコリアンダー1小束（約30g）、茎は鍋用にみじん切り、葉は飾り用に取り置く","新鮮な青唐辛子2本、縦に切れ目を入れる","熱湯1.2リットル（または、深みを増すために塩を加えていない鶏ストック）","細かい海塩小さじ1.5、好みで追加","スライスアーモンド60gとサルタナレーズン40g、ギー小さじ1で軽くトースト（仕上げに散らす用）","サフラン小さじ0.5、ぬるま湯大さじ2に浸す（任意、米の仕上げ用）"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (or 1.2 kg bone-in lamb shoulder cut into 6 cm chunks)","400 g basmati rice, rinsed and soaked in cold water for 30 minutes, then drained","60 ml neutral oil (or 30 g ghee + 2 tbsp oil for a richer flavour)","3 large onions (about 600 g), finely sliced — reserve a small handful raw for serving","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 30 g), finely grated","3 medium tomatoes (about 300 g), grated (or 200 g canned chopped tomatoes)","2 tbsp tomato paste","2 dried limes (loomi), pierced with a knife in 3 places (or 2 tbsp fresh lime juice as a less-traditional substitute)","1 tbsp baharat (or 1 tsp ground cinnamon + 1 tsp ground cumin + 1 tsp ground coriander + 0.5 tsp ground cardamom + 0.5 tsp ground black pepper)","0.5 tsp ground turmeric","4 whole green cardamom pods, lightly cracked + 1 cinnamon stick (5 cm) + 4 whole cloves + 2 bay leaves","1 small bunch fresh coriander (about 30 g), stems chopped fine for the pot, leaves reserved for garnish","2 fresh green chillies, slit lengthwise","1.2 litres hot water (or unsalted chicken stock for more depth)","1.5 tsp fine sea salt, plus more to taste","60 g flaked almonds and 40 g sultanas, lightly toasted in 1 tsp ghee (to scatter on top)","0.5 tsp saffron threads soaked in 2 tbsp warm water (optional, for finishing the rice)"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (sau 1,2 kg umăr de miel cu os tăiat bucăți de 6 cm)","400 g orez basmati, clătit și înmuiat în apă rece 30 de minute, apoi scurs","60 ml ulei neutru (sau 30 g ghee + 2 linguri ulei pentru aromă mai bogată)","3 cepe mari (aproximativ 600 g), feliate fin — păstrează o mică parte crudă pentru servit","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 30 g), ras fin","3 roșii medii (aproximativ 300 g), date pe răzătoare (sau 200 g roșii sfărâmate din conservă)","2 linguri pastă de roșii","2 lămâi uscate (loomi), înțepate cu cuțitul în 3 locuri (sau 2 linguri suc proaspăt de lime ca substitut mai puțin tradițional)","1 lingură baharat (sau 1 linguriță scorțișoară măcinată + 1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 0,5 linguriță cardamom măcinat + 0,5 linguriță piper negru măcinat)","0,5 linguriță turmeric măcinat","4 capsule întregi de cardamom verde, ușor crăpate + 1 baton de scorțișoară (5 cm) + 4 cuișoare + 2 foi de dafin","1 legătură mică de coriandru proaspăt (aproximativ 30 g), tijele tocate fin pentru oală, frunzele păstrate pentru garnitură","2 ardei iuți verzi proaspeți, crestați pe lungime","1,2 litri apă fierbinte (sau supă de pui nesărată pentru profunzime)","1,5 lingurițe sare fină de mare, plus după gust","60 g migdale feliate și 40 g stafide blonde, ușor prăjite în 1 linguriță ghee (pentru deasupra)","0,5 linguriță fire de șofran înmuiate în 2 linguri apă caldă (opțional, pentru finisarea orezului)"]},"howIsMade":{"ja":"バスマティ米を冷水で水が澄むまでとぎ、新しい冷水に30分浸す、これで余分なでんぷんが取れ、炊飯時間も短くなる、使用直前に水気を切る。鶏肉の水気を拭き、塩小さじ0.5で下味をつける、直径28cmの厚手鍋に油（またはギーと油）を中強火で熱する、油が光ってきたら、鶏肉を皮目を下にして並べ、片面4〜5分ずつ、濃いきつね色になるまで焼く、皿に取り出す。中火に落とす、同じ鍋にスライス玉ねぎとひとつまみの塩を加え、頻繁にかき混ぜながら12〜15分、深い黄金色で柔らかくなるまで炒める、にんにくと生姜を加えて1分、香りが立つまで炒める。カルダモンの莢、シナモンスティック、クローブ、ローリエ、バハラット、ターメリックを加える、30秒空炒りし、香りが立ち色が深くなるまで、トマトペーストとすりおろしたトマトを加え、4〜5分混ぜながら煮て、混合物が濃赤色になり油が縁で分離するまで。鶏肉を1段に戻し入れる、熱湯（またはストック）、ドライライム、切れ目を入れた青唐辛子、刻んだコリアンダーの茎、残りの塩を加える、穏やかに沸騰させ、蓋をして最弱火で35〜40分（鶏肉）または1時間30分（ラム）、肉が骨から外れスープが深いコクになるまで煮る。鶏肉を皿に取り、アルミホイルをふんわりかぶせて保温する、スープの余分な脂をすくい取る。水を切った米を鍋に加え、優しく押してスープにちょうど浸る状態にする（必要なら熱湯を足す——米の上に約2.5cmの液体が残る程度）、再び穏やかに沸騰させ、ぴったり蓋をして最弱火に落とし、動かさず18分炊く。火を止める、サフラン水（使う場合）を米に回しかけ、鶏肉を上にのせ、蓋を戻して10分蒸らす——蒸気で鶏肉に火が通り、米粒も離れる、米をフォークでほぐし、広めの皿に移して鶏肉をのせ、トーストしたアーモンド、サルタナ、生玉ねぎのスライス、新鮮なコリアンダーの葉を散らす、デイバ（タマリンドソース）かヨーグルトを添えて供する。","en":"Rinse the basmati rice under cold running water until the water runs almost clear, then soak in fresh cold water for 30 minutes; this removes excess starch and shortens the final cooking step; drain just before use. Pat the chicken pieces dry and season with 0.5 tsp of the salt; heat the oil (or ghee + oil) in a heavy 28 cm pot over medium-high heat; when shimmering, add the chicken skin-side down and sear for 4–5 minutes per side until deep golden; lift onto a plate. Reduce the heat to medium; add the sliced onions and a pinch of salt to the same pot and cook for 12–15 minutes, stirring often, until deeply golden and very soft; add the garlic and ginger and cook for 1 minute until fragrant. Stir in the cardamom pods, cinnamon stick, cloves, bay leaves, baharat, and turmeric; toast for 30 seconds — the spices should turn aromatic and deepen in colour; add the tomato paste and grated tomatoes and cook, stirring, for 4–5 minutes, until the mixture darkens to a rich red and the oil splits out around the edges. Return the chicken to the pot in a single layer; pour in the hot water (or stock), add the dried limes, slit chillies, chopped coriander stems, and remaining salt; bring to a gentle boil, then cover, reduce to the lowest simmer, and cook for 35–40 minutes (chicken) or 1 h 30 min (lamb), until the meat is fork-tender and the broth is deeply flavoured. Lift the chicken onto a plate and cover loosely with foil to keep warm; skim any excess fat from the broth. Add the drained rice to the pot, gently pushing it down so it is just covered by the broth (top up with hot water if needed — you want about 2.5 cm of liquid above the rice); bring back to a gentle boil, then cover with a tight lid, reduce to the lowest possible heat, and cook undisturbed for 18 minutes. Turn off the heat; drizzle the saffron water (if using) over the rice, place the chicken pieces on top, replace the lid, and rest for 10 minutes — the steam finishes cooking the chicken and the rice grains separate; fluff the rice with a fork, transfer to a wide platter with the chicken on top, and scatter with toasted almonds, sultanas, raw onion slices, and fresh coriander leaves; serve with deeba (tamarind sauce) or yoghurt on the side."}},{"id":142,"origin":{"ja":"コンゴ共和国","en":"Republic of the Congo","ro":"Republica Congo"},"name":{"ja":"ムアンベチキン","en":"Moambe chicken","ro":"Pui Moambe"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["骨付き皮付きの鶏もも肉とドラムスティック1.5kg（約8切れ）","鶏肉の下味用に細かい海塩小さじ1＋挽きたての黒胡椒小さじ0.5","赤パーム油60ml（風味が強すぎる場合はパーム油30ml＋中性油大さじ2でも可）","大玉ねぎ2個（約400g）、みじん切り","にんにく6片、みじん切り","親指大の新鮮な生姜1個（約20g）、すりおろし","完熟トマト400gをすりおろす、または400g缶のホールトマト1個","トマトペースト大さじ2","無糖の滑らかなピーナッツバター100g（または手に入れば、缶詰のモアンベ・パームペースト200g）","新鮮なスコッチボネットまたはハバネロ唐辛子2本、縦に切れ目を入れる（または乾燥赤唐辛子フレーク小さじ1；お好みで——モアンベは辛い料理）","ローリエ2枚","塩を加えていない温かい鶏ストックまたは水500ml","細かい海塩小さじ1.5、好みで追加","細かく刻んだイタリアンパセリ大さじ2（またはレモンバジル大さじ2）、飾り用","蒸し白米、フフ、または茹でたプランテン、添え用"],"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces)","1 tsp fine sea salt + 0.5 tsp freshly ground black pepper for the chicken","60 ml red palm oil (or 30 ml palm + 2 tbsp neutral oil if the flavour is too strong)","2 large onions (about 400 g), finely diced","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 20 g), finely grated","400 g ripe tomatoes, grated, or 1 × 400 g can chopped tomatoes","2 tbsp tomato paste","100 g unsweetened smooth peanut butter (or 200 g canned moambe palm paste when available)","2 fresh scotch bonnet or habanero chillies, slit lengthwise (or 1 tsp dried chilli flakes; adjust to taste — moambe is hot)","2 bay leaves","500 ml hot unsalted chicken stock or water","1.5 tsp fine sea salt, plus more to taste","2 tbsp finely chopped flat-leaf parsley (or 2 tbsp lemon basil), to garnish","Steamed white rice, fufu, or boiled plantains, to serve"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","1 linguriță sare fină de mare + 0,5 linguriță piper negru proaspăt măcinat pentru pui","60 ml ulei de palmier roșu (sau 30 ml palmier + 2 linguri ulei neutru dacă aroma e prea puternică)","2 cepe mari (aproximativ 400 g), tocate fin","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 20 g), ras fin","400 g roșii coapte, date pe răzătoare (sau 1 × 400 g conservă de roșii tocate)","2 linguri pastă de roșii","100 g unt de arahide neîndulcit, fin (sau 200 g pastă de moambe la conservă, când e disponibilă)","2 ardei iuți proaspeți scotch bonnet sau habanero, crestați pe lungime (sau 1 linguriță fulgi de ardei iute; ajustează după gust — muambe este picant)","2 foi de dafin","500 ml supă de pui fierbinte nesărată sau apă","1,5 lingurițe sare fină de mare, plus după gust","2 linguri pătrunjel cu frunze plate tocat fin (sau 2 linguri busuioc de lămâie), pentru garnitură","Orez alb fiert, fufu sau banane plantain fierte, pentru servit"]},"howIsMade":{"ja":"鶏肉の水気を拭き、両面に塩小さじ1とコショウ小さじ0.5で味付け、常温で15分休ませる。直径28cmの厚手鍋にパーム油を中強火で熱する——パーム油は溶けて濃いオレンジレッドの液体になる、油が光ってきたら、鶏肉を皮を下にして1段に並べ（必要なら2回に分ける）、片面4〜5分ずつ、皮が濃いきつね色になるまで焼く、皿に取り出す。火を中火に落とす、同じ鍋にみじん切り玉ねぎとひとつまみの塩を加え、頻繁にかき混ぜながら8〜10分、柔らかくつややかで、軽く色づく程度に色づくが焦がさずに炒める。にんにくと生姜を加え、1分香りが立つまで炒める、トマトペーストとすりおろしトマトを加え、5〜6分かき混ぜながら煮込み、混合物が深い煉瓦色になり、縁からパーム油が分離してくるまで——この油分離がモアンベの象徴的な見た目。ピーナッツバターと熱いストック200mlを小ボウルでなめらかになるまでホイップし、鍋に注いで混ぜる、残りのストック300ml、ローリエ、切れ目を入れた唐辛子、残りの塩小さじ0.5を加える。鶏肉を1段に戻し、皮目を上にしてソースに沈め、皮が液体の上に出るようにする、穏やかな沸騰にする。蓋を少しずらして閉め、最弱火で35〜40分煮込む、半分の時点で一度かき混ぜ、鶏肉が骨から外れ、内部温度が75°Cになるまで、ソースはコーラルオレンジで、スプーンの背を覆う程度の濃さに——詰まりすぎたら熱湯を少量加えて緩める。味を見て塩や追加の唐辛子で調整する、鶏肉を温めた皿に取り、ソースをたっぷりかけて刻んだパセリを散らし、蒸し白米、フフ、または茹でたプランテンと一緒に、ソースを吸わせて直ちに供する。","en":"Pat the chicken pieces dry and season both sides with 1 tsp salt and 0.5 tsp pepper; rest at room temperature for 15 minutes. Heat the palm oil in a heavy 28 cm pot over medium-high heat — palm oil melts into a deep orange-red liquid; when shimmering, add the chicken pieces skin-side down in one layer (work in two batches if needed) and sear for 4–5 minutes per side until the skin is deep golden; lift onto a plate. Reduce the heat to medium; add the diced onions and a pinch of salt to the same pot and cook for 8–10 minutes, stirring often, until soft, glossy, and lightly golden but not browned. Add the garlic and ginger and cook for 1 minute until fragrant; stir in the tomato paste and grated tomatoes and cook for 5–6 minutes, stirring, until the mixture darkens to a rich brick-red and the palm oil starts to separate around the edges — this oil split is the signature look of moambe. Whisk the peanut butter with 200 ml of the hot stock in a small bowl until smooth, then pour into the pot and stir to combine; add the remaining 300 ml stock, the bay leaves, slit chillies, and the remaining 0.5 tsp salt. Return the chicken to the pot in a single layer, nestling the pieces into the sauce skin-side up so the skin stays above the liquid; bring to a gentle simmer. Cover with a lid set slightly ajar and cook on the lowest heat for 35–40 minutes, stirring once at the halfway mark, until the chicken pulls easily from the bone and the internal temperature reads 75°C; the sauce should be coral-orange and thick enough to coat the back of a spoon — if it tightens too much, loosen with a splash of hot water. Taste and adjust with salt or extra chilli; lift the chicken into a warmed serving dish, spoon the sauce generously over the top, scatter with chopped parsley, and serve immediately with steamed rice, fufu, or boiled plantain to soak up the sauce."}},{"id":143,"origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"カスレ","en":"Cassoulet","ro":"Cassoulet"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["乾燥白いんげん豆500g（haricot tarbais またはカネリーニ）、冷水で一晩浸す","鴨のコンフィ脚4本（cuisses de canard confites）、常温、脂は取り置く","豚肩肉400g、4cm角切り","皮付き豚バラ肉300g、3cm角切り","トゥールーズソーセージ4本（合計約500g）——または燻製豚肉ソーセージで代用","大きいにんじん1本（約150g）、皮をむいて2cmぶつ切り","大玉ねぎ1個（約200g）、皮をむいてクローブ4個を刺す","にんにく1株（約60g）、横半分にカット","ブーケガルニ1束（ローリエ1枚＋タイム4枝＋パセリの軸4本＋ドライオレンジピールひと片、紐で束ねる）","豚すね骨またはハム骨1本（約400g、任意だが伝統的）","缶詰のクラッシュトマト200g（または完熟トマト2個、皮をむいて刻む）","トマトペースト大さじ2","塩を加えていない鶏または豚ストック1.5リットル（または水）","白い粗いパン粉60g","細かい海塩小さじ1.5、好みで追加","挽きたての黒胡椒小さじ1","細かく刻んだイタリアンパセリ大さじ2、飾り用","鴨脂大さじ2（コンフィから）、肉を焼くため"],"en":["500 g dried white beans (haricot tarbais or cannellini), soaked in cold water overnight","4 confit duck legs (cuisses de canard confites), at room temperature, fat reserved","400 g pork shoulder, cut into 4 cm pieces","300 g pork belly with rind, cut into 3 cm pieces","4 Toulouse sausages (about 500 g) — or smoked pork sausages as a substitute","1 large carrot (about 150 g), peeled and cut into 2 cm chunks","1 large onion (about 200 g), peeled and studded with 4 whole cloves","1 head of garlic (about 60 g), halved horizontally","1 bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks + a piece of dried orange peel, tied)","1 pork knuckle bone or ham hock (about 400 g, optional but traditional)","200 g canned chopped tomatoes (or 2 ripe tomatoes, peeled and chopped)","2 tbsp tomato paste","1.5 litres unsalted chicken or pork stock (or water)","60 g coarse white breadcrumbs","1.5 tsp fine sea salt, plus more to taste","1 tsp freshly ground black pepper","2 tbsp finely chopped fresh flat-leaf parsley, to garnish","2 tbsp duck fat (from the confit), for browning the meats"],"ro":["500 g fasole albă uscată (haricot tarbais sau cannellini), înmuiată în apă rece peste noapte","4 pulpe de rață confit (cuisses de canard confites), la temperatura camerei, grăsimea păstrată","400 g umăr de porc, tăiat bucăți de 4 cm","300 g piept de porc cu șorici, tăiat bucăți de 3 cm","4 cârnați de Toulouse (aproximativ 500 g) — sau cârnați afumați de porc ca substitut","1 morcov mare (aproximativ 150 g), curățat și tăiat bucăți de 2 cm","1 ceapă mare (aproximativ 200 g), curățată și înfiptă cu 4 cuișoare întregi","1 căpățână de usturoi (aproximativ 60 g), tăiată orizontal","1 bouquet garni (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel + o bucată de coajă uscată de portocală, legate)","1 os de jambon afumat sau o ciolan de porc (aproximativ 400 g, opțional dar tradițional)","200 g roșii sfărâmate din conservă (sau 2 roșii coapte, decojite și tocate)","2 linguri pastă de roșii","1,5 litri supă de pui sau de porc nesărată (sau apă)","60 g pesmet alb grosier","1,5 lingurițe sare fină de mare, plus după gust","1 linguriță piper negru proaspăt măcinat","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură","2 linguri grăsime de rață (din confit), pentru rumenirea cărnurilor"]},"howIsMade":{"ja":"前夜、豆を大きなボウルに入れ、少なくとも2リットルの冷水を注ぎ、10〜12時間浸す、約2倍に膨らむ、翌日水切りしてすすぐ。豆のスープを作る、水を切った豆を厚手の5リットル鍋に入れ、ハム骨（使う場合）、クローブを刺した玉ねぎ、半分にしたにんにくの頭、にんじん、ブーケガルニ、冷たいストック1.5リットルを加える、穏やかに沸騰させ、蓋をせず50〜60分煮込み、豆がちょうど柔らかいが崩れない程度まで、塩はまだ入れない。同時に肉を焼く、広めのフライパンに鴨脂大さじ2を中強火で熱する、豚肩肉と豚バラ肉の水気を拭き、複数回に分けて片面4〜5分、濃いきつね色になるまで焼く、皿に取り出す、同じ脂でトゥールーズソーセージを片面2〜3分、ケーシングに色がつく程度に焼く、皿に加える。オーブンを160°C（320°F／ファン140°C）に予熱する、ハム骨、玉ねぎ、にんにく、にんじん、ブーケガルニを豆鍋から取り出し、香味野菜は捨てる、骨から肉をはがして粗くほぐし、取り置く、トマトペーストと刻みトマトを豆の汁に加えて混ぜ、味見して塩小さじ1.5とコショウを加える。直径26cmの広めのカスール（または広めの耐熱鍋）でカスレを組み立てる、豆の3分の1を底に敷き、その上に焼いた豚肩肉、豚バラ肉、骨の肉、冷たい鴨のコンフィを並べる、豆の3分の1で覆い、焼いたソーセージをのせ、残りの豆で仕上げる、最上層の豆がちょうど浸るまで豆のスープを注ぐ——残りは追加用に保温する。パン粉を全体に均一に振る、カスールを蓋なしでオーブンに入れ、1時間焼く、パン粉が金色になり茶色の地殻が形成される。1時間後、木べらの背で地殻をカスレの中に押し込んで割る——混ぜない、乾燥して見えたら取り置いた豆のスープを一杯加える、オーブンに戻してさらに1時間焼き、30分後にもう一度地殻を割る、新しい地殻が形成され、縁から深く沸騰してくるまで。もう一度繰り返す：地殻を割り、液体を補充し、最後の30〜40分焼く、オーブン合計時間は約2時間30分——地殻は計3回、カスレをオーブンから出して10分休ませ、豆に液体を再吸収させる、刻んだパセリを散らして、カスールから直接、クラスティーなパンとグリーンサラダと共に供する。","en":"The night before, place the beans in a large bowl, cover with at least 2 litres of cold water, and soak for 10–12 hours; they will roughly double in size; drain and rinse the next day. Make the bean stock; put the drained beans in a heavy 5-litre pot with the pork knuckle (if using), the studded onion, the halved garlic head, the carrot chunks, the bouquet garni, and 1.5 litres of cold stock; bring to a gentle simmer and cook uncovered for 50–60 minutes, until the beans are just tender but not falling apart; do not salt yet. Meanwhile, brown the meats; heat 2 tbsp duck fat in a wide skillet over medium-high heat; pat the pork shoulder and pork belly dry and brown in batches for 4–5 minutes per side until deep golden; lift onto a plate; in the same fat, brown the Toulouse sausages for 2–3 minutes per side just to colour the casings; add to the plate. Heat the oven to 160°C (320°F / fan 140°C); lift the cooked knuckle, onion, garlic, carrot, and bouquet garni out of the bean pot and discard the aromatics; pull any meat from the knuckle bone, shred coarsely, and reserve; stir the tomato paste and chopped tomatoes into the bean liquid, then taste and add 1.5 tsp salt and the pepper. Assemble the cassoulet in a wide 26 cm cassole (or any wide oven-safe pot); spread one-third of the beans on the bottom, then arrange the browned pork shoulder, pork belly, knuckle meat, and the cold confit duck legs on top; cover with another third of the beans, lay the browned sausages on top, then finish with the remaining beans; pour over enough bean liquid to just cover the top layer of beans — keep the rest warm for topping up. Sprinkle the breadcrumbs evenly over the top; place the cassole in the oven, uncovered, and cook for 1 hour; the breadcrumbs will gild and form a brown crust. After 1 hour, break the crust by pressing it down into the cassoulet with the back of a wooden spoon — do not stir; top up with a ladle of reserved bean liquid if it looks dry; return to the oven and cook for another hour, breaking the crust again after 30 minutes, until a fresh crust has formed and the cassoulet is bubbling deeply around the edges. Repeat once more: break the crust, top up the liquid, and bake a final 30–40 minutes; the total oven time is about 2 h 30 m — three crusts in all; rest the cassoulet for 10 minutes out of the oven so the beans drink back the liquid; scatter with chopped parsley and serve straight from the pot, with crusty bread and a green salad."},"timeMins":{"total":240,"active":45}},{"id":144,"origin":{"ja":"クロアチア","en":"Croatia","ro":"Croația"},"name":{"ja":"パスティチャーダ","en":"Pasticada","ro":"Pašticada"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["牛ランプまたはトップサイド1.2kg、ひと塊","豚背脂またはパンチェッタ100g、5mm × 5cmの棒状に切り、ラルディング用","中サイズのにんじん2本（約200g）：1本はラルディング用にマッチ棒状、1本はソース用に細かいみじん切り","クローブ10個（5個はラルディング用、5個はマリネ用）＋ソース用にクローブパウダー小さじ0.5","にんにく6片、皮をむく——マリネ用に3片を潰し、ソース用に3片をみじん切り","白ワインビネガー200ml＋冷水200ml＋ローリエ3枚＋黒胡椒粒小さじ1＋ジュニパーベリー4粒（マリネ用）","大玉ねぎ2個（約400g）、みじん切り","種抜きプルーン（ドライプラム）200g","甘口ワイン プロシェク100ml（または甘口マルサラ、または黒砂糖大さじ1＋ポート80ml）","辛口赤ワイン500ml（プラヴァツ・マリ、メルロー、または他の力強い辛口赤）","塩を加えていない牛ストック300ml","トマトペースト大さじ2＋缶詰のホールトマト200g","シナモンパウダー小さじ1＋すりおろした生のナツメグ小さじ0.5","ラード50g（またはオリーブオイル大さじ3）、焼き色付け用","細かい海塩小さじ1.5、好みで追加","挽きたての黒胡椒小さじ0.5、仕上げ用","新鮮なパセリ、みじん切り、飾り用","ニョッキまたは生パスタ（約500g）、添え用"],"en":["1.2 kg beef rump or topside, in one piece","100 g pork fat back or pancetta, cut into 5 mm × 5 cm strips for larding","2 medium carrots (about 200 g): 1 cut into matchsticks for larding, 1 finely diced for the sauce","10 whole cloves (5 for larding, 5 for the marinade) + 0.5 tsp ground cloves for the sauce","6 garlic cloves, peeled — 3 crushed for the marinade, 3 finely chopped for the sauce","200 ml white wine vinegar + 200 ml cold water + 3 bay leaves + 1 tsp black peppercorns + 4 juniper berries (for the marinade)","2 large onions (about 400 g), finely diced","200 g pitted prunes (dried plums)","100 ml prošek dessert wine (or sweet Marsala or 1 tbsp brown sugar + 80 ml port)","500 ml dry red wine (Plavac Mali, Merlot, or any robust dry red)","300 ml unsalted beef stock","2 tbsp tomato paste + 200 g canned chopped tomatoes","1 tsp ground cinnamon + 0.5 tsp freshly grated nutmeg","50 g lard (or 3 tbsp olive oil), for browning","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper, for finishing","Fresh parsley, finely chopped, to garnish","Gnocchi or fresh pasta (about 500 g), to serve"],"ro":["1,2 kg vrăbioară sau pulpă de vită, într-o singură bucată","100 g slană de porc sau pancetta, tăiată fâșii de 5 mm × 5 cm pentru împănat","2 morcovi medii (aproximativ 200 g): 1 tăiat fâșii subțiri pentru împănat, 1 tăiat cuburi mici pentru sos","10 cuișoare întregi (5 pentru împănat, 5 pentru marinadă) + 0,5 linguriță cuișoare măcinate pentru sos","6 căței de usturoi decojiți — 3 zdrobiți pentru marinadă, 3 tocați fin pentru sos","200 ml oțet de vin alb + 200 ml apă rece + 3 foi de dafin + 1 linguriță boabe de piper negru + 4 boabe de ienupăr (pentru marinadă)","2 cepe mari (aproximativ 400 g), tocate fin","200 g prune uscate fără sâmburi","100 ml vin dulce prošek (sau Marsala dulce, sau 1 lingură zahăr brun + 80 ml porto)","500 ml vin roșu sec (Plavac Mali, Merlot sau orice vin sec robust)","300 ml supă de vită nesărată","2 linguri pastă de roșii + 200 g roșii sfărâmate din conservă","1 linguriță scorțișoară măcinată + 0,5 linguriță nucșoară proaspăt rasă","50 g untură (sau 3 linguri ulei de măsline), pentru rumenire","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat, pentru finisare","Pătrunjel proaspăt tocat fin, pentru garnitură","Gnocchi sau paste proaspete (aproximativ 500 g), pentru servit"]},"howIsMade":{"ja":"1日目、牛肉にラルディングを施す、よく切れるパーニングナイフで肉の表面に16か所の深い切れ目を入れる、各切れ目に豚脂の棒、にんじんの棒、そして1か所おきにクローブの半分を差し込む、脂が内側から肉をしっとりさせ、にんじんがソースに甘みを加え、クローブが肉に香りをつける。マリネ液を作る、肉がちょうど入る非反応性のボウルに、ワインビネガー200ml、冷水200ml、マリネ用にんにく3片（潰したもの）、ローリエ3枚、黒胡椒粒、ジュニパーベリー、残りの丸ごとクローブ5個を合わせる、肉を浸し、蓋をして冷蔵庫で24時間（最大48時間）、途中で2回ひっくり返す。2日目、肉を取り出し、付着したスパイスを取り除き、しっかり水気を拭く——濡れた肉は色がつかない、マリネ液は捨てる、塩小さじ1とコショウ小さじ0.5で肉に下味をつける。直径28cmの厚手ダッチオーブンかブレザーにラードを中強火で熱する、肉を全面、各面3〜4分、合計12〜15分、表面全体が均一なマホガニー色になるまで焼く、皿に取り出す。火を中火に落とす、出た脂にみじん切り玉ねぎとひとつまみの塩を加え、頻繁にかき混ぜながら10〜12分、深い金茶色になるまで炒める——このゆっくりとしたキャラメル化がソースの土台、サイコロ状にんじんと刻みにんにくを加え、さらに3〜4分炒める、トマトペースト、クローブパウダー、シナモン、ナツメグを加え、1分焙る。プロシェクを注ぎ1分混ぜながら鍋底をこそぐ、赤ワインを加え火を強め、半量まで煮詰める（約6〜8分）、刻みトマト、牛ストック、プルーン、残りの塩小さじ0.5を加える、肉を鍋に戻し、ソースに沈める——ソースは肉の高さの約4分の3に達するべき。ぴったり蓋をして最弱火（または150℃のオーブン）で2時間30分〜3時間、45分ごとに肉を返しながら、ナイフが中心に抵抗なく入るまで煮込む、肉をまな板に取り、アルミホイルをかぶせて15分休ませる。ソースを仕上げる、プルーンを取り出し、ひとつかみを飾り用に取り置く、残りはハンドブレンダーでソースと一緒に攪拌し、濃厚で艶やかなグレイビーにする（または、細かい仕上げにしたい場合は裏ごし）、とろみが足りなければ蓋を外して5〜8分煮詰める——スプーンの背を覆う濃度で、深い甘酸っぱく香り高い味になる、休ませた肉を繊維に逆らって1cm厚にスライスし、温めたニョッキや生パスタの上に並べ、ソースをたっぷりかけ、取り置いたプルーンと刻みパセリを散らしてすぐに供する。","en":"Day 1, lard the beef; using a sharp paring knife, make 16 deep slits across the surface of the beef joint; slide a strip of pork fat, a carrot matchstick, and (in alternate slits) half of a whole clove into each slit; the fat will baste the meat from the inside, the carrot will sweeten the sauce, and the cloves perfume the meat. Make the marinade; in a non-reactive bowl just large enough to hold the beef, combine 200 ml wine vinegar, 200 ml cold water, the 3 crushed marinade garlic cloves, 3 bay leaves, peppercorns, juniper berries, and the remaining 5 whole cloves; submerge the beef, cover, and refrigerate 24 hours (up to 48 hours), turning twice. Day 2, lift the beef out, scrape off any clinging spices, and pat thoroughly dry — wet meat will not brown; discard the marinade; season the meat with 1 tsp salt and 0.5 tsp pepper. Heat the lard in a heavy Dutch oven or braiser (28 cm) over medium-high heat; sear the beef on all sides for 3–4 minutes per side, about 12–15 minutes total, until evenly mahogany brown all over; lift onto a plate. Reduce the heat to medium; add the diced onion and a pinch of salt to the rendered fat and cook for 10–12 minutes, stirring often, until deeply golden brown — this slow caramelisation builds the sauce; add the diced carrot and chopped garlic and cook for another 3–4 minutes; stir in the tomato paste, ground cloves, cinnamon, and nutmeg and toast for 1 minute. Pour in the prošek and stir for 1 minute, scraping the base; add the red wine, raise the heat, and reduce by half (about 6–8 minutes); add the chopped tomatoes, beef stock, prunes, and the remaining 0.5 tsp salt; return the beef to the pot, settling it into the liquid — the sauce should come about three-quarters of the way up the meat. Cover with a tight lid and braise on the lowest hob heat (or in a 150°C oven) for 2 h 30 m – 3 h, turning the beef every 45 minutes, until a knife slides into the centre with no resistance; lift the beef onto a board and rest, tented with foil, for 15 minutes. Finish the sauce; lift out the prunes and reserve a handful for garnish; blend the rest with the sauce using a stick blender to a thick, glossy gravy (or push through a sieve for a finer finish); reduce uncovered for 5–8 minutes if it needs thickening — it should coat the back of a spoon and taste deeply sweet-sour-spiced; slice the rested beef across the grain into 1 cm slices, fan over warm gnocchi or fresh pasta, spoon the sauce generously, scatter with reserved prunes and chopped parsley, and serve immediately."}},{"id":145,"origin":{"ja":"キプロス","en":"Cyprus","ro":"Cipru"},"name":{"ja":"シェフタリア","en":"Sheftalia","ro":"Sheftalia"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mediterranean","ingredients":{"ja":["豚肩肉の粗びき400g（脂肪分15〜20%）","ラム肩肉の粗びき300g（または、ラムがない場合は豚肉のみで700g）","網脂（ラムまたは豚）300g、軽く塩を加えた冷水で30分浸してから水気を切る——約30×30cmのシート","大きい玉ねぎ1個（約200g）、すりおろして余分な水分を絞る","イタリアンパセリ30g、みじん切り","新鮮なミント（キプロスのジオスモス）20g、みじん切り（任意だが伝統的）","にんにく4片、みじん切り","細かい海塩小さじ1.5","挽きたての黒胡椒小さじ1","クミンパウダー小さじ1","シナモンパウダー小さじ0.5","辛口白ワイン60mlまたは赤ワインビネガー大さじ2（つなぎと柔らかさのため）","肉だね用のオリーブオイル大さじ1","グリルを塗るためのオリーブオイル大さじ1","レモンのくし切り、赤玉ねぎの薄切り、トマトの薄切り、温めたピタまたはキプロスのレモニーブレッド、添え用","ザジキまたはフムス、添え用"],"en":["400 g coarsely minced pork shoulder (15–20% fat)","300 g coarsely minced lamb shoulder (or 700 g all pork if lamb is unavailable)","300 g caul fat (lamb or pork), soaked in cold lightly-salted water for 30 minutes then drained — about a 30 × 30 cm sheet","1 large onion (about 200 g), grated and squeezed of excess liquid","30 g flat-leaf parsley, finely chopped","20 g fresh mint (Cypriot dyosmos), finely chopped (optional but traditional)","4 garlic cloves, finely minced","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground cinnamon","60 ml dry white wine or 2 tbsp red wine vinegar (to bind and tenderise)","1 tbsp olive oil for the meat mixture","1 tbsp olive oil for brushing the grill","Lemon wedges, sliced red onion, sliced tomato, and warm pitta or Cypriot lemoni-bread, to serve","Tzatziki or hummus, to serve"],"ro":["400 g umăr de porc tocat grosier (15–20% grăsime)","300 g umăr de miel tocat grosier (sau 700 g doar porc, dacă mielul nu este disponibil)","300 g prapure (de porc sau miel), înmuiat în apă rece ușor sărată 30 de minute, apoi scurs — o foaie de aproximativ 30 × 30 cm","1 ceapă mare (aproximativ 200 g), dată pe răzătoare și stoarsă de lichidul în exces","30 g pătrunjel cu frunze plate, tocat fin","20 g mentă proaspătă (dyosmos cipriot), tocată fin (opțional, dar tradițional)","4 căței de usturoi, tocați fin","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță scorțișoară măcinată","60 ml vin alb sec sau 2 linguri oțet de vin roșu (pentru a lega și a frăgezi)","1 lingură ulei de măsline pentru compoziție","1 lingură ulei de măsline pentru uns grătarul","Felii de lămâie, ceapă roșie feliată, roșii feliate și pita caldă sau pâine cipriotă de lămâie (lemoni), pentru servit","Tzatziki sau hummus, pentru servit"]},"howIsMade":{"ja":"肉だねを作る、広めのボウルに豚ひき肉、ラムひき肉、すりおろし玉ねぎ、パセリ、ミント（使う場合）、にんにく、塩、コショウ、クミン、シナモン、ワイン（または酢）、オリーブオイル大さじ1を入れる、粘りが出て均一になるまで手で2〜3分こねる、蓋をして冷蔵庫で最低1時間（最大12時間）寝かせ、味をなじませる。網脂を準備する、水気を切った網脂を清潔なまな板の上に注意深く広げる——非常に破れやすい、ハサミで約12 × 12cmの正方形12枚に切る、穴は別の切れ端を重ねてふさぐ。シェフタリアを成形する、大さじ1杯（約50〜60g）の肉を取り、わずかに先細りした7〜8cmの円柱状に整える、網脂の正方形の縁に置く、両端を肉にかぶせ、しっかり巻いてソーセージ形にし、合わせ目を下にする、金串があれば刺してまとめる——なければ巻いた合わせ目で十分、残りの肉と網脂も同様に：合計12個、1人あたり3個。包んだソーセージをトレイに並べ、最低15分（最大4時間）冷蔵して網脂を固める——グリルでも崩れにくくなる。炭火グリルまたは厚手の波型グリドルパンを中強火に熱する（表面約200°C）、オリーブオイル大さじ1で軽く塗る、シェフタリアは網に触れるとジューと音がするはず——火が強すぎると肉が中まで火が通る前に網脂が焦げる。シェフタリアを合計12〜15分焼く、3〜4分ごとに四面それぞれに回し、網脂が薄いレース状の皮になり、中心温度が70°Cになるまで、深い黄金色で、しっかり弾力があるが硬すぎない仕上がりに。シェフタリアをまな板に取り、アルミホイルを軽くかぶせて5分休ませる、肉汁が落ち着き、余熱で中まで火が通る。ピタやレモニーブレッドをグリルで片面30秒ずつ温める、1人につき3個のシェフタリアと温かいパン、レモンのくし切り、赤玉ねぎのスライス、トマトのスライスを皿に盛る、ザジキかフムスを添える、シェフタリアを手でちぎり、ピタにサラダやディップと一緒に挟んで食べる。","en":"Make the meat mixture; in a wide bowl combine the minced pork, minced lamb, grated onion, parsley, mint (if using), garlic, salt, pepper, cumin, cinnamon, wine (or vinegar), and 1 tbsp olive oil; knead with your hand for 2–3 minutes until sticky and homogeneous; cover and chill in the fridge for at least 1 hour (up to 12 hours) so the seasoning matures. Prepare the caul fat; spread the soaked and drained caul fat carefully on a clean board — it tears very easily; use scissors to cut it into 12 squares of about 12 × 12 cm; patch holes by overlapping pieces. Shape the sheftalia; take a tablespoon-sized portion of meat (about 50–60 g) and shape into a slightly tapered cylinder 7–8 cm long; place at the edge of one caul-fat square; fold the sides over the meat, then roll up tightly into a sausage shape, finishing with the seam underneath; pierce onto a metal skewer if you have one — otherwise the wrapped seam will hold; repeat with the remaining meat and caul fat: you should get 12 sheftalia, 3 per person. Rest the wrapped sausages on a tray and chill for at least 15 minutes (up to 4 hours) so the caul fat firms — they hold together better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 200°C / 390°F surface); brush lightly with 1 tbsp olive oil; the sheftalia should hiss when they touch the grill but not flare aggressively — too high and the caul fat will burn before the meat cooks through. Grill the sheftalia for 12–15 minutes total, turning every 3–4 minutes onto each of their four sides, until the caul fat has rendered down into a thin lacy crust and the meat reaches 70°C in the centre; they should be deep golden brown and feel firm but not hard. Lift the sheftalia onto a board and rest, loosely tented with foil, for 5 minutes; the juices settle and the meat finishes cooking from residual heat. Warm the pitta or Cypriot lemoni-bread on the grill for 30 seconds per side; pile 3 sheftalia per person on each plate with the warm bread, lemon wedges, sliced red onion, and tomato; spoon tzatziki or hummus to the side; eat by tearing pieces of sheftalia into the pitta with the salad and dip."}},{"id":146,"origin":{"ja":"ボスニア・ヘルツェゴビナ","en":"Bosnia and Herzegovina","ro":"Bosnia și Herțegovina"},"name":{"ja":"チェバピ","en":"Cevapi","ro":"Cevapi"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["牛肩肉の粗びき500g（脂肪分約15%）","ラム肩肉の粗びき300g（ラムがない場合は牛肉のみで800g）","にんにく4片、塩小さじ0.5と共に細かなペースト状に潰す","冷たい炭酸水60ml","重曹（重炭酸ナトリウム）小さじ1——弾力ある食感の鍵","細かい海塩小さじ1.5","挽きたての黒胡椒小さじ1","ハンガリーの甘いパプリカパウダー小さじ1","ドライマジョラムまたはオレガノ小さじ0.5（任意だが伝統的）","焼き網に塗る中性油大さじ1","ソムン平焼きパン4枚（または、ピタ4枚）、各直径約18cm、添え用","大きな赤玉ねぎ1個（約200g）、ごく細かいみじん切り","アイヴァール200g（焼き赤パプリカのレリッシュ）","カイマック100g（バルカンのクロテッドクリーム）または濃いクレームフレッシュで代用","イタリアンパセリの小さなブーケ、葉のみを摘んで散らす用"],"en":["500 g coarsely minced beef chuck (about 15% fat)","300 g coarsely minced lamb shoulder (or 800 g all beef if lamb is unavailable)","4 garlic cloves, crushed with 0.5 tsp salt to a fine paste","60 ml chilled sparkling water","1 tsp baking soda (sodium bicarbonate) — the key to the springy texture","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp sweet Hungarian paprika","0.5 tsp dried marjoram or oregano (optional but traditional)","1 tbsp neutral oil for brushing","4 somun flatbreads (or 4 pittas), about 18 cm across each, to serve","1 large red onion (about 200 g), very finely diced","200 g ajvar (roasted red-pepper relish)","100 g kajmak (Balkan clotted cream) or thick crème fraîche, as a substitute","1 small bunch flat-leaf parsley, leaves picked, to scatter"],"ro":["500 g pulpă de vită tocată grosier (15% grăsime)","300 g umăr de miel tocat grosier (sau 800 g doar vită, dacă nu există miel)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă fină","60 ml apă minerală rece (carbogazoasă)","1 linguriță bicarbonat de sodiu — cheia texturii elastice","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță boia dulce maghiară","0,5 linguriță maghiran sau oregano uscat (opțional, dar tradițional)","1 lingură ulei neutru pentru uns","4 lipii somun (sau 4 pita) de aproximativ 18 cm fiecare, pentru servit","1 ceapă roșie mare (aproximativ 200 g), tocată foarte fin","200 g ajvar (pastă de ardei copți)","100 g kajmak (smântână groasă balcanică) sau crème fraîche groasă ca substitut","1 legătură mică de pătrunjel cu frunze plate, frunzele păstrate, pentru servit"]},"howIsMade":{"ja":"肉だねを作る、広めのボウルに牛ひき肉、ラムひき肉、にんにくと塩のペースト、冷たい炭酸水、重曹、塩、コショウ、パプリカ、マジョラムを入れる、手で4〜5分しっかりこねる——粘りが出て、まとまり感が出てくる、この長いこねと重曹がチェヴァプの弾力ある食感の鍵。ボウルにラップをかけ、冷蔵庫で最低4時間、理想は12〜24時間休ませる、香りがなじみ、たんぱく質が落ち着く。手を冷水で濡らす、大さじ一杯（約35〜40g）の肉を手のひらの間で転がし、長さ7〜8cm、太さ2cmの指型シリンダーに成形する、残りの肉でも同様に、合計約24本（1人6本）作る、トレイに並べていく。成形したチェヴァプを最低20分（最大4時間）冷蔵して締める——グリルでも形を保ちやすくなる。炭火グリルか厚手の波型グリドルパンを中強火に熱する（表面約220°C）、チェヴァプにはほんのわずかにオリーブオイルを塗る——薄い被膜程度、グリルは音を立てるが激しく煙立てない程度。チェヴァプを合計8〜10分焼く、2分ごとに4面それぞれに回し、表面がマホガニー色で縁がカリッとし、中心が65°Cになるまで（皿の上でも火が入る）、押さえつけないこと、目標はジューシーで弾力ある中身。チェヴァプを2分休ませる間に、ソムン（またはピタ）をグリルで片面30秒、軽く膨らんでうっすら焦げ目がつくまで温める、継ぎ目に沿って切り、ポケット状にする。各温かいフラットブレッドに6本のチェヴァプを詰める（または各皿のパンの横に6本置く）、横にアイヴァール大さじ1〜2、たっぷりのカイマック（またはクレームフレッシュ）、刻んだ生の赤玉ねぎを少量盛る、パセリの葉を散らしてすぐに供する——チェヴァプの肉汁がソムンに染み込むように。","en":"Make the meat mixture; in a wide bowl combine the minced beef, minced lamb, garlic-salt paste, chilled sparkling water, baking soda, salt, pepper, paprika, and marjoram; knead vigorously with your hand for 4–5 minutes — the mixture should become noticeably sticky and start to pull together; this long knead and the bicarbonate are what give cevapi their characteristic springy bounce. Cover the bowl with cling film and rest the mixture in the fridge for at least 4 hours, ideally 12–24 hours; the flavour matures and the proteins relax. Wet your hands with cold water; take a tablespoon-sized portion of meat (about 35–40 g) and roll it between your palms into a finger-shaped cylinder about 7–8 cm long and 2 cm thick; repeat with the remaining meat to make about 24 cevapi (6 per person); arrange on a tray as you go. Chill the shaped cevapi for at least 20 minutes (up to 4 hours) to firm — they hold their shape better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 220°C surface); brush the cevapi very lightly with oil — barely a glaze; the grill should hiss but not smoke aggressively. Grill the cevapi for 8–10 minutes total, turning every 2 minutes onto all four sides, until the surface is mahogany brown with crisp edges and the centre reaches 65°C (they continue cooking on the plate); do not press them down; the goal is juicy, springy interiors. While the cevapi rest for 2 minutes, warm the somun (or pittas) on the grill 30 seconds per side until just puffed and lightly charred; split each one open along the seam to make a pocket. Pile 6 cevapi inside each warm flatbread (or arrange 6 on each plate beside the bread); spoon 1–2 tablespoons of ajvar to one side, add a generous knob of kajmak (or crème fraîche), and a small mound of diced raw red onion; scatter parsley leaves and serve immediately — the cevapi juices should soak into the somun."}},{"id":147,"origin":{"ja":"ガーナ","en":"Ghana","ro":"Ghana"},"name":{"ja":"フフ","en":"Fufu","ro":"Fufu"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"ja":["新鮮なキャッサバ700g、皮をむいて5cm角切り（または、皮むき済みの冷凍キャッサバ500gを解凍）","半熟プランテンバナナ500g、大3本程度、皮をむいて5cm角切り（黄色い皮に黒い斑点があるものが甘さとでんぷんのバランスがよい）","茹で用に細かい海塩大さじ1","茹で用に冷水2リットル","茹で汁の熱湯約150mlをジャグに取り置き、温かく保つ","中性油（パーム油またはひまわり油）大さじ1、手と盛り付け用ボウルに塗る用","西アフリカの温かいスープ大鍋（ライトスープ、パームナッツ、グラウンドナッツ、またはエグシ600ml〜1L）、添え用","新鮮なスコッチボネット唐辛子のスライス、辛味追加用","ローストピーナッツまたは砕いたピーナッツ、スープに散らす用（任意）"],"en":["700 g fresh cassava root, peeled and cut into 5 cm chunks (or 500 g pre-peeled frozen cassava chunks, thawed)","500 g semi-ripe plantains, about 3 large, peeled and cut into 5 cm chunks (yellow skin streaked with black gives the right balance of sweet and starchy)","1 tbsp fine sea salt for the cooking water","2 litres cold water for boiling","About 150 ml hot cooking water reserved from the pot, kept warm in a jug","1 tbsp neutral oil (palm or sunflower), for oiling hands and the serving bowl","1 large pot of hot West African soup (600 ml–1 L of light soup, palmnut, groundnut, or egusi), for serving","Sliced fresh scotch bonnet chilli, for those who want extra heat","Roasted peanuts or crushed groundnuts, to scatter over the soup (optional)"],"ro":["700 g manioc proaspăt, curățat și tăiat bucăți de 5 cm (sau 500 g cassava decongelată, deja curățată)","500 g banane plantain semi-coapte, aproximativ 3 mari, decojite și tăiate bucăți de 5 cm (coaja galbenă cu pete negre dă echilibrul potrivit între dulce și amidonos)","1 lingură sare fină de mare pentru apa de fierbere","2 litri apă rece pentru fierbere","Aproximativ 150 ml apă fierbinte de fierbere păstrată separat, ținută caldă într-un vas","1 lingură ulei neutru (palmier sau floarea-soarelui), pentru a unge mâinile și bolul de servit","O cratiță mare cu supă vest-africană caldă (600 ml–1 L de light soup, palmnut, groundnut sau egusi), pentru servit","Ardei iute scotch bonnet feliat, pentru cei care vor mai mult picant","Arahide prăjite sau pisate, pentru presărat peste supă (opțional)"]},"howIsMade":{"ja":"キャッサバを準備する、冷水でキャッサバを洗い、付着した汚れを取り除く、鋭いナイフで厚い茶色の皮を縦方向に切れ目を入れ、ピンクの下層と一緒に剥き取って白い芯を出す、各ピースの中央の繊維状の芯を切り取って捨てる。厚手の5リットル鍋に、皮をむいたキャッサバ、プランテン、塩大さじ1、冷水2リットルを入れる、中強火で穏やかな沸騰に持っていき、中弱火に落として30〜40分煮込む、両方ともフォークで簡単に刺さる状態に——キャッサバは茹でたじゃがいものような感触。ザルにあけて湯切りするが、後で使うため少なくとも250mlの熱いゆで汁をジャグに取っておく、見える繊維や筋を取り除く。フフを搗く、伝統的な方法：油を数滴垂らした重い木製の臼に、熱いキャッサバとプランテンの混合を数回に分けて移す、長い木製の杵でリズミカルに搗き、もう1人（軽く油を塗った手）が打撃の合間に塊を回し集める、各回8〜10分作業し、塊が緻密で完全に滑らか、弾力が明らかに出る——だまがない——まで続ける。臼なしの方法：熱いキャッサバとプランテンを丈夫なスタンドミキサーに入れ、ドウフックを装着する、低速で1分回して塊を砕き、中速にして6〜8分、2分ごとにボウルをこそげながら混ぜ、塊がフックの周りに一つにまとまった弾力ある生地になるまで、乾きすぎなら大さじ1の熱いゆで汁を順次加える——目標は光沢があり弾力があり、しかし濡れていない状態。食感をテスト、小さな塊（約50g）を取り、軽く油を塗った手のひらで滑らかなボールに丸める、表面は光沢があり継ぎ目がなく、ボールは皿の上で崩れたり割れたりせず形を保つはず、割れる場合は熱湯をもう一さじ練り込み；崩れる場合はさらに2分捏ねる。軽く油を塗った手で盛り付け用のポーションを成形：約250gの大きなボールを4個（または伝統的な個別盛り用に8個の小さなボール）作る、それぞれのボールを軽く油を塗った広いボウルに置いて、くっつかないようにする、提供までは湿った布で覆う——フフは空気にさらされるとすぐに固くなる。すぐに提供する、各フフボールの周りに、温かい西アフリカのスープ（ライトスープ、パームナッツ、グラウンドナッツ、またはエグシ）を広い汁碗に注ぐ、食べ方：右手で小さなフフをつまみ、親指で凹みを作って小さな器の形にし、スープをすくう——フフは噛まず、丸ごと飲み込み、スープの風味で運ばれるようにする、お好みで刻んだスコッチボネット唐辛子とローストピーナッツを散らす。","en":"Prepare the cassava; wash the cassava chunks under cold water to remove any clinging grit; with a paring knife slit the thick brown skin lengthwise, then peel it away (along with the pink underlayer) to expose the white core; cut out the fibrous central string from each piece and discard. In a heavy 5-litre pot, combine the peeled cassava chunks, the plantain chunks, the 1 tbsp salt, and the 2 litres cold water; bring to a gentle boil over medium-high heat, then reduce to medium-low and cook for 30–40 minutes, until both cassava and plantain are fork-tender — the cassava should feel like a cooked potato when pierced. Drain into a colander but reserve at least 250 ml of the hot cooking liquid in a jug for later; pick out and discard any visible fibres or strings. Pound the fufu; traditional method: transfer the hot cassava-plantain mixture in batches to a heavy wooden mortar lubricated with a few drops of oil; with a long wooden pestle, pound rhythmically while a second person (lightly oiled hands) turns and gathers the mass between strokes; work for 8–10 minutes per batch until the paste is dense, perfectly smooth, and noticeably elastic — no lumps remain. Mortar-free method: place the hot cassava and plantain together in a sturdy stand mixer with the dough-hook attachment; run at low speed for 1 minute to break down the chunks, then increase to medium and beat for 6–8 minutes, scraping the bowl every 2 minutes, until the mass forms a single elastic dough around the hook; add a tablespoon of reserved hot cooking water at a time if it is too dry — the goal is glossy and elastic without being wet. Test the texture; pinch off a small piece (about 50 g) and roll it in lightly oiled palms into a smooth ball; the surface should be glossy and seamless, and the ball should hold its shape on a plate without sagging or cracking; if it cracks, work in another spoonful of hot water; if it slumps, knead for another 2 minutes. Shape the serving portions with lightly oiled hands: form 4 large balls of about 250 g each (or 8 smaller balls for traditional individual servings); place each ball in a slightly oiled wide bowl so it does not stick; cover with a damp cloth until ready to serve — fufu hardens quickly when exposed to air. Serve immediately; ladle hot West African soup (light soup, palmnut, groundnut, or egusi) into a wide soup bowl around each fufu ball; eat by pinching off a small piece of fufu with the right hand, pressing a depression into it with the thumb to form a cup, and using it to scoop up the soup — do not chew the fufu, swallow it whole so the flavour of the soup carries it down; scatter chopped scotch bonnet and roasted peanuts to taste."}},{"id":148,"origin":{"ja":"ジョージア","en":"Georgia","ro":"Georgia"},"name":{"ja":"ヒンカリ","en":"Khinkali","ro":"Khinkali"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["中力粉500g、打ち粉用に少量追加","冷水250ml","Lサイズの卵1個、軽く溶く（任意——一部のジョージア家庭ではよりやわらかい生地のために卵を入れる）","生地用の細かい海塩小さじ1","生地用の中性油大さじ1","牛肉の粗びき500g（脂肪約15%）","豚肩肉の粗びき200g（または、より脂肪の少ない仕上がりにしたい場合は牛肉のみで700g）","大玉ねぎ1個（約200g）、ごく細かいみじん切り——すりおろさない、食感が重要","にんにく3片、みじん切り","新鮮なコリアンダー20g、みじん切り——茎と葉","クミンパウダー小さじ1＋挽きたての黒胡椒小さじ1＋クメリスネリ小さじ0.5（または代用にキャラウェイ小さじ0.25＋フェヌグリークパウダー小さじ0.25）","詰め物用の細かい海塩小さじ1.5","氷のように冷たい牛ストックまたは冷水200ml（茹でる間にゆっくりと蒸気を放出する——これが有名なスープ袋の秘密）","茹で水用の粗い海塩大さじ1","食卓で散らす用に十分な量の挽きたての黒胡椒"],"en":["500 g plain (all-purpose) flour, plus extra for rolling","250 ml cold water","1 large egg, lightly beaten (optional — some Georgian families use an egg for a softer dough)","1 tsp fine sea salt for the dough","1 tbsp neutral oil for the dough","500 g coarsely minced beef (around 15% fat)","200 g coarsely minced pork shoulder (or 700 g all beef for a leaner result)","1 large onion (about 200 g), very finely diced — do NOT grate, the texture matters","3 garlic cloves, finely minced","20 g fresh coriander, finely chopped — stems and leaves","1 tsp ground cumin + 1 tsp freshly ground black pepper + 0.5 tsp khmeli suneli (or 0.25 tsp caraway + 0.25 tsp ground fenugreek as substitute)","1.5 tsp fine sea salt for the filling","200 ml ice-cold beef stock or cold water (releases steam slowly during boiling — this is what creates the famous broth pocket)","1 tbsp coarse sea salt for the cooking water","Plenty of freshly cracked black pepper, to scatter at the table"],"ro":["500 g făină albă obișnuită, plus pentru întins","250 ml apă rece","1 ou mare, bătut ușor (opțional — unele familii georgiene folosesc un ou pentru un aluat mai moale)","1 linguriță sare fină de mare pentru aluat","1 lingură ulei neutru pentru aluat","500 g vită tocată grosier (în jur de 15% grăsime)","200 g umăr de porc tocat grosier (sau 700 g doar vită pentru un rezultat mai slab)","1 ceapă mare (aproximativ 200 g), tocată foarte fin — NU rasă, textura contează","3 căței de usturoi, tocați fin","20 g coriandru proaspăt, tocat fin — tulpini și frunze","1 linguriță chimion măcinat + 1 linguriță piper negru proaspăt măcinat + 0,5 linguriță khmeli suneli (sau 0,25 linguriță chimion negru + 0,25 linguriță schinduf măcinat ca substitut)","1,5 lingurițe sare fină de mare pentru umplutură","200 ml supă de vită rece ca gheața sau apă rece (eliberează aburi încet în timpul fierberii — acesta este secretul pungii de bulion)","1 lingură sare grunjoasă de mare pentru apa de fierbere","Mult piper negru proaspăt măcinat, pentru presărat la masă"]},"howIsMade":{"ja":"生地：大きなボウルで中力粉500gに塩小さじ1を加えて混ぜる、冷水250ml（任意で溶き卵1個+油大さじ1）を少しずつ加えてフォークで混ぜ、作業台に出して8–10分こねる、生地が滑らかでしっかりと弾力があるまで——薄く伸ばしても破れない硬さが必要、ラップで覆って室温で30分休ませる。詰め物：ボウルに牛粗びき500g+豚粗びき200gと、極細みじん切りの玉ねぎ200g、にんにく3片、コリアンダーみじん切り20g、クミン小さじ1、黒胡椒小さじ1、クメリスネリ小さじ0.5、塩小さじ1.5を入れて手で混ぜる、氷のように冷たいストック200mlを50mlずつゆっくり加え、その都度混ぜる——詰め物はゆるく湿っているがスープ状にはならないように、覆って30分冷蔵する。伸ばし：生地を4等分する、1つずつ作業（残りは覆っておく）、打ち粉をした台で2mmの薄さに伸ばす、受け皿や大きなグラスで直径12–14cmの円を抜く、切れ端を集めて軽くこね、再度伸ばす。成形：円を手のひらに乗せ、中央に約30ml（大さじ2）の詰め物を置く、もう一方の手で詰め物の周りに18–20のひだを作り、それぞれ親指と人差し指でつまんで中心に向かって軽く捻る、最後にすべてのひだを上に集め、頂部——しっぽ——を捻って閉じる、打ち粉をした台にヒンカリを置く。茹で水：大鍋に水4Lを入れて勢いよく沸騰させ、粗塩大さじ1を加える。茹で：沸騰した湯に一度に5–6個ヒンカリを入れる（詰めすぎない）、表面に浮いたらすぐ（2–3分後）タイマー開始：さらに8–10分茹でる、合計12–14分、ひだが半透明になり、中のスープが動くのが見えれば完成。取り上げ：穴あきレードルで取り出し、軽く水切りして温めた皿に並べる、すぐに挽きたての黒胡椒をたっぷり散らす、ソースなし——ヒンカリはそのまま食べる。食べ方：指でヒンカリのしっぽを持ち、少し傾けて縫い目の近くを小さく噛んで穴を開け、こぼれる前に中の熱いスープを先にすする、残りを食べ、捻じれたしっぽは皿に残す、残ったしっぽの数=食べた個数。","en":"DOUGH: mix 500 g flour with 1 tsp salt in a large bowl; gradually pour in 250 ml cold water (and optionally 1 beaten egg + 1 tbsp oil), stirring with a fork, then knead on the bench 8–10 minutes until the dough is smooth, firm and elastic — it needs to be tough enough to roll thin without tearing; cover with film and rest 30 minutes at room temperature. FILLING: in a bowl, mix by hand 500 g beef + 200 g pork coarse-mince with 200 g very finely diced onion, 3 garlic cloves, 20 g chopped coriander, 1 tsp cumin, 1 tsp black pepper, 0.5 tsp khmeli suneli and 1.5 tsp salt; slowly pour in 200 ml ice-cold stock, 50 ml at a time, mixing after each addition — the filling should be loose and wet but not soupy; cover and chill 30 minutes. ROLLING: divide the dough into 4 pieces; work one piece at a time (keep the rest covered); roll out to a 2 mm thin sheet on a lightly floured surface; cut 12–14 cm diameter circles with a saucer or large glass; gather scraps, knead briefly and roll again. SHAPING: place a circle in your palm, put about 30 ml (2 tbsp) of filling in the centre; with the other hand, form 18–20 pleats around the filling, pinching each pleat between thumb and forefinger and twisting it gently toward the centre; at the end, gather all pleats at the top and twist the tip — the tail — to seal; set the khinkali on a floured surface. COOKING WATER: bring 4 litres of water to a vigorous rolling boil in a large pot and add 1 tbsp coarse salt. BOILING: drop 5–6 khinkali at a time into the boiling water (do not crowd); the moment they float to the surface (after 2–3 minutes), start your timer: boil another 8–10 minutes; total 12–14 minutes; they are done when the pleats turn translucent and you can see the broth moving inside. REMOVING: lift them out with a slotted spoon, let drain briefly and arrange on a warm plate; immediately scatter plenty of freshly cracked black pepper over the top; no sauce — khinkali are eaten plain. HOW TO EAT: hold the khinkali by the tail with your fingers, tilt slightly and bite a small hole near the seam, then sip the hot broth from inside first before it spills; then eat the rest of the dumpling, leaving the twisted tail on the plate; the number of tails left = how many you ate."}},{"id":149,"origin":{"ja":"メキシコ","en":"Mexico","ro":"Mexic"},"name":{"ja":"ポソレ","en":"Pozole","ro":"Pozole"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":6,"tipType":"meat","pairingsType":"mexican","ingredients":{"ja":["豚肩ロース骨なし1.2kg、4cm角に切る","豚首または尻尾の骨500g（より濃いストックのため）","大きな白玉ねぎ1個、皮付きで半分に切る（色付け用）+ 小玉ねぎ1個、みじん切りで添える用","にんにく8片（ストック用6片、チリソース用2片）","ローリエ3枚","ストック用の粗塩大さじ1 + 味付け塩","ストック用の冷水4L","ホミニーコーン缶詰800g、水切りして洗ったもの（または乾燥ホミニー250gを一晩水に浸し別途茹でたもの）","乾燥グアヒージョチリ6本、ヘタと種を取る","乾燥アンチョチリ4本、ヘタと種を取る","乾燥アルボルチリ2本（任意、辛さ用）","クミンパウダー小さじ1","乾燥メキシカンオレガノ小さじ1","提供用の細切り緑キャベツ200g","薄切り赤ラディッシュ150g","ライム4–6個をくし切り","トスタダ12枚（カリカリのコーントルティーヤ）","食卓で散らす生または乾燥オレガノ"],"en":["1.2 kg boneless pork shoulder, cut into 4 cm cubes","500 g pork neck bones or pork tail (for a richer broth)","1 large white onion halved, skin on (for color) + 1 small onion finely diced for serving","8 garlic cloves (6 for the broth, 2 for the chili sauce)","3 bay leaves","1 tbsp coarse salt for the broth + salt to taste","4 litres cold water for the broth","800 g canned hominy, drained and rinsed (or 250 g dried hominy soaked overnight and boiled separately)","6 dried guajillo chilies, stemmed and deseeded","4 dried ancho chilies, stemmed and deseeded","2 dried árbol chilies (optional, for heat)","1 tsp ground cumin","1 tsp dried Mexican oregano","200 g green cabbage, finely shredded for serving","150 g red radishes, thinly sliced","4–6 limes cut into wedges","12 tostadas (crisp corn tortillas)","Fresh or dried oregano to scatter at the table"],"ro":["1,2 kg umăr de porc dezosat, tăiat în cuburi de 4 cm","500 g oase de porc cu carne (gât sau coadă) pentru un bulion mai bogat","1 ceapă albă mare tăiată în jumătăți (cu coajă, pentru culoare) + 1 ceapă mică tocată fin pentru servire","8 căței de usturoi (6 pentru bulion, 2 pentru sosul de ardei)","3 frunze de dafin","1 lingură sare grunjoasă pentru bulion + sare după gust","4 litri apă rece pentru bulion","800 g hominy din conservă, scurs și clătit (sau 250 g hominy uscat înmuiat peste noapte și fiert separat)","6 ardei guajillo uscați, decotorați și fără semințe","4 ardei ancho uscați, decotorați și fără semințe","2 ardei de árbol uscați (opțional, pentru iuțeală)","1 linguriță chimion măcinat","1 linguriță oregano mexican uscat","200 g varză verde tocată mărunt, pentru servire","150 g ridichi roșii feliate subțire","4–6 lime tăiate în sferturi","12 tostadas (lipii de porumb crocante)","Oregano proaspăt sau uscat de presărat la masă"]},"howIsMade":{"ja":"スープのベース：大きな鍋に4cm角に切った豚肩ロース1.2kg+豚骨500g、半分に切った玉ねぎ1個（皮付き）、にんにく6片、ローリエ3枚、塩大さじ1を入れる、冷水4Lを加える、沸騰させ、最初の5分間アクを取り、それから弱火に落としてゆっくり煮込む。豚肉の煮込み：蓋をせずに1.5–2時間煮込み、肉がフォークでほぐれるまで、肉と骨を取り出し、2本のフォークで粗くほぐして取っておく、スープを濾して（約3.5L）、残りは捨てる。チリのロースト：乾いたフライパンを中火にかける、グアヒージョ6本+アンチョ4本+アルボル2本（任意）のチリを、フライ返しで押さえながら片面30秒ずつローストする、香りが立ち、軽く膨らむまで——焦がさないこと、焦げるとスープが苦くなる、ボウルに移し、熱湯をかけて15分間柔らかくなるまで浸す。チリソース：浸したチリをミキサーに入れ、にんにく2片、クミン小さじ1、オレガノ小さじ1、温かいスープ500mlを加える、高速で2–3分間、完全になめらかになるまで撹拌する、ピューレを目の細かい漉し器でボウルに濾し、果肉を押し通す——残った皮は捨てる。合わせる：濾したチリソースをスープの鍋に戻す、ほぐした肉と水切りしたホミニーコーン800gを加える、沸騰させ、蓋をせずに30–40分間時々混ぜながら煮込み、スープがわずかにとろみつき、味がなじむまで、味を見て塩で調整する——しっかりとしたコクがあるはず。薬味の準備：ポソレを煮込んでいる間に、キャベツ200gを細切りに、ラディッシュ150gを薄切りに、玉ねぎ1個をみじん切りに、ライム4–6個をくし切りにし、オレガノを用意する、それぞれを小皿に分けてテーブルに並べる。トスタダ：乾いたフライパンでトスタダ12枚を片面30秒ずつ温め、カリッと軽く色づくまで、バスケットに入れてテーブルに置く。盛り付け：ポソレを深皿に盛る、各自が自分の皿をカスタマイズする：キャベツひと掴み、ラディッシュをひと振り、玉ねぎとオレガノをひとつまみ、ライムを絞る、トスタダは横で——スープに割って入れるか、スプーン代わりに使う、アツアツのうちにすぐに食べる。","en":"BROTH BASE: place 1.2 kg cubed pork shoulder + 500 g pork bones, 1 halved onion (skin on), 6 garlic cloves, 3 bay leaves and 1 tbsp salt in a large stockpot; cover with 4 litres of cold water; bring to a boil, skim the foam for the first 5 minutes, then reduce to a gentle simmer. SIMMER THE PORK: simmer uncovered 1.5–2 hours until the pork is fork-tender; lift out meat and bones, shred the meat coarsely with two forks, set aside; strain the broth (~3.5 L) and discard the solids. TOAST THE CHILIES: heat a dry skillet over medium heat; toast 6 guajillo + 4 ancho + 2 árbol chilies (optional), pressing them down with a spatula, 30 seconds per side until fragrant and lightly blistered — do not burn or the broth will turn bitter; transfer to a bowl, cover with boiling water, and soak 15 minutes until softened. CHILI SAUCE: transfer the soaked chilies to a blender with 2 garlic cloves, 1 tsp cumin, 1 tsp oregano and 500 ml of the warm broth; blend on high 2–3 minutes until completely smooth; strain the puree through a fine sieve into a bowl, pressing the pulp through — discard the skin bits left behind. COMBINE: pour the strained chili sauce back into the broth pot; add the shredded pork and 800 g drained hominy; bring to a simmer and cook uncovered 30–40 minutes, stirring occasionally, until the broth thickens slightly and the flavours meld; taste and adjust salt — it should be deeply savoury. PREP THE GARNISHES: while the pozole simmers, finely shred 200 g cabbage, thinly slice 150 g radishes, finely dice 1 onion, cut 4–6 limes into wedges, prepare oregano; arrange each in small bowls on the table. TOSTADAS: warm 12 tostadas in a dry skillet 30 seconds per side until crisp and lightly toasted; place in a basket for the table. SERVE: ladle the pozole into deep bowls; each guest customises their bowl: a handful of cabbage, scattering of radish, pinch of onion and oregano, squeeze of lime; tostadas eaten alongside — broken into the broth or used to scoop; eaten immediately while piping hot."}},{"id":150,"origin":{"ja":"グアテマラ","en":"Guatemala","ro":"Guatemala"},"name":{"ja":"ペピアン","en":"Pepian","ro":"Pepian"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"ja":["骨付き鶏もも肉とドラムスティック1.2kg（約8切れ）","鶏肉のポーチング用に冷水1.5L+塩小さじ1","生の殻むきカボチャの種（ペピタス）100g","ゴマ50g","乾燥グアヒージョチリ4本、ヘタと種を取る","乾燥アンチョまたはパシージャチリ2本、ヘタと種を取る","乾燥チポトレチリ1本（任意、スモーキーな風味用）","中サイズのトマト4個（約500g）、半分に切る","トマティーヨ4個（約200g）、皮をむいて半分に切る","中サイズの玉ねぎ1個（約150g）、4つ切り","皮付きにんにく5片","セイロンシナモンスティック1本（約5cm）","ホールクローブ2粒","黒コショウ粉小さじ1+オールスパイス粉小さじ0.5","コーントルティーヤ1枚、ちぎる（とろみ用）","ギュイスキル（チャヨーテ）またはズッキーニで代用200g、皮をむき2cm角に切る","ジャガイモ300g、皮をむき2cm角に切る","ペーストを炒める用の植物油大さじ2","飾り用の細かく刻んだ新鮮なコリアンダー大さじ2","塩で味付け","炊いた白米500g+提供用の温かいトルティーヤ"],"en":["1.2 kg bone-in chicken thighs and drumsticks (about 8 pieces)","1.5 L cold water + 1 tsp salt for poaching","100 g raw hulled pumpkin seeds (pepitas)","50 g sesame seeds","4 dried guajillo chilies, stemmed and deseeded","2 dried ancho or pasilla chilies, stemmed and deseeded","1 dried chipotle chili (optional, for smokiness)","4 medium tomatoes (~500 g), halved","4 tomatillos (~200 g), husked and halved","1 medium onion (~150 g), quartered","5 unpeeled garlic cloves","1 Ceylon cinnamon stick (~5 cm)","2 whole cloves","1 tsp ground black pepper + 0.5 tsp ground allspice","1 corn tortilla, torn into pieces (for thickening)","200 g güisquil (chayote squash) or zucchini, peeled and cubed 2 cm","300 g potatoes, peeled and cubed 2 cm","2 tbsp vegetable oil for cooking the paste","2 tbsp fresh cilantro, finely chopped, to garnish","Salt to taste","500 g cooked white rice + warm tortillas to serve"],"ro":["1,2 kg pulpe și pulpe inferioare de pui cu os (aproximativ 8 bucăți)","1,5 L apă rece + 1 linguriță sare pentru fierberea puiului","100 g semințe crude de dovleac decojite (pepitas)","50 g semințe de susan","4 ardei guajillo uscați, decotorați și fără semințe","2 ardei ancho sau pasilla uscați, decotorați și fără semințe","1 ardei chipotle (opțional, pentru afumare)","4 roșii medii (~500 g), tăiate în jumătăți","4 tomatillos (~200 g), curățați de coajă și tăiați în jumătăți","1 ceapă medie (~150 g), tăiată în sferturi","5 căței de usturoi, necurățați","1 batjoc de scorțișoară Ceylon (~5 cm)","2 cuișoare întregi","1 linguriță piper negru măcinat + 0,5 linguriță ienibahar măcinat","1 tortilla de porumb, ruptă în bucăți (pentru îngroșare)","200 g chayote (sau dovlecel ca substitut), curățat și tăiat cuburi de 2 cm","300 g cartofi, curățați și tăiați cuburi de 2 cm","2 linguri ulei vegetal pentru sotare","2 linguri coriandru proaspăt, tocat fin, pentru ornare","Sare după gust","500 g orez alb gătit + tortillas calde pentru servire"]},"howIsMade":{"ja":"鶏肉のポーチング：大きな鍋に鶏肉1.2kgと冷水1.5L、塩小さじ1を入れる、沸騰させ、アクを取り、弱火に落としてゆっくり煮込む、25–30分茹で、鶏肉に火が通る（透明な肉汁が出る）まで、鶏肉を皿に取り出し、スープ（約1.2L）を取っておく。種をローストする：乾いたフライパンを中火にかけ、絶えず混ぜながらカボチャの種100gを3–4分ローストし、膨らんで金茶色になるまで——焦がさない、ボウルに移す、同じフライパンでゴマ50gを1–2分、絶えず混ぜながら金色で香ばしくなるまでローストする、同じボウルに加える。野菜を焦がす：乾いたフライパンまたはコマルを中強火で、半分に切ったトマト4個（切り口を下向きにしてから）、半分に切ったトマティーヨ4個、4つ切り玉ねぎ1個、皮付きにんにく5片を焦がす、8–10分、時々返しながら、皮が部分的に黒くなり野菜が柔らかくなるまで、冷ましてからにんにくの皮をむく。チリとスパイスをロースト：同じフライパンで、グアヒージョ4本+アンチョ2本+チポトレ1本（任意）を、フライ返しで押さえながら20–30秒ずつ片面ローストし、香りが立つまで——焦がさない、ボウルに移し、熱湯をかけて15分浸す、同じフライパンで、シナモンスティック1本、クローブ2粒、コショウ小さじ1、オールスパイス小さじ0.5を30秒短時間ローストする、ちぎったトルティーヤを片面30秒ずつカリッとローストする。ペーストをブレンド：ブレンダーに水切りしたチリ、焦がした野菜、皮をむいたにんにく、ローストした種、トルティーヤの欠片、鶏スープ500mlを入れる、高速で3–4分、完全になめらかになるまでブレンドする——絹のような口当たりにしたい場合は目の細かい漉し器で漉す。ソースを煮る：鍋に油大さじ2を中火で熱する、ブレンドしたペーストを注ぐ——飛び散るので注意、10分、木べらで頻繁にかき混ぜながら煮込み、ソースが色を増し生っぽさが消えるまで、ソースは木べらの裏にコーティングするはず。鶏肉を煮込む：鶏肉を鍋に戻し、残りの700mlのスープ+200gのチャヨーテ+300gのジャガイモ角切りを注ぐ、半分蓋をして弱火で25–30分、ジャガイモとチャヨーテがフォークで通るほど柔らかくなり、鶏肉がソースに完全に染み込むまで煮込む、時々かき混ぜる、塩で調整する。盛り付け：蒸した白米のベッドの上に深皿にペピアンをよそる、新鮮なコリアンダーを散らし、お好みでライムを絞る（任意）、温かいコーントルティーヤを添えてソースをすくう。","en":"POACH THE CHICKEN: place 1.2 kg chicken pieces in 1.5 L cold water with 1 tsp salt in a large pot; bring to a boil, skim the foam, then reduce to a gentle simmer; cook 25–30 minutes until the chicken is just cooked through (juices run clear); remove the chicken to a plate and reserve the broth (~1.2 L). TOAST THE SEEDS: in a dry skillet over medium heat, toast 100 g pumpkin seeds, stirring constantly, 3–4 minutes until they puff up and turn golden brown — do not burn; transfer to a bowl; in the same skillet, toast 50 g sesame seeds 1–2 minutes until golden and fragrant, stirring constantly; add to the same bowl. CHAR THE VEGETABLES: in a dry skillet or comal over medium-high heat, char 4 halved tomatoes (cut side down first), 4 halved tomatillos, 1 quartered onion, and 5 unpeeled garlic cloves; turn occasionally for 8–10 minutes until the skins are blackened in spots and the vegetables soften; peel the garlic after they cool. TOAST THE CHILIES AND SPICES: in the same skillet, briefly toast 4 guajillo + 2 ancho + 1 chipotle (optional) chilies, pressing them flat with a spatula, 20–30 seconds per side until fragrant — do not burn; transfer to a bowl and cover with boiling water; soak 15 minutes; in the same skillet, briefly toast 1 cinnamon stick, 2 cloves, 1 tsp pepper, and 0.5 tsp allspice for 30 seconds; toast the torn tortilla pieces 30 seconds per side until crisp. BLEND THE PASTE: in a blender, combine the drained chilies, the charred vegetables, peeled garlic, toasted seeds, toasted tortilla pieces, and 500 ml of the chicken broth; blend on high 3–4 minutes until the paste is completely smooth — strain through a fine sieve if you want it silky. COOK THE SAUCE: heat 2 tablespoons of oil in the pot over medium heat; pour in the blended paste — be careful, it will splutter; simmer 10 minutes, stirring frequently with a wooden spoon, until the sauce darkens and the rawness cooks off; the sauce should coat the back of the spoon. STEW THE CHICKEN: return the chicken pieces to the pot, then pour in the remaining 700 ml broth + 200 g chayote + 300 g potato cubes; simmer gently, partially covered, 25–30 minutes until the potatoes and chayote are fork-tender and the chicken is fully infused with the sauce; stir occasionally to prevent sticking; adjust salt to taste — the sauce should taste deeply spiced and slightly sweet. SERVE: spoon the pepian into deep plates over a bed of steamed white rice; top each serving with a sprinkle of fresh cilantro and a squeeze of lime (optional); serve with warm corn tortillas on the side for scooping up the sauce."}},{"id":151,"origin":{"ja":"ロシア","en":"Russia","ro":"Rusia"},"name":{"ja":"オクロシカ","en":"Okroshka","ro":"Okroshka"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"ja":["プレーンケフィア（脂肪3.2%）1L、よく冷やしたもの","冷たい無炭酸ミネラルウォーター（または冷ました煮沸水）500ml、冷やしたもの","中サイズのでんぷん質のジャガイモ500g（4個）、皮付きで茹でて皮をむき1cmの角切り","Lサイズのゆで卵4個、殻をむいて1cmの角切り","キュウリ400g（中3本）、皮をむき大きな種を取り除き0.5cmの角切り","ドクトルスカヤソーセージまたは茹でハム300g、0.5cmの角切り","赤ラディッシュ150g、ヘタを取って0.5cmの角切り","青ねぎ6本（白い部分と緑の部分を分ける）、薄切り","新鮮なディル30g、みじん切り（飾り用に大さじ1追加）","ディジョンマスタード大さじ1（任意だが伝統的）","細塩小さじ1.5 + 挽きたての黒胡椒小さじ0.5","砂糖小さじ1（ケフィアの酸味を中和）","レモン汁または白ワインビネガー小さじ1","サワークリーム（スメタナ）、提供時に","氷とフレッシュなライ麦パン、提供時に"],"en":["1 L plain kefir (3.2% fat), well chilled","500 ml cold still mineral water (or cold boiled water), chilled","500 g medium starchy potatoes (4 pieces), boiled in skins then peeled and diced 1 cm","4 large hard-boiled eggs, peeled and diced 1 cm","400 g cucumbers (3 medium), peeled, large seeds scooped out, diced 0.5 cm","300 g cooked doktorskaya sausage or boiled ham, diced 0.5 cm","150 g red radishes, trimmed and diced 0.5 cm","6 spring onions (whites and greens kept separate), thinly sliced","30 g fresh dill, finely chopped (plus 1 tbsp to garnish)","1 tbsp Dijon-style mustard (optional but traditional)","1.5 tsp fine salt + 0.5 tsp freshly ground black pepper","1 tsp sugar (balances the kefir tang)","1 tsp lemon juice or white-wine vinegar","Sour cream (smetana) to drizzle when serving","Ice cubes and fresh dark rye bread for serving"],"ro":["1 L chefir simplu 3,2% grăsime, bine răcit","500 ml apă minerală plată rece sau apă fiartă rece, răcită","500 g cartofi medii (4 bucăți) fierți în coajă, decojiți și tăiați cuburi de 1 cm","4 ouă mari fierte tari, decojite și tăiate cuburi de 1 cm","400 g castraveți (3 bucăți medii), decojiți, fără sâmburi mari și tăiați cuburi de 0,5 cm","300 g cârnați doktorskaya sau șuncă fiartă, tăiată cuburi de 0,5 cm","150 g ridichi roșii, tăiate cuburi de 0,5 cm","6 cepe verzi (cu părți albe și verzi separate), feliate subțire","30 g mărar proaspăt, tocat fin (plus 1 lingură pentru ornare)","1 lingură muștar Dijon (opțional, dar tradițional)","1,5 lingurițe sare fină + 0,5 linguriță piper negru proaspăt măcinat","1 linguriță zahăr (echilibrează aciditatea chefirului)","1 linguriță suc de lămâie sau oțet de vin alb","Smântână (smetana) pentru servire","Cuburi de gheață și pâine neagră proaspătă pentru servire"]},"howIsMade":{"ja":"ジャガイモと卵を茹でる：冷たい塩水の鍋でジャガイモ500g丸ごと（皮付き、洗ったもの）を20–25分、フォークが通るまで茹でる、別の鍋に卵4個と冷水を入れ、沸騰させてから9分茹でて固ゆでにする、両方を湯切りし、ジャガイモは皮むきしやすいように冷水をかけ、卵は氷水に5分浸す、皮をむいて両方1cm角に切り、トレイに広げて30分冷蔵庫で冷やす——混ぜる前にすべて冷たくする必要がある。キュウリの角切り：キュウリ400gを皮をむき、縦半分に切り、大きな水っぽい種をスプーンで取り除き、0.5cm角に切る——小さく均等な角切りが必須で、大きな切片は沈んでスープを台無しにする、キッチンペーパーで水気をふき取る。たんぱく質の角切り：茹でたソーセージまたは茹でハム300gを0.5cm角に切る——キュウリと同じサイズで、ひとさじごとにバランスがよくなる。ラディッシュと玉ねぎ：ラディッシュ150gのヘタを取って0.5cm角に切る、青ねぎ6本を切る（白い部分と緑の部分を分けておく）、ディル30gを細かく刻み、飾り用に大さじ1取っておく、小さなボウルで青ねぎの白い部分大さじ2を塩ひとつまみとともにスプーンの背でつぶす——香りをスープに引き出す。ドレッシング：大きなボウルで冷たいケフィア1L + 冷水500ml + マスタード大さじ1 + レモン汁小さじ1 + 塩小さじ1.5 + コショウ小さじ0.5 + 砂糖小さじ1を泡立て器で混ぜる、30秒混ぜてなめらかになるまで、味見する——ベースは酸味と少し甘味があり、切った食材が薄めるため十分に味付けされていること。合わせる：切った全ての食材（ジャガイモ、卵、キュウリ、ソーセージ、ラディッシュ、青ねぎの緑、つぶした白、ディル）をケフィアのベースに加える、レードルで何も潰さずに均等に分散させるよう優しく混ぜる。冷やす：オクロシカを覆って最低30分（理想は1時間）冷蔵庫で冷やし、風味を融合させてスープを氷のように冷やす、3時間以上は冷やさないこと——キュウリが水分を出してスープが薄くなる。盛り付け：盛る前に優しく混ぜる、冷やした深皿にレードルでよそる、各ボウルにサワークリーム大さじ1、追加のディル、夏の暑さでは1ボウルあたり氷2個をトッピング、新鮮なライ麦パンを添えてすぐに提供する；卓上にマスタードをよりピリッとした味が好きな人のために置く。","en":"BOIL THE POTATOES AND EGGS: in a pot of cold salted water, boil 500 g whole potatoes (skins on, scrubbed) 20–25 min until fork-tender; in a second pot, place 4 eggs in cold water, bring to a boil, then simmer 9 min for hard-boiled; drain both, cover potatoes with cold water to peel easily, plunge eggs into ice water 5 min; peel and dice both 1 cm; spread on a tray and chill 30 min in the fridge — everything must be cold before mixing. DICE THE CUCUMBERS: peel 400 g cucumbers, halve lengthwise, scoop out any large watery seeds with a spoon, then dice 0.5 cm — the small even cube is essential, larger pieces sink and ruin the soup; pat with paper towel to remove excess water. DICE THE PROTEIN: dice 300 g cooked sausage or boiled ham into 0.5 cm cubes — the same size as the cucumbers so each spoonful balances. DICE RADISH AND ONIONS: trim and dice 150 g radishes 0.5 cm; slice 6 spring onions (whites and greens kept separate); finely chop 30 g dill, reserve 1 tbsp for garnish; in a small bowl, mash 2 tbsp of the spring-onion whites with a pinch of salt using the back of a spoon — this releases their aroma into the soup. THE DRESSING: in a large mixing bowl, whisk together 1 L cold kefir + 500 ml cold water + 1 tbsp mustard + 1 tsp lemon juice + 1.5 tsp salt + 0.5 tsp pepper + 1 tsp sugar; whisk 30 seconds until smooth, then taste — the base should be tangy and slightly sweet, generously seasoned because the diced ingredients will dilute it. ASSEMBLE: add all diced ingredients (potatoes, eggs, cucumbers, sausage, radish, spring-onion greens and mashed whites, dill) to the kefir base; stir gently with a ladle to distribute evenly without crushing anything. CHILL: cover and refrigerate the okroshka 30 minutes minimum (ideally 1 hour) so the flavours mingle and the soup becomes ice-cold; do not chill longer than 3 hours — the cucumbers will start to release water and the soup turns thin. SERVE: stir gently before serving; ladle into deep, well-chilled bowls; top each bowl with 1 tablespoon sour cream, a few extra dill fronds, and 2 ice cubes per bowl in summer heat; serve immediately with fresh dark rye bread on the side; mustard on the table for those who like it sharper."}},{"id":152,"origin":{"ja":"ウズベキスタン","en":"Uzbekistan","ro":"Uzbekistan"},"name":{"ja":"プロフ","en":"Plov","ro":"Plov"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"ja":["脂肪を含む羊肩肉または牛首肉600g、3cm角に切る","本格的な風味のための羊尾脂（kurdyuk）100g — または代用としてニュートラルなひまわり油150ml","デブズィラ米または長粒バスマティ米500g","黄人参（または橙人参600g）500g、0.5 × 0.5 × 5cmの千切り——すりおろさない","大きな黄玉ねぎ2個（約300g）、薄切り","にんにくの株丸ごと2個（外側の薄皮を取り、株は丸のままに）","ホールクミンシード大さじ1（粉末ではない）","乾燥バルベリー（zira/barbaris）大さじ1——任意だが伝統的","ターメリックパウダー小さじ0.5（色付け用）","乾燥した赤唐辛子1本（任意）","黒コショウ粉小さじ1","細塩大さじ1.5 + 味付け塩","熱湯1.2L（控え）","ひよこ豆100g、一晩水に浸したもの（任意、タシケント伝統)","提供時の付け合わせ: 酢を振った赤玉ねぎの薄切り、トマト・キュウリのアチチュクサラダ、ノーンの平焼きパン"],"en":["600 g lamb shoulder or beef chuck with some fat, cut into 3 cm cubes","100 g lamb-tail fat (kurdyuk) for authentic flavour — OR 150 ml neutral sunflower oil as a substitute","500 g devzira or long-grain basmati rice","500 g yellow carrots (or 600 g orange carrots), cut into julienne matchsticks 0.5 × 0.5 × 5 cm — do NOT grate","2 large yellow onions (~300 g), thinly sliced","2 whole heads of garlic (papery outer skins removed but heads intact)","1 tbsp whole cumin seeds (not ground)","1 tbsp dried barberries (zira/barbaris) — optional but traditional","0.5 tsp ground turmeric (for colour)","1 dried whole hot red chili (optional)","1 tsp ground black pepper","1.5 tbsp fine salt + extra to season","1.2 L boiling water (reserve)","100 g chickpeas, soaked overnight (optional, traditional Tashkent style)","To serve: thinly sliced red onion with vinegar, achichuk tomato-cucumber salad, flatbread (non)"],"ro":["600 g umăr de miel sau gulaș de vită cu puțină grăsime, tăiat cuburi de 3 cm","100 g grăsime de coadă de oaie (kurdyuk) — opțional pentru aromă autentică — SAU 150 ml ulei neutru de floarea-soarelui ca substitut","500 g orez devzira sau basmati cu bob lung","500 g morcovi galbeni (sau 600 g morcovi portocalii), tăiați julien în bețișoare de 0,5 × 0,5 × 5 cm — NU dați prin răzătoare","2 cepe galbene mari (~300 g), feliate subțire","2 căpățâni de usturoi întregi (cu coaja exterioară curățată, dar capul păstrat întreg)","1 lingură semințe de chimion întregi (nu măcinate)","1 lingură fructe uscate de cătină (zira/barbaris) — opțional, tradițional","0,5 linguriță turmeric măcinat (pentru culoare)","1 ardei roșu iute uscat întreg (opțional)","1 linguriță piper negru măcinat","1,5 linguri sare fină + sare după gust","1,2 L apă clocotită (rezerve)","100 g năut, înmuiat peste noapte (opțional, tradițional Tashkent)","Pentru servire: ceapă roșie feliată subțire cu oțet, salată de roșii cu castraveți (achichuk), pâine plată non"]},"howIsMade":{"ja":"米を浸す：500gの米を冷水で4–5回洗い水が透明になるまで、それから温かい塩水（1L当たり塩小さじ1）で1時間浸す、プロフにおいてこのステップは必須——米粒は離れていて、ブロスを均等に吸収する、鍋に加える直前に水を切る。脂をレンダリング：重い鋳鉄製カザンまたはダッチオーブンを中火にかけ、羊尾脂100gを溶かして肉カスが金茶色になるまで（約8分間）、その後穴あきレードルで取り出す、油を使う場合：150mlの油を輝いて軽く煙が出るまで温める（強火で約3分間）——生っぽさを中和するために必須。肉を焼く：強火に上げ、熱い脂に肉600gを1段に並べる、動かさず2–3分各面焼き、合計8–10分、全面が深く色付くまで、肉を取り出して皿に置く。玉ねぎ+人参：残った脂に薄切り玉ねぎ300gを加え、混ぜながら5–6分炒めて金茶色に、肉を戻して千切り人参500gを1層に上に乗せ——最初の5分は混ぜないこと（人参を蒸らす）、それから優しく混ぜ、さらに8–10分炒めて人参がしんなりし金茶色でちょうどカラメル化が始まるまで。ジルヴァク（スープベース）：熱湯1.2Lを注ぐ（肉と人参を1cm覆うはず）、クミンシード大さじ1（最初に手のひらで擦ってオイルを放出）、バルベリー大さじ1、ターメリック小さじ0.5、乾燥チリ1本、コショウ小さじ1、ひよこ豆100g、塩大さじ1.5、にんにくの株丸ごと2つを中央に押し込む、沸騰させ、火を弱め蓋なしで30分煮込む——これがジルヴァク、スープは少し味付けすぎに感じるはず；米がそれを和らげる。米を加える：浸した米を注意深く水切りし、ジルヴァクの上に均等に広げる（混ぜない）、米はちょうど水に浸かるはず——そうでなければ熱湯を慎重に追加する、強火に上げ、蓋なしで10–12分炊いて見える水が米の表面まで減るまで（箸で確認）、穴あきレードルで米を平らに叩くが、下の肉層と決して混ぜないこと。蓋+蒸す：表面の水が蒸発し米の表面に小さな蒸気孔が現れたら、米をドーム形に盛り上げ、木べらの柄で底まで届く深い穴を4–5個開け（蒸気が抜けるよう）、火を最弱にして、鍋に密閉する蓋をして（蓋の下に清潔な布巾を入れて結露を吸収）、25分炊く、それから火から下ろし、蓋をして15分休ませる——蓋を持ち上げないこと。盛り付け：蓋を外し、にんにくの株とチリを取り出す、スプーンで優しく掘り、米を持ち上げて肉と人参を底から上に出し、大きな共同の皿に移しながら混ぜる、中央に肉とにんにくを置き、米で囲む、すぐに酢を振った赤玉ねぎの薄切り、フレッシュなトマトサラダ、平焼きパンを添えて提供する。","en":"SOAK THE RICE: wash 500 g rice in cold water 4–5 times until the water runs clear, then soak it in warm salted water (1 tsp salt per litre) for 1 hour; this step is non-negotiable for plov — the grains stay separate and absorb the broth evenly; drain just before adding to the pot. RENDER THE FAT: in a heavy cast-iron kazan or Dutch oven over medium heat, melt 100 g lamb-tail fat until the cracklings are golden brown (about 8 minutes), then remove them with a slotted spoon; if using oil: heat 150 ml oil until it shimmers and faintly smokes (about 3 minutes at high heat) — essential to neutralize the raw taste. SEAR THE MEAT: raise heat to high and add 600 g cubed meat in a single layer to the hot fat; sear undisturbed 2–3 minutes per side, total 8–10 minutes, until deeply browned on all sides; lift the meat out to a plate. ONION + CARROT: in the remaining fat, add 300 g sliced onion and fry, stirring, 5–6 minutes until golden brown; return the meat and add 500 g julienned carrots in a single layer on top — do NOT stir for the first 5 minutes (this lets the carrots steam); then stir gently and cook another 8–10 minutes until the carrots are wilted, golden, and just starting to caramelize. ZIRVAK (BROTH BASE): pour in 1.2 L boiling water (it should cover the meat and carrots by 1 cm); add 1 tbsp cumin seeds (first rubbed briefly between your palms to release the oils), 1 tbsp barberries, 0.5 tsp turmeric, 1 dried chili, 1 tsp black pepper, 100 g chickpeas, 1.5 tbsp salt, and the 2 whole garlic heads pushed into the centre; bring to a boil, reduce heat to low and simmer uncovered 30 minutes — this is the zirvak; the broth must taste slightly over-seasoned; the rice will tame it. ADD THE RICE: drain the soaked rice carefully and spread it evenly over the zirvak (do not stir it in); the rice should just be submerged — if not, add boiling water carefully; raise heat to high and cook uncovered 10–12 minutes until the visible water has reduced to the surface of the rice (poke with a chopstick to check); tap the rice flat with a slotted spoon but never mix it with the meat layer below. COVER + STEAM: once the surface water has evaporated and small steam holes appear on the rice surface, mound the rice into a dome, poke 4–5 deep holes through to the bottom with the handle of a wooden spoon (for steam to escape), reduce heat to the lowest setting, cover the pot with a tight lid (place a clean kitchen towel under the lid to absorb condensation), and cook 25 minutes; then remove from heat and let rest, covered, 15 minutes — do not lift the lid. SERVE: uncover and lift out the garlic heads and chili; gently dig down with a spoon, lifting the rice and bringing the meat and carrots from the bottom to the top, mixing as you transfer to a large communal platter; arrange the meat and garlic on top in the centre, surrounded by rice; serve immediately with sliced red onion sprinkled with vinegar, fresh tomato salad, and flatbread on the side."}},{"id":153,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"ja":"スロベニア","en":"Slovenia","ro":"Slovenia"},"name":{"ja":"ポティツァ","en":"Potica","ro":"Potica"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"ingredients":{"ja":["生地用：強力粉500g、こね用に少量追加","インスタントドライイースト7g または生イースト21g","細目グラニュー糖50g（イースト活性化用に小さじ1、残りを生地に）","細塩5g","温めた全乳250ml（38 °C）","無塩バター100g、溶かして人肌に冷ましたもの","Lサイズの卵黄2個 + 生地用に全卵1個","ダークラム酒大さじ1（任意、伝統的）","無農薬レモン1個の細かいすりおろし皮","クルミフィリング用：殻むきクルミ400g、細かく挽いたもの（挽きたて——プリグラインドは不可）","熱い全乳200ml","アカシア蜂蜜150g（または穏やかな花蜂蜜）","フィリング用無塩バター100g、溶かしたもの","フィリング用細目グラニュー糖100g","卵黄2個 + 卵白2個（別々に角が立つまで泡立て）","ダークラム酒大さじ1、シナモンパウダー小さじ1、クローブパウダー小さじ0.5、新鮮なパン粉大さじ1","仕上げ用：卵1個を牛乳大さじ1で溶いた卵液、焼き上がり後にかける粉砂糖"],"en":["For the dough: 500 g bread flour (or strong all-purpose), plus extra for kneading","7 g instant dry yeast OR 21 g fresh yeast","50 g caster sugar (1 tsp to feed the yeast, the rest in the dough)","5 g fine salt","250 ml warm whole milk (38 °C)","100 g unsalted butter, melted and cooled to lukewarm","2 large egg yolks + 1 whole egg for the dough","1 tbsp dark rum (optional, traditional)","Finely grated zest of 1 unwaxed lemon","For the walnut filling: 400 g finely ground shelled walnuts (freshly ground — pre-ground will not work)","200 ml hot whole milk","150 g acacia honey (or mild floral honey)","100 g unsalted butter, melted, for the filling","100 g caster sugar for the filling","2 large egg yolks + 2 egg whites (whipped to stiff peaks separately)","1 tbsp dark rum, 1 tsp ground cinnamon, 0.5 tsp ground cloves, 1 tbsp fresh breadcrumbs","For finishing: 1 egg beaten with 1 tbsp milk (egg wash), icing sugar to dust after baking"],"ro":["Pentru aluat: 500 g făină pentru pâine (T550), plus pentru frământare","7 g drojdie uscată instant SAU 21 g drojdie proaspătă","50 g zahăr fin (1 linguriță pentru a hrăni drojdia, restul în aluat)","5 g sare fină","250 ml lapte integral cald (38 °C)","100 g unt nesărat topit și răcit la călduț","2 gălbenușuri mari + 1 ou întreg pentru aluat","1 lingură rom întunecat (opțional, tradițional)","Coaja rasă fin de la 1 lămâie netratată","Pentru umplutură: 400 g miez de nucă măcinat fin (proaspăt măcinat, nu pre-măcinat — esențial)","200 ml lapte integral fierbinte","150 g miere de salcâm (sau miere florală blândă)","100 g unt nesărat topit pentru umplutură","100 g zahăr fin pentru umplutură","2 gălbenușuri + 2 albușuri (bătute spumă tare separat)","1 lingură rom întunecat, 1 linguriță scorțișoară măcinată, 0,5 linguriță cuișoare măcinate, 1 lingură pesmet proaspăt","Pentru finisare: 1 ou bătut cu 1 lingură lapte (spălătură), zahăr pudră pentru presărat după coacere"]},"howIsMade":{"ja":"イーストを活性化：小さなボウルにインスタントドライイースト7g（または生イースト21g）を温めた牛乳250ml（約38 °C）と砂糖小さじ1で溶かす、10分間置いて表面にクリーミーな泡が現れるまで——泡立たない場合はイーストが死んでいるので、最初からやり直す。生地：ドゥフックの付いたスタンドミキサーで（または手で）、強力粉500gと残りの砂糖47g、塩5g、レモンの皮を合わせる、泡立てたイースト入り牛乳、卵黄2個+全卵1個、溶かし冷ました100gのバター、ラム酒大さじ1を注ぐ、中速で10分（手で15分）こねて、生地が滑らかで弾力があり、ボウルからきれいに離れるまで——柔らかいが粘らない状態に、フィルムで覆い、暖かい場所で1.5–2時間、倍の大きさになるまで発酵させる。クルミフィリング：挽きたてのクルミ400gを大きなボウルに入れる、熱い牛乳200ml、溶かしたバター100g、蜂蜜150g、砂糖100gをかける、よく混ぜてクルミを熱通しし砂糖を溶かす、10分間冷ました後、卵黄2個、ラム酒大さじ1、シナモン小さじ1、クローブ小さじ0.5、パン粉大さじ1、塩ひとつまみを混ぜ込む、別のボウルで卵白2個を角が立つまで泡立て、3回に分けてクルミ混合物に優しく折り込む——フィリングは空気を含んで広げやすい状態に。生地を伸ばす：清潔な布巾に軽く打ち粉をして、発酵した生地をその上に取り出す、優しく空気を抜き、60 × 40 cm、厚さ4–5 mmの薄い長方形に伸ばす——中心から外側に向かって作業し、持ち上げて回転させてくっつかないようにする、生地は焼き上がり後にらせんが見える程度に薄く、フィリングを保持できる程度に厚くする必要がある。フィリングを広げる：クルミフィリングを生地全体に均等に広げ、長辺に沿って2 cmの縁を残す、スパチュラで優しく押す——詰めすぎず、フィリングは5–6 mmの厚さに、薄く流れる箇所があれば、追加の挽いたクルミを散らす。巻く：布巾を使って、生地を長辺からきっちりと巻き、長い丸太状にする、きつく巻くが、フィリングを圧縮するほどではない、継ぎ目をつまんで閉じ、両端をしまい込む、丸太は約60 cmの長さに。型 + 二次発酵：チューブ状のポティツァ型（または24 cmのバントケーキ型かクグロフ型）をバターで十分に塗り、小麦粉を振る、生地を継ぎ目を下にして型に置き、両端をつまんで閉じたリング状にする、緩く覆って暖かい場所で45–60分、生地が目に見えて膨らみ型をほぼ満たすまで発酵させる、その間、オーブンを175 °Cに予熱する。焼く：上面に卵液を塗る、175 °Cのオーブンの中段で45–55分焼く——上が早く焼き色がつき過ぎる場合は30分後にホイルでゆるく覆う、串が清くて出てきて、内部温度が92–95 °Cに達すればポティツァは完成、型の中で15分休ませた後、慎重にケーキクーラーにひっくり返して完全に冷ます、スライスする前に粉砂糖をたっぷりかける、室温で濃いコーヒーまたは紅茶と一緒に提供する。","en":"ACTIVATE THE YEAST: in a small bowl, dissolve 7 g instant dry yeast (or 21 g fresh yeast) into 250 ml warm milk (~38 °C) with 1 tsp sugar; let stand 10 minutes until a creamy foam appears on top — if it doesn't foam, the yeast is dead, start over. THE DOUGH: in a stand mixer with dough hook (or by hand), combine 500 g flour with the remaining 47 g sugar, 5 g salt, and lemon zest; pour in the foamed yeast-milk, 2 egg yolks + 1 whole egg, 100 g melted-and-cooled butter, and 1 tbsp rum; knead on medium speed 10 minutes (or 15 by hand) until the dough is smooth, elastic, and pulls cleanly from the bowl — it should be soft but not sticky; cover with film and proof in a warm place 1.5–2 hours until doubled. THE WALNUT FILLING: place 400 g freshly ground walnuts in a large bowl; pour over 200 ml hot milk, 100 g melted butter, 150 g honey, and 100 g sugar; stir well to scald the walnuts and dissolve the sugars; cool 10 minutes, then mix in 2 egg yolks, 1 tbsp rum, 1 tsp cinnamon, 0.5 tsp cloves, 1 tbsp breadcrumbs, and a pinch of salt; in a separate bowl, whip 2 egg whites to stiff peaks, then fold them gently into the walnut mixture in 3 additions — the filling should be airy and spreadable. ROLL THE DOUGH: lightly flour a clean tea towel and turn the proofed dough out onto it; punch down gently, then roll out into a thin rectangle 60 × 40 cm and 4–5 mm thick — work from the centre outward, lifting and rotating to prevent sticking; the dough must be thin enough that the spiral is visible after baking, but thick enough to hold the filling. SPREAD THE FILLING: spread the walnut filling evenly over the rolled dough, leaving a 2 cm border along the long edges; pat it gently with a spatula — do not overload, the filling should be 5–6 mm thick; sprinkle a few extra ground walnuts if any spot oozes thin. ROLL UP: using the tea towel to help, roll up the dough tightly from the long side, forming a long log; roll snug but not so tight you compress the filling; pinch the seam closed and tuck in the ends; the log should be about 60 cm long. SHAPE IN MOLD + SECOND PROOF: grease a tubular potica mold (or a 24 cm Bundt pan or a kugelhopf form) thoroughly with butter and dust with flour; lay the log in the mold, seam side down, joining the ends to form a closed ring (pinch them together); cover loosely and proof again in a warm place 45–60 minutes until the dough has risen visibly to almost fill the mold; meanwhile, preheat the oven to 175 °C. BAKE: brush the top with the egg wash; bake on the middle rack of the 175 °C oven 45–55 minutes — cover loosely with foil after 30 min if the top is browning too fast; the potica is done when a skewer comes out clean and the internal temperature reaches 92–95 °C; let it rest 15 minutes in the mold, then carefully invert onto a wire rack to cool completely; dust generously with icing sugar before slicing; serve at room temperature with strong coffee or tea."}},{"id":154,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"ja":"ナイジェリア","en":"Nigeria","ro":"Nigeria"},"name":{"ja":"エグシスープ","en":"Egusi soup","ro":"Egusi soup"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["生のエグシ種子250g、細かく挽いたもの（または事前に挽いたエグシ200g）","骨付き山羊肉または牛肩肉600g、4cmの一口大に切る","燻製魚（鯖またはなまず）200g — 清掃、骨を取り、塊に分ける（任意、伝統的）","乾燥エビまたはストックフィッシュ100g、30分浸して小さく裂く（任意）","中サイズの玉ねぎ1個（約150g）、ざく切り","スコッチボネット唐辛子2本（またはハバネロ3本）— 辛さの許容範囲に合わせる","赤パプリカ2個（約300g）、種を取る","赤いパーム油100ml","大きな新鮮なトマト3個（約400g）または200gのトマトペーストを200mlの水で混ぜたもの","にんにく4片、みじん切り","新鮮なしょうが5cm、皮をむきおろす","コンソメキューブ2個（マギーや類似、10g）","クレイフィッシュパウダー大さじ1（本物の風味に必須）— 代用：乾燥エビパウダー大さじ1","ローリエ1枚（または粉末小さじ1）","新鮮なほうれん草またはウグカボチャの葉200g、洗ってざく切り","塩小さじ1.5 + 味付け塩","ロカストビーンズ大さじ1（iru/dawadawa）— 任意、伝統的ヨルバの追加","盛り付けに：突き砕いた山芋、フフ、エバ（ガリ）、または茹でた白米"],"en":["250 g raw egusi seeds, finely ground (or 200 g pre-ground egusi)","600 g goat meat or beef chuck on the bone, cut into 4 cm pieces","200 g smoked fish (mackerel or catfish) — cleaned, boned, broken into chunks (optional, traditional)","100 g dried prawns or stockfish (panla), soaked 30 min and torn small (optional)","1 medium onion (~150 g), roughly chopped","2 Scotch bonnet peppers (or 3 habaneros) — adjust to heat tolerance","2 red bell peppers (~300 g), seeded","100 ml red palm oil","3 large fresh tomatoes (~400 g) OR 200 g tomato paste blended with 200 ml water","4 garlic cloves, finely minced","5 cm fresh ginger, peeled and grated","2 stock cubes (Maggi or similar, 10 g)","1 tbsp ground crayfish (essential for authentic flavour) — substitute: 1 tbsp ground dried shrimp","1 bay leaf (or 1 tsp ground bay)","200 g fresh spinach or ugu pumpkin leaves, washed and roughly chopped","1.5 tsp salt + more to taste","1 tbsp locust beans (iru/dawadawa) — optional, traditional Yoruba addition","To serve: pounded yam, fufu, eba (gari), or boiled white rice"],"ro":["250 g semințe egusi brute, măcinate fin (sau 200 g egusi pre-măcinat)","600 g carne de capră sau gulaș de vită cu os, tăiată în bucăți de 4 cm","200 g pește afumat (macrou sau somn) — curățat, dezosat, rupt în bucăți (opțional, tradițional)","100 g creveți uscați sau stockfish, înmuiat 30 minute și rupt mic (opțional)","1 ceapă medie (~150 g), tocată grosier","2 ardei iuți Scotch bonnet (sau 3 habanero) — ajustează după toleranța la iuțeală","2 ardei roșii grași (~300 g), fără semințe","100 ml ulei roșu de palmier","3 roșii mari proaspete (~400 g) sau 200 g pastă de roșii amestecată cu 200 ml apă","4 căței de usturoi, tocați fin","5 cm rădăcină de ghimbir proaspăt, curățată și rasă","2 cuburi Maggi sau pentru condimentare (10 g)","1 lingură crayfish măcinat (esențial pentru aroma autentică) — substitut: 1 lingură creveți uscați măcinați","1 frunză de dafin (sau 1 linguriță dafin măcinat)","200 g spanac proaspăt sau frunze de ugu (pumpkin leaves), spălate și tocate","1,5 lingurițe sare + sare după gust","1 lingură semințe de locust (iru/dawadawa) — opțional, tradițional Yoruba","Pentru servire: igname pisată, fufu, eba (gari) sau orez fiert"]},"howIsMade":{"ja":"エグシペースト：エグシの種250gをスパイスグラインダーまたはフードプロセッサーで30秒間パルスし、細かく挽くがペースト状になるまではいかない状態にする、小さなボウルで温水200mlとフムスのような厚いペーストに混ぜる、10分間置いて完全に水和させる——シグニチャーのテクスチャの秘密：外側はざらつき、内側はクリーミー。肉を煮る：重い鍋に切った肉600g、刻んだ玉ねぎ1個、にんにくみじん切り4片、すりおろし生姜、コンソメキューブ2個、塩小さじ1、水1Lを入れる、沸騰させ、ふたをして40–50分（ヤギの場合はもっと長く）煮込み、肉が柔らかいが崩れない程度に、漉してスープ800mlを取っておく、肉を脇に置く。ペッパーベースをブレンド：ブレンダーに赤パプリカ2個、スコッチボネット2本、新鮮なトマト3個（またはペースト+水）を入れる、1–2分完全になめらかになるまでブレンドする、広いフライパンに注ぎ、中火で15分煮込む——半分に減って色が深いレンガ色になるまで、この濃縮は必須で、なければスープが水っぽくなる。パーム油でベースを炒める：スープ鍋に中火でパーム油100mlを2分温めて輝くまで（煙が出るまでではない——過熱は風味を破壊する）、濃縮したペッパー・トマトベースを加えて混ぜながら8–10分炒め、油が表面に浮き混合物が少し暗くなるまで、これを\"ベースを炒める\"と呼ぶ。エグシを加える：水和したエグシペーストを大さじで取り、煮立っているペッパーベースに餃子のように落とす——かき混ぜない、餃子を5分そのまま煮込み、その後優しく折りたたむ、一部は形を保ち（塊）、他は崩れてソースを濃くする——これが望ましいテクスチャ。ストック+肉+魚：取っておいたスープ800mlを注ぐ、煮た肉、燻製魚200g（塊に分けたもの）、浸した乾燥エビ/ストックフィッシュ100g（任意）、クレイフィッシュパウダー大さじ1、ロカストビーンズ大さじ1（任意）、ローリエ1枚を加える、優しく混ぜ、煮立たせ、ふたをせずに15–20分煮込み、スープがプリン状の濃度に減るまで——スプーンに山盛りになるはずで、ブロスのように流れない。葉物野菜を加える：刻んだほうれん草200g（またはウグ/カボチャの葉）を煮立っているスープに加える、ふたをせずに5–7分煮込み、葉物がしなびて鮮やかな緑のままになるまで、味を見て塩と辛さを調整する、スープは深い旨み、わずかにナッツの風味（エグシから）、清潔なパーム油の余韻、そして高まる辛さを持つはず。休ませて盛り付け：火を止めてスープを5分休ませる——風味が劇的に融合する、深皿に盛り付け、選んだ\"呑み込み\"（突き砕いた山芋、フフ、エバ、またはアマラ）を脇に添える、右手で食べる：小さな塊を取り、スープに浸し、噛まずに飲み込む、茹でた白米はより穏やかな選択肢。","en":"EGUSI PASTE: pulse 250 g egusi seeds in a spice grinder or food processor 30 seconds until finely ground but not yet pasty; in a small bowl, mix with 200 ml warm water into a thick, hummus-like paste; let it sit 10 minutes to hydrate fully — this is the secret to the signature lumpy-creamy texture. COOK THE MEAT: in a heavy pot, combine 600 g cut meat with 1 chopped onion, 4 minced garlic, grated ginger, 2 stock cubes, 1 tsp salt and 1 L water; bring to boil, then simmer covered 40–50 minutes (longer if using goat) until the meat is tender enough to bite easily but not falling apart; strain and reserve 800 ml of the broth; set the meat aside. BLEND THE PEPPER BASE: in a blender, combine 2 red bell peppers, 2 Scotch bonnet peppers, and 3 fresh tomatoes (or paste-and-water mix); blend 1–2 minutes until completely smooth; pour into a wide pan and simmer over medium heat 15 minutes — the mix should reduce by half and the colour deepen to a rich brick-red; this concentration is essential or the soup will be watery. FRY THE PALM-OIL BASE: in your soup pot over medium heat, warm 100 ml palm oil 2 minutes until it just shimmers (do NOT smoke it — over-smoking destroys the flavour); add the reduced pepper-tomato base and fry, stirring, 8–10 minutes until the oil floats to the surface and the mixture darkens slightly; this is called \"frying the base\". ADD THE EGUSI: take the hydrated egusi paste by tablespoons and drop dumpling-style into the simmering pepper base — do NOT stir; let the dumplings cook undisturbed 5 minutes, then gently fold them in; some will hold their shape (the lumps) while others break apart and thicken the sauce — this is the desired texture. ADD STOCK + MEAT + FISH: pour in 800 ml reserved meat broth; add the cooked meat, 200 g smoked fish (broken into chunks), 100 g soaked dried prawns/stockfish (optional), 1 tbsp ground crayfish, 1 tbsp locust beans (optional), and 1 bay leaf; stir gently, bring to a simmer and cook uncovered 15–20 minutes until the soup has reduced and thickened to a pudding-like consistency — it should mound on a spoon, not pour like broth. ADD GREENS: stir in 200 g chopped spinach (or ugu/pumpkin leaves) into the simmering soup; cook 5–7 minutes uncovered until the greens are wilted but still bright green; taste and adjust salt and heat; the soup should taste deeply savoury, slightly nutty (from the egusi), with a clean palm-oil finish and a building chili heat. REST AND SERVE: turn off the heat and let the soup rest 5 minutes — the flavours meld dramatically in this short rest; serve in deep bowls with the swallow of choice (pounded yam, fufu, eba, or amala) on the side; eat with the right hand: take a small lump of swallow, dip into the soup, and swallow without chewing; boiled white rice is a milder option."}},{"id":155,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ポーランド","en":"Poland","ro":"Polonia"},"name":{"ja":"コトレット・スハボヴィ","en":"Kotlet schabowy","ro":"Kotlet schabowy"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["豚ロース骨なし肉4枚（1枚あたり約180–200g、約1.5–2cm厚）— 合計約800g","豚肉用の細塩小さじ1","挽きたての白コショウ小さじ0.5","やわらかくするための漬け込み用全乳200ml（ポーランドの技）","衣用の薄力粉80g","牛乳大さじ1と塩ひとつまみで溶いた大きな卵3個","細かい新鮮なパン粉200g（前日のパンから手作りしたものがベスト）またはパンコ","揚げ用ラード80g（伝統的）または中性ひまわり油100ml","仕上げのバスター用無塩バター30g","くし切りのレモン1個（モダンな飾り）","ディルポテト用: 皮をむいたメイラード質ジャガイモ800g + バター30g + みじん切りディル小束1個 + 茹で水用塩","ザワークラウト炒め: 水切りザワークラウト400g + みじん切り小玉ねぎ1個 + ラード大さじ1 + 水100ml"],"en":["4 boneless pork loin chops (~180–200 g each, ~1.5–2 cm thick) — about 800 g total","1 tsp fine salt for the pork","0.5 tsp freshly ground white pepper","200 ml whole milk for the tenderizing soak (the Polish trick)","80 g all-purpose flour for breading","3 large eggs beaten with 1 tbsp milk and a pinch of salt","200 g fine fresh breadcrumbs (homemade from day-old bread is best) or panko","80 g lard (traditional) OR 100 ml neutral sunflower oil for frying","30 g unsalted butter for the finishing baste","1 lemon, cut into wedges (modern garnish)","For dill potatoes: 800 g floury potatoes peeled + 30 g butter + 1 small bunch chopped dill + salt for the cooking water","For sautéed sauerkraut: 400 g drained sauerkraut + 1 small onion finely chopped + 1 tbsp lard + 100 ml water"],"ro":["4 cotlete de porc din mușchi (~180–200 g fiecare, ~1,5–2 cm grosime) — aproximativ 800 g total","1 linguriță sare fină pentru carne","0,5 linguriță piper alb proaspăt măcinat","200 ml lapte integral pentru marinada de tendierare","80 g făină pentru panare","3 ouă mari bătute cu 1 lingură lapte și un vârf de sare","200 g pesmet fin proaspăt (de casă, din pâine de o zi) sau panko","80 g untură (tradițional) SAU 100 ml ulei neutru de floarea-soarelui pentru prăjit","30 g unt nesărat pentru finisare","1 lămâie tăiată în sferturi (garnitură modernă)","Pentru cartofi cu mărar: 800 g cartofi făinoși decojiți + 30 g unt + 1 bunch mic de mărar tocat + sare pentru apa de fierbere","Pentru varza murată: 400 g varză murată scursă + 1 ceapă mică tocată + 1 lingură untură + 100 ml apă"]},"howIsMade":{"ja":"豚肉を叩く：それぞれの豚肉をラップ2枚で挟み、平らな肉叩きで中心から外側に向かって叩く、片面30秒、肉が6–7mm厚で大きさがほぼ2倍になるまで——均一に火が通るように厚さを均一に、脂肪の縁に3–4箇所切り込みを入れて反り返りを防ぐ。牛乳漬け：叩いた豚肉の水気を拭き取り、各面に塩と白コショウを擦り込む、浅い皿に入れ、豚肉がほぼ浸かるように牛乳200mlを注ぎ、覆って30分（最大2時間）冷蔵庫で寝かせる——乳酸が風味を変えずに肉を柔らかくする。衣つけステーションを準備：浅い皿3枚を並べる：皿1に小麦粉80g；皿2に溶き卵3個+牛乳大さじ1+塩ひとつまみ；皿3に細かいパン粉200g、順序が重要：すべての豚肉が小麦粉→卵→パン粉の順で進む必要がある、ステップを飛ばさない。豚肉に衣をつける：牛乳から豚肉を取り出し、余分を切って小麦粉につけ、余分を払う——小麦粉が薄く均一に付かないと卵が付かない、それから卵に浸し、2秒滴らせ、パン粉に両面しっかりと押し付け、軽くたたいて付着させる、皿に置く、4枚すべて繰り返す、5分休ませる——衣が水和して結合する。ジャガイモを茹でる：その間に、ジャガイモ800gの皮をむいて4cmの塊に切る、冷たい塩水に入れ、沸騰させて15–18分茹でフォークで通るまで、湯切りし、火を止めた鍋に2分戻して乾かし、それからバター30gと刻んだディルと和える。ザワークラウトを炒める：別のフライパンで中火でラード大さじ1を溶かす、みじん切りにした小玉ねぎ1個を加え、5分炒めて金茶色に、水切りザワークラウト400gと水100mlを加える；ふたをして15分煮込み、ふたを取って5分さらに煮込み、ほとんどの水分が蒸発するまで、コショウのひねりで味付け。シュニッツェルを揚げる：大きな重いフライパンに中強火でラード80g（または油100ml）を熱し、輝くまで（175 °C、またはパン粉が接触すると即座にチリチリ音がする）、豚肉を一度に2枚揚げて鍋が混雑しないようにし、片面3–4分動かさず、深い金茶色でカリッとするまで；内部温度は70 °Cに達する、最後の30秒で、フライパンにバター15gを加え傾けてシュニッツェルにかける——バターが茶色く泡立ち、衣にポーランドの日曜日の象徴的な香りを与える、網にキッチンペーパーを敷いた上に移して水切り（皿の上ではなく——皿だと底が湿ってしまう）。すぐに提供：各シュニッツェルをディルポテトとザワークラウトの山と一緒に盛り付ける、お好みでレモンのくし切りを添える（絞り汁が脂をすっきりさせる）、ナイフとフォークで食べる——フォーク単独では絶対に食べない、これはクラシックを尊重する料理、シュニッツェルは最大のカリッと感を得るために揚げてから5分以内に食べるべき。","en":"POUND THE PORK: place each pork chop between two sheets of cling film and pound with a flat meat mallet from the centre outward, 30 seconds per side, until the chops are 6–7 mm thick and almost doubled in size — they must be even thickness for uniform cooking; score the fatty rim 3–4 times to prevent curling. MILK SOAK: pat the pounded chops dry and rub each side with salt and white pepper; place in a shallow dish, pour over 200 ml milk so the chops are mostly submerged, cover and refrigerate 30 minutes (up to 2 hours) — the lactic acid tenderizes the meat without altering the flavour. SET UP THE BREADING STATION: three shallow plates in a row: plate 1 with 80 g flour; plate 2 with 3 beaten eggs + 1 tbsp milk + a pinch of salt; plate 3 with 200 g fine breadcrumbs; the line-up matters: every chop must travel flour → egg → breadcrumbs without skipping. BREAD THE CHOPS: lift one chop from the milk, let the excess drip off, and dredge in flour, shaking off the excess — the flour must coat thinly and evenly or the egg won't stick; then dip into the egg, letting it drip 2 seconds, then press firmly into the breadcrumbs on both sides, patting them on so they adhere; set on a plate; repeat for all 4 chops; let them rest 5 minutes — the breading hydrates and binds. BOIL THE POTATOES: meanwhile, peel 800 g potatoes and cut into 4 cm chunks; place in cold salted water, bring to boil, and simmer 15–18 minutes until fork-tender; drain, return to the pot off heat for 2 minutes to dry, then toss with 30 g butter and chopped dill. SAUTÉ THE SAUERKRAUT: in a separate pan, melt 1 tbsp lard over medium heat; add 1 finely chopped onion, fry 5 minutes until golden; add 400 g drained sauerkraut and 100 ml water; simmer covered 15 minutes, then uncover and cook 5 minutes more until most of the liquid has evaporated and the kraut is tender; season with a twist of pepper. FRY THE SCHNITZELS: heat 80 g lard (or 100 ml oil) in a large heavy skillet over medium-high heat until shimmering (175 °C, or a breadcrumb sizzles immediately on contact); fry the chops 2 at a time so the pan isn't crowded, 3–4 minutes per side undisturbed until deeply golden brown and crisp; the internal temperature should reach 70 °C; in the last 30 seconds, add 15 g butter to the pan and tilt to baste the schnitzels — the butter foams brown and gives the breading its iconic Polish-Sunday aroma; transfer to a rack lined with paper towels to drain (NOT a plate, which would steam the bottom soggy). SERVE IMMEDIATELY: plate each schnitzel alongside a mound of dill potatoes and a heap of sauerkraut; garnish with a lemon wedge if you like (the squeeze brightens the fat); eat with a knife and fork — never just a fork, this is a respect-the-classics dish; the schnitzel should be eaten within 5 minutes of frying for maximum crunch."}},{"id":156,"origin":{"ja":"韓国","en":"South Korea","ro":"Coreea de Sud"},"name":{"ja":"キンパ","en":"Kimbap","ro":"Kimbap"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"ja":["短粒米360g（2カップ）、生 — 約4本分","ご飯の水分用冷水540ml（2¼カップ）","焼き海苔4枚（gim、20 × 18cm）","たくあん（danmuji）4本、海苔の長さに切り、厚さ~1cm","ベビースピナッチ100g（または小束のほうれん草）","中サイズの人参2本（~150g）、0.5 × 0.5 × 8cmのせん切り","大きな卵3個","カニカマ200g（または茹でハム、またはマヨネーズで和えたツナ缶）","きゅうり100g（韓国きゅうり1本または英国きゅうり1/3）、種を取り長い棒状に","焙煎ごま油大さじ3（米用に大さじ1.5、ほうれん草用に小さじ0.5、残りは外側用）","細塩小さじ1.5（米用に小さじ1、野菜と卵用にひとつまみずつ）","炒りごま小さじ2","卵と人参を炒める用の中性油大さじ1","白コショウ粉小さじ0.5","巻きす（gimbal）+ ラップ"],"en":["360 g (2 cups) short-grain white rice, uncooked — makes ~4 rolls","540 ml (2¼ cups) cold water for cooking the rice","4 sheets toasted nori (gim, 20 × 18 cm)","4 strips danmuji (yellow pickled radish), cut to nori length, ~1 cm thick","100 g baby spinach (or 1 small bunch regular spinach)","2 medium carrots (~150 g), julienned 0.5 × 0.5 × 8 cm matchsticks","3 large eggs","200 g imitation crab sticks (or cooked ham, or tuna mixed with mayo)","100 g cucumber (1 small Korean cucumber or 1/3 English cucumber), seeded and cut into long batons","3 tbsp toasted sesame oil (1.5 tbsp for the rice, 0.5 tsp for spinach, the rest for the outer rub)","1.5 tsp fine salt (1 tsp for the rice, pinches for veg and eggs)","2 tsp toasted sesame seeds","1 tbsp neutral oil for cooking the eggs and carrots","0.5 tsp ground white pepper","Bamboo rolling mat (gimbal) + plastic wrap"],"ro":["360 g (2 căni) orez cu bob scurt necopt, pentru ~4 rulouri","540 ml (2¼ căni) apă rece pentru fierberea orezului","4 foi de nori prăjit (gim, 20 × 18 cm)","4 fâșii de danmuji (ridiche galbenă murată), tăiate la lungimea norii, grosime ~1 cm","100 g spanac baby (sau 1 mănunchi mic de spanac obișnuit)","2 morcovi medii (~150 g), tăiați julien 0,5 × 0,5 × 8 cm","3 ouă mari, bătute","200 g bețe de crab imitație (sau șuncă fiartă sau ton conservat amestecat cu maioneză)","100 g castraveți (1 mic castravete coreean sau 1/3 castravete englezesc), fără sâmburi, tăiat fâșii lungi","3 linguri ulei de susan prăjit (1,5 lingură pentru orez, 0,5 linguriță pentru spanac, restul pentru exterior)","1,5 linguriță sare fină (1 linguriță pentru orez, restul pentru legume)","2 lingurițe semințe de susan prăjite","1 lingură ulei neutru pentru gătit ouăle și sotat morcovii","0,5 linguriță piper alb măcinat","Covoraș de bambus (kimbal) + folie alimentară"]},"howIsMade":{"ja":"ご飯：360gの米を冷水で3–4回水が澄むまで洗う、よく水切りし、厚手の鍋に新しい冷水540mlを入れる、中強火で蓋なし沸騰させ（3–4分）、蓋をして最弱火に落とし12分炊く——蓋を開けない、火から下ろし、蓋をしたまま10分蒸らす、ご飯はしっとりして、少し粘り、粒が立っているはず。ご飯の味付け：熱いうちに広いボウルに移す、ごま油大さじ1.5、塩小さじ1、炒りごま小さじ2を全体に振りかける、しゃもじで切るような動作で優しく折り混ぜる——激しく混ぜないこと、粒が崩れてベタつく、湿らせた布で覆い、人肌くらいまで冷ます（10–15分）。ほうれん草：小さな鍋に塩水を沸騰させる、100gのほうれん草を30秒だけ茹で、ちょうどしんなりするまで、水切りし、すぐに冷水で洗って加熱を止め、鮮やかな緑色を保つ、手で力いっぱい絞って全ての水分を抜く——濡れたほうれん草は巻きを台無しにする、ごま油小さじ0.5と塩ひとつまみで味付け。人参：小さなフライパンに中性油小さじ1を中火で熱す、150gのせん切り人参と塩ひとつまみを入れ、2分炒めてちょうど柔らかくなるがまだシャキッとするまで、皿に移して冷ます——ぐったりした油っぽい人参は巻きを破壊する。卵：3個の卵を塩ひとつまみと白コショウ小さじ0.5で溶く、ノンスティックフライパンに中性油小さじ1を中弱火で熱し、卵を流し入れて鍋を傾けて25 × 20cmの薄い均一なシートを作る、2分焼いて上が固まるまで、ひっくり返さない、まな板に滑らせて2分冷まし、海苔の幅に4本の長い帯に切る。具材の準備：100gのきゅうりを縦に8本の長い棒状に切り、ティースプーンで種の芯を取り除く、200gのカニカマを縦に2つに割る、たくあん4本を海苔の長さに切る、並べる順番にトレイに整理：ほうれん草 → 人参 → きゅうり → カニカマ → 卵 → たくあん。各キンパを巻く：竹簾の竹を水平に置き、海苔をつや面を下にして広げる、濡れた指で~150gのご飯を海苔の下から3/4に薄く均一に広げ、遠い端に4cmの空白を残す、手前から3cmのところに、ほうれん草、人参、きゅうり、カニカマ、卵、たくあんを密集して並べる、竹簾の手前端を持ち上げてしっかり前方に巻き、最初の回転で具材をご飯の下に押し込み、その後遠い端までしっかり巻いていく、継ぎ目に沿って押さえて封をする。切って盛り付け：各巻きの外側にごま油小さじ0.5を軽く塗り、海苔につやを出し、包丁にくっつかないようにする、切るごとに鋭い包丁を湿らせた布で拭く、各巻きを8つの均等な輪切りに、一回の決断的な押し切りで切る（のこぎり挽きしない）——合計32個、皿に並べ、ごまを振りかける、巻いてから4時間以内に食べる；キンパは絶対に冷蔵庫に入れない（米が固くなり、海苔が水分でしっとりする）。","en":"Rinse 360 g rice in cold water 3–4 times until the water runs clear, drain well, then put in a heavy pot with 540 ml fresh cold water, bring to a boil uncovered over medium-high heat (3–4 min), cover, reduce to the lowest possible heat and cook 12 minutes without lifting the lid, then remove from heat and rest covered 10 minutes until the rice is tender, slightly sticky, with separate grains. While the rice is still hot, transfer it to a wide bowl, drizzle 1.5 tbsp sesame oil, 1 tsp salt and 2 tsp toasted sesame seeds over the top and fold gently with a rice paddle in cutting motions — never stir aggressively or the grains break and turn mushy — then cover with a damp cloth and let cool to lukewarm (10–15 min). Bring a small pot of salted water to a boil and blanch 100 g spinach for 30 seconds until just wilted, then drain and rinse under cold water immediately to stop the cooking and preserve the bright green colour, squeeze in your fist as hard as possible to remove all water (wet spinach ruins the roll) and season with 0.5 tsp sesame oil and a pinch of salt. Heat 1 tsp neutral oil in a small pan over medium heat, add 150 g julienned carrot and a pinch of salt and stir-fry 2 minutes until just softened but still crisp, then tip onto a plate to cool — limp, oily carrots will break the roll. Beat 3 eggs with a pinch of salt and 0.5 tsp white pepper, heat 1 tsp neutral oil in a non-stick pan over medium-low heat, pour in the eggs and tilt the pan to form a thin even sheet 25 × 20 cm, cook 2 minutes until set on top without flipping, then slide onto a board, let cool 2 minutes and cut into 4 long strips the width of the nori. Cut 100 g cucumber lengthwise into 8 long batons and scrape the seedy core out with a teaspoon, split 200 g crab sticks in half lengthwise and cut 4 strips of danmuji to nori length, then arrange everything on a tray in the order you'll lay them: spinach, carrot, cucumber, crab, egg, danmuji. Place the bamboo mat with the slats running horizontally and lay a sheet of nori shiny-side down, then with wet fingers spread ~150 g rice in a thin even layer over the bottom 3/4 of the nori while leaving a clean 4 cm strip at the far edge, and about 3 cm in from the near edge line up one strip each of spinach, carrot, cucumber, crab, egg and danmuji in a tight bundle, then lift the near edge of the mat and roll firmly forward, tucking the fillings under the rice with the first roll and continuing to roll tightly to the far edge, then press along the seam to seal. Brush the outside of each roll lightly with 0.5 tsp sesame oil to make the nori glossy and prevent it from sticking to the knife, wipe a sharp knife with a damp cloth between cuts, then slice each roll into 8 even rounds with one decisive push (no sawing) for 32 pieces total, arrange on a plate and sprinkle with sesame seeds — eat within 4 hours of rolling and never refrigerate kimbap."},"timeMins":{"total":60,"active":50}},{"id":157,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"ja":"チリ","en":"Chile","ro":"Chile"},"name":{"ja":"パステル・デ・チョクロ","en":"Pastel de Choclo","ro":"Pastel de Choclo"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["ピノ（肉あん）用：牛ひき肉600g（肩肉またはサーロイン、脂肪20%）","大玉ねぎ2個（~400g）、みじん切り","にんにく4片、みじん切り","炒め用中性油大さじ2","ピノ用塩小さじ1.5 + 挽きたて黒コショウ小さじ1","クミンパウダー小さじ1 + 甘いパプリカ小さじ1 + 乾燥オレガノ小さじ1 + アヒ・コロル小さじ1（または燻製ピメントンで代用）","牛肉ストックまたは水60ml","黒レーズン80g、温水100mlに15分浸して水切り","骨付き皮付き鶏もも肉4本（~600g）— 茹でて手で裂いた（伝統的追加）","ローリエ1枚 + 鶏肉を茹でる水800ml","固ゆで卵6個、皮をむいて半分に（1ポーションあたり1個）","種抜き黒オリーブ18–24個（カラマタタイプ）","コーンペースト（チョクロ）用：新鮮な白いトウモロコシの粒1.2kg（~6–8本分）または解凍した冷凍コーン1kg","全乳80ml","無塩バター60g","新鮮なバジルの葉大さじ1、みじん切り（チリの特徴）","コーンペースト用：細塩小さじ1 + グラニュー糖大さじ1","焼く前に上にふりかける用グラニュー糖大さじ2（象徴的なキャラメル化したクラスト）"],"en":["For the pino (meat filling): 600 g ground beef (chuck or sirloin, 20% fat)","2 large onions (~400 g), finely diced","4 garlic cloves, finely minced","2 tbsp neutral oil for sautéing","1.5 tsp salt + 1 tsp freshly ground black pepper for the pino","1 tsp ground cumin + 1 tsp sweet paprika + 1 tsp dried oregano + 1 tsp aji color (or pimentón as substitute)","60 ml beef stock or water","80 g dark raisins, soaked 15 min in 100 ml warm water, then drained","4 bone-in skin-on chicken thighs (~600 g) — poached and pulled (traditional addition)","1 bay leaf + 800 ml water to poach the chicken","6 hard-boiled eggs, peeled and halved (1 per portion)","18–24 pitted black olives (kalamata-style)","For the corn paste (choclo): 1.2 kg fresh white corn kernels (~6–8 ears) OR 1 kg thawed frozen corn","80 ml whole milk","60 g unsalted butter","1 tbsp fresh basil leaves, finely chopped (the Chilean signature)","1 tsp fine salt + 1 tbsp granulated sugar for the corn paste","2 tbsp granulated sugar to sprinkle over the top before baking (for the iconic caramelized crust)"],"ro":["Pentru pino: 600 g vită tocată (gulaș sau pulpă, 20% grăsime)","2 cepe mari (~400 g), tăiate fin","4 căței de usturoi, tocați fin","2 linguri ulei neutru pentru sotat","1,5 lingurițe sare + 1 linguriță piper negru proaspăt măcinat (pentru pino)","1 linguriță chimion măcinat + 1 linguriță boia dulce + 1 linguriță oregano uscat + 1 linguriță aji color (sau pimentón pentru substitut)","60 ml supă de vită sau apă","80 g stafide negre, înmuiate 15 minute în 100 ml apă caldă, apoi scurse","4 pulpe de pui cu os și piele (~600 g) — fierte și destrămate (tradițional)","1 frunză de dafin + 800 ml apă pentru fiertul puiului","6 ouă tari, decojite și tăiate în jumătăți (1 per porție)","18–24 măsline negre cu sâmbure scos (stil kalamata)","Pentru pasta de porumb: 1,2 kg boabe proaspete de porumb alb (~6–8 știuleți) SAU 1 kg porumb congelat dezghețat","80 ml lapte integral","60 g unt nesărat","1 lingură busuioc proaspăt, tocat fin (semnătura chiliană)","1 linguriță sare fină + 1 lingură zahăr granulat pentru pasta de porumb","2 linguri zahăr granulat pentru presărat pe suprafață înainte de coacere (crusta caramelizată iconică)"]},"howIsMade":{"ja":"玉ねぎをカラメル化：重いフライパンに中火で油大さじ2を熱し、みじん切り玉ねぎ400gと塩小さじ0.5を加える、12–15分、頻繁に混ぜながら、深い金色で透明になるまで炒める——この工程は急がない、カラメル化した玉ねぎがピノの風味の基盤、みじん切りにんにく4片を加え、香りが立つまでさらに1分炒める。牛肉を焼く：火を中強火に上げる、玉ねぎに600gの牛ひき肉を加え、木べらでほぐす、6–8分、肉のピンク色がなくなり水分が蒸発するまで炒める、クミン小さじ1、パプリカ小さじ1、オレガノ小さじ1、アヒ・コロル小さじ1（使用する場合）、残りの塩小さじ1とコショウ小さじ1を加える、スパイスの香りが立つまで1分混ぜる。ピノを仕上げる：60mlのストックと水切りしたレーズンを加える、3–4分煮込み、混合物が湿っているがスープ状でないまで——ピノは艶があり、スプーンで形を保てるはず、火から下ろし、15分冷ます——休ませることで風味が深まり、コーンのトッピングが滑り落ちるのを防ぐ。鶏肉を茹でる：ピノを休ませている間に、軽く塩味の800mlの水とローリエ1枚で鶏もも肉4本を25分茹でて火が通るまで、水切りし、少し冷ましてから、肉を骨から大きなチャンクで引きはがす（皮は捨てる）、スープはパステルと一緒に出す用に取っておく。コーンペースト：フードプロセッサーまたはブレンダーで、1.2kgのコーン粒、牛乳80ml、塩小さじ1を30秒パルスして粗いピューレに——テクスチャを残し、滑らかなクリームにブレンドしない、バター60gと一緒に重い鍋に中火で移す、10–15分、木べらで常に混ぜながら、ピューレが鍋の側面から離れるポレンタのような濃度になるまで煮込む、刻んだバジル大さじ1を混ぜ込み、火から下ろす。組み立て：オーブンを200 °Cに上段で予熱、ピノを6つの個人用陶器パイラ（または28cmの焼き皿）に分ける、各ポーションに茹で鶏のチャンク、固ゆで卵1個分の半分、オリーブ3–4個、レーズンの小さな山を装飾的に配置する、温かいコーンペーストを上に均一な2cmの層で乗せ、スプーンの背で滑らかにして縁まで封をする。砂糖クラスト：コーントッピングの上にグラニュー糖大さじ2を均一に振りかける、このステップは交渉不可——焼く間に砂糖がカラメル化し、パステル・デ・チョクロを他のシェパーズパイから区別する、象徴的な暗くてほぼ焦げた金色のクラストになる。焼く：200 °Cのオーブンの上段ラックにパステルを置き、25–30分焼く、コーントッピングが金茶色になり、砂糖が表面の暗い斑点にカラメル化するまで、角は泡立つかもしれない——それは正しい、提供前に10分休ませる（フィリングが固まる必要がある）、パイラから直接、ペブレサルサとチリのカルメネールワイン一杯と一緒に提供する。","en":"CARAMELIZE THE ONIONS: in a heavy skillet over medium heat, warm 2 tbsp oil and add 400 g finely diced onion with 0.5 tsp salt; sauté 12–15 minutes, stirring often, until deeply golden and translucent — DO NOT rush this step, the caramelized onion is the foundation of pino flavour; add 4 minced garlic cloves and cook 1 minute more until fragrant. BROWN THE BEEF: raise the heat to medium-high; add 600 g ground beef to the onions, breaking it apart with a wooden spoon; cook 6–8 minutes until the meat is no longer pink and any liquid has evaporated; add 1 tsp cumin, 1 tsp paprika, 1 tsp oregano, 1 tsp aji color (if using), the remaining 1 tsp salt and 1 tsp pepper; stir 1 minute to bloom the spices. FINISH THE PINO: pour in 60 ml beef stock and the drained raisins; simmer 3–4 minutes until the mixture is moist but not soupy — the pino should be glossy and able to hold its shape on a spoon; remove from heat and let cool 15 minutes — letting it rest deepens the flavour and prevents the corn topping from sliding off. POACH THE CHICKEN: while the pino rests, simmer 4 chicken thighs in 800 ml lightly salted water with 1 bay leaf for 25 minutes until cooked through; drain, cool slightly, then pull the meat from the bones in large chunks (skin discarded); reserve the stock for serving alongside the pastel. CORN PASTE: in a food processor or blender, pulse 1.2 kg fresh corn kernels with 80 ml milk and 1 tsp salt 30 seconds until coarsely pureed — keep some texture, do not blend to a smooth cream; transfer to a heavy saucepan with 60 g butter over medium heat; cook 10–15 minutes, stirring constantly with a wooden spoon, until the puree thickens to a polenta-like consistency that pulls away from the sides of the pan; stir in 1 tbsp chopped basil and remove from heat. ASSEMBLE: preheat oven to 200 °C with a rack in the upper third; divide the pino between 6 individual earthenware pailas (or one 28 cm baking dish); top each portion with chunks of poached chicken, 1 hard-boiled egg half, 3–4 olives, and a small pile of raisins arranged decoratively; spoon the warm corn paste over the top in an even 2 cm layer, smoothing with the back of a spoon to seal all the way to the edges. SUGAR CRUST: sprinkle 2 tbsp granulated sugar evenly over the corn topping; this is non-negotiable — the sugar caramelizes during baking into the iconic dark, almost-burnt golden crust that distinguishes pastel de choclo from any other shepherd's pie. BAKE: place the pastels on the upper rack of the 200 °C oven and bake 25–30 minutes until the corn topping is golden brown and the sugar has caramelized into dark spots across the surface; the corners may bubble — that's correct; let rest 10 minutes before serving (the filling needs to set); serve straight from the paila with a side of pebre salsa and a glass of Chilean Carmenère."}},{"id":158,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"セルビア","en":"Serbia","ro":"Serbia"},"name":{"ja":"プリェスカヴィツァ","en":"Pljeskavica","ro":"Pljeskavica"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["粗びき牛肩肉500g（脂肪~20%）","粗びき羊肩肉300g（または穏やかなバージョンには豚肩肉）","大玉ねぎ1個（~200g）、細かくおろし水を絞り出した（ジューシーなパテの秘密）","にんにく4片、塩小さじ0.5と一緒につぶしてペースト状に","甘いハンガリアンパプリカ大さじ1","辛いパプリカ小さじ1（燻製またはカシミール、任意）","細塩小さじ1.5","挽きたての黒コショウ小さじ1","重曹小さじ1（バルカンのコツ——パテをジューシーで柔らかく保つ）","氷のように冷たい炭酸水100ml（フワッと弾力ある食感のため）","乾燥マジョラムまたはオレガノ小さじ0.5","グリルまたは鍋用の植物油大さじ1","盛り付け用：ソムンまたはピタパン4枚（~18cm）、中サイズの赤玉ねぎ1個（~150g）薄切り、アジバル200g、カイマクまたはサワークリーム100g、新鮮なパセリ、レモンのくし切り（任意）"],"en":["500 g coarsely ground beef chuck (~20% fat)","300 g coarsely ground lamb shoulder (or pork shoulder for a milder version)","1 large onion (~200 g), finely grated and water squeezed out (the secret to juicy patties)","4 garlic cloves, crushed with 0.5 tsp salt into a paste","1 tbsp sweet Hungarian paprika","1 tsp hot paprika (smoked or Kashmiri, optional)","1.5 tsp fine salt","1 tsp freshly ground black pepper","1 tsp baking soda (the Balkan trick — helps keep them juicy and tender)","100 ml ice-cold sparkling water (for the fluffy springy texture)","0.5 tsp dried marjoram or oregano","1 tbsp vegetable oil for the grill or pan","To serve: 4 somun or pita breads (~18 cm rounds), 1 medium red onion (~150 g) thinly sliced, 200 g ajvar red-pepper relish, 100 g kajmak or sour cream, fresh parsley, lemon wedges (optional)"],"ro":["500 g vită tocată grosier (ceafă, ~20% grăsime)","300 g umăr de miel tocat grosier (sau umăr de porc pentru o versiune mai blândă)","1 ceapă mare (~200 g), rasă fin și stoarsă bine (secretul cărnurilor suculente)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă","1 lingură boia ungurească dulce","1 linguriță boia iute (afumată sau Kashmir, opțional)","1,5 lingurițe sare fină","1 linguriță piper negru proaspăt măcinat","1 linguriță bicarbonat de sodiu (trucul balcanic — păstrează carnea suculentă și frageda)","100 ml apă minerală carbogazoasă rece ca gheața (pentru textura pufoasă)","0,5 linguriță maghiran uscat sau oregano","1 lingură ulei vegetal pentru grătar sau tigaie","Pentru servire: 4 chifle somun sau pita (~18 cm), 1 ceapă roșie medie (~150 g) tăiată subțire, 200 g ajvar, 100 g kajmak sau smântână, pătrunjel proaspăt, lămâie (opțional)"]},"howIsMade":{"ja":"玉ねぎの準備：玉ねぎ200gをおろし金の細かい面でおろす、清潔な布巾に移し、シンクの上で強く絞ってできるだけ液体を取り除く——少なくとも80mlの汁が出るはず、濡れた玉ねぎはグリルでパテをバラバラにする、絞った果肉大さじ2を肉用に取っておく。肉を混ぜる：大きなボウルで牛肉500g + 羊肉300g（または豚肉）を混ぜる、絞った玉ねぎ大さじ2、塩小さじ0.5でつぶしたにんにく4片、甘いパプリカ大さじ1、辛いパプリカ小さじ1（使用する場合）、塩小さじ1、コショウ小さじ1、マジョラム小さじ0.5、重曹小さじ1を加える、手で力強く4–5分こねる——混合物は粘り気が出て明らかに引き締まり、プリェスカヴィツァに特徴的な弾力を与える。炭酸水を加える：こねながら氷のように冷たい炭酸水100mlをゆっくりと注ぐ、25mlずつ4回に分ける、水は挽肉を空気を含ませ、重曹と組み合わさってパテをジューシーで柔らかく保つ、ラップで覆って少なくとも4時間、理想的には一晩冷蔵する——休ませることは風味の発達と結合のために交渉不可。パテを成形：休ませた肉を1つあたり~225gの4等分にする、濡れた手で（くっつき防止）、各部分をボール状に丸め、直径18–20cm、厚さ8mmの平らな円盤に押しつぶす、円盤は提供されるパンと同じ直径でなければならない、親指で中央を軽く押してくぼみを作る——これによりパテがグリルで膨らむのを防ぐ。2回目の冷蔵：成形したパテをクッキングシートを敷いたトレイに置く、緩く覆って20分冷蔵して固める、その間に炭火グリルを中強火（200 °C）にするか、重い溝付きグリルパンを油大さじ1で煙が出始めるまで温める。グリル：パテに軽く油を塗る、動かさずに片面4–5分グリル——一度だけ返す、内部温度が65 °C（ミディアム）に達し、両面に深いマホガニー色のクラストが形成され、グリルマークが見えればパテは完成、押さないこと——すべての汁を失い、ステップ3の作業が無駄になる。パンを温める：グリルの最後の1分間に、ソムンまたはピタ4枚をグリルに置き、片面30秒、温まって軽く焼けるまで、各ピタを片端で切り開いて、パテに十分な大きさのポケットを作る。盛り付け：温かいピタポケットに各パテを滑り込ませる、アジバル大さじ1、カイマク一塊、たっぷりの薄切り生赤玉ねぎの山、パセリのひと振り、お好みでレモンを絞る、パンが温かいうちに手で即座に食べる——熱くてジューシーな肉、冷たいカイマク、燻製アジバルの対比はバルカンストリートフードの魂。","en":"ONION PREP: grate 200 g onion on the fine side of a box grater; transfer to a clean tea towel and squeeze HARD over the sink to remove as much liquid as possible — at least 80 ml of juice should come out; wet onion makes the patties fall apart on the grill; reserve 2 tbsp of the squeezed pulp for the meat. MIX THE MEAT: in a large bowl, combine 500 g beef + 300 g lamb (or pork); add 2 tbsp squeezed onion pulp, 4 garlic cloves crushed with 0.5 tsp salt, 1 tbsp sweet paprika, 1 tsp hot paprika (if using), 1 tsp salt, 1 tsp pepper, 0.5 tsp marjoram and 1 tsp baking soda; knead vigorously by hand 4–5 minutes — the mixture should become sticky and noticeably tightened, which gives pljeskavica its signature springy bounce. ADD SPARKLING WATER: slowly drizzle in 100 ml ice-cold sparkling water while continuing to knead, in 4 additions of 25 ml each; the water aerates the mince and combines with the baking soda to keep the patties juicy and tender; cover with film and refrigerate at least 4 hours, ideally overnight — the rest is non-negotiable for flavour development and binding. SHAPE THE PATTIES: divide the rested meat into 4 equal portions of ~225 g each; with wet hands (to prevent sticking), roll each portion into a ball, then flatten into a flat disc 18–20 cm in diameter and 8 mm thick; the disc must be the same diameter as the bread it will be served in; press the centre slightly with your thumb to create a dimple — this prevents the patty from doming up on the grill. SECOND CHILL: place the shaped patties on a parchment-lined tray; cover loosely and refrigerate 20 minutes to firm up; meanwhile, fire up a charcoal grill to medium-high (200 °C) or heat a heavy ridged griddle pan with 1 tbsp oil until just smoking. GRILL: brush the patties lightly with oil; grill 4–5 minutes per side without moving — turn ONCE only; the patties are done when the internal temperature reaches 65 °C (medium) and a deep mahogany crust has formed on both sides with visible grill marks; resist pressing them — you'll lose all the juice and undo the work you did in step 3. WARM THE BREAD: during the last minute of grilling, place 4 somun or pita on the grill for 30 seconds per side until warmed and lightly toasted; split each pita open at one edge to make a pocket large enough for the patty. SERVE: slip one patty into each warm pita pocket; top with 1 tbsp ajvar, a knob of kajmak, a generous mound of sliced raw red onion, a sprinkle of parsley, and a squeeze of lemon if you like; eat immediately with your hands while the bread is warm — the contrast of hot juicy meat, cool kajmak, and smoky ajvar is the soul of Balkan street food."}},{"id":159,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"ja":"オランダ","en":"Netherlands","ro":"Olanda"},"name":{"ja":"ポッフェルチェス","en":"Poffertjes","ro":"Poffertjes"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"ingredients":{"ja":["そば粉250g（伝統的、シグネチャー風味を与える）——または100gそば粉+150g薄力粉のミルダーな代替品","インスタントドライイースト7g（または生イースト21g）","グラニュー糖大さじ1（イースト活性化用に小さじ1、残りを生地に）","細塩小さじ0.5","温めた全乳350ml（38 °C）","Lサイズの卵2個","生地用、溶かして人肌に冷ました無塩バター30g","鍋と仕上げ用、追加の無塩バター50g","ダークラム酒またはバニラエキス大さじ1（任意、伝統的）","盛り付け用: 上に乗せる冷たい無塩バターのキューブ30g、ふりかけ用粉砂糖60g、ストロープワッフルシロップまたはメープルシロップ（任意）、新鮮なベリー（任意）","器具: 24–30個のくぼみがある鋳鉄製ポッフェルチェスパン（またはエブルスキバーパン）; 裏返し用の小さな木製串"],"en":["250 g buckwheat flour (traditional, gives the signature flavour) — OR 100 g buckwheat + 150 g all-purpose flour as a milder substitute","7 g instant dry yeast (or 21 g fresh yeast)","1 tbsp granulated sugar (1 tsp to feed the yeast, the rest in the batter)","0.5 tsp fine salt","350 ml warm whole milk (38 °C)","2 large eggs","30 g unsalted butter, melted and cooled to lukewarm for the batter","50 g additional unsalted butter for the pan + finishing","1 tbsp dark rum or vanilla extract (optional, traditional)","To serve: 30 g cold unsalted butter cubes for topping, 60 g icing sugar to dust, stroopwafel syrup or maple syrup (optional), fresh berries (optional)","Equipment: poffertjespan cast-iron pan with 24–30 dimples (or aebleskiver pan); small wooden skewer or chopstick for flipping"],"ro":["250 g făină de hrișcă (tradițional, dă aroma signature) — SAU 100 g hrișcă + 150 g făină albă ca substitut mai blând","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 lingură zahăr (1 linguriță pentru drojdie, restul în aluat)","0,5 linguriță sare fină","350 ml lapte integral cald (38 °C)","2 ouă mari","30 g unt nesărat topit și răcit la călduț pentru aluat","50 g unt nesărat suplimentar pentru tigaie și finisare","1 lingură rom întunecat sau extract de vanilie (opțional, tradițional)","Pentru servire: 30 g unt rece în cuburi pentru a pune deasupra, 60 g zahăr pudră pentru presărat, sirop stroopwafel sau de arțar (opțional), fructe de pădure proaspete (opțional)","Echipament: tigaie poffertjespan din fontă cu 24–30 adâncituri (sau tigaie aebleskiver); bețișoară de lemn pentru întors"]},"howIsMade":{"ja":"イーストを活性化：350mlの牛乳を鍋で約38 °C（手首に心地よい温度）に温める、大きなボウルに注ぎ、表面にインスタントドライイースト7gと砂糖小さじ1を振りかけ、10分間置いて表面にクリーミーな泡が現れるまで、泡が出ない場合はイーストが死んでいる——新鮮なイーストで最初からやり直す。生地を作る：泡立てたイースト入り牛乳に卵2個を加えて滑らかになるまで混ぜる、別のボウルでそば粉250g（またはそば粉+薄力粉のミックス）、残りの砂糖小さじ2、塩小さじ0.5を一緒に篩う、乾いた材料を湿った材料に2回に分けて加え、毎回滑らかになるまで混ぜる——ダマなし、溶かして冷ました30gのバターとラム酒大さじ1（使用する場合）を混ぜ込む、生地は泡立て器からリボン状に落ちる薄いクリームの濃度であるべき。一次発酵：ボウルを清潔な布で覆い、暖かい場所で60分発酵させる、表面が気泡で覆われ、生地が目に見えて膨らむまで（約1.5倍の容量）、イーストが本物のポッフェルチェスのシグネチャーであるエアリーで少し酸っぱい風味を発達させる。混ぜて休ませる：膨らんだ生地を優しく混ぜて大きな気泡を抜く、絞り瓶、ピッチャー、または絞り袋に移す——小さなくぼみに正確に分配する最も簡単な方法、鍋が温まる間に10分休ませる。ポッフェルチェスパンを加熱：24または30個のくぼみがある鋳鉄製ポッフェルチェスパンを中弱火で3分間、均一に熱くなるまで（水を一滴落としてテスト——2秒で音を立てて蒸発するはず）、折りたたんだキッチンペーパーを溶かしたバターに浸し、各くぼみを大量にグリースする——すべてのくぼみがコーティングされていないとポッフェルチェスがくっつく。くぼみを満たす：素早く作業し、各くぼみに3/4満たす（くぼみあたり大さじ約1）まで生地を絞り入れたり注ぎ入れたりする、60–90秒待ち、縁が固まって金色のリングが各々の周りに形成され、表面に気泡が現れるまで。各々を裏返す：木製串を使って、半凝固の各ポッフェルチェスをくぼみの側面に沿って引き上げ、ひっくり返す——未調理の上部の生地がくぼみに流れ込み、丸いボールを満たす、さらに60–90秒、2番目の面が深い金茶色になるまで調理する、各ポッフェルチェスはふんわりした丸いボールで、両側が金色、約3cm幅。すぐに提供：各温かい皿に8–10個のポッフェルチェスをスライドさせる、冷たいバターの小さなかけら（溶けて染み込む）と細かい篩を通したたっぷりの粉砂糖を上にトッピング、すぐに提供——ポッフェルチェスは作ってから5分以内にゴム状になる、任意：ストロープワッフルシロップをかけたり、新鮮なベリーを散らしたりする。","en":"ACTIVATE THE YEAST: warm 350 ml milk in a saucepan to about 38 °C (lukewarm — comfortable on your wrist); pour into a large bowl, sprinkle 7 g instant dry yeast and 1 tsp sugar over the surface, and let stand 10 minutes until a creamy foam appears on top; if no foam, the yeast is dead — start over with fresh yeast. MAKE THE BATTER: whisk 2 eggs into the foamed yeast-milk until smooth; in a separate bowl, sift together 250 g buckwheat flour (or the buckwheat+all-purpose mix), the remaining 2 tsp sugar and 0.5 tsp salt; add the dry to the wet in two additions, whisking each time until smooth — no lumps; whisk in 30 g melted cooled butter and 1 tbsp rum (if using); the batter should be the consistency of thin cream that ribbons off the whisk. FIRST PROOF: cover the bowl with a clean cloth and let rise in a warm spot for 60 minutes, until the surface is covered with bubbles and the batter has risen noticeably (about 1.5× volume); the yeast develops the signature airy, slightly sour flavour of true poffertjes. STIR DOWN AND REST: gently stir the risen batter to deflate large bubbles; transfer to a squeeze bottle, jug or piping bag — the easiest way to portion accurately into the small dimples; let rest 10 minutes while the pan heats. HEAT THE POFFERTJESPAN: place a 24- or 30-dimple cast-iron poffertjespan over medium-low heat for 3 minutes until evenly hot (test with a drop of water — it should sizzle and evaporate in 2 seconds); use a folded paper towel dipped in melted butter to grease each dimple generously — every dimple must be coated or the poffertjes will stick. FILL THE DIMPLES: working fast, squeeze or pour batter into each dimple until 3/4 full (about 1 tbsp per dimple); wait 60–90 seconds until the edges are set and a golden ring forms around each one, with bubbles forming on the surface. FLIP EACH ONE: using a wooden skewer, pull each half-set poffertje up the side of its dimple and flip it upside down — the uncooked top batter will flow into the dimple, filling out a round ball; cook another 60–90 seconds until the second side is deep golden brown; each poffertje should be a fluffy round ball, golden on both sides, about 3 cm wide. SERVE IMMEDIATELY: slide 8–10 poffertjes onto each warm plate; top with a small knob of cold butter (it will melt and soak in) and a generous dust of icing sugar through a fine sieve; serve immediately — poffertjes turn rubbery within 5 minutes of being made; optional: drizzle stroopwafel syrup or scatter fresh berries."}},{"id":160,"origin":{"ja":"日本","en":"Japan","ro":"Japonia"},"name":{"ja":"カレーライス","en":"Japanese Curry Rice","ro":"Curry japonez"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"ja":["短粒米2カップ（乾燥）","骨なし皮なし鶏もも肉400g（または牛肩ロース）3cm角に切る","大玉ねぎ2個、中粗みじん切り","中じゃがいも2個、3cm角","中にんじん2本、1.5cm輪切り","サラダ油大さじ1","水800ml","カレールウ1箱（S&Bゴールデンカレー中辛など、約100g）","ウスターソース小さじ1","ケチャップ小さじ1（任意、コクを出す）","塩・黒コショウ適量"],"en":["2 cups short-grain rice (uncooked)","400g boneless skinless chicken thighs (or beef chuck), cut into 3 cm pieces","2 large onions, cut into medium dice","2 medium potatoes, cut into 3 cm cubes","2 medium carrots, cut into 1.5 cm rounds","1 tbsp vegetable oil","800ml water","1 pack Japanese curry roux blocks (e.g. S&B Golden Curry, medium, approx. 100g)","1 tsp Worcestershire sauce","1 tsp ketchup (optional, for depth)","salt and black pepper to taste"],"ro":["2 căni orez cu bob scurt (nepreparare)","400g pulpe de pui dezosate fără piele (sau vită pentru friptură), tăiate cuburi de 3 cm","2 cepe mari, tăiate cuburi medii","2 cartofi medii, tăiați cuburi de 3 cm","2 morcovi medii, tăiați rondele de 1,5 cm","1 lingură ulei vegetal","800ml apă","1 pachet blocuri de roux curry japonez (ex. S&B Golden Curry, mediu picant, aprox. 100g)","1 linguriță sos Worcestershire","1 linguriță ketchup (opțional, pentru rotunjimea gustului)","sare și piper negru după gust"]},"howIsMade":{"ja":"ご飯：短粒米360g（2カップ）を冷水で3–4回水が澄むまで洗う、鍋に540ml（2½カップ）の冷水と一緒に入れる、蓋なしで沸騰させ、蓋をして最弱火で13分炊く、火から下ろし、蓋をしたまま10分蒸らす、蓋を開けないこと。玉ねぎをカラメル化：大きな鍋で油大さじ1を中火で熱する、中サイズの角切り玉ねぎ2個を加え、頻繁に混ぜながら15–20分炒めて柔らかく金茶色になるまで——このステップを省略しないこと、カラメル化した玉ねぎが風味の骨格。肉を焼く：3cm角に切った鶏もも肉または牛肩肉400gを加え、塩こしょうで味付けし、全面を3–4分焼いて色を付ける、肉は深い金色のクラストが必要——追加の風味。野菜：1.5cm厚に切った人参2本と3cm角に切ったジャガイモ2個を加える、1分混ぜて野菜を油でコーティングする。ベースを煮込む：水800mlを注ぎ、沸騰させ、弱火に落として蓋なしで15分、またはジャガイモがちょうど柔らかくなるまで煮込む（串で確認）。ルウを加える：鍋を火から外す、日本のカレールウブロック100gを小さく割り入れて完全に溶けるまで混ぜる——火から外して入れるとダマになりにくい。ソースを濃くする：鍋を弱火に戻し、頻繁に混ぜながら10分煮込んでソースを濃くて光沢のあるものに——スプーンの裏をコーティングするはず、深みのためにウスターソース小さじ1とケチャップ小さじ1を混ぜ込み、味を見て塩を調整する。盛り付け：深皿の熱いご飯の上に、たっぷりのカレーをかける、伝統的な付け合わせ：カツ、千切りキャベツ、福神漬け、1つの皿にご飯とカレー両方を混ぜずに盛る——食卓でスプーンで一緒にする。","en":"THE RICE: rinse 360 g (2 cups) short-grain rice in cold water 3–4 times until the water runs clear; place in a pot with 540 ml (2½ cups) cold water; bring to a boil uncovered, cover, reduce to lowest heat and cook 13 minutes; remove from heat and rest covered 10 minutes; do not lift the lid. CARAMELIZE THE ONIONS: in a large pot, heat 1 tbsp oil over medium heat; add 2 medium-diced onions and cook, stirring often, for 15–20 minutes until soft and golden — DO NOT skip this step; the caramelized onions are the backbone of flavour. BROWN THE MEAT: add 400 g boneless chicken thighs or beef chuck cut in 3 cm pieces, season with salt and pepper, sear on all sides 3–4 minutes; the meat must have a deep golden crust — extra flavour. VEGETABLES: add 2 carrots cut in 1.5 cm rounds and 2 potatoes cut in 3 cm cubes; stir 1 minute to coat the vegetables in the oil. SIMMER THE BASE: pour in 800 ml water, bring to a boil, reduce to a gentle simmer uncovered for 15 minutes, or until the potato is just tender (check with a skewer). ADD THE ROUX: remove the pot from the heat; break 100 g Japanese curry roux blocks into small pieces and stir into the pot until fully dissolved — adding off heat prevents lumps. THICKEN THE SAUCE: return the pot to low heat and simmer, stirring frequently, for 10 minutes until the sauce is thick and glossy — it should coat the back of a spoon; stir in 1 tsp Worcestershire sauce and 1 tsp ketchup for depth, taste and adjust salt. SERVE: spoon a generous portion of curry over hot rice in deep plates; traditional accompaniments: katsu schnitzel, shredded cabbage, pickled red radishes (fukujinzuke); a single plate holds both rice and curry without mixing them — you spoon them together at the table."}},{"id":161,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"ファソラーダ","en":"Fasolada","ro":"Fasolada"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["乾燥白いんげん豆400g（カネリーニ、ネイビー、またはギリシャの大粒ジャイガンテス）、冷水に一晩浸す","中サイズの人参2本（~200g）、皮をむき1cm角に切る","セロリの茎2本（~150g）、1cm角に切る + セロリの葉30g刻む（任意、伝統的）","大玉ねぎ1個（~200g）、みじん切り","にんにく4片、みじん切り","完熟トマト400g（中4個）— 皮をむきおろす、または400g缶のクラッシュトマト1缶","トマトペースト大さじ1","ソフリット用エクストラバージンオリーブオイル100ml + 仕上げ用に60ml追加","ローリエ2枚","乾燥オレガノ小さじ1","塩小さじ1.5 + 味付け塩","挽きたて黒コショウ小さじ0.5","赤ワインビネガー大さじ1（任意、最後を明るくする）","水1.5L（または野菜ストック）","盛り付け用：カリカリの田舎パン、カラマタオリーブ、砕いたフェタチーズ、新鮮なパセリ"],"en":["400 g dried white beans (cannellini, navy, or large Greek gigantes), soaked overnight in cold water","2 medium carrots (~200 g), peeled and diced 1 cm","2 celery stalks (~150 g), diced 1 cm + 30 g celery leaves chopped (optional, traditional)","1 large onion (~200 g), finely diced","4 garlic cloves, finely minced","400 g ripe tomatoes (4 medium) — peeled and grated OR 1 × 400 g can crushed tomatoes","1 tbsp tomato paste","100 ml extra-virgin olive oil for the soffritto + 60 ml more for finishing","2 bay leaves","1 tsp dried oregano","1.5 tsp salt + more to taste","0.5 tsp freshly ground black pepper","1 tbsp red wine vinegar (optional, brightens at the end)","1.5 L water (or vegetable stock)","To serve: crusty country bread, Kalamata olives, crumbled feta cheese, fresh parsley"],"ro":["400 g fasole albă uscată (cannellini, navy sau gigantes grecești), înmuiate peste noapte în apă rece","2 morcovi medii (~200 g), curățați și tăiați cuburi de 1 cm","2 tulpini de țelină (~150 g), tăiate cuburi de 1 cm + 30 g frunze de țelină tocate (opțional, tradițional)","1 ceapă mare (~200 g), tăiată fin","4 căței de usturoi, tocați fin","400 g roșii coapte (4 medii) — decojite și rase SAU 1 conservă × 400 g de roșii zdrobite","1 lingură pastă de roșii","100 ml ulei de măsline extravirgin pentru sotat + 60 ml suplimentar pentru finisare","2 frunze de dafin","1 linguriță oregano uscat","1,5 lingurițe sare + sare după gust","0,5 linguriță piper negru proaspăt măcinat","1 lingură oțet de vin roșu (opțional, dă luminozitate la final)","1,5 L apă (sau supă de legume)","Pentru servire: pâine de țară crocantă, măsline Kalamata, brânză feta sfărâmată, pătrunjel proaspăt"]},"howIsMade":{"ja":"豆を浸す：白いんげん豆400gを大きなボウルに入れ、冷水で5cm覆って8時間または一晩浸す、水切りして洗う——浸すことで調理時間が短くなり、豆が均等に丸ごと茹で上がる。豆を下茹で：水切りした豆を大鍋に入れ、冷水で3cm覆って沸騰させる、強火で10分茹でて水切り——このステップで消化しにくいガスの原因となる成分を取り除き、よりすっきりしたスープが取れる。ソフリット：5L重い鍋に中火でオリーブオイル100mlを熱する、みじん切り玉ねぎ200g+人参200g+セロリ150gを加え、頻繁に混ぜながら12–15分炒める、とても柔らかくなり、軽く色づき始めるまで——このゆっくり調理した野菜のベースがファソラーダの深みの基礎、みじん切りにんにく4片を加え1分炒めて香りを立たせる。トマトを開花：トマトペースト大さじ1を加え、2分混ぜながら濃くなるまで煮る、400gのおろしトマト（または缶のクラッシュ）を加え、5分煮て生の酸味を飛ばし、深い赤色になるまで。豆と水を加える：下茹でした豆を鍋に戻す、水1.5L（または野菜ストック）、ローリエ2枚、オレガノ小さじ1、塩小さじ1.5、コショウ小さじ0.5を加える、沸騰させて弱火に落とす。ゆっくり煮る：蓋なしで60–90分、時々混ぜながら煮る、豆が完全に柔らかく中心がクリーミーになるが形は保つまで——1時間目以降は15分ごとに豆を試食、スープは約半分に減り、スープの濃度に、早く煮詰まりすぎる場合は水を足す。仕上げ：ローリエを取り除く、セロリの葉30g（使用する場合）と赤ワインビネガー大さじ1を加えて明るくする、味を見て塩を調整、火から下ろし、新鮮なエクストラバージンオリーブオイル60mlを表面にかける——これが仕上げオイルで、スープに艶と香りを与える、10分休ませて味をなじませる。盛り付け：深皿に盛り、各皿にもう小さじ1のオリーブオイルをかけ、挽きたて黒コショウを上に挽く、カリカリの田舎パン、小さなボウルのカラマタオリーブ、砕いたフェタチーズ、刻んだ新鮮なパセリを食卓に添えて提供する、翌日はさらに美味しい。","en":"SOAK THE BEANS: place 400 g dried white beans in a large bowl, cover with cold water by 5 cm, and soak 8 hours or overnight; drain and rinse — the soak shortens the cooking time and helps even, intact beans. PARBOIL THE BEANS: place the drained beans in a large pot, cover with cold water by 3 cm, and bring to a boil; boil hard 10 minutes, then drain — this removes the indigestible compounds that cause gas and gives a cleaner-tasting broth. SOFFRITTO: in a heavy 5 L pot, heat 100 ml olive oil over medium heat; add 200 g diced onion + 200 g diced carrot + 150 g diced celery and cook, stirring often, 12–15 minutes until very soft and starting to gold — this slow vegetable base is the foundation of fasolada's depth; add 4 minced garlic cloves and cook 1 more minute until fragrant. BLOOM THE TOMATO: add 1 tbsp tomato paste and cook stirring 2 minutes until darkened; add 400 g grated tomato (or canned crushed) and simmer 5 minutes until the raw acidity cooks off and the mixture turns deep red. ADD BEANS AND WATER: return the parboiled beans to the pot; add 1.5 L water (or vegetable stock), 2 bay leaves, 1 tsp oregano, 1.5 tsp salt and 0.5 tsp pepper; bring to a boil, reduce to a gentle simmer. SLOW SIMMER: cook uncovered 60–90 minutes, stirring occasionally, until the beans are completely tender and creamy at the centre but still hold their shape — taste a bean every 15 minutes after the 1 hour mark; the broth should reduce by about half and thicken to a soupy consistency; add more water if it dries out too fast. FINISH: discard the bay leaves; stir in 30 g chopped celery leaves (if using) and 1 tbsp red wine vinegar for brightness; taste and adjust salt; off the heat, drizzle 60 ml fresh extra-virgin olive oil over the surface — this is the finishing oil that makes the soup glossy and aromatic; let rest 10 minutes for flavours to settle. SERVE: ladle into deep bowls, drizzle each portion with another teaspoon of olive oil, and grind fresh black pepper over the top; serve with crusty country bread, a small bowl of Kalamata olives, crumbled feta, and chopped fresh parsley on the table; even better the next day."}},{"id":162,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"ja":"メキシコ","en":"Mexico","ro":"Mexic"},"name":{"ja":"トラユーダス","en":"Tlayudas","ro":"Tlayudas"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["トラユーダ用トルティーヤ4枚（~30cm、セミドライ）または大きな小麦トルティーヤ4枚で代用","黒豆250g、一晩水に浸す（または400g缶1個）","豆の調理用ラード100gまたは植物油100ml","大玉ねぎ1個（~200g）：半分は豆用に4等分、もう半分は提供用にみじん切り","にんにく4片（豆に2片、肉に2片）","豆用：クミンパウダー小さじ1+乾燥オレガノ小さじ1+塩小さじ1","フランクまたはスカートステーキ500g、繊維に対して直角に極薄切り（タサホ風）","新鮮メキシカンチョリソ200g（またはスペイン製）、ケーシングから出したもの","ケシージョ（オアハカチーズ）300gまたは低水分モッツァレラ、すりおろし","アイスバーグレタス200g、千切り","完熟アボカド2個（~300g）、スライス","完熟トマト4個（~400g）、スライス","サルサロハまたはベルデ200g（自家製または市販）","ライム1個くし切り+提供用の新鮮なコリアンダー"],"en":["4 tlayuda tortillas (~30 cm, semi-dried) or 4 large flour tortillas as substitute","250 g dried black beans soaked overnight (or 1 × 400 g can)","100 g lard or 100 ml vegetable oil for frying beans + cooking","1 large onion (~200 g): half quartered for the beans, the other half finely diced for serving","4 garlic cloves (2 for beans, 2 for meat)","1 tsp ground cumin + 1 tsp dried oregano + 1 tsp salt for the beans","500 g flank or skirt steak, sliced very thinly across the grain (tasajo-style)","200 g fresh Mexican chorizo (or Spanish), removed from casing","300 g quesillo (Oaxaca string cheese) or low-moisture mozzarella, shredded","200 g shredded iceberg lettuce","2 ripe avocados (~300 g), sliced","4 ripe tomatoes (~400 g), sliced","200 g salsa roja or salsa verde (homemade or store-bought)","1 lime cut into wedges + fresh cilantro for serving"],"ro":["4 tortillas tlayuda (~30 cm, semi-uscate) sau 4 tortillas mari de făină","250 g fasole neagră uscată înmuiată peste noapte (sau 1 conservă × 400 g)","100 g untură sau 100 ml ulei vegetal pentru prăjit fasolea + sotat","1 ceapă mare (~200 g): jumătate tăiată sferturi pentru fasole, cealaltă jumătate tocată fin pentru servire","4 căței de usturoi (2 pentru fasole, 2 pentru carne)","1 linguriță chimion măcinat + 1 linguriță oregano uscat + 1 linguriță sare pentru fasole","500 g flank steak sau skirt steak, feliat foarte subțire în diagonală (stil tasajo)","200 g chorizo proaspăt mexican (sau spaniol), scos din maț","300 g quesillo (brânză Oaxaca) sau mozzarella low-moisture, rasă","200 g salată iceberg, tocată","2 avocado coapte (~300 g), feliate","4 roșii coapte (~400 g), feliate","200 g salsa roja sau verde (de casă sau de la magazin)","1 lime tăiată sferturi + coriandru proaspăt pentru servire"]},"howIsMade":{"ja":"豆：水に浸した黒豆250gを水切り、1.5Lの水、半分に切った玉ねぎ4等分、皮付きにんにく2片、クミン小さじ1、オレガノ小さじ1、塩小さじ1を加え60–90分茹でてとても柔らかくなるまで、水切りし、煮汁200mlを取っておく。豆を炒める（フリホレスリフリトス）：フライパンにラード50gを中火で熱する、茹でた豆を加えてポテトマッシャーかへらで潰しながら、取っておいた煮汁を徐々に加えて濃いクリーミーペーストに、混ぜながら5–7分炒めて、わずかに黒くなりスモーキーな風味が出るまで。ステーキを焼く：大きなフライパンに油大さじ1を中強火で熱す、牛肉500gに塩こしょうをし、単層で片面2分焼く（鍋を混雑させない、バッチで作業）、アルミホイルで覆った皿に取り出して休ませる。チョリソを炒める：同じフライパンにケーシングを外したチョリソ200gを加え、木べらで崩しながら中火で5–7分炒めて、赤い油が出て肉が完全に火が通るまで、油と一緒に鍋に残しておく。トッピングを準備：アボカド2個、トマト4個、残りの玉ねぎの半分（みじん切り）をスライス、レタス200gを千切り、素早い組み立てのために、それぞれを別々のボウルに分ける。トラユーダを組み立てる：プランチャまたは大きなグリドルパンを中強火で予熱、乾いた表面にトラユーダトルティーヤを置き、リフライドビーンズを縁から1cmまで惜しみなく塗る、豆の上にすりおろしチーズ75gを散らす、焼いた肉とチョリソを一人前加える。カリッとさせる：プランチャで5–7分裏返さずに焼く——トルティーヤの底は金茶色でカリカリ、軽い焦げ目が見えるべき、チーズは完全に溶けなければならない、最後の2分は蓋をして溶けを加速する。盛り付け：広いへらでトラユーダを皿にスライドさせる、レタス、トマトスライス、アボカド、刻み玉ねぎ、サルサをトッピング、ライムを絞ってコリアンダーを散らす、半分に折るか、開いて手で食べる、残りの3枚も繰り返す、すぐに提供する——時間が経つとゴム状になる。","en":"THE BEANS: drain 250 g soaked black beans; boil in 1.5 L water with half an onion in quarters, 2 whole garlic cloves, 1 tsp cumin, 1 tsp oregano and 1 tsp salt for 60–90 minutes until very tender; drain, reserving 200 ml of the cooking liquid. REFRY THE BEANS (frijoles refritos): in a skillet, heat 50 g lard over medium heat; add the cooked beans and mash with a potato masher or spatula, adding the reserved liquid gradually until you have a thick creamy paste; cook 5–7 minutes, stirring, until slightly blackened and smoky. SEAR THE STEAK: heat 1 tbsp oil in a large skillet over medium-high; season 500 g beef with salt and pepper, sear 2 minutes per side in a single layer (do not crowd the pan, work in batches); rest the meat on a foil-tented plate. FRY THE CHORIZO: in the same skillet, add 200 g chorizo from its casing, break it up with a wooden spoon, and fry 5–7 minutes over medium heat until the red oil is released and the meat is fully cooked; leave it in the pan with its oil. PREP THE TOPPINGS: slice 2 avocados, 4 tomatoes and the remaining onion half (finely diced); shred 200 g lettuce; place each in a separate bowl for fast assembly. ASSEMBLE THE TLAYUDA: preheat a plancha or large griddle over medium-high heat; place a tlayuda tortilla on the dry surface and spread it with a generous layer of refried beans to within 1 cm of the edges; scatter 75 g shredded cheese over the beans; add a portion of seared steak and chorizo. CRISP IT UP: cook on the plancha over medium heat 5–7 minutes without flipping — the bottom of the tortilla must turn golden brown, crunchy, and show light scorch marks; the cheese must melt completely; cover with a lid for the last 2 minutes to speed melting. SERVE: slide the tlayuda onto a plate with a wide spatula; top with lettuce, tomato slices, avocado, diced onion, salsa; squeeze lime and scatter cilantro; fold in half or eat open with your hands; repeat for the remaining 3 tlayudas; serve immediately — it gets chewy if it sits."}},{"id":163,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"ja":"コロンビア","en":"Colombia","ro":"Columbia"},"name":{"ja":"バンデハ・パイサ","en":"Bandeja Paisa","ro":"Bandeja Paisa"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["フリホレス・アンティオケニョス用：乾燥赤キドニーまたはカーガマント豆400g、一晩浸す","中サイズ人参1本（~100g）すりおろし + 中サイズトマト2個（~250g）すりおろし + 玉ねぎ1個（~150g）みじん切り + にんにく4片、ホガオ用","豆用：油大さじ2 + トマトペースト大さじ1 + クミン小さじ1 + 塩小さじ1","熟したプランテン1本（~150g）角切り、豆用","アロス・ブランコ用：中粒米360g（2カップ）+ 水540ml + 塩小さじ0.5","カルネ・モリダ用：牛ひき肉500g + みじん切り玉ねぎ1個 + にんにく4片 + すりおろしトマト2個 + 油大さじ2 + クミン小さじ1 + 塩小さじ1 + コショウ小さじ0.5 + 牛肉ストック50ml","チチャロン用：皮付き豚バラ肉800g、~10cmの8本に切る + 塩小さじ1","生コロンビアチョリソ4本（各~80g）","モルシージャ4本（血ソーセージ、各~80g）","小さなアレパ4枚用：プリクック白コーンミール（Harina P.A.N.）200g + 温水240ml + 塩小さじ0.5 + 鍋用の油大さじ1","マドゥロ用：とても熟したプランテン2本（皮が真っ黒）+ 油大さじ2","目玉焼き用の大きな卵4個 + 油大さじ1 + 塩とコショウ","完熟アボカド2個、半分に切って種を取る","カリカリの白パン4切れ + ライムくし切り4個 + 提供用の塩"],"en":["For frijoles antioqueños: 400 g dried red kidney or cargamanto beans, soaked overnight","1 medium carrot (~100 g) grated + 2 medium tomatoes (~250 g) grated + 1 onion (~150 g) finely diced + 4 garlic cloves for the hogao","2 tbsp oil + 1 tbsp tomato paste + 1 tsp ground cumin + 1 tsp salt for the beans","1 ripe plantain (~150 g) diced for the beans","For arroz blanco: 360 g (2 cups) medium-grain white rice + 540 ml water + 0.5 tsp salt","For carne molida: 500 g ground beef + 1 onion finely diced + 4 garlic cloves + 2 grated tomatoes + 2 tbsp oil + 1 tsp cumin + 1 tsp salt + 0.5 tsp pepper + 50 ml beef stock","For chicharrón: 800 g pork belly skin-on cut into 8 strips of ~10 cm + 1 tsp salt","4 raw Colombian chorizos (~80 g each)","4 morcillas (blood sausages, ~80 g each)","For 4 small arepas: 200 g precooked white corn flour (Harina P.A.N.) + 240 ml warm water + 0.5 tsp salt + 1 tbsp oil for the griddle","For maduro: 2 very ripe plantains (deep black skin) + 2 tbsp oil","4 large eggs for sunny-side up + 1 tbsp oil + salt and pepper","2 ripe avocados, halved and pitted","4 slices of crusty white bread + 4 lime wedges + salt to serve"],"ro":["Pentru frijoles antioqueños: 400 g fasole roșie uscată (cargamanto sau kidney) înmuiată peste noapte","1 morcov mediu (~100 g) ras + 2 roșii medii (~250 g) rase + 1 ceapă (~150 g) tocată fin + 4 căței usturoi pentru hogao","2 linguri ulei + 1 lingură pastă de roșii + 1 linguriță chimion + 1 linguriță sare pentru fasole","1 banană plantain coaptă (~150 g) tocată în cuburi pentru fasole","Pentru arroz blanco: 360 g (2 căni) orez cu bob mediu + 540 ml apă + 0,5 linguriță sare","Pentru carne molida: 500 g vită tocată + 1 ceapă tocată + 4 căței usturoi + 2 roșii rase + 2 linguri ulei + 1 linguriță chimion + 1 linguriță sare + 0,5 linguriță piper + 50 ml supă de vită","Pentru chicharrón: 800 g costiță de porc cu coajă tăiată în 8 fâșii lungi de 10 cm + 1 linguriță sare","4 chorizos columbieni cruzi (~80 g fiecare)","4 morcillas (cârnați de sânge, ~80 g fiecare)","Pentru arepas (4 mici): 200 g făină de porumb precoaptă (Harina P.A.N.) + 240 ml apă caldă + 0,5 linguriță sare + 1 lingură ulei pentru tigaie","Pentru maduro: 2 banane plantain foarte coapte (coaja neagră) + 2 linguri ulei","4 ouă mari pentru ochiuri + 1 lingură ulei + sare și piper","2 avocado coapte, jumătățite și fără sâmbure","4 felii pâine albă crocantă + 4 felii de lime + sare pentru servire"]},"howIsMade":{"ja":"浸す＆計画：赤豆400gを一晩浸す、バンデハ・パイサは6つの並行コンポーネントを必要とする——開始前に全ての材料と道具を集め、3つの鍋と2つのフライパンを用意する。豆：豆を水切りし、1.5Lの水でおろし人参+おろしトマト1個+玉ねぎ+にんにく2片+クミン小さじ1+塩小さじ1と60–90分柔らかくなるまで煮込む、最後の15分でホガオを作る：油大さじ2で残りの玉ねぎ+にんにく2片+おろしトマト1個+トマトペースト大さじ1を5分炒める、豆に角切りプランテンと一緒に加え、さらに10分煮込む。ご飯：360gの米を冷水で3回洗う、540mlの水と塩小さじ0.5と一緒に鍋に入れる、沸騰させ、蓋をして最弱火に12分、火を止めて10分蒸らす。カルネ・モリダ：フライパンに油大さじ2を中強火で熱す、玉ねぎとにんにくを5分柔らかくなるまで炒める、牛ひき肉500gを加え、スプーンで崩しながら8分焼く、おろしトマト2個、クミン小さじ1、塩小さじ1、コショウ小さじ0.5を加え5分煮る、ストック50mlでデグラーズする。チチャロン：皮付き豚バラ8本を200ml冷水と塩小さじ1の鍋に入れる、沸騰させ、蓋をして30分煮込む、完全に水切り、同じ鍋で豚肉を自身の脂で中強火8–10分、頻繁に返しながら、皮が金茶色でカリカリになるまで焼く、（代替：200 °Cオーブンで40分、ラックの上で、）。アレパ：ボウルで250gコーンミール、240mlの温水、塩小さじ0.5を湿った生地になるまで混ぜる、5分休ませる、直径10cm、厚さ1cmの4枚のパティに成形する、熱いフライパンに油大さじ1を加え中火で片面4–5分、金茶色で暗い斑点ができるまで焼く。マドゥロ+卵+ソーセージ：黒プランテン2本を1cm厚の輪切りに、油大さじ2で中火2分ずつ片面、キャラメル化するまで揚げる、別のフライパンで生チョリソ4本を片面5分、モルシージャ4本を片面3分焼く、それから油小さじ1で卵4個を2分、白身が固まり黄身が流れる状態に焼く。盛り付け：4枚の大きな皿にこの順序で並べる：ご飯の山、豆の盛り、カルネ・モリダ一人前、チチャロン2片、チョリソ1本、モルシージャ1本、肉の上に目玉焼き1個、マドゥロ2スライス、アボカド1/2、アレパ1枚、パン1切れ、ライム1切れ、すぐ提供——バンデハ・パイサはナイフとフォークで食べ、一口ごとに複数のコンポーネントを組み合わせる。","en":"SOAK & PLAN: soak 400 g red beans overnight; bandeja paisa runs 6 parallel components — gather all ingredients and tools before starting, plus 3 pots and 2 skillets. THE BEANS: drain the beans, simmer in 1.5 L water with grated carrot + 1 grated tomato + onion + 2 garlic cloves + 1 tsp cumin + 1 tsp salt 60–90 minutes until tender; in the final 15 minutes make the hogao: sauté in 2 tbsp oil the remaining onion + 2 garlic + 1 grated tomato + 1 tbsp tomato paste 5 minutes; stir into the beans with the diced plantain and cook 10 more minutes. THE RICE: rinse 360 g rice in cold water 3 times; place with 540 ml water and 0.5 tsp salt; bring to a boil, cover, reduce to lowest heat 12 minutes, rest covered 10 minutes. CARNE MOLIDA: heat 2 tbsp oil in a skillet over medium-high; sauté onion and garlic 5 minutes until soft; add 500 g ground beef, break up with the spoon and brown 8 minutes; add 2 grated tomatoes, 1 tsp cumin, 1 tsp salt and 0.5 tsp pepper, cook 5 minutes; deglaze with 50 ml stock. CHICHARRÓN: place 8 strips of pork belly skin-on in a pot with 200 ml cold water and 1 tsp salt; bring to a boil, cover and simmer 30 minutes; drain completely; in the same pot, fry the pork in its own fat over medium-high heat 8–10 minutes turning often until the skin is golden and crackling; (Alternative: 200 °C oven 40 minutes on a rack.). AREPAS: mix 200 g corn flour with 240 ml warm water and 0.5 tsp salt in a bowl until a damp dough forms; rest 5 minutes; shape into 4 patties of 10 cm diameter and 1 cm thick; griddle in a hot pan with 1 tbsp oil over medium heat 4–5 minutes per side until golden with dark spots. MADURO + EGGS + SAUSAGES: slice 2 black plantains into 1 cm rounds; fry in 2 tbsp oil over medium heat 2 minutes per side until caramelized; in another skillet, fry 4 raw chorizos 5 minutes per side and 4 morcillas 3 minutes per side; then fry 4 eggs in 1 tsp oil 2 minutes until whites set but yolks runny. ASSEMBLY: on 4 large platters arrange in this order: a mound of rice, a generous ladle of beans, a portion of carne molida, 2 chicharrón pieces, 1 chorizo, 1 morcilla, 1 fried egg on top of the meat, 2 maduro slices, 1/2 avocado, 1 arepa, 1 bread slice, 1 lime wedge; serve immediately — bandeja paisa is eaten with knife and fork, each bite in combination with others."}},{"id":164,"servings":4,"tipType":"def","pairingsType":"def","origin":{"ja":"ハンガリー","en":"Hungary","ro":"Ungaria"},"name":{"ja":"ラーンゴシュ","en":"Lángos","ro":"Lángos"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["中力粉または強力粉T550 500g","インスタントドライイースト7g（または生イースト21g）","グラニュー糖小さじ1（イーストを活性化）","生地用の細かい塩小さじ1.5","38°Cの温めた全乳300ml（または水、伝統的）","茹でて潰したじゃがいも100g（ふわふわな食感の秘訣）","生地用の中性油大さじ2","揚げ油用ひまわり油または中性油1L","にんにくダレ用：にんにく4片を塩小さじ1と水大さじ1で潰しペースト状に","ハンガリーのサワークリーム（tejföl）200g","シャープな粉チーズ200g（チェダー/ゴーダ/エダム系）","新鮮なチャイブ小束1、みじん切り（任意）","仕上げ用の塩","器具：揚げ物用の幅広い重い鍋+穴あきおたま+ワイヤーラック"],"en":["500 g all-purpose or T550 bread flour","7 g instant dry yeast (or 21 g fresh yeast)","1 tsp granulated sugar (to feed yeast)","1.5 tsp fine salt for the dough","300 ml warm whole milk (or water, traditional) at 38 °C","100 g boiled mashed potato (the secret to the fluffy texture)","2 tbsp neutral oil for the dough","1 L sunflower or neutral oil for deep-frying","For garlic rub: 4 garlic cloves crushed with 1 tsp salt + 1 tbsp water into a paste","200 g Hungarian sour cream (tejföl)","200 g sharp grated cheese (cheddar/gouda/edam-style)","1 small bunch fresh chives, finely chopped (optional)","Salt for finishing","Equipment: wide heavy pot for frying + slotted spoon + wire rack"],"ro":["500 g făină universală sau de pâine T550","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 linguriță zahăr granulat (pentru hrănirea drojdiei)","1,5 lingurițe sare fină pentru aluat","300 ml lapte integral cald (sau apă, tradițional) la 38 °C","100 g cartof fiert și pasat (secretul texturii pufoase)","2 linguri ulei neutru pentru aluat","1 L ulei de floarea-soarelui sau neutru pentru prăjit","Pentru ungerea cu usturoi: 4 căței de usturoi zdrobiți cu 1 linguriță sare + 1 lingură apă în pastă","200 g smântână ungurească (tejföl)","200 g brânză tare rasă (cheddar/gouda/edam)","1 legăturică mică de ceapă verde proaspătă (arpagic), tocată fin (opțional)","Sare pentru finisare","Echipament: oală grea și lată pentru prăjit + lingură cu fante + grătar de sârmă"]},"howIsMade":{"ja":"イーストを活性化：牛乳100mlを38°Cに温め、イースト7gと砂糖小さじ1を加え、混ぜて10分置き泡立つまで、泡が出ない=死んだイースト、やり直す。生地を作る：大きなボウルに小麦粉500gと塩小さじ1.5を混ぜる、窪みを作り、泡立てたイースト牛乳、残りの温めた牛乳200ml、なめらかなマッシュポテト100g（だまなし）、油大さじ2を加える、手またはスタンドミキサーで10分こねて、なめらかで柔らかくやや粘着性のある状態に——パン生地より柔らかく。一次発酵：清潔な布で覆い、暖かい場所で1.5–2時間、2倍になるまで発酵させる。成形：手と作業台に薄く油を塗る、4等分（各~225g）に分ける、丸めて、覆って10分休ませる、油を塗った手で各球を25cmの円盤に約1cmの厚さに伸ばし、縁は少し薄く。二次発酵：成形した円盤を油を塗ったトレイに置き、ゆるく覆って20分発酵させ、ふっくらするまで。油を熱する：1Lの油を幅広い重い鍋に5cmの深さまで注ぐ、175°C（中強火）に熱する——小さな生地が5秒以内にジュージュー音を立てて浮き上がるべき。ラーンゴシュを揚げる：1枚のラーンゴシュをそっと熱い油に滑り込ませる、30秒後、穴あきおたまでそっと油の下に押し込む——劇的に膨らむ、深い黄金色になるまで片面60–90秒揚げる、ワイヤーラックで油切り（キッチンペーパーは底が蒸気で柔らかくなるので使わない）。トッピングと提供：まだ熱い表面にニンニクペースト（ニンニク4片を塩小さじ1+水大さじ1で潰したもの）を塗る、サワークリーム50gを塗り広げ、すりおろしチーズ50gを散らし、刻んだチャイブと塩ひとつまみを振る、手で持つかお皿で提供、パンが外はカリっと内はふんわりしている5分以内に食べる。","en":"PROOF THE YEAST: warm 100 ml of the milk to 38 °C, add 7 g yeast and 1 tsp sugar, stir and let stand 10 minutes until foamy; no foam = dead yeast, start over. MAKE THE DOUGH: in a large bowl combine 500 g flour with 1.5 tsp salt; make a well, add the foamed yeast-milk, the remaining 200 ml warm milk, 100 g smooth mashed potato (no lumps), and 2 tbsp oil; knead by hand or stand mixer 10 minutes until smooth, soft and slightly sticky — softer than bread dough. FIRST PROOF: cover with a clean towel and rise in a warm place 1.5–2 hours until doubled. SHAPE: lightly oil hands and work surface; divide into 4 equal portions (~225 g each); roll into balls, rest 10 minutes covered; with oiled hands stretch each ball into a 25 cm disc about 1 cm thick, slightly thinner at the edges. SECOND PROOF: place shaped discs on an oiled tray, cover loosely and let rise 20 minutes until puffy. HEAT THE OIL: pour 1 L oil into a wide heavy pot to a 5 cm depth; heat to 175 °C (medium-high) — a small piece of dough should sizzle and rise within 5 seconds. FRY THE LÁNGOS: carefully slide one lángos into the hot oil; after 30 seconds, gently push under with a slotted spoon — it puffs dramatically; fry 60–90 seconds per side until deeply golden brown; drain on a wire rack (NOT paper towels which steam the base soft). TOPPING & SERVE: brush the still-hot top with garlic paste (4 garlic crushed with 1 tsp salt + 1 tbsp water); smear with 50 g sour cream, scatter 50 g grated cheese, sprinkle chopped chives and a pinch of salt; serve in hand or on a plate, eaten within 5 minutes while bread is crisp outside and pillowy inside."}},{"id":165,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"ja":"インド","en":"India","ro":"India"},"name":{"ja":"ラジマ","en":"Rajma","ro":"Rajma"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["乾燥赤キドニービーンズ（ラジマ）350g、冷水に8–12時間浸す（または2×400g缶詰の赤キドニービーンズを水切りしたものを近道として）","豆を煮る水1.2L+塩小さじ1+月桂樹の葉2枚+ブラックカルダモンの莢4個（圧力鍋で煮るため）","マサラ用ギーまたは中性油大さじ3","クミンシード（ジーラ）小さじ1","中サイズの黄玉ねぎ2個（~300g）非常に細かく切る","ニンニク6片+生姜4cm——大さじ1の水とともにペースト状にすりおろす","青唐辛子1本（または好みで）、細かく刻む","中サイズの完熟トマト4個（~400g）、ブレンダーで滑らかなパルプに","トマトペースト大さじ1（コクのため）","マサラ用挽きコリアンダー（ダニア）小さじ1+挽きクミン（ジーラ）小さじ1+ターメリック（ハルディ）小さじ0.5+カシミールレッドチリパウダー小さじ1+塩小さじ1","ガラムマサラ小さじ1（最後に加える、煮込まない）","カスリメティ（乾燥フェヌグリーク葉）小さじ1、手のひらで揉む（最後に加える）","バター30gサイコロ状（レストラン風の仕上げ）","シングルクリーム大さじ1または全脂ヨーグルト大さじ2（任意、クリーミーさのため）","飾り用の新鮮なコリアンダー（パクチー）の葉+ライム1個をくし切り；提供用：540mlの水に塩小さじ0.5を加えて炊いた360g（2カップ）バスマティ米、お好みでナンまたはジーララ"],"en":["350 g dried red kidney beans (rajma) soaked 8–12 h in cold water (OR 2 × 400 g cans drained as a shortcut)","1.2 L cooking water for the beans + 1 tsp salt + 2 bay leaves + 4 black cardamom pods (for pressure-cooking the beans)","3 tbsp ghee or neutral oil for the masala","1 tsp whole cumin seeds (jeera)","2 medium yellow onions (~300 g) very finely diced","6 garlic cloves + 4 cm fresh ginger — grated into a paste with 1 tbsp water","1 green chili (or to taste), finely chopped","4 medium ripe tomatoes (~400 g), pureed in a blender to a smooth pulp","1 tbsp tomato paste (for body)","1 tsp ground coriander (dhania) + 1 tsp ground cumin (jeera) + 0.5 tsp turmeric (haldi) + 1 tsp Kashmiri red chili powder + 1 tsp salt for the masala","1 tsp garam masala (added at end, not boiled)","1 tsp kasuri methi (dried fenugreek leaves), crushed in palm (added at end)","30 g butter cubed (the restaurant-style finish)","1 tbsp single cream or 2 tbsp full-fat yogurt (optional, for creaminess)","Fresh coriander (cilantro) leaves to garnish + 1 lime in wedges; to serve: 360 g (2 cups) basmati rice cooked in 540 ml water with 0.5 tsp salt, and naan or jeera rice if preferred"],"ro":["350 g fasole roșie uscată (rajma) înmuiată 8–12 h în apă rece (SAU 2 × 400 g cutii de fasole roșie scursă ca scurtătură)","1,2 L apă de fierbere pentru fasole + 1 linguriță sare + 2 foi de dafin + 4 păstăi de cardamom negru (pentru fierberea sub presiune)","3 linguri ghee sau ulei neutru pentru masala","1 linguriță semințe întregi de chimion (jeera)","2 cepe galbene medii (~300 g) tocate foarte fin","6 căței de usturoi + 4 cm de ghimbir proaspăt — răzuite în pastă cu 1 lingură de apă","1 ardei iute verde (sau după gust), tocat fin","4 roșii medii coapte (~400 g), pasate la blender până la o pulpă fină","1 lingură pastă de roșii (pentru corp)","1 linguriță coriandru măcinat (dhania) + 1 linguriță chimion măcinat (jeera) + 0,5 linguriță turmeric (haldi) + 1 linguriță Kashmiri chili pudră + 1 linguriță sare pentru masala","1 linguriță garam masala (adăugat la final, nu fiert)","1 linguriță kasuri methi (frunze uscate de schinduf), zdrobite în palmă (adăugat la final)","30 g unt cubulețe (finisajul în stil restaurant)","1 lingură smântână dulce single sau 2 linguri iaurt gras (opțional, pentru cremozitate)","Frunze proaspete de coriandru (cilantro) pentru garnitură + 1 lămâie verde feliată; pentru servire: 360 g (2 căni) orez basmati fiert în 540 ml apă cu 0,5 linguriță sare, plus naan sau jeera rice dacă preferi"]},"howIsMade":{"ja":"豆を浸す：ラジマ350gを冷水で2–3回すすぐ、冷水で5cm上まで覆い、8–12時間（または一晩）浸す、水を切ってすすぐ、浸水を省くと中心が生煮えになりガスを発生させる食感になる。圧力鍋で豆を煮る：浸したラジマを圧力鍋に入れ、水1.2L+塩小さじ1+月桂樹の葉2枚+ブラックカルダモンの莢4個を加える、強火で4–5回の笛が鳴るまで圧力をかけ、その後弱火にして25分煮る、圧力を自然に抜く、豆は完全に柔らかくなるはず——親指と人差し指で1粒つぶしてみる；軽い圧力でつぶれるべき、（代替案：開放鍋で1.5–2時間煮込み、）500mlの煮汁を残して水切り。ブナオ（BHUNAO）——テンパリング：重いカダイまたは深いフライパンを中火にかけ、ギー大さじ3を溶かす、きらめいたら、クミンシード小さじ1を加える——5秒以内にジュージューと音を立てて弾ける、黒くしないこと。玉ねぎ：細かく切った玉ねぎ300gを加える、頻繁にかき混ぜながら12–15分煮て、深い黄金色——ほぼキャラメル化——になるまで、この長くゆっくりとした玉ねぎのブナオが、レストランのラジマと素人の試みを分けるもの、急がない。生姜-ニンニク-青唐辛子：生姜ニンニクペーストと青唐辛子を加える、生の匂いが消えるまで1–2分かき混ぜる。トマトベース：ピューレ状のトマトパルプ+トマトペースト大さじ1+挽きコリアンダー小さじ1+挽きクミン小さじ1+ターメリック小さじ0.5+カシミールチリ小さじ1+塩小さじ1を加える、頻繁にかき混ぜながら8–10分煮て、油がフライパンの縁でマサラから分離するまで——これがブナオが完了し、生のトマトが煮えたという視覚的サイン。豆と一緒に煮る：水切りしたラジマと予約しておいた煮汁500mlを入れる、優しくかき混ぜる、沸騰させたら蓋なしで20–25分煮て、スプーンでフライパンの側面に豆をいくつか部分的に潰してグレイビーを濃くする、グレイビーは煮詰まって豆にコーティングするはず——スープでも乾燥でもなく、スプーンに残る濃厚なシチューのよう。仕上げと提供：ガラムマサラ小さじ1+揉んだカスリメティ小さじ1+サイコロ状バター30g+クリーム大さじ1（任意）を混ぜ込む、バターが溶けるまでかき混ぜる、蓋をして火から離して5分置き、風味が落ち着くようにする、蒸したバスマティ米（またはジーララまたはナン）の上に熱々で提供し、刻んだ新鮮なコリアンダーとライムの絞り汁をかける、翌日の方が美味しい。","en":"SOAK THE BEANS: rinse 350 g rajma in cold water 2–3 times; cover with cold water by 5 cm and soak 8–12 hours (or overnight); drain and rinse; skipping the soak gives undercooked centers and gassy texture. PRESSURE-COOK THE BEANS: place soaked rajma in a pressure cooker with 1.2 L water + 1 tsp salt + 2 bay leaves + 4 black cardamom pods; pressure-cook on high heat 4–5 whistles, then reduce to low and cook 25 minutes; let the pressure release naturally; beans should be completely tender — press one between thumb and forefinger; it should mash with light pressure; (Alternative: open pot 1.5–2 h simmer.) Drain reserving 500 ml bean cooking liquid. BHUNAO — TEMPER: in a heavy kadhai or deep pan over medium heat, melt 3 tbsp ghee; when shimmering, add 1 tsp cumin seeds — they will sizzle and pop within 5 seconds; do not let them blacken. ONIONS: add 300 g very finely diced onion; cook stirring often 12–15 minutes until deeply golden brown — almost caramelized; this long, slow onion bhunao is what separates restaurant rajma from amateur attempts; do not rush. GINGER-GARLIC-CHILI: add the ginger-garlic paste and green chili; stir 1–2 minutes until the raw smell disappears. TOMATO BASE: add the pureed tomato pulp + 1 tbsp tomato paste + 1 tsp ground coriander + 1 tsp ground cumin + 0.5 tsp turmeric + 1 tsp Kashmiri chili powder + 1 tsp salt; cook stirring frequently 8–10 minutes until the oil separates from the masala on the edges of the pan — this is the visual sign the bhunao is complete and the raw tomato has cooked off. SIMMER WITH BEANS: tip in the drained rajma and 500 ml of reserved bean liquid; stir gently; bring to a simmer and cook uncovered 20–25 minutes, partially mashing some beans against the side of the pan with a spoon to thicken the gravy; the gravy should reduce and coat the beans — neither soupy nor dry, like a thick stew that holds on a spoon. FINISH AND SERVE: stir in 1 tsp garam masala + 1 tsp crushed kasuri methi + 30 g butter cubed + 1 tbsp cream (optional); stir until butter melts; cover and let rest off heat 5 minutes for flavors to settle; serve hot over steamed basmati rice (or jeera rice or naan), topped with chopped fresh coriander and a squeeze of lime; better the next day."}},{"id":166,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"ja":"キューバ","en":"Cuba","ro":"Cuba"},"name":{"ja":"ピカディージョ","en":"Picadillo","ro":"Picadillo"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛挽き肉600g（チャック、脂肪約20%）","ソフリト用オリーブオイル大さじ2","大きな黄玉ねぎ1個（~200g）、細かく角切り","大きな緑ピーマン1個（~200g）、細かく角切り","ニンニク6片、みじん切り","挽きクミン（コミーノ）小さじ1+乾燥オレガノ小さじ1+甘いスモークパプリカ（ピメントン）小さじ0.5+月桂樹の葉1枚","缶詰のクラッシュトマト400g（または新鮮なトマト4個を皮を剥いてすりおろし）+トマトペースト大さじ2","辛口白ワイン100mlまたは辛口シェリー酒50ml（キューバの伝統——生肉の臭みを飛ばす）","種なし緑オリーブ（マンサニーリャ）100g、半分に切る","金色または濃色レーズン60g、100mlの熱湯に10分浸してから水切り","冷凍グリーンピース100g、解凍","ケッパー大さじ1、水切り（任意、伝統的）","塩小さじ1.5+挽きたて黒胡椒小さじ0.5","飾り用の新鮮なフラットリーフパセリ","提供用：540mlの水に塩小さじ0.5を加えて炊いた白米360g（2カップ）+調理済み黒豆240g+熟したプランテン2本をスライスして揚げたもの+ライムのくし切り"],"en":["600 g ground beef (chuck, ~20% fat)","2 tbsp olive oil for the sofrito","1 large yellow onion (~200 g), finely diced","1 large green bell pepper (~200 g), finely diced","6 garlic cloves, minced","1 tsp ground cumin (comino) + 1 tsp dried oregano + 0.5 tsp sweet smoked paprika (pimentón) + 1 bay leaf","400 g can crushed tomatoes (or 4 fresh tomatoes peeled and grated) + 2 tbsp tomato paste","100 ml dry white wine OR 50 ml dry sherry (Cuban traditional — burns off raw-meat smell)","100 g pitted green olives (manzanilla), halved","60 g golden or dark raisins, soaked 10 min in 100 ml hot water then drained","100 g frozen green peas, thawed","1 tbsp capers, drained (optional, traditional)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","Fresh flat-leaf parsley to garnish","To serve: 360 g (2 cups) white rice cooked in 540 ml water with 0.5 tsp salt + 240 g cooked black beans + 2 ripe plantains sliced and fried + lime wedges"],"ro":["600 g carne tocată de vită (gât/cap de piept, ~20% grăsime)","2 linguri ulei de măsline pentru sofrito","1 ceapă galbenă mare (~200 g), tăiată cubulețe fine","1 ardei gras verde mare (~200 g), tăiat cubulețe fine","6 căței de usturoi, tocați mărunt","1 linguriță chimion măcinat (comino) + 1 linguriță oregano uscat + 0,5 linguriță boia dulce afumată (pimentón) + 1 foaie de dafin","400 g roșii zdrobite la conservă (sau 4 roșii proaspete decojite și răzuite) + 2 linguri pastă de roșii","100 ml vin alb sec SAU 50 ml sherry sec (tradițional cubanez — arde mirosul de carne crudă)","100 g măsline verzi fără sâmburi (manzanilla), tăiate în jumătăți","60 g stafide aurii sau negre, înmuiate 10 minute în 100 ml apă caldă, apoi scurse","100 g mazăre verde congelată, dezghețată","1 lingură capere, scurse (opțional, tradițional)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","Pătrunjel verde proaspăt cu frunza lată pentru garnitură","Pentru servire: 360 g (2 căni) orez alb fiert în 540 ml apă cu 0,5 linguriță sare + 240 g fasole neagră fiartă + 2 banane plantain coapte feliate și prăjite + felii de lămâie verde"]},"howIsMade":{"ja":"ソフリトのベース：重い5L鍋を中火にかけ、オリーブオイル大さじ2を熱する、角切り玉ねぎ200g+角切り青ピーマン200gと塩ひとつまみを加える、頻繁にかき混ぜながら8–10分、柔らかくなり金色になり始めるまで煮る——ソフリトはキューバ料理の魂、みじん切りニンニク6片を加え、香りが立つまでさらに1分煮る。スパイスを開花：クミン小さじ1、オレガノ小さじ1、スモークパプリカ小さじ0.5、月桂樹の葉1枚を熱い油と野菜のベースに加える、30秒かき混ぜ、スパイスが香りを放つまで——焦がさないこと。牛肉を焼く：火を中強火に上げる、牛挽き肉600gを1層に加え、2–3分そのままにして焼き色をつける、それから木べらで崩し、ピンクが残らず放出された液体が蒸発するまでさらに6–8分焼く。デグラッセ：辛口白ワイン100ml（またはシェリー酒50ml）を注ぎ、鍋底にこびりついた焼き色のかけらをこそげ取る、アルコール臭が消えるまで2–3分煮る。トマト+組み立て：缶詰のクラッシュトマト+トマトペースト大さじ2を混ぜる、混合物が暗くなり、表面に油が現れ始めるまで5分煮る——トマトが完全に火が通り、生の酸味がない状態。オリーブ、レーズン、調味料を加える：半分に切ったグリーンオリーブ100g+水切りしたレーズン60g+ケッパー大さじ1（使用する場合）+塩小さじ1.5+胡椒小さじ0.5を混ぜる、甘塩のコントラストがキューバ独自のシグネチャー。煮込む：火を弱火に落とし、部分的に蓋をして20–25分煮込み、数分ごとにかき混ぜる、混合物はソース状のハッシュに濃くなるべき——乾燥でもスープでもなく、スプーンに保持される、乾きすぎたら水60mlを加える。グリーンピース＆提供：最後の3分でグリーンピース100gを解凍したものを混ぜる——温めるだけで、鮮やかな緑を保つ、月桂樹の葉を取り除く、火から離し、刻んだパセリを散らす、蒸した白米の上に黒豆を添え、揚げプランテンとライムのくし切りと一緒に提供する——古典的なキューバのcomida criollaプレート。","en":"SOFRITO BASE: in a heavy 5 L pot, heat 2 tbsp olive oil over medium heat; add 200 g diced onion + 200 g diced green pepper with a pinch of salt; cook stirring often 8–10 minutes until soft and beginning to gold — the sofrito is the soul of Cuban cooking; add 6 minced garlic cloves and cook 1 minute more until fragrant. BLOOM THE SPICES: add 1 tsp cumin, 1 tsp oregano, 0.5 tsp smoked paprika and 1 bay leaf to the hot oil-and-vegetable base; stir 30 seconds until the spices release their aroma — do not burn. BROWN THE BEEF: raise heat to medium-high; add 600 g ground beef in a single layer and let it sit undisturbed 2–3 minutes to develop a crust; then break it up with a wooden spoon and brown another 6–8 minutes until no pink remains and any released liquid has evaporated. DEGLAZE: pour in 100 ml dry white wine (or 50 ml sherry) and scrape any browned bits stuck to the bottom of the pot; simmer 2–3 minutes until the alcohol smell disappears. TOMATO + BUILD: stir in the can of crushed tomatoes + 2 tbsp tomato paste; cook 5 minutes until the mixture darkens and oil starts to appear on the surface — tomato fully cooked, no raw acidity. ADD OLIVES, RAISINS & SEASON: stir in 100 g halved green olives + 60 g drained raisins + 1 tbsp capers (if using) + 1.5 tsp salt + 0.5 tsp pepper; the sweet-salty contrast is the unique Cuban signature. SIMMER: reduce heat to low, cover partially, and simmer 20–25 minutes, stirring every few minutes; the mixture should thicken into a saucy hash — neither dry nor soupy, holding together on a spoon; add 60 ml water if it gets too dry. PEAS & SERVE: in the last 3 minutes, stir in 100 g thawed peas — just to warm through, keeping them bright green; remove the bay leaf; off the heat, scatter chopped parsley; serve over steamed white rice with black beans on the side, fried plantains, and lime wedges — the classic Cuban comida criolla plate."}},{"id":167,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"モロッコ","en":"Morocco","ro":"Maroc"},"name":{"ja":"ラムのタジン","en":"Lamb Tagine","ro":"Tagine cu miel"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["骨なしラム肩肉1kg、4cm角に切る（コクのために少し脂を残す）","大きな黄玉ねぎ2個（~400g）、一つはベース用に細かく角切り、もう一つは煮込み用に厚いくし形に切る","ニンニク6片、みじん切り","新生姜4cm、すりおろし","オリーブオイル大さじ3（または油大さじ2+バター大さじ1で伝統的なコク）","挽きクミン小さじ1+挽きコリアンダー小さじ1+挽きシナモン小さじ1+挽きターメリック小さじ0.5+甘いパプリカ小さじ0.5+挽き生姜小さじ0.5+サフランの糸ひとつまみ（5–6本、大さじ2の熱湯で浸す）","ラス・エル・ハヌート小さじ1.5（モロッコのスパイスブレンド）","塩小さじ1.5+挽きたて黒胡椒小さじ0.5","トマトペースト大さじ2","熟したトマト400g（中4個）、皮を剥いてすりおろし、または400g缶詰1個","ドライアプリコット200g、半分に切る（トルコまたはカリフォルニア産——あまり甘くないもの）","種なしドライプルーンまたはレーズン60g（任意、深みのため）","熱湯または低塩チキンストック600ml","シナモンスティック1本+月桂樹の葉1枚","皮なしホールアーモンド80g（または皮付き、ロースト済み）","蜂蜜大さじ1（甘さを調整するために最後に加える）","新鮮なコリアンダー+フラットリーフパセリ+軽くローストしたゴマ大さじ1を飾りに","提供用：400gクスクスを400mlの水+バター大さじ1+塩小さじ0.5で蒸した、または温かいホブズ平パン"],"en":["1 kg boneless lamb shoulder, cut into 4 cm cubes (with some fat on for richness)","2 large yellow onions (~400 g), one finely diced for the base and one cut into thick wedges for the stew","6 garlic cloves, minced","4 cm fresh ginger, grated","3 tbsp olive oil (or 2 tbsp oil + 1 tbsp butter for traditional richness)","1 tsp ground cumin + 1 tsp ground coriander + 1 tsp ground cinnamon + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground ginger + a pinch of saffron threads (5–6 strands, bloomed in 2 tbsp hot water)","1.5 tsp ras el hanout (Moroccan spice blend)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","2 tbsp tomato paste","400 g ripe tomatoes (4 medium), peeled and grated, or 1 × 400 g can","200 g dried apricots, halved (use Turkish or California — not too sweet)","60 g pitted dried prunes or raisins (optional, for depth)","600 ml hot water or low-salt chicken stock","1 cinnamon stick + 1 bay leaf","80 g whole blanched almonds (or skin-on, toasted)","1 tbsp honey (added at the end to balance sweetness)","Fresh coriander + flat-leaf parsley + 1 tbsp lightly toasted sesame seeds to garnish","To serve: 400 g couscous steamed with 400 ml water + 1 tbsp butter + 0.5 tsp salt, OR warm khobz flatbread"],"ro":["1 kg pulpă de miel dezosată (spată), tăiată cuburi de 4 cm (cu puțină grăsime pentru bogăție)","2 cepe galbene mari (~400 g), una tăiată cubulețe fine pentru bază și una tăiată în felii groase pentru tocăniță","6 căței de usturoi, tocați mărunt","4 cm ghimbir proaspăt, ras","3 linguri ulei de măsline (sau 2 linguri ulei + 1 lingură unt pentru bogăție tradițională)","1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 1 linguriță scorțișoară măcinată + 0,5 linguriță turmeric măcinat + 0,5 linguriță boia dulce + 0,5 linguriță ghimbir măcinat + un vârf de șofran (5–6 fire, înflorit în 2 linguri apă caldă)","1,5 linguriță ras el hanout (amestec marocan de condimente)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","2 linguri pastă de roșii","400 g roșii coapte (4 medii), decojite și răzuite, sau 1 cutie × 400 g","200 g caise uscate, tăiate în jumătăți (turcești sau californiene — nu prea dulci)","60 g prune uscate fără sâmburi sau stafide (opțional, pentru profunzime)","600 ml apă fierbinte sau supă de pui cu puțină sare","1 baton de scorțișoară + 1 foaie de dafin","80 g migdale întregi blanșate (sau cu coajă, prăjite)","1 lingură miere (adăugată la final pentru a echilibra dulceața)","Coriandru proaspăt + pătrunjel cu frunza lată + 1 lingură semințe de susan ușor prăjite pentru garnitură","Pentru servire: 400 g couscous aburit cu 400 ml apă + 1 lingură unt + 0,5 linguriță sare, SAU pâine plată khobz caldă"]},"howIsMade":{"ja":"ラム肉をマリネ：大きなボウルにラム肉1kgの角切りとクミン小さじ1+コリアンダー小さじ1+シナモン小さじ1+ターメリック小さじ0.5+パプリカ小さじ0.5+生姜小さじ0.5+ラス・エル・ハヌート小さじ1.5+塩小さじ1.5+胡椒小さじ0.5+みじん切りニンニク3片+オリーブオイル大さじ1を入れる、手でスパイスを肉にもみ込む、覆って室温で30分（または冷蔵庫で最長24時間）休ませ、スパイスを浸透させる。サフランを開花：サフランの糸5–6本を熱湯大さじ2に浸し、10分置く——これで風味と色が引き出される、脇に置く。ベース作り：重底のタジンまたはダッチオーブンに残りのオイル大さじ2（使用する場合はバター大さじ1）を中火で熱する、細かく角切りした玉ねぎ200gを加え、頻繁にかき混ぜながら8–10分、柔らかく透明になるまで煮る、残りのみじん切りニンニク3片+すりおろした生姜を加え、1分かき混ぜる。ラム肉を焼く：火を中強火に上げる、玉ねぎを鍋の側面に押しやり、マリネしたラム肉を一層に加える（必要なら2回に分ける）、動かさずに片面3–4分焼き、すべての面が深く焼き色がつくまで焼く——クラストは煮込みの豊かな風味に不可欠、ラム肉が焼けたらすべて一緒に混ぜる。トマト+液体：トマトペースト大さじ2を混ぜ、1分煮て色が濃くなるまで、すりおろしトマト400g、サフラン水、シナモンスティック1本、月桂樹の葉1枚を加える、熱湯（またはストック）600mlを注ぐ——液体は肉の半分ほどまで、覆わないように、穏やかに沸騰させる。ゆっくり煮込む：火を弱火に落とし、タジンの蓋（またはダッチオーブンの密閉蓋）で覆い、1.5–2時間煮込む、30分ごとに確認し優しくかき混ぜる、フォークが簡単に入るとラム肉の準備完了、ソースが急速に減る場合は熱湯を少し加える。アプリコット+玉ねぎを加える：半分に切ったドライアプリコット200g+プルーン60g（使用する場合）+玉ねぎのくし切り200gを混ぜる、覆ってさらに25–30分煮込み、果物がふっくらして玉ねぎのくし切りが柔らかいが形を保つまで、ソースは光沢があり、スプーンの裏をコーティングするはず、蜂蜜大さじ1で仕上げ、味見し、塩を調整する。仕上げと提供：タジンが火から離れて5分休んでいる間に、ホールアーモンド80gを乾いたフライパンで中火で3–4分、黄金色になるまでローストする——よく注意して、すぐに焦げる、温かいクスクスの上にラムタジンを盛り（またはホブズと共に）、ローストアーモンド、ゴマ、新鮮なコリアンダーとパセリを散らす、パンと一緒に食べてソースを拭い取る。","en":"MARINATE THE LAMB: in a large bowl combine 1 kg lamb cubes with 1 tsp cumin + 1 tsp coriander + 1 tsp cinnamon + 0.5 tsp turmeric + 0.5 tsp paprika + 0.5 tsp ginger + 1.5 tsp ras el hanout + 1.5 tsp salt + 0.5 tsp pepper + 3 of the minced garlic cloves and 1 tbsp olive oil; rub the spices into the meat with your hands; cover and rest 30 minutes at room temperature (or up to 24 h in the fridge) so the spices penetrate. BLOOM SAFFRON: place 5–6 saffron threads in 2 tbsp hot water and let steep 10 minutes — this releases the flavour and colour; set aside. BUILD THE BASE: heat the remaining 2 tbsp oil (and 1 tbsp butter if using) in a heavy-bottomed tagine or Dutch oven over medium heat; add 200 g finely diced onion and cook stirring often 8–10 minutes until soft and translucent; add the remaining 3 minced garlic + grated ginger and stir 1 minute. SEAR THE LAMB: raise heat to medium-high; push the onions to the sides of the pot and add the marinated lamb in a single layer (work in 2 batches if needed); sear 3–4 minutes per side without moving until deeply browned on all sides — the crust is essential for the rich stew flavour; stir everything together once the lamb is browned. TOMATO + LIQUID: stir in 2 tbsp tomato paste and cook 1 minute until darkened; add the 400 g grated tomatoes, the saffron-water, 1 cinnamon stick and 1 bay leaf; pour in 600 ml hot water (or stock) — the liquid should come about halfway up the meat, not cover it; bring to a gentle simmer. SLOW COOK: reduce heat to low, cover with the tagine lid (or a tight Dutch-oven lid), and simmer 1.5–2 hours, checking every 30 minutes and stirring gently; the lamb is ready when a fork sinks in easily; add a splash of hot water if the sauce reduces too quickly. ADD APRICOTS + ONIONS: stir in 200 g halved dried apricots + 60 g prunes (if using) + the 200 g onion wedges; cover and simmer 25–30 minutes more until the fruit is plump and the onion wedges are tender but still holding shape; the sauce should be glossy, coating the back of a spoon; finish with 1 tbsp honey, taste, adjust salt. FINISH AND SERVE: while the tagine rests off the heat for 5 minutes, toast 80 g whole almonds in a dry pan over medium heat 3–4 minutes until golden — watch carefully, they burn fast; spoon the lamb tagine over warm couscous (or serve with khobz), top with toasted almonds, sesame seeds, and a scatter of fresh coriander and parsley; eat with bread to mop up the sauce."}},{"id":168,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"イギリス","en":"United Kingdom","ro":"Marea Britanie"},"name":{"ja":"シェパーズパイ","en":"Shepherd's Pie","ro":"Plăcintă a ciobanului"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["ラム挽肉600g（~15%脂肪——通常の牛挽肉より赤身だが、潤いに十分な脂肪を含む）","大きな玉ねぎ1個（~200g）、細かく角切り","中サイズの人参2本（~200g）、0.5cmに細かく角切り（小さなさいの目——具材の中で消えるように）","ニンニク4片、みじん切り","トマトペースト大さじ1","ウスターソース大さじ1（秘密の奥深さ——交渉不可）","ドライタイム小さじ1（または生の2枝）","ドライローズマリー小さじ1、細かく刻む","薄力粉大さじ2（グレービーを濃くするため）","熱いラムまたはビーフストック300ml（自家製または低塩）","冷凍グリーンピース150g","中性油大さじ1","塩小さじ1+挽きたて黒胡椒小さじ0.5を具材用","マッシュトッピング用：粉質ジャガイモ1kg（Maris Piper、King Edward、またはYukon Gold）、皮をむいて4cmに切る","無塩バター60g+温かい全乳100ml+大きな卵黄2個（卵黄が象徴的な金色のカリッとしたトップを生み出す）+おろしたエイジドチェダー30g（任意だが伝統的）","白胡椒小さじ0.5+塩小さじ0.5をマッシュ用"],"en":["600 g minced lamb (~15% fat — leaner than usual ground beef but with enough fat for moisture)","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), finely diced 0.5 cm (small dice — they should disappear into the filling)","4 garlic cloves, minced","1 tbsp tomato paste","1 tbsp Worcestershire sauce (the secret depth — non-negotiable)","1 tsp dried thyme (or 2 sprigs fresh)","1 tsp dried rosemary, finely chopped","2 tbsp plain flour (to thicken the gravy)","300 ml hot lamb or beef stock (homemade or low-salt)","150 g frozen peas","1 tbsp neutral oil","1 tsp salt + 0.5 tsp freshly ground black pepper for the filling","For the mash topping: 1 kg floury potatoes (Maris Piper, King Edward, or Yukon Gold), peeled and cut into 4 cm chunks","60 g unsalted butter + 100 ml warm whole milk + 2 large egg yolks (the yolks give the iconic golden crisp top) + 30 g grated mature cheddar (optional but traditional)","0.5 tsp white pepper + 0.5 tsp salt for the mash"],"ro":["600 g carne tocată de miel (~15% grăsime — mai slabă decât vita tocată obișnuită, dar cu suficientă grăsime pentru umiditate)","1 ceapă mare (~200 g), tăiată cubulețe fine","2 morcovi medii (~200 g), tăiați cubulețe fine de 0,5 cm (cubulețe mici — trebuie să dispară în umplutură)","4 căței de usturoi, tocați","1 lingură pastă de roșii","1 lingură sos Worcestershire (profunzimea secretă — nenegociabil)","1 linguriță cimbru uscat (sau 2 crenguțe proaspete)","1 linguriță rozmarin uscat, tocat fin","2 linguri făină albă (pentru a îngroșa sosul)","300 ml supă fierbinte de miel sau vită (de casă sau cu sare redusă)","150 g mazăre congelată","1 lingură ulei neutru","1 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat pentru umplutură","Pentru piureul de deasupra: 1 kg cartofi făinoși (Maris Piper, King Edward sau Yukon Gold), curățați și tăiați bucăți de 4 cm","60 g unt nesărat + 100 ml lapte integral cald + 2 gălbenușuri mari (gălbenușurile dau crusta aurie iconică) + 30 g cheddar maturat ras (opțional dar tradițional)","0,5 linguriță piper alb + 0,5 linguriță sare pentru piure"]},"howIsMade":{"ja":"ジャガイモを茹でる：皮をむいて角切りにしたジャガイモ1kgを大きな鍋の冷たい塩水（2Lあたり大さじ1の塩）に入れる、沸騰させ、一定の弱火に下げ、ナイフが抵抗なくスライドするまで15–18分茹でる、水を切り、火から下ろして鍋に戻し2分間蒸気を飛ばす——濡れたジャガイモは濡れたマッシュを作る、マッシュを作る：乾いたジャガイモをライサー（ふわふわのマッシュに最適）に通すか、手動マッシャーで潰す。まだ熱いうちにバター60gを混ぜ込み、次に温かい牛乳100mlを3回に分けて加え、それぞれの間に混ぜる、火から下ろし、卵黄2個、白胡椒小さじ0.5、塩小さじ0.5を混ぜ込む、マッシュは光沢があり、滑らかで、リッジを保てる十分な硬さでなければならない——緩すぎるとトッピングが沈む、アルミホイルで覆って保温する。野菜をスエットする：大きな重いスキレットに中火で油大さじ1を熱する、角切り玉ねぎ200g+角切り人参200gと塩ひとつまみを加える、頻繁にかき混ぜながら8–10分、非常に柔らかく人参が歯ごたえを失うまで煮る——肉と混ぜたらそれ以上柔らかくならない、みじん切りニンニク4片+タイム+ローズマリーを加え、さらに1分煮る。ラム肉を焼く：火を中強火に上げる、ラム挽肉600gを加え、木べらで細かく崩す、ラム肉がもうピンクでなくなりAND放出された脂肪がフライパンの底で小さな破片をカリッとさせ始めるまで8–10分煮る——このMaillard褐色化がグレービーの基礎、大さじ1を超える溜まった脂肪をすくい取る（ラムは多く出す——多すぎるとパイが脂っぽくなる）。グレービーを作る：トマトペースト大さじ1をラム肉に混ぜ、1分煮て色が濃くなるまで、小麦粉大さじ2を上に振りかけ、生の味を煮出すために1–2分かき混ぜる、熱いストック300ml+ウスターソース大さじ1+塩小さじ1+胡椒小さじ0.5を注ぎ、フライパンの底をこそげて焦げ目の付いた断片を持ち上げる、煮込み+グリーンピース：火を弱火に下げ、蓋なしで時々かき混ぜながら15分煮込み、グレービーが肉を覆う濃く光沢のあるコンシステンシーに濃くなるまで——水っぽくてはいけない、さもないとマッシュが沈む。冷凍グリーンピース150gを混ぜ込む（オーブンで温まる）、味見をして調味料を調整する、組み立て：オーブンを200 °Cに予熱する、ラムフィリングを23 × 30cmの耐熱皿（約2L容量）に移す。マッシュをドロップ状で上にのせ、次にスパチュラで端まで丁寧に広げて密封する、フォークの歯を表面に長い線で引く——これらのリッジはオーブンで美しくカリッとなる、使用する場合、すりおろしチェダー30gを上に散らす、焼いて休ませる：天板の上に皿を置く（沸騰する滴を捕らえる）。中段の棚で25–30分、上面が深い金色になり、リッジがカリッとし、グレービーが端で明確に泡立つまで焼く、提供前に10分休ませる——フィリングが固まり、切り分けがきれいになる、皿から直接、緑のサラダまたはバターを塗ったキャベツを添えて提供する、翌日にさらに良く、熱々になるまで再加熱する。","en":"1. BOIL THE POTATOES: place 1 kg peeled and cubed potatoes in a large pot of cold salted water (1 tbsp salt per 2 L), bring to a boil, then reduce to a steady simmer and cook 15–18 minutes until a knife slides through with no resistance; drain and return to the pot off the heat for 2 minutes to steam off, since wet potatoes make wet mash. 2. MAKE THE MASH: pass the dry potatoes through a ricer (best for fluffy mash) or mash with a hand masher, then beat in 60 g butter while still hot followed by 100 ml warm milk added in 3 stages, beating between each, and off the heat beat in 2 yolks, 0.5 tsp white pepper and 0.5 tsp salt until the mash is glossy, smooth and stiff enough to hold ridges (if it's too loose the topping will sink); cover with foil to keep warm. 3. SWEAT THE VEGETABLES: heat 1 tbsp oil in a large heavy skillet over medium heat, add 200 g diced onion and 200 g diced carrot with a pinch of salt, and cook, stirring often, 8–10 minutes until very soft and the carrots have lost their crunch (they will not soften further once mixed with meat), then stir in 4 minced garlic cloves, thyme and rosemary and cook 1 minute more. 4. BROWN THE LAMB: raise the heat to medium-high, add 600 g minced lamb and break it apart with a wooden spoon, then cook 8–10 minutes until the lamb is no longer pink and the released fat has begun to crisp small bits at the bottom of the pan (this Maillard browning is the foundation of the gravy), and spoon off any pooled fat over 1 tbsp, since lamb sheds a lot and too much makes the pie greasy. 5. BUILD THE GRAVY: stir 1 tbsp tomato paste into the lamb and cook 1 minute until darkened, sprinkle 2 tbsp flour over and stir 1–2 minutes to cook the raw taste out, then pour in 300 ml hot stock, 1 tbsp Worcestershire sauce, 1 tsp salt and 0.5 tsp pepper, scraping the bottom of the pan to lift the browned bits. 6. SIMMER + PEAS: reduce heat to low and simmer uncovered 15 minutes, stirring occasionally, until the gravy has thickened to a thick, glossy consistency that coats the meat (it should not be runny, or the mash will sink), then stir in 150 g frozen peas (they will warm through in the oven) and taste and adjust seasoning. 7. ASSEMBLE: preheat the oven to 200 °C and transfer the lamb filling to a 23 × 30 cm baking dish (about 2 L capacity), spoon the mash on top in dollops and spread carefully with a spatula sealing all the way to the edges, then drag the tines of a fork in long lines across the surface (these ridges crisp up beautifully in the oven) and scatter 30 g grated cheddar over the top if using. 8. BAKE & REST: place the dish on a baking sheet to catch any bubbling drips and bake on the middle rack 25–30 minutes until the top is deeply golden, the ridges are crisp, and the gravy is visibly bubbling around the edges, then rest 10 minutes before serving so the filling sets and slicing is cleaner, and serve straight from the dish with a green salad or buttered cabbage on the side (even better the next day, reheated until piping hot)."}},{"id":169,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"中国","en":"China","ro":"China"},"name":{"ja":"麻婆豆腐","en":"Mapo Tofu","ro":"Mapo Tofu"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["柔らかい（絹ごしまたは中程度の柔らかさ）豆腐600g、2cmの角切り——食感が料理の一部、固い豆腐を使わない","豚ひき肉200g（~20%脂肪——少量で旨味を加え、支配しない）","中性油大さじ3（菜種油またはピーナッツ油）","ピーシエン豆板醤大さじ3（四川そら豆唐辛子ペースト）——料理の魂、省略・代用不可","豆豉大さじ1（発酵黒豆）、すすいで粗く刻む","四川辣豆板醤（la doubanjiang）小さじ2または韓国コチュジャン小さじ1を代用品として","ニンニク4片、みじん切り","新鮮なショウガ4cm、皮をむいてすりおろし","青ねぎ6本：白い部分は調理用にみじん切り+緑色の先端は飾り用に斜め切り（別々に保管）","濃口醤油（老抽）大さじ1.5","グラニュー糖小さじ1","熱い無塩鶏スープまたは水300ml","四川山椒（花椒）小さじ2、乾いた鍋で60秒ローストし、すり鉢で砕く","コーンスターチ（cornflour）大さじ1.5を冷水大さじ3と混ぜて最終の水溶き","ラー油（la yu）小さじ2で仕上げ","焙煎ごま油小さじ1を最後の一滴に","添え物：ジャスミン米または短粒米の炊いたもの320g（乾燥1.6カップ）"],"en":["600 g soft (silken or medium-soft) tofu, cut into 2 cm cubes — the texture is part of the dish, do not use firm tofu","200 g ground pork (~20% fat — the small amount adds umami without dominating)","3 tbsp neutral oil (rapeseed or peanut)","3 tbsp Pixian doubanjiang (Sichuan broad-bean chili paste) — the SOUL of the dish, do not skip or substitute","1 tbsp douchi (fermented black beans), rinsed and roughly chopped","2 tsp Sichuan chili bean paste (la doubanjiang) OR 1 tsp Korean gochujang as substitute","4 garlic cloves, finely minced","4 cm fresh ginger, peeled and grated","6 spring onions: the white parts finely chopped for cooking + the green tops cut diagonally for garnish (keep separate)","1.5 tbsp dark soy sauce (laochou)","1 tsp granulated sugar","300 ml hot unsalted chicken stock or water","2 tsp Sichuan peppercorns (huajiao), toasted in a dry pan 60 sec and crushed in a mortar","1.5 tbsp cornstarch (cornflour) mixed with 3 tbsp cold water for the final slurry","2 tsp chili oil (la yu) for finishing","1 tsp toasted sesame oil for the last drizzle","To serve: 320 g (1.6 cups dry) cooked jasmine rice or short-grain rice"],"ro":["600 g tofu moale (mătăsos sau mediu-moale), tăiat în cuburi de 2 cm — textura face parte din preparat, nu folosi tofu ferm","200 g carne tocată de porc (~20% grăsime — cantitatea mică adaugă umami fără a domina)","3 linguri ulei neutru (rapiță sau arahide)","3 linguri doubanjiang Pixian (pastă de fasole-chili din Sichuan) — SUFLETUL preparatului, nu omite și nu substitui","1 lingură douchi (fasole neagră fermentată), clătită și tocată grosier","2 lingurițe pastă de fasole-chili Sichuan (la doubanjiang) SAU 1 linguriță gochujang coreean ca substitut","4 căței de usturoi, tocați fin","4 cm ghimbir proaspăt, curățat și ras","6 cepe verzi: părțile albe tocate fin pentru gătit + vârfurile verzi tăiate oblic pentru ornament (păstrează separat)","1,5 linguri sos de soia închis (laochou)","1 linguriță zahăr granulat","300 ml supă fierbinte de pui nesărată sau apă","2 lingurițe boabe de piper sichuan (huajiao), prăjite într-o tigaie uscată 60 sec și zdrobite în mojar","1,5 linguri amidon de porumb (cornflour) amestecat cu 3 linguri apă rece pentru slurry-ul final","2 lingurițe ulei de chili (la yu) pentru finisare","1 linguriță ulei de susan prăjit pentru ultima stropire","Pentru servire: 320 g (1,6 căni uscat) orez jasmine fiert sau orez cu bob scurt"]},"howIsMade":{"ja":"豆腐を準備する：水と塩小さじ1を入れた小鍋を弱火でゆっくり沸騰させる（沸騰させない）、2cmの豆腐キューブを慎重に滑り込ませ、2分間温める——これは表面を引き締め、ソースの中で形を保つようにする、優しく水切りし、火から下ろした暖かい鍋の脇に置く。四川山椒をローストする：乾いたフライパンに中火で四川山椒小さじ2を60秒ローストし、強い香りが立つまで、すり鉢に移し、粗く砕く、脇に置く。豚肉を炒める：中華鍋または重いスキレットに中強火で中性油大さじ2を熱する、豚ひき肉200gを加え、ヘラで崩す、4–5分間、豚肉がもうピンクでなくなり、小さな破片がカリッと黄金色になるまで炒める——カリカリの豚肉と柔らかい豆腐の食感の違いが不可欠。豆板醤を花開かせる：豚肉をフライパンの脇に押しやり、空いたスペースに油大さじ1を追加する、油に豆板醤大さじ3を加え、60–90秒、油が深紅色になるまで混ぜる——この油炒めはペーストの色と旨味を引き出す、豚肉と混ぜる、刻んだ豆豉+みじん切りニンニク+おろしショウガ+la doubanjiang小さじ2（またはコチュジャン）を加え、60秒、強い香りが立つまで炒める。液体：熱いストック300ml+濃口醤油大さじ1.5+砂糖小さじ1を注ぐ、煮立たせる。豆腐を加える：温かい豆腐キューブを煮立ったソースに優しく滑り込ませる、かき混ぜない——お玉の裏で押し沈め、その後フライパンを優しく振って落ち着かせる、4–5分煮込み、時々豆腐の上部にソースをかけ、キューブが壊れずに風味を吸収するようにする。とろみをつける：コーンスターチの水溶きをもう一度かき混ぜ、半分をソースに注ぎ、フライパンを振って30秒煮込ませる、ソースは光沢を帯び、豆腐をコーティングし始める、まだ薄ければ、残りの水溶きを加える、完成したソースは豆腐に軽く絡みつき、スープ状ではないはず。仕上げて提供する：火から下ろし、ラー油小さじ2+焙煎ごま油小さじ1を表面に垂らし、緑色のねぎの先端+砕いた四川山椒を散らす、かき混ぜない——山椒は希薄化されずに舌に当たり、麻（しびれ）の感覚を生む必要がある、熱いジャスミン米とすぐに提供する、一口ごとに：米+豆腐+ソース+山椒=完全な麻辣体験。","en":"PREP THE TOFU: bring a small pot of water with 1 tsp salt to a gentle simmer (not boil); slip the 2 cm tofu cubes in carefully and let them warm 2 minutes — this firms the surface so they hold their shape in the sauce; drain gently and set aside in the warm pot off the heat. TOAST SICHUAN PEPPERCORNS: in a dry pan over medium heat, toast 2 tsp Sichuan peppercorns 60 seconds until intensely fragrant; tip into a mortar and crush coarsely; set aside. RENDER THE PORK: heat 2 tbsp neutral oil in a wok or heavy skillet over medium-high heat; add 200 g ground pork and break it apart with a spatula; stir-fry 4–5 minutes until the pork is no longer pink and the small bits are crispy and golden brown — the texture difference between crisp pork and soft tofu is essential. BLOOM THE DOUBANJIANG: push the pork to the side of the pan and add 1 tbsp more oil to the empty space; add 3 tbsp doubanjiang to the oil and stir 60–90 seconds until the oil turns deep red — this oil-frying releases the colour and umami of the paste; stir into the pork; add chopped douchi + minced garlic + grated ginger + 2 tsp la doubanjiang (or gochujang) and stir-fry 60 seconds until intensely aromatic. LIQUID: pour in 300 ml hot stock + 1.5 tbsp dark soy sauce + 1 tsp sugar; bring to a simmer. ADD THE TOFU: slide the warm tofu cubes gently into the simmering sauce; do NOT stir — use the back of a ladle to push them under, then shake the pan gently to settle; simmer 4–5 minutes, basting the tops of the tofu with sauce occasionally, so the cubes absorb flavour without breaking. THICKEN: stir the cornstarch slurry one more time and pour HALF into the sauce, then shake the pan and let it simmer 30 seconds; the sauce will turn glossy and start to coat the tofu; if still thin, add the rest of the slurry; the finished sauce should cling lightly to the tofu, not be soupy. FINISH AND SERVE: off the heat, drizzle 2 tsp chili oil + 1 tsp toasted sesame oil over the surface and scatter the green spring-onion tops + crushed Sichuan peppercorns; do NOT stir — the peppercorns must hit your tongue undiluted for the ma (numbing) sensation; serve immediately with hot jasmine rice; each bite: rice + tofu + sauce + peppercorn = the full ma-la experience."}},{"id":170,"servings":2,"tipType":"veg","pairingsType":"veg","origin":{"ja":"トルコ","en":"Turkey","ro":"Turcia"},"name":{"ja":"メネメン","en":"Menemen","ro":"Menemen"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ja":["大きな卵6個、室温","トルコまたはエクストラバージンオリーブオイル大さじ3","シブリビベル（細長い緑色のトルコ唐辛子、軽い辛さ）2本、または代用品として緑ピーマン1個＋ハラペーニョ1個（合計約150g）、種を除き細かくみじん切り","熟したトマト4個（約500g）、皮をむき、箱型おろし器で粗くおろす（皮は手に残り、果肉だけがおろし器を通過する——これがトルコの技法）","トマトペースト（salça）大さじ1——任意、赤色を深める","プル ビベル（トルコの赤唐辛子フレーク、アレッポまたはマラシュ風）小さじ1——刺激的でない温かみを加える","乾燥オレガノ小さじ0.5","塩小さじ0.5＋挽きたて黒コショウ","ベヤズ ペイニル（フェタタイプ）30g、ほぐした（任意、エーゲ海地方の追加物）","イタリアンパセリ少々、細かく刻み、仕上げ用","チャイブまたは青ねぎの緑色部分の小束、細かく刻む（任意）","添え物：新鮮なエクメク（カントリーブレッド）の厚切り4枚、または2個のシミト（トルコのゴマベーグル）、濃く淹れたトルコの紅茶（çay）","地域論争についての注：このバージョンは玉ねぎなし（イスタンブール風）；エーゲ海風を作る場合は、小玉ねぎ1個を細かくみじん切りにし、唐辛子の前に4分炒める"],"en":["6 large eggs, at room temperature","3 tbsp Turkish or extra-virgin olive oil","2 sivri biber (long green Turkish peppers, mildly hot) OR 1 green bell pepper + 1 jalapeño as substitute (~150 g total), seeds removed and finely diced","4 ripe tomatoes (~500 g), peeled and roughly grated on a box grater (the skin holds back, only the pulp grates through — this is the Turkish technique)","1 tbsp tomato paste (salça) — optional, deepens the red","1 tsp pul biber (Turkish red pepper flakes, Aleppo or Maraş-style) — adds warmth without harsh heat","0.5 tsp dried oregano","0.5 tsp salt + freshly ground black pepper","30 g feta-style beyaz peynir, crumbled (optional, regional Aegean addition)","1 small handful flat-leaf parsley, finely chopped, to finish","1 small bunch chives or spring onion green, finely chopped (optional)","To serve: 4 thick slices of fresh ekmek country bread OR 2 simit (Turkish sesame bagels), Turkish black tea (çay) brewed strong","Note on regional debate: this version is WITHOUT onion (Istanbul-style); if making the Aegean-style, add 1 small onion finely diced and cook 4 min before the peppers"],"ro":["6 ouă mari, la temperatura camerei","3 linguri ulei de măsline turcesc sau extravirgin","2 sivri biber (ardei lungi verzi turcești, ușor iuți) SAU 1 ardei gras verde + 1 jalapeño ca substitut (~150 g total), fără semințe și tocați fin","4 roșii coapte (~500 g), opărite și răzuite grosier pe răzătoarea cu găuri mari (coaja rămâne în mână, doar pulpa trece prin răzătoare — aceasta este tehnica turcească)","1 lingură pastă de roșii (salça) — opțional, adâncește roșul","1 linguriță pul biber (fulgi de ardei roșu turcesc, stil Aleppo sau Maraș) — adaugă căldură fără iuțeală agresivă","0,5 linguriță oregano uscat","0,5 linguriță sare + piper negru proaspăt măcinat","30 g beyaz peynir tip feta, fărâmițat (opțional, adaos regional egeean)","1 mână mică de pătrunjel cu frunza lată, tocat fin, pentru finisare","1 legătură mică de arpagic sau partea verde a cepei verzi, tocată fin (opțional)","Pentru servire: 4 felii groase de ekmek proaspăt (pâine de țară) SAU 2 simit (covrigi turcești cu susan), ceai negru turcesc (çay) preparat tare","Notă despre dezbaterea regională: această versiune este FĂRĂ ceapă (stil Istanbul); dacă faci versiunea egeeană, adaugă 1 ceapă mică tocată fin și gătește 4 minute înainte de ardei"]},"howIsMade":{"ja":"トマトを皮むきしてすりおろす：4個の熟したトマトの底に浅い十字の切り込みを入れる、沸騰水に30秒落とし、その後氷水に移す、皮は簡単に剥がれる、各トマトを水平に半分に切り、ボウルの上に置いた箱型おろし器の粗い面に切った面を擦り付ける——果肉がおろし器を通過し、空の皮が手に残る、このトルコの技法は皮の破片のない、果肉のある、ジューシーなトマトベースを生む。唐辛子を調理する：24cmの重い鍋（鋳鉄または陶器のサハンが伝統的）に中火で3大さじのオリーブオイルを熱する、150gの細かくみじん切りした緑唐辛子を加え、頻繁にかき混ぜながら5–6分炒め、柔らかくなり端が少し焼けるが、まだ鮮やかな緑色のままになるまで——茶色にしない。トマトペーストを加える：1大さじのトマトペーストを唐辛子に混ぜて30秒調理する——サルチャは色と旨味を深める、（ペーストを使わない場合はこのステップをスキップ、）。おろしトマトを加える：おろしたトマトの果肉+プルビベル小さじ1+オレガノ小さじ0.5+塩小さじ0.5と寛大な黒コショウのひねりを注ぐ、煮立たせて6–8分調理し、時々かき混ぜ、トマトが半分に減少しジャム状になるまで——ヘラの底面はソースを通る明確な線を引くべきで、すぐには埋まらない。卵を準備する：トマトが煮えている間に、6個の卵を一度に1個ずつボウルに割る——溶かない、卵は丸ごとまたはほぼ無傷で鍋に入れ、最初は黄身が無傷の状態。卵を加える：トマトがジャム状になったら、火を中弱火に下げる、卵を鍋に優しく滑り込ませ、表面に間隔を空ける、底で凝固するように30秒触らずに置く。軽くスクランブルする：木のスプーンで、ゆっくりと8の字の動きでトマトを通して卵を優しく押す——激しくかき混ぜない、白身はリボン状に固まり、黄身は壊れて金色の渦でソースを通って筋を引くはず、90秒–2分のみ調理する——メネメンは光沢があり、ほとんど固まっていない状態であるべきで、スクランブルエッグのように乾いていないこと、まだ少し湿っているうちに火から下ろす——熱い鍋で調理を続ける。鍋から提供する：30gの砕いたフェタ+刻んだパセリ（使用する場合はチャイブも）を散らす、鍋を直接テーブルに持ってくる——メネメンは常に鍋から食べ、パンをちぎってソースに浸す、濃いトルコの紅茶と一緒に提供する、調理後5分以内に、暖かく光沢があるうちに食べるのが最高。","en":"PEEL AND GRATE THE TOMATOES: cut a shallow cross in the bottom of each of 4 ripe tomatoes; drop into boiling water 30 seconds, then transfer to ice water; the skins peel off easily; halve each tomato horizontally and rub the cut sides against the coarse side of a box grater placed over a bowl — the flesh grates through and the empty skin remains in your hand; this Turkish technique gives a pulpy, juicy tomato base with no skin pieces. COOK THE PEPPERS: heat 3 tbsp olive oil in a heavy 24 cm skillet (cast iron or earthenware sahan is traditional) over medium heat; add 150 g finely diced green peppers and cook stirring often 5–6 minutes until softened and slightly blistered at the edges but still bright green — do not let them brown. ADD TOMATO PASTE: stir 1 tbsp tomato paste into the peppers and cook 30 seconds — the salça deepens the colour and umami; (Skip this step if not using paste.). ADD GRATED TOMATOES: pour in the grated tomato pulp + 1 tsp pul biber + 0.5 tsp oregano + 0.5 tsp salt and a generous twist of black pepper; bring to a simmer and cook 6–8 minutes, stirring occasionally, until the tomato has reduced by half and looks jammy — the bottom of the spatula should drag a clear line through the sauce that does not fill in immediately. PREP THE EGGS: while the tomatoes cook, crack 6 eggs into a bowl one at a time — DO NOT beat them; the eggs go into the pan whole or barely broken, with yolks intact at first. ADD THE EGGS: when the tomato is jammy, lower the heat to medium-low; slip the eggs gently into the pan, spaced around the surface; let them sit 30 seconds undisturbed to set on the bottom. SCRAMBLE LIGHTLY: with a wooden spoon, push the eggs gently through the tomato in slow figure-eight motions — DO NOT vigorously stir; the whites should set into ribbons and the yolks should break and streak through the sauce in golden swirls; cook 90 seconds–2 minutes only — the menemen should remain glossy and barely-set, NOT scrambled-egg-dry; take off the heat while still slightly wet — it continues cooking in the hot pan. SERVE FROM THE PAN: scatter 30 g crumbled feta + chopped parsley (and chives if using); bring the pan straight to the table — menemen is always eaten from the pan with bread torn and dipped into the sauce; serve with strong Turkish black tea; best eaten within 5 minutes of cooking, while warm and glossy."}},{"id":171,"servings":4,"tipType":"meat","pairingsType":"soup","origin":{"ja":"ロシア","en":"Russia","ro":"Rusia"},"name":{"ja":"ソリャンカ","en":"Solyanka","ro":"Solyanka"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["骨付き牛のブリスケットまたはすね肉500g（ブロス用）","ブロス用に冷水2L+玉ねぎ1個+人参1本+月桂樹の葉2枚+黒コショウの粒5粒+塩小さじ1（ストック用）","燻製キルバサまたはクラコフスカヤ200g、5mm厚にスライス","茹でハム150g、1cm角に切る（または茹でた舌、伝統的）","サラミまたはハンティングソーセージ100g、薄くスライス","大きなピクルスきゅうり2本（約250g、半酸または完全酸）、細い棒状に切る；ピクルスのブライン100mlを取っておく","大玉ねぎ1個（約200g）、みじん切り","トマトペースト大さじ1","おろしトマト200g（または200g缶詰1個、水切り）","ソフリット用にバター大さじ2または融かした牛脂30g","種抜き黒オリーブ80g（カラマタ風）+種抜きグリーンオリーブ80g","ケッパー大さじ2、水切り","レモン1個、薄い半月切り","月桂樹の葉1枚+挽いた黒コショウ小さじ0.5+パプリカ小さじ1（任意、色付け用）","新鮮なディルの小束、みじん切り","提供用スメタナ（サワークリーム）200g","添え物：新鮮な濃いライ麦パンの厚切り4枚、任意で西洋わさび（khren）大さじ1"],"en":["500 g beef brisket or shin on the bone (for the broth)","2 L cold water for the broth + 1 onion + 1 carrot + 2 bay leaves + 5 black peppercorns + 1 tsp salt for the stock","200 g smoked kielbasa or krakovskaya, sliced 5 mm thick","150 g cooked ham, cut into 1 cm cubes (or boiled tongue, traditional)","100 g salami or hunting sausage, sliced thin","2 large pickled cucumbers (~250 g, half-sour or fully sour), cut into thin matchsticks; reserve 100 ml of the pickle brine","1 large onion (~200 g), finely diced","1 tbsp tomato paste","200 g grated tomatoes (or 1 × 200 g canned, drained)","2 tbsp butter or 30 g rendered beef fat for the soffritto","80 g pitted black olives (kalamata-style) + 80 g pitted green olives","2 tbsp capers, drained","1 lemon, sliced into thin half-moons","1 bay leaf + 0.5 tsp ground black pepper + 1 tsp paprika (optional, for color)","A small bunch fresh dill, finely chopped","200 g smetana (sour cream) for serving","To serve: 4 thick slices of fresh dark rye bread, optional 1 tbsp horseradish (khren)"],"ro":["500 g piept de vită sau rasol cu os (pentru supă)","2 L apă rece pentru supă + 1 ceapă + 1 morcov + 2 foi de dafin + 5 boabe de piper negru + 1 linguriță sare pentru bulion","200 g kielbasa afumată sau cracovskaya, tăiată felii de 5 mm","150 g șuncă fiartă, tăiată cuburi de 1 cm (sau limbă fiartă, tradițional)","100 g salam sau cârnați de vânătoare, tăiat felii subțiri","2 castraveți murați mari (~250 g, semi-acri sau acri complet), tăiați fâșii subțiri; păstrează 100 ml din zeama de murături","1 ceapă mare (~200 g), tocată fin","1 lingură pastă de roșii","200 g roșii răzuite (sau 1 × 200 g din conservă, scurse)","2 linguri unt sau 30 g grăsime de vită topită pentru sotă","80 g măsline negre fără sâmburi (gen kalamata) + 80 g măsline verzi fără sâmburi","2 linguri capere, scurse","1 lămâie, tăiată felii subțiri în formă de semilună","1 foaie de dafin + 0,5 linguriță piper negru măcinat + 1 linguriță boia (opțional, pentru culoare)","O legăturică mică de mărar proaspăt, tocat fin","200 g smetana (smântână) pentru servire","Pentru servire: 4 felii groase de pâine de secară neagră proaspătă, opțional 1 lingură hrean (khren)"]},"howIsMade":{"ja":"ブロス：500gの牛のブリスケットを大きな鍋に入れ、2Lの冷水を加える、沸騰させ、最初の5分間徹底的にアクを取る——これにより澄んだブロスが得られる、1個の丸ごと4等分した玉ねぎ+1本の丸ごと人参+月桂樹の葉2枚+胡椒5粒+塩小さじ1を加える、穏やかな煮込みに減らし、蓋をして1.5時間煮込み、肉が完全に柔らかくなるまで。濾して裂く：牛肉を取り出し、少し冷ます、ブロスを細かい篩を通して清潔な鍋に濾す——約1.5Lの澄んだ風味豊かなブロスができるはず、牛肉を繊維に対して垂直に一口大の細切りにし、固い筋を取り除く。ソフリット：広いスキレットで中火でバター大さじ2を溶かす、みじん切りの玉ねぎ200gを加え、6–8分間炒め、柔らかく透明になるまで、トマトペースト大さじ1を混ぜ込み、1分間調理し色が濃くなるまで、すりおろしたトマト200gを加え、4–5分間調理し、混合物が煮詰まり、油が表面に現れ始めるまで。ピクルスを加える：きゅうりの細切りをソフリットに混ぜ、3–4分間調理する、ピクルスは温まるべきで、過度に柔らかくなってはいけない——食感のコントラストのためにいくらかのクランチを保つ必要がある。ソーセージを揚げる：別の乾いた中火のフライパンで、燻製キルバサのスライス、ハムのキューブ、サラミのスライスを4–5分間揚げ、端が軽く焼け、脂肪が出てくるまで、このステップは譲れない——肉をブロスに加える前に焼くことが、ソリャンカに深い燻製の特徴を与える。スープを組み立てる：ソフリットを濾したブロスに注ぎ、焼いたソーセージ、ハム、サラミ、裂いた牛肉を混ぜる、取っておいたピクルスのブライン100ml+月桂樹の葉1枚+挽いたコショウ小さじ0.5+パプリカ小さじ1を加える、穏やかな煮込みにする。煮込む：弱火で15–20分間、部分的に蓋をして、風味が融合するように煮込む、オリーブ+ケッパーは最後の5分間にのみ加える——温まるべきだが形を保つ必要がある、味見をして塩を調整する——塩味のほとんどはピクルス、ケッパー、オリーブ、ブラインから来るので、慎重に進める。提供する：熱いソリャンカを深い椀に盛る、各椀に薄いレモンスライス1枚（皮付きで丸ごと）、寛大なスプーン1杯のスメタナ、刻んだディルの散らしを加える、黒コショウは好みで、新鮮な濃いライ麦パンの厚切りを脇に添えてすぐに提供する——ソリャンカはメインコースで、前菜のスープではない、ロシアの伝統では、これは祝賀後の古典的な回復料理である。","en":"THE BROTH: place 500 g beef brisket in a large pot with 2 L cold water; bring to a boil and skim the foam thoroughly for the first 5 minutes — this gives a clear broth; add 1 whole quartered onion + 1 whole carrot + 2 bay leaves + 5 peppercorns + 1 tsp salt; reduce to a gentle simmer and cook covered 1.5 hours until the meat is fully tender. STRAIN AND SHRED: lift the beef out and let it cool slightly; strain the broth through a fine sieve back into a clean pot — you should have about 1.5 L of clear, savoury broth; cut the beef across the grain into bite-sized strips, discarding any tough sinew. SOFFRITTO: in a wide skillet, melt 2 tbsp butter over medium heat; add 200 g finely diced onion and sauté 6–8 minutes until soft and translucent; stir in 1 tbsp tomato paste and cook 1 minute until darkened; add the 200 g grated tomatoes and cook 4–5 minutes until the mixture has reduced and the oil starts to appear on the surface. ADD PICKLES: stir the cucumber matchsticks into the soffritto and cook 3–4 minutes; the pickles should be warmed through, not over-softened — they need to keep some crunch for texture contrast. FRY THE SAUSAGES: in a separate dry pan over medium heat, fry the smoked kielbasa slices, ham cubes, and salami slices 4–5 minutes until lightly browned at the edges and the fat has rendered; this step is non-negotiable — searing the meats before adding them to the broth is what gives solyanka its deep, smoky character. ASSEMBLE THE SOUP: pour the soffritto into the strained broth and stir in the seared sausages, ham, salami, and shredded beef; add the reserved 100 ml pickle brine + 1 bay leaf + 0.5 tsp ground pepper + 1 tsp paprika; bring to a gentle simmer. SIMMER: cook over low heat 15–20 minutes, partially covered, for the flavours to marry; add the olives + capers in the last 5 minutes only — they should warm through but keep their shape; taste and adjust salt — most of the saltiness comes from the pickles, capers, olives, and brine, so go cautiously. SERVE: ladle the hot solyanka into deep bowls; to each bowl add 1 thin lemon slice (whole, peel on), a generous spoonful of smetana, and a scatter of chopped dill; black pepper to taste; serve immediately with thick slices of fresh dark rye bread on the side — solyanka is a main course, not a starter; in Russian tradition, this is the classic post-celebration restorative."}},{"id":172,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"ja":"アメリカ","en":"USA","ro":"SUA"},"name":{"ja":"クラムチャウダー","en":"Clam Chowder","ro":"Clam Chowder"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["殻付き新鮮なlittleneckまたはquahogアサリ1.5kg（または内陸部の料理人のための代用として200g缶詰の小さなアサリ全粒2缶を汁ごと）","新鮮なアサリの汁または魚のだし500ml（新鮮なアサリを使用する場合は蒸し汁をすべて取っておく）","厚切り燻製ベーコン150g、0.5cm角切り","大きな黄玉ねぎ1個（約250g）、みじん切り","中サイズのセロリの茎2本（約120g）、みじん切り","ニンニク4片、みじん切り（任意 — ボストンの純粋主義者は眉をひそめるが、ほとんどの現代のレシピには含まれている）","無塩バター30g","中力粉30g（ルー用）","粉質ジャガイモ750g（Yukon Goldまたはrusset）、皮をむいて1.5cm角に切る","全乳250ml","ヘビークリーム250ml（または軽めのバージョンのためのハーフアンドハーフ）","月桂樹の葉2枚+乾燥タイム小さじ1+挽きたての黒コショウ小さじ0.5","塩小さじ0.5（先に味見 — アサリの汁は塩辛い）","カイエンペッパー一つまみまたはホットソース1滴（任意）","新鮮なチャイブの小さな束、みじん切り、飾り用の新鮮なフラットリーフパセリ大さじ2","提供用：食べられるパンの器としてくり抜いた小さなサワードウロール4個、またはオイスタークラッカー（伝統的なニューイングランドの付け合わせ）；レモン1個、くし形切り"],"en":["1.5 kg fresh littleneck or quahog clams in shells (or 2 × 200 g cans whole baby clams in juice as substitute for landlocked cooks)","500 ml fresh clam juice or fish stock (reserve all the steaming liquid if using fresh clams)","150 g thick-cut smoked bacon, diced 0.5 cm","1 large yellow onion (~250 g), finely diced","2 medium celery stalks (~120 g), finely diced","4 garlic cloves, minced (optional — Boston purists frown but most modern recipes include)","30 g unsalted butter","30 g all-purpose flour (for the roux)","750 g floury potatoes (Yukon Gold or russet), peeled and cut into 1.5 cm cubes","250 ml whole milk","250 ml heavy cream (or half-and-half for a lighter version)","2 bay leaves + 1 tsp dried thyme + 0.5 tsp freshly ground black pepper","0.5 tsp salt (taste first — clam juice is salty)","A pinch of cayenne or 1 dash hot sauce (optional)","1 small bunch fresh chives, finely chopped, and 2 tbsp fresh flat-leaf parsley to garnish","To serve: 4 small hollowed-out sourdough rolls as edible bread bowls OR oyster crackers (a traditional New England side); 1 lemon, sliced into wedges"],"ro":["1,5 kg scoici proaspete (littleneck sau quahog) în cochilii (sau 2 × 200 g conserve de scoici mici întregi în suc, ca substitut pentru cei departe de mare)","500 ml suc de scoici proaspăt sau fond de pește (rezervă tot lichidul de aburire dacă folosești scoici proaspete)","150 g bacon afumat tăiat gros, cuburi de 0,5 cm","1 ceapă galbenă mare (~250 g), tăiată mărunt","2 tulpini medii de țelină (~120 g), tăiate mărunt","4 căței de usturoi, tocați (opțional — puriștii din Boston dezaprobă, dar majoritatea rețetelor moderne îi includ)","30 g unt nesărat","30 g făină universală (pentru roux)","750 g cartofi făinoși (Yukon Gold sau russet), curățați și tăiați cuburi de 1,5 cm","250 ml lapte integral","250 ml smântână grasă (sau jumătate-jumătate pentru o versiune mai ușoară)","2 foi de dafin + 1 linguriță cimbru uscat + 0,5 linguriță piper negru proaspăt măcinat","0,5 linguriță sare (gustă întâi — sucul de scoici este sărat)","Un vârf de cayenne sau 1 strop de sos iute (opțional)","O legăturică mică de arpagic proaspăt, tocat fin, și 2 linguri de pătrunjel proaspăt cu frunze plate pentru garnitură","Pentru servire: 4 chifle mici de sourdough scobite ca boluri comestibile SAU biscuiți pentru stridii (un acompaniament tradițional al Noii Anglii); 1 lămâie, tăiată felii pentru garnitură"]},"howIsMade":{"ja":"1.5kgの新鮮なアサリを冷水で2–3回すすいで砂を取り除く、開いていてタップしても閉じないものは捨てる、広い鍋に250mlの水と一緒に入れ、蓋をして強火で4–5分間、殻がちょうど開くまで蒸す、閉じたままのものは捨てる。アサリを取り出し、蒸し汁を残す、その液体を湿らせたチーズクロスを敷いた細かいふるいを通して計量カップに濾す——約400–500mlのきれいなアサリのブロスができるはず、アサリの身を殻から取り出し、粗く刻んで脇に置く、（缶詰のアサリを使う場合は、汁を残してそのまま水切りし、500mlの魚のだし+缶詰の汁を使う。中火で重い5L鍋またはダッチオーブンに150gの角切りベーコンを加える、頻繁にかき混ぜながら6–8分間、ベーコンが深く色づき、ほとんどの脂が出るまで調理する、穴あきスプーンでカリカリのベーコンをペーパータオルの上に取り、飾り用に脇に置く、鍋に大さじ3のベーコン脂を残す。250gの角切り玉ねぎ+120gの角切りセロリをベーコン脂に加え、ひとつまみの塩を加える、頻繁にかき混ぜながら8–10分間、柔らかく透明になるが色づかないように調理する——チャウダーは白で、ここでは色は欲しくない、みじん切りのニンニク4片を加え、さらに1分調理する、30gのバターを加えて溶かす。野菜の上に30gの小麦粉をふりかけ、木のスプーンで2分間絶えずかき混ぜ、生の小麦粉の味を出さずに色がつかないようにする——これは白いルーである、濾したアサリのブロスをゆっくり一定の流れで注ぎながら、ダマを防ぐために絶えず泡立てる、750gのジャガイモの角切り+月桂樹の葉2枚+タイム小さじ1+黒コショウ小さじ0.5を加える、穏やかな煮込みにする。蓋をせずに15–18分間、時々かき混ぜながら、ジャガイモが柔らかいが形を保つまで調理する——ナイフで一つを刺し、抵抗なくスライドするはず、火を最低に下げる、250mlの全乳と250mlのヘビークリームを混ぜる——乳製品を加えた後は沸騰させないように、さもないとクリームが分離する、3分間温める。刻んだアサリの身とほとんどのベーコンを混ぜる（ベーコン大さじ2と全てのチャイブは飾り用に取っておく）、さらに3分間煮込み、アサリがちょうど温まるまで——加熱しすぎると硬くゴムのようになる、月桂樹の葉を取り除く、味見をして塩とお好みでカイエンペッパー一つまみで調味する。4つの小さなサワードウロールをくり抜く（または伝統的なよりシンプルな選択肢としてオイスタークラッカーを使用）、熱いチャウダーをパンの器または深いスープ皿に注ぐ、それぞれに取っておいたカリカリのベーコン、たっぷりのチャイブとパセリ、新鮮な黒コショウのひねりを乗せる、レモンのくし切りを添えて即座に提供する、ニューイングランドのレストランは通常、テーブルに小さなオイスタークラッカーの皿とホットソースの付け合わせを持ってくる。","en":"Rinse 1.5 kg fresh clams in cold water 2-3 times to remove sand and discard any that are open and do not close when tapped, then place them in a wide pot with 250 ml water, cover and steam over high heat for 4-5 minutes until the shells just open, discarding any that stayed shut. Lift the clams out and strain the steaming liquid through a fine sieve lined with damp cheesecloth into a measuring cup, aiming for ~400-500 ml of clean clam broth, then pick the clam meat from the shells, roughly chop it, and set aside (if using canned clams, drain them reserving the juice and use the 500 ml fish stock plus the canned juice). In a heavy 5 L pot or Dutch oven over medium heat, add 150 g diced bacon and cook stirring often for 6-8 minutes until the bacon is deeply browned and most of the fat has rendered, then lift the crispy bacon onto a paper towel and set aside for garnish, leaving 3 tbsp of bacon fat in the pot. Add 250 g diced onion and 120 g diced celery to the bacon fat with a pinch of salt and cook stirring often for 8-10 minutes until soft and translucent but not browned (chowder is white, so you do not want colour here), then add 4 minced garlic cloves and cook 1 minute more. Add 30 g butter and let it melt, then sprinkle 30 g flour over the vegetables and stir constantly with a wooden spoon for 2 minutes, cooking out the raw flour taste without letting it darken to keep a white roux. Pour in the strained clam broth in a slow steady stream while whisking constantly to prevent lumps, add 750 g potato cubes, 2 bay leaves, 1 tsp thyme, and 0.5 tsp black pepper, bring to a gentle simmer, then cook uncovered for 15-18 minutes stirring occasionally until the potatoes are tender but still hold their shape and a knife slides in with no resistance. Lower the heat to its lowest setting and stir in 250 ml whole milk and 250 ml heavy cream, taking care not to let it boil after adding dairy or the cream will curdle, then warm through for 3 minutes before stirring in the chopped clam meat and most of the bacon (saving 2 tbsp of bacon and all the chives for garnish), and simmer 3 more minutes until the clams are just heated through (overcooking turns them tough and rubbery), then remove the bay leaves and taste, adjusting seasoning with salt and a pinch of cayenne if you like. Hollow out 4 small sourdough rolls (or use oyster crackers as a traditional simpler option), ladle the hot chowder into the bread bowls or deep soup plates, top each with the reserved crispy bacon, a generous scatter of chives and parsley, and a fresh twist of black pepper, and serve immediately with lemon wedges on the side, just as a New England restaurant typically brings a small dish of oyster crackers and a side of hot sauce to the table."}},{"id":173,"servings":2,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ドイツ","en":"Germany","ro":"Germania"},"name":{"ja":"カリーヴルスト","en":"Currywurst","ro":"Currywurst"},"category":{"ja":"スナック","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["ベルリンスタイルの豚肉Bratwurstソーセージ4本（各約120g、合計約480g）—新鮮で、事前にグリルされていないもの；Bratwurstが入手できない場合は細かいBockwurstまたはFrankfurterで代用","ソーセージを揚げるための中性油（ひまわり）大さじ2","カレーソース用：高品質のトマトケチャップ200g（Heinzまたはドイツのhela）","パッサータ100mlまたはトマトペースト大さじ1+水80mlで代用","中辛のカレーパウダー大さじ2（黄色いマドラススタイルのブレンド）—Herta Heuwerのオリジナルは同様のイギリス植民地カレーパウダーを使用","甘いハンガリーパプリカ小さじ1","スモークパプリカ小さじ0.5（任意、深みを加える）","ウスターソース大さじ1（Heuwerのオリジナルの秘密—交渉の余地なし）","りんご酢または白ワインビネガー大さじ1","白砂糖大さじ1（酢のバランスをとり、トマトを引き立てる）","オールスパイス粉小さじ0.5+生姜粉小さじ0.5（Heuwerが追加した'秘密'の温かいスパイスミックス）","塩小さじ0.5+カイエンペッパーまたはホットチリパウダー一つまみ","提供用：上に振りかけるための追加のカレーパウダー+Pommes Frites 2人前（オーブンまたはフライヤーからの熱々のカリカリポテト約400g）、または小さなBrötchenロール2個；本格的なベルリン体験のための小さな木製フォーク2本（Pommespieker）"],"en":["4 Berliner-style Bratwurst pork sausages (~120 g each, total ~480 g) — fresh, not pre-grilled; or substitute fine Bockwurst or Frankfurter if Bratwurst unavailable","2 tbsp neutral oil (sunflower) for frying the sausages","For the curry sauce: 200 g good-quality tomato ketchup (Heinz or German Hela)","100 ml passata or 1 tbsp tomato paste + 80 ml water as substitute","2 tbsp medium-hot curry powder (a yellow Madras-style blend) — Herta Heuwer's original used a similar British colonial curry powder","1 tsp sweet Hungarian paprika","0.5 tsp smoked paprika (optional, adds depth)","1 tbsp Worcestershire sauce (the secret of Heuwer's original — not negotiable)","1 tbsp apple cider vinegar OR white wine vinegar","1 tbsp white sugar (helps balance the vinegar and brings out the tomato)","0.5 tsp ground allspice + 0.5 tsp ground ginger (the 'secret' warm-spice mix Heuwer added)","0.5 tsp salt + a pinch of cayenne or hot chili powder","To serve: extra curry powder for dusting on top + 2 portions of Pommes Frites (about 400 g hot crispy fries from the oven or fryer), or 2 small Brötchen rolls; 2 small wooden forks (Pommespieker) for the authentic Berlin experience"],"ro":["4 cârnați Bratwurst de Berlin din porc (~120 g fiecare, total ~480 g) — proaspeți, nu pre-grătar; sau substituție cu Bockwurst fin sau Frankfurter dacă Bratwurst nu este disponibil","2 linguri ulei neutru (floarea-soarelui) pentru prăjirea cârnaților","Pentru sosul de curry: 200 g ketchup de tomate de bună calitate (Heinz sau german Hela)","100 ml passata sau 1 lingură pastă de tomate + 80 ml apă ca substitut","2 linguri pudră de curry medie-iute (un amestec galben stil Madras) — originalul Herta Heuwer folosea o pudră de curry similară colonială britanică","1 linguriță paprika dulce maghiară","0,5 linguriță paprika afumată (opțional, adaugă profunzime)","1 lingură sos Worcestershire (secretul originalului Heuwer — nu este negociabil)","1 lingură oțet de cidru de mere SAU oțet de vin alb","1 lingură zahăr alb (ajută la echilibrarea oțetului și scoate în evidență tomatele)","0,5 linguriță piment ienibahar + 0,5 linguriță ghimbir măcinat (amestecul 'secret' de mirodenii calde pe care Heuwer le-a adăugat)","0,5 linguriță sare + un vârf de cayenne sau chili iute","Pentru servire: pudră de curry suplimentară pentru presărare deasupra + 2 porții de Pommes Frites (aproximativ 400 g cartofi prăjiți fierbinți și crocanți din cuptor sau friteuză), sau 2 Brötchen mici; 2 furculițe mici de lemn (Pommespieker) pentru experiența autentică berlineză"]},"howIsMade":{"ja":"ソーセージに穴を開ける：4本のBratwurstを調理の15分前に冷蔵庫から出し、室温に近づける、各ソーセージをフォークで4–5回突き刺す — これにより皮が鍋で破れるのを防ぎ、いくらかの脂が出る。カレーソースを作る：小さな鍋に、ケチャップ200g+パッサータ100ml+カレーパウダー大さじ2+甘いパプリカ小さじ1+スモークパプリカ小さじ0.5+ウスターソース大さじ1+酢大さじ1+砂糖大さじ1+オールスパイス小さじ0.5+生姜粉小さじ0.5+塩小さじ0.5+カイエンペッパーひとつまみを合わせる、泡立て器で混ぜる。ソースを煮込む：カレーソースを中低火で穏やかな煮込みにする、8–10分間、木のスプーンで頻繁にかき混ぜながら調理する、ソースが艶やかになり、少し煮詰まるまで — スプーンの裏側をコーティングするはず、味見をして調整：辛すぎる場合は砂糖をひとつまみ追加；甘すぎる場合は酢を少し追加、最低火で温かく保つ。ソーセージを揚げる：重いフライパンで中火で油大さじ2を熱する、穴を開けたソーセージを加え、トングで2分ごとに裏返しながら8–10分揚げる、全面が深い黄金色になり、皮がパリッとするまで、内部温度は70 °Cに達するべき — ソーセージは完全に火が通っていなければならない。2分間休ませる：ソーセージをペーパータオルを敷いたボードに移す、2分間休ませる — これで調理が終わり、肉汁が再分配されるため、切ったときにあふれ出ない。スライス：鋭いナイフで、各ソーセージを斜めに1.5cmの8切れに切る、斜め切りはソースが絡む面が増え、象徴的なベルリンのプレゼンテーションである。盛り付け：スライスしたソーセージを2つの深い紙トレイの皿または浅いボウル（ベルリンImbissスタイル）に分ける、熱いカレーソースを上から豪快にかけ、スライスの周りにプールするようにする、皿全体に追加の豪快なカレーパウダーひとつまみを振りかける — ほこりっぽいトップが、単なるソースに入ったソーセージではなく、currywurstにするものである。Pommesと一緒に提供：木製のPommespieker（小さなフォーク）をスライスに刺し、トレイの横に黄金色のPommes Fritesの山と小さなマヨネーズ+ケチャップ（ドイツのPommes rot-weiß）を置く、立って食べる、理想的にはベルリンの街角で、冷たいピルスナーと組み合わせる、5分以内に食べるのが最適 — 喜びは、パリパリの皮、熱いソース、ほこりっぽいカレー、塩辛いフライの対比にある。","en":"PRICK THE SAUSAGES: take 4 Bratwurst out of the fridge 15 minutes before cooking to come closer to room temperature; prick each sausage 4–5 times with a fork — this prevents the skin from bursting open in the pan and lets some fat render out. MAKE THE CURRY SAUCE: in a small saucepan, combine 200 g ketchup + 100 ml passata + 2 tbsp curry powder + 1 tsp sweet paprika + 0.5 tsp smoked paprika + 1 tbsp Worcestershire + 1 tbsp vinegar + 1 tbsp sugar + 0.5 tsp allspice + 0.5 tsp ground ginger + 0.5 tsp salt + a pinch of cayenne; whisk to combine. SIMMER THE SAUCE: bring the curry sauce to a gentle simmer over medium-low heat; cook 8–10 minutes, stirring often with a wooden spoon, until the sauce is glossy and slightly reduced — it should coat the back of a spoon; taste and adjust: if too sharp, add a pinch more sugar; if too sweet, a splash more vinegar; keep warm on the lowest heat. FRY THE SAUSAGES: heat 2 tbsp oil in a heavy skillet over medium heat; add the pricked sausages and fry 8–10 minutes, turning every 2 minutes with tongs, until deeply golden brown on all sides and the skin is crisp; the internal temperature should reach 70 °C — sausages must be fully cooked through. REST 2 MINUTES: transfer the sausages onto a board lined with paper towel; let them rest 2 minutes — this finishes cooking and lets the juices redistribute, so they don't gush out when sliced. SLICE: with a sharp knife, slice each sausage diagonally into 8 pieces of 1.5 cm; the diagonal cut gives more surface for the sauce to cling to and is the iconic Berlin presentation. ASSEMBLE: divide the sliced sausages between 2 deep paper-tray plates or shallow bowls (the Berlin Imbiss style); ladle the hot curry sauce generously over the top so it pools around the slices; dust the whole plate with an extra generous pinch of curry powder — the dusty top is what makes it a currywurst, not just a sausage in sauce. SERVE WITH POMMES: stab a wooden Pommespieker (small fork) into the slices, set on the side of the tray a heap of golden Pommes Frites and a small dollop of mayonnaise + ketchup (the German Pommes rot-weiß); eat standing up, ideally on a Berlin street corner; pair with a cold Pilsner; best eaten within 5 minutes — the joy is in the contrast of crisp skin, hot sauce, dusty curry, and salty fries."}},{"id":174,"servings":4,"tipType":"meat","pairingsType":"thai","origin":{"ja":"タイ","en":"Thailand","ro":"Thailanda"},"name":{"ja":"トムカーガイ","en":"Tom Kha Gai","ro":"Tom Kha Gai"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["骨抜き皮なし鶏もも肉500g（この繊細なブロスでは胸肉より風味豊か）、繊維を断ち切るように5mmのストリップに薄切り","無糖の全脂肪ココナッツミルク400ml（クリーム層を分離、ステップ2参照）","無塩鶏ストック600ml（自家製または低ナトリウムの市販品）","新鮮なガランガル（kha）一手 — 約50g、皮をむいて5mmのコイン状にスライス；生姜では代用しない、風味が全く異なる","新鮮なレモングラス3本（takrai） — 外側の葉を取り除き、下10cmを包丁の背で叩いて潰し、5cmセクションに切る","新鮮なコブミカンの葉6枚（bai makrut）、葉脈を取って手で裂く（切らない — 裂くと油が放出される）","小さなタイの鳥目唐辛子4本（prik kee noo） — 全体を軽く叩いて潰し、優しい辛さが欲しい場合はスライスしない（辛さを求める場合はスライス）","ニンニク4片、軽く叩いて潰す","小さなエシャロット2個（約80g）、薄切り","藁茸200g（缶詰、水切り）、半分に切る — または新鮮なオイスター/シイタケ/マッシュルームで代用","タイの魚醤（nam pla）大さじ4 — 最高の風味のためにSquidまたはTiparosブランド","パームシュガー大さじ1（または淡褐色砂糖）","新鮮なライム果汁60ml（2個のライムから） — 最後に加える、絶対に煮ない","大豆油のタイ唐辛子ペースト（nam prik pao）大さじ2 — 特徴的なスモーキーな深みを加える（任意だが伝統的）","新鮮なシラントロ（コリアンダー）の小さな束、粗みじん切り、飾り用","万能ねぎ4本、斜めに薄切り、飾り用","提供用：炊いたジャスミンライス320g（1人前80gの乾燥米）+ くし形に切ったライム1個"],"en":["500 g boneless skinless chicken thighs (more flavour than breast in this delicate broth), thinly sliced across the grain into 5 mm strips","400 ml unsweetened full-fat coconut milk (the cream layer separated, see step 2)","600 ml unsalted chicken stock (low-sodium homemade or store-bought)","1 hand of fresh galangal (kha) — ~50 g, peeled and cut into 5 mm coin slices; do NOT substitute ginger, the flavour is completely different","3 stalks fresh lemongrass (takrai) — outer leaves removed, lower 10 cm bruised with the back of a knife and cut into 5 cm sections","6 fresh kaffir lime leaves (bai makrut), de-veined and torn (NOT chopped — they release oils when torn)","4 small Thai bird's eye chilies (prik kee noo) — lightly bruised whole, not sliced if you want gentle heat (sliced for hot)","4 garlic cloves, lightly bruised","2 small shallots (~80 g), thinly sliced","200 g straw mushrooms (canned, drained), halved — or fresh oyster/shiitake/button mushrooms as substitute","4 tbsp Thai fish sauce (nam pla) — Squid or Tiparos brand for best flavour","1 tbsp palm sugar (or light brown sugar)","60 ml fresh lime juice (from 2 limes) — added at the END, never boiled","2 tbsp Thai chili paste in soybean oil (nam prik pao) — adds the signature smoky depth (optional but traditional)","1 small bunch fresh cilantro (coriander) leaves, roughly chopped, to garnish","4 spring onions, thinly sliced on the diagonal, to garnish","To serve: 320 g cooked jasmine rice (80 g dry per serving) + 1 lime cut into wedges"],"ro":["500 g pulpe de pui dezosate și fără piele (mai aromate decât pieptul în acest bulion delicat), feliate subțire în benzi de 5 mm contra fibrei","400 ml lapte de cocos integral neîndulcit (cu stratul de smântână separat, vezi pasul 2)","600 ml supă de pui nesărată (de casă sau cumpărată cu conținut scăzut de sodiu)","1 mână de galangal proaspăt (kha) — ~50 g, curățat și tăiat în felii de 5 mm; NU înlocui cu ghimbir, aroma este complet diferită","3 tulpini de lemongrass proaspăt (takrai) — frunzele exterioare îndepărtate, partea inferioară de 10 cm zdrobită cu dosul cuțitului și tăiată în secțiuni de 5 cm","6 frunze de kaffir lime proaspete (bai makrut), cu vinele îndepărtate și rupte (NU tăiate — eliberează uleiurile când sunt rupte)","4 ardei iuți thailandezi mici (prik kee noo) — zdrobiți ușor întregi, nu feliați dacă vrei iuțeală blândă (feliați pentru iute)","4 căței de usturoi, zdrobiți ușor","2 șalote mici (~80 g), feliate subțire","200 g ciuperci de paie (la conservă, scurse), tăiate în jumătăți — sau ciuperci proaspete oyster/shiitake/champignon ca substitut","4 linguri sos de pește thailandez (nam pla) — marca Squid sau Tiparos pentru cea mai bună aromă","1 lingură zahăr de palmier (sau zahăr brun deschis)","60 ml suc de lime proaspăt (din 2 limete) — adăugat la SFÂRȘIT, niciodată fiert","2 linguri pastă thailandeză de ardei iute în ulei de soia (nam prik pao) — adaugă profunzimea afumată caracteristică (opțional dar tradițional)","1 mănunchi mic de coriandru proaspăt (frunze de cilantro), tocat grosier, pentru garnitură","4 cepe verzi, feliate subțire pe diagonală, pentru garnitură","Pentru servire: 320 g orez jasmin fiert (80 g uscat pe porție) + 1 lime tăiat în felii"]},"howIsMade":{"ja":"香味野菜の下準備：50gのガランガルを皮をむき、5mmのコインに切る、3本のレモングラスの茎から固い外側の葉を取り除き、重い包丁の背で下部10cmを叩いて油を放出させる — そして5cmの片に切る、6枚のコブミカンの葉を引き裂いて（切らない）油を放出させる、4本の唐辛子+4片のニンニクを包丁の側面で軽く叩いて潰す、これらの香味野菜はブロスの魂である — 挽いた代用品は決して使わない。ココナッツミルクを分離する：400ml缶のココナッツミルクを振らずに開ける、濃いクリームは通常上部にある — 濃いクリームを約100mlすくい、脇に置く（これがhua kati、クリームである）、残りは薄いミルク（hang kati）である。クリームをブルームさせる：中火の中型鍋で、100mlのココナッツクリームを3–4分煮る、それが分かれ、油が目に見えて分離し始めるまで — これはココナッツの風味を凝縮し、伝統的なタイのオープニングムーブである、（ココナッツミルクがきれいに分離しない場合は、このステップを飛ばして、すべてを鍋に入れて始める、）。香味野菜を浸す：ガランガルのスライス、レモングラスの片、引き裂いた青柠の葉、潰した唐辛子、ニンニク、80gのスライスしたシャロットを熱いココナッツクリームに加える、1分間、激しく香り高くなるまでかき混ぜる、キッチンは明らかにタイの香りがするはず — 明るい柑橘類、辛いガランガル、甘いココナッツ。ブロスを作る：残りの300mlのココナッツミルク+600mlの鶏ストック+2大さじのnam prik pao（使用する場合）を注ぐ、穏やかな煮込みにする（激しい沸騰は決してしない — ココナッツミルクは激しく沸騰させると醜く分離する）、蓋なしで8分煮込み、香味野菜が完全に浸み込み、ブロスが深く丸みのある味になるようにする。鶏肉を加える：500gのスライスした鶏肉を煮込み中のブロスに落とし、片を分けるためにそっとかき混ぜる、鶏肉がちょうど火が通って白くなるまで4–5分煮込む — 煮すぎると硬くなる、半分に切った200gの藁茸を加え、さらに2分煮込む。味付け：火を止める、4大さじのナンプラー+1大さじのパームシュガーを混ぜ入れる、味見する — ブロスは塩辛く、わずかに甘く、軽くピリッとし、柑橘類の香りに満ちているべきである、必要に応じて、ナンプラーや砂糖を少し追加する、火から離すことがここで重要である。最後の瞬間にライム：60mlの新鮮なライム果汁を提供直前にのみ混ぜる — ライム果汁を沸騰させると苦く鈍くなる、深いボウルに盛る、新鮮なコリアンダー+スライスした万能ねぎ+辛さを好む人のために潰した唐辛子の追加スライスを数枚トッピングする、蒸したジャスミンライスとライムのくし切りと一緒に熱々で提供する、ゲストに伝える：ガランガル、レモングラス、ライムの葉は香味であり、食べられない — ボウルの端に押しやってください。","en":"PREP THE AROMATICS: peel and slice 50 g galangal into 5 mm coins; remove the tough outer leaves from 3 lemongrass stalks and bruise the lower 10 cm with the back of a heavy knife to release the oils — then cut into 5 cm pieces; tear (don't chop) 6 kaffir lime leaves to release their oils; lightly bruise 4 chilies + 4 garlic cloves with the side of the knife; these aromatics are the soul of the broth — never use ground substitutes. SEPARATE THE COCONUT MILK: open a 400 ml can of coconut milk without shaking; the thick cream usually sits on top — spoon off about 100 ml of the thick cream and set aside (this is your hua kati, the cream); the rest is the thinner milk (hang kati). BLOOM THE CREAM: in a medium pot over medium heat, simmer the 100 ml coconut cream 3–4 minutes until it splits and the oil starts to separate visibly — this concentrates the coconut flavor and is the traditional Thai opening move; (If your coconut milk doesn't separate cleanly, skip this step and just start with everything in the pot.). INFUSE THE AROMATICS: add the galangal slices, lemongrass pieces, torn lime leaves, bruised chilies, garlic, and 80 g sliced shallots to the hot coconut cream; stir 1 minute until intensely aromatic; the kitchen should smell distinctly of Thai — bright citrus, peppery galangal, and sweet coconut. BUILD THE BROTH: pour in the remaining 300 ml coconut milk + 600 ml chicken stock + 2 tbsp nam prik pao (if using); bring to a gentle simmer (NEVER a hard boil — coconut milk separates ugly if boiled hard); simmer 8 minutes uncovered, so the aromatics infuse fully and the broth tastes deep and rounded. ADD THE CHICKEN: drop the 500 g sliced chicken into the simmering broth, stirring gently to separate the pieces; simmer 4–5 minutes until the chicken is just cooked through and white — overcooking turns it tough; add 200 g halved straw mushrooms and simmer 2 minutes more. SEASON: turn off the heat; stir in 4 tbsp fish sauce + 1 tbsp palm sugar; taste — the broth should be savoury, slightly sweet, mildly hot, and full of citrus aroma; add a splash more fish sauce or sugar if needed; off heat is critical here. LIME AT THE LAST MOMENT: stir in 60 ml fresh lime juice ONLY just before serving — boiling the lime juice turns it bitter and dull; ladle into deep bowls; top with fresh cilantro + sliced spring onions + a few extra slices of bruised chili for those who like more heat; serve hot with steamed jasmine rice on the side and lime wedges; tell guests: the galangal, lemongrass, and lime leaves are aromatics, not edible — fish them to the side of the bowl."}},{"id":175,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"ja":"カーボベルデ","en":"Cape Verde","ro":"Capul Verde"},"name":{"ja":"カチュパ","en":"Cachupa","ro":"Cachupa"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["milho cachupa 400g（白いホミニーコーン、カーボベルデ特有のひび割れた乾燥品種）— 大量の冷水に一晩浸す（必須）","乾燥赤キドニービーンズ 200g — 一晩浸す","乾燥バタービーンズ（リマ豆）またはひよこ豆 200g — 一晩浸す（豆類の混合がカーボベルデの特徴）","豚肩肉（cabidela）500g、3cmの角切り","塩漬け豚あばら肉または豚バラ肉（toucinho）300g、ぶつ切り — 余分な塩を取り除くために冷水に1時間浸す","linguiçaまたはchouriço portuguesa（ポルトガル燻製ソーセージ）200g、1.5cmスライス","morcela（ポルトガル血ソーセージ）200g — 任意、伝統的","大きな黄玉ねぎ2個（約350g）、1つはrefogado用に細かく刻み、もう1つはくし切り","ニンニク6片、みじん切り","中ぐらいの熟したトマト2個（約250g）、皮をむいてすりおろす、または1×200g缶の砕いたトマト","トマトペースト大さじ1","ローリエ2枚+クミンパウダー小さじ1+甘いパプリカ小さじ1+乾燥オレガノ小さじ0.5+塩小さじ1+黒胡椒小さじ0.5","赤いパームオイル大さじ3またはオリーブオイル（一部の島ではパームオイルがより伝統的）","カボチャまたはバターナッツスカッシュ500g、皮をむいて4cmの角切り","サツマイモまたはヤムイモ300g、皮をむいて4cmの角切り","サボイキャベツ200g、4cmのくし切り（最終段階で加える）","水（または豚肉ストック）2L+ピリピリまたはスコッチボンネット唐辛子1本（任意、島の軽い辛さのため）","提供用：新鮮な白パンの塊、グリルしたlinguiçaの追加スライス数枚、辛いピリピリソース、そして翌日の'cachupa guisada'オプション — 卵と一緒にフライパンで焼いたもの"],"en":["400 g milho cachupa (white hominy corn, the cracked dried Cape Verdean variety) — soaked overnight in plenty of cold water (mandatory)","200 g dried red kidney beans — soaked overnight","200 g dried butter beans (lima beans) or chickpeas — soaked overnight (the mixture of legumes is the Cape Verdean signature)","500 g pork shoulder (cabidela), cut into 3 cm cubes","300 g salted pork ribs or pork belly (toucinho), cut into chunks — soak 1 hour in cold water to remove excess salt","200 g linguiça or chouriço portuguesa (Portuguese smoked sausage), cut into 1.5 cm slices","200 g morcela (Portuguese blood sausage) — optional, traditional","2 large yellow onions (~350 g), one finely diced for the refogado and one cut into wedges","6 garlic cloves, minced","2 medium ripe tomatoes (~250 g), peeled and grated, or 1 × 200 g can crushed tomatoes","1 tbsp tomato paste","2 bay leaves + 1 tsp ground cumin + 1 tsp sweet paprika + 0.5 tsp dried oregano + 1 tsp salt + 0.5 tsp black pepper","3 tbsp red palm oil OR olive oil (palm oil is more traditional in some islands)","500 g pumpkin or butternut squash, peeled and cut into 4 cm cubes","300 g sweet potato or yam, peeled and cut into 4 cm cubes","200 g savoy cabbage, cut into 4 cm wedges (added in the final stage)","2 L water (or pork stock) + 1 piri-piri or scotch bonnet chili (optional, for the islands' light heat)","To serve: chunks of fresh white bread, a few extra slices of grilled linguiça, hot piri-piri sauce, and the next-day pan-fried 'cachupa guisada' with eggs option mentioned"],"ro":["400 g milho cachupa (porumb hominy alb, varietatea crăpată uscată specifică Capului Verde) — înmuiat peste noapte în multă apă rece (obligatoriu)","200 g fasole roșie uscată — înmuiată peste noapte","200 g fasole untoasă uscată (lima) sau năut — înmuiată peste noapte (amestecul de leguminoase este semnătura capverdiană)","500 g spată de porc (cabidela), tăiată în cuburi de 3 cm","300 g coaste de porc sărate sau burtă de porc (toucinho), tăiate în bucăți — înmuiate 1 oră în apă rece pentru a îndepărta excesul de sare","200 g linguiça sau chouriço portuguesa (cârnat afumat portughez), tăiat în felii de 1.5 cm","200 g morcela (cârnat de sânge portughez) — opțional, tradițional","2 cepe galbene mari (~350 g), una tăiată mărunt pentru refogado și una tăiată în felii mari","6 căței de usturoi, tocați mărunt","2 roșii medii coapte (~250 g), decojite și răzuite, sau 1 cutie de 200 g de roșii zdrobite","1 lingură pastă de roșii","2 foi de dafin + 1 linguriță chimion măcinat + 1 linguriță boia dulce + 0.5 linguriță oregano uscat + 1 linguriță sare + 0.5 linguriță piper negru","3 linguri ulei roșu de palmier SAU ulei de măsline (uleiul de palmier este mai tradițional în unele insule)","500 g dovleac sau dovleac plăcintar, curățat și tăiat în cuburi de 4 cm","300 g cartof dulce sau ignamă, curățat și tăiat în cuburi de 4 cm","200 g varză de Milano, tăiată în felii mari de 4 cm (adăugată în etapa finală)","2 L apă (sau supă de porc) + 1 ardei iute piri-piri sau scotch bonnet (opțional, pentru iuțeala ușoară a insulelor)","Pentru servire: bucăți de pâine albă proaspătă, câteva felii suplimentare de linguiça la grătar, sos iute piri-piri și opțiunea 'cachupa guisada' a doua zi (prăjită în tigaie cu ouă)"]},"howIsMade":{"ja":"一晩浸す：このステップは交渉の余地がない、調理の前夜、400gのホミニーコーン+200gのキドニービーンズ+200gのバタービーンズ/ひよこ豆をそれぞれ別々のボウルに入れ、5cmの冷水で覆う、最低12時間浸す、翌朝、水切りしてすすぐ、浸漬をスキップすると、何時間も調理した後にもざらざらした状態のままのコーンになる。ホミニーを予め煮る：水切りしたホミニーを大きな鍋に入れ、1.5Lの新鮮な冷水+ローリエ1枚+塩小さじ1を加える、沸騰させ、蓋をして1時間煮込む、コーンは部分的に柔らかいが中心はまだ硬い状態であるべき — シチューの中でさらに煮込まれる、水切りし、煮汁500mlを取っておく。豆を予め煮る：2つ目の鍋に、水切りしたキドニービーンズとバタービーンズを一緒に入れ、3cm覆うように新鮮な冷水を加える、沸騰させ、5分間アクを取り、al denteになるまで45分煮込む — シチューの中で完成する、水切りする。REFOGADO：大きな重い8L鍋で、パームオイルまたはオリーブオイル大さじ3を中火で熱する、細かく刻んだ玉ねぎ200g+みじん切りニンニク6片を加え、柔らかく金色になるまで8–10分炒める、トマトペースト大さじ1を混ぜ、暗くなるまで1分炒める、すりおろしたトマト250g+パプリカ小さじ1+クミン小さじ1+オレガノ小さじ0.5を加え、混合物が減少し油が表面に分離するまで4–5分炒める。豚肉を焼く：refogadoを脇に押しやる、火を中強火に上げ、500gの豚肩肉キューブを単層で加える、両面3分ずつ焼き、金色になるまで、その後refogadoに混ぜる、水切りした塩漬け豚あばら/バラ肉+塩小さじ1+胡椒小さじ0.5+残りのローリエ1枚+任意のピリピリ唐辛子を加える。シチューを組み立てる：部分的に煮たホミニー+水切りした豆+水（または豚肉ストック）2L+取っておいたトウモロコシの煮汁500mlを加える、穏やかな煮込みにする。ゆっくり煮込む：蓋なしで2時間、20–30分ごとにかき混ぜながら煮込む、1時間後、500gのカボチャキューブ+300gのサツマイモキューブ+linguiçaスライスを加える、1.5時間後、200gのキャベツくし切り+玉ねぎくし切り+morcelaスライス（使用する場合）を加える、シチューは、コーン、豆、野菜、肉がすべて柔らかい、お粥のような厚い濃度に減少するべきである、味見して塩を調整する — 塩漬け豚肉とソーセージが多くを加える。休ませて提供する：火を止め、cachupaを10分間休ませる — そこで完璧な濃度に厚みが増す、すべての色が見えるように深いボウルにたっぷり盛る：黄色いコーン、赤い豆、オレンジ色のカボチャ、緑のキャベツ、金色のソーセージ、豊かな豚肉、新鮮な白パンの塊、テーブルに辛いピリピリソース、カーボベルデのgrogueまたはビールのグラスと一緒に提供する、翌日の残り物はフライパンで焼き、上に目玉焼きを載せた'cachupa guisada'として — 初日よりさらに良いと考えられている。","en":"SOAK OVERNIGHT: this is non-negotiable; the night before cooking, place 400 g hominy corn + 200 g kidney beans + 200 g butter beans/chickpeas each in separate bowls covered by 5 cm of cold water; soak 12 hours minimum; the next morning, drain and rinse; skipping the soak gives a corn that stays gritty after hours of cooking. PRE-COOK THE HOMINY: place the drained hominy in a large pot with 1.5 L fresh cold water + 1 bay leaf + 1 tsp salt; bring to a boil, then simmer covered 1 hour; the corn should be partially tender but still firm at the centre — it will continue cooking in the stew; drain, reserving 500 ml of the cooking liquid. PRE-COOK THE BEANS: in a second pot, place the drained kidney beans and butter beans together with fresh cold water to cover by 3 cm; bring to a boil, skim foam for 5 min, then simmer 45 min until al dente — they will finish in the stew; drain. THE REFOGADO: in a large heavy 8 L pot, heat 3 tbsp palm or olive oil over medium heat; add 200 g finely diced onion + 6 minced garlic and cook 8–10 minutes until soft and golden; stir in 1 tbsp tomato paste and cook 1 min until darkened; add 250 g grated tomato + 1 tsp paprika + 1 tsp cumin + 0.5 tsp oregano and cook 4–5 min until the mixture reduces and the oil separates on the surface. SEAR THE PORK: push the refogado to the side; raise the heat to medium-high and add the 500 g pork shoulder cubes in a single layer; sear 3 minutes per side until golden brown, then stir into the refogado; add the drained salted pork ribs/belly + 1 tsp salt + 0.5 tsp pepper + 1 remaining bay leaf + the optional piri-piri chili. BUILD THE STEW: add the partially-cooked hominy + the drained beans + 2 L water (or pork stock) + the 500 ml reserved corn-cooking liquid; bring to a gentle simmer. SLOW SIMMER: simmer uncovered, stirring every 20–30 minutes, for 2 hours; after 1 hour, add the 500 g pumpkin cubes + 300 g sweet potato cubes + the linguiça slices; after 1.5 hours, add the 200 g cabbage wedges + the onion wedges + the morcela slices (if using); the stew should reduce to a thick, porridge-like consistency where the corn, beans, vegetables, and meats are all tender; taste and adjust salt — the saltpork and sausages add a lot. REST AND SERVE: turn off the heat and let the cachupa rest 10 minutes — this is when it thickens to the perfect consistency; ladle generously into deep bowls with all the colors visible: yellow corn, red beans, orange pumpkin, green cabbage, golden sausage, and rich pork; serve with chunks of fresh white bread, hot piri-piri sauce on the table, and a glass of Cape Verdean grogue or beer; the leftovers next day are pan-fried with a fried egg on top as 'cachupa guisada' — considered even better than the first day."}},{"id":176,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"ja":"インド","en":"India","ro":"India"},"name":{"ja":"パブバジ","en":"Pav Bhaji","ro":"Pav Bhaji"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["粉質ジャガイモ 500g、皮をむいて3cmの角切り","カリフラワーの小房 250g（小さな1/2玉ほど）","グリーンピース 100g（生または冷凍）","フレンチビーンズ 100g、1cmの長さに切る","中ぐらいのニンジン1本（約100g）、角切り","無塩バター 100g（はい — そんなに、これは屋台のバター量です）— 分けて使う","大きな赤玉ねぎ2個（約300g）— 1つはバジ用にみじん切り、1つは飾り用に生でみじん切り","大きな緑ピーマンまたはカプシカム1個（約150g）、みじん切り","熟したトマト4個（約500g）、ブレンダーでピューレに","ショウガ・ニンニクペースト大さじ1（または3cmのショウガ+ニンニク4片を一緒にすりおろす）","パブバジマサラ大さじ2（EverestまたはMDHブランド）— 特定のスパイスブレンド、ガラムマサラで代用しないこと","カシミールレッドチリパウダー小さじ1（象徴的な赤色用、マイルドな辛さ）","ターメリック小さじ0.5+塩小さじ1.5+黒胡椒小さじ0.5","レモン1個、4等分のくし切り+刻んだ新鮮なコリアンダー（シラントロ）、たっぷり","小さくて柔らかいパブパン8個（ムンバイスタイルのラディパブ、またはブリオッシュスライダーパンで代用）","パブを焼くための無塩バター50g+ふりかけ用の追加の赤チリパウダー","提供用：追加の生赤玉ねぎ、新鮮なコリアンダー、レモンのくし切り、小さな青唐辛子1本をみじん切り（任意）"],"en":["500 g floury potatoes, peeled and cut into 3 cm cubes","250 g cauliflower florets (about 1/2 small head)","100 g green peas (fresh or frozen)","100 g French beans, cut into 1 cm pieces","1 medium carrot (~100 g), diced","100 g unsalted butter (yes — that much, this is street-vendor butter quantities) — divided","2 large red onions (~300 g) — one finely diced for the bhaji, one finely diced raw for the garnish","1 large green bell pepper or capsicum (~150 g), finely diced","4 ripe tomatoes (~500 g), pureed in a blender","1 tbsp ginger-garlic paste (or 3 cm ginger + 4 garlic cloves, grated together)","2 tbsp pav bhaji masala (Everest or MDH brand) — the specific spice blend, do not substitute with garam masala","1 tsp Kashmiri red chili powder (for the iconic red color, mild heat)","0.5 tsp turmeric + 1.5 tsp salt + 0.5 tsp ground black pepper","1 lemon, cut into 4 wedges + chopped fresh coriander (cilantro), generously","8 small soft pav buns (Mumbai-style ladi pav, or substitute with brioche slider buns)","50 g unsalted butter for toasting the pav + extra red chili powder for sprinkling","To serve: extra raw red onion, fresh coriander, lemon wedges, 1 small green chili finely chopped (optional)"],"ro":["500 g cartofi făinoși, curățați și tăiați în cuburi de 3 cm","250 g buchețele de conopidă (aproximativ 1/2 căpățână mică)","100 g mazăre verde (proaspătă sau congelată)","100 g fasole verde franceză, tăiată în bucăți de 1 cm","1 morcov mediu (~100 g), tăiat cubulețe","100 g unt nesărat (da — atât de mult, acestea sunt cantitățile de unt ale vânzătorilor de stradă) — împărțit","2 cepe roșii mari (~300 g) — una tăiată mărunt pentru bhaji, una tăiată mărunt crudă pentru garnitură","1 ardei capia verde mare sau capsicum (~150 g), tăiat mărunt","4 roșii coapte (~500 g), pasate în blender","1 lingură pastă de ghimbir-usturoi (sau 3 cm ghimbir + 4 căței usturoi, răzuiți împreună)","2 linguri pav bhaji masala (marca Everest sau MDH) — amestecul specific de condimente, nu înlocuiți cu garam masala","1 linguriță pudră de chili roșu Kashmiri (pentru culoarea roșie iconică, iuțeală blândă)","0.5 linguriță turmeric + 1.5 linguriță sare + 0.5 linguriță piper negru măcinat","1 lămâie, tăiată în 4 sferturi + coriandru proaspăt (cilantro) tocat, generos","8 chifle pav mici și moi (ladi pav stil Mumbai, sau înlocuiți cu chifle brioche slider)","50 g unt nesărat pentru prăjirea pavului + suplimentar pudră de chili roșu pentru presărat","Pentru servire: ceapă roșie crudă suplimentară, coriandru proaspăt, sferturi de lămâie, 1 ardei iute verde mic tocat mărunt (opțional)"]},"howIsMade":{"ja":"圧力鍋で野菜を調理する：圧力鍋（または大きな鍋）に500gのジャガイモの角切り+250gのカリフラワー+100gのグリーンピース+100gのフレンチビーンズ+100gの角切りニンジン+500mlの水+塩小さじ1を入れます、強火で3回のホイッスルまで圧力をかけ、火を止めて自然に減圧させます（約15分）、通常の鍋を使用する場合は、蓋をして25–30分間煮込み、すべてがフォークで刺せるようになるまで、水を切り、調理水250mlを取っておく。野菜をつぶす：ジャガイモマッシャーで、茹でた野菜を鍋の中で勢いよくつぶし、粗いピューレにします — いくつかの食感が残るべきで、これは滑らかなスープではありません、横に置いておく。香味料を開花させる：大きな重いフライパンまたはkadhaiで50gのバターを中火で溶かして泡立つまで加熱する、150gのみじん切りした赤玉ねぎを加え、よくかき混ぜながら5–6分間、柔らかくなり縁が金色になり始めるまで調理する。ショウガ・ニンニク+ピーマン：ショウガ・ニンニクペースト大さじ1を加え、生の匂いが消えるまで1分間かき混ぜる、150gの角切りした緑ピーマンを加え、3–4分間、まだ鮮やかな緑色だが少し柔らかくなるまで調理する。スパイスを開花させる：パブバジマサラ大さじ2+カシミールチリ小さじ1+ターメリック小さじ0.5を加える、スパイスが強く香るまで30秒かき混ぜる — 焦がさず、必要に応じて火を少し弱める。バジを構築する：ピューレ状のトマト+黒胡椒小さじ0.5+塩小さじ0.5を入れる、よくかき混ぜながら6–8分間、トマトが減りバターがフライパンの縁で分離し始めるまで調理する — これがマサラが準備できた視覚的なサイン、取っておいた250mlの野菜水+つぶした野菜を加える、勢いよくかき混ぜて混ぜる。煮込み+さらにつぶす：バジを10–12分間煮込み、頻繁にかき混ぜながらフライパンの中で直接ジャガイモマッシャーでさらにつぶす、バジは濃く、暗赤色で、つやがあり、強く香るようになるはず、味を調整する — ムンバイの屋台売りは塩辛くて辛いものが大好き、さらに30gのバターと1大さじの刻んだコリアンダーを加える、半分のレモンの汁を絞る。パブを焼いて提供する：8つのパブパンを完全に切らずに水平にスライスする（本のスタイル）、広いフライパンを中火で加熱する、30gのバター+パブバジマサラのつまみ+カシミールチリのつまみを加え、回す、開いたパブパンを熱いバターに押し付け、片面30–60秒、黄金色で香りが立つまで焼く、すぐに盛り付ける：熱いバジを大盛りにし、上にバターの塊、刻んだ生赤玉ねぎ、刻んだコリアンダー、レモンのくし切り、任意で刻んだ緑唐辛子をのせる、1人につき2つの焼いたパブを横に添えて提供する、パブをちぎってバジに浸し、一口ごとにレモンを絞る — ムンバイのストリートフードを家で。","en":"PRESSURE-COOK THE VEGETABLES: in a pressure cooker (or large pot) combine 500 g potato cubes + 250 g cauliflower + 100 g peas + 100 g French beans + 100 g diced carrot + 500 ml water + 1 tsp salt; pressure cook 3 whistles on high, then turn off and let the pressure release naturally (about 15 min); if using a regular pot, cover and simmer 25–30 minutes until everything is fork-tender; drain, RESERVING 250 ml of the cooking water. MASH THE VEGETABLES: with a potato masher, vigorously mash the boiled vegetables right in the pot until you have a coarse purée — some texture should remain, this is NOT a smooth soup; set aside. BLOOM THE AROMATICS: heat 50 g butter in a large heavy skillet or kadhai over medium heat until melted and foaming; add 150 g finely diced red onion and cook stirring often 5–6 minutes until soft and just turning golden at the edges. GINGER-GARLIC + BELL PEPPER: add 1 tbsp ginger-garlic paste and stir 1 minute until the raw smell disappears; add 150 g diced green bell pepper and cook 3–4 minutes until just softened but still bright green. SPICES BLOOM: add 2 tbsp pav bhaji masala + 1 tsp Kashmiri chili powder + 0.5 tsp turmeric; stir 30 seconds until the spices are intensely fragrant — do not burn, lower the heat slightly if needed. BUILD THE BHAJI: pour in the pureed tomatoes + 0.5 tsp ground pepper + 0.5 tsp salt; cook stirring often 6–8 minutes until the tomato has reduced and the butter starts to separate around the edges of the pan — this is the visual sign that the masala is ready; add the reserved 250 ml vegetable water + the mashed vegetables; stir vigorously to combine. SIMMER + MASH MORE: simmer the bhaji 10–12 minutes, stirring frequently and mashing more with a potato masher right in the pan; the bhaji should become thick, dark red, glossy, and intensely fragrant; adjust seasoning — Mumbai street vendors love it salty and spicy; stir in another 30 g butter and 1 tbsp chopped coriander; squeeze in juice of half a lemon. TOAST THE PAV AND SERVE: slice 8 pav buns horizontally without cutting all the way through (book-style); heat a wide skillet over medium heat; add 30 g butter + a pinch of pav bhaji masala + a pinch of Kashmiri chili powder, swirl; press the open pav buns into the hot butter and toast 30–60 seconds per side until golden and fragrant; plate immediately: a generous mound of hot bhaji topped with a knob of butter, chopped raw red onion, chopped coriander, a lemon wedge, and optional chopped green chili; serve with 2 toasted pav per person on the side; tear the pav, dip into the bhaji, squeeze the lemon over each bite — Mumbai street food at home."}},{"id":177,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"ja":"フィンランド","en":"Finland","ro":"Finlanda"},"name":{"ja":"カレリアンシチュー","en":"Karelian stew","ro":"Karjalanpaisti"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛肩肉（chuck）400g、3cmの角切り","豚肩肉400g、3cmの角切り","ラム肩肉400g、3cmの角切り（またはラップランドではトナカイ肉）","大きな黄玉ねぎ2個（約400g）、厚切り","中ぐらいのニンジン4本（約400g）、3cmのぶつ切り","黒胡椒粒小さじ1","ローリエ4枚","ジュニパーベリー丸ごと6粒（フィンランドの特徴、わずかに松の香り — 譲れない要素）","オールスパイス丸ごと6粒","塩小さじ2","冷水1L（または薄い牛肉ストック — 伝統的には水）","中性油大さじ1またはバター50g（任意の焼き目付け工程用）","提供用：バターとディルを和えた茹で新じゃがいも800g、ピクルスきゅうり、リンゴンベリージャム（puolukkahillo）、ダークライ麦パン、そして冷たい牛乳またはビール1杯"],"en":["400 g beef chuck, cubed 3 cm","400 g pork shoulder, cubed 3 cm","400 g lamb shoulder, cubed 3 cm (or reindeer in Lapland)","2 large yellow onions (~400 g), thickly sliced","4 medium carrots (~400 g), cut into 3 cm chunks","1 tsp whole black peppercorns","4 bay leaves","6 whole juniper berries (the Finnish signature, slightly piny — non-negotiable)","6 whole allspice berries","2 tsp salt","1 L cold water (or weak beef stock — traditional is water)","1 tbsp neutral oil OR 50 g butter for the optional searing step","To serve: 800 g boiled new potatoes with butter and dill, pickled cucumber, lingonberry jam (puolukkahillo), dark rye bread, and a glass of cold milk or beer"],"ro":["400 g pulpă de vită (chuck), tăiată în cuburi de 3 cm","400 g spată de porc, tăiată în cuburi de 3 cm","400 g spată de miel, tăiată în cuburi de 3 cm (sau ren în Laponia)","2 cepe galbene mari (~400 g), tăiate în felii groase","4 morcovi medii (~400 g), tăiați în bucăți de 3 cm","1 linguriță boabe întregi de piper negru","4 foi de dafin","6 boabe întregi de ienupăr (semnătura finlandeză, ușor rășinos — non-negociabil)","6 boabe întregi de ienibahar","2 lingurițe sare","1 L apă rece (sau supă slabă de vită — tradițional este apa)","1 lingură ulei neutru SAU 50 g unt pentru pasul opțional de rumenire","Pentru servire: 800 g cartofi noi fierți cu unt și mărar, castravete murat, gem de merișoare lingonberry (puolukkahillo), pâine neagră de secară și un pahar de lapte rece sau bere"]},"howIsMade":{"ja":"オーブンを125°Cに予熱します — 非常に低温の遅いオーブンがKarjalanpaistiのシグネチャーであり、その溶けるような食感を定義する料理です。整えて角切りに：400gの牛肉+400gの豚肉+400gのラム肉の筋を取り除きます、均一な3cmの角切りに切ります — 小さく切らないでください、これは5時間の調理で、大きめの角切りは耐えます、小さい片は繊維状に溶けます。スタイルを選ぶ — 伝統的：焼き色付けはスキップ、すべてを生のまま重ね、カレリアのおばあちゃんたちが何世紀にもわたってやってきたように、オーブンに任せます、モダン：ダッチオーブンで強火に大さじ1の油を熱し、肉を3回に分けて片面2分ずつ焼き、追加のメイラード風味のために褐色にし、取り出します、両方の方法とも素晴らしい結果を生み出します。鍋を層にする：大きなダッチオーブンまたは鋳鉄キャセロールで、この順序で交互に層を構築します：底に牛肉、スライスした玉ねぎ、豚肉、ニンジンの塊、ラム肉を上に、ローリエ4枚+ジュニパーベリー6粒+オールスパイス6粒+黒胡椒粒小さじ1+塩小さじ2を層の間に分散させます — 決して上だけに置かないでください。液体を加える：1Lの冷水（または薄い牛肉ストック）を肉の半分まで来るように注ぎます — 覆わないでください、肉は長時間の調理中に自分の汁を放出し、ソースは自然に濃縮されます。密閉して低温調理：密閉できる蓋で覆います、125°Cのオーブンに4–5時間移します — はい、5時間、それがポイントです、1.5時間ごとに液体を確認する以外は蓋を開けないでください、減りが早すぎる場合は、熱湯を少し加えます、フォークが楽に沈むようになったら肉は出来上がりです。オーブンで休ませる：オーブンを消し、karjalanpaistiを閉じた暖かいオーブンの中でさらに30分休ませます — 風味が深まり、肉がソースに馴染みます。提供：柔らかい肉を温かい深皿に持ち上げます、だし汁のような濃縮された汁をかけます、ジュニパーベリーとオールスパイスは勇敢な人のために残すか、取り出します、バターとディルで和えた茹で新じゃがいも、付け合わせのピクルスきゅうり、たっぷりのリンゴンベリージャム（甘酸っぱい対比）、ダークライ麦パンのスライス、冷たい牛乳またはビール1杯と一緒に提供します — 伝統的なフィンランドの夕食の付け合わせです。","en":"PREHEAT THE OVEN to 125 °C — the very low slow oven is the SIGNATURE of Karjalanpaisti, the dish that defines its melting texture. TRIM AND CUBE: trim 400 g beef + 400 g pork + 400 g lamb of any sinew; cut into uniform 3 cm cubes — DO NOT cut smaller; this is a 5 h cook and larger cubes hold up; smaller pieces dissolve into shreds. CHOOSE YOUR STYLE — TRADITIONAL: skip browning; layer everything raw and let the oven do the work, as Karelian grandmothers have done for centuries; mODERN: heat 1 tbsp oil in a Dutch oven over high heat, brown the meat in 3 batches 2 min per side for added Maillard flavour, then lift out; both methods produce excellent results. LAYER THE POT: in a large Dutch oven or cast-iron casserole, build alternating layers in this order: beef on the bottom, sliced onion, pork, carrot chunks, lamb on top; distribute 4 bay leaves + 6 juniper berries + 6 allspice + 1 tsp peppercorns + 2 tsp salt between the layers — never just on top. ADD LIQUID: pour in 1 L cold water (or weak beef stock) so it comes halfway up the meat — NOT covering; the meats release their own juices during the long cook and the sauce concentrates naturally. SEAL AND SLOW-COOK: cover with a tight-fitting lid; transfer to the 125 °C oven for 4–5 hours — yes, five hours, that is the point; do NOT open the lid except once every 1.5 hours to check the liquid; if reducing too fast, add a splash of hot water; the meat is ready when a fork sinks in effortlessly. REST IN THE OVEN: turn off the oven and let the karjalanpaisti rest in the closed warm oven another 30 minutes — the flavours deepen and the meat relaxes into the sauce. SERVE: lift the tender meat into warm deep plates; spoon over the brothy concentrated juices; the juniper berries and allspice can stay in for the brave, or be fished out; serve with boiled new potatoes tossed in butter and dill, pickled cucumber on the side, a generous dollop of lingonberry jam (the sweet-tart counterpoint), slices of dark rye bread, and a glass of cold milk or beer — the traditional Finnish dinner accompaniment."}},{"id":178,"servings":6,"tipType":"meat","pairingsType":"french","origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"ブッフ・ブルギニヨン","en":"Boeuf Bourguignon","ro":"Boeuf Bourguignon"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛肩肉またはすね肉1.5kg、4cmの角切り（コクのために少しサシ入り）","ラルドン200g（燻製ポークベリーを1cm×3cmに切ったもの）または厚切りベーコンの角切り200g","フルボディの赤ブルゴーニュワイン（ピノ・ノワール）750ml — 安いワインは使用しないでください","牛肉ストック200ml","トマトペースト大さじ2","大きな玉ねぎ1個（約250g）、マリネと煮込み用にみじん切り","中ぐらいのニンジン2本（約250g）、2cmのぶつ切り","ニンニク4片、みじん切り","無塩バター30g+オリーブオイル大さじ2（焼き付け用）","薄力粉大さじ3","ブーケガルニ1束：タイム3枝+ローリエ2枚+パセリの茎6本を料理用ひもで縛る","パールオニオン250g（silverskin）、皮をむいたもの","クレミニまたはマッシュルーム250g、半分または4等分に切る","マッシュルームとパールオニオンのガーニッシュ用の追加バター30g","塩小さじ1.5+挽きたての黒胡椒小さじ1","コニャックまたはブランデー大さじ2（任意のフランベ用）","新鮮なフラットリーフパセリ+バゲット+茹で新じゃがいもまたはバター卵麺（提供用）"],"en":["1.5 kg beef chuck or shin, cubed 4 cm (some marbling for richness)","200 g lardons (smoked pork belly cut 1 cm × 3 cm) OR 200 g thick-cut bacon diced","750 ml full-bodied Burgundy red wine (Pinot Noir) — DO NOT use cheap wine","200 ml beef stock","2 tbsp tomato paste","1 large onion (~250 g), finely diced for the marinade and braise","2 medium carrots (~250 g), cut into 2 cm chunks","4 garlic cloves, minced","30 g unsalted butter + 2 tbsp olive oil for searing","3 tbsp all-purpose flour","1 bouquet garni: 3 thyme sprigs + 2 bay leaves + 6 parsley stems tied with kitchen string","250 g pearl onions (silverskin), peeled","250 g cremini or button mushrooms, halved or quartered","30 g extra butter for the mushroom-and-pearl-onion garnish","1.5 tsp salt + 1 tsp freshly ground black pepper","2 tbsp Cognac OR brandy for optional flambé","Fresh flat-leaf parsley + baguette + boiled new potatoes or buttered egg noodles to serve"],"ro":["1.5 kg pulpă de vită (chuck) sau gambă, tăiată în cuburi de 4 cm (cu ceva marmurare pentru bogăție)","200 g lardoni (piept de porc afumat tăiat 1 cm × 3 cm) SAU 200 g bacon gros tăiat cubulețe","750 ml vin roșu Burgundia robust (Pinot Noir) — NU folosi vin ieftin","200 ml supă de vită","2 linguri pastă de roșii","1 ceapă mare (~250 g), tăiată mărunt pentru marinadă și pentru tocană","2 morcovi medii (~250 g), tăiați în bucăți de 2 cm","4 căței de usturoi, tocați mărunt","30 g unt nesărat + 2 linguri ulei de măsline pentru rumenire","3 linguri făină universală","1 buchet garni: 3 crenguțe cimbru + 2 foi de dafin + 6 cozi de pătrunjel legate cu sfoară de bucătărie","250 g ceapă perlată (silverskin), curățată","250 g ciuperci cremini sau champignon, tăiate în jumătăți sau sferturi","30 g unt suplimentar pentru garnitura de ciuperci și ceapă perlată","1.5 linguriță sare + 1 linguriță piper negru proaspăt măcinat","2 linguri Cognac SAU brandy pentru flambare opțională","Pătrunjel proaspăt cu frunza plată + baghetă + cartofi noi fierți sau tăiței cu unt pentru servire"]},"howIsMade":{"ja":"牛肉をマリネする（12-24時間前、ジュリア・チャイルドの譲れない手順）：1.5kgの角切り牛肉を非反応性のボウルに入れ、赤ブルゴーニュ750ml+みじん切り玉ねぎ1個+みじん切りニンジン1本+ニンニク4片+ブーケガルニ+黒胡椒小さじ1を加えます、蓋をして12-24時間冷蔵します、ふるいで濾し、ワインを取っておきます、牛肉をペーパータオルで非常によく水気を拭き取ります — 濡れた肉は蒸されるだけで、決して焼き付きません。ラルドンを脂出し：重いダッチオーブンに中火で、200gのラルドンを6-8分間調理し、カリッと黄金色になり、脂が完全に出るまで、穴あきスプーンで皿に取り出します、鍋に大さじ2の脂を残します、牛肉を焼く：火を強火に上げます。オリーブオイル大さじ1+バター15gを加えます、混雑させずに3-4回に分けて作業し、乾燥した牛肉の角切りを片面2-3分焼き、全面が深く茶色になるまで — 1バッチあたり約8分、各バッチをトレイに移します、鍋底にくっついた濃い色のフォンは風味のベースです — そのままにしておきます。ソフリット+フランベ：火を中火に下げます、鍋に250gのみじん切り玉ねぎ+250gのニンジンの塊を加えます、柔らかくなり始めるまで5分間調理します、みじん切りニンニク4片+トマトペースト大さじ2を加えて混ぜ、1分間調理します。コニャック大さじ2を注ぎ、慎重に火をつけます（炎は30秒で消えます）、またはフランベをスキップして、コニャックを単に脱釉として加えます、煮込みを構築する：野菜の上に小麦粉大さじ3を振りかけ、生の味を煮出すために1分間混ぜます、取っておいたワインをゆっくりと注ぎながら混ぜ、底をこそげてフォンを持ち上げます。牛肉ストック200ml+ブーケガルニ+塩小さじ1.5+黒胡椒小さじ1を加えます、牛肉+ラルドンを鍋に戻します — 液体はすべてをぎりぎり覆うべきです、ゆっくりと煮込む：穏やかな煮立ちにします、蓋を少し開けて160°Cのオーブンに2.5-3時間移します（またはコンロで最低火で煮込みます）、45分ごとに混ぜ、牛肉がほろほろと崩れるほど柔らかく、ソースが艶のあるスプーンを覆う濃厚さに濃縮されるまで。ブーケガルニを捨てます、パールオニオン+マッシュルームのガーニッシュ：別のフライパンで、中火でバター15gを溶かします、皮をむいたパールオニオン250g+水大さじ1+砂糖小さじ1+塩ひとつまみを加え、蓋をして15分間調理し、その後蓋を開けて5分間焼き、艶やかで黄金色になるまで、同じフライパンに、さらにバター15gとマッシュルーム250gを加え、2回に分けて6-8分間、深い黄金茶色になるまでソテーします — フライパンを混雑させないでください。組み立てて提供する：パールオニオン+マッシュルームを煮込みに混ぜ込みます、一緒に5分間温めます、味見をして塩を調整します、火から下ろして煮込みを10分間休ませます — 風味が劇的に深まります。茹で新じゃがいも（またはバター卵麺）の上に、深い皿に寛大な分量を盛り付け、ソースを拭うためのカリカリのバゲット、刻んだ新鮮なパセリを散らします、常に翌日の方が良い — 風味が一晩で結婚します、あなたが調理した同じブルゴーニュのボトルを飲んでください。","en":"Place 1.5 kg cubed beef in a non-reactive bowl with the 750 ml red Burgundy, 1 chopped onion, 1 chopped carrot, 4 garlic cloves, the bouquet garni and 1 tsp pepper, then cover and refrigerate for 12-24 hours; drain through a sieve while reserving the wine, and pat the beef very dry with paper towel so it sears rather than steams. In a heavy Dutch oven over medium heat, cook 200 g lardons for 6-8 minutes until crisp and golden and the fat is fully rendered, then lift them out with a slotted spoon and leave 2 tbsp of rendered fat behind in the pot. Raise the heat to high and add 1 tbsp olive oil plus 15 g butter, then sear the dried beef cubes in 3-4 uncrowded batches for 2-3 minutes per side (about 8 minutes per batch) until deeply browned on all sides; transfer each batch to a tray and leave the dark fond stuck to the pot as your flavour base. Reduce the heat to medium, add 250 g diced onion and 250 g carrot chunks and cook 5 minutes until starting to soften, then stir in 4 minced garlic cloves and 2 tbsp tomato paste and cook 1 minute; pour in 2 tbsp Cognac and ignite carefully (the flames die in 30 seconds), or skip the flambe and simply use the Cognac to deglaze. Sprinkle 3 tbsp flour over the vegetables and stir for 1 minute to cook out the raw taste, then pour in the reserved wine slowly while scraping the bottom to lift the fond, add 200 ml beef stock, the bouquet garni, 1.5 tsp salt and 1 tsp pepper, and return the beef and lardons to the pot so the liquid barely covers everything. Bring to a gentle simmer, cover with the lid slightly ajar and transfer to a 160 °C oven (or simmer on the lowest stovetop heat) for 2.5-3 hours, stirring every 45 minutes until the beef is fall-apart tender and the sauce has thickened to a glossy coats-the-spoon consistency; discard the bouquet garni. In a separate skillet, melt 15 g butter over medium heat, add 250 g peeled pearl onions with 1 tbsp water, 1 tsp sugar and a pinch of salt, cover and cook 15 minutes, then uncover and brown 5 minutes until glossy and golden; in the same skillet add another 15 g butter and 250 g mushrooms and saute 6-8 minutes in 2 batches until deeply golden brown, never crowding the pan. Fold the pearl onions and mushrooms into the braise and warm together 5 minutes, then taste and adjust the salt and let the braise rest 10 minutes off the heat so the flavours deepen; serve generous portions in deep plates over boiled new potatoes (or buttered egg noodles), scatter with chopped fresh flat-leaf parsley and offer crusty baguette to mop up the sauce -- it is always better the next day, and pairs perfectly with a bottle of the same Burgundy you cooked with."}},{"id":179,"servings":2,"tipType":"veg","pairingsType":"middle-eastern","origin":{"ja":"チュニジア","en":"Tunisia","ro":"Tunisia"},"name":{"ja":"シャクシュカ","en":"Chakchouka","ro":"Chakchouka"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["室温の大きな卵4個","エクストラバージンオリーブオイル大さじ4（チュニジア産または地中海産）","中ぐらいの黄玉ねぎ1個（約150g）、細かく刻む","マイルドな赤パプリカ2個（約300g）、種を取って1cm角に切る","小さな赤唐辛子1本を細かく刻むかチュニジアのハリッサペースト小さじ1（より伝統的な選択）","ニンニク4片、みじん切り","クミンパウダー小さじ1（kamoun）— 温かい香辛料のベース","キャラウェイパウダー小さじ1（karwiya）— チュニジアを定義する温かい香辛料、見た目が似ているがクミンとは別物；入手できない場合はフェンネルシードで代用","甘いパプリカ小さじ1","コリアンダーパウダー小さじ0.5","缶詰の砕いたトマト400g（または皮をむいてすりおろした熟したトマト4個）","コクのためのトマトペースト大さじ1","塩小さじ1+挽きたて黒胡椒小さじ0.5+酸味のバランスのための砂糖ひとつまみ","フェタタイプのチーズ60g（チュニジア風またはブルガリア風、崩したもの、任意）+ 新鮮なイタリアンパセリ + コリアンダー + レモンのくし切り + 新鮮なバゲットまたはチュニジアのkhobz taboumaを添えて"],"en":["4 large eggs at room temperature","4 tbsp extra-virgin olive oil (Tunisian or Mediterranean)","1 medium yellow onion (~150 g), finely diced","2 mild red bell peppers (~300 g), seeded and cut into 1 cm dice","1 small red chili finely chopped OR 1 tsp Tunisian harissa paste (the more traditional choice)","4 garlic cloves, minced","1 tsp ground cumin (kamoun) — the warm spice base","1 tsp ground caraway (karwiya) — Tunisia's DEFINING warm spice, NOT the same as cumin despite looking similar; substitute fennel seed if unavailable","1 tsp sweet paprika","0.5 tsp ground coriander","400 g can crushed tomatoes (or 4 ripe tomatoes peeled and grated)","1 tbsp tomato paste for body","1 tsp salt + 0.5 tsp freshly ground black pepper + a pinch of sugar to balance acidity","60 g feta-style cheese (Tunisian or Bulgarian-style, crumbled, optional) + fresh flat-leaf parsley + cilantro + lemon wedges + fresh baguette or Tunisian khobz tabouna to serve"],"ro":["4 ouă mari la temperatura camerei","4 linguri ulei de măsline extravirgin (tunisian sau mediteranean)","1 ceapă galbenă medie (~150 g), tăiată mărunt","2 ardei graşi roşii blânzi (~300 g), curăţaţi de seminţe şi tăiaţi în cuburi de 1 cm","1 ardei iute roşu mic tocat mărunt SAU 1 linguriţă pastă de harissa tunisiană (alegerea mai tradiţională)","4 căţei de usturoi, tocaţi mărunt","1 linguriţă chimion măcinat (kamoun) — baza de mirodenii calde","1 linguriţă chimen măcinat (karwiya) — mirodenia caldă DEFINITORIE a Tunisiei, NU acelaşi lucru cu chimionul deşi arată asemănător; înlocuieşte cu sămânţă de fenicul dacă nu este disponibil","1 linguriţă boia dulce","0.5 linguriţă coriandru măcinat","400 g roşii zdrobite la cutie (sau 4 roşii coapte decojite şi rase)","1 lingură pastă de roşii pentru corp","1 linguriţă sare + 0.5 linguriţă piper negru proaspăt măcinat + un vârf de zahăr pentru echilibrul acidităţii","60 g brânză tip feta (tunisiană sau bulgărească, sfărâmată, opţional) + pătrunjel proaspăt cu frunza lată + coriandru + felii de lămâie + baghetă proaspătă sau khobz tabouna tunisian pentru servire"]},"howIsMade":{"ja":"芳香材料の準備：チャクチューカは早く調理される — mise-en-placeは交渉の余地がない、玉ねぎ150g + 赤パプリカ300g + 赤唐辛子1本を角切りにする、ニンニク4片をみじん切りにする、スパイスのカルテット — クミン + キャラウェイ + パプリカ + コリアンダー — を小さなボウルに計量する、キャラウェイがこれをチュニジア風にし、イスラエルまたはレバント風のシャクシューカではなくする。油を温める：重い24cmスキレット（鋳鉄が理想 — 陶器のタジン鍋が最も伝統的なチュニジア風）でオリーブオイル大さじ4を中火で揺らめくまで熱する。ソフリット：刻んだ玉ねぎ150gとひとつまみの塩を加え、非常に柔らかく半透明になるまで6–8分炒める — 茶色にしない、チュニジア風チャクチューカは、ゆっくり汗をかいた玉ねぎの甘さを求め、キャラメル化ではない。パプリカ + 唐辛子 + ニンニク：角切りの赤パプリカ300g + 刻んだ赤唐辛子1本（またはハリッサ小さじ1）を加える、パプリカが柔らかくなるが鮮やかな赤を保つまで6–8分炒める、みじん切りニンニク4片を加え、香りが立つまで1分炒める。スパイスを開花させる：スパイスミックス（クミン小さじ1 + キャラウェイ小さじ1 + パプリカ小さじ1 + コリアンダー小さじ0.5）を熱い油と野菜のベースに直接加える、強く香り立つまで30秒かき混ぜる — 焦がさない、さもないと料理が苦くなる。ソースを作る：トマトペースト大さじ1を混ぜ入れ、1分炒める、砕いたトマト400g + 塩小さじ1 + 胡椒小さじ0.5 + 砂糖ひとつまみを注ぐ、時々かき混ぜながら8–10分煮込み、ソースが濃くなるまで — 表面をスプーンでなぞった跡がすぐに埋まらない明確な道を残すべき。卵を加える：スプーンの背で、煮立っているソースに4つのくぼみを作る、各くぼみに卵1個を割り入れる — 黄身を無傷に保つ、白身にひとつまみの塩、黄身に胡椒のひねりをかける、スキレットに蓋をして、中弱火で4–6分加熱する、白身が固まりかけているが黄身は流動的なまま — 蓋越しに覗く；白身は不透明で、黄身はまだ鮮やかなオレンジ色で震えているべき。仕上げて提供する：上に崩したフェタ60g + 刻んだパセリとコリアンダーをたっぷりひと握り散らす、フライパンを直接テーブルに持ってくる — チャクチューカは常に共同で、フライパンから食べる、各食卓の客は新鮮なバゲットまたはkhobz taboumaの一片をちぎり、それを使ってソースを拭き取り、黄身を割る、自分の取り分にレモンのくし切りを絞る、調理から10分以内が最高、黄身がまだ溶けている間。","en":"PREP THE AROMATICS: chakchouka cooks fast — mise-en-place is non-negotiable; dice 150 g onion + 300 g red bell peppers + 1 red chili; mince 4 garlic; measure the spice quartet — cumin + caraway + paprika + coriander — into a small bowl; the caraway is what makes this Tunisian and not Israeli or Levantine shakshuka. WARM THE OIL: heat 4 tbsp olive oil in a heavy 24 cm skillet (cast iron is ideal — earthenware tagine is the most traditional Tunisian) over medium heat until shimmering. SOFFRITTO: add 150 g diced onion with a pinch of salt and cook 6–8 min until very soft and translucent — NOT browned; tunisian chakchouka wants the sweetness of slowly-sweated onions, not caramelization. PEPPERS + CHILI + GARLIC: add 300 g diced red bell peppers + 1 chopped red chili (or 1 tsp harissa); cook 6–8 min until peppers are softened but still bright red; add 4 minced garlic and cook 1 min until fragrant. BLOOM THE SPICES: add the spice mix (1 tsp cumin + 1 tsp caraway + 1 tsp paprika + 0.5 tsp coriander) directly into the hot oil-and-vegetable base; stir 30 seconds until intensely aromatic — do not burn, or the dish turns bitter. BUILD THE SAUCE: stir in 1 tbsp tomato paste and cook 1 min; pour in 400 g crushed tomatoes + 1 tsp salt + 0.5 tsp pepper + a pinch of sugar; simmer 8–10 min, stirring occasionally, until the sauce has thickened — a spoon dragged through the surface should leave a clear trail that does not immediately fill back in. ADD EGGS: with the back of a spoon, make 4 wells in the simmering sauce; crack 1 egg into each well — keep yolks intact; sprinkle a pinch of salt over the whites and a twist of pepper over the yolks; cover the skillet with a lid and cook over medium-low heat 4–6 min, until the whites are just set but the yolks remain runny — peek through the lid; the whites should be opaque and the yolks still bright orange and trembling. FINISH AND SERVE: scatter 60 g crumbled feta + a generous handful of chopped parsley and cilantro over the top; bring the pan straight to the table — chakchouka is always communal, eaten from the skillet; each diner tears off a piece of fresh baguette or khobz tabouna and uses it to mop up the sauce and break into a yolk; squeeze a lemon wedge over your own portion; best within 10 minutes of cooking, while the yolks are still molten."}},{"id":180,"origin":{"ja":"日本","en":"Japan","ro":"Japonia"},"name":{"ja":"お好み焼き","en":"Okonomiyaki","ro":"Okonomiyaki"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"ja":["薄力粉200g","冷たいだし汁240ml（または水＋だしの素小さじ1）","大きな卵2個","白キャベツ400g、細かく千切り","豚バラ肉の薄切り200g（5cm幅に切る）","天かす大さじ2（任意）","ベーキングパウダー小さじ½","キューピーマヨネーズ大さじ4","お好みソース（オタフクなど）大さじ4","ウスターソース小さじ1","かつお節（仕上げ用）","青のり（仕上げ用）"],"en":["200g plain flour (or cake flour)","240ml cold dashi stock (or water + 1 tsp dashi powder)","2 large eggs","400g white cabbage, finely shredded","200g thinly sliced pork belly (buta bara), cut into 5 cm pieces","2 tbsp tenkasu (tempura scraps, optional)","½ tsp baking powder","4 tbsp Japanese mayonnaise (Kewpie)","4 tbsp okonomiyaki sauce (e.g. Otafuku brand)","1 tsp Worcestershire sauce","katsuobushi (dried bonito flakes) to serve","aonori (powdered seaweed) to serve"],"ro":["200g făină albă simplă (sau făină pentru prăjituri)","240ml supă dashi (rece; sau apă + 1 linguriță pudră dashi)","2 ouă mari","400g varză albă, tăiată fin","200g burta de porc feliată subțire (buta bara), tăiată în bucăți de 5 cm","2 linguri tenkasu (firimituri de tempura, opțional)","½ linguriță praf de copt","4 linguri maioneză Kewpie (japoneză)","4 linguri sos okonomiyaki (ex. Otafuku)","1 linguriță sos Worcestershire","katsuobushi (fulgi de ton uscat), pentru servire","aonori (alge marine pudră), pentru servire"]},"howIsMade":{"ja":"大きなボウルに薄力粉・ベーキングパウダー・卵・冷たいだし汁を合わせ、混ぜすぎずにさっくり合わせる。千切りキャベツと天かすをゴムべらで折り込む——生地はもったりとキャベツたっぷりの状態に。フライパンをよく温めて薄く油を引き、生地を入れて2cmほどの厚さの円形に整える。豚バラ肉を全面に広げて乗せる。中弱火で5〜6分焼き、縁が固まり底面がきつね色になったら2枚のへらで慎重にひっくり返し、軽く押さえる。さらに5〜6分焼いて豚がカリッと仕上がったら完成。豚側にお好みソースを塗り、キューピーマヨをジグザクにかけ、かつお節と青のりを散らす。すぐに鍋ごと出す。","en":"In a large bowl whisk together flour, baking powder, eggs, and cold dashi until just combined — do not overmix. Fold in shredded cabbage and tenkasu with a spatula; the batter should be thick and mounded with cabbage. Heat a non-stick pan over medium heat, brush with a thin layer of oil. Pour batter into the pan and shape into a disc about 2 cm thick. Lay pork belly slices over the entire top surface. Cook 5–6 minutes on medium-low until the edges look set and the underside is golden-brown. Flip carefully using two spatulas, pressing lightly; cook another 5–6 minutes until pork is crisp and batter is cooked through. Brush the pork side with okonomiyaki sauce, drizzle Kewpie in a zigzag, scatter katsuobushi and aonori. Serve immediately from the pan."}},{"id":181,"servings":2,"tipType":"meat","timeMins":{"total":780,"active":120},"pairingsType":"japanese","origin":{"ja":"日本","en":"Japan","ro":"Japonia"},"name":{"ja":"豚骨ラーメン","en":"Tonkotsu Ramen","ro":"Ramen Tonkotsu"},"category":{"ja":"ディナー","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["豚脊髄骨1.2kg（下茹でする）","新鮮な細ラーメン麺300g","濃口醤油大さじ3（タレ用）","みりん大さじ2","チャーシュー200g（1cm厚に切る）","半熟ラーメン卵2個（半分に切る）","メンマ80g（水気を切る）","海苔2枚（半分に切る）","ねぎ2本（薄切り）","にんにく4片（つぶす）","生姜30g（皮をむいてスライス）","焙煎ごま油小さじ1"],"en":["1.2kg pork marrow bones, blanched","300g fresh thin ramen noodles","3 tbsp dark soy sauce (for tare)","2 tbsp mirin","200g chashu pork belly, sliced 1cm thick","2 soft-boiled ramen eggs, halved","80g bamboo shoots (menma), drained","2 sheets nori, halved","2 spring onions, thinly sliced","4 cloves garlic, crushed","30g fresh ginger, peeled and sliced","1 tsp toasted sesame oil"],"ro":["1,2 kg oase de porc (măduvă), opărite","300g tăiței ramen proaspeți subțiri","3 linguri sos de soia închis (pentru tare)","2 linguri mirin","200g burtă de porc chashu, feliată la 1 cm grosime","2 ouă ramen fierte moale, tăiate în jumătate","80g lăstari de bambus (menma), scurși","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate subțire","4 căței usturoi, zdrobiți","30g ghimbir proaspăt, curățat și feliat","1 linguriță ulei de susan prăjit"]},"howIsMade":{"ja":"豚骨を沸騰した湯で10分下茹でし、ザルに上げて冷水でよく洗う。大きな鍋に3Lの水と骨を入れ、強火で沸騰させたらそのまま10〜12時間グラグラ煮続ける——弱火では白濁しない。水が減ったら足す。豚バラをしっかり巻いてたこ糸で結び、乾いたフライパンで全面に焼き色をつけてから、醤油大さじ3・みりん大さじ2・酒大さじ1・水100mlを加え、極弱火で90分煮込む。20分休ませてから1cm厚に切る。タレ：醤油大さじ4＋みりん大さじ2を小鍋で3分煮立てて冷ます。麺を袋の通り茹でて湯切り。各丼にタレ大さじ2を入れ、熱いスープを400ml注いだら、チャーシュー・半熟卵・メンマ・海苔・ねぎをのせ、ごま油を数滴たらす。","en":"Blanch pork bones in boiling water for 10 minutes, drain and rinse under cold water. Transfer to a large pot with 3L cold water, bring to a rolling boil and hold it there — not a simmer — for 10 to 12 hours, topping up with water as needed; the hard boil breaks down collagen and turns the broth white. Roll pork belly tightly, tie with kitchen string, sear all sides in a dry pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on the lowest heat for 90 minutes; rest 20 minutes, slice 1cm thick. Make tare: 4 tbsp soy sauce + 2 tbsp mirin, simmer 3 minutes, cool. Cook noodles per packet, drain. Spoon 2 tbsp tare into each bowl, ladle 400ml hot broth, then top with chashu slices, halved egg, bamboo shoots, nori and spring onion. Finish with sesame oil."}},{"id":182,"servings":2,"tipType":"meat","timeMins":{"total":360,"active":90},"pairingsType":"japanese","origin":{"ja":"日本","en":"Japan","ro":"Japonia"},"name":{"ja":"醤油ラーメン","en":"Shoyu Ramen","ro":"Ramen Shoyu"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["鶏がらスープ1.5L","醤油大さじ2","みりん大さじ1","酒大さじ1","豚バラ肉400g（巻いてたこ糸で結ぶ）","卵4個（Lサイズ）","生ラーメン麺300g","メンマ100g（水洗い）","海苔4枚","ねぎ3本（薄切り）","なると4枚","ごま油小さじ1"],"en":["1.5L chicken bone stock","2 tbsp soy sauce","1 tbsp mirin","1 tbsp sake","400g pork belly, rolled and tied with kitchen string","4 large eggs","300g fresh ramen noodles","100g bamboo shoots (menma), rinsed","4 sheets nori","3 spring onions, thinly sliced","4 slices narutomaki fish cake","1 tsp sesame oil"],"ro":["1,5 L supă de oase de pui","2 linguri sos de soia","1 lingură mirin","1 lingură sake","300g burtă de porc, rulată și legată","4 ouă mari","300g tăiței ramen proaspeți","100g lăstari de bambus (menma), clătiți","4 foi alge nori","3 cepe verzi, feliate subțire","4 felii pastă de pește narutomaki","1 linguriță ulei de susan"]},"howIsMade":{"ja":"鶏がらスープに生姜1片（5cm）・にんにく3かけ・ねぎ2本を加えて3〜4時間じっくり煮出し、こして不要なものを取り除く。醤油・みりん・酒を小鍋に合わせて5分煮立て、アルコールを飛ばす——これが醤油ダレ。豚バラをしっかり巻いてたこ糸で縛り、全面をしっかり焼き色をつけ、醤油大さじ3・みりん大さじ2・酒大さじ1・水100mlで弱火1.5時間煮込む；15分休ませてから1cm厚みに切る。卵は6分30秒ジャスト茹でて冷水で冷まし、殻をむいてチャーシューの煮汁に最低4時間漬け込む。麺を袋の指示通り茹でて水を切り、熱いスープをどんぶりに注ぎ（醤油ダレ大さじ2/丼）、麺をのせ、チャーシュー・半熟卵・メンマ・海苔・ねぎ・なると・ごま油少々で仕上げる。","en":"Simmer chicken bone stock with a 5cm piece of ginger, 3 garlic cloves and 2 spring onions for 3–4 hours, strain and discard solids. Mix soy sauce, mirin and sake in a small pan, simmer 5 minutes to cook off the alcohol — this is the shoyu tare. Roll pork belly tightly, tie with kitchen string, sear on all sides in a hot pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on low heat for 1.5 hours; rest 15 minutes before slicing into 1cm rounds. Soft-boil eggs exactly 6.5 minutes, cool in cold water, peel and submerge in the remaining chashu braising liquid for at least 4 hours. Cook noodles per packet, drain; ladle hot broth into bowls (2 tbsp shoyu tare per bowl), add noodles and top with sliced chashu, halved egg, bamboo shoots, nori, spring onions, narutomaki and a drizzle of sesame oil."}},{"id":183,"servings":2,"tipType":"def","pairingsType":"japanese","origin":{"ja":"日本","en":"Japan","ro":"Japonia"},"name":{"ja":"味噌ラーメン","en":"Miso Ramen","ro":"Ramen Miso"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["鶏がらまたは豚骨スープ1.5L","赤または白味噌大さじ3","生ラーメン麺300g","豚ひき肉150g","コーン缶80g（水気を切る）","無塩バター大さじ1","メンマ60g（水気を切ってスライス）","半熟味付け卵2個（半分に切る）","海苔2枚（半分に切る）","ねぎ2本（小口切り）","焙煎ごま小さじ1","もやし80g（さっと茹でる）"],"en":["1.5L chicken or pork bone broth","3 tbsp red or white miso paste","300g fresh ramen noodles","150g ground pork","80g canned corn kernels, drained","1 tbsp unsalted butter","60g bamboo shoots, drained and sliced","2 soft-boiled ramen eggs, halved","2 sheets nori, halved","2 spring onions, sliced","1 tsp toasted sesame seeds","80g fresh bean sprouts, blanched"],"ro":["1,5L supă de oase de pui sau porc","3 linguri pastă miso roșu sau alb","300g tăiței ramen proaspeți","150g carne tocată de porc","80g porumb din conservă, scurs","1 lingură unt nesărat","60g lăstari de bambus, scurși și feliați","2 ouă fierte moale, marinate, tăiate în jumătate","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate","1 linguriță semințe de susan prăjit","80g muguri de fasole proaspeți, opăriți"]},"howIsMade":{"ja":"強火にかけたフライパンやウォックでにんにくと豚ひき肉を炒め、ひき肉をほぐしながら色が変わるまで火を通す。味噌を加えて60秒炒め、少し焦がし色をつける。熱いスープを注ぎ、弱めの沸騰状態に保つ——味噌を入れたら強火にしない。バターを加えて溶けるまで混ぜる。麺は別で茹でて水気を切る。麺を二つの丼に分け、味噌スープをかける。コーン・もやし・味付け卵・メンマ・海苔・ねぎを盛り、ごまを最後に散らす。","en":"Sauté garlic and ground pork in a wok over high heat, breaking up the meat as it cooks, until no pink remains. Add miso paste and stir-fry 60 seconds until it darkens slightly. Pour in hot broth and bring to a low simmer — do not boil hard once miso is in or it loses its fermented edge. Add butter and stir until melted. Cook noodles per packet, drain. Divide noodles between two bowls, ladle miso broth over. Top with corn, bean sprouts, halved ramen egg, bamboo shoots, nori and spring onion. Scatter sesame seeds last."}},{"id":184,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":480,"prot":22,"carb":38,"fat":26,"fib":3},"origin":{"ja":"日本","en":"Japan","ro":"Japonia"},"name":{"ja":"天ぷら","en":"Tempura","ro":"Tempura"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["大正海老 400 g（殻つき 8〜12 尾、頭つき・尾を残して殻を剥く）、背わたを取って水気を完全に拭く","薩摩芋 約 200 g、皮を剥いて厚さ 5 mm の輪切り","かぼちゃ 200 g、皮つきのまま 5 mm の半月切り","茄子 1 本、斜めに 1 cm 幅でスライス","生椎茸 6 個、軸を切り落とし、傘の表面に十文字の切れ目を入れる","ししとう 100 g、各個フォークで穴を開け破裂防止","衣（揚げる直前に最後に作る）: 卵 1 個、よく冷えた炭酸水 250 ml、ふるった薄力粉 150 g","打ち粉用の薄力粉 30 g（衣にくぐらせる前にまぶす）","揚げ油 1.5 L（米油または植物油）","天つゆ用: 出汁 200 ml、醤油 60 ml、みりん 60 ml","大根 30 g、細かくおろして軽く水気を絞る","生姜 10 g、細かくおろす","細かい海塩とくし切りレモン、お好みで"],"en":["400 g large prawns (8–12 head-on, peeled but tails on), deveined and patted bone-dry","1 small Japanese sweet potato (~200 g), peeled and cut into 5 mm rounds","200 g kabocha squash, cut into 5 mm half-moons (skin left on)","1 Japanese eggplant, cut on the bias into 1 cm slices","6 fresh shiitake mushrooms, stems trimmed, caps scored with an X","100 g shishito or thin green peppers, each pricked with a fork so they don't burst","For the batter (mix LAST, just before frying): 1 large egg, 250 ml ice-cold sparkling water, 150 g plain (cake) flour, sifted","30 g extra plain flour for dusting the pieces before dipping","1.5 L neutral oil for deep-frying (rice bran or vegetable)","For the tentsuyu dipping sauce: 200 ml dashi, 60 ml soy sauce, 60 ml mirin","30 g daikon, finely grated and lightly squeezed","10 g fresh ginger, finely grated","Fine sea salt and lemon wedges, to serve"],"ro":["400 g creveți mari (8–12 bucăți cu cap, decojiți dar cu coadă), curățați de vinișor și șterși bine de umiditate","1 cartof dulce japonez mic (~200 g), curățat și tăiat rondele de 5 mm","200 g dovleac kabocha, tăiat semilune de 5 mm (cu coajă)","1 vânătă japoneză, tăiată oblic în felii de 1 cm","6 ciuperci shiitake proaspete, fără picioare, capul crestat în X","100 g ardei shishito sau ardei verzi subțiri, fiecare înțepat cu furculița ca să nu plesnească","Pentru aluat (se amestecă LA FINAL, chiar înainte de prăjit): 1 ou mare, 250 ml apă minerală foarte rece, 150 g făină simplă cernută","30 g făină simplă suplimentară pentru pudrat bucățile înainte de înmuierea în aluat","1.5 L ulei neutru pentru prăjit (de orez sau vegetal)","Pentru sosul tentsuyu: 200 ml dashi, 60 ml sos de soia, 60 ml mirin","30 g daikon, ras fin și stors ușor","10 g ghimbir proaspăt, ras fin","Sare fină de mare și felii de lămâie, pentru servit"]},"howIsMade":{"ja":"海老と野菜を完全に水気を切り、海老の腹側に浅く三か所切り込みを入れて背骨に沿って軽く押し、揚げたときに丸まらず真っ直ぐになるようにする。\n\n天つゆは出汁・醤油・みりんをさっと沸かしてアルコールを飛ばし、小さな器に分けて、おろし大根とおろし生姜を別添えで横に置く。\n\n厚手の鍋で油を175℃に熱し、温度は必ず温度計で測る。\n\n揚げる直前に、冷やしたボウルで卵と冷えた炭酸水を合わせ、ふるった粉を一度に加えて五〜八回だけ混ぜる ── 衣には乾いた粉の筋が残っている状態でよい。\n\n打ち粉用の粉を各具材に薄くまぶし、衣にくぐらせて一度に四〜五個ずつ油に滑り込ませる。海老と椎茸は約90秒、茄子とかぼちゃは2分、薩摩芋は3分、ししとうは1分が目安で、衣は淡い象牙色を保つ。\n\n紙を敷いた揚げ網に取り、すぐに食卓へ運ぶ。天つゆに大根と生姜を溶いてつけるか、塩を一つまみとレモンを絞って野菜を味わう。","en":"Pat the prawns and vegetables completely dry, then make three shallow cuts on the underside of each prawn and press gently along the spine so they fry straight rather than curling.\n\nFor the tentsuyu, bring the dashi, soy sauce and mirin briefly to a simmer to cook off the alcohol, then divide between small dipping bowls and set the grated daikon and ginger alongside.\n\nHeat the oil in a heavy pot to 175°C, measured with a probe thermometer.\n\nJust before frying, beat the egg into the ice-cold sparkling water in a chilled bowl, tip in the sifted flour all at once and stir only five to eight strokes — the batter should still show streaks of dry flour.\n\nDust each piece lightly with the extra flour, dip into the batter, and slip into the oil four or five at a time; prawns and shiitake take about 90 seconds, eggplant and kabocha 2 minutes, sweet potato 3 minutes, shishito a minute, and the crust should stay pale ivory.\n\nLift onto a wire rack set over paper and serve straight away, with the tentsuyu, daikon and ginger to stir in, or the vegetables with a pinch of fine salt and a squeeze of lemon."}},{"id":185,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":280,"prot":7,"carb":52,"fat":4,"fib":2},"origin":{"ja":"日本","en":"Japan","ro":"Japonia"},"name":{"ja":"おにぎり","en":"Onigiri","ro":"Onigiri"},"category":{"ja":"ランチ","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["短粒米 500 g（コシヒカリまたは寿司米）","炊飯用の冷水 600 ml（米:水 ~1:1.1）","手水（てず）用: ぬるま湯 200 ml + 細かい塩 小さじ1.5","焼海苔 4 枚、約 3 cm 幅 × 海苔の長さの帯にカット","具材1 — ツナマヨ: ツナ缶（油切り）80 g、日本のマヨネーズ 大さじ1.5、醤油 小さじ½","具材2 — 梅干し: 種を取った梅干し 60 g、フォークで軽く潰す","具材3 — 塩鮭: 焼いた塩鮭 100 g、皮を取って身をほぐす","具材4 — おかか: かつおぶし 8 g + 醤油 小さじ1","プレーンおにぎり用: ふりかけ 大さじ2 で外側にまぶす","お好みで: 表面に白ごまを少々"],"en":["500 g Japanese short-grain rice (Koshihikari or sushi rice)","600 ml fresh cold water for cooking (rice to water ratio ~1:1.1)","For the tezu (finger water): 200 ml warm water + 1.5 tsp fine sea salt","4 sheets toasted nori, cut into strips about 3 cm wide × the length of the sheet","Filling option 1 — tuna mayo: 80 g canned tuna (drained), 1.5 tbsp Japanese mayonnaise, ½ tsp soy sauce","Filling option 2 — umeboshi: 60 g pitted salted plums, lightly mashed with a fork","Filling option 3 — shiozake (grilled salted salmon): 100 g salmon fillet grilled and flaked, with the skin removed","Filling option 4 — okaka: 8 g bonito flakes mixed with 1 tsp soy sauce","For plain onigiri: 2 tbsp furikake (rice seasoning), to coat the outside","Optional: a few sesame seeds for the surface of plain ones"],"ro":["500 g orez japonez cu bobul scurt (Koshihikari sau orez pentru sushi)","600 ml apă rece proaspătă pentru fiert (raport orez:apă ~1:1.1)","Pentru tezu (apa de mâini): 200 ml apă caldă + 1.5 linguriță sare fină de mare","4 foi de nori prăjit, tăiate fâșii de ~3 cm lățime × lungimea foii","Umplutură opțiunea 1 — ton cu maioneză: 80 g ton la conservă (scurs), 1.5 lingură maioneză japoneză, ½ linguriță sos de soia","Umplutură opțiunea 2 — umeboshi: 60 g prune sărate fără sâmburi, ușor strivite cu furculița","Umplutură opțiunea 3 — shiozake (somon sărat la grătar): 100 g file de somon făcut la grătar, fără piele, fărâmițat","Umplutură opțiunea 4 — okaka: 8 g fulgi de bonito amestecați cu 1 linguriță sos de soia","Pentru onigiri simplu: 2 linguri furikake (condiment pentru orez), pentru exterior","Opțional: câteva semințe de susan pentru exterior"]},"howIsMade":{"ja":"米を冷水で4〜5回研ぎ、研ぎ汁がほぼ澄むまで繰り返したら、ザルに上げて20分置く。厚手の鍋か炊飯器に米と冷水600 mlを入れて炊き、炊き上がったら火を止めたまま蓋をして10分蒸らす。\n\n蒸らしの間に、梅干しはフォークで潰し、ツナ缶を日本のマヨネーズと和えてクリーミーにし、塩鮭は身をほぐす ── おにぎり1個に使うのは具材大さじ1ほどでよい。\n\n温かい水に塩を溶かして手水（てず）を作る。手のひらに米が張りつくのを防ぎ、外側にほんのりと塩味をのせる役目を担う。\n\n炊きたての米を大きなトレイにあけ、しゃもじで切るようにほぐし、握れる程度の温かさになるまで冷ます。\n\n手のひらを手水で湿らせ、米を100 gほど手に取って中央にくぼみを作り、具を大さじ1のせて米で包む。手を丸めて三つの平らな面を持つ三角形に握る ── しっかりと、しかし潰さずに。\n\n食べる直前に三角形の底辺に海苔の帯を巻き、海苔のパリッとした食感を残す。具なしのおにぎりは、海苔の代わりに外側にふりかけをまぶす。常温で4時間以内に食べきる。","en":"Rinse the rice in cold water four or five times until the water runs almost clear, drain in a strainer for 20 minutes, then cook with the 600 ml of fresh water in a heavy pot or rice cooker; once cooked, rest off the heat with the lid on for 10 minutes.\n\nWhile the rice rests, mash the umeboshi with a fork, mix the tuna with the Japanese mayonnaise into a creamy paste, and flake the grilled salmon — each onigiri needs only about a tablespoon of filling.\n\nDissolve the salt in the warm water to make the tezu; this is the finger water that keeps the rice from sticking to your palms and lightly salts the outside.\n\nTip the hot rice onto a wide tray, fluff gently with a wooden paddle and let it cool until just warm enough to handle.\n\nWet your palms in the tezu, take about 100 g of rice in your palm, press a hollow in the centre, drop in a tablespoon of filling and gather the rice around it; cup your hand and press into a triangle with three flat faces, firm but not crushed.\n\nWrap a strip of nori around the base of each triangle just before eating so the seaweed stays crisp; for plain onigiri, roll the outside in furikake instead. Eat at room temperature within 4 hours."}},{"id":186,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":360,"prot":36,"carb":8,"fat":18,"fib":1},"origin":{"ja":"日本","en":"Japan","ro":"Japonia"},"name":{"ja":"焼き鳥","en":"Yakitori","ro":"Yakitori"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["鶏もも肉（皮付き、骨なし）600 g、2.5 cm 角に切る","太めの長ねぎ 6 本（または白ねぎ 2 本）、白と薄緑の部分を 3 cm の長さに切る（合計 150 g 程度）","短い竹串 16 本（15 cm）、冷水に 30 分浸す","タレ用: 濃口醤油 120 ml、みりん 120 ml、清酒 60 ml、薄口きび砂糖 30 g","塩串用の細かい海塩","焼き網に塗る無味の油 小さじ 1","七味唐辛子（添えて）","くし切りレモン（添えて）"],"en":["600 g boneless, skin-on chicken thighs, cut into 2.5 cm cubes","6 fat spring onions (or 2 negi), white and pale green parts cut into 3 cm pieces (~150 g total)","16 short bamboo skewers (15 cm), soaked in cold water for 30 minutes","For the tare: 120 ml dark soy sauce, 120 ml mirin, 60 ml sake, 30 g light brown sugar","Fine sea salt for the shio skewers","1 tsp neutral oil for the grate","Shichimi togarashi, to serve","Lemon wedges, to serve"],"ro":["600 g pulpe de pui dezosate cu piele, tăiate cuburi de 2.5 cm","6 cepe verzi mari (sau 2 negi), partea albă și verde-deschis tăiată bucățele de 3 cm (~150 g)","16 frigărui scurte de bambus (15 cm), înmuiate în apă rece 30 de minute","Pentru tare: 120 ml sos de soia închis, 120 ml mirin, 60 ml sake, 30 g zahăr brun deschis","Sare fină de mare pentru frigăruile shio","1 linguriță ulei neutru pentru grătar","Shichimi togarashi, pentru servit","Felii de lămâie, pentru servit"]},"howIsMade":{"ja":"鶏もも肉を 2.5 cm 角に切り、長ねぎの白い部分を 3 cm の長さに切り、竹串は焦げ防止のために冷水に 30 分浸しておく。\n\nタレは小鍋に醤油、みりん、清酒、きび砂糖を合わせて 10 分ほど煮詰め、軽くシロップ状になったら室温まで冷ます。\n\n串は二種類で打つ。ねぎまは鶏・ねぎ・鶏・ねぎ・鶏と交互に、もも串は鶏のみを隙間なく、ただし潰さない程度に詰める。\n\n炭火または厚手のグリルパンを強火で熱し、網に薄く油を塗る。\n\n串は皮の側、もしくは脂の多い側を下にして 3〜4 分焼き、深いきつね色になったら裏返してさらに 2〜3 分焼く。\n\nタレ串は冷めたタレに浸し、網に戻して 30 秒ほど焼き付ける作業をもう一度繰り返す。塩串は焼き上がりに細かい塩をひとつまみ。すぐに七味とくし切りレモンを添えて供する。","en":"Cut the chicken thigh into 2.5 cm cubes and the white parts of the spring onions into 3 cm pieces, then soak the bamboo skewers in cold water for 30 minutes so they don't burn on the grill.\n\nFor the tare, simmer the soy sauce, mirin, sake and brown sugar in a small pan for about 10 minutes until lightly syrupy, then let it cool to room temperature.\n\nThread the skewers in two styles: negima alternates chicken, scallion, chicken, scallion, chicken; momo is just chicken cubes packed close together but not squashed.\n\nHeat a charcoal grill or a heavy grill pan over high heat and lightly oil the grate.\n\nLay the skewers down with the skin or fattiest side first and grill for 3–4 minutes until deep golden, then flip and cook another 2–3 minutes.\n\nFor tare skewers, dip in the cooled sauce, return to the grill for 30 seconds to glaze, then dip and glaze once more; season the shio skewers with a pinch of salt straight off the heat. Serve at once with shichimi togarashi and lemon."}},{"id":187,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":520,"prot":38,"carb":22,"fat":28,"fib":6},"origin":{"ja":"メキシコ","en":"Mexico","ro":"Mexic"},"name":{"ja":"モレ・ポブラーノ","en":"Mole Poblano","ro":"Mole Poblano"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["ミックスドライチリ 80 g — アンチョ 3 本 + ムラート 3 本 + パシリャ 2 本 — ヘタと種を除く","アドボ漬けチポトレ 1 本と、そのソース 大さじ 1","皮なしアーモンド 100 g と生ピーナッツ 80 g","生白ごま 30 g（仕上げ用に少し別取り）とレーズン 60 g","完熟大玉トマト 2 個を半分に、白玉ねぎ 1 個を 4 等分、皮付きにんにく 3 片","シナモンスティック 1 本、クローブ 2 粒、スターアニス 1 個、黒粒胡椒 6 粒","コーントルティーヤ 2 枚、ちぎる — 伝統的なとろみ素材","メキシカンチョコレート 60 g、砕く（またはダークチョコ 50 g + シナモン小さじ 1 + 薄口黒糖大さじ 1）","塩抜きチキンスープ 1.2 L、温かい状態で","ラード（マンテカ）大さじ 3、または無味の油","骨付き鶏もも肉 4 本、塩水で 25 分茹で、水気を拭く","細かい海塩 小さじ 1、砂糖ひとつまみ","添え物: 炊いた白米、温かいコーントルティーヤ、新鮮なコリアンダーの葉"],"en":["80 g mixed dried chiles — 3 ancho + 3 mulato + 2 pasilla — stemmed and seeded","1 chipotle chile in adobo, plus 1 tbsp of its sauce","100 g blanched almonds and 80 g raw peanuts","30 g raw sesame seeds (plus extra to garnish) and 60 g raisins","2 large ripe tomatoes, halved; 1 small white onion, quartered; 3 garlic cloves, unpeeled","1 cinnamon stick, 2 cloves, 1 star anise and 6 black peppercorns","2 corn tortillas, torn into pieces — the traditional thickener","60 g Mexican chocolate, broken up (or 50 g dark chocolate + 1 tsp cinnamon + 1 tbsp light brown sugar)","1.2 L unsalted chicken stock, kept warm","3 tbsp lard (manteca) or neutral oil","4 bone-in chicken thighs, poached in salted water for 25 minutes and patted dry","1 tsp fine sea salt and a small pinch of sugar","To serve: cooked white rice, warm corn tortillas, fresh coriander leaves"],"ro":["80 g de ardei iuți uscați amestecați — 3 ancho + 3 mulato + 2 pasilla — fără codiță și seminţe","1 ardei chipotle în sos adobo, plus 1 lingură din sosul lui","100 g de migdale blanşate și 80 g de arahide crude","30 g de seminţe de susan crude (plus în plus pentru garnitură) și 60 g de stafide","2 roșii mari coapte, tăiate jumătăți; 1 ceapă albă mică, tăiată sferturi; 3 căţei de usturoi, necurăţaţi","1 baton de scorţișoară, 2 cuișoare, 1 stea de anason și 6 boabe de piper negru","2 tortilla de porumb, rupte în bucăţi — îngroșătorul tradiţional","60 g de ciocolată mexicană, fărâmiţată (sau 50 g de ciocolată neagră + 1 linguriţă de scorţișoară + 1 lingură de zahăr brun deschis)","1.2 L de supă de pui nesărată, ţinută caldă","3 linguri de untură (manteca) sau ulei neutru","4 pulpe de pui cu os, fierte în apă sărată 25 de minute și șterse","1 linguriţă de sare fină de mare și un vârf mic de zahăr","Pentru servit: orez alb fiert, tortilla de porumb calde, frunze de coriandru proaspăt"]},"howIsMade":{"ja":"乾燥唐辛子を厚手のフライパンで強めの中火、片面約 30 秒ずつ空炒りして香りを引き出し、ボウルに移して熱湯を注ぎ、20 分浸す。\n\n同じフライパンで、アーモンド、ピーナッツ、白ごま、レーズン、ホールスパイスを少しずつ薄く色づくまで炒る — それぞれ約 2 分 — 取り出しておく。\n\nトマトの半割、玉ねぎ、皮付きにんにくを直火または強めのブロイラーで斑に黒くなるまで焼き、にんにくは触れる程度に冷めたら皮をむく。\n\n唐辛子の水気を切り（戻し汁はとっておく）、焼いた野菜、チポトレとそのソース、炒ったナッツとごま、レーズン、スパイス、ちぎったトルティーヤと一緒にミキサーへ。温かい鶏スープを 500 ml ほど加え、なめらかな黒っぽいペーストにする。\n\n厚手の鍋でラードを中強火で熱し、ペーストを流し入れて 10〜15 分絶えず混ぜる。香りと脂が一体になるにつれ、モレは色を深め、とろみと艶を増す。\n\n残り 700 ml の鶏スープと砕いたチョコレートを加え、頻繁に混ぜながら 30〜40 分弱火で煮込み、スプーンの背に絡む濃度に整える。塩とひとつまみの砂糖で味を整える。\n\n茹でた鶏もも肉をモレに沈め、さらに 10 分煮てソースをまとわせる。\n\n深皿に鶏を盛り、たっぷりのモレをかけ、取り置いたごま、コリアンダーの葉を散らし、白米と温かいコーントルティーヤを添えて供する。","en":"Toast the dried chiles in a dry heavy pan over medium heat for about 30 seconds per side until fragrant, then transfer to a bowl, cover with hot water and soak for 20 minutes.\n\nIn the same pan, toast the almonds, peanuts, sesame seeds, raisins and whole spices in small batches until just golden — about 2 minutes each — and set aside.\n\nChar the tomato halves, onion quarters and unpeeled garlic directly over a flame or under a hot broiler until blackened in patches, then peel the garlic once cool enough to handle.\n\nDrain the chiles (keeping the soaking water) and blend them with the charred vegetables, chipotle and its sauce, toasted nuts and seeds, raisins, spices and torn tortillas, adding about 500 ml of warm chicken stock to make a smooth dark paste.\n\nHeat the lard in a heavy pot over medium-high heat, pour in the paste and stir constantly for 10–15 minutes; the mole will darken, thicken and turn glossy as the flavours fry together.\n\nStir in the remaining 700 ml of chicken stock and the broken chocolate, then simmer gently for 30–40 minutes, stirring often, until the sauce coats the back of a spoon; season with the salt and a small pinch of sugar.\n\nSlide the poached chicken thighs into the mole and simmer 10 minutes more so they take on the sauce.\n\nServe the chicken in shallow bowls, ladle generous mole over the top, and finish with the reserved sesame seeds, coriander leaves, white rice and warm corn tortillas on the side."}},{"id":188,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":480,"prot":18,"carb":38,"fat":28,"fib":6},"origin":{"ja":"メキシコ","en":"Mexico","ro":"Mexic"},"name":{"ja":"チラキレス","en":"Chilaquiles","ro":"Chilaquiles"},"category":{"ja":"朝食","en":"Breakfast","ro":"Mic dejun"},"ingredients":{"ja":["前日のコーントルティーヤ 200 g、八等分（または市販のトトポス）","揚げ油 500 ml（または浅く揚げ焼きする場合は大さじ 4）","サルサ・ロハ用: 完熟トマト 6 個（約 600 g）、グアヒージョ唐辛子 2 本＋デ・アルボル唐辛子 1 本（ヘタと種を除く）、にんにく 1 片、白玉ねぎ ½ 個","細かい海塩 小さじ 1、ソース用の無味の油 大さじ 1","大きい卵 4 個、目玉焼き（任意だが定番）","メキシカンクレマ 100 ml（または牛乳でゆるめたサワークリーム）","ケソ・フレスコ 80 g、ほぐして（または穏やかなフェタ）","小さな赤玉ねぎ ½ 個、ごく薄切り","新鮮なコリアンダー少々、葉のみ","完熟アボカド 1 個、提供直前にスライス","ハラペーニョのピクルス、お好みで"],"en":["200 g day-old corn tortillas, cut into eighths (or store-bought totopos)","500 ml neutral oil for frying (or 4 tbsp for shallow-frying)","For the salsa roja: 6 ripe tomatoes (~600 g), 2 guajillo chiles + 1 chile de árbol (stemmed and seeded), 1 garlic clove, ½ small white onion","1 tsp fine sea salt and 1 tbsp neutral oil for the salsa","4 large eggs, fried sunny-side-up (optional but classic)","100 ml Mexican crema (or sour cream thinned with milk)","80 g queso fresco, crumbled (or mild feta)","½ small red onion, very thinly sliced","A small handful of fresh coriander, leaves picked","1 ripe avocado, sliced just before serving","Pickled jalapeños, to taste"],"ro":["200 g tortilla de porumb de o zi, tăiate în opt (sau totopos cumpărate)","500 ml ulei neutru pentru prăjit (sau 4 linguri pentru prăjit superficial)","Pentru salsa roja: 6 roșii coapte (~600 g), 2 ardei guajillo + 1 ardei de árbol (fără codiță și semințe), 1 cățel de usturoi, ½ ceapă albă mică","1 linguriță sare fină de mare și 1 lingură ulei neutru pentru salsa","4 ouă mari, ochiuri (opțional dar tradițional)","100 ml crema mexicană (sau smântână subțiată cu lapte)","80 g queso fresco, sfărâmat (sau feta blândă)","½ ceapă roșie mică, tăiată felii foarte subțiri","Un mic mănunchi de coriandru proaspăt, doar frunzele","1 avocado copt, feliat chiar înainte de servit","Jalapeños murați, după gust"]},"howIsMade":{"ja":"前日のトルティーヤを八等分に切り、175℃の油で 90 秒ほど揚げてきつね色に仕上げる、もしくは大さじ 4 の油で揚げ焼きにする。網に上げ、温かいうちに塩を軽くふる。\n\nサルサは、グアヒージョとデ・アルボル唐辛子を乾いたフライパンで片面 20 秒ずつ香りが立つまで空炒りし、熱湯で 10 分戻す。その間にトマト、にんにく、玉ねぎを強めのブロイラー、または直火で部分的に黒くなるまで焼く。\n\n戻した唐辛子の水気を切り、焼いた野菜・塩小さじ 1・戻し汁少々と一緒にミキサーでなめらかなソースにする。\n\n広めのフライパンで油大さじ 1 を熱し、ソースを注いで 5 分ほど混ぜながら煮詰める。色が深まり艶が出れば良い。\n\n揚げたトルティーヤを加えて中火で 1〜2 分、ソースに優しくくぐらせる。ソースを吸わせつつ、歯ごたえを少し残す。\n\nすぐに盛り、好みで目玉焼きを乗せ、クレマをかけ、ケソ・フレスコ、紫玉ねぎ、コリアンダー、アボカド、ハラペーニョのピクルスを散らす。","en":"Cut the day-old tortillas into eighths and either deep-fry them at 175°C until golden and crisp, about 90 seconds per batch, or shallow-fry in 4 tablespoons of oil; drain on a rack and salt lightly while still warm.\n\nFor the salsa, toast the guajillo and árbol chiles in a dry pan for 20 seconds per side until fragrant, then soak in hot water for 10 minutes; meanwhile, char the tomatoes, garlic and onion under a hot broiler or directly over a flame until blackened in patches.\n\nDrain the chiles and blend with the charred vegetables, 1 teaspoon of salt and a splash of the chile-soaking water until smooth.\n\nHeat 1 tablespoon of oil in a wide pan, pour in the salsa and simmer for about 5 minutes, stirring, until it deepens in colour and looks glossy.\n\nTip in the crisp tortillas and gently fold them through the salsa over medium heat for a minute or two — they should soak up sauce while keeping some bite.\n\nPlate at once, top with the fried eggs if using, drizzle with crema, and scatter queso fresco, sliced red onion, coriander, avocado and pickled jalapeños over the top."}},{"id":189,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":9,"carb":70,"fat":24,"fib":1},"origin":{"ja":"メキシコ","en":"Mexico","ro":"Mexic"},"name":{"ja":"トレス・レチェス・ケーキ","en":"Tres Leches Cake","ro":"Tort Tres Leches"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"ingredients":{"ja":["L 卵 5 個、卵黄と卵白に分け、室温に戻す","グラニュー糖 200 g、ホイップ用に別途 30 g","薄力粉 200 g とベーキングパウダー 小さじ 1、合わせてふるう","スポンジ用バニラエクストラクト 小さじ 1、クリーム用に小さじ ½","加糖練乳 1 缶（397 g）","無糖練乳（evaporated milk）1 缶（340 g）","全脂牛乳 200 ml と生クリーム 50 ml（三種ミルクの浸し液）","冷えた生クリーム 250 ml（ホイップ用）、仕上げ用シナモンパウダー"],"en":["5 large eggs, separated, at room temperature","200 g caster sugar, plus 30 g for the whipped cream","200 g plain flour and 1 tsp baking powder, sifted together","1 tsp vanilla extract for the sponge, plus ½ tsp for the cream","1 can (397 g) sweetened condensed milk","1 can (340 g) evaporated milk","200 ml whole milk and 50 ml heavy cream (the three-milk soak)","250 ml cold heavy cream for whipping, plus ground cinnamon for dusting"],"ro":["5 ouă mari, separate, la temperatura camerei","200 g zahăr tos, plus 30 g pentru frișcă","200 g făină albă și 1 linguriță praf de copt, cernute împreună","1 linguriță esență de vanilie pentru blat, plus ½ linguriță pentru frișcă","1 cutie (397 g) lapte condensat îndulcit","1 cutie (340 g) lapte evaporat","200 ml lapte integral și 50 ml smântână pentru frișcă (amestec pentru îmbibare)","250 ml smântână rece pentru frișcă (35% grăsime), plus scorțișoară măcinată pentru pudrat"]},"howIsMade":{"ja":"オーブンを 175℃ に予熱し、23×33 cm の耐熱皿にバターを塗って薄く粉をふり、続けて卵白に塩ひとつまみを加えて軽い角が立つまで泡立て、100 g のグラニュー糖を少しずつ加えて艶のあるしっかりした角が立つまで泡立てる。\n\n卵黄に残りの 100 g のグラニュー糖とバニラを加えて 3〜4 分、色が淡くなり量が 3 倍になるまで泡立て、薄力粉とベーキングパウダーをふるい入れてゴムベラでさっくり合わせ、続けてメレンゲを 3 回に分けて加え、できるだけ空気を残しながら混ぜる。\n\n型に流し入れ、表面を平らにして 25〜30 分、深い黄金色になり指で押すと戻るまで焼き、そのまま型のなかで 30 分以上冷ます。\n\nジャグの中で加糖練乳・無糖練乳・牛乳と生クリームの混合液をよく混ぜ、冷ました生地に細い串で底まで全面に穴を開け、三種ミルクの液を全体に 3〜4 回に分けてゆっくり注ぐ — 液体が多すぎるように見えても、スポンジが全部吸ってくれる；覆って冷蔵庫で最低 4 時間、できれば一晩冷やす。\n\n供する直前に冷えた生クリームに 30 g のグラニュー糖と残りのバニラを加えて軽い角が立つまで泡立て、冷えたケーキの上に塗り広げ、シナモンパウダーをたっぷりとふる。","en":"Heat the oven to 175°C and butter and flour a 23×33 cm baking dish, then whisk the whites with a pinch of salt to soft peaks, beating in 100 g of the sugar a spoonful at a time until glossy and stiff.\n\nWhip the yolks with the remaining 100 g sugar and the vanilla for 3–4 minutes until pale and tripled, sift the flour and baking powder over them and fold in gently, then fold in the meringue in three additions, keeping as much air as you can.\n\nPour into the dish, level the top and bake 25–30 minutes until deep golden and springy at the centre, then cool in the dish for at least 30 minutes.\n\nWhisk the three milks together in a jug, pierce the cooled cake all over to the base with a thin skewer and pour the mixture across the surface in three or four slow passes — it looks like too much liquid, but the sponge drinks every drop; cover and refrigerate at least 4 hours, ideally overnight.\n\nJust before serving, whip the cold cream with the 30 g sugar and the remaining vanilla to soft peaks, spread it over the chilled cake and dust generously with ground cinnamon."}},{"id":190,"servings":6,"tipType":"fish","pairingsType":"french","nutrition":{"cal":480,"prot":50,"carb":30,"fat":18,"fib":4},"origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"ブイヤベース","en":"Bouillabaisse","ro":"Bouillabaisse"},"category":{"ja":"魚介","en":"Fish","ro":"Pește"},"ingredients":{"ja":["地中海の小型岩礁魚 800 g（カサゴ、ミシマオコゼ、ベラ — スープのベース用）、内臓を抜く","身のしっかりした地中海魚 1.2 kg、ぶつ切り（カサゴ、アンコウ、マトウダイ、アナゴ、ホウボウ — 少なくとも 4 種）、皮付き、ウロコ落とし済","大玉ねぎ 1 個、ポロネギ 2 本（白い部分のみ）、フェンネル 1 個、完熟トマト 4 個、にんにく 6 片","ブーケガルニ：タイム、ローリエ、パセリの茎、乾燥オレンジ皮 1 切れ、フェンネルシード 小さじ 1","サフラン 1 g（たっぷり一つまみ）、最後に加えるパスティス（Pernod）大さじ 2","オリーブオイル 100 ml、塩 小さじ 1、挽きたての黒こしょう","水 2 L（または淡いフィッシュフュメ）","前日のバゲットの薄切り 12〜15 枚（軽く焼く）、ルイユ（にんにく 3 片、サフラン 小さじ ½、カイエン 小さじ ¼、卵黄 1 個、オリーブオイル 200 ml、塩、スープに浸したパンひとかけ）"],"en":["800 g small Mediterranean rockfish (rascasse, weever, wrasse — for the broth), gutted","1.2 kg firm Mediterranean fish in chunks (rascasse, monkfish, John Dory, conger, gurnard — at least four species), skin on, scaled","1 large onion, 2 leeks (white parts only), 1 fennel bulb, 4 ripe tomatoes, 6 garlic cloves","Bouquet garni: thyme, bay, parsley stalks, a strip of dried orange peel, a teaspoon of fennel seeds","1 g saffron threads (a generous pinch), 2 tbsp pastis (Pernod) stirred in at the end","100 ml olive oil, 1 tsp salt, freshly ground pepper","2 L water (or light fish fumet)","12–15 slices of toasted day-old baguette and rouille (3 garlic cloves, ½ tsp saffron, ¼ tsp cayenne, 1 egg yolk, 200 ml olive oil, salt, a small piece of bread soaked in the broth)"],"ro":["800 g pești mici mediteraneeni de stâncă (rascassa, năsărel, vrana — pentru fond), eviscerați","1,2 kg pește mediteranean ferm tăiat bucăți (rascassa, lotă, Saint-Pierre, congru, grondin — minim patru specii), cu piele, scuamat","1 ceapă mare, 2 praz (doar partea albă), 1 bulb de fenicul, 4 roșii coapte, 6 căței de usturoi","Buchet garni: cimbru, foi de dafin, codițe de pătrunjel, coajă uscată de portocală, o linguriță de semințe de fenicul","1 g șofran (un vârf bun), 2 linguri de pastis (Pernod) adăugat la final","100 ml ulei de măsline, 1 linguriță sare, piper proaspăt măcinat","2 l apă (sau fumet uşor de pește)","12–15 felii de baghetă uscată prăjită și rouille (3 căței usturoi, ½ linguriță șofran, ¼ linguriță cayenne, 1 gălbenuș, 200 ml ulei de măsline, sare, o bucată de pâine înmuiată în fond)"]},"howIsMade":{"ja":"魚はすべて鱗を引き、内臓を抜いてよく洗う — 大きな魚は 3 cm 角に切り、頭と骨はスープ用に取り置き、小型の岩礁魚は丸ごと鍋に入れる。\n\n厚手の大鍋にオリーブオイル大さじ 4 を入れて中火で熱し、玉ねぎ・ポロネギ・フェンネルを色づけずに 10 分ほど蒸し炒めにし、刻んだトマトとにんにく 5 片を加えてさらに 5 分、果肉が崩れるまで煮る。\n\n小魚と大きな魚の頭・骨を加え、水 2 L を注ぎ、ブーケガルニ（タイム、ローリエ、パセリ、オレンジ皮、フェンネルシード）を加えて強火で 30〜40 分、小魚が完全に崩れるまで煮たのち、粗目の濾し器かムーランレギュムで強く押して全部を漉し出す — 骨・ハーブ・実は捨てる — 濾したスープを再び沸騰させ、塩味を整え、サフランを加える。\n\n身のしっかりした魚（アンコウ、アナゴ）を先に入れて 5〜6 分、その後やわらかい魚（カサゴ、マトウダイ）を加えてさらに 3〜4 分 — 魚はちょうど火が入った状態で、決して崩れていない — 火を止めてパスティスを回しかける。\n\nルイユは、残ったにんにく 1 片、塩、サフランをすり鉢でつぶし、スープに浸して絞ったパンを加え、卵黄を加え、最後にオリーブオイルを少しずつ垂らしながらマヨネーズ状になるまで混ぜたのち、2 段階で供する — まずスープを焼いたバゲットにかけ、その上にルイユを一さじのせ、続いて魚を別皿に盛り、ルイユを添える。","en":"Scale, gut and rinse all the fish — cut the larger ones into 3 cm chunks and keep the heads and bones for the broth, while the small rockfish go whole into the pot.\n\nIn a large heavy pot, heat 4 tablespoons of olive oil over medium heat and sweat the chopped onion, leeks and fennel without colour for about 10 minutes, then add the chopped tomatoes and 5 garlic cloves and cook another 5 minutes to a pulp.\n\nTip in the small fish and the heads and bones of the larger ones, cover with the 2 L of water, drop in the bouquet garni (thyme, bay, parsley, orange peel, fennel seeds) and simmer hard for 30–40 minutes until the small fish completely break down, then pass everything through a coarse sieve or food mill, pressing hard to extract every drop — bones, herbs and pulp discarded — bring the strained broth back to a rolling boil, taste for salt and stir in the saffron.\n\nSlip the firm fish (monkfish, conger) into the broth first and poach 5–6 minutes, then add the more delicate ones (rascasse, John Dory) for another 3–4 — they should be just opaque, never falling apart — and off the heat, swirl in the pastis.\n\nFor the rouille, pound the last garlic clove with the salt and saffron in a mortar, work in the bread (dipped in broth and squeezed), then the yolk, then olive oil in a thin stream, whisking constantly until thick like mayonnaise, then serve in two courses: the broth first, ladled over toasted baguette with a spoonful of rouille on top; the fish after, on a separate plate, with more rouille alongside."}},{"id":191,"servings":4,"tipType":"meat","pairingsType":"french","nutrition":{"cal":650,"prot":30,"carb":40,"fat":38,"fib":2},"origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"クロックムッシュ","en":"Croque Monsieur","ro":"Croque Monsieur"},"category":{"ja":"昼食","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["パン・ド・ミ（きめ細かい白いサンドイッチ用パン）の厚切り 8 枚、一日置いたもの","無塩バター 80 g、室温で柔らかくしたもの。ベシャメル用に 30 g 別途","グリュイエール、またはコンテ 200 g、細かくおろす","ジャンボン・ド・パリ 4 枚（合計約 120 g）","ディジョンマスタード 小さじ 2","薄力粉 30 g、全脂牛乳 300 ml（ベシャメル用）","細かい海塩、白こしょう、ひと振りのナツメグ"],"en":["8 thick slices of pain de mie (soft white sandwich bread), one day old","80 g unsalted butter, softened, plus 30 g for the béchamel","200 g Gruyère or Comté, finely grated","4 slices of jambon de Paris (~120 g total)","2 tsp Dijon mustard","30 g plain flour and 300 ml whole milk (for the béchamel)","Fine sea salt, white pepper, a grating of nutmeg"],"ro":["8 felii groase de pain de mie (pâine albă fină de sandviș), o zi vechi","80 g unt nesărat, înmuiat, plus 30 g pentru béchamel","200 g Gruyère sau Comté, ras fin","4 felii de jambon de Paris (~120 g în total)","2 lingurițe muștar Dijon","30 g făină albă și 300 ml lapte integral (pentru béchamel)","Sare fină, piper alb, un sfert de nucușoară rasă"]},"howIsMade":{"ja":"ベシャメル用のバター 30 g を小鍋に入れ中火で溶かし、薄力粉を加えて色がつかないように 1〜2 分炒め、温めた牛乳を少しずつ注いで泡立て器で絶えず混ぜながらなめらかにし、弱火に落として 4〜5 分よく混ぜながらスプーンの背に角が立つくらいの濃さまで煮詰める — 塩、白こしょう、ナツメグで味を整え、保温しておく。\n\nオーブンの上火（ブロイラー）を最強で予熱し、各パンの両面に柔らかいバターを塗り、サンドイッチ 1 個につき 1 枚の内側の面だけにディジョンを薄く塗る。\n\nオーブンシートを敷いた天板に、バターを塗った 4 枚を並べ、それぞれにグリュイエールの細切りを薄く一層（〜60 g を上掛け用に取り置く）、ハム 1 枚、もう一度薄くチーズの層を重ね、残りの 4 枚をディジョン側を内にして重ねて軽く押さえる。\n\n各サンドイッチに山盛り大さじ 2 のベシャメルを縁まで広げ、パン全体を覆い、ソースが少し横へ垂れる程度にして、取り置いたグリュイエールを上に散らし、熱したブロイラーの下に天板を入れて 4〜6 分、目を離さず焼く — ベシャメルが沸き、ところどころ深い焼き色がつき、チーズが完全に溶けるまで。バターがすでに底に密着しているので、パンの裏側はカリッと仕上がる。\n\n取り出して 30 秒休ませる — そうしないとチーズが手に貼り付く — そして斜めに切る；クロックマダムにする場合は、サンドイッチを焼いている間に少量のバターで目玉焼きを作り、提供する直前に上に乗せる。","en":"Melt the 30 g béchamel butter in a small saucepan over medium heat, whisk in the flour and cook 1–2 minutes without colouring, then pour the warm milk in gradually while whisking constantly and simmer gently 4–5 minutes, stirring often, until thick enough to hold a peak on the spoon — season with salt, white pepper and nutmeg and keep warm.\n\nPreheat the broiler (top grill) to high, butter both sides of every bread slice with the softened butter, then thinly spread Dijon on the inner face of one slice per sandwich.\n\nLay 4 buttered slices on a lined tray, top each with a thin layer of grated Gruyère (hold ~60 g back for the top), a slice of ham and another thin layer of cheese, then close with the remaining 4 slices, mustard side in, and press lightly.\n\nSpoon 2 heaped tablespoons of béchamel over each sandwich right to the edges so the bread is fully covered and the sauce runs a little down the sides, scatter the reserved Gruyère on top and slide the tray under the hot broiler for 4–6 minutes, watching closely, until the béchamel is bubbling and deeply browned in patches and the cheese is molten — the bread crisps from below from the butter already gripped to its underside.\n\nLift out, rest 30 seconds — the cheese would stick to you otherwise — and cut on the diagonal; for a croque madame, fry an egg in a little butter while the sandwiches are under the broiler and slip it on top just before serving."}},{"id":192,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":420,"prot":13,"carb":60,"fat":14,"fib":1},"origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"クレープ","en":"Crêpes","ro":"Crêpes"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"ingredients":{"ja":["薄力粉 250 g（T45 か T55 相当）、ふるう","L 卵 4 個、室温に戻す","全脂牛乳 500 ml（軽い仕上がりを好むなら牛乳 350 ml + 水 150 ml）","無塩バター 50 g、こんがり色づくまで溶かす（beurre noisette、焦がしバター）","グラニュー糖 30 g、細かい塩をひとつまみたっぷり","ダークラム 大さじ 1、またはオレンジフラワーウォーター（あるいはバニラエクストラクト 小さじ 1）","フライパン用の追加バター（約 30 g、刷毛で塗る）","供し方：グラニュー糖、レモンのくし切り、お好みでジャム、Nutella、バナナのスライス"],"en":["250 g plain flour (T45 or T55), sifted","4 large eggs, at room temperature","500 ml whole milk (or 350 ml milk + 150 ml water for lighter crêpes)","50 g unsalted butter, melted until it browns to beurre noisette","30 g sugar and a good pinch of fine salt","1 tbsp dark rum or orange-flower water (or 1 tsp vanilla extract)","Extra butter for the pan (~30 g, kept on a brush)","To serve: caster sugar, lemon wedges, optionally jam, Nutella or sliced banana"],"ro":["250 g făină albă (T45 sau T55), cernută","4 ouă mari, la temperatura camerei","500 ml lapte integral (sau 350 ml lapte + 150 ml apă pentru crêpes mai ușoare)","50 g unt nesărat, topit până devine beurre noisette (alunizat)","30 g zahăr și un vârf bun de sare fină","1 lingură de rom închis sau apă de flori de portocal (sau 1 linguriță extract de vanilie)","Unt în plus pentru ungerea tigăii (~30 g, ținut cu o pensulă)","Pentru servit: zahăr tos, felii de lămâie, opțional gem, Nutella sau banane"]},"howIsMade":{"ja":"鍋にバター 50 g を入れ、中火で溶かし、ナッツのような香りが立ち、深い黄金色になるまで加熱したら、茶こしで濾してボウルに移し、黒い澱は鍋に残す — これがブール・ノワゼット（焦がしバター）、菓子屋仕込みのクレープの香りの正体である。\n\n大きなボウルに薄力粉と塩をふるい入れ、中央にくぼみを作って卵を割り入れ、牛乳の 1/3 と砂糖を加え、続けて泡立て器で中心から外側へ向け、徐々に粉を引き込みながらダマのないなめらかで濃いペースト状にし、残りの牛乳を細い流れで注いだあと、人肌に冷ました焦がしバターとラム酒を加える；生地は液状の生クリーム程度の濃さに仕上げる。\n\nボウルに蓋をして冷蔵庫で最低 30 分、できれば 1 時間休ませる — グルテンが落ち着き、生地はゴムのようでなく、薄く柔らかく仕上がる。\n\n22〜24 cm のフッ素加工フライパン、またはクレピエールを中強火で温め、刷毛でごく薄くバターを塗り、生地約 50 ml を流し入れ、すぐにフライパンを回して底全体に薄く広げ、50〜60 秒、縁が浮き上がり、裏面がレース状の黄金色になるまで焼き、薄いヘラ（もしくは軽くフライパンを返して）でもう 25〜30 秒、皿に滑らせ、清潔なふきんで覆う — 1〜2 枚ごとにバターを少量塗りながら、生地を使い切るまで繰り返す。\n\n温かいうちにグラニュー糖をふり、レモンを一搾りして、四つに畳んで供する — パリの屋台の定番はシュクレ、シュクレ・シトロン、フルーツジャム、Nutella、またはバナナと Nutella。","en":"Melt the 50 g of butter in a small saucepan over medium heat and keep cooking until it smells nutty and turns deep gold, then strain into a bowl leaving the dark sediment behind — that's beurre noisette, the signature flavour of bakery-grade crêpes.\n\nSift the flour and salt into a large bowl, make a well in the middle, crack in the eggs and add a third of the milk with the sugar, then whisk from the centre outwards drawing in the flour until you have a thick smooth paste with no lumps, thin with the rest of the milk in a slow stream and finally add the cooled brown butter and the rum; the batter should be the consistency of single cream.\n\nCover and rest the batter in the fridge at least 30 minutes, ideally an hour — the gluten settles and the crêpes turn out thin and flexible rather than elastic.\n\nHeat a 22–24 cm non-stick pan or crêpière over medium-high heat, brush with a very thin film of butter and pour in about 50 ml of batter, immediately swirling so it covers the base in a thin disc, then cook 50–60 seconds until the edges lift and the underside is lacy golden, flip with a thin spatula (or a quick toss of the pan) for another 25–30 seconds, slide onto a plate and cover with a clean cloth — carry on, brushing the pan with a little butter every one or two crêpes, until the batter is gone.\n\nServe warm, scattered with caster sugar and a squeeze of lemon, folded into quarters — the Parisian street-stand alternatives are sucre, sucre-citron, fruit jam, Nutella, or banana with Nutella."}},{"id":193,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":5,"carb":65,"fat":28,"fib":3},"origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"タルト・タタン","en":"Tarte Tatin","ro":"Tarte Tatin"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"ingredients":{"ja":["しっかりして少し酸味のあるりんご 8〜10 個（レーヌ・ド・レネット、ゴールデンデリシャス、ハニークリスプなど）、皮をむいて半分に切り、芯を除く — 約 1.5 kg","無塩バター 150 g、角切り、室温に戻したもの","グラニュー糖（白砂糖）200 g（古典的なタタンに茶色の砂糖は使わない）","搾りたてのレモン汁 大さじ 1","パイ生地（pâte feuilletée）約 250 g 1 枚、26 cm の円形、厚さ 3 mm に伸ばす","フルール・ド・セルひとつまみ","供し方：クレーム・フレッシュ 200 ml、アイスではなく — ソローニュ地方の伝統"],"en":["8–10 firm tart apples (reine de reinette, golden delicious or honeycrisp), peeled, halved and cored — about 1.5 kg","150 g unsalted butter, cut into cubes, at room temperature","200 g white granulated sugar (do not use brown sugar for a classic tatin)","1 tbsp fresh lemon juice","1 round of puff pastry (pâte feuilletée), ~250 g, rolled to 26 cm and 3 mm thick","A pinch of fleur de sel","To serve: 200 ml crème fraîche, not ice cream — the Sologne tradition"],"ro":["8–10 mere ferme și ușor acrișoare (reine de reinette, golden delicious sau honeycrisp), curățate, înjumătățite și fără cotor — în jur de 1,5 kg","150 g unt nesărat, tăiat cuburi, la temperatura camerei","200 g zahăr alb tos (nu se folosește zahăr brun pentru un tatin clasic)","1 lingură suc proaspăt de lămâie","Un disc de aluat de foitaj (pâte feuilletée), ~250 g, rulat la 26 cm diametru și 3 mm grosime","Un vârf de fleur de sel","Pentru servit: 200 ml smântână grasă (crème fraîche), nu înghețată — tradiția din Sologne"]},"howIsMade":{"ja":"りんごをレモン汁でからめて変色を防ぎ、22〜24 cm のオーブン対応の厚手フライパン（あるいは専用のタタン型）に無塩バター 50 g を中火で溶かし、その上にグラニュー糖をムラなく振り、混ぜずに加熱し続けて、砂糖が溶けて深い琥珀色のキャラメルになるまで — 8〜10 分ほど — 色が浅いとオーブンで色が抜け、味も平坦になるためしっかり色をつける。\n\n火から外し、残りのバター 100 g を角切りでキャラメルの上に落とす — 強くジューッと音を立てる — フライパンを回してバターを均一に溶かし、艶のあるキャラメル・バターソースにし、りんごの半割りを断面を上にして中心から外側に向かって渦巻きにきっちり詰める（入る）、中火に戻して 25〜30 分、蓋をせずに、時々フライパンを傾けて縁のキャラメルを中央に戻しながら、りんごの底面がキャラメルを吸い込み、ちょうど柔らかくなり始めるまで加熱する。\n\n並行してオーブンを 200℃ に予熱し、パイ生地をフライパンよりひと回り大きい円形に伸ばし、りんごの火を止めて 1〜2 分冷まし、生地をりんごの上にかぶせ、はみ出した縁をフライパンの内側、りんごと壁の間に折り込む — ひっくり返すときに生地がりんごをしっかり抱える — フォークで生地に数か所穴を開ける。\n\nオーブンで 25〜30 分、生地が完全な黄金色になり、縁でキャラメルがふつふつと音を立てるまで焼き、ちょうど 10 分休ませる — キャラメルが落ち着くが完全に固まらない時間。\n\nフライパンより大きな皿を生地にかぶせ、厚布でフライパンを持ち、迷いのない一動作で反転させる — フライパンにりんごが残ったら、ヘラでタルトに戻す — フルール・ド・セルをひとつまみ振り、温かいうちに、各皿にクレーム・フレッシュをたっぷりのせて供する。","en":"Toss the apples with the lemon juice so they don't brown, melt 50 g of the butter in a heavy 22–24 cm oven-safe pan with an ovenproof handle (or a proper tatin pan), scatter the sugar over it in an even layer and leave on medium heat without stirring until the sugar dissolves and caramelises to a deep amber — about 8–10 minutes — because pale caramel bleeds out in the oven and tastes flat.\n\nTake the pan off the heat and drop the remaining 100 g butter in cubes onto the caramel — it will hiss hard — swirl until the butter melts evenly into a glossy buttery sauce, then pack the apple halves cut-side-up, tight against each other in a spiral from the centre outwards (they will fit), return to medium heat and cook uncovered for 25–30 minutes, tilting the pan now and then to catch the caramel from the edges, until the underside of the apples has drunk the caramel and they just start to soften.\n\nMeanwhile heat the oven to 200°C and roll the puff pastry to a disc a little larger than the pan, cut the heat under the apples and let them settle a minute, then drape the pastry over the top and tuck the edges down inside the pan between the apples and the wall — the crust will grip the fruit when you flip — and prick the pastry a few times with a fork.\n\nBake 25–30 minutes until the pastry is fully golden and the caramel bubbles around the edges, then rest exactly 10 minutes — long enough for the caramel to settle without setting hard.\n\nPlace a serving plate wider than the pan over the pastry, hold the pan with a thick cloth and invert in one decisive motion — if any apple stays stuck to the pan, lift it back onto the tart with a spatula — scatter a pinch of fleur de sel over the top and serve warm with a generous spoonful of crème fraîche on each plate."}},{"id":194,"servings":6,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":28,"carb":28,"fat":10,"fib":1},"origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"アヴゴレモノ","en":"Avgolemono","ro":"Avgolemono"},"category":{"ja":"スープ","en":"Soup","ro":"Supă"},"ingredients":{"ja":["丸鶏 1.5 kg（または骨つき鶏もも 1 kg）","にんじん 2 本、玉ねぎ 1 個、セロリ 2 本（出汁用）","ローリエ 1 枚、パセリの茎ひとつかみ、黒こしょう 8 粒","長粒米 150 g（オルゾでも可）","L 卵 3 個、室温に戻したもの","レモン 2 個分の果汁（約 80 ml）","塩と白こしょう","仕上げ用のディルかパセリ"],"en":["1.5 kg whole chicken (or 1 kg bone-in chicken thighs)","2 carrots, 1 onion, 2 celery stalks (for the broth)","1 bay leaf, a handful of parsley stems, 8 black peppercorns","150 g long-grain rice (or orzo if you prefer)","3 large eggs, at room temperature","Juice of 2 lemons (about 80 ml)","Salt and white pepper","Fresh dill or parsley to finish"],"ro":["1,5 kg pui întreg (sau 1 kg pulpe de pui cu os)","2 morcovi, 1 ceapă, 2 tulpini de țelină (pentru fond)","1 frunză de dafin, un mănunchi de codițe de pătrunjel, 8 boabe de piper negru","150 g orez cu bob lung (sau orzo, dacă preferi)","3 ouă mari, la temperatura camerei","Zeama de la 2 lămâi (aproximativ 80 ml)","Sare și piper alb","Mărar sau pătrunjel proaspăt pentru a încheia"]},"howIsMade":{"ja":"厚手の鍋に鶏、にんじん、玉ねぎ、セロリ、ローリエ、パセリの茎、こしょうを入れ、冷水 2.5 L を注いで穏やかに沸かす。アクをすくい、蓋をせず 90 分ほど、肉が骨から外れるまで煮込む。\n\n鶏を取り出し、スープは野菜を漉してきれいな鍋に移す。骨から肉を外して一口大に割り、スープに戻し、再び沸かして米を加える；15〜18 分、米が柔らかくなるまで炊く。\n\nボウルに卵を割り入れ、淡く泡立つまで泡立て、レモン汁を加える。卵をテンパリングする：熱いスープをひしゃくで少しずつ注ぎながら絶えず泡立て、もう一杯加え、ボウルがほんのり温かくなるまで続ける。\n\n火を止め、テンパリングした卵液を細く均等な流れで鍋に戻し、止めずに混ぜ続ける — この後沸騰させてはならない、沸かせば卵が散る。塩と白こしょうで整え、ディルかパセリを散らしてすぐに供する。","en":"Simmer the chicken in 2.5 L cold water with the carrots, onion, celery, bay leaf, parsley stems and peppercorns. Skim any foam and cook uncovered for about 90 minutes, until the meat falls from the bones.\n\nLift the chicken out, strain the broth into a clean pot and discard the vegetables. Shred the meat off the bones, return it to the broth, bring back to a simmer and stir in the rice; cook 15–18 minutes until tender.\n\nWhisk the eggs in a bowl until light and foamy, then whisk in the lemon juice. Temper them by slowly ladling a cup of hot broth in while whisking, then another, until the bowl is warm to the touch.\n\nOff the heat, pour the tempered eggs back into the pot in a slow steady stream, stirring continuously — never let the soup boil again. Season with salt and white pepper and serve immediately, finished with dill or parsley."}},{"id":195,"servings":4,"tipType":"meat","pairingsType":"mediterranean","nutrition":{"cal":620,"prot":38,"carb":52,"fat":28,"fib":4},"origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"ギロピタ","en":"Gyros","ro":"Gyros"},"category":{"ja":"昼食","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["豚肩ロース 1 kg、繊維に逆らって 1 cm 幅にスライス（または骨なし鶏もも）","にんにく 4 片、みじん切り","ギリシャ産オリーブオイル 大さじ 2","赤ワインビネガー 大さじ 1","ドライオレガノ 大さじ 1（可能ならギリシャの「リガニ」）","甘いパプリカパウダー 小さじ 1","塩 小さじ 1、黒こしょう 小さじ ½","大ぶりの柔らかいギリシャのピタ 4 枚（ポケットなしの平たいフラットブレッド）","添え：ツァジキ 200 ml、完熟トマト 1 個のスライス、紫玉ねぎ ½ 個の薄切り、オレガノ、レモンのくし切り、お好みでフライドポテト"],"en":["1 kg pork shoulder, sliced into 1 cm thick strips against the grain (or boneless chicken thighs)","4 garlic cloves, minced","2 tbsp Greek olive oil","1 tbsp red wine vinegar","1 tbsp dried oregano (Greek rigani if possible)","1 tsp sweet paprika","1 tsp salt, ½ tsp black pepper","4 large soft Greek pitas (the unfilled flatbread, not pocket pita)","To serve: 200 ml tzatziki, 1 ripe tomato sliced, ½ red onion thinly sliced, oregano, lemon wedges, optional French fries"],"ro":["1 kg ceafă de porc, tăiată în fâșii de 1 cm grosime contra fibrei (sau pulpe de pui dezosate)","4 căței de usturoi, tocați","2 linguri ulei de măsline grecesc","1 lingură oțet de vin roșu","1 lingură oregano uscat (rigani grecesc, dacă ai)","1 linguriță boia dulce","1 linguriță sare, ½ linguriță piper negru","4 lipii grecești mari și moi (turtă plată neumplută, nu pita cu buzunar)","Pentru servit: 200 ml tzatziki, 1 roșie coaptă feliată, ½ ceapă roșie tăiată subțire, oregano, felii de lămâie, opțional cartofi prăjiți"]},"howIsMade":{"ja":"ボウルにおろしにんにく、オリーブオイル、酢、オレガノ、パプリカ、塩、こしょうを合わせ、豚肉のスライスを加えて全体に絡める。ふたをして 3 時間以上、できれば一晩漬け込む。\n\n厚手のフライパンか鉄板を煙が立つほど高温に熱する。豚肉を重ならないよう並べ、必要なら何回かに分ける；触らずに片面 2〜3 分ずつ焼き、縁が深く色づき中心がちょうど火が通る程度に仕上げる。詰め込みすぎると蒸し焼きになって焦げ目がつかない。焼き上がった分は皿に休ませ、次の分を焼く。\n\n同じフライパンでピタを 1 枚ずつ片面 20 秒ずつ温め、しなやかになったところで取り出す。中央に山盛り大さじ 1 のザジキを塗り、熱い豚肉をのせ、トマトのスライスと紫玉ねぎの輪切りを散らす — アテネ風に忠実にいくなら、最後にひとつかみのフライドポテトをトッピングする。\n\nペーパーできつく巻き、片端をひねって閉じ、追加のオレガノ、レモンのくし切り、残りのザジキを添えてすぐに供する。","en":"Whisk the garlic, olive oil, vinegar, oregano, paprika, salt and pepper in a large bowl, add the pork strips and toss until every piece is coated. Cover and marinate at least 3 hours, ideally overnight.\n\nHeat a large heavy skillet or griddle pan over high heat until smoking. Lay the strips down in a single layer, in batches if needed, and sear without moving for 2–3 minutes per side, until the edges are deeply browned and the centre just cooked through; don't crowd the pan or the meat will steam instead of caramelise. Rest each batch on a plate while you cook the next.\n\nWarm the pitas one at a time on the same hot skillet for 20 seconds per side, just until pliable. Spread a heaped tablespoon of tzatziki down the centre of each, lay the hot pork on top, add a few tomato slices and rings of red onion, and — if you're being faithful to Athens — a small handful of French fries on top.\n\nWrap tightly in paper with one end pinched closed, and serve immediately with extra oregano, a wedge of lemon, and the rest of the tzatziki on the side."}},{"id":196,"servings":8,"tipType":"pasta","pairingsType":"mediterranean","nutrition":{"cal":680,"prot":30,"carb":62,"fat":32,"fib":4},"origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"パスティツィオ","en":"Pastitsio","ro":"Pastitsio"},"category":{"ja":"パスタ","en":"Pasta","ro":"Paste"},"ingredients":{"ja":["パスティツィオ用パスタ 500 g（長く太い筒状パスタ 2 番；ブカティーニで代用可）","牛ひき肉 600 g（または牛と羊半々）","大玉ねぎ 1 個、細かいみじん切り","にんにく 3 片、みじん切り","缶詰のカットトマト 400 g","トマトペースト 大さじ 2","辛口赤ワイン 150 ml","シナモンスティック 1 本、ホールクローブ 4 粒、ローリエ 1 枚、ドライオレガノ 小さじ 1","ケファロティリまたはペコリーノ 100 g、細かくおろす（最悪パルメザンで代用）","ベシャメル用：バター 100 g、薄力粉 100 g、全脂牛乳 1 L、卵黄 4 個、おろしたてのナツメグ少々","塩、こしょう、オリーブオイル"],"en":["500 g pastitsio noodles (long, tubular #2; bucatini is a fair substitute)","600 g beef mince (or half beef, half lamb)","1 large onion, finely chopped","3 garlic cloves, minced","400 g chopped tomatoes (canned)","2 tbsp tomato paste","150 ml dry red wine","1 cinnamon stick, 4 whole cloves, 1 bay leaf, 1 tsp dried oregano","100 g Kefalotyri or Pecorino, finely grated (Parmesan works at a pinch)","For the béchamel: 100 g butter, 100 g flour, 1 L whole milk, 4 egg yolks, a grating of nutmeg","Salt and pepper, olive oil"],"ro":["500 g paste tip pastitsio (lungi, tubulare nr. 2; bucatini este o alternativă bună)","600 g carne tocată de vită (sau jumătate vită, jumătate miel)","1 ceapă mare, tocată mărunt","3 căței de usturoi, tocați","400 g roșii tocate (la conservă)","2 linguri pastă de roșii","150 ml vin roșu sec","1 baton de scorțișoară, 4 cuișoare întregi, 1 frunză de dafin, 1 linguriță oregano uscat","100 g Kefalotyri sau Pecorino, ras fin (Parmezan se poate la nevoie)","Pentru béchamel: 100 g unt, 100 g făină, 1 l lapte integral, 4 gălbenușuri, puțină nucușoară rasă","Sare, piper, ulei de măsline"]},"howIsMade":{"ja":"厚手の鍋にオリーブオイル大さじ 3 を熱し、刻んだ玉ねぎを 8〜10 分炒める。にんにくを加えて 30 秒、ひき肉を崩しながら加え、木べらでよくほぐして 10 分ほどしっかりと焼き色をつける。トマトペーストを加えてレンガ色になるまで炒め、ワインで鍋底をこそげ、半量に煮詰めてからトマト、シナモンスティック、クローブ、ローリエ、オレガノを加える。塩こしょうをしっかりして弱火で蓋なし 45 分以上煮込み、組み立て前に丸ごとの香辛料は取り除く。\n\n肉を煮込んでいる間にベシャメルを作る：広めの鍋でバターを溶かし、薄力粉を加えて色がつかないよう 1〜2 分炒め、温めた牛乳を細く絶えず注ぎながら泡立て、5〜7 分煮て木べらの背を覆うほどのとろみに仕上げる。火を止めて卵黄を一つずつ加え、ナツメグと半量の粉チーズを混ぜ、味を調える。\n\nパスタはたっぷりの塩を加えた湯で、袋表示より 2 分短く茹でる — 残りはオーブンで火が入る — 湯切りして残りのチーズと肉ソースをひとお玉ほど絡め、麺がくっつかないようにする。\n\n25×35 cm の耐熱皿に、パスタの半量を同じ向きに敷き詰め、肉ソースを均一に広げ、残りのパスタを同じ向きに重ねる。ベシャメルを全面に流して平らに整え、180°C で 45〜50 分、黄金色になり中央がふつふつするまで焼く。\n\n切り分ける前に少なくとも 20 分は休ませる。熱いまま切ると層が崩れる。","en":"Heat 3 tablespoons of olive oil in a heavy pan and brown the chopped onion for 8–10 minutes, add the garlic for 30 seconds, then crumble in the mince. Break it up with a wooden spoon and let it brown deeply, about 10 minutes. Stir in the tomato paste, fry until brick-red, deglaze with the wine and let it reduce by half before adding the tomatoes, cinnamon stick, cloves, bay leaf and oregano. Season generously and simmer uncovered on low heat for at least 45 minutes; fish out the whole spices before assembling.\n\nWhile the meat cooks, make the béchamel: melt the butter in a wide saucepan, whisk in the flour for a couple of minutes without colour, pour in the warm milk in a slow stream while whisking, then simmer 5–7 minutes until it coats the back of a spoon. Off the heat, beat in the egg yolks one at a time, add the nutmeg and half the grated cheese, and season.\n\nBoil the pasta in well-salted water 2 minutes less than the package says — it'll finish in the oven — drain and toss with the remaining cheese and a ladle of meat sauce so the noodles don't stick.\n\nIn a 25×35 cm baking dish, lay half the pasta in one direction, spread the meat sauce evenly over it, then top with the rest of the pasta aligned the same way. Pour the béchamel over, smooth it level, and bake at 180°C for 45–50 minutes until golden and bubbling.\n\nLet it rest at least 20 minutes before cutting; sliced too hot, the layers collapse."}},{"id":197,"servings":6,"tipType":"veg","pairingsType":"mediterranean","nutrition":{"cal":280,"prot":5,"carb":35,"fat":14,"fib":3},"origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"ドルマデス","en":"Dolmades","ro":"Dolmades"},"category":{"ja":"前菜","en":"Appetizer","ro":"Aperitiv"},"ingredients":{"ja":["瓶詰めのブドウの葉（塩漬け）1 瓶 450 g、湯切りして洗う（または茹でた生の葉 60 枚）","長粒米 200 g（アルボリオでも可）","大玉ねぎ 1 個、みじん切り","万能ねぎ 6 本、薄切り","フレッシュディル 大きめ 1 束、刻む","フレッシュミント 小さめ 1 束、刻む","イタリアンパセリ 小さめ 1 束、刻む","レモン 2 個分の果汁","エクストラバージンオリーブオイル 150 ml","塩 小さじ 1、挽きたての黒こしょう","任意だが伝統的：すりおろしトマト 1 個分"],"en":["1 jar (450 g) preserved grape leaves, drained and rinsed (or 60 fresh blanched leaves)","200 g long-grain rice (arborio works)","1 large onion, finely chopped","6 spring onions, thinly sliced","A large bunch of fresh dill, chopped","A small bunch of fresh mint, chopped","A small bunch of flat-leaf parsley, chopped","Juice of 2 lemons","150 ml extra-virgin olive oil","1 tsp salt, freshly ground black pepper","Optional but traditional: 1 grated tomato"],"ro":["1 borcan (450 g) de frunze de viță conservate, scurse și clătite (sau 60 de frunze proaspete opărite)","200 g orez cu bob lung (merge și arborio)","1 ceapă mare, tocată mărunt","6 fire de ceapă verde, tăiate subțire","Un mănunchi mare de mărar proaspăt, tocat","Un mănunchi mic de mentă proaspătă, tocată","Un mănunchi mic de pătrunjel cu frunza plată, tocat","Zeama de la 2 lămâi","150 ml ulei de măsline extravirgin","1 linguriță sare, piper negru proaspăt măcinat","Opțional dar tradițional: 1 roșie rasă"]},"howIsMade":{"ja":"米を冷水に 15 分浸し、水気を切る。広めのフライパンにオリーブオイル大さじ 3 を熱し、刻んだ玉ねぎを 8 分、色がつかず透き通るまでしっとり炒める。万能ねぎ、全てのハーブ、水気を切った米、レモン汁の半量、塩ひとつまみを加え、香りが立つよう 1 分炒めたら、皿に広げて室温まで冷ます。\n\n葡萄の葉を葉脈を上に、軸を手前にして作業台に置く。軸寄りに山盛り小さじ 1 の米詰めを置き、下端を被せるように折り、両側を内に折り込んで小さなシガー型にきつく巻く。詰めすぎないこと — 米は煮ると膨らみ、きつすぎるとドルマが裂ける。\n\n厚手の鍋の底にちぎった葉を敷いて焦げつき防止にする。巻いたドルマデスを縫い目を下にし、互いに支え合うようにきっちりと同心円状に並べる。残りのオリーブオイルとレモン汁を回しかけ、ドルマデスの高さまで冷水を注ぎ、耐熱の皿を直接押し当てて沈めておく。\n\nゆっくりと弱い沸騰まで持っていき、蓋をして最弱火で 50〜60 分、米が柔らかくなり水分がほぼ吸われるまで煮る。鍋のまま冷ます — 冷たいか室温で、レモンのくし切りと濃いめのヨーグルトを添えて供する。前日に作ると味が格段に良くなる。","en":"Soak the rice in cold water for 15 minutes and drain. Heat 3 tablespoons of olive oil in a wide pan and sweat the chopped onion for 8 minutes until translucent, no colour. Add the spring onions, all the herbs, the drained rice, half the lemon juice and a generous pinch of salt; stir for a minute to bloom the aromas, then tip onto a plate to cool to room temperature.\n\nLay a grape leaf on the work surface vein-side up, stem at the bottom. Place a heaped teaspoon of the rice mixture near the stem, fold the bottom edge up and over, fold both sides in, and roll up tightly into a small cigar. Don't overfill — the rice swells as it cooks and packed too tightly the dolma will split.\n\nLine the bottom of a heavy pot with torn or broken leaves to prevent sticking. Pack the rolled dolmades in concentric circles, seam-side down, snug enough to hold each other in place. Pour over the remaining olive oil and lemon juice, add cold water just to the top of the dolmades, and press a heatproof plate directly on the surface to keep them submerged.\n\nBring slowly to a simmer, cover, and cook on the lowest heat for 50 minutes to an hour, until the rice is tender and the liquid mostly absorbed. Leave to cool in the pot — they're served cold or at room temperature, with a wedge of lemon and a bowl of thick yoghurt. Made the day before, they taste markedly better."}},{"id":198,"servings":12,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":380,"prot":7,"carb":48,"fat":18,"fib":1},"origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"ガラクトブレコ","en":"Galaktoboureko","ro":"Galaktoboureko"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"ingredients":{"ja":["フィロ生地 500 g、解凍","無塩バター 200 g、溶かしておく","全脂牛乳 1 L","グラニュー糖 200 g（カスタード用）","細かいセモリナ粉 150 g","L 卵 4 個","バニラエクストラクト 小さじ 1","レモン 1 個分の皮（すりおろし）","シロップ用：グラニュー糖 400 g、水 250 ml、レモン半個分の果汁、オレンジ皮ひと切れ、シナモンスティック 1 本"],"en":["500 g phyllo pastry, thawed","200 g unsalted butter, melted","1 L whole milk","200 g caster sugar (for the custard)","150 g fine semolina","4 large eggs","1 tsp vanilla extract","Zest of 1 lemon","For the syrup: 400 g caster sugar, 250 ml water, juice of half a lemon, a strip of orange peel, 1 stick of cinnamon"],"ro":["500 g foi de plăcintă (phyllo), dezghețate","200 g unt nesărat, topit","1 l lapte integral","200 g zahăr tos (pentru cremă)","150 g griș fin","4 ouă mari","1 linguriță extract de vanilie","Coaja rasă de la 1 lămâie","Pentru sirop: 400 g zahăr, 250 ml apă, zeama de la o jumătate de lămâie, o fâșie de coajă de portocală, 1 baton de scorțișoară"]},"howIsMade":{"ja":"シロップは早めに作っておく — 熱いパイがオーブンから出てきた時点で冷たくなっていなければならない — 小鍋に砂糖、水、レモン汁、オレンジの皮、シナモンを合わせ、沸騰させてから 4 分煮詰め、火から下ろして完全に冷ます。カスタードは、大きな鍋に牛乳、砂糖、レモンの皮を入れ、湯気が立つ寸前まで温め（沸騰させない）、セモリナを細く均一に振り入れながら絶え間なく泡立て、その後弱火で 5〜6 分、緩めのプディング状にとろみがつくまで泡立て続ける；火から下ろし、卵を 1 個ずつ加え（混合物は温かいがスクランブルしない温度であるべき）、バニラも加え、表面に直接ラップを密着させて膜が張るのを防ぐ。22×30 cm の耐熱皿に溶かしバターを塗り、フィロを 7 枚重ねて底に敷き、それぞれにバターをたっぷり塗り、端を皿の側面から垂らしておく（このフラップは後で上に折り戻す）、まだ温かいカスタードを注ぎ入れ、表面を平らに整え、垂れているフラップを内側に折り、バターを塗り、さらに 7 枚のフィロで覆い（各枚にバターを塗る）、端を整えるか折り込んでパイが完全に密封されるようにする。鋭いナイフでトップのフィロにダイヤモンドまたは正方形の切り込みを入れる — 後でシロップが浸透できるように、最後まで切る — 残りのバターを表面にたっぷり塗り、170℃ で 45〜55 分、上面が深い金茶色になるまで焼く。オーブンから出した瞬間、冷たいシロップを熱いパイの上に均等に注ぐ — ジューと音を立てて蒸気が立つ — 切り込み線に沿って切り、室温で供する前に少なくとも 4 時間、できれば一晩、落ち着かせる。","en":"Start the syrup well in advance — it must be cold when the hot pie comes out of the oven — combine the sugar, water, lemon juice, orange peel and cinnamon in a small saucepan, bring to a boil then simmer 4 minutes, take off the heat and leave to cool completely. For the custard, heat the milk in a wide saucepan with the sugar and lemon zest until just steaming (do not let it boil), sprinkle the semolina in a fine even stream while whisking constantly, then keep whisking on low heat for 5–6 minutes until it thickens to a loose pudding; off the heat, beat in the eggs one at a time (the mixture should be warm but not hot enough to scramble them) and the vanilla, then press clingfilm directly onto the surface to stop a skin forming. Brush a 22×30 cm baking dish with melted butter, lay 7 sheets of phyllo across the bottom brushing each generously with butter and letting the edges hang over the sides (those flaps will fold back over the top later), pour in the still-warm custard, smooth it level, fold the overhanging flaps inward and brush them with butter, then cover with another 7 sheets of phyllo (again buttering each) and trim or tuck the edges so the pie is fully sealed. Score the top phyllo into diamonds or squares with a sharp knife — cut all the way through so the syrup can later penetrate — brush the surface lavishly with the last of the butter, and bake at 170°C for 45–55 minutes until the top is deeply golden brown. The moment it comes out of the oven, pour the cold syrup evenly over the hot pie — it will sizzle and steam — leave to settle at least 4 hours, ideally overnight, before cutting along the score lines and serving at room temperature."}},{"id":199,"servings":4,"tipType":"def","pairingsType":"italian","nutrition":{"cal":740,"prot":28,"carb":88,"fat":30,"fib":4},"origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"ピッツァ・マルゲリータ","en":"Pizza Margherita","ro":"Pizza Margherita"},"category":{"ja":"ピッツァ","en":"Pizza","ro":"Pizza"},"ingredients":{"ja":["生地（ピッツァ 4 枚分）：00 粉 500 g（または強力粉）、冷水 325 ml、塩 10 g、生イースト 1 g（またはドライイースト 小さじ ¼）","ピッツァ 1 枚あたり：サンマルツァーノ缶詰トマト 80 g（手で潰す）、塩ひとつまみ、オリーブオイル少々","ピッツァ 1 枚あたり、フィオール・ディ・ラッテのモッツァレラ 100 g、手でちぎる（または水牛のモッツァレラ）","ピッツァ 1 枚あたり、フレッシュバジルの葉を数枚","仕上げ用エクストラバージンオリーブオイル","成形やピール用のセモリナまたは小麦粉"],"en":["For the dough (4 pizzas): 500 g 00 flour (or bread flour), 325 ml cold water, 10 g salt, 1 g fresh yeast (or ¼ tsp dried)","For each pizza: 80 g San Marzano tomatoes (canned, hand-crushed), a pinch of salt, a drizzle of olive oil","100 g fior di latte mozzarella per pizza, torn into pieces (or buffalo mozzarella)","A few fresh basil leaves per pizza","Extra-virgin olive oil to finish","Semolina or flour for shaping and the peel"],"ro":["Pentru aluat (4 pizza): 500 g făină 00 (sau pentru pâine), 325 ml apă rece, 10 g sare, 1 g drojdie proaspătă (sau ¼ linguriță uscată)","Pentru fiecare pizza: 80 g roșii San Marzano (la conservă, sfărâmate cu mâna), un praf de sare, un fir de ulei de măsline","100 g mozzarella fior di latte per pizza, ruptă în bucățele (sau mozzarella de bivoliță)","Câteva frunze de busuioc proaspăt pentru fiecare pizza","Ulei de măsline extravirgin pentru finalizare","Griș sau făină pentru modelare și pentru lopată"]},"howIsMade":{"ja":"生地：冷水でイーストを溶かし、小麦粉と塩を混ぜてざらついた塊にし、手で 10 分（またはスタンドミキサーのドゥフックで 6 分）滑らかで弾力が出るまでこね、覆って室温で 1 時間休ませてから、冷蔵庫で最低 24 時間、理想は 48〜72 時間寝かせる — この長時間の低温発酵こそ、ナポリの生地にあの気泡だらけの焦げた縁と空気を含んだ構造を与えるものだ。焼く 2 時間前に生地を冷蔵庫から出し、210 g のボール 4 個に分け、粉をふって湿った布で覆い、室温に戻す；同時にオーブンを最高温度（250℃ 以上）に予熱し、ピザストーンまたは厚い鋼板を中に入れて最低 45 分予熱する；ピザの下にきちんとした熱がなければ、生地は時間内に固まらない。1 個のボールを粉をふった台で手で伸ばす — 指先で中心を平らに押さえ、縁を盛り上げて残し、ディスクを優しく引っ張って約 28 cm に広げる — 麺棒は絶対に使わない、それは生地の気泡を潰してしまう — そして粉をふったパドルに移す。中心に 80 g の砕いたトマトを置き、スプーンの背で螺旋状に広げ、縁から 2 cm のところで止め、トマトに軽く塩を振り、少量のオリーブオイルを回しかけ、ちぎったモッツァレラを上に散らす（多すぎないように、さもないとピザが浸水する）。ピザを石の上に滑り込ませ、生地が膨らんで所々黒く焦げ、チーズが水たまり状に溶け、縁が濃い金色になるまで焼く — 家庭オーブンの全開で 4〜6 分、薪窯のナポリピザ窯で 90 秒 — 取り出し、バジルの葉をちぎって上に散らし（オーブンに入れると焦げる）、最後のオリーブオイルをひとすじ回しかけ、すぐに食べる。","en":"For the dough, dissolve the yeast in the cold water then mix in the flour and salt until you have a shaggy mass, knead by hand for 10 minutes (or 6 minutes with a stand mixer and dough hook) until smooth and elastic, cover and rest at room temperature for an hour, then refrigerate for at least 24 hours and ideally 48 to 72 — the long cold proof is what gives Neapolitan dough its blistered char and airy structure. Two hours before baking, take the dough out, divide into four 210 g balls, dust with flour, cover with a damp cloth and let them come to room temperature, meanwhile heat the oven as hot as it goes (250°C or above) with a pizza stone or heavy steel sheet inside for at least 45 minutes; without serious heat under the pizza, the crust will never set in time. Hand-stretch one ball on a well-floured surface — press the centre flat with your fingertips leaving a raised lip, then gently pull and stretch the disc to about 28 cm across — never use a rolling pin, which collapses the gas pockets in the crust — and slide it onto a floured peel. Spoon 80 g of crushed tomato into the centre and spread it in a spiral with the back of the spoon stopping 2 cm from the edge, salt the tomato lightly, drizzle a little olive oil, and scatter the torn mozzarella over the top (not too much, or the pizza floods). Slide the pizza onto the stone and bake until the crust is puffed and charred in spots, the cheese has melted into pools and the rim is dark gold — 4 to 6 minutes in a domestic oven at full blast, 90 seconds in a wood-fired Neapolitan oven — pull it out, tear over the basil leaves (which would scorch in the oven), drizzle a final thread of olive oil, and eat immediately."}},{"id":200,"servings":6,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":720,"prot":36,"carb":58,"fat":36,"fib":4},"origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"ラザニア・アッラ・ボロネーゼ","en":"Lasagne alla Bolognese","ro":"Lasagne alla Bolognese"},"category":{"ja":"パスタ","en":"Pasta","ro":"Paste"},"ingredients":{"ja":["ラグー用：牛ひき肉 400 g、豚ひき肉 200 g、パンチェッタ 80 g 細かい角切り、玉ねぎ 1 個 + にんじん 1 本 + セロリ 1 本（すべてみじん切り）、辛口赤ワイン 200 ml、パッサータまたはカットトマト 400 g、全脂牛乳 250 ml、ローリエ 1 枚、塩こしょう、オリーブオイル","ベシャメル用：バター 80 g、薄力粉 80 g、全脂牛乳 1 L、塩、ナツメグおろし少々","ラザニア用生卵パスタシート 300 g（または乾燥 250 g、下茹で済み）","パルミジャーノ・レッジャーノ 150 g、細かくおろす","型に塗るバター"],"en":["For the ragù: 400 g beef mince, 200 g pork mince, 80 g pancetta finely diced, 1 onion + 1 carrot + 1 celery stalk all finely diced, 200 ml dry red wine, 400 g passata or chopped tomatoes, 250 ml whole milk, 1 bay leaf, salt and pepper, olive oil","For the béchamel: 80 g butter, 80 g flour, 1 L whole milk, salt, a grating of nutmeg","300 g fresh egg lasagne sheets (or 250 g dried, blanched)","150 g Parmigiano Reggiano, finely grated","Butter for the dish"],"ro":["Pentru ragù: 400 g vită tocată, 200 g porc tocat, 80 g pancetta tăiată cubulețe, 1 ceapă + 1 morcov + 1 țelină — toate tocate mărunt, 200 ml vin roșu sec, 400 g passata sau roșii tocate, 250 ml lapte integral, 1 frunză de dafin, sare și piper, ulei de măsline","Pentru béchamel: 80 g unt, 80 g făină, 1 l lapte integral, sare, puțină nucușoară rasă","300 g foi proaspete de lasagne cu ou (sau 250 g uscate, opărite)","150 g Parmigiano Reggiano, ras fin","Unt pentru vasul de copt"]},"howIsMade":{"ja":"パンチェッタを厚手の鍋にオリーブ油を少々加えて中弱火で 5 分、脂が透き通るまでゆっくり脂を引き出し、刻んだソフリット（玉ねぎ、にんじん、セロリ）を加えて 10 分、しんなりして縁が金色に色付くまで炒め、それから 2 種の肉をほぐし入れてきちんと焼き色を付ける — 忍耐：最初の 3 分は触らない、それから崩してさらに 10 分、鍋底が深くキャラメル化するまで炒める。ワインを注いで、木べらで鍋底のフォンを溶かし、半量まで煮詰めたら、トマト、牛乳（これがボロネーゼの署名 — 酸を丸くし、テクスチャーを引き締める）、ベイリーフ、塩小さじ 1 を加える；ぎりぎり沸騰しない火加減にし、半蓋で、可能な限り弱火で最低 2 時間、できれば 3 時間煮込み、時々かき混ぜながら、乾きそうなら水を少々足す — 完成したラグーは艶があり、深い茶赤色で、ほぼペースト状、決してスープではない。ラグーが仕上がっている間にベシャメルを作る：バターを溶かし、小麦粉を 2 分間、色を付けずに混ぜ、温めた牛乳をゆっくりと注ぎながら泡立て器で混ぜ、5 分間煮詰めて濃度をつけ、塩とたっぷりすりおろしたナツメグで味付け。乾燥ラザニアシートを使うなら、塩を入れた湯で 1 分茹で、湿らせた布巾に並べる — フレッシュなシートはそのままで使う — オーブンを 180℃ に予熱し、25×35 cm の耐熱皿にバターを塗り、底に薄くベシャメル、次にパスタ、次にラグー、次にベシャメル、次に雪のようにパルミジャーノを振り、すべてを使い切るまで繰り返す（6〜7 層がボローニャの目標）、最後はベシャメルとさらに多めのパルミジャーノで仕上げ。35〜40 分焼き、表面が褐色になり、ふつふつと泡立つまで、その後 20 分休ませてから切る — 熱いまま切るとラザニアは崩れ、休ませると層を保つ。","en":"Render the pancetta gently in a heavy pot with a splash of olive oil over medium-low heat for 5 minutes until the fat runs clear, add the chopped soffritto (onion, carrot, celery) and cook 10 minutes until soft and just gilded at the edges, then crumble in both meats and brown them properly — patience: do not stir for the first 3 minutes, then break them up and cook 10 more minutes until the pan bottom is deeply caramelised. Pour in the wine, scrape the fond from the pan with a wooden spoon and reduce by half, then add the tomatoes, the milk (the Bolognese signature — it rounds the acid and tightens the texture), the bay leaf and a teaspoon of salt; bring to a bare simmer, partially cover, and cook on the lowest possible heat for at least 2 hours and ideally 3, stirring occasionally and adding a splash of water if it threatens to dry — the finished ragù should be glossy, deep brown-red and almost a paste, never a soup. While the ragù finishes, make the béchamel: melt the butter, whisk in the flour for 2 minutes without colour, pour in the warm milk in a slow stream while whisking and simmer 5 minutes until thick, then season with salt and a generous grating of nutmeg. If using dried lasagne sheets blanch them in salted boiling water for a minute and lay on damp tea towels — fresh sheets go in raw — heat the oven to 180°C and butter a 25×35 cm baking dish, then spread a thin layer of béchamel on the bottom, then a layer of pasta, then ragù, then béchamel, then a snowy dusting of Parmigiano, and repeat until you have used everything (six to seven layers is the Bolognese target), finishing with béchamel and a heavier shower of Parmigiano. Bake 35–40 minutes until the top is bronzed and bubbling, then rest 20 minutes before cutting — lasagne sliced hot slides apart, lasagne rested holds its layers."}},{"id":201,"servings":4,"tipType":"meat","pairingsType":"italian","nutrition":{"cal":580,"prot":42,"carb":18,"fat":32,"fib":3},"origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"オッソブーコ・アッラ・ミラネーゼ","en":"Osso Buco alla Milanese","ro":"Osso Buco alla Milanese"},"category":{"ja":"メイン","en":"Main","ro":"Fel principal"},"ingredients":{"ja":["厚切りの子牛すね肉 4 枚（厚さ 3〜4 cm、各約 350 g）、外周をタコ糸で巻く","塩と挽きたての黒こしょう","まぶす用の薄力粉","無塩バター 大さじ 4、オリーブオイル 大さじ 2","玉ねぎ 1 個 + にんじん 1 本 + セロリ 1 本、すべて細かいみじん切り","辛口白ワイン 200 ml","缶詰のカットトマト 400 g","仔牛または鶏のフォン（だし） 500 ml","ローリエ 1 枚、タイムの枝数本","グレモラータ用：レモン 1 個分の皮（すりおろし）、にんにく 2 片 ごく細かく、イタリアンパセリ 小束 細かく刻む"],"en":["4 thick-cut veal shanks (3–4 cm thick, about 350 g each), tied around the circumference with kitchen string","Salt and freshly ground black pepper","Plain flour for dusting","4 tbsp unsalted butter, 2 tbsp olive oil","1 onion + 1 carrot + 1 celery stalk, all finely diced","200 ml dry white wine","400 g chopped tomatoes","500 ml veal or chicken stock","1 bay leaf, a few sprigs of thyme","For the gremolata: zest of 1 lemon, 2 garlic cloves finely minced, a small bunch of flat-leaf parsley finely chopped"],"ro":["4 rasoluri groase de vițel (3–4 cm grosime, aproximativ 350 g fiecare), legate cu sfoară de bucătărie pe circumferință","Sare și piper negru proaspăt măcinat","Făină albă pentru tăvălit","4 linguri unt nesărat, 2 linguri ulei de măsline","1 ceapă + 1 morcov + 1 țelină, toate tocate mărunt","200 ml vin alb sec","400 g roșii tocate","500 ml fond de vițel sau pui","1 frunză de dafin, câteva fire de cimbru","Pentru gremolata: coaja rasă de la 1 lămâie, 2 căței de usturoi tocați fin, un mănunchi mic de pătrunjel cu frunza plată, tocat fin"]},"howIsMade":{"ja":"スネ肉をペーパーでよく拭き — 濡れた肉は焼き付かず蒸気が立つ — 塩こしょうをしっかり振り、小麦粉を薄くまぶして余分を払い、厚手の鍋に半量のバターと全量の油を強めの中火で熱して泡が立ったら、スネ肉を並べて 4 分間動かさず、底面が深く色付くまで焼き、ひっくり返してもう片面も焼き、皿に取り出す。火を中火に下げて、残りのバターとソフリットを加え、優しく 10 分炒めて柔らかく縁が金色になるまで仕上げ、ワインを注ぎ火を強めて、鍋底のキャラメル化した部分をこそげながら半量まで煮詰める。トマト、ベイリーフ、タイムを混ぜ、スネ肉を一段に戻し入れ、肉の高さの 3 分の 2 までブイヨンを注ぐ — 骨は露出させておき、骨髄が逃げないように — そして火を最弱でぎりぎり沸騰の状態にする。蓋をして最弱火、または 160℃ のオーブンで 2 〜 2 時間半、スネ肉を 30 分ごとに優しく返しながら均一に火を通す — スプーンで押すと肉が骨から崩れ落ち、ソースが艶のあるグレービー状になったら出来上がり — その時点で骨と骨髄は脆いので、注意して取り出す。スネ肉を休ませる間に、レモンの皮、にんにく、パセリを混ぜてグレモラータを作り、皿に 1 個ずつスネ肉を盛り、たっぷりのソースをかけ、生のグレモラータをひとつまみたっぷり王冠のように乗せる — そのキレが豊かさを断ち切り、ただの煮込み仔牛肉ではなく『ミラノ風オッソブーコ』にする — リゾット・アッラ・ミラネーゼ、ポレンタ、または骨髄を取るためのパンと共に供する。","en":"Pat the shanks dry — wet meat steams instead of searing — season aggressively with salt and pepper and dust lightly in flour knocking off the excess, then heat half the butter and all the oil in a heavy braising pan over medium-high heat until foaming, lay the shanks in and do not touch them for 4 minutes until the bottom is deeply browned, flip and do the second side, then lift onto a plate. Lower the heat to medium, add the rest of the butter and the soffritto, and cook gently for 10 minutes until soft and golden at the edges, then pour in the wine, raise the heat, and reduce by half while scraping up the caramelised bits from the bottom of the pan. Stir in the tomatoes, bay leaf and thyme, return the shanks to the pan in a single layer, and pour in just enough stock to come about two-thirds of the way up the meat — the bones should stay exposed so the marrow stays in — and bring to a bare simmer. Cover and braise on the lowest heat or in a 160°C oven for 2 to 2½ hours, turning the shanks gently every 30 minutes so they cook evenly — they are done when the meat slumps off the bone at the press of a spoon and the sauce has thickened to a glossy gravy — then lift them out carefully because the bones and marrow are fragile at this point. While the shanks rest, stir together the lemon zest, garlic and parsley to make the gremolata, place a shank on each plate, spoon over plenty of sauce, and crown with a generous pinch of the raw gremolata — its sharpness cuts the richness and is what makes osso buco Milanese rather than just braised veal — serve with risotto alla milanese, polenta, or a piece of bread for the marrow."}},{"id":202,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":540,"prot":9,"carb":42,"fat":36,"fib":1},"origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"ティラミス","en":"Tiramisu","ro":"Tiramisu"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"ingredients":{"ja":["マスカルポーネ 500 g、室温","L 卵 5 個、卵黄と卵白に分け、室温に戻したもの","グラニュー糖 100 g","濃いめの冷たいエスプレッソ 250 ml（約 5 ショット）","甘口マルサラ酒、またはダークラム 大さじ 2（任意、トレヴィーゾの伝統）","サヴォイアルディ 300 g（イタリアのフィンガービスケット、しっかりした硬めのタイプ）","仕上げ用の無糖ココアパウダー","削り用のダークチョコレート 少々（任意）","卵白用の塩ひとつまみ"],"en":["500 g mascarpone, at room temperature","5 large eggs, separated, at room temperature","100 g caster sugar","250 ml strong cold espresso (about 5 shots)","2 tbsp Marsala (sweet) or dark rum (optional, traditional in Treviso)","300 g savoiardi (Italian ladyfingers — the firm kind, not the soft kind)","Unsweetened cocoa powder for dusting","A small piece of dark chocolate for shaving (optional)","Pinch of salt for the egg whites"],"ro":["500 g mascarpone, la temperatura camerei","5 ouă mari, separate, la temperatura camerei","100 g zahăr tos","250 ml espresso tare rece (aproximativ 5 ceșcuțe)","2 linguri Marsala dulce sau rom închis (opțional, tradițional la Treviso)","300 g savoiardi (pișcoturi italiene — cele ferme, nu cele moi)","Cacao amară pentru pudrare","O bucățică de ciocolată neagră pentru ras (opțional)","Un praf de sare pentru albușuri"]},"howIsMade":{"ja":"大きなボウルで卵黄と砂糖を 4〜5 分間 — 手でも電動の泡立て器でも — 色が淡くなり、泡立ち、体積が劇的に 3 倍に膨らむまで泡立てる；指で少しこすってみて砂糖が完全に溶けているはず、ここで混ぜが足りないとあとでざらついたティラミスになる。マスカルポーネを 3 回に分けて加え、加えるたびに優しく泡立てて、クリームが滑らかで艶を持つまで仕上げる、別の清潔なボウルで卵白に塩ひとつまみを加え、泡立て器を持ち上げても形を保つしっかりとした艶のあるピークまで泡立て、大きなヘラで卵白を 3 回に分けてマスカルポーネに合わせ、中央から外側へと畳むように混ぜて空気を残す — 仕上がりのクリームは軽く、ほとんど流れるようでありながら、柔らかなピークを保っているはず。冷たいエスプレッソとマルサラを浅い皿で混ぜ、サヴォイアルディを 1 本ずつ浸す — ほんの一瞬、片面につき最大 2 秒 — 彼らはスポンジで、浸しすぎたレディーフィンガーはどろどろになり、クリームを通して泣き出す、22×30 cm のバットの底にぴったりと 1 段に並べる。マスカルポーネクリームの半量をレディーフィンガーの上に均等に広げ、もう一度繰り返す — もう一段、浸したサヴォイアルディをぴったり並べ、残りのクリームを上に乗せ、ヘラで平らに整える。ラップで覆い、少なくとも 6 時間、理想的には一晩冷蔵庫で寝かせる — 当日のティラミスはそれぞれのパーツの味、一晩寝かせたティラミスは一つのデザートの味になる — 提供直前に細かなふるいに通してたっぷりのココアを表面に振り、好みでダークチョコレートを少し削り、熱いナイフでカット、一切れごとにナイフを拭く。","en":"Whisk the egg yolks with the sugar in a large bowl for 4–5 minutes — by hand or with an electric beater — until pale, foamy and dramatically tripled in volume; the sugar should be completely dissolved when you rub a little between your fingers, undermixing here gives you a grainy tiramisu later. Add the mascarpone in three batches, whisking gently after each, until the cream is smooth and glossy, then in a separate clean bowl whisk the egg whites with a pinch of salt to firm glossy peaks that hold their shape when the whisk is lifted, and fold the whites into the mascarpone in three additions with a large spatula, folding from the centre outwards to keep the air in — the finished cream should be light, almost pourable but holding soft peaks. Mix the cold espresso and Marsala in a shallow dish, then dip the savoiardi one at a time — just briefly, 2 seconds per side at most — they are sponges, and oversoaked ladyfingers turn to mush and weep through the cream, and lay them in a tight single layer in the bottom of a 22×30 cm dish. Spread half the mascarpone cream over the ladyfingers in an even layer, then repeat — another tight layer of dipped savoiardi, then the rest of the cream on top, smoothed level with the spatula. Cover with clingfilm and refrigerate at least 6 hours, ideally overnight — tiramisu eaten the same day tastes like its parts, tiramisu rested overnight tastes like one dessert — just before serving dust the top generously with cocoa pushed through a fine sieve, shave over a little dark chocolate if you like, and cut with a hot knife wiped between slices."}},{"id":203,"servings":4,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":520,"prot":22,"carb":76,"fat":14,"fib":3},"origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"カチョ・エ・ペペ","en":"Cacio e Pepe","ro":"Cacio e Pepe"},"category":{"ja":"パスタ","en":"Pasta","ro":"Paste"},"ingredients":{"ja":["トンナレッリ、または太めのスパゲッティ 400 g","ペコリーノ・ロマーノ 200 g、マイクロプレーンで細かくおろす（パルメザンは不可 — 同じ溶け方をしない）","黒こしょうの粒、山盛り大さじ 1、すり鉢で挽きたてに砕く（あらかじめ挽いたものは不可）","パスタを茹でる塩水用の海塩（普段より少なめに — チーズ自体が塩辛い）"],"en":["400 g tonnarelli or thick spaghetti","200 g Pecorino Romano, finely grated on a microplane (no Parmesan — it doesn't melt the same way)","1 heaped tablespoon whole black peppercorns, freshly cracked in a mortar (not pre-ground)","Sea salt for the pasta water (less than usual, since the cheese is salty)"],"ro":["400 g tonnarelli sau spaghete groase","200 g Pecorino Romano, ras fin pe microplane (fără Parmezan — nu se topește la fel)","1 lingură plină de boabe întregi de piper negru, proaspăt zdrobite în mojaru (nu măcinat în prealabil)","Sare de mare pentru apa pastelor (mai puțină decât de obicei, fiindcă brânza este sărată)"]},"howIsMade":{"ja":"つぶした黒こしょうを広めの乾いたフライパンに入れて中火で 30 秒、はっきり香りが立つまで空煎りする — そこへ冷水を半お玉分加えて加熱を止め、ピリッとしたペースト状の液体を作る。火から外して脇に置く。\n\n3 L のうっすら塩を効かせた湯を沸騰させ、パスタを袋の表示より 1 分ほど早めにアルデンテ寸前で上げる；ローマではパスタは鍋ではなくソースの中で仕上げる。\n\nパスタを茹でている間に、鍋からマグ 1 杯分のでんぷんを含んだ茹で汁を取り分けておく。広めのボウルで、おろしたペコリーノに茹で汁大さじ 4 ほどを加えて泡立て器で混ぜる — まず数秒冷ましてから加える、沸騰した湯を直接チーズにかけると瞬時に塊になるから — リコッタのような濃いペーストになるまで。固すぎたら茹で汁を 1 さじ追加してゆるめる。\n\nトングでパスタを鍋から直接こしょうのフライパンへ移し（水は切らない）、でんぷん入り茹で汁をお玉 1 杯加え、弱火で 30 秒、力強くあおって絡める — パスタがツヤを帯び、よく絡んだ状態に。\n\nフライパンを火から外す — ペコリーノは沸点を超えると瞬時に糸のように固まる — そこへチーズペーストを流し込み、もう一度素早く混ぜる、必要なら茹で汁を 1 さじずつ足しながら、ソースが各麺にまとわりつくクリーミーなエマルションになるまで。すぐに皿に盛り、もう一度こしょうを挽きかける；カチョ・エ・ペペは冷めるのが速いので、皿は温めてあり、客はすでに席についていることが望ましい。","en":"Toast the cracked pepper in a wide dry pan over medium heat for 30 seconds — until you can smell it sharply — and add half a ladle of cold water to stop the cooking and create a peppery slurry. Set aside off the heat.\n\nBring 3 L of lightly salted water to a boil and cook the pasta until just shy of al dente, about a minute less than the package says; in Rome the pasta finishes cooking in the sauce, not in the pot.\n\nWhile the pasta cooks, scoop out a mug of starchy water from the pot. In a wide bowl, whisk the grated Pecorino with about 4 tablespoons of the hot pasta water — let it cool a few seconds first, since boiling water on cheese clumps it instantly — until you have a thick, ricotta-like paste; loosen with another spoonful of water if it's too stiff.\n\nLift the pasta from the pot with tongs straight into the peppered pan (don't drain it), splash in a ladle of starchy water, and toss vigorously over low heat for 30 seconds, until the pasta is glossy and well coated.\n\nTake the pan off the heat — Pecorino above boiling point seizes into stringy clumps — pour over the cheese paste and toss again, fast, adding more pasta water by the spoonful if needed, until the sauce becomes a creamy emulsion that clings to every strand. Plate immediately with another crack of pepper on top; cacio e pepe cools quickly, so plates should be warm and diners at the table."}},{"id":204,"servings":4,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":720,"prot":42,"carb":28,"fat":48,"fib":4},"origin":{"ja":"インド","en":"India","ro":"India"},"name":{"ja":"バターチキン (ムルグ・マカニ)","en":"Butter Chicken (Murgh Makhani)","ro":"Butter Chicken (Murgh Makhani)"},"category":{"ja":"カレー","en":"Curry","ro":"Curry"},"ingredients":{"ja":["骨なし鶏もも 800 g、4 cm 角に切る","マリネ用：全脂ヨーグルト 200 g、ジンジャー＆ガーリックペースト 大さじ 2、カシミール赤唐辛子粉 小さじ 1、ガラムマサラ 小さじ 1、レモン半個分の果汁、無味の油 大さじ 2、塩 小さじ 1","グレービー用：完熟トマト 800 g（または大缶のカットトマト 1 缶）、生カシューナッツ 60 g、大玉ねぎ 1 個（4 等分）、にんにく 4 片、しょうが 3 cm、グリーンカルダモン 4 粒、シナモンスティック 1 本、クローブ 4 粒、ローリエ 1 枚","無塩バター 80 g、生クリーム 200 ml","カスーリ・メティ（乾燥フェヌグリーク葉）大さじ 1","カシミール唐辛子粉 小さじ 1、ガラムマサラ 小さじ 1、砂糖 小さじ 1、塩","仕上げの生コリアンダー"],"en":["800 g boneless chicken thighs, cut into 4 cm pieces","For the marinade: 200 g full-fat yoghurt, 2 tbsp ginger-garlic paste, 1 tsp Kashmiri red chilli powder, 1 tsp garam masala, juice of half a lemon, 2 tbsp neutral oil, 1 tsp salt","For the gravy: 800 g ripe tomatoes (or 1 large can chopped tomatoes), 60 g raw cashews, 1 large onion quartered, 4 garlic cloves, 3 cm piece of ginger, 4 green cardamom pods, 1 cinnamon stick, 4 cloves, 1 bay leaf","80 g unsalted butter, 200 ml double cream","1 tbsp kasoori methi (dried fenugreek leaves)","1 tsp Kashmiri red chilli powder, 1 tsp garam masala, 1 tsp sugar, salt","Fresh coriander to finish"],"ro":["800 g pulpe de pui dezosate, tăiate în bucăți de 4 cm","Pentru marinadă: 200 g iaurt gras, 2 linguri pastă de ghimbir-usturoi, 1 linguriță boia Kashmiri, 1 linguriță garam masala, zeama de la o jumătate de lămâie, 2 linguri ulei neutru, 1 linguriță sare","Pentru sosul de bază: 800 g roșii coapte (sau o cutie mare de roșii tocate), 60 g caju crud, 1 ceapă mare în sferturi, 4 căței de usturoi, 3 cm bucată de ghimbir, 4 capsule de cardamom verde, 1 baton de scorțișoară, 4 cuișoare, 1 frunză de dafin","80 g unt nesărat, 200 ml smântână grasă","1 lingură kasoori methi (frunze uscate de schinduf)","1 linguriță boia Kashmiri, 1 linguriță garam masala, 1 linguriță zahăr, sare","Coriandru proaspăt pentru a încheia"]},"howIsMade":{"ja":"広めのボウルでマリネ液を混ぜ、鶏肉を加えて 1 切れずつしっかりまとわせ、蓋をして冷蔵庫で少なくとも 4 時間、理想的には一晩漬ける。グレービー用にカシューナッツを 100 ml の熱湯に 20 分浸す；トマト、玉ねぎ、にんにく、生姜、ホールスパイスを厚手の鍋に 200 ml の水と入れ、煮立たせて蓋をして 20〜25 分、トマトが崩れ玉ねぎが完全に柔らかくなるまで煮、シナモン、カルダモン、クローブ、ベイリーフを取り出し、戻したカシューとその水を含めすべてをビロードのようなピューレに撹拌して漉す。グリルを最高温度に予熱し、トレーにアルミ箔を敷き、マリネした鶏肉を間隔をあけて一段に並べ、熱源から 5〜6 cm の距離で各面 6〜8 分、縁が焦げ、肉がちょうど火が通るまで焼く — 縁は本当に黒く焦がす。広めのフライパンでバターを中火で溶かし、漉したグレービーを注ぎ、チリパウダー、砂糖、塩小さじ 1 を加え、頻繁に混ぜながら 10 分弱火で煮込み、色が深いレンガ色に深まるまで；生クリームを加えて滑らかなビロード状になるまで混ぜ、焦げ目のついた鶏肉をトレーの肉汁ごと滑り込ませ、さらに 4〜5 分一緒に煮込む。フライパンの上でカスリメティを手のひらでもんで散らし、ガラムマサラを加え、塩と砂糖の味を整え、コリアンダーの葉を散らし、ナンまたはバスマティライスと共に供する。","en":"Mix the marinade in a wide bowl, add the chicken and turn each piece until well coated, then cover and chill at least 4 hours, ideally overnight. For the gravy, soak the cashews in 100 ml of hot water for 20 minutes; put the tomatoes, onion, garlic, ginger and whole spices into a heavy pan with 200 ml of water, bring to a simmer and cook covered for 20–25 minutes until the tomatoes have collapsed and the onion is fully soft, then fish out the cinnamon, cardamom, cloves and bay leaf, and blend everything — including the soaked cashews and their water — to a velvety purée and pass through a sieve. Heat the broiler high, line a tray with foil, spread the marinated chicken in a single layer with space between the pieces and broil 5–6 cm from the heat for 6–8 minutes per side, until the edges are charred and the meat is just cooked through — let the edges go genuinely dark. Melt the butter in a wide pan over medium heat, pour in the strained gravy and add the chilli powder, sugar and a teaspoon of salt, simmer gently for 10 minutes stirring often until the colour deepens to a rich brick-orange; pour in the cream, stir until the gravy turns velvet, then slide in the charred chicken with any juices from the tray and let everything bubble together for 4–5 minutes more. Crush the kasoori methi between your palms over the pan, stir in the garam masala and taste for salt and sugar, scatter coriander leaves on top, and serve with naan or basmati rice."}},{"id":205,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":780,"prot":38,"carb":78,"fat":32,"fib":3},"origin":{"ja":"インド","en":"India","ro":"India"},"name":{"ja":"ハイデラバード風ラム・ビリヤニ","en":"Hyderabadi Lamb Biryani","ro":"Biryani de miel din Hyderabad"},"category":{"ja":"メイン","en":"Main","ro":"Fel principal"},"ingredients":{"ja":["骨つきラム肩肉または腿肉 800 g、4 cm 角に切る","バスマティ米 500 g、冷水に 30 分浸して水切りする","大玉ねぎ 4 個、ごく薄切り（合計約 600 g）","全脂ヨーグルト 200 g","ギー 50 g + 無味の油 80 ml","ジンジャー＆ガーリックペースト 大さじ 3","青唐辛子 2 本、縦に切れ目を入れる","カシミール赤唐辛子粉 小さじ 2、ターメリック 小さじ 1、塩 小さじ 1","ホールスパイス：シナモンスティック 1 本、グリーンカルダモン 4 粒 + ブラックカルダモン 2 粒、クローブ 4 粒、ローリエ 1 枚、シャヒジーラ 小さじ 1、黒こしょう（粒）小さじ 1","サフランひとつまみを温めた全脂牛乳 60 ml に浸ける","レモン 1 個分の果汁","刻んだミント 大さじ 2、刻んだコリアンダー 大さじ 2","ローズウォーター 大さじ 1（任意、伝統）","封蓋用にやわらかい生地ひとかけ、または厚手のアルミホイル 1 枚"],"en":["800 g bone-in lamb shoulder or leg, cut into 4 cm pieces","500 g basmati rice, soaked 30 minutes in cold water and drained","4 large onions, very thinly sliced (about 600 g)","200 g full-fat yoghurt","50 g ghee + 80 ml neutral oil","3 tbsp ginger-garlic paste","2 green chillies, slit lengthwise","2 tsp Kashmiri red chilli powder, 1 tsp turmeric, 1 tsp salt","Whole spices: 1 cinnamon stick, 4 green cardamom + 2 black cardamom, 4 cloves, 1 bay leaf, 1 tsp shahi jeera, 1 tsp black peppercorns","A pinch of saffron infused in 60 ml warm whole milk","Juice of 1 lemon","2 tbsp chopped mint and 2 tbsp chopped coriander","1 tbsp rose water (optional, traditional)","A piece of soft dough or a sheet of heavy foil for sealing"],"ro":["800 g spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","500 g orez basmati, înmuiat 30 de minute în apă rece și scurs","4 cepe mari, tăiate foarte subțire (aproximativ 600 g)","200 g iaurt gras","50 g ghee + 80 ml ulei neutru","3 linguri pastă de ghimbir-usturoi","2 ardei iuți verzi, despicați pe lungime","2 lingurițe boia Kashmiri, 1 linguriță turmeric, 1 linguriță sare","Mirodenii întregi: 1 baton de scorțișoară, 4 capsule cardamom verde + 2 cardamom negru, 4 cuișoare, 1 frunză de dafin, 1 linguriță shahi jeera, 1 linguriță boabe de piper negru","Un vârf de șofran infuzat în 60 ml lapte cald","Sucul de la 1 lămâie","2 linguri mentă tocată și 2 linguri coriandru tocat","1 lingură apă de trandafiri (opțional, tradițional)","O bucată de aluat moale sau o folie groasă pentru sigilare"]},"howIsMade":{"ja":"厚手の広いフライパンに中火でギーと油を熱し、薄切り玉ねぎを 25〜30 分かけてゆっくり炒め、頻繁にかき混ぜながら深い黄金色（バリスタ）になるまで揚げ焼きし、紙にあげて油を切り、油はフライパンに残し、玉ねぎの半量を層作り用に取り分ける。ラム肉をヨーグルト、ジンジャー・ガーリックペースト、手で潰した炒め玉ねぎの半量、チリパウダー、ターメリック、塩、レモン汁、シャヒ・ジーラ小さじ 1 と合わせ、よく混ぜて冷蔵庫で 2 時間以上、できれば一晩マリネする；マリネしたラムを取っておいた玉ねぎ油に戻し、シナモン、カルダモン、クローブ、ベイリーフを加え、蓋をして弱火で 1 時間〜1 時間 15 分、ラムが柔らかくグレービーが濃いコーティングまで煮詰まるまで煮込む。深鍋にしっかり塩を入れた湯を沸騰させ、残りのホールスパイスと油大さじ 1 を加え、浸水したバスマティを入れて 4〜5 分だけ茹で、米粒が伸び、約 7 分通り火が通る程度に — 残りは蒸気で仕上げる — 素早く優しく湯切りする。同じフライパンのラムの上に米を均等に広げ、残りの炒め玉ねぎ、刻んだミントとコリアンダー、青唐辛子を散らし、サフランミルクを表面にゆっくり筋状に流し入れ、使う場合はローズウォーターも。湿らせた生地のテープか、ぴっちりとしたアルミ箔で蓋を密閉し、最弱火で 25〜30 分、蓋を持ち上げずに火を止めて、さらに 10 分密閉のまま蒸らす — 食卓で封を開け、長いスプーンを底まで差し込み、まっすぐに持ち上げて、1 人分の中に米とラム肉が共に取り出されるように、決して混ぜずに盛る。","en":"Heat the ghee and oil in a wide heavy pan over medium heat and fry the sliced onions slowly for 25–30 minutes, stirring often, until deeply golden brown (birista), then drain on paper, reserve the oil in the pan and keep half the onions for layering. Combine the lamb with the yoghurt, ginger-garlic paste, half of the fried onions crushed in your hand, chilli powder, turmeric, salt, lemon juice and a teaspoon of the shahi jeera, mix thoroughly and rest at least 2 hours or overnight in the fridge; tip the marinated lamb back into the reserved onion oil, add the cinnamon, cardamom, cloves and bay leaf, and cook covered over low heat for an hour to an hour and a quarter, until the lamb is tender and the gravy has reduced to a thick coating. Bring a deep pot of well-salted water to a rolling boil with the rest of the whole spices and a tablespoon of oil, add the soaked basmati and cook just 4–5 minutes until the grains have lengthened and are about three-quarters done — they finish in the steam — then drain quickly and gently. In the same pan over the lamb, spread the rice evenly, scatter the remaining fried onions, chopped mint and coriander, and the green chillies on top, then drizzle the saffron milk in slow streaks across the surface and the rose water if using. Seal the lid with a strip of wet dough or a tight wrap of foil, set on the lowest heat for 25–30 minutes, then turn off the flame without lifting the lid and rest sealed for another 10 minutes — break the seal at the table and plunge a long spoon to the bottom to lift straight up, so each portion comes out with both rice and meat, never stirred together."}},{"id":206,"servings":4,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":480,"prot":22,"carb":18,"fat":36,"fib":5},"origin":{"ja":"インド","en":"India","ro":"India"},"name":{"ja":"パラックパニール","en":"Palak Paneer","ro":"Palak Paneer"},"category":{"ja":"カレー","en":"Curry","ro":"Curry"},"ingredients":{"ja":["新鮮なほうれん草 500 g（または冷凍 250 g、解凍）","パニール 250 g、2 cm 角に切る","大玉ねぎ 1 個、みじん切り","完熟トマト 2 個、刻む（または缶詰のカットトマト 200 g）","にんにく 3 片としょうが 2 cm、合わせてみじん切り","青唐辛子 2 本","クミンシード 小さじ 1","コリアンダーパウダー 小さじ 1、カシミール唐辛子粉 小さじ 1、ターメリック 小さじ ½、ガラムマサラ 小さじ 1","カスーリ・メティ 大さじ 1","生クリーム 80 ml、ギー 大さじ 3","塩 適量","仕上げに、千切りにした生しょうがを少々"],"en":["500 g fresh spinach (or 250 g frozen, defrosted)","250 g paneer, cut into 2 cm cubes","1 large onion, finely chopped","2 ripe tomatoes, chopped (or 200 g chopped tomatoes)","3 garlic cloves and 2 cm piece of ginger, minced together","2 green chillies","1 tsp cumin seeds","1 tsp coriander powder, 1 tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp garam masala","1 tbsp kasoori methi (dried fenugreek leaves)","80 ml double cream, 3 tbsp ghee","Salt to taste","A small piece of fresh ginger, julienned, to finish"],"ro":["500 g spanac proaspăt (sau 250 g congelat, dezghețat)","250 g paneer, tăiat cuburi de 2 cm","1 ceapă mare, tocată mărunt","2 roșii coapte, tocate (sau 200 g roșii tocate)","3 căței de usturoi și o bucată de 2 cm de ghimbir, tocate împreună","2 ardei iuți verzi","1 linguriță semințe de chimion","1 linguriță coriandru pudră, 1 linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță garam masala","1 lingură kasoori methi (frunze uscate de schinduf)","80 ml smântână grasă, 3 linguri ghee","Sare după gust","O bucățică mică de ghimbir proaspăt, tăiată julien, pentru finisat"]},"howIsMade":{"ja":"大鍋にたっぷりの湯を沸かし、ほうれん草を 90 秒湯がいてすぐに氷水のボウルに移し、湯切りして軽く絞り、青唐辛子の 1 本と冷水大さじ数杯と共に滑らかなピューレにする。広めのフライパンに大さじ 1 のギーを熱し、パニールのキューブを中火で各面 2〜3 分、軽く金色になるまで焼き、紙にあげるか、温めた塩水のボウルに浸して残りを調理する間キープしておく。同じフライパンに残りのギーとクミンシードを入れて 30 秒香り立たせ、玉ねぎを入れて 8〜10 分、しんなりして縁が金色になるまで炒め、ジンジャー・ガーリックペーストと 2 本目の切り込みを入れた青唐辛子を加えてさらに 1 分炒める。刻んだトマトをコリアンダー、チリパウダー、ターメリック、小さじ 1 の塩と共に入れて 6〜8 分、マサラがジャム状になり、縁から油が分離し始めるまで炒め、ほうれん草のピューレと水 100 ml を加え、よく混ぜて穏やかに 5 分煮る。パニールのキューブをソースに滑り込ませ、生クリームを回し入れ、カスリメティを手のひらで揉んでフライパンに振り入れ、ガラムマサラを散らし、さらに 2 分加熱、塩を見て、千切り生姜をトップに添え、ナン、パラタ、またはバスマティライスと共に供する。","en":"Bring a large pot of water to a boil, blanch the spinach for 90 seconds and transfer immediately to a bowl of ice water, then drain, squeeze gently and blend to a smooth purée with one of the green chillies and a few tablespoons of cold water. Heat a tablespoon of ghee in a wide pan and fry the paneer cubes over medium heat for 2–3 minutes per side until lightly gold, then lift onto paper or slip them into a bowl of warm salted water while everything else cooks. In the same pan add the remaining ghee and the cumin seeds and let them sizzle for 30 seconds, tip in the onion and cook 8–10 minutes until soft and golden at the edges, then add the ginger-garlic paste and the second slit green chilli and cook a minute more. Stir in the chopped tomato with the coriander, chilli powder, turmeric and a teaspoon of salt and cook 6–8 minutes until the masala is jammy and the oil starts to separate at the edges, then pour in the spinach purée and 100 ml of water, stir well and simmer gently for 5 minutes. Slide the paneer cubes into the gravy, swirl in the cream, crush the kasoori methi between your palms over the pan and sprinkle the garam masala, heat through for another 2 minutes, taste for salt, finish with julienned ginger on top, and serve with naan, paratha or basmati."}},{"id":207,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":620,"prot":40,"carb":12,"fat":44,"fib":2},"origin":{"ja":"インド","en":"India","ro":"India"},"name":{"ja":"ローガン・ジョシュ","en":"Rogan Josh","ro":"Rogan Josh"},"category":{"ja":"カレー","en":"Curry","ro":"Curry"},"ingredients":{"ja":["骨つきラム肩肉または腿肉 1 kg、4 cm 角に切る","マスタードオイル 大さじ 4","全脂ヨーグルト 200 g、なめらかに泡立てる","乾燥カシミール赤唐辛子 4 本、ぬるま湯で 20 分戻してペースト状にすりつぶす（またはカシミール唐辛子粉 大さじ 2）","フェンネルパウダー 小さじ 1","ジンジャーパウダー（ソント） 小さじ 1","アサフォエティダ（ヒング） 小さじ ½","ホールスパイス：グリーンカルダモン 8 粒 + ブラックカルダモン 2 粒、シナモンスティック 1 本、クローブ 6 粒、ローリエ 1 枚","塩 小さじ 1","サフラン ひとつまみを温めた牛乳 大さじ 2 に浸す"],"en":["1 kg bone-in lamb shoulder or leg, cut into 4 cm pieces","4 tbsp mustard oil","200 g full-fat yoghurt, whisked smooth","4 dried Kashmiri red chillies, soaked in warm water 20 minutes and ground to a paste (or 2 tbsp Kashmiri chilli powder)","1 tsp fennel powder","1 tsp dried ginger powder (sonth)","½ tsp asafoetida (hing)","Whole spices: 8 green cardamom + 2 black cardamom, 1 cinnamon stick, 6 cloves, 1 bay leaf","1 tsp salt","A pinch of saffron, soaked in 2 tbsp warm milk"],"ro":["1 kg spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","4 linguri ulei de muștar","200 g iaurt gras, bătut neted","4 ardei roșii Kashmiri uscați, înmuiați 20 de minute în apă caldă și pisați pastă (sau 2 linguri boia Kashmiri)","1 linguriță pudră de fenicul","1 linguriță pudră de ghimbir uscat (sonth)","½ linguriță asafoetida (hing)","Mirodenii întregi: 8 capsule cardamom verde + 2 cardamom negru, 1 baton de scorțișoară, 6 cuișoare, 1 frunză de dafin","1 linguriță sare","Un vârf de șofran, infuzat în 2 linguri lapte cald"]},"howIsMade":{"ja":"厚手の鍋でマスタードオイルを煙が立ち始める寸前まで熱し、一瞬火から外す — この煙が刺激臭を和らげる、焦がさずに — 中火に戻し、ホールスパイスとローリエを入れて 30 秒、油に香りを移す。ラム肉を 1 段に並べ、全面を 8〜10 分かけてしっかり焼き色をつける（この料理の焼き色のチャンスはこれ 1 回だけだから、しっかり色を出す）、アサフォエティダ、ジンジャーパウダー、フェンネルパウダーを加え、熱い油で肉を 1 分包む。ヨーグルトにカシミール唐辛子のペーストと冷水大さじ 1 を加えて混ぜ、鍋にひしゃく 1 杯ずつ加え、加えるたびに絶えず混ぜる — ゆっくり加えれば、ヨーグルトは分離しない — 塩を加えて火を弱め、蓋をして 10 分、ヨーグルトが艶のある赤いベースに溶けるまで煮る。熱湯 500 ml を加えて再沸騰させ、火を最弱にし、蓋をして 1 時間 20 分、20 分ごとに混ぜながら煮込む、ラムがスプーンに従って崩れ、ソースが薄く艶のある深いマホガニー色になるまで；サフランミルクは終了の 5 分前に流し入れ、完全には混ぜきらない。火から外して 10 分休ませ、蒸したバスマティライスと共に供する — ローガン・ジョシュはスープに近い料理、鮮やかな色と豊かな香りを持ち、辛さで攻めない；辛さは肉そのものから、色は唐辛子から、香りはそれ以外のすべてから来る。","en":"Heat the mustard oil in a heavy pan until it just begins to smoke, then pull it off the heat for a moment — letting it smoke neutralises the raw pungency without scorching — and return to medium heat, add the whole spices and bay leaf, and let them perfume the oil for 30 seconds. Add the lamb in a single layer and brown well on all sides for 8–10 minutes (this is the only browning the dish gets, so let the colour develop properly), then stir in the asafoetida, ginger powder and fennel powder and let them coat the meat in the hot oil for another minute. Whisk the yoghurt with the Kashmiri chilli paste and a tablespoon of cold water, then add it to the pan a ladleful at a time stirring continuously after each addition — going slowly keeps the yoghurt from splitting — add the salt, lower the heat and cook covered for 10 minutes until the yoghurt has melted into a glossy red base. Pour in 500 ml of hot water, bring back to a simmer, then drop the heat to its lowest and braise covered for an hour and 20 minutes, stirring every 20 minutes, until the lamb yields to a spoon and the gravy is thin, glossy and a deep mahogany red; swirl the saffron milk through 5 minutes before the end without fully stirring it out. Rest off the heat for 10 minutes before serving with steamed basmati — Rogan Josh is meant to be soup-like, brilliantly coloured and aromatic rather than spicy hot, the heat supplied by the meat, the colour by the chillies, and the perfume by everything else."}},{"id":208,"servings":8,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":280,"prot":6,"carb":32,"fat":14,"fib":3},"origin":{"ja":"インド","en":"India","ro":"India"},"name":{"ja":"サモサ","en":"Samosa","ro":"Samosa"},"category":{"ja":"軽食","en":"Snack","ro":"Gustare"},"ingredients":{"ja":["生地：薄力粉 300 g、アジョワンシード 小さじ 1、塩 小さじ ½、ギーまたは無味の油 60 ml、冷水 120 ml","フィリング：粉質じゃがいも 500 g（マリスパイパーやラセット）、冷凍グリーンピース 100 g、無味の油 大さじ 2、クミンシード 小さじ 1、青唐辛子 1 本みじん切り、しょうが 2 cm みじん切り","コリアンダーパウダー 小さじ 1、ガラムマサラ 小さじ 1、カシミール唐辛子粉 小さじ ½、ターメリック 小さじ ½、アムチュール（乾燥マンゴーの粉）小さじ 1、塩 小さじ 1","生コリアンダー ひとつかみ、刻む","揚げ油用の無味の油 約 1 L","添え：タマリンドのチャツネとミント＆コリアンダーのチャツネ"],"en":["For the pastry: 300 g plain flour, 1 tsp ajwain (carom) seeds, ½ tsp salt, 60 ml ghee or neutral oil, 120 ml cold water","For the filling: 500 g floury potatoes (Maris Piper or Russet), 100 g frozen peas, 2 tbsp neutral oil, 1 tsp cumin seeds, 1 green chilli minced, 2 cm piece of ginger minced","1 tsp coriander powder, 1 tsp garam masala, ½ tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp amchur (dried mango powder), 1 tsp salt","A handful of fresh coriander, chopped","About 1 L neutral oil for deep-frying","To serve: tamarind chutney and mint-coriander chutney"],"ro":["Pentru aluat: 300 g făină albă, 1 linguriță semințe de ajwain (chimen-aristotel), ½ linguriță sare, 60 ml ghee sau ulei neutru, 120 ml apă rece","Pentru umplutură: 500 g cartofi făinoși (Maris Piper sau Russet), 100 g mazăre congelată, 2 linguri ulei neutru, 1 linguriță semințe de chimion, 1 ardei iute verde tocat, 2 cm bucată de ghimbir tocat","1 linguriță coriandru pudră, 1 linguriță garam masala, ½ linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță amchur (pudră de mango uscat), 1 linguriță sare","Un mănunchi de coriandru proaspăt, tocat","Aproximativ 1 l ulei neutru pentru prăjit","Pentru servit: chutney de tamarind și chutney de mentă-coriandru"]},"howIsMade":{"ja":"ギーを薄力粉、アジョワン、塩の中に指先ですり込み、粗いパン粉のような状態にする — この脂の量こそが、サモサの皮にあのビスケットのような波打つカリッとした食感を与える — 冷水を大さじ 1 ずつ加え、しっかりしてなめらかな生地にこねる（チャパティより少し柔らかく、パンよりは硬い）、覆って 30 分休ませる。じゃがいもを皮ごとちょうど火が通るまで茹で、湯切りして皮を剥き、フォークの背で粗くつぶす（マッシュではなく食感を残す）；広めの鍋で油を熱し、クミンシードを入れて香りを立たせ、しょうがと青唐辛子を 30 秒、乾燥スパイスを加えてさっと炒め、じゃがいも、グリーンピース、塩、アムチュール、コリアンダーを入れ、全体を返しながら 4〜5 分、スパイスが一切れ一切れにまとうまで炒める — 成形する前に常温まで冷ます。生地を 8 個の球に分け、1 つを長さ約 18 cm の薄い楕円形に伸ばし、中央でカットして半円を 2 つ作る；半円を 1 枚取り、直線の縁に細い水のラインを刷毛で塗り、直線の角どうしが 1 cm 重なるようにコーン状に巻く、継ぎ目をしっかりつまんで閉じる。片手でコーンを持ち、4 分の 3 までじゃがいもの具を詰め、開いた縁を片側に小さなひだを折り込みながら閉じ、湿らせた指で縁を完全に密着させる — この折り込みがサモサ特有の側面の稜線を作り、揚げるときに自立する助けにもなる — 残りも同じ手順で。揚げ油を 150℃ に熱する（思うより低めだが、このゆっくりした温度上昇こそが皮にあの気泡を作る）、サモサを 3〜4 個ずつ落とし入れて優しく返しながら 6〜7 分、淡い黄金色になるまで揚げ、温度を 180℃ に上げてさらに 3〜4 分、深い黄金色とちゃんとした歯ごたえになるまで揚げる、網にあげて油を切り、温かいうちにタマリンドとミントのチャツネを添えて供する。","en":"Rub the ghee into the flour, ajwain and salt with your fingertips until the mixture resembles coarse breadcrumbs — the amount of fat is what gives samosa pastry its blistered, biscuit-crisp shell — then add the cold water a tablespoon at a time, mixing into a stiff smooth dough (softer than chapati but firmer than bread dough) and rest it covered for 30 minutes. Boil the potatoes in their skins until just tender, drain, peel and crush coarsely with the back of a fork (you want texture, not mash); heat the oil in a wide pan, add the cumin seeds and let them sizzle, then the ginger and green chilli for 30 seconds, stir in the dry spices and fry briefly, tip in the potato, peas, salt, amchur and coriander, and cook 4–5 minutes turning everything until the spices coat every piece — cool to room temperature before shaping. Divide the dough into 8 balls, roll one into a thin oval about 18 cm long and cut across the middle to make two half-circles; take one half, brush a thin line of water along the straight edge, and fold into a cone by bringing the two corners of the straight edge together so they overlap by 1 cm, pinching the seam tightly to seal. Hold the cone in one hand, fill it three-quarters with potato, then pleat the open edge by folding a small tuck on one side and sealing the rim shut with a damp finger — the tucked pleat creates the samosa's signature side ridge and helps it sit upright while cooking — and repeat with the rest. Heat the frying oil to 150°C (lower than you might expect, but the slow climb is what gives the shell its blisters), slip in the samosas in batches of 3 or 4 and fry 6–7 minutes turning gently until pale gold, then raise the heat to 180°C and fry another 3–4 minutes until deep golden and properly crisp, draining on a rack and serving hot with tamarind and mint chutneys."}},{"id":209,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":620,"prot":32,"carb":22,"fat":44,"fib":5},"origin":{"ja":"タイ","en":"Thailand","ro":"Thailanda"},"name":{"ja":"グリーンカレー (ゲーン・キアオ・ワーン)","en":"Green Curry (Gaeng Khiao Wan)","ro":"Curry verde (Gaeng Khiao Wan)"},"category":{"ja":"カレー","en":"Curry","ro":"Curry"},"ingredients":{"ja":["グリーンカレーペースト 大さじ 4（自家製または Mae Ploy など信頼できるタイブランド）","全脂ココナッツミルク 400 ml（Aroy-D が理想)","ココナッツクリーム 200 ml（缶の上の濃い部分、または 100 ml と上澄みを合わせて）","鶏もも肉 500 g、3 cm 角に切る","タイなす 4 個、4 等分（または小ぶりのアジアなす 1 個を角切り）","ピーなすひとつまみ（主に飾り、任意）","竹の子のスライス 100 g","コブミカンの葉 4 枚、軸を除いて手でちぎる","赤い長唐辛子 2 本、斜め薄切り","パームシュガー 大さじ 1（または淡いブラウンシュガー）","タイの魚醤 大さじ 2","タイ・バジル（ホラパー）の葉ひとつかみ","ジャスミンライス、添えて"],"en":["4 tbsp green curry paste (homemade, or a good Thai brand like Mae Ploy)","400 ml full-fat coconut milk (Aroy-D is ideal)","200 ml coconut cream (the thick top layer from the can, or 100 ml plus the skimmed cream)","500 g chicken thighs, cut into 3 cm pieces","4 Thai eggplants, quartered (or 1 small Asian eggplant cubed)","A small handful of pea eggplants (mainly garnish, optional)","100 g bamboo shoots, sliced","4 kaffir lime leaves, torn (stem removed)","2 long red chillies, sliced thinly on the bias","1 tbsp palm sugar (or light brown sugar)","2 tbsp Thai fish sauce","A small handful of Thai basil leaves (horapha)","Jasmine rice to serve"],"ro":["4 linguri pastă curry verde (de casă sau o marcă thailandeză bună precum Mae Ploy)","400 ml lapte de cocos gras (ideal Aroy-D)","200 ml smântână de cocos (stratul gros de deasupra cutiei, sau 100 ml plus crema rămasă)","500 g pulpe de pui, tăiate în bucăți de 3 cm","4 vinete thailandeze, tăiate în sferturi (sau 1 vânătă asiatică mică, cuburi)","Un mic mănunchi de vinete-mazăre (în principal pentru garnitură, opțional)","100 g vârfuri de bambus, feliate","4 frunze de lămâi kaffir, rupte (codița înlăturată)","2 ardei roșii lungi, feliați subțire în diagonală","1 lingură zahăr de palmier (sau zahăr brun deschis)","2 linguri sos de pește thailandez","Un mic mănunchi de busuioc thailandez (horapha)","Orez iasomie pentru servit"]},"howIsMade":{"ja":"中火にかけた中華鍋か厚手の鍋にココナッツクリームを入れ、4〜5 分、ときどき混ぜながら煮る — 油が浮き上がり、クリームが油光を帯びるまで；この最初の一手こそ、タイ料理店のグリーンカレーと家でやると水っぽいやつを分ける土台の工程。割れたクリームにグリーンカレーペーストを加え、絶え間なく混ぜながら 2〜3 分炒める — ペーストが色を深め、ガランガル、レモングラス、タイ・バジルの香りを放ち、油が鮮やかな緑色に変わるまで；台所はバンコクの裏通りの匂いになる。鶏肉を加え、ペーストにくぐらせるように絡め、3〜4 分焼いて半分火が通ったら、ココナッツミルクを注いで穏やかに沸かす；なす、たけのこ、ちぎったコブミカンの葉を加え、蓋をせずに 10〜12 分、なすが柔らかく鶏に火がちょうど通るまで煮る。ナンプラーとパームシュガーで味を整え、途中で必ず味を見る — グリーンカレーは塩味・甘み・ハーバルな香り・青唐辛子のクリーンな辛味を同時に当ててくる味であるべき — スライスした赤唐辛子とタイ・バジルを加え、鍋を一度回し、30 秒後に火から下ろす；器の中でバジルが鮮やかなまま残るように。浅めの器に盛り、ジャスミンライスを添える。","en":"In a wok or heavy pan over medium heat, spoon in the coconut cream and let it cook for 4–5 minutes, stirring occasionally, until the oil cracks out and the cream takes on a slick sheen — this foundation step is what separates Thai-restaurant green curry from the watery home version. Add the green curry paste to the split cream and fry for 2–3 minutes, stirring constantly, until the paste darkens, releases its perfume of galangal, lemongrass and Thai basil, and the oil turns a vivid green — the kitchen will smell like a Bangkok back street. Slide in the chicken and turn the pieces in the paste until coated, cook 3–4 minutes until the meat is half-sealed, then pour in the coconut milk and bring to a gentle simmer; add the eggplants, bamboo shoots and torn kaffir lime leaves, and simmer uncovered for 10–12 minutes until the eggplants are tender and the chicken is just cooked through. Season with the fish sauce and palm sugar, tasting as you go — the curry should hit salty, sweet, herbaceous and a clean green chilli heat all at once — then stir in the sliced red chillies and Thai basil, swirl the pan once and take it off the heat after 30 seconds so the basil stays bright in the bowl. Serve in shallow bowls with jasmine rice on the side."}},{"id":210,"servings":6,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":680,"prot":36,"carb":38,"fat":42,"fib":6},"origin":{"ja":"タイ","en":"Thailand","ro":"Thailanda"},"name":{"ja":"マッサマンカレー","en":"Massaman Curry","ro":"Massaman"},"category":{"ja":"カレー","en":"Curry","ro":"Curry"},"ingredients":{"ja":["マッサマンカレーペースト 大さじ 4（Mae Ploy が安定）","牛すね肉または肩肉 1 kg、5 cm 角に切る","全脂ココナッツミルク 800 ml","ココナッツクリーム 200 ml","粘質系のじゃがいも（シャルロットまたはユーコンゴールド）500 g、皮をむいて 4 cm 角に切る","小玉ねぎ 2 個、皮をむいて 4 等分","ローストした無塩ピーナッツ 100 g（数粒は飾り用に砕く）","ホールスパイス：カルダモン 5 粒、シナモンスティック 1 本、クローブ 4 粒、八角 1 個、ローリエ 1 枚","タマリンドペースト 大さじ 3（代用なら ライム 1 個分の果汁）","パームシュガー 大さじ 3","タイの魚醤 大さじ 3","コブミカンの葉 4 枚、手でちぎる","添えにジャスミンライス"],"en":["4 tbsp Massaman curry paste (Mae Ploy is reliable)","1 kg beef shin or chuck, cut into 5 cm cubes","800 ml full-fat coconut milk","200 ml coconut cream","500 g waxy potatoes (Charlotte or Yukon Gold), peeled and cut into 4 cm chunks","2 small onions, peeled and quartered","100 g roasted unsalted peanuts (a few crushed for garnish)","Whole spices: 5 cardamom pods, 1 cinnamon stick, 4 cloves, 1 star anise, 1 bay leaf","3 tbsp tamarind paste (or juice of 1 lime as a back-up)","3 tbsp palm sugar","3 tbsp Thai fish sauce","4 kaffir lime leaves, torn","Jasmine rice to serve"],"ro":["4 linguri pastă Massaman (Mae Ploy este o alegere sigură)","1 kg rasol sau pulpă de vită, tăiată în cuburi de 5 cm","800 ml lapte de cocos gras","200 ml smântână de cocos","500 g cartofi cu textură fermă (Charlotte sau Yukon Gold), curățați și tăiați în bucăți de 4 cm","2 cepe mici, curățate și tăiate în sferturi","100 g arahide prăjite nesărate (câteva zdrobite pentru ornat)","Mirodenii întregi: 5 capsule cardamom, 1 baton de scorțișoară, 4 cuișoare, 1 anason stelat, 1 frunză de dafin","3 linguri pastă de tamarind (sau zeama de la 1 lime de rezervă)","3 linguri zahăr de palmier","3 linguri sos de pește thailandez","4 frunze de lămâi kaffir, rupte","Orez iasomie pentru servit"]},"howIsMade":{"ja":"厚手の鍋にココナッツクリームを入れて中火で 5 分、ときどき混ぜながら煮詰める — 油が浮き出し、クリームが艶を帯び、わずかにざらつき始めるまで。マッサマンペーストとホールスパイスを加えて 3 分炒める — ペーストは色を深め、台所はシナモン、カルダモン、焙煎クミンの香りに包まれる；スパイスを早めに花開かせるこの工程こそ、マッサマンに与えられるペルシャ的な深みの源だ。牛肉を加えてペーストにくぐらせ、表面が暗い赤に染まるまで返したら、ココナッツミルク、タマリンドペースト、コブミカンの葉を注ぎ、ぎりぎり沸騰しない火加減にして、蓋を少し開けたまま 1 時間半、20 分ごとにかき混ぜながら煮込む — スプーンで押すと簡単にほどけるが形は残っている、それが牛肉の合図。じゃがいも、玉ねぎ、ピーナッツを加え、蓋を取ったまま 30 分、じゃがいもが柔らかく、ソースが艶のある濃い茶色になるまで煮詰め、最後にナンプラーとパームシュガーを加えて塩味・甘味・酸味の三角を、深くまろやかな味になるまで整える — 甘すぎず、刺し過ぎず。火から下ろし 10 分休ませ、浅めの器にジャスミンライスを添えて盛り、上に砕いたピーナッツを少し散らす — マッサマンは一晩寝かせて深みを増すタイカレーで、翌日の方が美味い。","en":"Spoon the coconut cream into a heavy pot over medium heat and let it cook for 5 minutes, stirring, until the oil separates and the cream looks glossy and slightly grainy. Add the Massaman paste and the whole spices and fry for 3 minutes — the paste will darken and the kitchen should smell of cinnamon, cardamom and roasted cumin; this early bloom of the spices is what gives Massaman its Persian-inflected depth. Add the beef and turn it in the paste until every piece is dark red, pour in the coconut milk, tamarind paste and kaffir lime leaves, bring to a bare simmer and braise gently with the lid ajar for an hour and a half, stirring every 20 minutes — the beef is ready when it gives easily to a spoon but still holds its shape. Slide in the potatoes, onions and peanuts and continue cooking uncovered for another 30 minutes until the potatoes are tender and the gravy has thickened to a glossy rich brown; stir in the fish sauce and palm sugar at the end, balancing the salt-sweet-sour triangle until it tastes deep and round, neither too sweet nor too sharp. Rest off the heat for 10 minutes, then serve in shallow bowls with jasmine rice, scattered with a few crushed peanuts on top — Massaman is the Thai curry that gains depth overnight, and any leftovers taste better the next day."}},{"id":211,"servings":4,"tipType":"veg","pairingsType":"thai","nutrition":{"cal":180,"prot":6,"carb":28,"fat":6,"fib":4},"origin":{"ja":"タイ","en":"Thailand","ro":"Thailanda"},"name":{"ja":"ソムタム","en":"Som Tam","ro":"Som Tam"},"category":{"ja":"サラダ","en":"Salad","ro":"Salată"},"ingredients":{"ja":["青パパイヤ（未熟）400 g、皮を剥いて極細の千切り","ミニトマト 4 個、半分に切る","ヤードロングビーンズ 2 本、または インゲン 4 本、4 cm に切る","にんにく 2 片、皮を剥く","プリッキーヌー（鳥目唐辛子） 2 本（または好みで)","パームシュガー 大さじ 2","タイの魚醤 大さじ 2","ライム 1 個分の果汁","タマリンドペースト 大さじ 1","干しエビ 大さじ 1","ローストピーナッツ 大さじ 2（一部は砕き、一部はそのまま）","添え用のアイスバーグ・レタスやキャベツの葉（任意、伝統)"],"en":["400 g green (unripe) papaya, peeled and finely julienned","4 cherry tomatoes, halved","2 long beans (yardlong) or 4 green beans, cut into 4 cm lengths","2 garlic cloves, peeled","2 bird's eye chillies (or to taste)","2 tbsp palm sugar","2 tbsp Thai fish sauce","Juice of 1 lime","1 tbsp tamarind concentrate","1 tbsp dried shrimp","2 tbsp roasted peanuts (some crushed, some whole)","Iceberg lettuce or cabbage leaves to serve (optional, traditional)"],"ro":["400 g papaya verde (necoaptă), curățată și tăiată julienne foarte fin","4 roșii cherry, tăiate în jumătăți","2 fasole lungă (yardlong) sau 4 fire de fasole verde, tăiate în bucăți de 4 cm","2 căței de usturoi, curățați","2 ardei iuți bird's eye (sau după gust)","2 linguri zahăr de palmier","2 linguri sos de pește thailandez","Sucul de la 1 lime","1 lingură concentrat de tamarind","1 lingură creveți uscați","2 linguri arahide prăjite (unele zdrobite, altele întregi)","Frunze de salată iceberg sau varză pentru servit (opțional, tradițional)"]},"howIsMade":{"ja":"クロック（タイの素焼き乳鉢）または頑丈な石臼で、にんにくと唐辛子を一緒に砕く — 粉にせず、香りが開く程度まで — その後パームシュガーを加えて数回叩き、唐辛子の油に溶け込ませる。ナンプラー、ライム果汁、タマリンドを注ぎ、すりこぎで混ぜて砂糖を溶かし、続けて干しエビを加えて 2 回ほど叩いてドレッシングに平らに溶け込ませる。ヤードロングビーンズと半分に切ったミニトマトを加えて優しく叩く — 各 5〜6 回ずつ、軽く潰してジュースをドレッシングに移すだけでいい — すりこぎはここでは味付けの道具であって、破壊の道具ではない。青パパイヤの千切りを 2 回に分けて加え、軽く叩いてはスプーンで全体を返すを繰り返し、すべての糸がドレッシングで光りながらシャキ感を残している状態に仕上げ、続いてピーナッツを加える（食感のために丸ごと、コクのために砕いたものを）、もう一度だけ全体を返す。味を見る — ソムタムは「酸味・塩味・甘味・容赦のない辛味」の四つを同時に当ててこなければならない — 浅い器、あるいはレタスの上に盛り、もち米やグリルチキンと共にすぐに食べる。","en":"In a clay krok or sturdy stone mortar, pound the garlic and chillies together until bruised — not pulverised, just opened up — then add the palm sugar and pound a few more times to dissolve it into the chilli oil. Pour in the fish sauce, lime juice and tamarind, stir with the pestle until the sugar dissolves, then tip in the dried shrimp and pound a couple of times to flatten them into the dressing. Add the long beans and tomato halves and pound gently — five or six taps each, just enough to bruise them and release their juices into the dressing — the pestle here is a tool of seasoning, not destruction. Tip in the shredded papaya in two batches, alternating light pounding with turning everything with a spoon until each strand is glossy with the dressing but still crisp, then add the peanuts (whole for crunch, crushed for body) and toss one last time. Taste — Som Tam should hit four flavours at once: sour, salty, sweet and chilli-fierce — then pile into shallow bowls or onto lettuce leaves and eat immediately with sticky rice or grilled chicken."}},{"id":212,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":720,"prot":32,"carb":60,"fat":38,"fib":4},"origin":{"ja":"タイ","en":"Thailand","ro":"Thailanda"},"name":{"ja":"カオソーイ","en":"Khao Soi","ro":"Khao Soi"},"category":{"ja":"麺スープ","en":"Noodle soup","ro":"Tăiței în supă"},"ingredients":{"ja":["北タイのカオソーイ用カレーペースト 大さじ 4（または レッドカレーペースト 大さじ 3 + カレー粉 小さじ 1 + ターメリック 小さじ 1）","骨つき鶏もも 500 g、または ぶつ切りにした鶏脚","全脂ココナッツミルク 800 ml","ココナッツクリーム 200 ml","鶏のだし 500 ml","タイの魚醤 大さじ 2","パームシュガー 大さじ 1","生卵麺 400 g（または乾燥麺 300 g）","麺をひとつかみ揚げる用の無味の油","ライム 2 個分の果汁、食卓で加える","薬味：エシャロットの薄切り、漬けからし菜、生コリアンダー、ライムのくし切り、辣油"],"en":["4 tbsp Northern Thai khao soi curry paste (or 3 tbsp red curry paste + 1 tsp curry powder + 1 tsp ground turmeric)","500 g bone-in chicken thighs or chicken legs cut into pieces","800 ml full-fat coconut milk","200 ml coconut cream","500 ml chicken stock","2 tbsp Thai fish sauce","1 tbsp palm sugar","400 g fresh egg noodles (or 300 g dried)","Neutral oil for deep-frying a handful of noodles","Juice of 2 limes, added at the table","Garnishes: sliced shallots, pickled mustard greens, fresh coriander, lime wedges, chilli oil"],"ro":["4 linguri pastă de curry Khao Soi din nordul Thailandei (sau 3 linguri pastă curry roșu + 1 linguriță curry pudră + 1 linguriță turmeric)","500 g pulpe de pui cu os sau pulpe întregi tăiate în bucăți","800 ml lapte de cocos gras","200 ml smântână de cocos","500 ml fond de pui","2 linguri sos de pește thailandez","1 lingură zahăr de palmier","400 g tăiței de ouă proaspeți (sau 300 g uscați)","Ulei neutru pentru a prăji o mână de tăiței","Sucul de la 2 lime, adăugat la masă","Garnituri: șalote feliate, frunze de muștar murate, coriandru proaspăt, felii de lime, ulei de chili"]},"howIsMade":{"ja":"厚手の鍋に中火でココナッツクリームを 4〜5 分熱し、油が浮き出てクリームが艶を帯びるまで詰めたら、カオソーイのカレーペーストを加えて 2〜3 分炒め、色が深まり、台所が深く焙煎されたような香りになるまで仕上げる——中部タイのカレーよりも重く、土の匂いを帯びている、ペーストが乾燥スパイスに寄っているから。鶏肉を加えてペーストにまとわせ、ココナッツミルクと鶏のだしを注ぎ、穏やかに沸騰させ、蓋を少し開けたまま 30〜35 分、鶏がほろりと崩れる柔らかさになり、汁が少し詰まるまで煮る；仕上がり前にナンプラーとパームシュガーで味を整え、汁がリッチで、ほのかに甘く、ペースト自体からくる淡い酸味を持つようにする。煮ている間に、生卵麺をひとつまみ取って余分な水気を払い、180℃ の油で 30〜45 秒、ふくらんで黄金色になるまで揚げる——各椀の上にのる「カリッとした王冠」——紙にあげて油を切る。残りの麺は普通の湯でちょうど火が通るまで茹で、手早く湯切りして深めの椀に分けて入れ、熱いカレーを 1 椀につき少なくとも鶏肉が 1 切れ入るように注ぎ、揚げた麺をのせる。薬味を食卓に回す——エシャロットの薄切り、漬けからし菜、コリアンダー、最後に絞るためのライムくし切り、ひとさじの辣油——この料理は対比で生きる（絹のような汁、その下の柔らかい麺、上のカリカリの麺、生エシャロットの噛みごたえ、漬物の酸、ライムの光）、1 椀のカオソーイは必ず食卓で完成される。","en":"Heat the coconut cream in a heavy pot over medium heat for 4–5 minutes until the oil cracks out and the cream looks slick, then stir in the khao soi paste and fry for 2–3 minutes until it darkens and smells deeply toasted — heavier and earthier than central-Thai curries because the paste leans on dry spices. Add the chicken pieces and turn them in the paste until coated, pour in the coconut milk and stock, bring to a gentle simmer and cook with the lid ajar for 30–35 minutes until the chicken is meltingly tender and the broth has reduced a little; season with fish sauce and palm sugar towards the end so the broth is rich, gently sweet and faintly sour from the curry paste itself. While the curry simmers, take a small handful of the fresh egg noodles, shake off any excess water, and deep-fry in 180°C oil for 30–45 seconds until puffed and golden — the crispy crown for every bowl — then drain on paper. Boil the remaining noodles in plain water until just tender, drain quickly and divide between deep bowls, ladle over the hot curry with at least one piece of chicken per portion, and top with the fried noodles. Pass the garnishes round the table — sliced shallots, pickled mustard greens, coriander, a lime wedge to squeeze in last, and a spoon of chilli oil — the dish lives on contrast (silky soup, soft noodles below, crisp on top, raw shallot bite, pickle tang, lime brightness) and each bowl is built at the table."}},{"id":213,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":520,"prot":6,"carb":92,"fat":16,"fib":4},"origin":{"ja":"タイ","en":"Thailand","ro":"Thailanda"},"name":{"ja":"マンゴーともち米 (カオ・ニャオ・マムアン)","en":"Mango Sticky Rice (Khao Niao Mamuang)","ro":"Orez glutinos cu mango (Khao Niao Mamuang)"},"category":{"ja":"デザート","en":"Dessert","ro":"Desert"},"ingredients":{"ja":["タイのもち米（カオニャオ）300 g、冷水で 4 時間以上、できれば一晩浸ける","全脂ココナッツミルク 400 ml","パームシュガー 80 g（または淡いブラウンシュガー）","塩 小さじ ½","結んだパンダンリーフ 1 枚（任意、伝統)","完熟した黄色いマンゴー 2 個（ナムドクマイまたはアタウルフォ）、皮を剥いてスライス","ローストした白ごま、または剥いた緑豆 大さじ 2、飾り用","米粉 小さじ 1（任意、塩気のあるソースをとろませる用)"],"en":["300 g Thai glutinous (sticky) rice, soaked in cold water at least 4 hours or overnight","400 ml full-fat coconut milk","80 g palm sugar (or light brown sugar)","½ tsp salt","1 pandan leaf, tied in a knot (optional, traditional)","2 ripe yellow mangoes (Nam Dok Mai or Ataulfo), peeled and sliced","2 tbsp toasted sesame seeds or split mung beans, for garnish","1 tsp rice flour (optional, for thickening the salty topping)"],"ro":["300 g orez glutinos thailandez (lipicios), pus la înmuiat în apă rece minim 4 ore sau peste noapte","400 ml lapte de cocos gras","80 g zahăr de palmier (sau zahăr brun deschis)","½ linguriță sare","1 frunză de pandan, legată în nod (opțional, tradițional)","2 mango galbene coapte (Nam Dok Mai sau Ataulfo), curățate și feliate","2 linguri semințe de susan prăjite sau mazăre mungo decorticată, pentru garnitură","1 linguriță făină de orez (opțional, pentru a îngroșa topping-ul sărat)"]},"howIsMade":{"ja":"浸したもち米の水を切る。蒸し器のかごにさらしかバナナの葉を敷き、もち米を入れて、しっかり蒸気が立った状態で蓋をして 20〜25 分蒸す——蒸し時間の半ばに布を持ち上げて米の山をひっくり返し均一に火を通す；米粒が半透明で艶があり、芯までもちっと柔らかくなったら完成。米を蒸している間に、ココナッツミルク 300 ml を小鍋に入れ、パームシュガー、塩、結んだパンダンリーフを加え、砂糖が溶ける程度に混ぜる——沸騰させない；残りの 100 ml は塩気の仕上げ用にとっておく。蒸しあがった熱々のもち米を広めの器に移し、温かい甘いココナッツミルクの 3 分の 2 をヘラで折りたたむように混ぜてすべての粒が艶を帯びるまで仕上げ、蓋をして 15〜20 分置く——米がミルクを飲み、柔らかなパールプディングのような食感まで膨らむ。塩気の仕上げソースには、残りの 100 ml のココナッツミルクを塩ひとつまみたっぷりと小さじ 1 の米粉と一緒に 2 分煮る、ちょうど少しとろみがつくまで。温かいココナッツライスを皿に山型に盛り、横にマンゴーのスライスを並べ、塩気のあるココナッツクリームを上から回しかけ、ローストしたごまや剥いた緑豆を散らし、スプーンでひと口ごとに少しのご飯と少しのマンゴーを一緒に食べる——温かいココナッツの甘さと冷たい果実の鋭さの対比、それこそが料理本体だ。","en":"Drain the soaked rice; line a steamer basket with cheesecloth or banana leaf, tip in the rice and steam covered over a moderate boil for 20–25 minutes, lifting the cloth halfway to flip the mound so it cooks evenly — done when the grains are translucent, glossy and chewy-tender all the way through. While the rice steams, warm 300 ml of the coconut milk in a small saucepan with the palm sugar, salt and pandan leaf, stirring just enough to dissolve the sugar without bringing it to a boil; reserve the remaining 100 ml for the salty topping. When the rice comes hot off the steamer, tip it into a wide bowl, fold through two-thirds of the warm sweet coconut milk with a spatula until each grain glistens, then cover and rest 15–20 minutes so the rice drinks the milk and swells to a soft pearl-pudding consistency. For the salty topping, simmer the remaining 100 ml coconut milk with a generous pinch of salt and the teaspoon of rice flour for 2 minutes, just until it thickens lightly. Mound the warm coconut rice on a plate with the mango slices alongside, drizzle the salty coconut cream across the top, scatter toasted sesame seeds or split mung beans, and eat with a spoon, a little rice and a little mango in every bite — warm coconut-sweet against cool fruit-sharp is the dish itself."}},{"id":214,"tipType":"meat","pairingsType":"meat","origin":{"ja":"インターナショナル","en":"International","ro":"Internațional"},"name":{"ja":"ラムシチュー","en":"Lamb Stew","ro":"Tocăniță de miel"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["ラム肩肉800g（角切り）","玉ねぎ2個","にんじん3本","じゃがいも3個","にんにく2片","トマトペースト大さじ2","ビーフストック500ml","タイム、ローリエ","塩、こしょう、オリーブオイル"],"en":["800 g lamb shoulder, cubed","2 onions","3 carrots","3 potatoes","2 garlic cloves","2 tbsp tomato paste","500 ml beef stock","thyme, bay leaf","salt, pepper, olive oil"],"ro":["800 g pulpă de miel, cuburi","2 cepe","3 morcovi","3 cartofi","2 căței usturoi","2 linguri pastă de tomate","500 ml supă de carne","frunze de cimbru, dafin","sare, piper, ulei de măsline"]},"howIsMade":{"ja":"ラム肩肉を約4cm角に切る — 長時間の煮込みでも崩れず柔らかさを保てる大きさ。表面をしっかり拭き、塩こしょうをたっぷり、薄く小麦粉をはたいてソースのとろみを助ける。鋳鉄の重い鍋に油を薄く敷き、煙が立つ手前まで熱し、ラム肉を3〜4回に分けて、鍋を混み合わせずに深い焼き色がつくまで焼き付ける — 詰め込むと肉が蒸れて焼き色が出ない。焼けた肉は皿に取り置く。同じ脂でみじん切りの玉ねぎとにんにくを透き通るまで炒め、トマトペーストを加えて1分加熱し、香りが丸くなるまで炒める。ラム肉と肉汁を戻し、温めたストックを材料が辛うじて浸る程度に注ぎ、タイムの枝とローリエを加え、軽く沸かしてから最弱火に落とす。蓋をして90分、沸騰させず、ぽつぽつと小さく泡が立つ状態で煮る。途中で一度かき混ぜる。斜め切りのにんじんと、形が崩れにくいワキシーポテトを大きめに切って加え、さらに30〜40分、ラム肉がフォークで触れるだけで割れ、じゃがいもがまだ形を保つまで煮る。味見をし、塩を整え、ローリエを引き上げる。深めの器に盛り、クラスティーなパンを添えて出す。火から下ろして10分休ませ、汁が落ち着いてから供する。","en":"Cut the lamb shoulder into roughly 4 cm cubes — large enough to stay tender through a long simmer without falling apart. Pat them completely dry and season generously with salt and pepper, then dust very lightly with flour to help the sauce thicken. Heat a heavy casserole or Dutch oven with a film of oil until it shimmers, and brown the lamb in three or four batches without crowding the pan — crowding steams the meat and you lose the deep crust. Set each batch aside on a plate. In the same fat, sweat finely chopped onion and garlic until translucent, then stir in tomato paste and let it cook a minute until it smells rounder. Return the lamb with any resting juices, pour in enough hot stock to just cover, add a few sprigs of thyme and a bay leaf, bring to a gentle simmer and lower the heat to the smallest possible. Cover and cook for ninety minutes — never let it boil, only bubble — stirring once. Add carrots cut on the bias and waxy potatoes in large chunks and cook another thirty to forty minutes, until the lamb pulls apart at the touch of a fork and the potatoes hold their shape. Taste, adjust salt, and lift out the bay. Serve in deep bowls with crusty bread, after letting the stew rest off the heat for ten minutes so the broth pulls together."}},{"id":215,"tipType":"salad","pairingsType":"salad","origin":{"ja":"ギリシャ","en":"Greece","ro":"Grecia"},"name":{"ja":"ギリシャサラダ","en":"Greek Salad","ro":"Salată grecească"},"category":{"ja":"サラダ","en":"Salad","ro":"Salate"},"ingredients":{"ja":["完熟トマト4個（厚切り）","大きなきゅうり1本（薄切り）","ピーマン1個","赤玉ねぎ1個（薄い輪切り）","フェタチーズ200gブロック","カラマタオリーブ100g","エクストラバージンオリーブオイル大さじ2","乾燥ギリシャオレガノ小さじ1","粗塩"],"en":["4 ripe tomatoes, thickly sliced","1 large cucumber, sliced","1 green pepper","1 red onion, thinly ringed","200 g block feta","100 g Kalamata olives","2 tbsp extra-virgin olive oil","1 tsp dried Greek oregano","coarse salt"],"ro":["4 roșii coapte, tăiate felii groase","1 castravete mare, tăiat felii","1 ardei verde","1 ceapă roșie, tăiată rondele subțiri","200 g feta în bloc","100 g măsline Kalamata","2 linguri ulei de măsline extravirgin","1 linguriță oregano grecesc uscat","sare grunjoasă"]},"howIsMade":{"ja":"完熟トマトは厚く切る — 指一本分以上 — くし形か輪切りに。皿の上で果汁を保ち、ピューレに崩れないように。きゅうりは半月切り、ピーマンは薄い輪切り、赤玉ねぎはできるだけ薄く。辛みが強ければ氷水に10分浸し、角を取りつつシャキッとした食感は残す。すべてを幅広で浅いボウルに入れ、粗塩をひとつまみ振り、混ぜないこと — ギリシャ人はかき混ぜず層を作る。カラマタオリーブを丸ごと種つきのまま散らす。フェタチーズは砕かず塊のまま上に置く — クレタ島のタベルナで出てくる姿のままに。エクストラバージンオリーブオイルをたっぷり回しかけ、乾燥オレガノを手のひらで擦って香りを立てサラダ全体に散らす。クラスティーなパンを添えてすぐに食卓へ。","en":"Slice ripe tomatoes thick — at least a finger across — into wedges or rounds, so they hold their juice rather than collapse into purée. Cut the cucumber into half-moons, the green pepper into thin rings, and the red onion paper-thin; if sharp, soak the rings in iced water for ten minutes to soften the bite while keeping the crunch. Combine in a wide, shallow bowl with a pinch of coarse salt and resist tossing — Greeks build this salad in layers, never mixed. Scatter the Kalamata olives whole, with their stones. Lay the feta on top as a single uncut slab, exactly as you'd be served in a Cretan taverna. Drizzle generously with extra-virgin olive oil, then shower with dried oregano rubbed between your palms to release the aroma. Serve immediately with crusty bread for mopping the juices."}},{"id":216,"tipType":"salad","pairingsType":"italian","origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"カプレーゼ","en":"Caprese Salad","ro":"Salată Caprese"},"category":{"ja":"サラダ","en":"Salad","ro":"Salate"},"ingredients":{"ja":["完熟トマト3個（薄切り）","水牛モッツァレラ250g","フレッシュバジルの葉","エクストラバージンオリーブオイル","粗塩","挽きたて黒こしょう","バルサミコ酢（お好みで）"],"en":["3 ripe tomatoes, sliced","250 g buffalo mozzarella","fresh basil leaves","extra-virgin olive oil","coarse salt","freshly ground black pepper","balsamic vinegar (optional)"],"ro":["3 roșii coapte, tăiate felii","250 g mozzarella di bufala","frunze de busuioc proaspăt","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt măcinat","oțet balsamic (opțional)"]},"howIsMade":{"ja":"提供する三十分以上前にモッツァレラを冷蔵庫から出しておく — 冷たいままだとクリーミーさを失い、味も平坦に。完熟して香り立つトマトを選ぶ — クオーレ・ディ・ブエからチェリートマトまで、夏の香りがすれば何でもよい — を約1cm厚の輪切りに。モッツァレラも同じ厚さにスライス。大きな平皿の上に、トマトとモッツァレラを少しずつ重ねながら一列に交互に並べ、それぞれの間にバジルの葉を丸ごと挟んで緑が見えるように。エクストラバージンオリーブオイルを皿の底に溜まるくらいたっぷり回しかけ、海塩のフレークと挽きたての黒胡椒をひと振り。すぐに常温で、クラスティーなパンと共に食卓へ。バルサミコ酢は不要 — カプレーゼはバルサミコなしで生まれ、その方が一番美味しい。","en":"Take the mozzarella out of the fridge at least thirty minutes before serving — fridge-cold it loses its creaminess and the flavour stays flat. Choose ripe, fragrant tomatoes — anything from Cuore di Bue to cherries on the vine, as long as they smell of summer — and slice them about a centimetre thick. Cut the mozzarella into slices of the same thickness. On a large flat plate, alternate one slice of tomato with one of mozzarella in a single, slightly overlapping row, tucking a whole basil leaf between each pair so the green shows. Drizzle with extra-virgin olive oil until it pools at the base, season with a few flakes of sea salt and a turn of freshly cracked black pepper. Serve immediately at room temperature, with crusty bread. Purists refuse balsamic vinegar — Caprese was born without it and works best that way."}},{"id":217,"tipType":"pasta","pairingsType":"italian","origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"ラザニア","en":"Lasagna","ro":"Lasagna"},"category":{"ja":"パスタ","en":"Pasta","ro":"Paste"},"ingredients":{"ja":["ラザニアシート300g","牛ひき肉500g","玉ねぎ1個","にんにく2片","トマトソース400g","ベシャメルソース300ml","パルミジャーノおろし150g","モッツァレラ150g","塩、こしょう、オリーブオイル"],"en":["300 g lasagna sheets","500 g beef mince","1 onion","2 garlic cloves","400 g tomato sauce","300 ml béchamel sauce","150 g Parmigiano grated","150 g mozzarella","salt, pepper, olive oil"],"ro":["300 g foi de lasagna","500 g vită tocată","1 ceapă","2 căței usturoi","400 g sos de roșii","300 ml sos béchamel","150 g Parmigiano ras","150 g mozzarella","sare, piper, ulei de măsline"]},"howIsMade":{"ja":"まずラグーから：オリーブオイルと一かけのバターで、みじん切りの玉ねぎ・にんじん・セロリを10分かけて弱火でじっくり甘く — このソフリットがすべての味の土台だ。火を強め、牛ひき肉を加えて木べらの背でほぐしながらしっかり焼き色をつける。赤ワインをグラス一杯注いで飛ばし、トマトのパッサータ、塩ひとつまみ、ナツメグをひと擦り。蓋をせず最弱火で最低1時間 — 時間があれば2時間 — 時折かき混ぜながら煮込む。並行してベシャメルを作る：バターを溶かし、小麦粉を加えて1分炒り、温めた牛乳を少しずつ注ぎながら泡立て器で混ぜ、なめらかで濃度がつくまで仕上げる。塩とナツメグで味を整える。オーブンを180°Cに予熱。深皿の底にベシャメルを薄く塗って張りつき防止し、この順で重ねていく — パスタシート、ラグー、ベシャメル、たっぷりのパルミジャーノ。少なくとも5層重ね、最上段はベシャメルと最後のパルミジャーノで締める。35–40分、表面が黄金色になり縁が沸き立つまで焼く。切る前に15分休ませる — これは絶対、休ませないと層が崩れて滑る。","en":"Start with the ragù: gently soften finely chopped onion, carrot and celery in olive oil and a knob of butter for ten minutes — the soffritto is the base of all the flavour. Raise the heat, add the minced beef and brown it deeply, breaking it up with the back of a spoon. Pour in a glass of red wine and let it evaporate, then add the tomato passata, a pinch of salt and a grating of nutmeg. Cook uncovered on the lowest flame for at least one hour — two if you have time — stirring every so often. Meanwhile, make the béchamel: melt butter, whisk in flour, cook a minute, then gradually pour in warm milk while whisking until smooth and thickened; season with salt and a touch of nutmeg. Heat the oven to 180°C. Spoon a thin layer of béchamel into the base of a deep dish to prevent sticking, then layer in this order: pasta sheets, ragù, béchamel, a generous grating of Parmigiano. Repeat for at least five layers, ending with béchamel and a final shower of Parmigiano. Bake 35–40 minutes until the top is golden and the edges bubble. Rest fifteen minutes before cutting — this is non-negotiable, or the layers slide."}},{"id":218,"tipType":"salad","pairingsType":"salad","origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"ニース風サラダ","en":"Salade Niçoise","ro":"Salată Niçoise"},"category":{"ja":"サラダ","en":"Salad","ro":"Salate"},"ingredients":{"ja":["オイル漬けツナ缶200g","固ゆで卵4個","インゲン200g","新じゃが300g","ニース風オリーブ12個","アンチョビフィレ4枚","トマト2個","オリーブオイル大さじ2","ワインビネガー、塩、こしょう"],"en":["200 g tinned tuna in oil","4 hard-boiled eggs","200 g green beans","300 g new potatoes","12 Niçoise olives","4 anchovy fillets","2 tomatoes","2 tbsp olive oil","wine vinegar, salt, pepper"],"ro":["200 g ton la conservă în ulei","4 ouă fierte tari","200 g fasole verde","300 g cartofi noi","12 măsline Niçoise","4 file de hamsii","2 roșii","2 linguri ulei de măsline","oțet de vin, sare, piper"]},"howIsMade":{"ja":"卵は冷水から8分茹で、すぐに氷水に取って加熱を止め、黄身が固まり切る寸前で止める。新じゃがは丸のまま塩水で、ナイフの先がすっと入るまで約15分茹で、温かいうちに半分に切ってドレッシングが染み込むようにする。さやいんげんは塩を効かせた湯で3分茹で、氷水に取って歯ごたえと鮮緑を保つ。大きな平皿に若葉のベッドを敷き、すべての具材をグループごとに配置する — 卵は四つ切り、じゃがは半分、いんげん、トマトのくし切り、ツナはほぐして、オリーブ、アンチョビフィレを上に斜め掛けに。オリーブオイルにワインビネガーを少し加えて乳化させ、塩胡椒し、提供直前にかける。冷たすぎず、涼しい状態で食卓へ。","en":"Boil the eggs eight minutes from cold, then plunge straight into iced water to stop the cooking and keep the yolk just set. Cook the new potatoes whole in salted water until a knife tip slides in cleanly, around fifteen minutes, then halve them while still warm so they soak up the dressing. Blanch the green beans for three minutes in plenty of boiling salted water, then refresh in iced water so they stay snappy and bright. On a wide, flat plate, lay a bed of greens and arrange everything in groups rather than tossing — quartered eggs, potato halves, beans, tomato wedges, the tuna broken into chunks, olives, anchovy fillets draped across the top. Whisk olive oil with a splash of wine vinegar, season, and spoon over only just before serving. Bring to the table cool, not fridge-cold."}},{"id":219,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ロシア","en":"Russia","ro":"Rusia"},"name":{"ja":"ビーフストロガノフ","en":"Beef Stroganoff","ro":"Boeuf Stroganoff"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["牛フィレ600g（細切り）","マッシュルーム300g","玉ねぎ1個","にんにく2片","サワークリーム200ml","マスタード大さじ2","ビーフストック200ml","バター大さじ2","塩、こしょう、パセリ"],"en":["600 g beef tenderloin, sliced into strips","300 g button mushrooms","1 onion","2 garlic cloves","200 ml sour cream","2 tbsp mustard","200 ml beef stock","2 tbsp butter","salt, pepper, parsley"],"ro":["600 g mușchi de vită, tăiat fâșii","300 g ciuperci champignon","1 ceapă","2 căței usturoi","200 ml smântână","2 linguri muștar","200 ml supă de vită","2 linguri unt","sare, piper, pătrunjel"]},"howIsMade":{"ja":"牛フィレ肉は繊維に対して直角に、鉛筆より太くならない細切りにする — 太いと短い加熱時間では硬く残る。表面の水分を完全に拭き取り、塩こしょうして薄く小麦粉をはたく。広めのフライパンを強火でしっかり熱し、バターひとかけと油を入れ、肉を2〜3回に分けて、混み合わせずに焼く。片面30秒だけ、外は焼き色、中はピンクで止める。皿に取って休ませる。同じフライパンの火を弱め、薄切りの玉ねぎをバターで透き通るまで炒め、マッシュルームを入れて最初の3分は触らず深く焼き色をつける。ビーフストックと、あればブランデーをひと垂らし注ぎ、底の旨味のかけらを全部こそげ落として半量まで詰める。フライパンを火から完全に下ろす — これが要 — サワークリームとマスタードを加え、なめらかになるまで混ぜる。ここで沸かすとクリームが分離する。肉と休ませた間の肉汁を戻し、軽くあおって温め、塩を調え、刻んだパセリを散らす。バターを絡めたヌードル、マッシュポテト、または蒸し米に乗せてすぐに供する。","en":"Cut the beef tenderloin into strips against the grain, no thicker than a pencil — thicker pieces stay tough in the short cook time. Pat them completely dry, season with salt and pepper, then dust lightly with flour. Heat a wide pan very hot, add a knob of butter and oil, and sear the beef in two or three batches without crowding the pan, just thirty seconds a side, until browned outside and still pink within. Lift onto a plate and rest. In the same pan, lower the heat and soften finely sliced onion in butter, then add the mushrooms and let them brown deeply without stirring for the first three minutes. Pour in the beef stock and a splash of brandy if you have it, scrape up every brown bit from the base, and reduce by half. Take the pan completely off the heat — the critical step — and stir in the sour cream and the mustard until smooth; if it boils now, the cream splits. Return the beef and any resting juices to the pan, swirl through to warm, taste for salt, and shower with chopped parsley. Serve immediately over buttered noodles, mash, or steamed rice."}},{"id":222,"tipType":"meat","pairingsType":"meat","origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"コック・オー・ヴァン","en":"Coq au Vin","ro":"Coq au vin"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["丸鶏1羽（8つに切る）","パンチェッタまたはベーコン200g","マッシュルーム250g","パールオニオン200g","ブルゴーニュ赤ワイン1本","にんにく2片","にんじん2本","タイム、ローリエ","バター、小麦粉、塩、こしょう、パセリ"],"en":["1 whole chicken, cut into 8 pieces","200 g pancetta or bacon","250 g button mushrooms","200 g pearl onions","1 bottle red Burgundy wine","2 garlic cloves","2 carrots","thyme, bay leaf","butter, flour, salt, pepper, parsley"],"ro":["1 pui întreg, tăiat în 8 bucăți","200 g pancetta sau bacon","250 g ciuperci champignon","200 g ceapă mică","1 sticlă vin roșu Burgundia","2 căței usturoi","2 morcovi","cimbru, dafin","unt, făină, sare, piper, pătrunjel"]},"howIsMade":{"ja":"前の晩、鶏を8つに切り分け、赤いブルゴーニュワインに月桂樹、タイム、半分に切った玉ねぎ、黒胡椒を数粒入れて漬け込む。蓋をして冷蔵庫で一晩、ワインが肉に染み込み、マリネ液が鶏の香りを吸う。翌日、鶏を取り出し一切れずつ完全に拭き上げる — 濡れた皮は焼き色がつかない、これがここでの大罪だ。マリネ液は取っておく。重い鋳鉄鍋でサイコロ切りのパンチェッタをカリッとするまで焼き、取り出す。その脂で鶏肉を2回に分け、皮目から焼き始めて深いマホガニー色になるまで焼く。取り出して脇に置く。同じ鍋でみじん切りの玉ねぎ、にんにく、にんじんを甘く炒め、山盛りの小麦粉一杯を振り入れて1分炒め、取っておいたマリネ液と濃いめのチキンストックをお玉一杯注ぎ、底の焦げ目をこそげ落とす。鶏とパンチェッタを戻し、軽く沸騰させて蓋をし、最弱火で — または160°Cのオーブンで — 60分、肉が柔らかく、しかし骨にまだ寄り添っている状態まで煮込む。煮ている間、別鍋で真珠玉ねぎをバターで琥珀色に、別のフライパンでマッシュルームを深く色付けに焼く — 一緒には絶対しない、互いに蒸し合ってしまうから。残り15分で両方を鍋に滑り込ませ、塩を整え、火を止めてから冷たいバター一かけを溶かし入れ、パセリを散らす。マッシュポテトかバターを絡めたタリアテッレを添え、ソースの一滴も逃さず楽しむ。","en":"The night before, joint the chicken into eight pieces and submerge in red Burgundy with bay, thyme, a halved onion and a few peppercorns; cover and refrigerate overnight so the wine penetrates the flesh and the marinade takes on the bird's perfume. Next day, lift the chicken out and pat each piece bone-dry — wet skin will not brown, which is the cardinal sin here. Reserve the marinade. In a heavy cast-iron pot, render diced pancetta until crisp; lift it out and brown the chicken in the rendered fat in two batches, skin-side first, until each piece is mahogany. Set aside. In the same pot, sweat finely chopped onion, garlic and carrot, scatter a heaped spoonful of flour over and stir for a minute, then pour in the reserved marinade and a ladle of dark chicken stock, scraping every brown trace from the bottom. Return the chicken and pancetta, bring to a gentle simmer, cover and cook on the lowest flame — or in a 160°C oven — for sixty minutes, until the meat is tender but still clings to the bone. While it cooks, sauté the pearl onions in butter until amber and the mushrooms in a separate pan until deeply browned — never together, or they steam each other. Slip both into the pot for the last fifteen minutes, taste for salt, finish with a knob of cold butter swirled in off the heat and a shower of parsley. Serve with mashed potato or buttered noodles to catch every drop of sauce."}},{"id":223,"tipType":"meat","pairingsType":"meat","origin":{"ja":"ポーランド","en":"Poland","ro":"Polonia"},"name":{"ja":"ビゴス","en":"Bigos","ro":"Bigos"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["ザワークラウト500g（水気を絞る）","生キャベツ300g（千切り）","豚肩肉400g（角切り）","スモークソーセージ（キェルバサ）200g","ベーコン150g","玉ねぎ1個","にんにく2片","プルーン3個","オールスパイス、ローリエ、パプリカ、塩、こしょう"],"en":["500 g sauerkraut, drained","300 g fresh cabbage, shredded","400 g pork shoulder, cubed","200 g smoked sausage (kielbasa)","150 g bacon","1 onion","2 garlic cloves","3 dried prunes","allspice, bay leaf, paprika, salt, pepper"],"ro":["500 g varză murată, scurtă","300 g varză proaspătă, tăiată","400 g porc (umăr), cuburi","200 g cârnați afumați (kielbasa)","150 g bacon","1 ceapă","2 căței usturoi","3 prune uscate","ienibahar, dafin, boia, sare, piper"]},"howIsMade":{"ja":"ビゴスは層を重ねて作る — ポーランドのどの料理人にも自分の順序があるが、原則は忍耐だ。重い鍋でベーコンの角切りを中火でじっくり脂を引き出し、カリッとしたら取り出して取り置く。豚肩のサイコロ切りをそのベーコンの脂で、鍋を混み合わせずに2回に分け、深い黄金色になるまで焼き付けて取り出す。同じ脂でみじん切りの玉ねぎとにんにくを甘く炒め、肉とベーコンを戻す。ザワークラウトを軽く水切り、酸味が強ければさっとすすぎ、千切りの生キャベツ、スライスしたキェルバサ、種を抜いたプルーン、月桂樹の葉数枚、手のひらで潰したジュニパーベリー、オールスパイス、スイートパプリカと一緒に鍋に入れる。具材が辛うじて浸る程度に水を注ぎ、軽く沸かしてから最弱火に落とし、蓋をして2〜3時間ほど鍋を忘れる。30分ごとに混ぜ、キャベツを汁の中に押し沈める。最後に塩を整える。ビゴスの正直な秘密：一晩冷蔵庫で冷やし、翌日ゆっくり温め直す — 風味が結ばれ、燻香が深まり、煮汁が凝縮する。","en":"Bigos is built in layers — every cook in Poland has their own order, but the principle is patience. In a heavy pot, render diced bacon over medium heat until the fat runs and the pieces crisp, then lift them out and reserve. Brown the cubed pork shoulder in the bacon fat in two batches without crowding, until each side is deeply golden, and remove. Soften finely chopped onion and garlic in the same fat, then return the meat with the bacon. Drain and rinse the sauerkraut briefly if very sour, and pile it in with the shredded fresh cabbage, the sliced kielbasa, the pitted prunes, a few bay leaves, several juniper berries crushed in the palm, allspice and sweet paprika. Pour in just enough water to barely cover, bring to a gentle simmer, then lower the heat right down, cover, and forget about it for two to three hours, stirring every half hour and pushing the cabbage down into the liquor. Taste and adjust salt at the end. The honest secret of bigos: cool it overnight in the fridge, then warm slowly the next day — the flavours marry, the smoke deepens, the broth concentrates."}},{"id":226,"tipType":"asian","pairingsType":"asian","origin":{"ja":"ベトナム","en":"Vietnam","ro":"Vietnam"},"name":{"ja":"生春巻き","en":"Vietnamese Spring Rolls","ro":"Rulouri vietnameze proaspete"},"category":{"ja":"昼食","en":"Lunch","ro":"Prânz"},"ingredients":{"ja":["ライスペーパー（バインチャン）12枚","茹でて殻をむいたエビ200g","茹でた豚バラ薄切り200g","茹でた米麺100g","きゅうり1本","レタスの葉","フレッシュミント","フレッシュパクチー","ホイシンまたはヌクチャムソース"],"en":["12 rice paper wrappers (bánh tráng)","200 g cooked prawns, peeled","200 g cooked pork belly, sliced","100 g cooked rice vermicelli","1 cucumber","lettuce leaves","fresh mint leaves","fresh coriander leaves","hoisin or nước chấm sauce for dipping"],"ro":["12 foi de orez (bánh tráng)","200 g creveți fierți, decojiți","200 g piept de porc fiert, feliat","100 g tăiței de orez fierți","1 castravete","frunze de salată","frunze de mentă proaspătă","frunze de coriandru","sos hoisin sau nước chấm pentru servit"]},"howIsMade":{"ja":"巻く前にすべて段取りしておく — 一度始めたら止まれない。米麺は袋の指示通りに茹で、完全に冷えるまで冷水で流し、よく水気を切る。茹でた豚バラは薄切り、茹でたエビは縦に半分に開き、ピンクの面がライスペーパー側を向くようにする — 見た目が美しい。きゅうりは細い千切りに。ハーブ、芯を取ったレタス、米麺、きゅうり、たんぱく質を手の届くトレーに集める。浅いボウルに温かい — 熱くない — 湯を張る。ライスペーパーは5秒だけ浸す。少し湿らせた布巾に乗せた時点ではまだ硬く感じるくらいでよく、巻きながら最後に柔らかくなる。自分に一番近い三分の一の位置に小さなレタス、ミントとパクチー、ひとつまみの米麺、きゅうり、豚肉一切れを置く。下端を具の上にかぶせ、左右を折り込み、最後の一巻きに入る直前にエビの半身2つをピンク面下にして紙の上に置くと、巻き上がった時に透けて見える。きつく巻いて閉じる。出来上がった巻きは湿らせた布で覆って乾燥を防ぎ、ホイシン・ピーナッツソースまたはヌクチャムを添えて供する。","en":"Prep everything before you start rolling — once you begin you can't pause. Cook the rice vermicelli per the packet, rinse under cold water until completely cool, and drain well. Slice the cooked pork belly thinly; have the cooked prawns split lengthwise so the pink side faces the wrapper for presentation. Cut the cucumber into matchsticks. Pile the herbs, lettuce leaves with their stems removed, vermicelli, cucumber and proteins on a tray within easy reach. Fill a shallow bowl with warm — not hot — water. Dip one rice paper for just five seconds; it should still feel firm when you lay it on a slightly damp tea towel, and it will finish softening as you build the roll. On the third closest to you, lay a small lettuce leaf, then a few mint and coriander leaves, a pinch of vermicelli, cucumber matchsticks and a slice of pork. Fold the bottom edge up over the filling, then fold the two sides in, and as you start the final roll lay two prawn halves pink-side-down on the wrapper so they show through the finished roll. Roll tightly to seal. Cover finished rolls with a damp cloth so they don't dry, and serve with hoisin-peanut sauce or nước chấm."}},{"id":227,"tipType":"fish","pairingsType":"seafood","origin":{"ja":"地中海","en":"Mediterranean","ro":"Mediterana"},"name":{"ja":"鯛のグリル","en":"Grilled Sea Bream","ro":"Dorada la grătar"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["鯛丸ごと2尾（各約500g）","レモン2個","にんにく4片","フレッシュディルとパセリ","タイム","エクストラバージンオリーブオイル","粗塩","挽きたて黒こしょう"],"en":["2 whole sea bream (about 500 g each)","2 lemons","4 garlic cloves","fresh dill and parsley","thyme","extra-virgin olive oil","coarse salt","freshly ground black pepper"],"ro":["2 dorade întregi (cca 500 g fiecare)","2 lămâi","4 căței usturoi","mărar și pătrunjel proaspăt","cimbru","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt"]},"howIsMade":{"ja":"できる限り新鮮な鯛を選ぶ — 目が澄み、エラが鮮やかな赤、押すとすぐに戻る身。魚屋がしていなければ自分でうろこと内臓を取り除き、頭と尾は残す。鋭い刃で皮の上に両側それぞれ斜めに三本の切れ目を入れ、骨に届くほど深く — 熱が均等に入り、皮がグリルで反り返るのを防ぐ。焼く二十分前に腹の中と皮にたっぷりと塩を打ち、塩が身に行き渡り、表面が乾いて香ばしく焼けるようにする。腹にはレモンの輪切り、潰したにんにく、ディル、パセリ、タイムの枝を詰める。外側にエクストラバージンオリーブオイルを刷毛で塗る。炭を強火に熾し、片面6–8分ずつ焼く。網からきれいに離れるまで触らずに待ち、無理に動かさないこと — 皮が破ける。フォークの先で骨から身が浮き上がるようになれば焼き上がり。火から下ろして2分休ませ、まるごと板に乗せて食卓へ。レモンのくし切り、新しいオリーブオイルをひと回し、ギリシャサラダを脇に添えて。","en":"Buy the freshest sea bream you can find — clear eyes, bright red gills, firm flesh that springs back when pressed. Scale and gut the fish if your fishmonger hasn't, leaving head and tail on. With a sharp knife, score three diagonal slashes through the skin on each side, almost to the bone — they let the heat penetrate evenly and stop the skin from curling on the grill. Salt generously inside the cavity and on the skin, twenty minutes before cooking, so the salt has time to season the flesh and dry the surface for crisp browning. Stuff the belly with lemon slices, smashed garlic cloves, dill, parsley and a few sprigs of thyme. Brush the outside with extra-virgin olive oil. Build a hot charcoal fire and grill 6–8 minutes per side, flipping only when the fish releases cleanly from the grate — force it and the skin tears. The flesh is ready when it lifts off the bone with the tip of a fork. Rest two minutes off the heat, then carry the whole fish to the table on a board with extra lemon wedges, a drizzle of new olive oil, and a Greek salad alongside."}},{"id":228,"tipType":"fish","pairingsType":"seafood","origin":{"ja":"フランス","en":"France","ro":"Franța"},"name":{"ja":"スズキのプロヴァンス風","en":"Sea Bass Provençal","ro":"Lup de mare provensal"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["スズキの切り身2枚（各約200g）","ミニトマト400g","ニース風黒オリーブ12個","にんにく2片","ケッパー大さじ1","ローズマリー1枝","フレッシュタイム","オリーブオイル、辛口白ワイン","塩、こしょう、バジル"],"en":["2 sea bass fillets (about 200 g each)","400 g cherry tomatoes","12 black Niçoise olives","2 garlic cloves","1 tbsp capers","1 sprig rosemary","fresh thyme","olive oil, dry white wine","salt, pepper, basil"],"ro":["2 fileuri de lup de mare (cca 200 g fiecare)","400 g roșii cherry","12 măsline negre Niçoise","2 căței usturoi","1 lingură capere","1 ramură rozmarin","cimbru proaspăt","ulei de măsline, vin alb sec","sare, piper, busuioc"]},"howIsMade":{"ja":"まず魚から：皮付きの切り身を使うなら、30分前に冷蔵庫から出して常温に近づけ、キッチンペーパーで一切れずつ完全に水分を拭き取る — 冷たく湿った魚は火の通りが不均一で、焼き色もつかない。両面に軽く塩をして脇に置く。オーブンを200°Cに予熱。広めの耐熱皿にオリーブオイルを薄く塗り、半分に切ったチェリートマトを切り口を上にして、丸ごとのニソワーズ・オリーブ、洗ったケッパー、薄切りのにんにく数片、タイムの小枝、ローズマリーを一枝散らす。さらにオリーブオイルをたっぷり回しかけ、辛口白ワインをグラス一杯注ぎ、塩と挽きたての黒胡椒で味付け。10分焼く — トマトが弾けて果汁を放ち、ワインは半量まで詰まり、にんにくの角が取れる。これが魚を受ける香りのベッドになる。皿を取り出し、切り身を皮を上にしてトマトの間に並べ、皿底のソースをスプーンですくって魚にかける。さらに8〜10分焼き、身が白っぽくなりフォークの先でほろほろと分かれ、皮にも金色の斑点がつくまで。中心にナイフの先を入れて確かめ、抵抗なくすっと入れば焼き上がり。2分休ませ、手で千切ったバジルの葉を散らし、クラスティーなパンと共に皿ごと食卓へ。プロヴァンサルソースを拭い取らないと、料理の半分は皿の中に置き去りだ。","en":"Start with the fish: if using skin-on fillets, take them out of the fridge thirty minutes ahead to temper, and pat each piece bone-dry with kitchen paper — cold, wet fish cooks unevenly and won't brown. Salt lightly on both sides and set aside. Heat the oven to 200°C. In a wide oiled dish, lay halved cherry tomatoes cut-side up, whole Niçoise olives, rinsed capers, a few thinly sliced garlic cloves, thyme sprigs and a single sprig of rosemary. Drizzle generously with more olive oil, pour in a glass of dry white wine, season with salt and freshly cracked pepper. Slide into the oven for ten minutes — the tomatoes need to burst and release their juices, the wine reduces by half, and the garlic loses its sharpness; this is how the aromatic bed for the fish is built. Pull the dish out, lay the fillets skin-up among the tomatoes and spoon some of the pan juices over them. Return for eight to ten minutes, until the flesh turns opaque and flakes at the tip of a fork, and the skin takes on a few golden patches. Check the centre with a knife tip: if it slides in without resistance, it is done. Rest two minutes, scatter torn basil leaves on top, and bring the dish to the table with crusty bread to mop the Provençal sauce — without it, half the meal stays in the pan."}},{"id":229,"tipType":"meat","pairingsType":"italian","origin":{"ja":"イタリア","en":"Italy","ro":"Italia"},"name":{"ja":"ローストチキン・アッラ・ディアボラ","en":"Roast Chicken Diavola","ro":"Pui la cuptor alla diavola"},"category":{"ja":"夕食","en":"Dinner","ro":"Cină"},"ingredients":{"ja":["丸鶏1羽（spatchcockに開く）","にんにく4片（潰す）","唐辛子フレーク大さじ2（ペペロンチーノ）","スモークパプリカ小さじ1","レモン1個（果汁と皮）","オリーブオイル大さじ3","タイムとローズマリー","粗塩、黒こしょう"],"en":["1 whole chicken, spatchcocked","4 garlic cloves, crushed","2 tbsp crushed chilli flakes (peperoncino)","1 tsp smoked paprika","1 lemon (juice and zest)","3 tbsp olive oil","thyme and rosemary","coarse salt, black pepper"],"ro":["1 pui întreg, despicat (spatchcocked)","4 căței usturoi zdrobiți","2 linguri ardei iute zdrobit (peperoncino)","1 linguriță boia afumată","1 lămâie (suc și coajă)","3 linguri ulei de măsline","cimbru și rozmarin","sare grunjoasă, piper negru"]},"howIsMade":{"ja":"肉屋がしていなければ、鶏を自分でスパチコックする：胸を下にして置き、丈夫なキッチンばさみで背骨を両側に沿って切り取る。裏返して胸骨にしっかり体重をかけ、骨が「パキッ」と音を立てて平らになるまで押す。広いボウルにオリーブオイル、潰したにんにく、スモークパプリカ、粗塩、レモン汁とレモンの皮、そして大胆な量の唐辛子フレークを合わせて混ぜる — これがこの料理の人格そのものだ。マリネを両面と皮のひだの隅々まですり込み、室温で最低1時間、できれば冷蔵庫で一晩寝かせて深く味を入れる。重い天板をオーブンに入れたまま220°Cに予熱し、鶏を載せた瞬間に「ジュッ」と音がするようにする。皮を上にして熱い天板に置き、もう一枚の重い鍋かアルミホイルに包んだレンガで上から押さえつける — これがディアボラの本物の押し具で、皮を熱に密着させて最大限のカリッと感を出す。35–40分焼き、皮が赤褐色になり、骨際の腿肉に温度計を刺して75°Cを示すまで。アルミホイルをふんわり掛けて10分休ませ、関節で切り分け、追加のレモンと天板の肉汁をかけて供する。","en":"Spatchcock the chicken if your butcher hasn't: lay it breast-down, snip out the backbone along both sides with sturdy kitchen shears, flip and press firmly on the breastbone until it cracks and the bird lies flat. In a wide bowl whisk olive oil, crushed garlic, smoked paprika, coarse salt, lemon juice and zest, and a defiant amount of crushed chilli flakes — the dish's whole personality. Rub the marinade into both sides and into every fold of the skin, then leave the bird at least one hour at room temperature, or overnight covered in the fridge for deeper penetration. Heat the oven to 220°C with a heavy roasting tray inside, so the chicken hits a sizzling surface. Lay the chicken skin-up on the hot tray and weigh it down with a second heavy pan or a foil-wrapped brick — the authentic diavola press, which forces the skin into contact with the heat for maximum crispness. Roast 35–40 minutes until the skin is mahogany and a probe in the thigh near the bone reads 75°C. Rest ten minutes loosely tented with foil, carve through the joints, and serve with extra lemon wedges and the pan juices spooned over."}}];export default recipes;